#!/usr/bin/env tsx
/**
 * OAuth Configuration Check Script
 * سكربت للتحقق من إعدادات OAuth و redirect_uri
 * 
 * Checks:
 * - Google OAuth redirect_uri configuration
 * - Environment variables (GOOGLE_CLIENT_ID, GOOGLE_CLIENT_SECRET, NEXT_PUBLIC_BASE_URL)
 * - Redirect URI format validation
 * - Consistency between code and documentation
 * 
 * Usage: npm run check:oauth
 *        tsx scripts/check-oauth-config.ts
 */

import * as fs from 'fs';
import * as path from 'path';
import { config } from 'dotenv';

// Load environment variables
config({ path: path.join(__dirname, '..', '.env.local') });
config({ path: path.join(__dirname, '..', '.env') });

const PROJECT_ROOT = path.join(__dirname, '..');

interface OAuthReport {
  google: {
    clientId: string | null;
    clientSecret: string | null;
    baseUrl: string | null;
    redirectUri: string | null;
    isConfigured: boolean;
    validation: {
      valid: boolean;
      errors: string[];
      warnings: string[];
    };
  };
  errors: string[];
  warnings: string[];
  recommendations: string[];
}

function validateRedirectUri(redirectUri: string): { valid: boolean; errors: string[]; warnings: string[] } {
  const errors: string[] = [];
  const warnings: string[] = [];

  if (!redirectUri || redirectUri.trim() === '') {
    errors.push('Redirect URI cannot be empty');
    return { valid: false, errors, warnings };
  }

  try {
    const url = new URL(redirectUri);
    
    // Check protocol
    if (url.protocol !== 'http:' && url.protocol !== 'https:') {
      errors.push(`Invalid protocol: ${url.protocol}. Must be http:// or https://`);
    }

    // Check for trailing slash (common mistake)
    if (redirectUri.endsWith('/') && !redirectUri.endsWith('/callback/')) {
      errors.push('Redirect URI should not end with a trailing slash (except /callback/)');
    }

    // Check path format
    if (!url.pathname.startsWith('/api/auth/')) {
      errors.push('Redirect URI path must start with /api/auth/');
    }

    // Check for Google OAuth callback path
    if (!url.pathname.includes('/google/callback')) {
      warnings.push('Redirect URI does not include /google/callback path');
    }

    // Warn about localhost in production
    if (url.hostname === 'localhost' && process.env.NODE_ENV === 'production') {
      warnings.push('Using localhost in production environment is not recommended');
    }

    // Warn about http in production
    if (url.protocol === 'http:' && process.env.NODE_ENV === 'production') {
      warnings.push('Using http:// in production is not secure. Use https://');
    }

    return {
      valid: errors.length === 0,
      errors,
      warnings,
    };
  } catch (error) {
    errors.push(`Invalid redirect URI format: ${error instanceof Error ? error.message : String(error)}`);
    return { valid: false, errors, warnings };
  }
}

function getRedirectUri(): string {
  const baseUrl = (process.env.NEXT_PUBLIC_BASE_URL || 'http://localhost:3000').trim();
  const cleanBaseUrl = baseUrl.replace(/\/+$/, '');
  return `${cleanBaseUrl}/api/auth/google/callback`;
}

function checkOAuthConfig(): OAuthReport {
  const report: OAuthReport = {
    google: {
      clientId: process.env.GOOGLE_CLIENT_ID || null,
      clientSecret: process.env.GOOGLE_CLIENT_SECRET || null,
      baseUrl: process.env.NEXT_PUBLIC_BASE_URL || null,
      redirectUri: null,
      isConfigured: false,
      validation: {
        valid: false,
        errors: [],
        warnings: [],
      },
    },
    errors: [],
    warnings: [],
    recommendations: [],
  };

  // Check environment variables
  if (!report.google.clientId || report.google.clientId.trim() === '') {
    report.errors.push('GOOGLE_CLIENT_ID is not set');
  } else {
    report.google.clientId = report.google.clientId.substring(0, 20) + '...';
  }

  if (!report.google.clientSecret || report.google.clientSecret.trim() === '') {
    report.errors.push('GOOGLE_CLIENT_SECRET is not set');
  } else {
    report.google.clientSecret = '***';
  }

  if (!report.google.baseUrl || report.google.baseUrl.trim() === '') {
    report.warnings.push('NEXT_PUBLIC_BASE_URL is not set, using default: http://localhost:3000');
    report.google.baseUrl = 'http://localhost:3000';
  }

  // Calculate redirect URI
  report.google.redirectUri = getRedirectUri();
  report.google.isConfigured = 
    (process.env.GOOGLE_CLIENT_ID || '').trim() !== '' && 
    (process.env.GOOGLE_CLIENT_SECRET || '').trim() !== '';

  // Validate redirect URI
  if (report.google.redirectUri) {
    report.google.validation = validateRedirectUri(report.google.redirectUri);
  }

  // Generate recommendations
  if (!report.google.isConfigured) {
    report.recommendations.push('Add GOOGLE_CLIENT_ID and GOOGLE_CLIENT_SECRET to .env.local');
  }

  if (!report.google.validation.valid) {
    report.recommendations.push('Fix redirect_uri format errors (see validation errors above)');
    report.recommendations.push(`Make sure redirect_uri in Google Cloud Console matches: ${report.google.redirectUri}`);
  } else {
    report.recommendations.push(`Add this redirect_uri to Google Cloud Console: ${report.google.redirectUri}`);
  }

  if (report.google.baseUrl?.startsWith('http://') && process.env.NODE_ENV === 'production') {
    report.recommendations.push('Use https:// in production for NEXT_PUBLIC_BASE_URL');
  }

  return report;
}

function formatReport(report: OAuthReport): void {
  console.log('\n' + '='.repeat(70));
  console.log('OAuth Configuration Check / فحص إعدادات OAuth');
  console.log('='.repeat(70) + '\n');

  // Google OAuth Status
  console.log('📋 Google OAuth Configuration:');
  console.log(`   Client ID: ${report.google.clientId || '❌ Not set'}`);
  console.log(`   Client Secret: ${report.google.clientSecret || '❌ Not set'}`);
  console.log(`   Base URL: ${report.google.baseUrl || '❌ Not set'}`);
  console.log(`   Redirect URI: ${report.google.redirectUri || '❌ Not calculated'}`);
  console.log(`   Configured: ${report.google.isConfigured ? '✅ Yes' : '❌ No'}`);
  console.log();

  // Validation
  if (report.google.redirectUri) {
    console.log('🔍 Redirect URI Validation:');
    if (report.google.validation.valid) {
      console.log('   ✅ Valid format');
    } else {
      console.log('   ❌ Invalid format');
      report.google.validation.errors.forEach(error => {
        console.log(`      • ${error}`);
      });
    }
    
    if (report.google.validation.warnings.length > 0) {
      report.google.validation.warnings.forEach(warning => {
        console.log(`      ⚠️  ${warning}`);
      });
    }
    console.log();
  }

  // Errors
  if (report.errors.length > 0) {
    console.log('❌ Errors:');
    report.errors.forEach(error => {
      console.log(`   • ${error}`);
    });
    console.log();
  }

  // Warnings
  if (report.warnings.length > 0) {
    console.log('⚠️  Warnings:');
    report.warnings.forEach(warning => {
      console.log(`   • ${warning}`);
    });
    console.log();
  }

  // Recommendations
  if (report.recommendations.length > 0) {
    console.log('💡 Recommendations / التوصيات:');
    report.recommendations.forEach((rec, index) => {
      console.log(`   ${index + 1}. ${rec}`);
    });
    console.log();
  }

  // Google Cloud Console Instructions
  console.log('📝 Google Cloud Console Setup Instructions:');
  console.log('   1. Go to https://console.cloud.google.com/');
  console.log('   2. Navigate to: APIs & Services → Credentials');
  console.log('   3. Select your OAuth 2.0 Client ID');
  console.log(`   4. Add this exact redirect_uri to "Authorized redirect URIs":`);
  console.log(`      ${report.google.redirectUri || 'N/A'}`);
  console.log('   5. Make sure it matches EXACTLY (same protocol, domain, port, path)');
  console.log();

  // Summary
  console.log('='.repeat(70));
  const allValid = report.google.isConfigured && report.google.validation.valid && report.errors.length === 0;
  if (allValid) {
    console.log('✅ All checks passed! OAuth configuration looks good.');
  } else {
    console.log('❌ Configuration issues found. Please fix the errors above.');
  }
  console.log('='.repeat(70) + '\n');
}

async function main() {
  try {
    const report = checkOAuthConfig();
    formatReport(report);
    
    // Exit with error code if there are critical issues
    if (report.errors.length > 0 || !report.google.validation.valid) {
      process.exit(1);
    }
  } catch (error) {
    console.error('Error checking OAuth configuration:', error);
    process.exit(1);
  }
}

main();

#!/usr/bin/env tsx
/**
 * سكربت للتحقق من ازدواجية ملفات الصفحات (Pages) في Next.js App Router
 * يكتشف الملفات المكررة مثل page-enhanced.tsx, layout-new.tsx, page-new.tsx, page-advanced.tsx
 */

import * as fs from 'fs';
import * as path from 'path';

interface DuplicateFile {
  directory: string;
  files: string[];
  standardFile: string | null;
  duplicateFiles: string[];
  issue: string;
}

interface CheckResult {
  duplicates: DuplicateFile[];
  suspiciousFiles: string[];
  summary: {
    totalDuplicates: number;
    totalSuspicious: number;
  };
}

// الأنماط المشبوهة لأسماء الملفات
const SUSPICIOUS_PATTERNS = [
  /page-enhanced\.tsx?$/i,
  /page-new\.tsx?$/i,
  /page-advanced\.tsx?$/i,
  /page-improved\.tsx?$/i,
  /page-old\.tsx?$/i,
  /page-backup\.tsx?$/i,
  /page-copy\.tsx?$/i,
  /page-v\d+\.tsx?$/i,
  /layout-new\.tsx?$/i,
  /layout-enhanced\.tsx?$/i,
  /layout-improved\.tsx?$/i,
  /layout-old\.tsx?$/i,
  /layout-backup\.tsx?$/i,
  /layout-copy\.tsx?$/i,
  /layout-v\d+\.tsx?$/i,
  /-improved\.tsx?$/i,
  /-enhanced\.tsx?$/i,
  /-new\.tsx?$/i,
  /-old\.tsx?$/i,
  /-backup\.tsx?$/i,
  /-copy\.tsx?$/i,
  /-v2\.tsx?$/i,
  /-v\d+\.tsx?$/i,
  /\.bak\.tsx?$/i,
  /\.old\.tsx?$/i,
];

// أسماء الملفات القياسية في Next.js App Router
const STANDARD_PAGE_FILES = ['page.ts', 'page.tsx', 'layout.ts', 'layout.tsx'];

/**
 * البحث عن الملفات المشبوهة في مجلد app
 */
function findSuspiciousFiles(appDir: string): string[] {
  const suspiciousFiles: string[] = [];

  function scanDirectory(dir: string, relativePath: string = '') {
    if (!fs.existsSync(dir)) {
      return;
    }

    const entries = fs.readdirSync(dir, { withFileTypes: true });

    for (const entry of entries) {
      const fullPath = path.join(dir, entry.name);
      const relativeFilePath = relativePath 
        ? path.join(relativePath, entry.name).replace(/\\/g, '/')
        : entry.name;

      if (entry.isDirectory()) {
        // تخطي node_modules و .next
        if (entry.name === 'node_modules' || entry.name === '.next' || entry.name.startsWith('.')) {
          continue;
        }
        scanDirectory(fullPath, relativeFilePath);
      } else if (entry.isFile()) {
        // التحقق من الأنماط المشبوهة
        const isSuspicious = SUSPICIOUS_PATTERNS.some(pattern => pattern.test(entry.name));
        if (isSuspicious) {
          suspiciousFiles.push(relativeFilePath);
        }
      }
    }
  }

  scanDirectory(appDir);
  return suspiciousFiles;
}

/**
 * اكتشاف الملفات المكررة في نفس المجلد
 */
function detectDuplicates(appDir: string): DuplicateFile[] {
  const duplicates: DuplicateFile[] = [];

  function scanDirectory(dir: string, relativePath: string = '') {
    if (!fs.existsSync(dir)) {
      return;
    }

    const entries = fs.readdirSync(dir, { withFileTypes: true });
    const pageFiles: string[] = [];
    const layoutFiles: string[] = [];
    const otherPageFiles: string[] = [];
    const otherLayoutFiles: string[] = [];

    for (const entry of entries) {
      if (entry.isFile()) {
        const fileName = entry.name.toLowerCase();

        // ملفات page القياسية
        if (fileName === 'page.ts' || fileName === 'page.tsx') {
          pageFiles.push(entry.name);
        }
        // ملفات layout القياسية
        else if (fileName === 'layout.ts' || fileName === 'layout.tsx') {
          layoutFiles.push(entry.name);
        }
        // ملفات page مشبوهة (مثل page-enhanced.tsx)
        else if (fileName.startsWith('page-') && (fileName.endsWith('.ts') || fileName.endsWith('.tsx'))) {
          otherPageFiles.push(entry.name);
        }
        // ملفات layout مشبوهة (مثل layout-new.tsx)
        else if (fileName.startsWith('layout-') && (fileName.endsWith('.ts') || fileName.endsWith('.tsx'))) {
          otherLayoutFiles.push(entry.name);
        }
      }
    }

    // التحقق من ازدواجية ملفات page
    if (pageFiles.length > 0 && otherPageFiles.length > 0) {
      duplicates.push({
        directory: relativePath || 'app',
        files: [...pageFiles, ...otherPageFiles],
        standardFile: pageFiles[0],
        duplicateFiles: otherPageFiles,
        issue: `Found standard page.tsx alongside duplicate page files: ${otherPageFiles.join(', ')}`,
      });
    }

    // التحقق من ازدواجية ملفات layout
    if (layoutFiles.length > 0 && otherLayoutFiles.length > 0) {
      duplicates.push({
        directory: relativePath || 'app',
        files: [...layoutFiles, ...otherLayoutFiles],
        standardFile: layoutFiles[0],
        duplicateFiles: otherLayoutFiles,
        issue: `Found standard layout.tsx alongside duplicate layout files: ${otherLayoutFiles.join(', ')}`,
      });
    }

    // التحقق من وجود ملفات page متعددة بدون ملف قياسي
    if (pageFiles.length === 0 && otherPageFiles.length > 1) {
      duplicates.push({
        directory: relativePath || 'app',
        files: otherPageFiles,
        standardFile: null,
        duplicateFiles: otherPageFiles,
        issue: `Found multiple duplicate page files without a standard page.tsx: ${otherPageFiles.join(', ')}`,
      });
    }

    // التحقق من وجود ملفات layout متعددة بدون ملف قياسي
    if (layoutFiles.length === 0 && otherLayoutFiles.length > 1) {
      duplicates.push({
        directory: relativePath || 'app',
        files: otherLayoutFiles,
        standardFile: null,
        duplicateFiles: otherLayoutFiles,
        issue: `Found multiple duplicate layout files without a standard layout.tsx: ${otherLayoutFiles.join(', ')}`,
      });
    }
  }

  function scanRecursive(dir: string, relativePath: string = '') {
    if (!fs.existsSync(dir)) {
      return;
    }

    scanDirectory(dir, relativePath);

    const entries = fs.readdirSync(dir, { withFileTypes: true });
    for (const entry of entries) {
      if (entry.isDirectory()) {
        // تخطي node_modules و .next
        if (entry.name === 'node_modules' || entry.name === '.next' || entry.name.startsWith('.')) {
          continue;
        }
        const newRelativePath = relativePath 
          ? `${relativePath}/${entry.name}` 
          : entry.name;
        scanRecursive(path.join(dir, entry.name), newRelativePath);
      }
    }
  }

  scanRecursive(appDir);
  return duplicates;
}

/**
 * الوظيفة الرئيسية
 */
function checkPageDuplicates(): CheckResult {
  const appDir = path.join(process.cwd(), 'src', 'app');

  if (!fs.existsSync(appDir)) {
    console.error('❌ مجلد app غير موجود:', appDir);
    process.exit(1);
  }

  console.log('🔍 بدء فحص ملفات الصفحات (Pages) في App Router...\n');

  // 1. اكتشاف الملفات المكررة
  const duplicates = detectDuplicates(appDir);
  console.log(`✓ تم فحص ازدواجية الملفات`);

  // 2. اكتشاف الملفات المشبوهة
  const suspiciousFiles = findSuspiciousFiles(appDir);
  console.log(`✓ تم فحص الملفات المشبوهة\n`);

  return {
    duplicates,
    suspiciousFiles,
    summary: {
      totalDuplicates: duplicates.length,
      totalSuspicious: suspiciousFiles.length,
    },
  };
}

/**
 * طباعة التقرير
 */
function printReport(result: CheckResult) {
  console.log('='.repeat(80));
  console.log('📊 تقرير فحص ازدواجية ملفات الصفحات (Pages)');
  console.log('='.repeat(80));
  console.log();

  // ملخص
  console.log('📈 الملخص:');
  console.log(`   • الملفات المكررة: ${result.summary.totalDuplicates}`);
  console.log(`   • الملفات المشبوهة: ${result.summary.totalSuspicious}`);
  console.log();

  // الملفات المكررة
  if (result.duplicates.length > 0) {
    console.log('⚠️  الملفات المكررة:');
    console.log('-'.repeat(80));
    result.duplicates.forEach((dup, index) => {
      console.log(`\n${index + 1}. المجلد: src/app/${dup.directory}`);
      console.log(`   المشكلة: ${dup.issue}`);
      if (dup.standardFile) {
        console.log(`   ✅ الملف القياسي: ${dup.standardFile}`);
      }
      console.log(`   ❌ الملفات المكررة (يجب حذفها):`);
      dup.duplicateFiles.forEach(file => {
        console.log(`      - ${file}`);
      });
    });
    console.log();
  }

  // الملفات المشبوهة
  if (result.suspiciousFiles.length > 0) {
    console.log('🔍 الملفات المشبوهة (تحتوي على أنماط مثل -enhanced, -new, -advanced):');
    console.log('-'.repeat(80));
    result.suspiciousFiles.forEach((file, index) => {
      console.log(`   ${index + 1}. src/app/${file}`);
    });
    console.log();
  }

  // النتيجة النهائية
  console.log('='.repeat(80));
  if (result.summary.totalDuplicates === 0 && result.summary.totalSuspicious === 0) {
    console.log('✅ لا توجد مشاكل مكتشفة!');
  } else {
    console.log('❌ تم اكتشاف مشاكل تحتاج إلى معالجة');
    console.log('\n💡 التوصيات:');
    console.log('   1. Next.js يستخدم فقط الملفات القياسية (page.tsx, layout.tsx)');
    console.log('   2. احذف جميع الملفات المكررة (page-enhanced.tsx, layout-new.tsx, etc.)');
