import path from 'path';
import fs from 'fs';
import { log, colors, removeDir, killProcess, runCommand } from './lib/script-utils';

async function main() {
    const args = process.argv.slice(2);
    const shouldBuild = args.includes('--build') || args.includes('-Build');

    log('\n=== Fixing Prisma EPERM Error ===', colors.cyan);

    // Step 1: Stop Node.js processes
    log('\n[1/5] Stopping Node.js processes...', colors.yellow);
    await killProcess('node');

    // Wait a bit for processes to fully release handles
    await new Promise(resolve => setTimeout(resolve, 2000));

    // Step 2: Clean Prisma cache
    log('\n[2/5] Cleaning Prisma cache...', colors.yellow);

    const nodeModules = path.join(process.cwd(), 'node_modules');
    const prismaCache = path.join(nodeModules, '.prisma');
    const prismaClientCache = path.join(nodeModules, '@prisma', 'client', '.prisma');

    // Attempt to remove .prisma directory with retries
    if (fs.existsSync(prismaCache)) {
        let success = false;
        let attempts = 0;
        const maxAttempts = 5;

        while (attempts < maxAttempts && !success) {
            try {
                fs.rmSync(prismaCache, { recursive: true, force: true });
                success = true;
                log('   Prisma cache cleaned successfully', colors.green);
            } catch (error) {
                attempts++;
                log(`   Attempt ${attempts} failed, waiting...`, colors.yellow);
                await new Promise(resolve => setTimeout(resolve, 2000));
            }
        }

        if (!success) {
            log('   Warning: Could not fully clean Prisma cache. Some files may be locked.', colors.red);
        }
    } else {
        log('   Prisma cache not found (already clean)', colors.gray);
    }

    // Clean client cache
    if (fs.existsSync(prismaClientCache)) {
        try {
            fs.rmSync(prismaClientCache, { recursive: true, force: true });
            log('   Prisma client cache cleaned', colors.green);
        } catch (error) {
            log('   Warning: Could not clean Prisma client cache', colors.yellow);
        }
    }

    // Step 3: Verify Prisma schema
    log('\n[3/5] Verifying Prisma schema...', colors.yellow);
    const schemaPath = path.join(process.cwd(), 'prisma', 'schema.prisma');
    if (!fs.existsSync(schemaPath)) {
        log('   Error: prisma/schema.prisma not found!', colors.red);
        process.exit(1);
    }
    log('   Prisma schema found', colors.green);

    // Step 4: Generate Prisma Client
    log('\n[4/5] Generating Prisma Client...', colors.yellow);
    process.env.PRISMA_GENERATE_SKIP_AUTOINSTALL = 'true';

    if (runCommand('npx prisma generate --schema=./prisma/schema.prisma')) {
        log('   Prisma Client generated successfully', colors.green);
    } else {
        log('   Error generating Prisma Client', colors.red);
        log('   Tip: Make sure all Node processes are stopped and try again', colors.yellow);
        process.exit(1);
    }

    // Step 5: Build (if requested)
    if (shouldBuild) {
        log('\n[5/5] Building Next.js application...', colors.yellow);
        if (runCommand('npm run build')) {
            log('\n[SUCCESS] Build completed successfully!', colors.green);
        } else {
            log('\n[ERROR] Build failed', colors.red);
            process.exit(1);
        }
    } else {
        log('\n[5/5] Skipping build (use --build flag to build)', colors.gray);
    }

    log('\n=== Done ===', colors.green);
}

main().catch(err => {
    console.error(err);
    process.exit(1);
});

import { execSync, exec } from 'child_process';
import fs from 'fs';
import path from 'path';
import os from 'os';
import net from 'net';

/**
 * Colors for console output
 */
export const colors = {
    reset: '\x1b[0m',
    red: '\x1b[31m',
    green: '\x1b[32m',
    yellow: '\x1b[33m',
    blue: '\x1b[34m',
    magenta: '\x1b[35m',
    cyan: '\x1b[36m',
    white: '\x1b[37m',
    gray: '\x1b[90m',
};

/**
 * Log a message with color
 */
export function log(message: string, color: string = colors.white) {
    console.log(`${color}${message}${colors.reset}`);
}

/**
 * Kill a process by name (cross-platform)
 */
export async function killProcess(processName: string): Promise<void> {
    log(`Stopping ${processName} processes...`, colors.yellow);

    const isWindows = os.platform() === 'win32';

    try {
        if (isWindows) {
            // PowerShell command to find and kill process
            // Using a more robust PowerShell command that handles errors gracefully
            const cmd = `powershell -Command "Get-Process | Where-Object {$_.ProcessName -like '*${processName}*'} | Stop-Process -Force -ErrorAction SilentlyContinue"`;
            execSync(cmd, { stdio: 'ignore' });
        } else {
            // Unix/Linux/macOS
            execSync(`pkill -f ${processName}`, { stdio: 'ignore' });
        }
        log(`✓ Stopped ${processName}`, colors.green);
    } catch (error) {
        // Ignore errors if process wasn't running
        // log(`No running ${processName} processes found or could not stop them.`, colors.gray);
    }
}

/**
 * Remove a directory recursively (cross-platform)
 */
export function removeDir(dirPath: string) {
    if (fs.existsSync(dirPath)) {
        log(`Removing ${dirPath}...`, colors.yellow);
        try {
            fs.rmSync(dirPath, { recursive: true, force: true });
            log(`✓ ${dirPath} cleared`, colors.green);
        } catch (error) {
            log(`✗ Failed to remove ${dirPath}: ${(error as Error).message}`, colors.red);
        }
    } else {
        log(`✓ ${dirPath} doesn't exist`, colors.gray);
    }
}

/**
 * Run a shell command and return output
 */
export function runCommand(command: string, cwd: string = process.cwd()): boolean {
    try {
        execSync(command, { stdio: 'inherit', cwd });
        return true;
    } catch (error) {
        return false;
    }
}

/**
 * Check if a file exists
 */
export function fileExists(filePath: string): boolean {
    return fs.existsSync(filePath);
}

/**
 * Read file content
 */
export function readFile(filePath: string): string | null {
    if (!fs.existsSync(filePath)) return null;
    return fs.readFileSync(filePath, 'utf-8');
}

/**
 * Write file content
 */
export function writeFile(filePath: string, content: string): void {
    fs.writeFileSync(filePath, content, 'utf-8');
}

/**
 * Check if a port is in use
 */
export function checkPort(port: number, host: string = 'localhost'): Promise<boolean> {
    return new Promise((resolve) => {
        const socket = new net.Socket();

        socket.setTimeout(2000);

        socket.on('connect', () => {
            socket.destroy();
            resolve(true);
        });

        socket.on('timeout', () => {
            socket.destroy();
            resolve(false);
        });

        socket.on('error', () => {
            socket.destroy();
            resolve(false);
        });

        socket.connect(port, host);
    });
}

