export default function BiometricManagement() {
  const { user } = useAuth();
  const setupTwoFactor = async () => {};
  const verifyTwoFactorSetup = async () => {};
  const disableTwoFactor = async () => {};
  const setupBiometricAuth = async () => {};
  const disableBiometricAuth = async () => {};
  const [isLoading, setIsLoading] = useState(false);
  const [credentials, setCredentials] = useState<BiometricCredential[]>([]);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [deviceName, setDeviceName] = useState('');
  const [verificationCode, setVerificationCode] = useState('');
  const [showVerification, setShowVerification] = useState(false);
  const [setupInProgress, setSetupInProgress] = useState(false);

  // Fetch biometric credentials
  const fetchCredentials = async () => {
    try {
      // Token is in httpOnly cookie - no need to send Authorization header
      const response = await fetch('/api/auth/biometric/credentials', {
        credentials: 'include',
      });

      if (response.ok) {
        const data = await response.json();
        setCredentials(data.credentials || []);
      }
    } catch (error) {
      logger.error('Error fetching biometric credentials:', error);
    }
  };

  useEffect(() => {
    if (user) {
      fetchCredentials();
    }
  }, [user]);

  const handleSetupBiometric = async () => {
    if (!deviceName.trim()) {
      toast.error('يرجى إدخال اسم الجهاز');
      return;
    }

    setIsLoading(true);
    try {
      // In a real implementation, this would use WebAuthn API
      // For now, we'll simulate it
      // Token is in httpOnly cookie - no need to send Authorization header
      const response = await fetch('/api/auth/biometric/setup', {
        method: 'POST',
        credentials: 'include',
      });

      if (!response.ok) {
        throw new Error('Failed to setup biometric authentication');
      }

      const data = await response.json();

      // In a real implementation, we would use the challenge to create a credential
      // For now, we'll just simulate it
      setSetupInProgress(true);
      toast.success('تم إعداد المصادقة البيومترية بنجاح');

      // Refresh credentials list
      fetchCredentials();
      setIsDialogOpen(false);
      setDeviceName('');
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : 'فشل إعداد المصادقة البيومترية';
      toast.error(message);
    } finally {
      setIsLoading(false);
    }
  };

  const handleRemoveCredential = async (credentialId: string) => {
    setIsLoading(true);
    try {
      // Token is in httpOnly cookie - no need to send Authorization header
      const response = await fetch('/api/auth/biometric/credentials', {
        method: 'DELETE',
        headers: {
          'Content-Type': 'application/json',
        },
        credentials: 'include',
        body: JSON.stringify({ credentialId })
      });

      if (!response.ok) {
        throw new Error('Failed to remove biometric credential');
      }

      toast.success('تم إزالة جهاز المصادقة البيومترية بنجاح');

      // Refresh credentials list
      fetchCredentials();
