'use client';

import { useEffect, useRef, useState } from 'react';
import { Loader2, Shield } from 'lucide-react';

interface CaptchaWidgetProps {
  siteKey?: string;
  provider?: 'hcaptcha' | 'recaptcha';
  onVerify: (token: string) => void;
  onError?: (error: string) => void;
  theme?: 'light' | 'dark';
  size?: 'normal' | 'compact';
}

export function CaptchaWidget({
  siteKey,
  provider = 'hcaptcha',
  onVerify,
  onError,
  theme = 'dark',
  size = 'normal',
}: CaptchaWidgetProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const widgetRef = useRef<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (!siteKey || !containerRef.current) {
      setIsLoading(false);
      setError('مفتاح CAPTCHA غير متوفر');
      return;
    }

    // Load CAPTCHA script
    const scriptId = `${provider}-script`;
    let script = document.getElementById(scriptId) as HTMLScriptElement;

    if (!script) {
      script = document.createElement('script');
      script.id = scriptId;
      
      if (provider === 'hcaptcha') {
        script.src = 'https://js.hcaptcha.com/1/api.js';
        script.async = true;
        script.defer = true;
      } else if (provider === 'recaptcha') {
        script.src = `https://www.google.com/recaptcha/api.js?render=${siteKey}`;
        script.async = true;
        script.defer = true;
      }

      script.onload = () => {
        renderWidget();
      };

      script.onerror = () => {
        setIsLoading(false);
        const errorMsg = 'فشل تحميل CAPTCHA';
        setError(errorMsg);
        onError?.(errorMsg);
      };

      document.head.appendChild(script);
    } else {
      renderWidget();
    }

    function renderWidget() {
      if (!containerRef.current || !siteKey) return;

      try {
        if (provider === 'hcaptcha') {
          if (window.hcaptcha) {
            widgetRef.current = window.hcaptcha.render(containerRef.current, {
              sitekey: siteKey,
              theme,
              size,
              callback: (token: string) => {
                setIsLoading(false);
                onVerify(token);
              },
              'error-callback': (err: unknown) => {
                setIsLoading(false);
                const errorMsg = 'فشل التحقق من CAPTCHA';
                setError(errorMsg);
                onError?.(errorMsg);
              },
            });
            setIsLoading(false);
          }
        } else if (provider === 'recaptcha') {
          if (window.grecaptcha) {
            widgetRef.current = window.grecaptcha.render(containerRef.current, {
              sitekey: siteKey,
              theme,
              size,
              callback: (token: string) => {
                setIsLoading(false);
                onVerify(token);
              },
              'error-callback': () => {
                setIsLoading(false);
                const errorMsg = 'فشل التحقق من CAPTCHA';
                setError(errorMsg);
                onError?.(errorMsg);
              },
            });
            setIsLoading(false);
          }
        }
      } catch (err) {
        setIsLoading(false);
        const errorMsg = 'خطأ في تهيئة CAPTCHA';
        setError(errorMsg);
        onError?.(errorMsg);
      }
    }

    // Cleanup
    return () => {
      if (widgetRef.current && provider === 'hcaptcha') {
        try {
          window.hcaptcha?.reset(widgetRef.current);
        } catch (err) {
          // Ignore cleanup errors
        }
      }
    };
  }, [siteKey, provider, theme, size, onVerify, onError]);

  if (error) {
    return (
      <div className="rounded-xl bg-red-500/10 border border-red-500/30 p-4 flex items-center gap-3">
        <Shield className="h-5 w-5 text-red-400" />
        <div className="text-sm text-red-300">
          <p className="font-semibold">خطأ في CAPTCHA</p>
          <p className="text-xs">{error}</p>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-3">
      <div className="flex items-center gap-2 text-sm text-slate-300">
        <Shield className="h-4 w-4" />
        <span>تحقق من أنك لست روبوتاً</span>
      </div>
      {isLoading && (
        <div className="flex items-center justify-center py-4">
          <Loader2 className="h-5 w-5 animate-spin text-indigo-400" />
        </div>
      )}
      <div ref={containerRef} className="flex justify-center" />
    </div>
  );
}

// Type declarations for CAPTCHA libraries
interface HCaptchaOptions {
  sitekey: string;
  theme?: 'light' | 'dark';
  size?: 'normal' | 'compact';
  callback?: (token: string) => void;
  'error-callback'?: (err: unknown) => void;
}

interface ReCaptchaOptions {
  sitekey: string;
  theme?: 'light' | 'dark';
  size?: 'normal' | 'compact';
  callback?: (token: string) => void;
  'error-callback'?: () => void;
}

declare global {
  interface Window {
    hcaptcha?: {
      render: (container: HTMLElement, options: HCaptchaOptions) => string;
      reset: (widgetId: string) => void;
      execute: (widgetId: string) => void;
    };
    grecaptcha?: {
      render: (container: HTMLElement, options: ReCaptchaOptions) => string;
      reset: (widgetId: string) => void;
      execute: (widgetId: string) => Promise<string>;
    };
  }
}

'use client';

import { useState, useEffect } from 'react';
import { useUnifiedAuth } from '@/contexts/auth-context';
import { toast } from 'sonner';
import { Eye, EyeOff, Lock, Loader2, CheckCircle2, XCircle } from 'lucide-react';
import { getPasswordStrengthDisplay } from '../_utils/password-strength';
import { parseApiError, handleNetworkError, createFetchWithTimeout } from '../_utils/error-handling';
// Token is in httpOnly cookie - no need to import getTokenFromStorage

import { logger } from '@/lib/logger';

export default function ChangePassword() {
  const { user } = useUnifiedAuth();
  const [formData, setFormData] = useState({
    currentPassword: '',
    newPassword: '',
    confirmPassword: '',
  });
  const [showPasswords, setShowPasswords] = useState({
    current: false,
    new: false,
    confirm: false,
  });
  const [isLoading, setIsLoading] = useState(false);
  const [passwordStrength, setPasswordStrength] = useState(
    getPasswordStrengthDisplay('')
  );

  useEffect(() => {
    if (formData.newPassword) {
      setPasswordStrength(getPasswordStrengthDisplay(formData.newPassword));
    } else {
      setPasswordStrength(getPasswordStrengthDisplay(''));
    }
  }, [formData.newPassword]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    // التحقق من البيانات
    if (!formData.currentPassword || !formData.newPassword || !formData.confirmPassword) {
      toast.error('يرجى ملء جميع الحقول');
      return;
    }

    if (formData.newPassword.length < 8) {
      toast.error('كلمة المرور يجب أن تكون على الأقل 8 أحرف');
      return;
    }

    if (formData.newPassword !== formData.confirmPassword) {
      toast.error('كلمة المرور الجديدة وتأكيدها غير متطابقين');
      return;
    }

    if (formData.currentPassword === formData.newPassword) {
      toast.error('كلمة المرور الجديدة يجب أن تكون مختلفة عن الحالية');
      return;
    }

    setIsLoading(true);

    try {
      // Token is in httpOnly cookie - no need to send Authorization header
      const response = await createFetchWithTimeout(
        '/api/auth/change-password',
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          credentials: 'include',
          body: JSON.stringify({
            currentPassword: formData.currentPassword,
            newPassword: formData.newPassword,
          }),
        }
      );

      if (!response.ok) {
        const apiError = await parseApiError(response);
        toast.error(apiError?.error || 'فشل تغيير كلمة المرور');
        setIsLoading(false);
        return;
      }

      // Read response text first to check if it's HTML
      const text = await response.text();
      
      // Check if response is HTML (error page)
      if (text.trim().startsWith('<!DOCTYPE') || text.trim().startsWith('<html')) {
        logger.error('Server returned HTML instead of JSON');
        toast.error('خطأ في الخادم: تم إرجاع HTML بدلاً من JSON');
        setIsLoading(false);
        return;
      }

      // Try to parse as JSON
      try {
        const data = JSON.parse(text);
        toast.success('تم تغيير كلمة المرور بنجاح');
        
        // مسح النموذج
        setFormData({
          currentPassword: '',
          newPassword: '',
          confirmPassword: '',
        });
        setPasswordStrength(getPasswordStrengthDisplay(''));
      } catch (parseError) {
        logger.error('Error parsing JSON:', parseError);
        toast.error('فشل في معالجة استجابة الخادم');
      }
    } catch (error) {
      const networkError = handleNetworkError(error);
      logger.error('Change password error:', error);
      toast.error(networkError.error);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="rounded-3xl bg-white/10 p-8 shadow-2xl backdrop-blur-xl">
      <div className="mb-6 text-center">
        <h2 className="text-2xl font-bold text-white">تغيير كلمة المرور</h2>
        <p className="mt-2 text-sm text-slate-300">
          أدخل كلمة المرور الحالية والجديدة
        </p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-5">
        {/* Current Password */}
        <div>
          <label className="mb-2 block text-sm font-medium text-slate-200">
            كلمة المرور الحالية
          </label>
          <div className="relative">
            <Lock className="absolute right-4 top-1/2 h-5 w-5 -translate-y-1/2 text-slate-400" />
            <input
              type={showPasswords.current ? 'text' : 'password'}
              name="currentPassword"
              value={formData.currentPassword}
              onChange={handleInputChange}
              placeholder="••••••••"
              className="w-full rounded-xl bg-white/10 py-3 pr-12 pl-12 text-white placeholder-slate-400 focus:bg-white/20 focus:outline-none focus:ring-2 focus:ring-indigo-400"
              required
            />
            <button
              type="button"
              onClick={() => setShowPasswords((prev) => ({ ...prev, current: !prev.current }))}
              className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-200"
            >
              {showPasswords.current ? (
                <EyeOff className="h-5 w-5" />
              ) : (
                <Eye className="h-5 w-5" />
              )}
            </button>
          </div>
        </div>

        {/* New Password */}
        <div>
          <label className="mb-2 block text-sm font-medium text-slate-200">
            كلمة المرور الجديدة
          </label>
          <div className="relative">
            <Lock className="absolute right-4 top-1/2 h-5 w-5 -translate-y-1/2 text-slate-400" />
            <input
              type={showPasswords.new ? 'text' : 'password'}
              name="newPassword"
              value={formData.newPassword}
              onChange={handleInputChange}
              placeholder="••••••••"
              className="w-full rounded-xl bg-white/10 py-3 pr-12 pl-12 text-white placeholder-slate-400 focus:bg-white/20 focus:outline-none focus:ring-2 focus:ring-indigo-400"
              required
              minLength={8}
            />
            <button
              type="button"
              onClick={() => setShowPasswords((prev) => ({ ...prev, new: !prev.new }))}
              className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-200"
            >
              {showPasswords.new ? (
                <EyeOff className="h-5 w-5" />
              ) : (
                <Eye className="h-5 w-5" />
              )}
            </button>
          </div>

          {/* Password Strength Indicator */}
          {formData.newPassword && (
            <div className="mt-2">
              <div className="flex items-center gap-2 mb-1">
                <div className="flex-1 h-2 bg-white/10 rounded-full overflow-hidden">
                  <div
                    className={`h-full transition-all ${passwordStrength.color}`}
                    style={{ width: `${passwordStrength.score}%` }}
                  />
                </div>
                <span className="text-xs text-slate-300">
                  {passwordStrength.label}
                </span>
              </div>
              <div className="text-xs text-slate-400 space-y-1 mt-2">
                <div className="flex items-center gap-2">
                  {passwordStrength.checks.minLength ? (
                    <CheckCircle2 className="h-3 w-3 text-green-400" />
                  ) : (
                    <XCircle className="h-3 w-3 text-red-400" />
                  )}
                  <span>8 أحرف على الأقل</span>
                </div>
                <div className="flex items-center gap-2">
                  {passwordStrength.checks.hasUpper && passwordStrength.checks.hasLower ? (
                    <CheckCircle2 className="h-3 w-3 text-green-400" />
                  ) : (
                    <XCircle className="h-3 w-3 text-red-400" />
                  )}
                  <span>أحرف كبيرة وصغيرة</span>
                </div>
                <div className="flex items-center gap-2">
                  {passwordStrength.checks.hasNumber ? (
                    <CheckCircle2 className="h-3 w-3 text-green-400" />
                  ) : (
                    <XCircle className="h-3 w-3 text-red-400" />
                  )}
                  <span>أرقام</span>
                </div>
                <div className="flex items-center gap-2">
                  {passwordStrength.checks.hasSpecial ? (
                    <CheckCircle2 className="h-3 w-3 text-green-400" />
                  ) : (
                    <XCircle className="h-3 w-3 text-red-400" />
                  )}
                  <span>رمز خاص</span>
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Confirm Password */}
        <div>
          <label className="mb-2 block text-sm font-medium text-slate-200">
            تأكيد كلمة المرور الجديدة
          </label>
          <div className="relative">
            <Lock className="absolute right-4 top-1/2 h-5 w-5 -translate-y-1/2 text-slate-400" />
            <input
              type={showPasswords.confirm ? 'text' : 'password'}
              name="confirmPassword"
              value={formData.confirmPassword}
              onChange={handleInputChange}
              placeholder="••••••••"
              className="w-full rounded-xl bg-white/10 py-3 pr-12 pl-12 text-white placeholder-slate-400 focus:bg-white/20 focus:outline-none focus:ring-2 focus:ring-indigo-400"
              required
            />
            <button
              type="button"
              onClick={() => setShowPasswords((prev) => ({ ...prev, confirm: !prev.confirm }))}
              className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-200"
            >
              {showPasswords.confirm ? (
                <EyeOff className="h-5 w-5" />
              ) : (
                <Eye className="h-5 w-5" />
              )}
            </button>
          </div>
          {formData.confirmPassword && formData.newPassword !== formData.confirmPassword && (
            <p className="mt-1 text-xs text-red-400">كلمة المرور غير متطابقة</p>
          )}
        </div>

        {/* Submit Button */}
        <button
          type="submit"
          disabled={isLoading}
          className="w-full rounded-xl bg-gradient-to-r from-indigo-500 to-purple-600 px-6 py-4 font-semibold text-white shadow-lg transition hover:from-indigo-600 hover:to-purple-700 disabled:opacity-50 disabled:cursor-not-allowed"
        >
          {isLoading ? (
            <span className="flex items-center justify-center gap-2">
              <Loader2 className="h-5 w-5 animate-spin" />
              جارٍ تغيير كلمة المرور...
            </span>
          ) : (
            'تغيير كلمة المرور'
          )}
        </button>
      </form>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { useUnifiedAuth } from '@/contexts/auth-context';
import { useRouter } from 'next/navigation';
import {
  Shield,
  Mail,
  Smartphone,
  CheckCircle2,
  ArrowRight,
  Loader2,
  XCircle,
  Lock,
} from 'lucide-react';
import { toast } from 'sonner';
import TOTPSetup from './TOTPSetup';

type OnboardingStep = 
  | 'welcome'
  | 'email-verification'
  | 'password-setup'
  | 'two-factor'
  | 'recovery-codes'
  | 'complete';

interface SecurityOnboardingProps {
  onComplete?: () => void;
  skipable?: boolean;
}

export default function SecurityOnboarding({
  onComplete,
  skipable = false,
}: SecurityOnboardingProps) {
  const { user, refreshUser } = useUnifiedAuth();
  const router = useRouter();
  const [currentStep, setCurrentStep] = useState<OnboardingStep>('welcome');
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    if (!user) {
      router.push('/login');
      return;
    }

    // Determine starting step based on user status
    if (!user.emailVerified) {
      setCurrentStep('email-verification');
    } else if (!user.twoFactorEnabled) {
      setCurrentStep('two-factor');
    } else {
      setCurrentStep('complete');
    }
  }, [user, router]);

  const handleNext = () => {
    const steps: OnboardingStep[] = [
      'welcome',
      'email-verification',
      'password-setup',
      'two-factor',
      'recovery-codes',
      'complete',
    ];
    const currentIndex = steps.indexOf(currentStep);
    if (currentIndex < steps.length - 1) {
      setCurrentStep(steps[currentIndex + 1]);
    }
  };

  const handleSkip = () => {
    if (skipable) {
      onComplete?.();
    }
  };

  const handleResendVerification = async () => {
    setIsLoading(true);
    try {
      const response = await fetch('/api/auth/send-verification', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
      });

      if (response.ok) {
        toast.success('تم إرسال رابط التفعيل إلى بريدك الإلكتروني');
      } else {
        toast.error('فشل إرسال رابط التفعيل');
      }
    } catch (error) {
      toast.error('حدث خطأ أثناء إرسال رابط التفعيل');
    } finally {
      setIsLoading(false);
    }
  };

  const renderStep = () => {
    switch (currentStep) {
      case 'welcome':
        return (
          <div className="text-center space-y-6">
            <div className="mx-auto flex h-20 w-20 items-center justify-center rounded-full bg-indigo-500/20">
              <Shield className="h-10 w-10 text-indigo-300" />
            </div>
            <div>
              <h2 className="text-2xl font-bold text-white">
                مرحباً بك في ثناوي!
              </h2>
              <p className="mt-2 text-sm text-slate-300">
                دعنا نؤمن حسابك خطوة بخطوة
              </p>
            </div>
            <div className="rounded-xl bg-white/5 p-6 text-right space-y-4">
              <div className="flex items-start gap-3">
                <Mail className="h-5 w-5 text-slate-400 mt-0.5" />
                <div className="text-sm">
                  <p className="font-semibold text-white">التحقق من البريد الإلكتروني</p>
                  <p className="text-slate-300">تأكيد ملكية بريدك الإلكتروني</p>
                </div>
              </div>
              <div className="flex items-start gap-3">
                <Lock className="h-5 w-5 text-slate-400 mt-0.5" />
                <div className="text-sm">
                  <p className="font-semibold text-white">كلمة مرور قوية</p>
                  <p className="text-slate-300">حماية حسابك بكلمة مرور آمنة</p>
                </div>
              </div>
              <div className="flex items-start gap-3">
                <Smartphone className="h-5 w-5 text-slate-400 mt-0.5" />
                <div className="text-sm">
