import { useState, useEffect, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import dynamic from 'next/dynamic';
import {
  MapPin,
  Globe,
  Clock,
  AlertTriangle,
  CheckCircle,
  Monitor,
  Smartphone,
  Loader2,
  ChevronDown,
  ChevronUp,
  Shield,
} from 'lucide-react';
import { cn } from '@/lib/utils';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { getGeoLocationService } from '@/lib/security/geo/geo-location-service';
import type { GeoLocation, GeoLocationSession } from '@/lib/security/geo/geo-location-service';
import { logger } from '@/lib/logger';

// Dynamically import map components (Leaflet requires window)
const MapContainer = dynamic(
  () => import('react-leaflet').then((mod) => mod.MapContainer),
  { ssr: false }
) as React.ComponentType<any>;
const TileLayer = dynamic(
  () => import('react-leaflet').then((mod) => mod.TileLayer),
  { ssr: false }
) as React.ComponentType<any>;
const Marker = dynamic(
  () => import('react-leaflet').then((mod) => mod.Marker),
  { ssr: false }
) as React.ComponentType<any>;
const Popup = dynamic(
  () => import('react-leaflet').then((mod) => mod.Popup),
  { ssr: false }
) as React.ComponentType<any>;
const Circle = dynamic(
  () => import('react-leaflet').then((mod) => mod.Circle),
  { ssr: false }
) as React.ComponentType<any>;

interface GeoActivityMapProps {
  sessions?: GeoLocationSession[];
  showAllLocations?: boolean;
  height?: string;
  className?: string;
}

// Default sessions for demo
const DEFAULT_SESSIONS: GeoLocationSession[] = [];

export function GeoActivityMap({
  sessions = DEFAULT_SESSIONS,
  showAllLocations = true,
  height = '400px',
  className,
}: GeoActivityMapProps) {
  const [isLoaded, setIsLoaded] = useState(false);
  const [selectedSession, setSelectedSession] = useState<GeoLocationSession | null>(null);
  const [isExpanded, setIsExpanded] = useState(false);
  const [loadingSessions, setLoadingSessions] = useState(true);
  const [activeSessions, setActiveSessions] = useState<GeoLocationSession[]>(sessions);
  
  const geoService = getGeoLocationService();

  // Load sessions from API
  useEffect(() => {
    const loadSessions = async () => {
      setLoadingSessions(true);
      try {
        const response = await fetch('/api/auth/sessions/geo');
        if (response.ok) {
          const data = await response.json();
          setActiveSessions(data.sessions || []);
        }
      } catch (error) {
        logger.error('Failed to load geo sessions:', error);
      } finally {
        setLoadingSessions(false);
        setIsLoaded(true);
      }
    };

    loadSessions();
  }, []);

  // Calculate map center
  const mapCenter = useMemo(() => {
    if (activeSessions.length === 0) {
      return { lat: 25, lng: 45 }; // Default to Middle East
    }

    const validSessions = activeSessions.filter(
      s => s.location.lat !== 0 && s.location.lng !== 0
    );

    if (validSessions.length === 0) {
      return { lat: 25, lng: 45 };
    }

    const avgLat = validSessions.reduce((sum, s) => sum + s.location.lat, 0) / validSessions.length;
    const avgLng = validSessions.reduce((sum, s) => sum + s.location.lng, 0) / validSessions.length;

    return { lat: avgLat, lng: avgLng };
  }, [activeSessions]);

  // Get unique countries
  const uniqueCountries = useMemo(() => {
    const countries = new Set(activeSessions.map(s => s.location.country));
    return Array.from(countries);
  }, [activeSessions]);

  // Get suspicious sessions
  const suspiciousSessions = useMemo(() => {
    return activeSessions.filter(s => s.isSuspicious);
  }, [activeSessions]);

  // Format relative time
  const formatRelativeTime = (date: Date) => {
    const now = new Date();
    const diff = now.getTime() - new Date(date).getTime();
    const minutes = Math.floor(diff / 60000);
    const hours = Math.floor(minutes / 60);
    const days = Math.floor(hours / 24);

    if (minutes < 1) return 'الآن';
    if (minutes < 60) return `منذ ${minutes} دقيقة`;
    if (hours < 24) return `منذ ${hours} ساعة`;
    return `منذ ${days} يوم`;
  };

  if (!isLoaded || loadingSessions) {
    return (
      <Card className={className}>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Globe className="h-5 w-5 text-primary" />
            خريطة النشاط
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div 
            className="flex items-center justify-center bg-muted/50 rounded-lg"
            style={{ height }}
          >
            <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
          </div>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card className={className}>
      <CardHeader className="pb-2">
        <div className="flex items-start justify-between">
          <div>
            <CardTitle className="flex items-center gap-2">
              <Globe className="h-5 w-5 text-primary" />
              خريطة النشاط الجغرافية
            </CardTitle>
            <CardDescription className="mt-1">
              مواقع تسجيل الدخول إلى حسابك
            </CardDescription>
          </div>
          
          {/* Stats badges */}
          <div className="flex gap-2">
            <Badge variant="outline" className="gap-1">
              <MapPin className="h-3 w-3" />
              {activeSessions.length} جلسة
            </Badge>
            <Badge variant="outline" className="gap-1">
              <Globe className="h-3 w-3" />
              {uniqueCountries.length} دولة
            </Badge>
            {suspiciousSessions.length > 0 && (
              <Badge variant="destructive" className="gap-1">
                <AlertTriangle className="h-3 w-3" />
                {suspiciousSessions.length} مشبوهة
              </Badge>
            )}
          </div>
        </div>
      </CardHeader>

      <CardContent className="space-y-4">
        {/* Map */}
        <div 
          className="rounded-lg overflow-hidden border relative"
          style={{ height }}
        >
          {typeof window !== 'undefined' && (
            <MapContainer
              center={[mapCenter.lat, mapCenter.lng]}
              zoom={3}
              style={{ height: '100%', width: '100%' }}
              scrollWheelZoom={true}
            >
              <TileLayer
                attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
                url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
              />

              {activeSessions.map((session) => (
                session.location.lat !== 0 && (
                  <Marker
                    key={session.sessionId}
                    position={[session.location.lat, session.location.lng]}
                    eventHandlers={{
                      click: () => setSelectedSession(session),
                    }}
                  >
                    <Popup>
                      <div className="text-sm space-y-1 min-w-[200px]">
                        <div className="font-bold flex items-center gap-1">
                          {geoService.getCountryFlag(session.location.countryCode)}
                          {session.location.city}, {session.location.country}
                        </div>
                        <div className="text-muted-foreground flex items-center gap-1">
                          <Clock className="h-3 w-3" />
                          {formatRelativeTime(session.timestamp)}
                        </div>
                        {session.device && (
                          <div className="text-muted-foreground flex items-center gap-1">
                            <Monitor className="h-3 w-3" />
                            {session.device}
                          </div>
                        )}
                        {session.isCurrentSession && (
                          <Badge variant="secondary" className="mt-1">
                            الجلسة الحالية
                          </Badge>
                        )}
                        {session.isSuspicious && (
                          <Badge variant="destructive" className="mt-1">
                            نشاط مشبوه
                          </Badge>
                        )}
                      </div>
                    </Popup>
                  </Marker>
                )
              ))}

              {/* Highlight suspicious areas */}
              {suspiciousSessions.map((session) => (
                session.location.lat !== 0 && (
                  <Circle
                    key={`circle-${session.sessionId}`}
                    center={[session.location.lat, session.location.lng]}
                    radius={50000}
                    pathOptions={{
                      color: 'red',
                      fillColor: 'red',
                      fillOpacity: 0.1,
                    }}
                  />
                )
              ))}
            </MapContainer>
          )}

          {/* Current location indicator */}
          {activeSessions.some(s => s.isCurrentSession) && (
            <div className="absolute bottom-4 left-4 z-[1000] bg-white dark:bg-gray-800 rounded-lg shadow-lg p-2 text-xs">
              <div className="flex items-center gap-1.5">
                <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse" />
                <span>موقعك الحالي</span>
              </div>
            </div>
          )}
        </div>

        {/* Session list */}
        <div>
          <Button
            variant="ghost"
            size="sm"
            onClick={() => setIsExpanded(!isExpanded)}
            className="w-full justify-between"
          >
            <span className="flex items-center gap-2">
              <Shield className="h-4 w-4" />
              قائمة الجلسات ({activeSessions.length})
            </span>
            {isExpanded ? (
              <ChevronUp className="h-4 w-4" />
            ) : (
              <ChevronDown className="h-4 w-4" />
            )}
          </Button>

          <AnimatePresence>
            {isExpanded && (
              <motion.div
                initial={{ height: 0, opacity: 0 }}
                animate={{ height: 'auto', opacity: 1 }}
                exit={{ height: 0, opacity: 0 }}
                className="overflow-hidden"
              >
                <div className="space-y-2 mt-2 max-h-[300px] overflow-y-auto">
                  {activeSessions.map((session) => (
                    <div
                      key={session.sessionId}
                      className={cn(
                        'p-3 rounded-lg border flex items-center justify-between',
                        session.isCurrentSession && 'bg-green-50 dark:bg-green-900/20 border-green-200',
                        session.isSuspicious && 'bg-red-50 dark:bg-red-900/20 border-red-200'
                      )}
                    >
                      <div className="flex items-center gap-3">
                        <span className="text-2xl">
                          {geoService.getCountryFlag(session.location.countryCode)}
                        </span>
                        <div>
                          <p className="font-medium text-sm">
                            {session.location.city}, {session.location.country}
                          </p>
                          <p className="text-xs text-muted-foreground flex items-center gap-1">
                            <Clock className="h-3 w-3" />
                            {formatRelativeTime(session.timestamp)}
                            {session.device && (
                              <>
                                <span className="mx-1">•</span>
                                {session.device}
                              </>
                            )}
                          </p>
                        </div>
                      </div>

                      <div className="flex items-center gap-2">
                        {session.isCurrentSession && (
                          <Badge variant="outline" className="bg-green-100 text-green-700 border-green-300">
                            <CheckCircle className="h-3 w-3 mr-1" />
                            الحالية
                          </Badge>
                        )}
                        {session.isSuspicious && (
                          <Badge variant="destructive">
                            <AlertTriangle className="h-3 w-3 mr-1" />
                            مشبوهة
                          </Badge>
                        )}
                      </div>
                    </div>
                  ))}

                  {activeSessions.length === 0 && (
                    <div className="text-center py-8 text-muted-foreground">
                      <Globe className="h-8 w-8 mx-auto mb-2 opacity-50" />
                      <p>لا توجد جلسات مسجلة</p>
                    </div>
                  )}
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </CardContent>
    </Card>
  );
}

export default GeoActivityMap;

'use client';

/**
 * 🎨 ModernLoginCard - بطاقة تسجيل الدخول العصرية
 * 
 * تصميم احترافي مع:
 * - Glassmorphism
 * - Animations
 * - Social Login
 * - Biometric Support
 */

import { useState, FormEvent } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import Link from 'next/link';
import {
  Mail,
  Lock,
  Eye,
  EyeOff,
  ArrowRight,
  Fingerprint,
  Loader2,
  AlertCircle,
  Sparkles,
  X,
  CheckCircle,
} from 'lucide-react';
import { cn } from '@/lib/utils';
import { SocialButton } from '../shared';
import { useUnifiedAuth } from '@/contexts/auth-context';

interface ModernLoginCardProps {
  onSuccess?: () => void;
  onForgotPassword?: () => void;
  onRegister?: () => void;
  showSocialLogin?: boolean;
  showBiometric?: boolean;
  defaultEmail?: string;
}

export function ModernLoginCard({
  onSuccess,
  onForgotPassword,
  onRegister,
  showSocialLogin = true,
  showBiometric = true,
  defaultEmail = '',
}: ModernLoginCardProps) {
  const { loginWithCredentials, loginWithSocial, isLoading: authLoading } = useUnifiedAuth();
  
  const [email, setEmail] = useState(defaultEmail);
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [focusedField, setFocusedField] = useState<string | null>(null);
  
  // Forgot Password Popup State
  const [showForgotPasswordPopup, setShowForgotPasswordPopup] = useState(false);
  const [forgotPasswordEmail, setForgotPasswordEmail] = useState('');
  const [forgotPasswordLoading, setForgotPasswordLoading] = useState(false);
  const [forgotPasswordSuccess, setForgotPasswordSuccess] = useState(false);
  const [forgotPasswordError, setForgotPasswordError] = useState<string | null>(null);

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    setError(null);
    setIsLoading(true);

    try {
      const result = await loginWithCredentials(email, password, rememberMe);
      
      if (result.requiresTwoFactor) {
        // Handle 2FA - would redirect or show 2FA form
        window.location.href = `/login/2fa?attemptId=${result.loginAttemptId}`;
        return;
      }
      
      onSuccess?.();
    } catch (err) {
      const message = err instanceof Error ? err.message : 'حدث خطأ في تسجيل الدخول';
      setError(message);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSocialLogin = async (provider: 'google' | 'github' | 'twitter') => {
    try {
      await loginWithSocial(provider);
    } catch (err) {
      const message = err instanceof Error ? err.message : 'حدث خطأ';
      setError(message);
    }
  };

  const handleBiometricLogin = async () => {
    setError(null);
    setIsLoading(true);
    
    try {
      // Check if WebAuthn is supported
      if (!window.PublicKeyCredential) {
        throw new Error('المتصفح لا يدعم المصادقة البيومترية');
      }
      
      const response = await fetch('/api/auth/passkey/authenticate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
      });
      
      const data = await response.json();
      
      if (!response.ok) {
        throw new Error(data.error || 'فشل في المصادقة البيومترية');
      }
      
      // Handle WebAuthn authentication
      // This would be implemented with the actual WebAuthn API
      onSuccess?.();
    } catch (err) {
      const message = err instanceof Error ? err.message : 'حدث خطأ';
      setError(message);
    } finally {
      setIsLoading(false);
    }
  };

  const openForgotPasswordPopup = () => {
    setForgotPasswordEmail(email); // Pre-fill with current email if available
    setForgotPasswordSuccess(false);
    setForgotPasswordError(null);
    setShowForgotPasswordPopup(true);
    onForgotPassword?.(); // Still call the callback if provided
  };

  const handleForgotPassword = async (e: FormEvent) => {
    e.preventDefault();
    setForgotPasswordError(null);
    setForgotPasswordLoading(true);

    try {
      const response = await fetch('/api/auth/forgot-password', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email: forgotPasswordEmail }),
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.error || 'حدث خطأ أثناء إرسال الطلب');
      }

      setForgotPasswordSuccess(true);
    } catch (err) {
      const message = err instanceof Error ? err.message : 'حدث خطأ';
      setForgotPasswordError(message);
    } finally {
      setForgotPasswordLoading(false);
    }
  };

  const closeForgotPasswordPopup = () => {
    setShowForgotPasswordPopup(false);
    setForgotPasswordEmail('');
    setForgotPasswordSuccess(false);
    setForgotPasswordError(null);
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 30, scale: 0.95 }}
      animate={{ opacity: 1, y: 0, scale: 1 }}
      transition={{ duration: 0.5, ease: 'easeOut' }}
      className="w-full max-w-md"
    >
      <div className="relative overflow-hidden rounded-3xl bg-gradient-to-br from-slate-900/90 to-slate-800/90 backdrop-blur-xl border border-white/10 shadow-2xl">
        {/* Decorative elements */}
        <div className="absolute -top-32 -right-32 h-64 w-64 rounded-full bg-gradient-to-br from-indigo-500/30 to-purple-500/30 blur-3xl" />
        <div className="absolute -bottom-32 -left-32 h-64 w-64 rounded-full bg-gradient-to-br from-purple-500/30 to-pink-500/30 blur-3xl" />
        
        <div className="relative z-10 p-8">
          {/* Header */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.1 }}
            className="text-center mb-8"
          >
            {/* Logo */}
            <motion.div
              initial={{ scale: 0 }}
              animate={{ scale: 1 }}
              transition={{ type: 'spring', delay: 0.2 }}
              className="mx-auto mb-4 relative inline-block"
            >
              <div className="flex h-16 w-16 items-center justify-center rounded-2xl bg-gradient-to-br from-indigo-500 to-purple-600 shadow-lg shadow-indigo-500/30">
                <Sparkles className="h-8 w-8 text-white" />
              </div>
              <motion.div
                animate={{ 
                  scale: [1, 1.2, 1],
                  opacity: [0.5, 1, 0.5]
                }}
                transition={{ duration: 2, repeat: Infinity }}
                className="absolute -inset-1 rounded-2xl bg-gradient-to-br from-indigo-500 to-purple-600 blur-lg opacity-50"
              />
            </motion.div>

            <h1 className="text-2xl font-bold text-white mb-2">
              مرحباً بعودتك! 👋
            </h1>
            <p className="text-sm text-slate-400">
              سجّل دخولك للمتابعة
            </p>
          </motion.div>

          {/* Error Alert */}
          <AnimatePresence>
            {error && (
              <motion.div
                initial={{ opacity: 0, y: -10, height: 0 }}
                animate={{ opacity: 1, y: 0, height: 'auto' }}
                exit={{ opacity: 0, y: -10, height: 0 }}
                className="mb-6 rounded-xl bg-red-500/10 border border-red-500/30 p-4 flex items-start gap-3"
              >
                <AlertCircle className="h-5 w-5 text-red-400 flex-shrink-0 mt-0.5" />
                <div>
                  <p className="text-sm text-red-400">{error}</p>
                </div>
              </motion.div>
            )}
          </AnimatePresence>

          {/* Form */}
          <form onSubmit={handleSubmit} className="space-y-5">
            {/* Email Field */}
            <motion.div
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ delay: 0.3 }}
            >
              <label className="block text-sm font-medium text-slate-300 mb-2">
                البريد الإلكتروني
              </label>
              <div className="relative">
                <input
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  onFocus={() => setFocusedField('email')}
                  onBlur={() => setFocusedField(null)}
                  placeholder="example@email.com"
                  className={cn(
                    'w-full rounded-xl border bg-white/5 px-4 py-3 pl-11',
                    'text-white placeholder:text-slate-500',
                    'transition-all duration-200',
                    'focus:outline-none focus:ring-2',
                    focusedField === 'email'
                      ? 'border-indigo-500 ring-indigo-500/30 bg-white/10'
                      : 'border-white/10 hover:border-white/20'
                  )}
                  dir="ltr"
                  autoComplete="email"
                  required
                />
                <Mail className={cn(
                  'absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 transition-colors',
                  focusedField === 'email' ? 'text-indigo-400' : 'text-slate-500'
                )} />
              </div>
            </motion.div>

            {/* Password Field */}
            <motion.div
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ delay: 0.4 }}
            >
              <label className="block text-sm font-medium text-slate-300 mb-2">
                كلمة المرور
              </label>
              <div className="relative">
                <input
                  type={showPassword ? 'text' : 'password'}
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  onFocus={() => setFocusedField('password')}
                  onBlur={() => setFocusedField(null)}
                  placeholder="••••••••"
                  className={cn(
                    'w-full rounded-xl border bg-white/5 px-4 py-3 pl-11 pr-11',
                    'text-white placeholder:text-slate-500',
                    'transition-all duration-200',
                    'focus:outline-none focus:ring-2',
                    focusedField === 'password'
                      ? 'border-indigo-500 ring-indigo-500/30 bg-white/10'
                      : 'border-white/10 hover:border-white/20'
                  )}
                  autoComplete="current-password"
                  required
                />
                <Lock className={cn(
                  'absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 transition-colors',
                  focusedField === 'password' ? 'text-indigo-400' : 'text-slate-500'
                )} />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 hover:text-white transition-colors"
                >
                  {showPassword ? <EyeOff className="h-5 w-5" /> : <Eye className="h-5 w-5" />}
                </button>
              </div>
            </motion.div>

            {/* Remember Me & Forgot Password */}
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 0.5 }}
              className="flex items-center justify-between"
            >
              <label className="flex items-center gap-2 cursor-pointer">
                <div className="relative">
                  <input
                    type="checkbox"
                    checked={rememberMe}
                    onChange={(e) => setRememberMe(e.target.checked)}
                    className="sr-only"
                  />
                  <div className={cn(
                    'w-4 h-4 rounded border transition-colors',
                    rememberMe
                      ? 'bg-indigo-500 border-indigo-500'
                      : 'bg-white/5 border-white/20'
                  )}>
                    {rememberMe && (
                      <motion.svg
                        initial={{ scale: 0 }}
                        animate={{ scale: 1 }}
                        className="w-4 h-4 text-white"
                        fill="none"
                        viewBox="0 0 24 24"
                        stroke="currentColor"
                        strokeWidth={3}
                      >
                        <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                      </motion.svg>
                    )}
                  </div>
                </div>
                <span className="text-sm text-slate-400">تذكرني</span>
              </label>
              
              <button
                type="button"
                onClick={openForgotPasswordPopup}
                className="text-sm text-indigo-400 hover:text-indigo-300 transition-colors"
              >
                نسيت كلمة المرور؟
              </button>
            </motion.div>

            {/* Submit Button */}
            <motion.button
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.6 }}
              whileHover={{ scale: 1.02 }}
              whileTap={{ scale: 0.98 }}
              type="submit"
              disabled={isLoading || authLoading}
              className={cn(
                'relative w-full rounded-xl py-3.5 font-semibold',
                'bg-gradient-to-r from-indigo-500 to-purple-600',
                'text-white shadow-lg shadow-indigo-500/30',
                'hover:from-indigo-600 hover:to-purple-700',
                'transition-all duration-200',
                'disabled:opacity-60 disabled:cursor-not-allowed',
                'overflow-hidden'
              )}
            >
              {/* Shimmer effect */}
              <motion.div
                className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent"
                animate={{ x: ['-100%', '200%'] }}
                transition={{ duration: 2, repeat: Infinity, repeatDelay: 3 }}
              />
              
              <span className="relative z-10 flex items-center justify-center gap-2">
                {isLoading || authLoading ? (
                  <>
                    <Loader2 className="h-5 w-5 animate-spin" />
                    جاري تسجيل الدخول...
                  </>
                ) : (
                  <>
                    تسجيل الدخول
                    <ArrowRight className="h-5 w-5" />
                  </>
                )}
              </span>
            </motion.button>
          </form>

          {/* Biometric Login */}
          {showBiometric && (
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 0.7 }}
              className="mt-4"
            >
              <button
                type="button"
                onClick={handleBiometricLogin}
                disabled={isLoading}
                className={cn(
                  'w-full rounded-xl py-3 font-medium',
                  'bg-white/5 border border-white/10',
                  'text-slate-300 hover:text-white hover:bg-white/10',
                  'transition-all duration-200',
                  'flex items-center justify-center gap-2'
                )}
              >
                <Fingerprint className="h-5 w-5" />
                تسجيل الدخول بالبصمة
              </button>
            </motion.div>
          )}

          {/* Divider */}
          {showSocialLogin && (
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 0.8 }}
              className="relative my-8"
            >
              <div className="absolute inset-0 flex items-center">
                <div className="w-full border-t border-white/10"></div>
              </div>
              <div className="relative flex justify-center text-sm">
                <span className="px-4 bg-slate-900/50 text-slate-400">
                  أو تسجيل الدخول باستخدام
                </span>
              </div>
            </motion.div>
          )}

          {/* Social Login Buttons */}
          {showSocialLogin && (
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.9 }}
              className="grid grid-cols-3 gap-3"
            >
              <SocialButton
                              provider="google"
                              onClick={() => handleSocialLogin('google')}
                              fullWidth children={undefined}              />
              <SocialButton
                              provider="github"
                              onClick={() => handleSocialLogin('github')}
                              fullWidth children={undefined}              />
              <SocialButton
                              provider="twitter"
                              onClick={() => handleSocialLogin('twitter')}
                              fullWidth children={undefined}              />
            </motion.div>
          )}

          {/* Register Link */}
          <motion.p
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 1 }}
            className="mt-8 text-center text-sm text-slate-400"
          >
            ليس لديك حساب؟{' '}
            <Link
              href="/register"
              onClick={onRegister}
              className="font-semibold text-indigo-400 hover:text-indigo-300 transition-colors"
            >
              أنشئ حساباً جديداً
            </Link>
          </motion.p>
        </div>
      </div>

      {/* Forgot Password Popup */}
      <AnimatePresence>
        {showForgotPasswordPopup && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 flex items-center justify-center p-4"
            onClick={closeForgotPasswordPopup}
          >
            {/* Backdrop */}
            <motion.div 
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="absolute inset-0 bg-black/60 backdrop-blur-sm"
            />
            
            {/* Popup Content */}
            <motion.div
              initial={{ opacity: 0, scale: 0.9, y: 20 }}
              animate={{ opacity: 1, scale: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.9, y: 20 }}
              transition={{ type: 'spring', duration: 0.5 }}
              onClick={(e) => e.stopPropagation()}
              className="relative w-full max-w-md overflow-hidden rounded-3xl bg-gradient-to-br from-slate-900/95 to-slate-800/95 backdrop-blur-xl border border-white/10 shadow-2xl"
            >
              {/* Decorative elements */}
              <div className="absolute -top-20 -right-20 h-40 w-40 rounded-full bg-gradient-to-br from-indigo-500/20 to-purple-500/20 blur-3xl" />
              <div className="absolute -bottom-20 -left-20 h-40 w-40 rounded-full bg-gradient-to-br from-purple-500/20 to-pink-500/20 blur-3xl" />
              
              {/* Close Button */}
              <button
                onClick={closeForgotPasswordPopup}
                className="absolute top-4 left-4 p-2 rounded-full bg-white/5 hover:bg-white/10 text-slate-400 hover:text-white transition-all z-10"
              >
                <X className="h-5 w-5" />
              </button>
              
