'use client';

/**
 * Passkey Management UI Component
 * User interface for managing passkeys
 */

import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  Key,
  Plus,
  Trash2,
  Edit2,
  Check,
  X,
  Smartphone,
  Monitor,
  Shield,
  AlertCircle,
  Loader2,
} from 'lucide-react';
import { toast } from 'sonner';
import { getPasskeyManager, type PasskeyCredential } from './PasskeyManager';
import { cn } from '@/lib/utils';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';

export default function PasskeyManagement() {
  const [passkeys, setPasskeys] = useState<PasskeyCredential[]>([]);
  const [isSupported, setIsSupported] = useState(false);
  const [isPlatformAvailable, setIsPlatformAvailable] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editingName, setEditingName] = useState('');
  const [showAddDialog, setShowAddDialog] = useState(false);

  const passkeyManager = getPasskeyManager();

  useEffect(() => {
    checkSupport();
    loadPasskeys();
  }, []);

  const checkSupport = async () => {
    const supported = passkeyManager.isSupported();
    setIsSupported(supported);

    if (supported) {
      const platformAvailable = await passkeyManager.isPlatformAuthenticatorAvailable();
      setIsPlatformAvailable(platformAvailable);
    }
  };

  const loadPasskeys = () => {
    const registered = passkeyManager.getRegisteredPasskeys();
    setPasskeys(registered);
  };

  const handleAddPasskey = async () => {
    setIsLoading(true);
    try {
      // Request registration options from server
      const optionsResponse = await fetch('/api/auth/passkey/register-options', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
      });

      if (!optionsResponse.ok) {
        throw new Error('Failed to get registration options');
      }

      const options = await optionsResponse.json();

      // Register passkey
      await passkeyManager.registerPasskey(options);

      // Reload passkeys
      loadPasskeys();
      setShowAddDialog(false);
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : (error as { message?: string })?.message || 'فشل إضافة المفتاح';
      if (message === 'تم إلغاء عملية التسجيل') {
        toast.info(message);
      } else {
        toast.error(message);
      }
    } finally {
      setIsLoading(false);
    }
  };

  const handleDeletePasskey = async (credentialId: string) => {
    if (!confirm('هل أنت متأكد من حذف هذا المفتاح؟')) {
      return;
    }

    try {
      await passkeyManager.deletePasskey(credentialId);
      loadPasskeys();
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : 'فشل حذف المفتاح';
      toast.error(message);
    }
  };

  const handleStartEdit = (passkey: PasskeyCredential) => {
    setEditingId(passkey.id);
    setEditingName(passkey.deviceName);
  };

  const handleSaveEdit = async (credentialId: string) => {
    if (!editingName.trim()) {
      toast.error('يرجى إدخال اسم صحيح');
      return;
    }

    try {
      await passkeyManager.renamePasskey(credentialId, editingName.trim());
      loadPasskeys();
      setEditingId(null);
      setEditingName('');
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : 'فشل تغيير الاسم';
      toast.error(message);
    }
  };

  const handleCancelEdit = () => {
    setEditingId(null);
    setEditingName('');
  };

  const getDeviceIcon = (deviceType: string) => {
    return deviceType === 'platform' ? (
      <Smartphone className="h-5 w-5" />
    ) : (
      <Monitor className="h-5 w-5" />
    );
  };

  const formatDate = (date: Date) => {
    return new Intl.DateTimeFormat('ar-SA', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    }).format(date);
  };

  if (!isSupported) {
    return (
      <div className="rounded-xl bg-destructive/10 border border-destructive/20 p-6">
        <div className="flex items-start gap-3">
          <AlertCircle className="h-6 w-6 text-destructive flex-shrink-0 mt-0.5" />
          <div>
            <h3 className="text-lg font-semibold text-destructive mb-2">
              غير مدعوم
            </h3>
            <p className="text-sm text-destructive/80">
              متصفحك لا يدعم مفاتيح المرور (Passkeys). يرجى استخدام متصفح حديث مثل
              Chrome أو Safari أو Edge.
            </p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-foreground flex items-center gap-3">
            <Key className="h-7 w-7 text-primary" />
            مفاتيح المرور
          </h2>
          <p className="mt-1 text-sm text-muted-foreground">
            قم بإدارة مفاتيح المرور الخاصة بك للدخول بدون كلمة مرور
          </p>
        </div>
        <Button
          onClick={() => setShowAddDialog(true)}
          disabled={isLoading}
          className="gap-2"
        >
          <Plus className="h-4 w-4" />
          إضافة مفتاح جديد
        </Button>
      </div>

      {/* Info Banner */}
      {isPlatformAvailable && (
        <div className="rounded-xl bg-primary/10 border border-primary/20 p-4">
          <div className="flex items-start gap-3">
            <Shield className="h-5 w-5 text-primary flex-shrink-0 mt-0.5" />
            <div className="text-sm text-primary/80">
              <p className="font-medium mb-1 text-primary">مصادقة آمنة بدون كلمة مرور</p>
              <p>
                استخدم بصمة الإصبع أو التعرف على الوجه أو رقم PIN للدخول بسرعة وأمان.
              </p>
            </div>
          </div>
        </div>
      )}

      {/* Passkeys List */}
      <div className="space-y-3">
        <AnimatePresence mode="popLayout">
          {passkeys.length === 0 ? (
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -20 }}
              className="rounded-xl bg-muted/50 border border-border p-8 text-center"
            >
              <Key className="h-12 w-12 text-muted-foreground mx-auto mb-3" />
              <p className="text-muted-foreground">لم تقم بإضافة أي مفاتيح مرور بعد</p>
              <p className="text-sm text-muted-foreground/80 mt-1">
                قم بإضافة مفتاح مرور للدخول بسرعة وأمان
              </p>
            </motion.div>
          ) : (
            passkeys.map((passkey, index) => (
              <motion.div
                key={passkey.id}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -20 }}
                transition={{ delay: index * 0.05 }}
                className="rounded-xl bg-card border border-border p-4 hover:bg-accent/50 transition-colors"
              >
                <div className="flex items-start justify-between gap-4">
                  <div className="flex items-start gap-3 flex-1">
                    <div className="rounded-lg bg-primary/10 p-2 text-primary">
                      {getDeviceIcon(passkey.deviceType)}
                    </div>
                    <div className="flex-1 min-w-0">
                      {editingId === passkey.id ? (
                        <div className="flex items-center gap-2 mb-2">
                          <Input
                            type="text"
                            value={editingName}
                            onChange={(e) => setEditingName(e.target.value)}
                            className="flex-1 h-8"
                            autoFocus
                          />
                          <Button
                            size="icon"
                            variant="ghost"
                            onClick={() => handleSaveEdit(passkey.credentialId)}
                            className="h-8 w-8 text-green-500 hover:text-green-600 hover:bg-green-500/10"
                          >
                            <Check className="h-4 w-4" />
                          </Button>
                          <Button
                            size="icon"
                            variant="ghost"
                            onClick={handleCancelEdit}
                            className="h-8 w-8 text-destructive hover:text-destructive hover:bg-destructive/10"
                          >
                            <X className="h-4 w-4" />
                          </Button>
                        </div>
                      ) : (
                        <h3 className="text-base font-medium text-foreground mb-1">
                          {passkey.deviceName}
                        </h3>
                      )}
                      <div className="space-y-1 text-xs text-muted-foreground">
                        <p>تم الإنشاء: {formatDate(passkey.createdAt)}</p>
                        {passkey.lastUsedAt && (
                          <p>آخر استخدام: {formatDate(passkey.lastUsedAt)}</p>
                        )}
                        <p>
                          النوع: {passkey.deviceType === 'platform' ? 'جهاز' : 'خارجي'}
                        </p>
                      </div>
                    </div>
                  </div>
                  {editingId !== passkey.id && (
                    <div className="flex items-center gap-2">
                      <Button
                        size="icon"
                        variant="ghost"
                        onClick={() => handleStartEdit(passkey)}
                        className="h-8 w-8 text-muted-foreground hover:text-primary"
                      >
                        <Edit2 className="h-4 w-4" />
                      </Button>
                      <Button
                        size="icon"
                        variant="ghost"
                        onClick={() => handleDeletePasskey(passkey.credentialId)}
                        className="h-8 w-8 text-muted-foreground hover:text-destructive"
                      >
                        <Trash2 className="h-4 w-4" />
                      </Button>
                    </div>
                  )}
                </div>
              </motion.div>
            ))
          )}
        </AnimatePresence>
      </div>

      {/* Add Passkey Dialog */}
      <AnimatePresence>
        {showAddDialog && (
          <>
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="fixed inset-0 bg-background/80 backdrop-blur-sm z-50"
              onClick={() => !isLoading && setShowAddDialog(false)}
            />
            <motion.div
              initial={{ opacity: 0, scale: 0.9, y: 20 }}
              animate={{ opacity: 1, scale: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.9, y: 20 }}
              className="fixed left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 w-full max-w-md z-50"
            >
              <div className="rounded-2xl bg-card border border-border p-6 shadow-2xl">
                <h3 className="text-xl font-bold text-foreground mb-4">
                  إضافة مفتاح مرور جديد
                </h3>
                <p className="text-sm text-muted-foreground mb-6">
                  سيطلب منك المتصفح التحقق من هويتك باستخدام بصمة الإصبع أو التعرف
                  على الوجه أو رقم PIN.
                </p>
                <div className="flex gap-3">
                  <Button
                    onClick={handleAddPasskey}
                    disabled={isLoading}
                    className="flex-1 gap-2"
                  >
                    {isLoading ? (
                      <>
                        <Loader2 className="h-4 w-4 animate-spin" />
                        جارٍ الإضافة...
                      </>
                    ) : (
                      <>
                        <Plus className="h-4 w-4" />
                        إضافة
                      </>
                    )}
                  </Button>
                  <Button
                    variant="outline"
                    onClick={() => setShowAddDialog(false)}
                    disabled={isLoading}
                    className="flex-1"
                  >
                    إلغاء
                  </Button>
                </div>
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>
    </div>
  );
}

/**
 * 🔑 Synced Passkeys Service
 * 
 * خدمة مزامنة Passkeys عبر الأجهزة
 * تدعم iCloud Keychain, Google Password Manager, 1Password, etc.
 */

import { logger } from '@/lib/logger';
import type { PasskeyCredential } from './PasskeyManager';

export interface SyncedPasskeyInfo {
    credentialId: string;
    userHandle: string;
    rpId: string;
    transports: AuthenticatorTransport[];
    deviceType: 'platform' | 'cross-platform' | 'hybrid';
    isSynced: boolean;
    syncProvider?: 'icloud' | 'google' | '1password' | 'other' | 'unknown';
    createdAt: Date;
    lastUsedAt?: Date;
}

export interface DiscoverableCredentialOptions {
    rpId: string;
    challenge: string;
    timeout?: number;
    userVerification?: UserVerificationRequirement;
    mediation?: 'conditional' | 'optional' | 'required' | 'silent';
}

/**
 * Service for managing synced (discoverable) passkeys
 * that work across devices via platform sync services
 */
export class SyncedPasskeyService {
    private rpId: string;

    constructor(rpId?: string) {
        this.rpId = rpId || this.getDefaultRpId();
    }

    /**
     * Check if synced passkeys are supported
     */
    async isSyncedPasskeysSupported(): Promise<boolean> {
        if (typeof window === 'undefined') return false;
        if (!window.PublicKeyCredential) return false;

        try {
            // Check for platform authenticator (required for synced passkeys)
            const hasPlatformAuth =
                await PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable();

            if (!hasPlatformAuth) return false;

            // Check for conditional mediation (indicates modern passkey support)
            if (typeof PublicKeyCredential.isConditionalMediationAvailable === 'function') {
                return await PublicKeyCredential.isConditionalMediationAvailable();
            }

            return hasPlatformAuth;
        } catch (error) {
            logger.warn('Error checking synced passkey support:', error);
            return false;
        }
    }

    /**
     * Register a synced passkey (discoverable credential)
     */
    async registerSyncedPasskey(options: {
        challenge: ArrayBuffer | string;
        userId: string;
        userName: string;
        userDisplayName: string;
        deviceName?: string;
        excludeCredentials?: PublicKeyCredentialDescriptor[];
    }): Promise<{
        credential: PublicKeyCredential;
        attestation: {
            clientDataJSON: string;
            attestationObject: string;
            transports?: string[];
        };
    }> {
        const challenge = typeof options.challenge === 'string'
            ? this.base64urlToBuffer(options.challenge)
            : options.challenge;

        const publicKeyOptions: PublicKeyCredentialCreationOptions = {
            challenge,
            rp: {
                id: this.rpId,
                name: document.title || 'Thanawy',
            },
            user: {
                id: new TextEncoder().encode(options.userId),
                name: options.userName,
                displayName: options.userDisplayName,
            },
            pubKeyCredParams: [
                { type: 'public-key', alg: -7 },   // ES256
                { type: 'public-key', alg: -257 }, // RS256
                { type: 'public-key', alg: -8 },   // EdDSA
            ],
            authenticatorSelection: {
                // Key settings for synced passkeys
                authenticatorAttachment: 'platform',
                residentKey: 'required',           // Makes it discoverable
                requireResidentKey: true,         // Backwards compatibility
                userVerification: 'required',
            },
            timeout: 120000, // 2 minutes
            attestation: 'none', // Don't need attestation for most use cases
            excludeCredentials: options.excludeCredentials,
            // Request hints for better UX
            extensions: {
                credProps: true, // Get credential properties
            },
        };

        try {
            const credential = await navigator.credentials.create({
                publicKey: publicKeyOptions,
            }) as PublicKeyCredential;

            if (!credential) {
                throw new Error('No credential returned');
            }

            const response = credential.response as AuthenticatorAttestationResponse;

            return {
                credential,
                attestation: {
                    clientDataJSON: this.bufferToBase64url(response.clientDataJSON),
                    attestationObject: this.bufferToBase64url(response.attestationObject),
                    transports: response.getTransports?.() || [],
                },
            };
        } catch (error: unknown) {
            const err = error as Error;
            if (err.name === 'NotAllowedError') {
                throw new Error('تم إلغاء تسجيل مفتاح المرور');
            }
            if (err.name === 'InvalidStateError') {
                throw new Error('مفتاح المرور مسجل بالفعل على هذا الجهاز');
            }
            throw error;
        }
    }

    /**
     * Authenticate with discoverable credential (no username needed)
     * User can select from their synced passkeys
     */
    async authenticateWithDiscoverableCredential(
        options: DiscoverableCredentialOptions
    ): Promise<{
        credential: PublicKeyCredential;
        assertion: {
            clientDataJSON: string;
            authenticatorData: string;
            signature: string;
            userHandle: string | null;
        };
    }> {
        const challenge = this.base64urlToBuffer(options.challenge);

        const publicKeyOptions: PublicKeyCredentialRequestOptions = {
            challenge,
            rpId: options.rpId,
            timeout: options.timeout || 60000,
            userVerification: options.userVerification || 'required',
            // Empty allowCredentials = discoverable credential
            allowCredentials: [],
        };

        try {
            const credential = await navigator.credentials.get({
                publicKey: publicKeyOptions,
                mediation: options.mediation,
            } as CredentialRequestOptions) as PublicKeyCredential;

            if (!credential) {
                throw new Error('No credential selected');
            }

            const response = credential.response as AuthenticatorAssertionResponse;

            return {
                credential,
                assertion: {
                    clientDataJSON: this.bufferToBase64url(response.clientDataJSON),
                    authenticatorData: this.bufferToBase64url(response.authenticatorData),
                    signature: this.bufferToBase64url(response.signature),
                    userHandle: response.userHandle
                        ? this.bufferToBase64url(response.userHandle)
                        : null,
                },
            };
        } catch (error: unknown) {
            const err = error as Error;
            if (err.name === 'NotAllowedError') {
                throw new Error('تم إلغاء المصادقة');
            }
            throw error;
        }
    }

    /**
     * Start conditional UI authentication
     * Shows passkeys in autofill dropdown when user focuses on username field
     */
    async startConditionalUIAuthentication(
        options: Omit<DiscoverableCredentialOptions, 'mediation'>,
        abortSignal?: AbortSignal
    ): Promise<{
        credential: PublicKeyCredential;
        assertion: {
            clientDataJSON: string;
            authenticatorData: string;
            signature: string;
            userHandle: string | null;
        };
    }> {
        // Check if conditional UI is supported
        if (typeof PublicKeyCredential.isConditionalMediationAvailable !== 'function') {
            throw new Error('المتصفح لا يدعم Autofill للـ Passkeys');
        }

        const isSupported = await PublicKeyCredential.isConditionalMediationAvailable();
        if (!isSupported) {
            throw new Error('Conditional UI غير متاح');
        }

        const challenge = this.base64urlToBuffer(options.challenge);

        const publicKeyOptions: PublicKeyCredentialRequestOptions = {
            challenge,
            rpId: options.rpId,
            timeout: options.timeout || 300000, // 5 minutes for conditional UI
            userVerification: options.userVerification || 'preferred',
            allowCredentials: [], // Empty for discoverable
        };

        try {
            const credential = await navigator.credentials.get({
                publicKey: publicKeyOptions,
                mediation: 'conditional',
                signal: abortSignal,
            } as CredentialRequestOptions) as PublicKeyCredential;

            if (!credential) {
                throw new Error('No credential selected');
            }

            const response = credential.response as AuthenticatorAssertionResponse;

            return {
                credential,
                assertion: {
                    clientDataJSON: this.bufferToBase64url(response.clientDataJSON),
                    authenticatorData: this.bufferToBase64url(response.authenticatorData),
                    signature: this.bufferToBase64url(response.signature),
                    userHandle: response.userHandle
                        ? this.bufferToBase64url(response.userHandle)
                        : null,
                },
            };
        } catch (error: unknown) {
            const err = error as Error;
            if (err.name === 'AbortError') {
                throw new Error('تم إلغاء العملية');
            }
            throw error;
        }
    }

    /**
     * Detect sync provider from client hints or platform
     */
    detectSyncProvider(): SyncedPasskeyInfo['syncProvider'] {
        if (typeof window === 'undefined') return 'unknown';

        const ua = navigator.userAgent;
        const platform = navigator.platform;

        // Apple devices use iCloud Keychain
        if (/Mac|iPhone|iPad|iPod/.test(platform) || /Safari/.test(ua)) {
            return 'icloud';
        }

        // Chrome on any platform uses Google Password Manager
        if (/Chrome/.test(ua) && !/Edg/.test(ua)) {
            return 'google';
        }

        // Check for 1Password or other extension
        if ((window as unknown as { __1password?: boolean }).__1password) {
            return '1password';
        }

        return 'other';
    }

    /**
     * Get friendly name for sync provider
     */
    getSyncProviderName(provider: SyncedPasskeyInfo['syncProvider']): {
        en: string;
        ar: string;
    } {
        switch (provider) {
            case 'icloud':
                return { en: 'iCloud Keychain', ar: 'سلسلة مفاتيح iCloud' };
            case 'google':
                return { en: 'Google Password Manager', ar: 'مدير كلمات مرور Google' };
            case '1password':
                return { en: '1Password', ar: '1Password' };
            case 'other':
                return { en: 'Password Manager', ar: 'مدير كلمات المرور' };
            default:
                return { en: 'Unknown', ar: 'غير معروف' };
        }
    }

    // ============================================
    // Helper Methods
    // ============================================

    private getDefaultRpId(): string {
        if (typeof window === 'undefined') return 'localhost';
        return window.location.hostname;
    }

    private base64urlToBuffer(base64url: string): ArrayBuffer {
        const base64 = base64url.replace(/-/g, '+').replace(/_/g, '/');
        const padded = base64.padEnd(base64.length + ((4 - (base64.length % 4)) % 4), '=');
        const binary = atob(padded);
        const bytes = new Uint8Array(binary.length);
        for (let i = 0; i < binary.length; i++) {
            bytes[i] = binary.charCodeAt(i);
        }
        return bytes.buffer;
    }

    private bufferToBase64url(buffer: ArrayBuffer): string {
        const bytes = new Uint8Array(buffer);
        let binary = '';
        for (let i = 0; i < bytes.length; i++) {
            binary += String.fromCharCode(bytes[i]);
        }
        const base64 = btoa(binary);
        return base64.replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');
    }
}

// Singleton instance
let syncedPasskeyServiceInstance: SyncedPasskeyService | null = null;

export function getSyncedPasskeyService(rpId?: string): SyncedPasskeyService {
    if (!syncedPasskeyServiceInstance || rpId) {
        syncedPasskeyServiceInstance = new SyncedPasskeyService(rpId);
    }
    return syncedPasskeyServiceInstance;
}

