          >
            <Icon className="h-5 w-5" />
          </div>
          <div>
            <h4 className="font-medium text-white">{title}</h4>
            <p className="text-xs text-slate-400 mt-0.5">{description}</p>
          </div>
        </div>
        
        <div className="flex items-center gap-2">
          {onConfigure && (
