"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { AuthGuard } from "@/components/auth/AuthGuard";

import { ensureUser } from "@/lib/user-utils";

import { logger } from '@/lib/logger';

type Event = {
  id: string;
  title: string;
  description: string;
  location?: string;
  startDate: string;
  endDate: string;
  imageUrl?: string;
  organizerId: string;
  organizerName: string;
  category: string;
  isPublic: boolean;
  maxAttendees?: number;
  currentAttendees: number;
  tags: string[];
};

export default function EventsPage() {
  const [userId, setUserId] = useState<string | null>(null);
  const [events, setEvents] = useState<Event[]>([]);
  const [filteredEvents, setFilteredEvents] = useState<Event[]>([]);
  const [activeCategory, setActiveCategory] = useState<string>("all");
  const [searchTerm, setSearchTerm] = useState("");
  const [sortBy, setSortBy] = useState<"newest" | "soonest">("newest");

  useEffect(() => {
    ensureUser().then(setUserId);
  }, []);

  useEffect(() => {
    const fetchEvents = async () => {
      try {
        const res = await fetch("/api/events");
        if (res.ok) {
          const data = await res.json() as Event[];
          setEvents(data);
        }
      } catch (error) {
        logger.error("Error fetching events:", error);
      }
    };

    fetchEvents();
  }, []);

  useEffect(() => {
    let result = events;

    // Filter by category
    if (activeCategory !== "all") {
      result = result.filter(event => event.category === activeCategory);
    }

    // Filter by search term
    if (searchTerm) {
      const term = searchTerm.toLowerCase();
      result = result.filter(event => 
        event.title.toLowerCase().includes(term) || 
        event.description.toLowerCase().includes(term) ||
        event.location?.toLowerCase().includes(term) ||
        event.tags.some(tag => tag.toLowerCase().includes(term))
      );
    }

    // Sort
    if (sortBy === "newest") {
      result = [...result].sort((a, b) => 
        new Date(b.startDate).getTime() - new Date(a.startDate).getTime()
      );
    } else { // soonest
      result = [...result].sort((a, b) => 
        new Date(a.startDate).getTime() - new Date(b.startDate).getTime()
      );
    }

    setFilteredEvents(result);
  }, [events, activeCategory, searchTerm, sortBy]);

  const formatDate = (dateString: string) => {
    const date = new Date(dateString);
    return date.toLocaleDateString("ar-SA", {
      year: "numeric",
      month: "long",
      day: "numeric",
      hour: "2-digit",
      minute: "2-digit"
    });
  };

  const categories = [
    { id: "all", name: "الكل", icon: "📅" },
    { id: "academic", name: "أكاديمي", icon: "🎓" },
    { id: "social", name: "اجتماعي", icon: "👥" },
    { id: "sports", name: "رياضي", icon: "⚽" },
    { id: "cultural", name: "ثقافي", icon: "🎭" },
    { id: "workshop", name: "ورشة عمل", icon: "🛠️" },
  ];

  return (
    <AuthGuard>
      <div className="px-4">
        <section className="mx-auto max-w-7xl py-8 space-y-6">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
          <div>
            <h1 className="text-2xl md:text-3xl font-bold">الإعلانات والمناسبات</h1>
            <p className="text-muted-foreground">استكشف الفعاليات والمناسبات القادمة</p>
          </div>
          {userId && (
            <Link href="/events/new" className="px-4 py-2 bg-primary text-primary-foreground rounded-md">
              إنشاء مناسبة جديدة
            </Link>
          )}
        </div>

        {/* Categories */}
        <div className="rounded-lg border p-4">
          <h2 className="font-semibold mb-3">التصنيفات</h2>
          <div className="flex flex-wrap gap-2">
            {categories.map((category) => (
              <button
                key={category.id}
                className={`px-3 py-1.5 rounded-md text-sm flex items-center gap-1.5 ${activeCategory === category.id ? "bg-primary text-primary-foreground" : "bg-muted"}`}
                onClick={() => setActiveCategory(category.id)}
              >
                <span>{category.icon}</span>
                <span>{category.name}</span>
              </button>
            ))}
          </div>
        </div>

        {/* Search and Sort */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="rounded-lg border p-4">
            <div className="relative">
              <input
                type="text"
                placeholder="ابحث في المناسبات..."
                className="w-full border rounded-md px-4 py-2 pl-10"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
              <svg
                xmlns="http://www.w3.org/2000/svg"
                className="h-5 w-5 absolute left-3 top-2.5 text-muted-foreground"
                fill="none"
                viewBox="0 0 24 24"
                stroke="currentColor"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"
                />
              </svg>
            </div>
          </div>

          <div className="rounded-lg border p-4">
            <div className="flex items-center gap-2">
              <span className="text-sm font-medium">ترتيب حسب:</span>
              <select
                className="border rounded-md px-3 py-1.5 text-sm"
                value={sortBy}
                onChange={(e) => setSortBy(e.target.value as "newest" | "soonest")}
              >
                <option value="newest">الأحدث</option>
                <option value="soonest">الأقرب</option>
              </select>
            </div>
          </div>
        </div>

        {/* Events Grid */}
        {filteredEvents.length > 0 ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {filteredEvents.map((event) => (
              <div key={event.id} className="rounded-lg border overflow-hidden transition-transform hover:scale-[1.02]">
                <div className="aspect-video bg-muted relative">
                  {event.imageUrl ? (
                    <img 
                      src={event.imageUrl} 
                      alt={event.title} 
                      className="w-full h-full object-cover"
                    />
                  ) : (
                    <div className="w-full h-full flex items-center justify-center bg-gradient-to-br from-primary/20 to-primary/5">
                      <span className="text-4xl">📅</span>
                    </div>
                  )}
                  <div className="absolute top-2 right-2 bg-black/70 text-white text-xs px-2 py-1 rounded">
                    {categories.find(c => c.id === event.category)?.name || event.category}
                  </div>
                </div>
                <div className="p-4">
                  <h3 className="font-semibold line-clamp-2 mb-2">{event.title}</h3>
                  <p className="text-sm text-muted-foreground line-clamp-3 mb-3">{event.description}</p>

                  <div className="space-y-2 mb-3">
                    <div className="flex items-center gap-2 text-sm text-muted-foreground">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
                      </svg>
                      <span>{formatDate(event.startDate)}</span>
                    </div>

                    {event.location && (
                      <div className="flex items-center gap-2 text-sm text-muted-foreground">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" />
                        </svg>
                        <span>{event.location}</span>
                      </div>
                    )}

                    <div className="flex items-center gap-2 text-sm text-muted-foreground">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
                      </svg>
                      <span>المنظم: {event.organizerName}</span>
                    </div>

                    {event.maxAttendees && (
                      <div className="flex items-center gap-2 text-sm text-muted-foreground">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" />
                        </svg>
                        <span>{event.currentAttendees} من {event.maxAttendees} مشارك</span>
                      </div>
                    )}
                  </div>

                  <div className="flex flex-wrap gap-1 mb-3">
                    {event.tags.slice(0, 3).map((tag, index) => (
                      <span key={index} className="text-xs bg-muted px-2 py-0.5 rounded">
                        {tag}
                      </span>
                    ))}
                    {event.tags.length > 3 && (
                      <span className="text-xs bg-muted px-2 py-0.5 rounded">
                        +{event.tags.length - 3}
                      </span>
                    )}
                  </div>

                  <Link 
                    href={`/events/${event.id}`} 
                    className="block text-center px-3 py-2 bg-primary text-primary-foreground rounded-md text-sm font-medium"
                  >
                    عرض التفاصيل
                  </Link>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="rounded-lg border p-12 text-center">
            <div className="text-5xl mb-4">📅</div>
            <h3 className="text-lg font-medium mb-2">لا توجد مناسبات في هذا التصنيف</h3>
            <p className="text-muted-foreground">جرب تغيير التصنيف أو معايير البحث</p>
          </div>
        )}
        </section>
      </div>
    </AuthGuard>
  );
}

"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { AuthGuard } from "@/components/auth/AuthGuard";

import { ensureUser } from "@/lib/user-utils";

type ForumCategory = {
  id: string;
  name: string;
  description: string;
  icon: string;
};

type ForumPost = {
  id: string;
  title: string;
  content: string;
  authorName: string;
  categoryId: string;
  categoryName: string;
  createdAt: string;
  views: number;
  repliesCount: number;
  isPinned: boolean;
};

export default function ForumPage() {
  const [userId, setUserId] = useState<string | null>(null);
  const [categories, setCategories] = useState<ForumCategory[]>([]);
  const [posts, setPosts] = useState<ForumPost[]>([]);
  const [activeCategory, setActiveCategory] = useState<string>("all");
  const [searchTerm, setSearchTerm] = useState("");

  useEffect(() => {
    ensureUser().then(setUserId);
  }, []);

  useEffect(() => {
    // Load categories
    const fetchCategories = async () => {
      const res = await fetch("/api/forum/categories");
      const data = await res.json() as ForumCategory[];
      setCategories(data);
    };

    // Load posts
    const fetchPosts = async () => {
      const res = await fetch("/api/forum/posts");
      const data = await res.json() as ForumPost[];
      setPosts(data);
    };

    fetchCategories();
    fetchPosts();
  }, []);

  const filteredPosts = Array.isArray(posts) ? posts.filter(post => {
    const matchesCategory = activeCategory === "all" || post.categoryId === activeCategory;
    const matchesSearch = post.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
                         post.content.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesCategory && matchesSearch;
  }) : [];

  // Sort pinned posts first
  const sortedPosts = [...filteredPosts].sort((a, b) => {
    if (a.isPinned && !b.isPinned) return -1;
    if (!a.isPinned && b.isPinned) return 1;
    return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
  });

  return (
    <AuthGuard>
      <div className="px-4">
        <section className="mx-auto max-w-7xl py-8 space-y-6">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
          <div>
            <h1 className="text-2xl md:text-3xl font-bold">المنتدى التعليمي</h1>
            <p className="text-muted-foreground">تواصل مع زملائك واطرح أسئلتك</p>
          </div>
          <Link href="/forum/new-post" className="px-4 py-2 bg-primary text-primary-foreground rounded-md">
            إضافة موضوع جديد
          </Link>
        </div>

        {/* Categories */}
        <div className="rounded-lg border p-4">
          <h2 className="font-semibold mb-3">التصنيفات</h2>
          <div className="flex flex-wrap gap-2">
            <button 
              className={`px-3 py-1.5 rounded-md text-sm ${activeCategory === "all" ? "bg-primary text-primary-foreground" : "bg-muted"}`}
              onClick={() => setActiveCategory("all")}
            >
              الكل
            </button>
            {Array.isArray(categories) && categories.map((category) => (
              <button
                key={category.id}
                className={`px-3 py-1.5 rounded-md text-sm flex items-center gap-1.5 ${activeCategory === category.id ? "bg-primary text-primary-foreground" : "bg-muted"}`}
                onClick={() => setActiveCategory(category.id)}
              >
                <span>{category.icon}</span>
                <span>{category.name}</span>
              </button>
            ))}
          </div>
        </div>

        {/* Search */}
        <div className="rounded-lg border p-4">
          <div className="relative">
            <input
              type="text"
              placeholder="ابحث في المنتدى..."
              className="w-full border rounded-md px-4 py-2 pl-10"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
            <svg
              xmlns="http://www.w3.org/2000/svg"
              className="h-5 w-5 absolute left-3 top-2.5 text-muted-foreground"
              fill="none"
              viewBox="0 0 24 24"
              stroke="currentColor"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"
              />
            </svg>
          </div>
        </div>

        {/* Posts */}
        <div className="rounded-lg border">
          <div className="p-4 border-b">
            <h2 className="font-semibold">المواضيع</h2>
          </div>
          <ul className="divide-y">
            {sortedPosts.length > 0 ? (
              sortedPosts.map((post) => (
                <li key={post.id} className="p-4 hover:bg-muted/50 transition-colors">
                  <Link href={`/forum/post/${post.id}`} className="block">
                    <div className="flex items-start gap-3">
                      {post.isPinned && (
                        <span className="text-primary mt-1" title="مثبت">
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                            <path fillRule="evenodd" d="M5.05 4.05a7 7 0 119.9 9.9L10 18.9l-4.95-4.95a7 7 0 010-9.9zM10 11a2 2 0 100-4 2 2 0 000 4z" clipRule="evenodd" />
                          </svg>
                        </span>
                      )}
                      <div className="flex-1">
                        <div className="flex items-center gap-2 mb-1">
                          <span className="bg-primary/10 text-primary px-2 py-0.5 rounded text-xs font-medium">
                            {post.categoryName}
                          </span>
                          <h3 className="font-medium hover:text-primary transition-colors">{post.title}</h3>
                        </div>
                        <p className="text-sm text-muted-foreground line-clamp-2 mb-2">{post.content}</p>
                        <div className="flex items-center gap-4 text-xs text-muted-foreground">
                          <span>بواسطة: {post.authorName}</span>
                          <span>{new Date(post.createdAt).toLocaleDateString()}</span>
                          <div className="flex items-center gap-1">
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
                            </svg>
                            <span>{post.views}</span>
                          </div>
                          <div className="flex items-center gap-1">
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" />
                            </svg>
                            <span>{post.repliesCount}</span>
                          </div>
                        </div>
                      </div>
                    </div>
                  </Link>
                </li>
              ))
            ) : (
              <li className="p-8 text-center text-muted-foreground">
                لا توجد مواضيع في هذا التصنيف
              </li>
            )}
          </ul>
        </div>
        </section>
      </div>
    </AuthGuard>
  );
}

"use client";

import { useState } from 'react';
import { motion } from 'framer-motion';
import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Achievement } from '../types';
import {
	getCategoryIcon,
	getDifficultyLabel,
	getDifficultyColor,
	getRarityColor,
	getRarityLabel,
	formatRelativeTime,
} from '../utils';
import {
	Trophy,
	Lock,
	Zap,
	Eye,
	EyeOff,
	Sparkles,
	Award,
	Clock,
} from 'lucide-react';
import { AchievementModal } from './AchievementModal';

interface AchievementCardProps {
	achievement: Achievement;
	index?: number;
}

export function AchievementCard({ achievement, index = 0 }: AchievementCardProps) {
	const [isModalOpen, setIsModalOpen] = useState(false);
	const isEarned = achievement.isEarned || false;
	const rarity = achievement.rarity || 'common';

	const cardVariants = {
		hidden: { opacity: 0, y: 20 },
		visible: (i: number) => ({
			opacity: 1,
			y: 0,
			transition: {
				delay: i * 0.05,
				duration: 0.3,
			},
		}),
		hover: {
			scale: 1.02,
			transition: { duration: 0.2 },
		},
	};

	return (
		<>
			<motion.div
				variants={cardVariants}
				initial="hidden"
				animate="visible"
				custom={index}
				whileHover="hover"
				className="h-full"
			>
				<Card
					className={`h-full cursor-pointer transition-all duration-300 ${
						isEarned
							? 'border-2 border-primary/50 bg-gradient-to-br from-background to-primary/5 hover:shadow-lg hover:shadow-primary/20'
							: 'border border-muted opacity-75 hover:opacity-100 hover:shadow-md'
					}`}
					onClick={() => setIsModalOpen(true)}
				>
					<CardContent className="p-5">
						<div className="flex flex-col h-full">
							{/* Header with Icon and Status */}
							<div className="flex items-start justify-between mb-3">
								<div className="flex items-center gap-3 flex-1">
									<div
										className={`text-4xl transition-transform duration-300 ${
											isEarned ? 'animate-pulse' : 'grayscale opacity-50'
										}`}
									>
										{achievement.icon || getCategoryIcon(achievement.category)}
									</div>
									<div className="flex-1 min-w-0">
										<h3
											className={`font-bold text-lg mb-1 line-clamp-2 ${
												isEarned ? 'text-foreground' : 'text-muted-foreground'
											}`}
										>
											{achievement.title}
										</h3>
										{achievement.isSecret && !isEarned && (
											<div className="flex items-center gap-1 text-xs text-muted-foreground">
												<EyeOff className="h-3 w-3" />
												<span>إنجاز سري</span>
											</div>
										)}
									</div>
								</div>
								{isEarned ? (
									<Trophy className="h-5 w-5 text-yellow-500 flex-shrink-0" />
								) : (
									<Lock className="h-5 w-5 text-muted-foreground flex-shrink-0" />
								)}
							</div>

							{/* Description */}
							{(!achievement.isSecret || isEarned) && (
								<p className="text-sm text-muted-foreground mb-4 line-clamp-2 flex-1">
									{achievement.description}
								</p>
							)}

							{/* Badges */}
							<div className="flex flex-wrap gap-2 mb-4">
								<Badge
									variant="outline"
									className={`text-xs ${getDifficultyColor(achievement.difficulty)}`}
								>
									{getDifficultyLabel(achievement.difficulty)}
								</Badge>
								<Badge
									variant="outline"
									className={`text-xs ${getRarityColor(rarity)}`}
								>
									{getRarityLabel(rarity)}
								</Badge>
								<Badge variant="outline" className="text-xs">
									{getCategoryIcon(achievement.category)}{' '}
									{achievement.category}
								</Badge>
							</div>

							{/* Footer */}
							<div className="mt-auto pt-3 border-t flex items-center justify-between">
								{/* XP Reward */}
								<div className="flex items-center gap-1 text-sm">
									<Zap className="h-4 w-4 text-yellow-500" />
									<span className="font-semibold">{achievement.xpReward}</span>
									<span className="text-muted-foreground text-xs">XP</span>
								</div>

								{/* Earned Date or Progress */}
								{isEarned && achievement.earnedAt ? (
									<div className="flex items-center gap-1 text-xs text-muted-foreground">
										<Clock className="h-3 w-3" />
										<span>{formatRelativeTime(achievement.earnedAt)}</span>
									</div>
								) : achievement.progress !== undefined && achievement.maxProgress ? (
									<div className="flex-1 mr-3">
										<div className="flex items-center justify-between text-xs mb-1">
											<span className="text-muted-foreground">التقدم</span>
											<span className="font-medium">
												{achievement.progress} / {achievement.maxProgress}
											</span>
										</div>
										<div className="h-1.5 bg-secondary rounded-full overflow-hidden">
											<div
												className="h-full bg-gradient-to-r from-primary to-primary/80 rounded-full transition-all duration-500"
												style={{
													width: `${(achievement.progress / achievement.maxProgress) * 100}%`,
												} as React.CSSProperties}
											/>
										</div>
									</div>
								) : (
									<span className="text-xs text-muted-foreground">غير محرز</span>
								)}
							</div>

							{/* Earned Animation Overlay */}
							{isEarned && (
								<div className="absolute inset-0 pointer-events-none overflow-hidden rounded-xl">
									<motion.div
										initial={{ scale: 0, opacity: 0 }}
										animate={{ scale: 1.5, opacity: [0, 0.3, 0] }}
										transition={{ duration: 2, repeat: Infinity, repeatDelay: 3 }}
										className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2"
									>
										<Sparkles className="h-20 w-20 text-yellow-400" />
									</motion.div>
								</div>
							)}
						</div>
					</CardContent>
				</Card>
			</motion.div>

			<AchievementModal
				achievement={achievement}
				isOpen={isModalOpen}
				onClose={() => setIsModalOpen(false)}
			/>
		</>
	);
}

