								<Card>
									<CardContent className="p-8 text-center">
										<p className="text-muted-foreground">
											لا توجد إنجازات تطابق الفلترة المحددة
										</p>
										<Button
											variant="outline"
											size="sm"
											onClick={() =>
												setFilters({
													search: '',
													category: 'all',
													difficulty: 'all',
													status: 'all',
												})
											}
											className="mt-4"
										>
											إعادة تعيين الفلاتر
										</Button>
									</CardContent>
								</Card>
							) : achievements.length === 0 ? (
								<EmptyState />
							) : (
								<motion.div
									initial={{ opacity: 0 }}
									animate={{ opacity: 1 }}
									className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4"
								>
									{filteredAchievements.map((achievement, index) => (
										<AchievementCard
											key={achievement.id}
											achievement={achievement}
											index={index}
										/>
									))}
								</motion.div>
							)}
						</div>

						{/* Info Section */}
						<Card className="border-2">
							<CardHeader>
								<CardTitle className="flex items-center gap-2">
									<Info className="h-5 w-5" />
									كيفية الحصول على المزيد من الإنجازات
								</CardTitle>
							</CardHeader>
							<CardContent>
								<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
									<div className="p-4 rounded-lg border bg-secondary/30">
										<div className="text-2xl mb-2">📚</div>
										<h3 className="font-medium mb-2">إنجازات الدراسة</h3>
										<ul className="text-sm text-muted-foreground space-y-1">
											<li>• دراسة لمدة 10 ساعات</li>
											<li>• دراسة لمدة 50 ساعة</li>
											<li>• دراسة لمدة 100 ساعة</li>
											<li>• دراسة 7 أيام متتالية</li>
											<li>• دراسة 30 يوم متتالي</li>
										</ul>
									</div>
