          </button>
        </div>
      </form>
    </div>
  );
}

"use client";

import React, { useState, useRef, useEffect } from 'react';
import { Send, MessageSquare, Bot, User, Zap, Mic, MicOff, AlertCircle, Heart } from 'lucide-react';
import { logger } from '@/lib/logger';

interface Message {
  role: 'user' | 'assistant';
  content: string;
  timestamp: Date;
  sentiment?: {
    sentiment: string;
    score: number;
    suggestions?: string[];
  };
}

interface AIAssistantEnhancedProps {
  initialMessage?: string;
  placeholder?: string;
  title?: string;
  className?: string;
  userId?: string;
}

export default function AIAssistantEnhanced({
  initialMessage = "مرحباً! أنا مساعدك الذكي في منصة ثناوي. كيف يمكنني مساعدتك اليوم؟",
  placeholder = "اكتب سؤالك هنا أو اضغط على الميكروفون للتحدث...",
  title = "المساعد الذكي",
  className = "",
  userId
}: AIAssistantEnhancedProps) {
  const [messages, setMessages] = useState<Message[]>([
    {
      role: 'assistant',
      content: initialMessage,
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [sentimentAlert, setSentimentAlert] = useState<{ sentiment: string; suggestions?: string[] } | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);

  // Initialize speech recognition
  useEffect(() => {
    if (typeof window !== 'undefined' && 'webkitSpeechRecognition' in window) {
      const SpeechRecognition = (window as any).webkitSpeechRecognition || (window as any).SpeechRecognition;
      const recognition = new SpeechRecognition();
      recognition.lang = 'ar-SA';
      recognition.continuous = false;
      recognition.interimResults = false;

      recognition.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setInput(transcript);
        setIsListening(false);
      };

      recognition.onerror = (event: any) => {
        logger.error('Speech recognition error:', event.error);
        setIsListening(false);
      };

      recognition.onend = () => {
        setIsListening(false);
      };

      recognitionRef.current = recognition;
    }

    return () => {
      if (recognitionRef.current) {
        recognitionRef.current.stop();
      }
    };
  }, []);

  // Scroll to bottom
  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Auto-hide sentiment alert
  useEffect(() => {
    if (sentimentAlert) {
      const timer = setTimeout(() => setSentimentAlert(null), 10000);
      return () => clearTimeout(timer);
    }
  }, [sentimentAlert]);

  const startListening = () => {
    if (recognitionRef.current && !isListening) {
      setIsListening(true);
      recognitionRef.current.start();
    }
  };

  const stopListening = () => {
    if (recognitionRef.current && isListening) {
      recognitionRef.current.stop();
      setIsListening(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    // Add user message
    const userMessage: Message = {
      role: 'user',
      content: input,
      timestamp: new Date()
    };
    setMessages(prev => [...prev, userMessage]);
    const currentInput = input;
    setInput('');
    setIsLoading(true);

    try {
      // Send request to API
      const response = await fetch('/api/ai/chat', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          messages: [...messages, userMessage].map(msg => ({
            role: msg.role,
            content: msg.content
          })),
          provider: 'gemini',
          userId: userId
        }),
      });

      if (!response.ok) {
        throw new Error('فشلت عملية الاتصال بالمساعد الذكي');
      }

      const data = await response.json();

      // Show sentiment alert if negative sentiment detected
      if (data.sentiment && (data.sentiment.sentiment === 'frustrated' || data.sentiment.sentiment === 'tired')) {
        setSentimentAlert({
          sentiment: data.sentiment.sentiment,
          suggestions: data.sentiment.suggestions
        });
      }

      // Add assistant response
      const assistantMessage: Message = {
        role: 'assistant',
        content: data.message,
        timestamp: new Date(),
        sentiment: data.sentiment
      };
      setMessages(prev => [...prev, assistantMessage]);
    } catch (error) {
      logger.error('Error sending message:', error);

      // Add error message
      const errorMessage: Message = {
        role: 'assistant',
        content: 'عذراً، حدث خطأ أثناء معالجة طلبك. يرجى المحاولة مرة أخرى لاحقاً.',
        timestamp: new Date()
      };
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  };

  const formatTime = (date: Date) => {
    return date.toLocaleTimeString('ar-EG', {
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  const getSentimentColor = (sentiment?: string) => {
    switch (sentiment) {
      case 'frustrated':
        return 'bg-orange-100 text-orange-800 border-orange-300';
      case 'tired':
        return 'bg-yellow-100 text-yellow-800 border-yellow-300';
      case 'positive':
        return 'bg-green-100 text-green-800 border-green-300';
      default:
        return 'bg-gray-100 text-gray-800 border-gray-300';
    }
  };

  return (
    <div className={`bg-white rounded-xl shadow-lg flex flex-col h-full ${className}`}>
      <div className="p-4 border-b border-gray-200">
        <div className="flex items-center gap-2">
          <div className="p-2 bg-blue-100 rounded-lg">
            <Bot className="h-5 w-5 text-blue-600" />
          </div>
          <h3 className="font-bold text-lg text-gray-800">{title}</h3>
          <div className="ml-auto flex items-center gap-1 text-xs bg-green-100 text-green-800 px-2 py-1 rounded-full">
            <Zap className="h-3 w-3" />
            <span>Gemini 2.0 Flash</span>
          </div>
        </div>
      </div>

      {/* Sentiment Alert */}
      {sentimentAlert && (
        <div className={`mx-4 mt-2 p-3 rounded-lg border ${getSentimentColor(sentimentAlert.sentiment)} flex items-start gap-2`}>
          <Heart className="h-5 w-5 flex-shrink-0 mt-0.5" />
          <div className="flex-1">
            <p className="font-semibold text-sm">
              {sentimentAlert.sentiment === 'frustrated' 
                ? 'نلاحظ أنك تبدو محبطاً' 
                : 'نلاحظ أنك تبدو متعباً'}
            </p>
            {sentimentAlert.suggestions && sentimentAlert.suggestions.length > 0 && (
              <ul className="mt-1 text-xs list-disc list-inside">
                {sentimentAlert.suggestions.slice(0, 2).map((suggestion, idx) => (
                  <li key={idx}>{suggestion}</li>
                ))}
              </ul>
            )}
          </div>
          <button
            onClick={() => setSentimentAlert(null)}
            className="text-current opacity-70 hover:opacity-100"
          >
            ×
          </button>
        </div>
      )}

      <div className="flex-1 overflow-y-auto p-4 space-y-4 max-h-[400px]">
        {messages.map((message, index) => (
          <div
            key={index}
            className={`flex gap-3 ${message.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            {message.role === 'assistant' && (
              <div className="flex-shrink-0 w-8 h-8 rounded-full bg-blue-100 flex items-center justify-center">
                <Bot className="h-4 w-4 text-blue-600" />
              </div>
            )}

            <div
              className={`max-w-[80%] rounded-2xl px-4 py-3 ${
                message.role === 'user'
                  ? 'bg-blue-500 text-white rounded-tr-none'
                  : 'bg-gray-100 text-gray-800 rounded-tl-none'
              }`}
            >
              <div className="text-sm">{message.content}</div>
              <div
                className={`text-xs mt-1 flex items-center gap-2 ${
                  message.role === 'user' ? 'text-blue-100' : 'text-gray-500'
                }`}
              >
                <span>{formatTime(message.timestamp)}</span>
                {message.sentiment && message.sentiment.sentiment === 'positive' && (
                  <span className="text-green-600">😊</span>
                )}
              </div>
            </div>

            {message.role === 'user' && (
              <div className="flex-shrink-0 w-8 h-8 rounded-full bg-blue-500 flex items-center justify-center">
                <User className="h-4 w-4 text-white" />
              </div>
            )}
          </div>
        ))}

        {isLoading && (
          <div className="flex gap-3 justify-start">
            <div className="flex-shrink-0 w-8 h-8 rounded-full bg-blue-100 flex items-center justify-center">
              <Bot className="h-4 w-4 text-blue-600" />
            </div>
            <div className="bg-gray-100 text-gray-800 rounded-2xl rounded-tl-none px-4 py-3">
              <div className="flex space-x-1">
                <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '0.4s' }}></div>
              </div>
            </div>
          </div>
        )}

        <div ref={messagesEndRef} />
      </div>

      <form onSubmit={handleSubmit} className="p-4 border-t border-gray-200">
        <div className="flex gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder={placeholder}
            className="flex-1 border border-gray-300 rounded-full px-4 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            disabled={isLoading}
          />
          <button
            type="button"
            onClick={isListening ? stopListening : startListening}
            className={`rounded-full p-2 transition-colors ${
              isListening 
                ? 'bg-red-500 hover:bg-red-600 text-white animate-pulse' 
                : 'bg-gray-200 hover:bg-gray-300 text-gray-700'
            }`}
            disabled={isLoading}
            title={isListening ? 'إيقاف التسجيل' : 'بدء التسجيل الصوتي'}
          >
            {isListening ? <MicOff className="h-5 w-5" /> : <Mic className="h-5 w-5" />}
          </button>
          <button
            type="submit"
            className="bg-blue-500 hover:bg-blue-600 text-white rounded-full p-2 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
            disabled={isLoading || !input.trim()}
          >
            <Send className="h-5 w-5" />
          </button>
        </div>
        {isListening && (
          <p className="text-xs text-red-600 mt-2 text-center animate-pulse">
            🎤 جاري الاستماع... تحدث الآن
          </p>
        )}
      </form>
    </div>
  );
}

"use client";

import React, { useState, useCallback, useMemo } from 'react';
import { FileText, BookOpen, Calendar, Brain, Loader2, CheckCircle, Zap, AlertCircle, Save, X, RefreshCw } from 'lucide-react';
import { getGeminiInfo } from '@/lib/ai-config';
import { logger } from '@/lib/logger';
import { safeFetch } from "@/lib/safe-client-utils";
import { Button } from '@/components/ui/button';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';

interface Question {
  question: string;
  type: 'multiple_choice' | 'true_false' | 'short_answer';
  options?: string[];
  correctAnswer: string;
  explanation: string;
}

interface ExamGeneratorProps {
  subjects: string[];
  years: number[];
  className?: string;
}

export default function ExamGenerator({
  subjects,
  years,
  className = ""
}: ExamGeneratorProps) {
  const [selectedSubject, setSelectedSubject] = useState('');
  const [selectedYear, setSelectedYear] = useState('');
  const [lesson, setLesson] = useState('');
  const [difficulty, setDifficulty] = useState('');
  const [questionCount, setQuestionCount] = useState(10);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [examData, setExamData] = useState<{ examId?: string; questions?: Question[] } | null>(null);
  const [error, setError] = useState('');
  const [saveError, setSaveError] = useState('');
  const [saveSuccess, setSaveSuccess] = useState(false);
  const [retryCount, setRetryCount] = useState(0);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSaveError('');
    setSaveSuccess(false);
    
    // Validation
    if (!selectedSubject || !selectedYear || !lesson) {
      setError('الرجاء ملء جميع الحقول المطلوبة');
      return;
    }

    if (lesson.trim().length < 3) {
      setError('اسم الدرس يجب أن يكون على الأقل 3 أحرف');
      return;
    }

    if (questionCount < 1 || questionCount > 50) {
      setError('عدد الأسئلة يجب أن يكون بين 1 و 50');
      return;
    }

    if (!difficulty && difficulty !== '') {
      setError('الرجاء اختيار مستوى الصعوبة');
      return;
    }

    setIsGenerating(true);
    setExamData(null);
    setError('');
    setSaveError('');
    setSaveSuccess(false);

    try {
      const { data, error: responseError } = await safeFetch<{ examId?: string; questions?: Question[] }>(
        '/api/ai/exam',
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            subject: selectedSubject,
            year: selectedYear,
            lesson: lesson.trim(),
            difficulty: difficulty || undefined,
            questionCount: Math.min(Math.max(1, questionCount), 50),
            provider: 'gemini'
          }),
        },
        null
      );

      if (responseError) {
        const errorMessage = responseError.message || 'فشلت عملية إنشاء الامتحان';
        setError(errorMessage);
        logger.error('Error generating exam:', responseError);
        
        // إعادة المحاولة التلقائية في حالة أخطاء الشبكة
        if (errorMessage.includes('network') || errorMessage.includes('timeout')) {
          if (retryCount < 2) {
            setTimeout(() => {
              setRetryCount(prev => prev + 1);
              handleSubmit(e as any);
            }, 2000);
          }
        }
      } else if (data) {
        if (!data.questions || data.questions.length === 0) {
          setError('لم يتم إنشاء أي أسئلة. يرجى المحاولة مرة أخرى.');
        } else {
          setExamData(data);
          setError('');
          setRetryCount(0);
        }
      } else {
        setError('لم يتم إنشاء الامتحان. يرجى المحاولة مرة أخرى.');
      }
    } catch (err) {
      logger.error('Error generating exam:', err);
      setError(err instanceof Error ? err.message : 'حدث خطأ غير معروف');
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSaveExam = useCallback(async () => {
    if (!examData?.questions || examData.questions.length === 0) {
      setSaveError('لا توجد أسئلة لحفظها');
      return;
    }

    if (!selectedSubject || !selectedYear || !lesson) {
      setSaveError('الرجاء التأكد من ملء جميع الحقول المطلوبة');
      return;
    }

    setIsSaving(true);
    setSaveError('');
    setSaveSuccess(false);

    try {
      // Create exam title
      const examTitle = `امتحان ${selectedSubject} - ${lesson} (${selectedYear})`;
      
      // First, create the exam record
      const { data: examResult, error: examError } = await safeFetch<{ success: boolean; exam: { id: string } }>(
        '/api/exams',
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            subject: selectedSubject,
            title: examTitle,
            year: parseInt(selectedYear),
            url: '',
            type: 'QUIZ'
          }),
        },
        null
      );

      if (examError || !examResult?.success) {
        throw new Error(examError?.message || 'فشل إنشاء سجل الامتحان');
      }

      setSaveSuccess(true);
      setSaveError('');
      
      // Reset form after successful save
      setTimeout(() => {
        setExamData(null);
        setSelectedSubject('');
        setSelectedYear('');
        setLesson('');
        setDifficulty('');
        setQuestionCount(10);
        setSaveSuccess(false);
      }, 2000);
    } catch (err) {
      logger.error('Error saving exam:', err);
      setSaveError(err instanceof Error ? err.message : 'حدث خطأ أثناء حفظ الامتحان');
    } finally {
      setIsSaving(false);
    }
  }, [examData, selectedSubject, selectedYear, lesson]);

  return (
    <div className={`bg-white rounded-xl shadow-lg p-6 ${className}`}>
      <div className="flex items-center gap-3 mb-6">
        <div className="p-2 bg-blue-100 rounded-lg">
          <FileText className="h-6 w-6 text-blue-600" />
        </div>
        <h2 className="text-xl font-bold text-gray-800">منشئ الامتحانات الذكي</h2>
        <div className="ml-auto flex items-center gap-1 text-xs bg-green-100 text-green-800 px-2 py-1 rounded-full">
          <Zap className="h-3 w-3" />
          <span>Gemini 2.0 Flash</span>
        </div>
      </div>

      {!examData ? (
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <Label htmlFor="selectedSubject" className="mb-1">
                المادة <span className="text-red-500">*</span>
              </Label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none z-10">
                  <BookOpen className="h-5 w-5 text-gray-400" aria-hidden="true" />
                </div>
                <Select
                  value={selectedSubject}
                  onValueChange={setSelectedSubject}
                  required
                >
                  <SelectTrigger className="pl-10" id="selectedSubject" aria-label="اختر المادة">
                    <SelectValue placeholder="اختر المادة" />
                  </SelectTrigger>
                  <SelectContent>
                    {subjects.map((subject) => (
                      <SelectItem key={subject} value={subject}>
                        {subject}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>

            <div>
              <Label htmlFor="selectedYear" className="mb-1">
                السنة الدراسية <span className="text-red-500">*</span>
              </Label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none z-10">
                  <Calendar className="h-5 w-5 text-gray-400" aria-hidden="true" />
                </div>
                <Select
                  value={selectedYear}
                  onValueChange={setSelectedYear}
                  required
                >
                  <SelectTrigger className="pl-10" id="selectedYear" aria-label="اختر السنة الدراسية">
                    <SelectValue placeholder="اختر السنة الدراسية" />
                  </SelectTrigger>
                  <SelectContent>
                    {years.map((year) => (
                      <SelectItem key={year} value={String(year)}>
                        {year}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>

            <div>
              <Label htmlFor="lesson" className="mb-1">
                الدرس <span className="text-red-500">*</span>
              </Label>
              <Input
                id="lesson"
                type="text"
                value={lesson}
                onChange={(e) => setLesson(e.target.value)}
                placeholder="أدخل اسم الدرس"
                required
                minLength={3}
                maxLength={200}
              />
            </div>

            <div>
              <Label htmlFor="difficulty" className="mb-1">
                مستوى الصعوبة (اختياري)
              </Label>
              <Select
                value={difficulty}
                onValueChange={setDifficulty}
              >
                <SelectTrigger id="difficulty" aria-label="مستوى الصعوبة">
                  <SelectValue placeholder="اختر مستوى الصعوبة" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="">اختر مستوى الصعوبة</SelectItem>
                  <SelectItem value="سهل">سهل</SelectItem>
                  <SelectItem value="متوسط">متوسط</SelectItem>
                  <SelectItem value="صعب">صعب</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div>
              <Label htmlFor="questionCount" className="mb-1">
                عدد الأسئلة
              </Label>
              <Input
                id="questionCount"
                type="number"
                min="1"
                max="50"
                value={questionCount}
                onChange={(e) => setQuestionCount(Math.max(1, Math.min(50, parseInt(e.target.value) || 10)))}
                aria-label="عدد الأسئلة في الامتحان"
              />
            </div>
          </div>

          {error && (
            <Alert variant="destructive" className="flex items-start gap-2" role="alert">
              <AlertCircle className="h-5 w-5 mt-0.5 flex-shrink-0" aria-hidden="true" />
              <div className="flex-1">
                <AlertDescription>{error}</AlertDescription>
                {error.includes('network') || error.includes('timeout') ? (
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => {
                      setRetryCount(0);
                      handleSubmit({ preventDefault: () => {} } as React.FormEvent);
                    }}
                    className="mt-2"
                  >
                    <RefreshCw className="h-4 w-4 mr-2" />
                    إعادة المحاولة
                  </Button>
                ) : null}
              </div>
            </Alert>
          )}

          <button
            type="submit"
            disabled={isGenerating}
            className="w-full bg-blue-500 hover:bg-blue-600 text-white font-medium py-2 px-4 rounded-lg transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
          >
            {isGenerating ? (
              <>
                <Loader2 className="h-5 w-5 animate-spin" />
                جاري إنشاء الامتحان...
              </>
            ) : (
              <>
                <Brain className="h-5 w-5" />
                إنشاء الامتحان
              </>
            )}
          </button>
        </form>
      ) : (
        <div className="space-y-6">
          <div className="flex items-center gap-2 text-green-600">
            <CheckCircle className="h-5 w-5" />
            <span className="font-medium">تم إنشاء الامتحان بنجاح!</span>
          </div>

          <div className="border border-gray-200 rounded-lg p-4">
            <h3 className="font-medium text-gray-800 mb-3">الأسئلة ({examData.questions?.length || 0})</h3>
            <div className="space-y-4 max-h-96 overflow-y-auto pr-2">
              {examData.questions?.map((question, index) => (
                <div key={index} className="border border-gray-200 rounded-lg p-4">
                  <div className="flex items-start gap-3">
                    <div className="flex-shrink-0 w-8 h-8 rounded-full bg-blue-100 flex items-center justify-center text-blue-600 font-medium">
                      {index + 1}
                    </div>
                    <div className="flex-1">
                      <p className="font-medium text-gray-800 mb-2">{question.question}</p>

                      {question.type === 'multiple_choice' && question.options && (
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-2 mb-3">
                          {question.options.map((option, i) => (
                            <div
                              key={i}
                              className={`p-2 rounded-lg border ${
                                option === question.correctAnswer
                                  ? 'border-green-500 bg-green-50'
                                  : 'border-gray-200'
                              }`}
                            >
                              {option}
                            </div>
                          ))}
                        </div>
                      )}

                      {question.type === 'true_false' && (
                        <div className="flex gap-4 mb-3">
                          <div
                            className={`p-2 rounded-lg border ${
                              question.correctAnswer === 'صح'
                                ? 'border-green-500 bg-green-50'
                                : 'border-gray-200'
                            }`}
                          >
                            صح
                          </div>
                          <div
                            className={`p-2 rounded-lg border ${
                              question.correctAnswer === 'خطأ'
                                ? 'border-green-500 bg-green-50'
                                : 'border-gray-200'
                            }`}
                          >
                            خطأ
                          </div>
                        </div>
                      )}

                      <div className="bg-blue-50 p-3 rounded-lg">
                        <p className="text-sm font-medium text-blue-800 mb-1">الإجابة الصحيحة:</p>
                        <p className="text-blue-700">{question.correctAnswer}</p>
                        {question.explanation && (
                          <>
                            <p className="text-sm font-medium text-blue-800 mt-2 mb-1">الشرح:</p>
                            <p className="text-blue-700">{question.explanation}</p>
                          </>
                        )}
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {saveSuccess && (
            <Alert className="bg-green-50 border-green-200 text-green-800 flex items-center gap-2">
              <CheckCircle className="h-5 w-5 flex-shrink-0" />
              <AlertDescription>تم حفظ الامتحان بنجاح!</AlertDescription>
            </Alert>
          )}

          {saveError && (
            <Alert variant="destructive" className="flex items-start gap-2">
              <AlertCircle className="h-5 w-5 mt-0.5 flex-shrink-0" />
              <AlertDescription>{saveError}</AlertDescription>
            </Alert>
          )}

          <div className="flex gap-3">
            <Button
              onClick={() => {
                setExamData(null);
                setError('');
                setSaveError('');
                setSaveSuccess(false);
              }}
              variant="outline"
              className="flex-1"
              disabled={isSaving}
            >
              <X className="h-4 w-4 mr-2" />
              إنشاء امتحان جديد
            </Button>
            <Button 
              onClick={handleSaveExam}
              className="flex-1"
              disabled={isSaving || !examData?.questions || examData.questions.length === 0}
            >
              {isSaving ? (
                <>
                  <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                  جاري الحفظ...
                </>
              ) : (
                <>
                  <Save className="h-4 w-4 mr-2" />
                  حفظ الامتحان
                </>
              )}
            </Button>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import React, { useState } from 'react';
import { Search, User, Star, ExternalLink, Youtube, Loader2, BookOpen, Zap } from 'lucide-react';
import { getGeminiInfo } from '@/lib/ai-config';
import { logger } from '@/lib/logger';

interface Teacher {
  name: string;
  subject: string;
  url?: string;
  description?: string;
  rating?: number;
  thumbnail?: string;
}

interface TeacherSearchProps {
  subjects: string[];
  platforms?: string[];
  className?: string;
}

export default function TeacherSearch({
  subjects,
  platforms = ['يوتيوب', 'منصة دروس', 'منصة مدرستي', 'أخرى'],
  className = ""
}: TeacherSearchProps) {
  const [selectedSubject, setSelectedSubject] = useState('');
  const [keywords, setKeywords] = useState('');
  const [selectedPlatform, setSelectedPlatform] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [teachers, setTeachers] = useState<{
    localTeachers: Teacher[];
    aiTeachers: Teacher[];
    youtubeResults: Teacher[];
  } | null>(null);
  const [error, setError] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedSubject) {
      setError('الرجاء اختيار المادة');
      return;
    }

    setIsSearching(true);
    setError('');
    setTeachers(null);

    try {
      const response = await fetch('/api/ai/teachers', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          subject: selectedSubject,
          keywords: keywords || undefined,
          platform: selectedPlatform || undefined,
          provider: 'gemini' // استخدام Gemini كخيار افتراضي
        }),
      });

      if (!response.ok) {
        let errorMessage = 'فشلت عملية البحث عن المدرسين';
        
        try {
          const errorData = await response.json();
          if (errorData && errorData.error) {
            errorMessage = errorData.error;
          }
        } catch (e) {
          logger.error('Error parsing error response:', e);
          // إذا فشل تحليل استجابة الخطأ، استخدم رسالة عامة بناءً على رمز الحالة
          if (response.status === 401) {
            errorMessage = 'مشكلة في المصادقة. يرجى تسجيل الدخول والمحاولة مرة أخرى.';
          } else if (response.status === 403) {
            errorMessage = 'مفتاح API لـ Google Gemini غير مهيأ. يرجى التواصل مع فريق الدعم.';
          } else if (response.status === 500) {
            errorMessage = 'مشكلة في الخادم. يرجى المحاولة مرة أخرى لاحقاً.';
          } else if (response.status === 429) {
            errorMessage = 'تم تجاوز حد الطلبات. يرجى المحاولة مرة أخرى بعد قليل.';
          }
        }
        
        // لا ترمي الخطأ هنا، بل قم بتعيينه مباشرة
        setError(errorMessage);
        setIsSearching(false);
        return;
      }

      let data;
      try {
        data = await response.json();
        
        // التحقق من أن البيانات تحتوي على الحقول المطلوبة
        if (!data || (typeof data !== 'object')) {
          throw new Error('بيانات غير صالحة من الخادم');
        }
        
        // التأكد من وجود الحقول الأساسية
        if (!data.localTeachers || !data.aiTeachers || !data.youtubeResults) {
          // إذا كانت هناك حقول مفقودة، قم بإنشائها
          data.localTeachers = data.localTeachers || [];
          data.aiTeachers = data.aiTeachers || [];
          data.youtubeResults = data.youtubeResults || [];
        }
        
        setTeachers(data);
      } catch (parseError) {
        logger.error('Error parsing response data:', parseError);
        setError('حدث خطأ في تحليل بيانات الاستجابة. يرجى المحاولة مرة أخرى.');
        setIsSearching(false);
        return;
      }
    } catch (err) {
      logger.error('Error searching teachers:', err);
      let errorMessage = 'حدث خطأ غير معروف';
      
      if (err instanceof Error) {
        errorMessage = err.message;
        
        // تحسين رسائل الخطأ الشائعة
        if (errorMessage.includes('API key') || errorMessage.includes('مفتاح API')) {
          errorMessage = 'مفتاح API لـ Google Gemini غير مهيأ. يرجى التواصل مع فريق الدعم لحل هذه المشكلة.';
        } else if (errorMessage.includes('fetch')) {
          errorMessage = 'فشل الاتصال بخدمة الذكاء الاصطناعي. يرجى التحقق من اتصال الإنترنت والمحاولة مرة أخرى.';
        }
      }
      
      setError(errorMessage);
    } finally {
      setIsSearching(false);
    }
  };

  const renderStars = (rating?: number) => {
    if (!rating) return null;

    return (
      <div className="flex items-center gap-1">
        {[...Array(5)].map((_, i) => (
          <Star
            key={i}
            className={`h-4 w-4 ${
              i < Math.floor(rating) ? 'text-yellow-400 fill-yellow-400' : 'text-gray-300'
            }`}
          />
        ))}
        <span className="text-sm text-gray-600 ml-1">{rating.toFixed(1)}</span>
      </div>
    );
  };

  const renderTeacherCard = (teacher: Teacher, source: string) => (
    <div key={`${teacher.name}-${source}`} className="border border-gray-200 rounded-lg p-4 hover:shadow-md transition-shadow">
      <div className="flex items-start gap-4">
        {teacher.thumbnail ? (
          <img
            src={teacher.thumbnail}
            alt={teacher.name}
            className="w-16 h-16 rounded-lg object-cover"
          />
        ) : (
          <div className="w-16 h-16 rounded-lg bg-blue-100 flex items-center justify-center">
            <User className="h-8 w-8 text-blue-600" />
          </div>
        )}

        <div className="flex-1">
          <div className="flex items-start justify-between">
            <div>
              <h3 className="font-bold text-gray-800">{teacher.name}</h3>
              <div className="flex items-center gap-2 mt-1">
                <span className="inline-flex items-center gap-1 px-2 py-1 bg-blue-100 text-blue-800 text-xs font-medium rounded-full">
                  <BookOpen className="h-3 w-3" />
                  {teacher.subject}
                </span>
                {source === 'youtube' && (
                  <span className="inline-flex items-center gap-1 px-2 py-1 bg-red-100 text-red-800 text-xs font-medium rounded-full">
                    <Youtube className="h-3 w-3" />
                    يوتيوب
                  </span>
                )}
                {source === 'ai' && (
                  <span className="inline-flex items-center gap-1 px-2 py-1 bg-green-100 text-green-800 text-xs font-medium rounded-full">
                    Gemini 2.0 Flash
                  </span>
                )}
              </div>
            </div>

            {teacher.url && (
              <a
                href={teacher.url}
                target="_blank"
                rel="noopener noreferrer"
                className="text-blue-500 hover:text-blue-700"
              >
                <ExternalLink className="h-5 w-5" />
              </a>
            )}
          </div>

          {teacher.description && (
            <p className="text-gray-600 text-sm mt-2 line-clamp-2">{teacher.description}</p>
          )}

          <div className="mt-3">
            {renderStars(teacher.rating)}
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <div className={`bg-white rounded-xl shadow-lg p-6 ${className}`}>
      <div className="flex items-center gap-3 mb-6">
        <div className="p-2 bg-blue-100 rounded-lg">
          <Search className="h-6 w-6 text-blue-600" />
        </div>
        <h2 className="text-xl font-bold text-gray-800">البحث عن مدرسين</h2>
        <div className="ml-auto flex items-center gap-1 text-xs bg-green-100 text-green-800 px-2 py-1 rounded-full">
          <Zap className="h-3 w-3" />
          <span>Gemini 2.0 Flash</span>
        </div>
      </div>

      {!teachers ? (
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                المادة <span className="text-red-500">*</span>
              </label>
              <select
                value={selectedSubject}
                onChange={(e) => setSelectedSubject(e.target.value)}
                className="block w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                required
              >
                <option value="">اختر المادة</option>
                {subjects.map((subject) => (
                  <option key={subject} value={subject}>
                    {subject}
                  </option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                كلمات مفتاحية (اختياري)
              </label>
              <input
                type="text"
                value={keywords}
                onChange={(e) => setKeywords(e.target.value)}
                placeholder="مثال: ثانوي، إعدادي..."
                className="block w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                المنصة (اختياري)
              </label>
              <select
                value={selectedPlatform}
                onChange={(e) => setSelectedPlatform(e.target.value)}
                className="block w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              >
                <option value="">الكل</option>
                {platforms.map((platform) => (
                  <option key={platform} value={platform}>
                    {platform}
                  </option>
                ))}
              </select>
            </div>
          </div>

          {error && (
            <div className="bg-red-50 text-red-700 p-3 rounded-lg">
              {error}
            </div>
          )}

          <button
            type="submit"
            disabled={isSearching}
            className="w-full bg-blue-500 hover:bg-blue-600 text-white font-medium py-2 px-4 rounded-lg transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
          >
            {isSearching ? (
              <>
                <Loader2 className="h-5 w-5 animate-spin" />
                جاري البحث...
              </>
            ) : (
              <>
                <Search className="h-5 w-5" />
                بحث عن مدرسين
              </>
            )}
          </button>
        </form>
      ) : (
        <div className="space-y-6">
          <div className="flex items-center justify-between">
            <h3 className="font-medium text-gray-800">نتائج البحث</h3>
            <button
              onClick={() => {
                setTeachers(null);
                setError('');
              }}
              className="text-blue-500 hover:text-blue-700 text-sm font-medium"
            >
              بحث جديد
            </button>
          </div>

          {teachers.localTeachers.length > 0 && (
            <div>
              <h4 className="text-sm font-medium text-gray-700 mb-3">المدرسين المحفوظين ({teachers.localTeachers.length})</h4>
              <div className="space-y-3">
                {teachers.localTeachers.map((teacher) => renderTeacherCard(teacher, 'local'))}
              </div>
            </div>
          )}

          {teachers.aiTeachers.length > 0 && (
            <div>
              <h4 className="text-sm font-medium text-gray-700 mb-3">مدرسين موصى بهم ({teachers.aiTeachers.length})</h4>
              <div className="space-y-3">
                {teachers.aiTeachers.map((teacher) => renderTeacherCard(teacher, 'ai'))}
              </div>
            </div>
          )}

          {teachers.youtubeResults.length > 0 && (
            <div>
              <h4 className="text-sm font-medium text-gray-700 mb-3">قنوات يوتيوب ({teachers.youtubeResults.length})</h4>
              <div className="space-y-3">
                {teachers.youtubeResults.map((teacher) => renderTeacherCard(teacher, 'youtube'))}
              </div>
            </div>
          )}

          {teachers.localTeachers.length === 0 && 
           teachers.aiTeachers.length === 0 && 
           teachers.youtubeResults.length === 0 && (
            <div className="text-center py-8 text-gray-500">
              لم يتم العثور على أي مدرسين. يرجى المحاولة مرة أخرى بكلمات مفتاحية مختلفة.
            </div>
          )}
        </div>
      )}
    </div>
  );
}

"use client";

import React, { useState } from 'react';
import { Lightbulb, BookOpen, Target, AlertTriangle, CheckCircle, Loader2, RefreshCw, Zap } from 'lucide-react';
import { getGeminiInfo } from '@/lib/ai-config';
import { logger } from '@/lib/logger';

interface Tip {
  category: 'استراتيجيات الدراسة' | 'التغلب على التحديات' | 'المصادر التعليمية' | 'الخطة الدراسية' | 'تحسين الأداء';
  title: string;
  content: string;
  priority: 'high' | 'medium' | 'low';
}

interface TipsGeneratorProps {
  subjects?: string[];
  userId?: string;
  className?: string;
}

export default function TipsGenerator({
  subjects = [],
  userId,
  className = ""
}: TipsGeneratorProps) {
  const [selectedSubject, setSelectedSubject] = useState('');
  const [studyGoal, setStudyGoal] = useState('');
  const [challenges, setChallenges] = useState('');
  const [currentGrade, setCurrentGrade] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [tipsData, setTipsData] = useState<{ tips?: Tip[]; summary?: string } | null>(null);
  const [error, setError] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsGenerating(true);
    setError('');
    setTipsData(null);

    try {
      const response = await fetch('/api/ai/tips', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          userId,
          subject: selectedSubject || undefined,
          studyGoal: studyGoal || undefined,
          challenges: challenges || undefined,
          currentGrade: currentGrade || undefined,
          provider: 'gemini' // استخدام Gemini كخيار افتراضي
        }),
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || 'فشلت عملية إنشاء النصائح');
      }

      const data = await response.json();
      setTipsData(data);
    } catch (err) {
      logger.error('Error generating tips:', err);
      setError(err instanceof Error ? err.message : 'حدث خطأ غير معروف');
    } finally {
      setIsGenerating(false);
    }
  };

  const getCategoryIcon = (category: Tip['category']) => {
    switch (category) {
      case 'استراتيجيات الدراسة':
        return <BookOpen className="h-5 w-5" />;
      case 'التغلب على التحديات':
        return <AlertTriangle className="h-5 w-5" />;
      case 'المصادر التعليمية':
        return <BookOpen className="h-5 w-5" />;
      case 'الخطة الدراسية':
        return <Target className="h-5 w-5" />;
      case 'تحسين الأداء':
        return <CheckCircle className="h-5 w-5" />;
      default:
        return <Lightbulb className="h-5 w-5" />;
    }
  };

  const getCategoryColor = (category: Tip['category']) => {
    switch (category) {
      case 'استراتيجيات الدراسة':
        return 'bg-blue-100 text-blue-800';
      case 'التغلب على التحديات':
        return 'bg-yellow-100 text-yellow-800';
      case 'المصادر التعليمية':
        return 'bg-green-100 text-green-800';
      case 'الخطة الدراسية':
        return 'bg-purple-100 text-purple-800';
      case 'تحسين الأداء':
        return 'bg-indigo-100 text-indigo-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const getPriorityColor = (priority: Tip['priority']) => {
    switch (priority) {
      case 'high':
        return 'bg-red-100 text-red-800';
      case 'medium':
        return 'bg-yellow-100 text-yellow-800';
      case 'low':
        return 'bg-green-100 text-green-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const getPriorityText = (priority: Tip['priority']) => {
    switch (priority) {
      case 'high':
        return 'عالية';
      case 'medium':
        return 'متوسطة';
      case 'low':
        return 'منخفضة';
      default:
        return '';
    }
  };

  return (
    <div className={`bg-white rounded-xl shadow-lg p-6 ${className}`}>
      <div className="flex items-center gap-3 mb-6">
        <div className="p-2 bg-blue-100 rounded-lg">
          <Lightbulb className="h-6 w-6 text-blue-600" />
        </div>
        <h2 className="text-xl font-bold text-gray-800">النصائح التعليمية</h2>
        <div className="ml-auto text-xs bg-green-100 text-green-800 px-2 py-1 rounded-full">
          Gemini 2.0 Flash
        </div>
      </div>

      {!tipsData ? (
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {subjects.length > 0 && (
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  المادة (اختياري)
                </label>
                <select
                  value={selectedSubject}
                  onChange={(e) => setSelectedSubject(e.target.value)}
                  className="block w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                >
                  <option value="">اختر المادة</option>
                  {subjects.map((subject) => (
                    <option key={subject} value={subject}>
                      {subject}
                    </option>
                  ))}
                </select>
              </div>
            )}

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                المستوى الدراسي (اختياري)
              </label>
              <input
                type="text"
                value={currentGrade}
                onChange={(e) => setCurrentGrade(e.target.value)}
                placeholder="مثال: أول ثانوي، ثالث إعدادي..."
                className="block w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                الهدف الدراسي (اختياري)
              </label>
              <input
                type="text"
                value={studyGoal}
                onChange={(e) => setStudyGoal(e.target.value)}
                placeholder="مثال: تحسين الدرجات، فهم مفاهيم صعبة..."
                className="block w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                التحديات (اختياري)
              </label>
              <input
                type="text"
                value={challenges}
                onChange={(e) => setChallenges(e.target.value)}
                placeholder="مثال: صعوبة الحفظ، قلة التركيز..."
                className="block w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              />
            </div>
          </div>

          {error && (
            <div className="bg-red-50 text-red-700 p-3 rounded-lg">
              {error}
            </div>
          )}

          <button
            type="submit"
            disabled={isGenerating}
            className="w-full bg-blue-500 hover:bg-blue-600 text-white font-medium py-2 px-4 rounded-lg transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
          >
            {isGenerating ? (
              <>
                <Loader2 className="h-5 w-5 animate-spin" />
                جاري إنشاء النصائح...
              </>
            ) : (
              <>
                <Lightbulb className="h-5 w-5" />
                احصل على نصائح تعليمية
              </>
            )}
          </button>
        </form>
      ) : (
        <div className="space-y-6">
          <div className="flex items-center justify-between">
            <h3 className="font-medium text-gray-800">نصائح مخصصة لك</h3>
            <button
              onClick={() => {
                setTipsData(null);
                setError('');
              }}
              className="text-blue-500 hover:text-blue-700 text-sm font-medium flex items-center gap-1"
            >
              <RefreshCw className="h-4 w-4" />
              نصائح جديدة
            </button>
          </div>

          {tipsData.summary && (
            <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
              <h4 className="font-medium text-blue-800 mb-2">ملخص النصائح</h4>
              <p className="text-blue-700">{tipsData.summary}</p>
            </div>
          )}

          <div className="space-y-4">
            {tipsData.tips?.map((tip, index) => (
              <div key={index} className="border border-gray-200 rounded-lg p-4 hover:shadow-md transition-shadow">
                <div className="flex items-start justify-between mb-3">
                  <div className="flex items-center gap-2">
                    <div className={`p-2 rounded-lg ${getCategoryColor(tip.category)}`}>
                      {getCategoryIcon(tip.category)}
                    </div>
                    <h4 className="font-bold text-gray-800">{tip.title}</h4>
                  </div>
                  <span className={`text-xs px-2 py-1 rounded-full ${getPriorityColor(tip.priority)}`}>
                    {getPriorityText(tip.priority)}
                  </span>
                </div>
                <p className="text-gray-600">{tip.content}</p>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

'use client';

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Progress } from "@/components/ui/progress";
import { Target, TrendingUp, TrendingDown, Activity, Zap, Award } from 'lucide-react';

type WeeklyData = { 
	bySubject: Record<string, number>; 
	byDay: { date: string | Date; minutes: number }[] 
};

type SummaryData = {
	totalMinutes: number;
	averageFocus: number;
	tasksCompleted: number;
	streakDays: number;
};

interface PerformanceMetricsData {
	[key: string]: unknown;
}

interface PerformanceMetricsProps {
	summary: SummaryData | null;
	weekly: WeeklyData | null;
	performanceMetrics: PerformanceMetricsData | null;
}

export default function PerformanceMetrics({ 
	summary, 
	weekly, 
	performanceMetrics 
}: PerformanceMetricsProps) {
	const calculateMetrics = () => {
		if (!summary || !weekly) {
			return {
				productivityScore: 0,
				consistencyScore: 0,
				engagementScore: 0,
				growthRate: 0
			};
		}

		// Productivity Score (0-100)
		const totalHours = summary.totalMinutes / 60;
		const weeklyHours = Object.values(weekly.bySubject).reduce((a, b) => a + b, 0) / 60;
		const productivityScore = Math.min(100, Math.round(
			(totalHours / 20 * 30) + // 30% weight for total hours
			(weeklyHours / 20 * 30) + // 30% weight for weekly hours
			(summary.averageFocus / 100 * 40) // 40% weight for focus
		));

		// Consistency Score (0-100)
		const dailyMinutes = weekly.byDay.map(d => d.minutes);
		const activeDays = dailyMinutes.filter(m => m > 0).length;
		const consistencyScore = Math.round((activeDays / 7) * 100);

		// Engagement Score (0-100)
		const taskCompletionRate = summary.tasksCompleted > 0 
			? Math.min(100, (summary.tasksCompleted / (summary.tasksCompleted + 5)) * 100)
			: 0;
		const engagementScore = Math.round(
			(taskCompletionRate * 0.5) + 
			(summary.streakDays / 30 * 50)
		);

		// Growth Rate
		const firstHalf = dailyMinutes.slice(0, Math.floor(dailyMinutes.length / 2));
		const secondHalf = dailyMinutes.slice(Math.floor(dailyMinutes.length / 2));
		const firstAvg = firstHalf.length > 0 
			? firstHalf.reduce((a, b) => a + b, 0) / firstHalf.length 
			: 0;
		const secondAvg = secondHalf.length > 0
			? secondHalf.reduce((a, b) => a + b, 0) / secondHalf.length
			: 0;
		const growthRate = firstAvg > 0 
			? Math.round(((secondAvg - firstAvg) / firstAvg) * 100)
			: 0;

		return {
			productivityScore,
			consistencyScore,
			engagementScore,
			growthRate
		};
	};

	const metrics = calculateMetrics();

	const getScoreColor = (score: number) => {
		if (score >= 80) return 'text-green-600 dark:text-green-400';
		if (score >= 60) return 'text-blue-600 dark:text-blue-400';
		if (score >= 40) return 'text-yellow-600 dark:text-yellow-400';
		return 'text-red-600 dark:text-red-400';
	};

	const getScoreLabel = (score: number) => {
		if (score >= 80) return 'ممتاز';
		if (score >= 60) return 'جيد';
		if (score >= 40) return 'متوسط';
		return 'يحتاج تحسين';
	};

	const performanceCards = [
		{
			title: "درجة الإنتاجية",
			value: metrics.productivityScore,
			icon: Zap,
			color: "from-blue-500 to-blue-600",
			bgColor: "bg-blue-50 dark:bg-blue-950/20",
			borderColor: "border-blue-200 dark:border-blue-800",
			description: "مقياس أدائك الإجمالي"
		},
		{
			title: "درجة الانتظام",
			value: metrics.consistencyScore,
			icon: Target,
			color: "from-green-500 to-green-600",
			bgColor: "bg-green-50 dark:bg-green-950/20",
			borderColor: "border-green-200 dark:border-green-800",
			description: "معدل المذاكرة المنتظمة"
		},
		{
			title: "درجة المشاركة",
			value: metrics.engagementScore,
			icon: Activity,
			color: "from-purple-500 to-purple-600",
			bgColor: "bg-purple-50 dark:bg-purple-950/20",
			borderColor: "border-purple-200 dark:border-purple-800",
			description: "مستوى تفاعلك مع المحتوى"
		},
		{
			title: "معدل النمو",
			value: metrics.growthRate,
			icon: metrics.growthRate >= 0 ? TrendingUp : TrendingDown,
			color: metrics.growthRate >= 0 ? "from-green-500 to-green-600" : "from-red-500 to-red-600",
			bgColor: metrics.growthRate >= 0 ? "bg-green-50 dark:bg-green-950/20" : "bg-red-50 dark:bg-red-950/20",
			borderColor: metrics.growthRate >= 0 ? "border-green-200 dark:border-green-800" : "border-red-200 dark:border-red-800",
			description: "التطور في الأداء",
			isPercentage: true
		}
	];

	return (
		<div className="space-y-6">
			{/* Performance Score Cards */}
			<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
				{performanceCards.map((card, index) => {
					const Icon = card.icon;
					return (
						<Card 
							key={index}
							className={`${card.bgColor} ${card.borderColor} border-2 hover:shadow-lg transition-all duration-300`}
						>
							<CardContent className="p-6">
								<div className="flex items-start justify-between mb-4">
									<div className="flex-1">
										<p className="text-sm font-medium text-muted-foreground mb-1">
											{card.title}
										</p>
										<p className={`text-3xl font-bold ${getScoreColor(card.value)} mb-1`}>
											{card.value}{card.isPercentage ? '%' : ''}
										</p>
										<p className="text-xs text-muted-foreground">
											{card.description}
										</p>
									</div>
									<div className={`p-3 rounded-lg bg-gradient-to-br ${card.color}`}>
										<Icon className="h-6 w-6 text-white" />
									</div>
								</div>
								{!card.isPercentage && (
									<>
										<Progress value={card.value} className="h-2 mt-4" />
										<p className="text-xs text-muted-foreground mt-2 text-center">
											{getScoreLabel(card.value)}
										</p>
									</>
								)}
							</CardContent>
						</Card>
					);
				})}
			</div>

			{/* Overall Performance Summary */}
			<Card className="border-2 border-primary/20 shadow-lg">
				<CardHeader className="bg-gradient-to-r from-primary/5 to-primary/10 dark:from-primary/10 dark:to-primary/20">
					<CardTitle className="flex items-center gap-2">
						<Award className="h-5 w-5 text-primary" />
						ملخص الأداء الشامل
					</CardTitle>
				</CardHeader>
				<CardContent className="p-6">
					<div className="grid grid-cols-1 md:grid-cols-3 gap-6">
						<div className="space-y-2">
							<p className="text-sm font-medium text-muted-foreground">متوسط الأداء</p>
							<p className={`text-3xl font-bold ${getScoreColor(
								(metrics.productivityScore + metrics.consistencyScore + metrics.engagementScore) / 3
							)}`}>
								{Math.round((metrics.productivityScore + metrics.consistencyScore + metrics.engagementScore) / 3)}%
							</p>
							<Progress 
								value={(metrics.productivityScore + metrics.consistencyScore + metrics.engagementScore) / 3} 
								className="h-3 mt-2"
							/>
						</div>
						<div className="space-y-2">
							<p className="text-sm font-medium text-muted-foreground">الاتجاه</p>
							<div className="flex items-center gap-2">
								{metrics.growthRate >= 0 ? (
									<>
										<TrendingUp className="h-6 w-6 text-green-600 dark:text-green-400" />
										<p className="text-2xl font-bold text-green-600 dark:text-green-400">
											تحسن
										</p>
									</>
								) : (
									<>
										<TrendingDown className="h-6 w-6 text-red-600 dark:text-red-400" />
										<p className="text-2xl font-bold text-red-600 dark:text-red-400">
											تراجع
										</p>
									</>
								)}
							</div>
							<p className="text-xs text-muted-foreground">
								{metrics.growthRate >= 0 ? 'أداؤك في تحسن مستمر' : 'يحتاج إلى تحسين'}
							</p>
						</div>
						<div className="space-y-2">
							<p className="text-sm font-medium text-muted-foreground">التوصية</p>
							<p className="text-lg font-semibold">
								{metrics.productivityScore >= 80 
									? 'استمر في الأداء الممتاز'
									: metrics.productivityScore >= 60
									? 'أنت على الطريق الصحيح'
									: 'ركز على زيادة وقت المذاكرة'
								}
							</p>
							<p className="text-xs text-muted-foreground">
								بناءً على تحليل أدائك
							</p>
						</div>
					</div>
				</CardContent>
			</Card>
		</div>
	);
}

'use client';

import { useMemo } from 'react';
import {
	Chart as ChartJS,
	CategoryScale,
	LinearScale,
	PointElement,
	LineElement,
	Tooltip,
	Legend,
	Filler
} from "chart.js";
import { Line } from "react-chartjs-2";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { TrendingUp, TrendingDown, Calendar, Clock, Activity } from 'lucide-react';
import { format } from 'date-fns';
import { ar } from 'date-fns/locale';
import { useIsMounted } from '@/lib/safe-client-utils';

ChartJS.register(
	CategoryScale,
	LinearScale,
	PointElement,
	LineElement,
	Tooltip,
	Legend,
	Filler
);

type WeeklyData = { 
	bySubject: Record<string, number>; 
	byDay: { date: string | Date; minutes: number }[] 
};

interface TimeTrendsProps {
	weekly: WeeklyData | null;
}

export default function TimeTrends({ weekly }: TimeTrendsProps) {
	const isMounted = useIsMounted();
	
	const trendData = useMemo(() => {
		if (!weekly || !weekly.byDay) return null;

		const days = weekly.byDay.map((d, index) => {
			const date = new Date(d.date);
			return {
				date,
				label: format(date, 'EEEE', { locale: ar }),
				shortLabel: format(date, 'EEE', { locale: ar }),
				minutes: d.minutes,
				hours: d.minutes / 60
			};
		});

		// Calculate trends
		const firstHalf = days.slice(0, Math.floor(days.length / 2));
		const secondHalf = days.slice(Math.floor(days.length / 2));
		const firstAvg = firstHalf.reduce((sum, d) => sum + d.minutes, 0) / firstHalf.length || 0;
		const secondAvg = secondHalf.reduce((sum, d) => sum + d.minutes, 0) / secondHalf.length || 0;
		const trend = secondAvg > firstAvg ? 'up' : secondAvg < firstAvg ? 'down' : 'stable';
		const trendPercentage = firstAvg > 0 
			? Math.abs(((secondAvg - firstAvg) / firstAvg) * 100)
			: 0;

		// Find peak and low days
		const peakDay = days.length > 0 
			? days.reduce((max, day) => day.minutes > max.minutes ? day : max, days[0])
			: null;
		const lowDay = days.length > 0
			? days.reduce((min, day) => day.minutes < min.minutes ? day : min, days[0])
			: null;

		return {
			days,
			trend,
			trendPercentage,
			firstAvg,
			secondAvg,
			peakDay,
			lowDay,
			totalMinutes: days.reduce((sum, d) => sum + d.minutes, 0)
		};
	}, [weekly]);

	if (!trendData) {
		return (
			<Card>
				<CardContent className="p-6">
					<div className="text-center py-8 text-muted-foreground">
						<Activity className="h-12 w-12 mx-auto mb-4 opacity-50" />
						<p>لا توجد بيانات للاتجاهات</p>
					</div>
				</CardContent>
			</Card>
		);
	}

	const lineChartData = {
		labels: trendData.days.map(d => d.shortLabel),
		datasets: [
			{
				label: "وقت المذاكرة (دقائق)",
				data: trendData.days.map(d => d.minutes),
				borderColor: 'rgb(59, 130, 246)',
				backgroundColor: 'rgba(59, 130, 246, 0.1)',
				fill: true,
				tension: 0.4,
				pointRadius: 6,
				pointHoverRadius: 8,
				pointBackgroundColor: 'rgb(59, 130, 246)',
				pointBorderColor: '#fff',
				pointBorderWidth: 2
			},
			{
				label: "المتوسط",
				data: trendData.days.map(() => trendData.firstAvg),
				borderColor: 'rgba(156, 163, 175, 0.5)',
				backgroundColor: 'transparent',
				borderDash: [5, 5],
				pointRadius: 0,
				fill: false
			}
		]
	};

	return (
		<div className="space-y-6">
			{/* Trend Summary Cards */}
			<div className="grid grid-cols-1 md:grid-cols-4 gap-4">
				<Card className={`border-2 ${
					trendData.trend === 'up' 
						? 'border-green-200 dark:border-green-800 bg-green-50 dark:bg-green-950/20'
						: trendData.trend === 'down'
						? 'border-red-200 dark:border-red-800 bg-red-50 dark:bg-red-950/20'
						: 'border-gray-200 dark:border-gray-800'
				}`}>
					<CardContent className="p-6">
						<div className="flex items-center justify-between">
							<div>
								<p className="text-sm font-medium text-muted-foreground mb-1">الاتجاه</p>
								<p className="text-2xl font-bold">
									{trendData.trend === 'up' ? 'تحسن' : trendData.trend === 'down' ? 'تراجع' : 'مستقر'}
								</p>
							</div>
							{trendData.trend === 'up' ? (
								<TrendingUp className="h-8 w-8 text-green-600 dark:text-green-400" />
							) : trendData.trend === 'down' ? (
								<TrendingDown className="h-8 w-8 text-red-600 dark:text-red-400" />
							) : (
								<Activity className="h-8 w-8 text-gray-600 dark:text-gray-400" />
							)}
						</div>
					</CardContent>
				</Card>
				<Card className="border-blue-200 dark:border-blue-800">
					<CardContent className="p-6">
						<div className="flex items-center justify-between">
							<div>
								<p className="text-sm font-medium text-muted-foreground mb-1">متوسط اليوم</p>
								<p className="text-2xl font-bold">
									{(trendData.firstAvg / 60).toFixed(1)} ساعة
								</p>
							</div>
							<Clock className="h-8 w-8 text-blue-600 dark:text-blue-400" />
						</div>
					</CardContent>
				</Card>
				<Card className="border-purple-200 dark:border-purple-800">
					<CardContent className="p-6">
						<div className="flex items-center justify-between">
							<div>
								<p className="text-sm font-medium text-muted-foreground mb-1">أفضل يوم</p>
								<p className="text-2xl font-bold">{trendData.peakDay?.label || '-'}</p>
							</div>
							<Calendar className="h-8 w-8 text-purple-600 dark:text-purple-400" />
						</div>
					</CardContent>
				</Card>
				<Card className="border-orange-200 dark:border-orange-800">
					<CardContent className="p-6">
						<div className="flex items-center justify-between">
							<div>
								<p className="text-sm font-medium text-muted-foreground mb-1">التغيير</p>
								<p className={`text-2xl font-bold ${
									trendData.trend === 'up' 
										? 'text-green-600 dark:text-green-400'
										: trendData.trend === 'down'
										? 'text-red-600 dark:text-red-400'
										: 'text-gray-600 dark:text-gray-400'
								}`}>
									{trendData.trend === 'up' ? '+' : trendData.trend === 'down' ? '-' : ''}
									{trendData.trendPercentage.toFixed(1)}%
								</p>
							</div>
							<Activity className="h-8 w-8 text-orange-600 dark:text-orange-400" />
						</div>
					</CardContent>
				</Card>
			</div>

			{/* Trend Chart */}
			{isMounted && (
				<Card>
					<CardHeader className="bg-gradient-to-r from-blue-50 to-blue-100 dark:from-blue-950/20 dark:to-blue-900/20">
						<CardTitle className="flex items-center gap-2">
							<TrendingUp className="h-5 w-5 text-blue-600 dark:text-blue-400" />
							اتجاه وقت المذاكرة خلال الأسبوع
						</CardTitle>
					</CardHeader>
					<CardContent className="p-6">
						<div className="h-96">
							<Line
								data={lineChartData}
							options={{
								responsive: true,
								maintainAspectRatio: false,
								plugins: {
									legend: {
										display: true,
										position: 'top'
									},
									tooltip: {
										callbacks: {
											label: (context) => {
												if (context.datasetIndex === 0) {
													const minutes = context.parsed.y ?? 0;
													const hours = (minutes / 60).toFixed(1);
													return `${context.dataset.label}: ${minutes} دقيقة (${hours} ساعة)`;
												}
												const minutes = context.parsed.y ?? 0;
												return `${context.dataset.label}: ${minutes.toFixed(1)} دقيقة`;
											}
										}
									}
								},
								scales: {
									y: {
										beginAtZero: true,
										ticks: {
											callback: function(value) {
												return value + ' د';
											}
										}
									}
								}
							}}
						/>
					</div>
				</CardContent>
			</Card>
			)}

			{/* Day Details */}
			<Card>
				<CardHeader className="bg-gradient-to-r from-green-50 to-green-100 dark:from-green-950/20 dark:to-green-900/20">
					<CardTitle className="flex items-center gap-2">
						<Calendar className="h-5 w-5 text-green-600 dark:text-green-400" />
						تفاصيل الأيام
					</CardTitle>
				</CardHeader>
				<CardContent className="p-6">
					<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
						{trendData.days.map((day, index) => (
							<div
								key={index}
								className={`p-4 rounded-lg border-2 ${
									day.minutes === trendData.peakDay?.minutes
										? 'border-green-200 dark:border-green-800 bg-green-50 dark:bg-green-950/20'
										: day.minutes === trendData.lowDay?.minutes
										? 'border-red-200 dark:border-red-800 bg-red-50 dark:bg-red-950/20'
										: 'border-gray-200 dark:border-gray-800'
								}`}
							>
								<div className="flex items-center justify-between mb-2">
									<p className="font-semibold">{day.label}</p>
									{day.minutes === trendData.peakDay?.minutes && (
										<TrendingUp className="h-4 w-4 text-green-600 dark:text-green-400" />
									)}
									{day.minutes === trendData.lowDay?.minutes && (
										<TrendingDown className="h-4 w-4 text-red-600 dark:text-red-400" />
									)}
								</div>
								<p className="text-2xl font-bold">{day.hours.toFixed(1)} ساعة</p>
								<p className="text-sm text-muted-foreground">{day.minutes} دقيقة</p>
							</div>
						))}
					</div>
				</CardContent>
			</Card>
		</div>
	);
}

"use client";

import { useEffect, useState } from "react";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { PageContainer } from "@/components/ui/PageContainer";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { AuthGuard } from "@/components/auth/AuthGuard";
import { 
	BarChart3, 
	TrendingUp, 
	TrendingDown, 
	Clock, 
	Target, 
	Calendar, 
	Zap, 
	Brain,
	RefreshCw,
	Download,
	Filter,
	Activity,
	Award,
	BookOpen,
	ArrowUp,
	ArrowDown
} from 'lucide-react';
import { ensureUser } from "@/lib/user-utils";
import OverviewStats from "./components/OverviewStats";
import WeeklyChart from "./components/WeeklyChart";
import PerformanceMetrics from "./components/PerformanceMetrics";
import PredictionsSection from "./components/PredictionsSection";
import SubjectDistribution from "./components/SubjectDistribution";
import TimeTrends from "./components/TimeTrends";
import StudyPatterns from "./components/StudyPatterns";

import { logger } from '@/lib/logger';

type WeeklyData = { 
	bySubject: Record<string, number>; 
	byDay: { date: string | Date; minutes: number }[] 
};

type SummaryData = {
	totalMinutes: number;
	averageFocus: number;
	tasksCompleted: number;
	streakDays: number;
};

type PredictionsData = {
	period: string;
	predictedScore: number;
	confidence: number;
	milestones: Array<{ date: string; goal: string; status: string }>;
	recommendations: string[];
};

function AnalyticsPage() {
	const [activeTab, setActiveTab] = useState("overview");
	const [isLoading, setIsLoading] = useState(true);
	const [summary, setSummary] = useState<SummaryData | null>(null);
	const [weekly, setWeekly] = useState<WeeklyData | null>(null);
	const [predictions, setPredictions] = useState<PredictionsData[]>([]);
	const [performanceMetrics, setPerformanceMetrics] = useState<Record<string, unknown> | null>(null);
	const [error, setError] = useState<string | null>(null);

	const fetchData = async () => {
		try {
			setIsLoading(true);
			setError(null);
			const userId = await ensureUser();
			
			// Fetch all data in parallel
			const [summaryRes, weeklyRes, predictionsRes, performanceRes] = await Promise.all([
				fetch(`/api/progress/summary?userId=${userId}`).catch(() => null),
				fetch(`/api/analytics/weekly?userId=${userId}`).catch(() => null),
				fetch(`/api/analytics/predictions?userId=${userId}`).catch(() => null),
				fetch(`/api/analytics/performance?hours=168`).catch(() => null)
			]);

			if (summaryRes?.ok) {
				try {
					const summaryData = await summaryRes.json();
					setSummary(summaryData);
				} catch (e) {
					logger.error('Error parsing summary data:', e);
				}
			}

			if (weeklyRes?.ok) {
				try {
					const weeklyData = await weeklyRes.json();
					setWeekly(weeklyData);
				} catch (e) {
					logger.error('Error parsing weekly data:', e);
				}
			}

			if (predictionsRes?.ok) {
				try {
					const predictionsData = await predictionsRes.json();
					if (predictionsData.success) {
						setPredictions(predictionsData.predictions || []);
					}
				} catch (e) {
					logger.error('Error parsing predictions data:', e);
				}
			}

			if (performanceRes?.ok) {
				try {
					const performanceData = await performanceRes.json();
					setPerformanceMetrics(performanceData);
				} catch (e) {
					logger.error('Error parsing performance data:', e);
				}
			}
		} catch (err: unknown) {
			logger.error('Error fetching analytics:', err);
			const errorMessage = err instanceof Error ? err.message : 'حدث خطأ أثناء تحميل البيانات';
			setError(errorMessage);
		} finally {
			setIsLoading(false);
		}
	};

	useEffect(() => {
		fetchData();
	}, []);

	const handleExport = () => {
		// Export analytics data as JSON
		const exportData = {
			summary,
			weekly,
			predictions,
			performanceMetrics,
			exportedAt: new Date().toISOString()
		};
		const blob = new Blob([JSON.stringify(exportData, null, 2)], { type: 'application/json' });
		const url = URL.createObjectURL(blob);
		const a = document.createElement('a');
		a.href = url;
		a.download = `analytics-${new Date().toISOString().split('T')[0]}.json`;
		document.body.appendChild(a);
		a.click();
		document.body.removeChild(a);
		URL.revokeObjectURL(url);
	};

	if (isLoading) {
		return (
			<PageContainer size="xl" spacing="lg">
				<div className="flex flex-col items-center justify-center min-h-[400px] space-y-4">
					<RefreshCw className="h-8 w-8 animate-spin text-primary" />
					<p className="text-lg font-semibold">جاري تحميل التحليلات...</p>
					<p className="text-sm text-muted-foreground">يرجى الانتظار</p>
				</div>
			</PageContainer>
		);
	}

	if (error) {
		return (
			<PageContainer size="xl" spacing="lg">
				<Card className="border-red-200 dark:border-red-800">
					<CardContent className="p-6">
						<div className="flex flex-col items-center justify-center space-y-4 text-center">
							<div className="p-3 bg-red-100 dark:bg-red-900/30 rounded-full">
								<Activity className="h-6 w-6 text-red-600 dark:text-red-400" />
							</div>
							<div>
								<h3 className="text-lg font-semibold mb-2">حدث خطأ</h3>
								<p className="text-sm text-muted-foreground mb-4">{error}</p>
								<Button onClick={fetchData} variant="outline">
									<RefreshCw className="h-4 w-4 ml-2" />
									إعادة المحاولة
								</Button>
							</div>
						</div>
					</CardContent>
				</Card>
			</PageContainer>
		);
	}

	return (
		<PageContainer size="xl" spacing="lg">
			{/* Header */}
			<div className="mb-8 text-center">
				<div className="flex items-center justify-center gap-3 mb-4">
					<div className="p-3 bg-gradient-to-r from-blue-600 to-indigo-700 rounded-xl shadow-lg">
						<BarChart3 className="h-8 w-8 text-white" />
					</div>
					<h1 className="text-3xl md:text-4xl font-bold text-gray-800 dark:text-gray-100">
						التحليلات والإحصائيات
					</h1>
				</div>
				<p className="text-base md:text-lg text-gray-600 dark:text-gray-300 max-w-2xl mx-auto mb-6">
					تابع أداءك التعليمي وتطورك مع تحليلات شاملة ومفصلة
				</p>
				<div className="flex items-center justify-center gap-3">
					<Button
						variant="outline"
						size="sm"
						onClick={fetchData}
						className="flex items-center gap-2"
					>
						<RefreshCw className="h-4 w-4" />
						تحديث البيانات
					</Button>
					<Button
						variant="outline"
						size="sm"
						onClick={handleExport}
						className="flex items-center gap-2"
					>
						<Download className="h-4 w-4" />
						تصدير البيانات
					</Button>
				</div>
			</div>

			{/* Tabs */}
			<Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
				<TabsList className="grid w-full grid-cols-2 sm:grid-cols-4 lg:grid-cols-7 gap-2 mb-6">
					<TabsTrigger value="overview" className="flex items-center gap-2">
						<Activity className="h-4 w-4" />
						<span className="hidden sm:inline">نظرة عامة</span>
					</TabsTrigger>
					<TabsTrigger value="weekly" className="flex items-center gap-2">
						<Calendar className="h-4 w-4" />
						<span className="hidden sm:inline">الأسبوعي</span>
					</TabsTrigger>
					<TabsTrigger value="performance" className="flex items-center gap-2">
						<Target className="h-4 w-4" />
						<span className="hidden sm:inline">الأداء</span>
					</TabsTrigger>
					<TabsTrigger value="subjects" className="flex items-center gap-2">
						<BookOpen className="h-4 w-4" />
						<span className="hidden sm:inline">المواد</span>
					</TabsTrigger>
					<TabsTrigger value="trends" className="flex items-center gap-2">
						<TrendingUp className="h-4 w-4" />
						<span className="hidden sm:inline">الاتجاهات</span>
					</TabsTrigger>
					<TabsTrigger value="patterns" className="flex items-center gap-2">
						<Brain className="h-4 w-4" />
						<span className="hidden sm:inline">الأنماط</span>
					</TabsTrigger>
					<TabsTrigger value="predictions" className="flex items-center gap-2">
						<Zap className="h-4 w-4" />
						<span className="hidden sm:inline">التنبؤات</span>
					</TabsTrigger>
				</TabsList>

				<TabsContent value="overview" className="space-y-6">
					<OverviewStats summary={summary} weekly={weekly} />
				</TabsContent>

				<TabsContent value="weekly" className="space-y-6">
					<WeeklyChart weekly={weekly} />
				</TabsContent>

				<TabsContent value="performance" className="space-y-6">
					<PerformanceMetrics 
						summary={summary} 
						weekly={weekly}
						performanceMetrics={performanceMetrics}
					/>
				</TabsContent>

				<TabsContent value="subjects" className="space-y-6">
					<SubjectDistribution weekly={weekly} />
				</TabsContent>

				<TabsContent value="trends" className="space-y-6">
					<TimeTrends weekly={weekly} />
				</TabsContent>

				<TabsContent value="patterns" className="space-y-6">
					<StudyPatterns weekly={weekly} />
				</TabsContent>

				<TabsContent value="predictions" className="space-y-6">
					<PredictionsSection predictions={predictions} />
				</TabsContent>
			</Tabs>
		</PageContainer>
	);
}

// Wrap with AuthGuard
const AnalyticsPageWithAuth = () => {
	return (
		<AuthGuard>
			<AnalyticsPage />
		</AuthGuard>
	);
};

export default AnalyticsPageWithAuth;

"use client";

import { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { AuthGuard } from "@/components/auth/AuthGuard";
import { useGamification, CustomGoal } from '@/hooks/use-gamification';
import { AchievementToast } from '@/components/gamification/AchievementToast';
import { ensureUser } from "@/lib/user-utils";
import { CreateGoalModal } from './components/CreateGoalModal';
import { GoalCard } from './components/GoalCard';

export default function GoalsPage() {
  const [userId, setUserId] = useState<string>('');
  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [filter, setFilter] = useState<'all' | 'active' | 'completed'>('all');

  const {
    userProgress,
    currentAchievement,
    clearAchievementNotification,
    createCustomGoal,
    updateCustomGoal,
    isLoading,
    error
  } = useGamification({
    userId,
    enableRealTime: true,
    enableNotifications: true
  });

  useEffect(() => {
    (async () => {
      const id = await ensureUser();
      setUserId(id);
    })();
  }, []);

  const handleCreateGoal = async (goalData: Omit<CustomGoal, 'id' | 'userId' | 'isCompleted' | 'createdAt' | 'completedAt'>) => {
    await createCustomGoal(goalData);
  };

  const handleUpdateGoal = async (goalId: string, currentValue: number) => {
    await updateCustomGoal(goalId, currentValue);
  };

  const filteredGoals = userProgress?.customGoals.filter(goal => {
    if (filter === 'active') return !goal.isCompleted;
    if (filter === 'completed') return goal.isCompleted;
    return true;
  }) || [];

  if (isLoading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-green-50 to-emerald-100 p-4">
        <div className="max-w-4xl mx-auto">
          <div className="flex justify-center items-center py-20">
            <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-emerald-600"></div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <AuthGuard>
      <div className="min-h-screen bg-gradient-to-br from-green-50 to-emerald-100">
      <div className="max-w-4xl mx-auto p-4">
        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          className="text-center mb-8"
        >
          <h1 className="text-4xl font-bold text-gray-900 mb-2">
            🎯 أهدافي المخصصة
          </h1>
          <p className="text-gray-600">
            حدد أهدافك الخاصة وسجل تقدمك نحو تحقيقها
          </p>
        </motion.div>

        {/* Filter Tabs */}
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.2 }}
          className="flex justify-center mb-8"
        >
          <div className="bg-white rounded-lg p-1 shadow-md">
            {[
              { key: 'all', label: 'الكل', icon: '📋' },
              { key: 'active', label: 'نشط', icon: '🔄' },
              { key: 'completed', label: 'مكتمل', icon: '✅' }
            ].map(tab => (
              <button
                key={tab.key}
                onClick={() => setFilter(tab.key as any)}
                className={`px-6 py-2 rounded-md font-medium transition-all ${
                  filter === tab.key
                    ? 'bg-emerald-600 text-white shadow-md'
                    : 'text-gray-600 hover:text-gray-900'
                }`}
              >
                {tab.icon} {tab.label}
              </button>
            ))}
          </div>
        </motion.div>

        {/* Create Goal Button */}
        <motion.div
          initial={{ opacity: 0, scale: 0.95 }}
          animate={{ opacity: 1, scale: 1 }}
          transition={{ delay: 0.3 }}
          className="mb-8"
        >
          <button
            onClick={() => setIsCreateModalOpen(true)}
            className="w-full bg-gradient-to-r from-emerald-500 to-green-600 text-white py-4 px-6 rounded-xl font-bold text-lg hover:from-emerald-600 hover:to-green-700 transition-all shadow-lg hover:shadow-xl"
          >
            ➕ إنشاء هدف جديد
          </button>
        </motion.div>

        {/* Goals Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <AnimatePresence>
            {filteredGoals.map((goal, index) => (
              <GoalCard
                key={goal.id}
                goal={goal}
                onUpdateProgress={handleUpdateGoal}
                onComplete={handleUpdateGoal}
              />
            ))}
          </AnimatePresence>
        </div>

        {filteredGoals.length === 0 && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="text-center py-16"
          >
            <div className="text-6xl mb-4">🎯</div>
            <h3 className="text-xl font-semibold text-gray-900 mb-2">
              {filter === 'all' ? 'لا توجد أهداف بعد' :
               filter === 'active' ? 'لا توجد أهداف نشطة' :
               'لا توجد أهداف مكتملة'}
            </h3>
            <p className="text-gray-600 mb-6">
              ابدأ بإنشاء هدف جديد لتتبع تقدمك
            </p>
            <button
              onClick={() => setIsCreateModalOpen(true)}
              className="bg-emerald-600 text-white px-6 py-3 rounded-lg font-medium hover:bg-emerald-700 transition-colors"
            >
              إنشاء أول هدف
            </button>
          </motion.div>
        )}
      </div>

      {/* Create Goal Modal */}
      <CreateGoalModal
        isOpen={isCreateModalOpen}
        onClose={() => setIsCreateModalOpen(false)}
        onCreateGoal={handleCreateGoal}
      />

      {/* Achievement Toast */}
      <AchievementToast
        achievement={currentAchievement}
        onClose={clearAchievementNotification}
      />
      </div>
    </AuthGuard>
  );
}

"use client";

import { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { AuthGuard } from "@/components/auth/AuthGuard";
import { useGamification } from '@/hooks/use-gamification';
import { AchievementToast } from '@/components/gamification/AchievementToast';

import { ensureUser } from "@/lib/user-utils";

export default function LeaderboardPage() {
  const [userId, setUserId] = useState<string>('');
  const [leaderboardType, setLeaderboardType] = useState<'global' | 'friends'>('global');

  const {
    leaderboard,
    userProgress,
    currentAchievement,
    clearAchievementNotification,
    getUserRank,
    isLoading,
    error
  } = useGamification({
    userId,
    enableRealTime: true,
    enableNotifications: true
  });

  useEffect(() => {
    (async () => {
      const id = await ensureUser();
      setUserId(id);
    })();
  }, []);

  const userRank = getUserRank();

  // Ensure leaderboard is always an array
  const safeLeaderboard = Array.isArray(leaderboard) ? leaderboard : [];

  if (isLoading) {
    return (
      <AuthGuard>
        <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100 p-4">
          <div className="max-w-4xl mx-auto">
            <div className="flex justify-center items-center py-20">
              <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-indigo-600"></div>
            </div>
          </div>
        </div>
      </AuthGuard>
    );
  }

  return (
    <AuthGuard>
      <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100">
      <div className="max-w-4xl mx-auto p-4">
        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          className="text-center mb-8"
        >
          <h1 className="text-4xl font-bold text-gray-900 mb-2">
            🏆 لوحة المتصدرين
          </h1>
          <p className="text-gray-600">
            تابع تقدمك وترتيبك بين المتعلمين
          </p>
        </motion.div>

        {/* User Stats Card */}
        {userProgress && (
          <motion.div
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            className="bg-white rounded-xl shadow-lg p-6 mb-8 border border-gray-200"
          >
            <div className="flex items-center justify-between">
              <div className="flex items-center space-x-4">
                <div className="w-16 h-16 bg-gradient-to-r from-indigo-500 to-purple-600 rounded-full flex items-center justify-center text-white text-2xl font-bold">
                  {userProgress.level}
                </div>
                <div>
                  <h2 className="text-xl font-bold text-gray-900">
                    مستواك الحالي
                  </h2>
                  <p className="text-gray-600">
                    إجمالي النقاط: {userProgress.totalXP} XP
                  </p>
                  <p className="text-sm text-gray-500">
                    أفضل سلسلة متتالية: {userProgress.longestStreak} أيام
                  </p>
                </div>
              </div>
              <div className="text-right">
                <div className="text-3xl font-bold text-indigo-600">
                  #{userRank || '?'}
                </div>
                <div className="text-gray-500">ترتيبك</div>
              </div>
            </div>

            {/* Level Progress Bar */}
            <div className="mt-4">
              <div className="flex justify-between text-sm text-gray-600 mb-2">
                <span>المستوى {userProgress.level}</span>
                <span>المستوى {userProgress.level + 1}</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-3">
                <motion.div
                  initial={{ width: 0 }}
                  animate={{ width: `${((userProgress.totalXP % 100) / 100) * 100}%` }}
                  className="bg-gradient-to-r from-indigo-500 to-purple-600 h-3 rounded-full"
                />
              </div>
            </div>
          </motion.div>
        )}

        {/* Leaderboard Type Toggle */}
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.2 }}
          className="flex justify-center mb-8"
        >
          <div className="bg-white rounded-lg p-1 shadow-md">
            <button
              onClick={() => setLeaderboardType('global')}
              className={`px-6 py-2 rounded-md font-medium transition-all ${
                leaderboardType === 'global'
                  ? 'bg-indigo-600 text-white shadow-md'
                  : 'text-gray-600 hover:text-gray-900'
              }`}
            >
              🌍 عالمي
            </button>
            <button
              onClick={() => setLeaderboardType('friends')}
              className={`px-6 py-2 rounded-md font-medium transition-all ${
                leaderboardType === 'friends'
                  ? 'bg-indigo-600 text-white shadow-md'
                  : 'text-gray-600 hover:text-gray-900'
              }`}
            >
              👥 الأصدقاء
            </button>
          </div>
        </motion.div>

        {/* Leaderboard */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.3 }}
          className="bg-white rounded-xl shadow-lg overflow-hidden"
        >
          <div className="p-6 border-b border-gray-200">
            <h2 className="text-xl font-bold text-gray-900">
              {leaderboardType === 'global' ? 'المتصدرون عالمياً' : 'متصدرون الأصدقاء'}
            </h2>
          </div>

          <div className="divide-y divide-gray-200">
            {safeLeaderboard.length === 0 ? (
              <div className="p-8 text-center text-gray-500">
                لا توجد بيانات متاحة بعد
              </div>
            ) : (
              safeLeaderboard.map((entry, index) => (
                <motion.div
                  key={entry.userId}
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: index * 0.05 }}
                  className={`p-4 flex items-center justify-between hover:bg-gray-50 transition-colors ${
                    entry.userId === userId ? 'bg-indigo-50 border-r-4 border-indigo-600' : ''
                  }`}
                >
                  <div className="flex items-center space-x-4">
                    <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold text-lg ${
                      index === 0 ? 'bg-yellow-100 text-yellow-800' :
                      index === 1 ? 'bg-gray-100 text-gray-800' :
                      index === 2 ? 'bg-orange-100 text-orange-800' :
                      'bg-indigo-100 text-indigo-800'
                    }`}>
                      {entry.rank}
                    </div>
                    <div className="w-10 h-10 bg-gradient-to-r from-indigo-400 to-purple-500 rounded-full flex items-center justify-center text-white font-bold">
                      {entry.username.charAt(0).toUpperCase()}
                    </div>
                    <div>
                      <div className="font-medium text-gray-900">
                        {entry.username}
                        {entry.userId === userId && (
                          <span className="ml-2 text-xs bg-indigo-600 text-white px-2 py-1 rounded-full">
                            أنت
                          </span>
                        )}
                      </div>
                      <div className="text-sm text-gray-500">
                        مستوى {entry.level}
                      </div>
                    </div>
                  </div>
                  <div className="text-right">
                    <div className="font-bold text-lg text-gray-900">
                      {entry.totalXP.toLocaleString()}
                    </div>
                    <div className="text-sm text-gray-500">
                      نقاط
                    </div>
                  </div>
                </motion.div>
              ))
            )}
          </div>
        </motion.div>

        {/* Stats Summary */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.4 }}
          className="mt-8 grid grid-cols-1 md:grid-cols-3 gap-6"
        >
          <div className="bg-white rounded-lg p-6 shadow-md text-center">
            <div className="text-2xl font-bold text-indigo-600 mb-2">
              {safeLeaderboard.length}
            </div>
            <div className="text-gray-600">مشارك</div>
          </div>
          <div className="bg-white rounded-lg p-6 shadow-md text-center">
            <div className="text-2xl font-bold text-green-600 mb-2">
              {safeLeaderboard.length > 0 
                ? Math.max(...safeLeaderboard.map(l => l.totalXP)).toLocaleString() 
                : '0'}
            </div>
            <div className="text-gray-600">أعلى نقاط</div>
          </div>
          <div className="bg-white rounded-lg p-6 shadow-md text-center">
            <div className="text-2xl font-bold text-purple-600 mb-2">
              {userProgress ? Math.floor(userProgress.totalStudyTime / 60) : 0}
            </div>
            <div className="text-gray-600">ساعات دراسة</div>
          </div>
        </motion.div>
      </div>

        {/* Achievement Toast */}
        <AchievementToast
          achievement={currentAchievement}
          onClose={clearAchievementNotification}
        />
      </div>
    </AuthGuard>
  );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { AuthGuard } from '@/components/auth/AuthGuard';
import { Bell, Check, CheckCheck, ExternalLink, Clock } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Avatar, AvatarFallback } from '@/components/ui/avatar';
import { logger } from '@/lib/logger';

interface Notification {
  id: string;
  title: string;
  message: string;
  type: 'info' | 'success' | 'warning' | 'error';
  isRead: boolean;
  actionUrl?: string;
  icon?: string;
  createdAt: string;
}

export default function NotificationsPage() {
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [unreadCount, setUnreadCount] = useState(0);
  const [isLoading, setIsLoading] = useState(false);
  const [hasMore, setHasMore] = useState(true);
  const [offset, setOffset] = useState(0);
  const limit = 10;

  // Fetch notifications
  const fetchNotifications = useCallback(async (reset = false) => {
    setIsLoading(true);
    try {
      const currentOffset = reset ? 0 : offset;
      const params = new URLSearchParams({
        limit: limit.toString(),
        offset: currentOffset.toString(),
      });

      const response = await fetch(`/api/notifications?${params}`, {
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
      });

      if (!response.ok) throw new Error('Failed to fetch notifications');

      const data = await response.json();

      if (reset) {
        setNotifications(data.notifications);
        setOffset(0);
      } else {
        setNotifications((prev) => [...prev, ...data.notifications]);
        setOffset(currentOffset + limit);
      }

      setUnreadCount(data.unreadCount);
      setHasMore(data.hasMore);
    } catch (error) {
      logger.error('Error fetching notifications:', error);
    } finally {
      setIsLoading(false);
    }
  }, [offset, limit]);

  // Initial fetch
  useEffect(() => {
    fetchNotifications(true);
  }, []);

  // Mark notifications as read
  const markAsRead = async (notificationIds?: string[], all = false) => {
    try {
      const response = await fetch('/api/notifications/mark-read', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ notificationIds, all }),
      });

      if (!response.ok) throw new Error('Failed to mark notifications as read');

      const data = await response.json();

      if (all) {
        setNotifications((prev) => prev.map((n) => ({ ...n, isRead: true })));
      } else if (notificationIds) {
        setNotifications((prev) =>
          prev.map((n) => (notificationIds.includes(n.id) ? { ...n, isRead: true } : n))
        );
      }

      setUnreadCount(data.unreadCount);
    } catch (error) {
      logger.error('Error marking notifications as read:', error);
    }
  };

  // Format date helper
  const formatDate = (dateString: string) => {
    const date = new Date(dateString);
    const now = new Date();
    const diffMs = now.getTime() - date.getTime();
    const diffMins = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMs / 3600000);
    const diffDays = Math.floor(diffMs / 86400000);

    if (diffMins < 1) return 'الآن';
    if (diffMins < 60) return `منذ ${diffMins} دقيقة`;
    if (diffHours < 24) return `منذ ${diffHours} ساعة`;
    if (diffDays < 7) return `منذ ${diffDays} يوم`;

    return date.toLocaleDateString('ar-SA', {
      day: 'numeric',
      month: 'short',
      year: date.getFullYear() !== now.getFullYear() ? 'numeric' : undefined,
    });
  };

  // Icon helper
  const getNotificationIcon = (type: string, icon?: string) => {
    if (icon) return icon;
    switch (type) {
      case 'success':
        return '✅';
      case 'warning':
        return '⚠️';
      case 'error':
        return '❌';
      default:
        return 'ℹ️';
    }
  };

  // Color helper
  const getNotificationTypeColor = (type: string) => {
    switch (type) {
      case 'success':
        return 'bg-green-100 text-green-800 border-green-200';
      case 'warning':
        return 'bg-yellow-100 text-yellow-800 border-yellow-200';
      case 'error':
        return 'bg-red-100 text-red-800 border-red-200';
      default:
        return 'bg-blue-100 text-blue-800 border-blue-200';
    }
  };

  // Load more
  const loadMore = () => {
    if (!isLoading && hasMore) fetchNotifications();
  };

  return (
    <AuthGuard>
      <div className="container mx-auto py-8 px-4 max-w-4xl">
        <div className="mb-8">
          <h1 className="text-3xl font-bold mb-2 flex items-center gap-2">
            <Bell className="h-8 w-8 text-blue-600" />
            الإشعارات
          </h1>
          <p className="text-gray-600">عرض جميع الإشعارات والتنبيهات</p>
        </div>

        <Card className="mb-6">
          <CardHeader>
            <div className="flex justify-between items-center">
              <div>
                <CardTitle>الإشعارات</CardTitle>
                <CardDescription>
                  {unreadCount > 0
                    ? `لديك ${unreadCount} إشعار${unreadCount > 1 ? 'ات غير مقروءة' : ' غير مقروء'}`
                    : 'لا توجد إشعارات غير مقروءة'}
                </CardDescription>
              </div>
              {unreadCount > 0 && (
                <Button variant="outline" onClick={() => markAsRead(undefined, true)} className="flex items-center gap-2">
                  <CheckCheck className="h-4 w-4" />
                  تحديد الكل كمقروء
                </Button>
              )}
            </div>
          </CardHeader>
          <CardContent>
            {notifications.length === 0 ? (
              <div className="text-center py-12">
                <Bell className="h-12 w-12 text-gray-400 mx-auto mb-4" />
                <h3 className="text-lg font-medium text-gray-900 mb-1">لا توجد إشعارات</h3>
                <p className="text-gray-500">سيتم عرض الإشعارات هنا عند توفرها</p>
              </div>
            ) : (
              <div className="space-y-4">
                {notifications.map((notification) => (
                  <div
                    key={notification.id}
                    className={`p-4 rounded-lg border transition-colors ${
                      notification.isRead ? 'bg-white border-gray-200' : 'bg-blue-50 border-blue-200'
                    }`}
                  >
                    <div className="flex gap-4">
                      <Avatar className="h-10 w-10 flex-shrink-0">
                        <AvatarFallback className="text-lg">
                          {getNotificationIcon(notification.type, notification.icon)}
                        </AvatarFallback>
                      </Avatar>
                      <div className="flex-1 min-w-0">
                        <div className="flex justify-between items-start">
                          <div>
                            <h3 className={`font-medium ${!notification.isRead ? 'font-bold' : ''}`}>
                              {notification.title}
                            </h3>
                            <div className="flex items-center gap-2 mt-1">
                              <Badge variant="outline" className={`text-xs ${getNotificationTypeColor(notification.type)}`}>
                                {notification.type === 'info' && 'معلومات'}
                                {notification.type === 'success' && 'نجاح'}
                                {notification.type === 'warning' && 'تحذير'}
                                {notification.type === 'error' && 'خطأ'}
                              </Badge>
                              <div className="flex items-center text-xs text-gray-500">
                                <Clock className="h-3 w-3 mr-1" />
                                {formatDate(notification.createdAt)}
                              </div>
                            </div>
                          </div>
                          {!notification.isRead && (
                            <span className="h-2 w-2 rounded-full bg-blue-600 flex-shrink-0 mt-2" />
                          )}
                        </div>
                        <p className="mt-2 text-gray-700">{notification.message}</p>
                        <div className="flex justify-between items-center mt-3">
                          <div className="flex gap-2">
                            {!notification.isRead && (
                              <Button variant="ghost" size="sm" onClick={() => markAsRead([notification.id])} className="h-8 px-2 text-xs">
                                <Check className="h-3 w-3 mr-1" />
                                تحديد كمقروء
                              </Button>
                            )}
                            {notification.actionUrl && (
                              <Button
                                variant="ghost"
                                size="sm"
                                onClick={() => {
                                  if (typeof window !== 'undefined' && notification.actionUrl) {
                                    try {
                                      const parsed = new URL(notification.actionUrl, window.location.origin);
                                      if (parsed.protocol === 'http:' || parsed.protocol === 'https:') {
                                        window.location.href = parsed.href;
                                      } else {
                                        console.warn('Blocked unsafe redirect:', notification.actionUrl);
                                      }
                                    } catch {
                                      console.warn('Invalid URL for redirect:', notification.actionUrl);
                                    }
                                  }
                                }}
                                className="h-8 px-2 text-xs"
                              >
                                <ExternalLink className="h-3 w-3 mr-1" />
                                الانتقال
                              </Button>
                            )}
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
                {hasMore && (
                  <div className="text-center mt-6">
                    <Button variant="outline" onClick={loadMore} disabled={isLoading} className="w-full">
                      {isLoading ? 'جاري التحميل...' : 'تحميل المزيد'}
                    </Button>
                  </div>
                )}
              </div>
            )}
          </CardContent>
        </Card>
      </div>
    </AuthGuard>
  );
}

