'use client';

import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { useState, useEffect, useMemo } from 'react';
import { Button } from '@/components/ui/button';
import { AuthGuard } from '@/components/auth/AuthGuard';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Checkbox } from '@/components/ui/checkbox';
import { Dialog, DialogTrigger, DialogContent, DialogHeader, DialogFooter, DialogTitle, DialogDescription } from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Plus, Trash2, Edit, Filter, Search, Calendar, Clock, Tag, CheckCircle2, Circle, AlertCircle } from 'lucide-react';
import { Task, TaskStatus, SubjectType } from '@/types/tasks';
import { TaskForm, TaskAnalytics, TaskList } from '@/app/(dashboard)/tasks/components';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Badge } from '@/components/ui/badge';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { toast } from 'sonner';

const taskSchema = z.object({
  title: z.string().min(1, { message: 'العنوان مطلوب' }),
  description: z.string().optional(),
  subject: z.nativeEnum(SubjectType).optional(),
  dueAt: z.string().optional(),
  priority: z.number().int().min(0).max(2).optional(),
});

export default function TasksPage() {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [loading, setLoading] = useState(true);
  const [isAddDialogOpen, setIsAddDialogOpen] = useState(false);
  const [isEditDialogOpen, setIsEditDialogOpen] = useState(false);
  const [editingTask, setEditingTask] = useState<Task | null>(null);
  const [statusFilter, setStatusFilter] = useState<TaskStatus | 'ALL'>('ALL');
  const [sortBy, setSortBy] = useState<'dueAt' | 'priority'>('priority');
  const [searchTerm, setSearchTerm] = useState('');
  const [activeTab, setActiveTab] = useState('all');

  const {
    control,
    register,
    handleSubmit,
    reset,
    setValue,
    formState: { errors },
  } = useForm<z.infer<typeof taskSchema>>({
    resolver: zodResolver(taskSchema),
  });

  useEffect(() => {
    fetchTasks();
  }, []);

  const fetchTasks = () => {
    setLoading(true);
    fetch('/api/tasks')
      .then((res) => {
        if (!res.ok) throw new Error('فشل في جلب المهام');
        return res.json();
      })
      .then((data) => {
        setTasks(data);
        setLoading(false);
      })
      .catch((error) => {
        toast.error(error.message);
        setLoading(false);
      });
  };

  const filteredAndSortedTasks = useMemo(() => {
    return tasks
      .filter(task => {
        const searchTermLower = searchTerm.toLowerCase();
        return (statusFilter === 'ALL' || task.status === statusFilter) && 
               (task.title.toLowerCase().includes(searchTermLower) || 
                (task.description && task.description.toLowerCase().includes(searchTermLower)));
      })
      .sort((a, b) => {
        if (sortBy === 'priority') {
          return b.priority - a.priority;
        }
        if (sortBy === 'dueAt') {
          if (!a.dueAt) return 1;
          if (!b.dueAt) return -1;
          return new Date(a.dueAt).getTime() - new Date(b.dueAt).getTime();
        }
        return 0;
      });
  }, [tasks, statusFilter, sortBy, searchTerm]);

  const handleAddTaskSubmit = (data: z.infer<typeof taskSchema>) => {
    fetch('/api/tasks', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
      .then((res) => {
        if (!res.ok) throw new Error('فشل في إضافة المهمة');
        return res.json();
      })
      .then((newTask) => {
        setTasks([...tasks, newTask]);
        reset();
        setIsAddDialogOpen(false);
        toast.success('تمت إضافة المهمة بنجاح');
      })
      .catch((error) => {
        toast.error(error.message);
      });
  };

  const handleEditTaskSubmit = (data: z.infer<typeof taskSchema>) => {
    if (!editingTask) return;

    fetch(`/api/tasks/${editingTask.id}`,
      {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      })
      .then((res) => {
        if (!res.ok) throw new Error('فشل في تحديث المهمة');
        return res.json();
      })
      .then((updatedTask) => {
        setTasks(tasks.map((task) => (task.id === editingTask.id ? updatedTask : task)));
        setEditingTask(null);
        reset();
        setIsEditDialogOpen(false);
        toast.success('تم تحديث المهمة بنجاح');
      })
      .catch((error) => {
        toast.error(error.message);
      });
  };

  const handleStatusChange = (id: string, status: TaskStatus) => {
    const newStatus = status === 'COMPLETED' ? 'PENDING' : 'COMPLETED';
    fetch(`/api/tasks/${id}`,
      {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ status: newStatus }),
      })
      .then((res) => {
        if (!res.ok) throw new Error('فشل في تحديث حالة المهمة');
        return res.json();
      })
      .then((updatedTask) => {
        setTasks(tasks.map((task) => (task.id === id ? updatedTask : task)));
        toast.success(`تم ${newStatus === 'COMPLETED' ? 'إكمال' : 'إعادة فتح'} المهمة بنجاح`);
      })
      .catch((error) => {
        toast.error(error.message);
      });
  };

  const handleDeleteTask = (id: string) => {
    fetch(`/api/tasks/${id}`, { method: 'DELETE' })
      .then((res) => {
        if (!res.ok) throw new Error('فشل في حذف المهمة');
        setTasks(tasks.filter((task) => task.id !== id));
        toast.success('تم حذف المهمة بنجاح');
      })
      .catch((error) => {
        toast.error(error.message);
      });
  };

  const openEditDialog = (task: Task) => {
    setEditingTask(task);
    setValue('title', task.title);
    setValue('description', task.description || '');
    setValue('subject', task.subject || undefined);
    setValue('dueAt', task.dueAt ? new Date(task.dueAt).toISOString().substring(0, 16) : '');
    setValue('priority', task.priority);
    setIsEditDialogOpen(true);
  };

  const getPriorityBadge = (priority: number) => {
    switch (priority) {
      case 2:
        return <Badge className="bg-red-500 hover:bg-red-600">عالية</Badge>;
      case 1:
        return <Badge className="bg-yellow-500 hover:bg-yellow-600">متوسطة</Badge>;
      default:
        return <Badge className="bg-green-500 hover:bg-green-600">منخفضة</Badge>;
    }
  };

  const getStatusIcon = (status: TaskStatus) => {
    switch (status) {
      case 'COMPLETED':
        return <CheckCircle2 className="h-5 w-5 text-green-500" />;
      case 'IN_PROGRESS':
        return <Clock className="h-5 w-5 text-blue-500" />;
      case 'PENDING':
        return <Circle className="h-5 w-5 text-gray-400" />;
      default:
        return <AlertCircle className="h-5 w-5 text-yellow-500" />;
    }
  };

  const isOverdue = (dueAt: string | undefined) => {
    if (!dueAt) return false;
    return new Date(dueAt) < new Date();
  };

	if (loading) {
		return <div className="flex justify-center items-center h-screen">جاري التحميل...</div>;
	}

	return (
		<AuthGuard>
			<div className="container mx-auto px-4 sm:px-6 md:px-8 py-6 sm:py-8 md:py-10 max-w-7xl font-sans">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 sm:gap-6 mb-6 sm:mb-8">
        <h1 className="text-2xl sm:text-3xl md:text-4xl font-bold">مركز المهام</h1>
        <Dialog open={isAddDialogOpen} onOpenChange={setIsAddDialogOpen}>
          <DialogTrigger asChild>
            <Button onClick={() => reset()}>
              <Plus className="mr-2 h-4 w-4" />
              إضافة مهمة جديدة
            </Button>
          </DialogTrigger>
          <DialogContent className="sm:max-w-[425px]">
            <DialogHeader>
              <DialogTitle>إضافة مهمة</DialogTitle>
              <DialogDescription>
                أضف مهمة جديدة إلى قائمة مهامك. املأ الحقول أدناه للمتابعة.
              </DialogDescription>
            </DialogHeader>
            <form onSubmit={handleSubmit(handleAddTaskSubmit)} className="grid gap-4 py-4">
              <TaskForm control={control} register={register} errors={errors} />
              <DialogFooter>
                <Button type="submit">إضافة</Button>
              </DialogFooter>
            </form>
          </DialogContent>
        </Dialog>
      </div>

      <div className="mb-6">
        <TaskAnalytics tasks={tasks} />
      </div>

      <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full mb-6">
        <TabsList className="grid w-full grid-cols-4">
          <TabsTrigger value="all">الكل</TabsTrigger>
          <TabsTrigger value="pending">قيد الانتظار</TabsTrigger>
          <TabsTrigger value="inProgress">قيد التنفيذ</TabsTrigger>
          <TabsTrigger value="completed">مكتملة</TabsTrigger>
        </TabsList>
        <TabsContent value="all" className="mt-4">
          <TaskList 
            tasks={filteredAndSortedTasks} 
            onStatusChange={handleStatusChange}
            onEdit={openEditDialog}
            onDelete={handleDeleteTask}
            getPriorityBadge={getPriorityBadge}
            getStatusIcon={getStatusIcon}
            isOverdue={isOverdue}
          />
        </TabsContent>
        <TabsContent value="pending" className="mt-4">
          <TaskList 
            tasks={filteredAndSortedTasks.filter(task => task.status === 'PENDING')} 
            onStatusChange={handleStatusChange}
            onEdit={openEditDialog}
            onDelete={handleDeleteTask}
            getPriorityBadge={getPriorityBadge}
            getStatusIcon={getStatusIcon}
            isOverdue={isOverdue}
          />
        </TabsContent>
        <TabsContent value="inProgress" className="mt-4">
          <TaskList 
            tasks={filteredAndSortedTasks.filter(task => task.status === 'IN_PROGRESS')} 
            onStatusChange={handleStatusChange}
            onEdit={openEditDialog}
            onDelete={handleDeleteTask}
            getPriorityBadge={getPriorityBadge}
            getStatusIcon={getStatusIcon}
            isOverdue={isOverdue}
          />
        </TabsContent>
        <TabsContent value="completed" className="mt-4">
          <TaskList 
            tasks={filteredAndSortedTasks.filter(task => task.status === 'COMPLETED')} 
            onStatusChange={handleStatusChange}
            onEdit={openEditDialog}
            onDelete={handleDeleteTask}
            getPriorityBadge={getPriorityBadge}
            getStatusIcon={getStatusIcon}
            isOverdue={isOverdue}
          />
        </TabsContent>
      </Tabs>

      <div className="flex flex-wrap items-center justify-between gap-4 mb-4">
        <div className="flex items-center gap-2">
            <Search className="h-5 w-5"/>
            <Input 
                placeholder="بحث في المهام..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-64"
            />
        </div>
        <div className="flex items-center gap-2">
            <Filter className="h-5 w-5"/>
            <Button variant={statusFilter === 'ALL' ? 'default' : 'outline'} onClick={() => setStatusFilter('ALL')}>الكل</Button>
            <Button variant={statusFilter === TaskStatus.PENDING ? 'default' : 'outline'} onClick={() => setStatusFilter(TaskStatus.PENDING)}>قيد الانتظار</Button>
            <Button variant={statusFilter === TaskStatus.IN_PROGRESS ? 'default' : 'outline'} onClick={() => setStatusFilter(TaskStatus.IN_PROGRESS)}>قيد التنفيذ</Button>
            <Button variant={statusFilter === TaskStatus.COMPLETED ? 'default' : 'outline'} onClick={() => setStatusFilter(TaskStatus.COMPLETED)}>مكتملة</Button>
        </div>
        <Select value={sortBy} onValueChange={(value: 'dueAt' | 'priority') => setSortBy(value)}>
            <SelectTrigger className="w-[180px]">
                <SelectValue placeholder="فرز حسب" />
            </SelectTrigger>
            <SelectContent>
                <SelectItem value="priority">الأولوية</SelectItem>
                <SelectItem value="dueAt">تاريخ الاستحقاق</SelectItem>
            </SelectContent>
        </Select>
      </div>

      {/* Edit Task Dialog */}
      <Dialog open={isEditDialogOpen} onOpenChange={setIsEditDialogOpen}>
          <DialogContent className="sm:max-w-[425px]">
            <DialogHeader>
              <DialogTitle>تعديل المهمة</DialogTitle>
              <DialogDescription>
                قم بتعديل تفاصيل المهمة أدناه. انقر على حفظ عند الانتهاء.
              </DialogDescription>
            </DialogHeader>
            <form onSubmit={handleSubmit(handleEditTaskSubmit)} className="grid gap-4 py-4">
               <TaskForm control={control} register={register} errors={errors} />
               <DialogFooter>
                 <Button type="submit">حفظ التغييرات</Button>
               </DialogFooter>
            </form>
          </DialogContent>
        </Dialog>

      {/* هذا القسم تم استبداله بمكون Tabs و TaskList في الأعلى */}
			</div>
		</AuthGuard>
  );
}

'use client';

import { useState } from 'react';
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Download, FileText, FileJson, Printer, Calendar } from 'lucide-react';
import { exportToCSV, exportToJSON, generatePDFReport, downloadFile, printPDFReport, type ExportData } from '../utils/exportUtils';
import { format as formatDate, subDays, subWeeks, subMonths, startOfWeek, endOfWeek } from 'date-fns';
import { ar } from 'date-fns/locale';
import type { Task, StudySession, Reminder } from '../types';

import { logger } from '@/lib/logger';

interface ExportDialogProps {
  tasks: Task[];
  studySessions: StudySession[];
  reminders: Reminder[];
}

export default function ExportDialog({ tasks, studySessions, reminders }: ExportDialogProps) {
  const [period, setPeriod] = useState<'week' | 'month' | 'all'>('week');
  const [isExporting, setIsExporting] = useState(false);

  const getPeriodDates = () => {
    const now = new Date();
    let start: Date;
    let end: Date = now;

    switch (period) {
      case 'week':
        start = startOfWeek(subWeeks(now, 1), { locale: ar });
        end = endOfWeek(now, { locale: ar });
        break;
      case 'month':
        start = subMonths(now, 1);
        end = now;
        break;
      case 'all':
        start = new Date(0); // Beginning of time
        end = now;
        break;
    }

    return { start, end };
  };

  const filterDataByPeriod = () => {
    const { start, end } = getPeriodDates();
    
    const filteredTasks = tasks.filter(task => {
      const taskDate = task.createdAt ? new Date(task.createdAt) : null;
      return !taskDate || (taskDate >= start && taskDate <= end);
    });

    const filteredSessions = studySessions.filter(session => {
      const sessionDate = new Date(session.startTime);
      return sessionDate >= start && sessionDate <= end;
    });

    const filteredReminders = reminders.filter(reminder => {
      const reminderDate = new Date(reminder.remindAt);
      return reminderDate >= start && reminderDate <= end;
    });

    return { filteredTasks, filteredSessions, filteredReminders };
  };

  const handleExport = async (exportFormat: 'csv' | 'json' | 'pdf' | 'print') => {
    setIsExporting(true);
    try {
      const { start, end } = getPeriodDates();
      const { filteredTasks, filteredSessions, filteredReminders } = filterDataByPeriod();

      const exportData: ExportData = {
        tasks: filteredTasks,
        studySessions: filteredSessions,
        reminders: filteredReminders,
        exportDate: formatDate(new Date(), 'yyyy-MM-dd HH:mm:ss', { locale: ar }),
        period: {
          start: formatDate(start, 'yyyy-MM-dd', { locale: ar }),
          end: formatDate(end, 'yyyy-MM-dd', { locale: ar })
        }
      };

      const filename = `time-management-${exportFormat}-${formatDate(new Date(), 'yyyy-MM-dd')}`;

      switch (exportFormat) {
        case 'csv':
          const csvContent = exportToCSV(exportData);
          downloadFile(csvContent, `${filename}.csv`, 'text/csv;charset=utf-8;');
          break;
        
        case 'json':
          const jsonContent = exportToJSON(exportData);
          downloadFile(jsonContent, `${filename}.json`, 'application/json');
          break;
        
        case 'pdf':
          const htmlContent = generatePDFReport(exportData);
          const blob = new Blob([htmlContent], { type: 'text/html' });
          const url = URL.createObjectURL(blob);
          const link = document.createElement('a');
          link.href = url;
          link.download = `${filename}.html`;
          document.body.appendChild(link);
          link.click();
          document.body.removeChild(link);
          URL.revokeObjectURL(url);
          break;
        
        case 'print':
          const printHtml = generatePDFReport(exportData);
          printPDFReport(printHtml);
          break;
      }
    } catch (error) {
      logger.error('Error exporting data:', error);
      alert('حدث خطأ أثناء التصدير. يرجى المحاولة مرة أخرى.');
    } finally {
      setIsExporting(false);
    }
  };

  const { start, end } = getPeriodDates();
  const { filteredTasks, filteredSessions, filteredReminders } = filterDataByPeriod();

  return (
    <Dialog>
      <DialogTrigger asChild>
        <Button variant="outline" className="flex items-center gap-2">
          <Download className="h-4 w-4" />
          تصدير البيانات
        </Button>
      </DialogTrigger>
      <DialogContent className="max-w-md">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Download className="h-5 w-5" />
            تصدير بيانات إدارة الوقت
          </DialogTitle>
          <DialogDescription>
            اختر الفترة والصيغة لتصدير بياناتك
          </DialogDescription>
        </DialogHeader>
        
        <div className="space-y-4 py-4">
          {/* Period Selection */}
          <div className="space-y-2">
            <label className="text-sm font-medium flex items-center gap-2">
              <Calendar className="h-4 w-4" />
              الفترة الزمنية
            </label>
            <Select value={period} onValueChange={(value: 'week' | 'month' | 'all') => setPeriod(value)}>
              <SelectTrigger>
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="week">الأسبوع الماضي</SelectItem>
                <SelectItem value="month">الشهر الماضي</SelectItem>
                <SelectItem value="all">جميع البيانات</SelectItem>
              </SelectContent>
            </Select>
            <p className="text-xs text-muted-foreground">
              {formatDate(start, 'yyyy-MM-dd', { locale: ar })} إلى {formatDate(end, 'yyyy-MM-dd', { locale: ar })}
            </p>
          </div>

          {/* Data Summary */}
          <div className="p-3 rounded-lg bg-muted/50">
            <p className="text-sm font-medium mb-2">ملخص البيانات:</p>
            <ul className="text-xs text-muted-foreground space-y-1">
              <li>• {filteredTasks.length} مهمة</li>
              <li>• {filteredSessions.length} جلسة مذاكرة</li>
              <li>• {filteredReminders.length} تذكير</li>
            </ul>
          </div>

          {/* Export Options */}
          <div className="grid grid-cols-2 gap-2">
            <Button
              onClick={() => handleExport('csv')}
              disabled={isExporting}
              variant="outline"
              className="flex items-center gap-2"
            >
              <FileText className="h-4 w-4" />
              CSV
            </Button>
            
            <Button
              onClick={() => handleExport('json')}
              disabled={isExporting}
              variant="outline"
              className="flex items-center gap-2"
            >
              <FileJson className="h-4 w-4" />
              JSON
            </Button>
            
            <Button
              onClick={() => handleExport('pdf')}
              disabled={isExporting}
              variant="outline"
              className="flex items-center gap-2"
            >
              <FileText className="h-4 w-4" />
              PDF (HTML)
            </Button>
            
            <Button
              onClick={() => handleExport('print')}
              disabled={isExporting}
              variant="outline"
              className="flex items-center gap-2"
            >
              <Printer className="h-4 w-4" />
              طباعة
            </Button>
          </div>

          {isExporting && (
            <p className="text-sm text-center text-muted-foreground">
              جاري التصدير...
            </p>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

'use client';

import { useMemo } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { 
  Lightbulb, 
  AlertTriangle, 
  CheckCircle, 
  Target, 
  TrendingUp, 
  Clock,
  Zap,
  Calendar,
  BookOpen
} from 'lucide-react';
import type { Task, StudySession } from '../types';
import { format, isPast, differenceInDays, differenceInHours } from 'date-fns';
import { ar } from 'date-fns/locale';

interface ProductivityInsightsProps {
  tasks: Task[];
  studySessions: StudySession[];
}

export default function ProductivityInsights({ tasks, studySessions }: ProductivityInsightsProps) {
  const insights = useMemo(() => {
    const now = new Date();
    
    // Overdue tasks
    const overdueTasks = tasks.filter(task => 
      task.dueAt && 
      task.status !== 'COMPLETED' && 
      isPast(new Date(task.dueAt))
    );
    
    // Upcoming deadlines (next 3 days)
    const upcomingDeadlines = tasks.filter(task =>
      task.dueAt &&
      task.status !== 'COMPLETED' &&
      !isPast(new Date(task.dueAt)) &&
      differenceInDays(new Date(task.dueAt), now) <= 3
    );
    
    // High priority pending tasks
    const highPriorityTasks = tasks.filter(task =>
      task.status !== 'COMPLETED' &&
      (task.priority === 'HIGH' || task.priority === 'URGENT')
    );
    
    // Time estimation accuracy
    const tasksWithTime = tasks.filter(t => t.estimatedTime && t.actualTime);
    const timeAccuracy = tasksWithTime.length > 0
      ? tasksWithTime.reduce((sum, t) => {
          const diff = Math.abs((t.estimatedTime || 0) - (t.actualTime || 0));
          const accuracy = 100 - (diff / (t.estimatedTime || 1)) * 100;
          return sum + Math.max(0, accuracy);
        }, 0) / tasksWithTime.length
      : 0;
    
    // Study consistency (days with sessions in last 7 days)
    const last7Days = Array.from({ length: 7 }, (_, i) => {
      const date = new Date(now);
      date.setDate(date.getDate() - i);
      return date.toDateString();
    });
    const studyDays = new Set(
      studySessions
        .filter(s => last7Days.includes(new Date(s.startTime).toDateString()))
        .map(s => new Date(s.startTime).toDateString())
    ).size;
    const consistencyScore = (studyDays / 7) * 100;
    
    // Focus areas (subjects with most incomplete tasks)
    const subjectTaskCount = new Map<string, number>();
    tasks
      .filter(t => t.status !== 'COMPLETED' && t.subject)
      .forEach(t => {
        const count = subjectTaskCount.get(t.subject!) || 0;
        subjectTaskCount.set(t.subject!, count + 1);
      });
    
    // Recommendations
    const recommendations: string[] = [];
    
    if (overdueTasks.length > 0) {
      recommendations.push(`لديك ${overdueTasks.length} مهمة متأخرة تحتاج إلى انتباه فوري`);
    }
    
    if (upcomingDeadlines.length > 0) {
      recommendations.push(`${upcomingDeadlines.length} مهمة قريبة من الموعد النهائي`);
    }
    
    if (consistencyScore < 50) {
      recommendations.push('حاول المذاكرة يومياً لتحسين الانتظام');
    }
    
    if (timeAccuracy < 70 && tasksWithTime.length > 0) {
      recommendations.push('حسّن تقديرك للوقت المطلوب لإكمال المهام');
    }
    
    if (highPriorityTasks.length > 0) {
      recommendations.push(`ركز على ${highPriorityTasks.length} مهمة عالية الأولوية`);
    }
    
    if (recommendations.length === 0) {
      recommendations.push('أحسنت! أنت على المسار الصحيح');
    }
    
    // Best time to study (based on session quality - longer sessions indicate better focus time)
    const hourQuality = Array.from({ length: 24 }, () => ({
      total: 0,
      count: 0,
      avg: 0
    }));
    
    studySessions.forEach(session => {
      const hour = new Date(session.startTime).getHours();
      hourQuality[hour].total += session.durationMin;
      hourQuality[hour].count += 1;
    });
    
    hourQuality.forEach((h, i) => {
      h.avg = h.count > 0 ? h.total / h.count : 0;
    });
    
    const bestHour = hourQuality.reduce((best, current, index) => 
      current.avg > best.avg ? { ...current, index } : best
    , { avg: 0, index: -1 });
    
    return {
      overdueTasks,
      upcomingDeadlines,
      highPriorityTasks,
      timeAccuracy,
      consistencyScore,
      subjectTaskCount,
      recommendations,
      bestHour: bestHour.index >= 0 ? bestHour.index : null,
      studyDays
    };
  }, [tasks, studySessions]);

  return (
    <div className="space-y-6">
      <Card className="border-2 border-primary/10 shadow-lg">
        <CardHeader className="bg-gradient-to-r from-primary/5 to-primary/10 dark:from-primary/10 dark:to-primary/20">
          <CardTitle className="flex items-center text-lg">
            <div className="p-2 rounded-lg bg-primary/10 dark:bg-primary/20 ml-2">
              <Lightbulb className="h-5 w-5 text-primary" />
            </div>
            رؤى الإنتاجية والتوصيات
          </CardTitle>
        </CardHeader>
        <CardContent className="p-6 space-y-6">
          {/* Recommendations */}
          <div className="p-4 rounded-lg bg-gradient-to-br from-blue-50/50 to-transparent dark:from-blue-950/20 border border-blue-200/50 dark:border-blue-800/50">
            <h3 className="font-semibold mb-3 flex items-center">
              <Lightbulb className="h-4 w-4 ml-2 text-blue-600 dark:text-blue-400" />
              توصيات ذكية
            </h3>
            <ul className="space-y-2">
              {insights.recommendations.map((rec, index) => (
                <li key={index} className="flex items-start gap-2 text-sm">
                  <CheckCircle className="h-4 w-4 mt-0.5 text-blue-600 dark:text-blue-400 flex-shrink-0" />
                  <span>{rec}</span>
                </li>
              ))}
            </ul>
          </div>

          {/* Alerts */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {insights.overdueTasks.length > 0 && (
              <div className="p-4 rounded-lg bg-gradient-to-br from-red-50/50 to-transparent dark:from-red-950/20 border border-red-200/50 dark:border-red-800/50">
                <div className="flex items-center justify-between mb-2">
                  <span className="font-semibold flex items-center">
                    <AlertTriangle className="h-4 w-4 ml-2 text-red-600 dark:text-red-400" />
                    المهام المتأخرة
                  </span>
                  <Badge variant="destructive">{insights.overdueTasks.length}</Badge>
                </div>
                <p className="text-sm text-muted-foreground">
                  {insights.overdueTasks.length} مهمة تجاوزت موعدها النهائي
                </p>
              </div>
            )}

            {insights.upcomingDeadlines.length > 0 && (
              <div className="p-4 rounded-lg bg-gradient-to-br from-yellow-50/50 to-transparent dark:from-yellow-950/20 border border-yellow-200/50 dark:border-yellow-800/50">
                <div className="flex items-center justify-between mb-2">
                  <span className="font-semibold flex items-center">
                    <Clock className="h-4 w-4 ml-2 text-yellow-600 dark:text-yellow-400" />
                    مواعيد قريبة
                  </span>
                  <Badge variant="outline" className="bg-yellow-100 dark:bg-yellow-900/30">
                    {insights.upcomingDeadlines.length}
                  </Badge>
                </div>
                <p className="text-sm text-muted-foreground">
                  {insights.upcomingDeadlines.length} مهمة خلال 3 أيام القادمة
                </p>
              </div>
            )}

            {insights.highPriorityTasks.length > 0 && (
              <div className="p-4 rounded-lg bg-gradient-to-br from-orange-50/50 to-transparent dark:from-orange-950/20 border border-orange-200/50 dark:border-orange-800/50">
                <div className="flex items-center justify-between mb-2">
                  <span className="font-semibold flex items-center">
                    <Target className="h-4 w-4 ml-2 text-orange-600 dark:text-orange-400" />
                    أولوية عالية
                  </span>
                  <Badge variant="outline" className="bg-orange-100 dark:bg-orange-900/30">
                    {insights.highPriorityTasks.length}
                  </Badge>
                </div>
                <p className="text-sm text-muted-foreground">
                  {insights.highPriorityTasks.length} مهمة تحتاج إلى انتباه فوري
                </p>
              </div>
            )}
          </div>

          {/* Metrics */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="p-4 rounded-lg bg-gradient-to-br from-green-50/50 to-transparent dark:from-green-950/20 border border-green-200/50 dark:border-green-800/50">
              <div className="flex items-center justify-between mb-2">
                <span className="font-medium text-sm">انتظام المذاكرة</span>
                <Calendar className="h-4 w-4 text-green-600 dark:text-green-400" />
              </div>
              <div className="text-2xl font-bold text-green-600 dark:text-green-400">
                {Math.round(insights.consistencyScore)}%
              </div>
              <p className="text-xs text-muted-foreground mt-1">
                {insights.studyDays} من 7 أيام
              </p>
            </div>

            <div className="p-4 rounded-lg bg-gradient-to-br from-purple-50/50 to-transparent dark:from-purple-950/20 border border-purple-200/50 dark:border-purple-800/50">
              <div className="flex items-center justify-between mb-2">
                <span className="font-medium text-sm">دقة التقدير</span>
                <Target className="h-4 w-4 text-purple-600 dark:text-purple-400" />
              </div>
              <div className="text-2xl font-bold text-purple-600 dark:text-purple-400">
                {Math.round(insights.timeAccuracy)}%
              </div>
              <p className="text-xs text-muted-foreground mt-1">
                تقدير الوقت المطلوب
              </p>
            </div>

            {insights.bestHour !== null && (
              <div className="p-4 rounded-lg bg-gradient-to-br from-blue-50/50 to-transparent dark:from-blue-950/20 border border-blue-200/50 dark:border-blue-800/50">
                <div className="flex items-center justify-between mb-2">
                  <span className="font-medium text-sm">أفضل وقت</span>
                  <Zap className="h-4 w-4 text-blue-600 dark:text-blue-400" />
                </div>
                <div className="text-2xl font-bold text-blue-600 dark:text-blue-400">
                  {insights.bestHour}:00
                </div>
                <p className="text-xs text-muted-foreground mt-1">
                  أكثر ساعة إنتاجية
                </p>
              </div>
            )}
          </div>

          {/* Focus Areas */}
          {insights.subjectTaskCount.size > 0 && (
            <div className="p-4 rounded-lg bg-gradient-to-br from-indigo-50/50 to-transparent dark:from-indigo-950/20 border border-indigo-200/50 dark:border-indigo-800/50">
              <h3 className="font-semibold mb-3 flex items-center">
                <BookOpen className="h-4 w-4 ml-2 text-indigo-600 dark:text-indigo-400" />
                مجالات التركيز (مهام غير مكتملة)
              </h3>
              <div className="flex flex-wrap gap-2">
                {Array.from(insights.subjectTaskCount.entries())
                  .sort((a, b) => b[1] - a[1])
                  .slice(0, 5)
                  .map(([subject, count]) => (
                    <Badge 
                      key={subject} 
                      variant="outline"
                      className="bg-indigo-100 dark:bg-indigo-900/30 text-indigo-700 dark:text-indigo-300"
                    >
                      {subject}: {count}
                    </Badge>
                  ))}
              </div>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

'use client';

import { useState, useEffect, useMemo, useCallback } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { Label } from "@/components/ui/label";
import { 
  Clock,
  BookOpen,
  BarChart3,
  TrendingUp,
  TrendingDown,
  Activity,
  Brain,
  Coffee,
  Eye,
  EyeOff,
  Filter,
  Search,
  SortAsc,
  SortDesc,
  Download,
  Zap,
  Trophy,
  LineChart,
  PieChart,
  Flame,
  MoreHorizontal,
  ChevronLeft,
  ChevronRight
} from 'lucide-react';
import { cn } from '@/lib/utils';
import { format, startOfWeek, subDays, subMonths, startOfMonth } from 'date-fns';
import { ar } from 'date-fns/locale';

import { logger } from '@/lib/logger';

interface StudySession {
  id: string;
  userId: string;
  taskId?: string;
  durationMin: number;
  subject?: string;
  notes?: string;
  mood?: 'EXCELLENT' | 'GOOD' | 'AVERAGE' | 'POOR';
  productivity?: number;
  breaks?: number;
  distractions?: number;
  focusScore?: number;
  energyLevel?: number;
  difficulty?: number;
  satisfaction?: number;
  tags?: string[];
  location?: string;
  createdAt: string;
  updatedAt: string;
}

interface StudySessionsHistoryProps {
  readonly sessions: StudySession[];
  readonly subjects: string[];
}

interface SessionStats {
  totalSessions: number;
  totalHours: number;
  averageSessionLength: number;
  averageProductivity: number;
  averageFocusScore: number;
  averageMood: number;
  totalBreaks: number;
  totalDistractions: number;
  longestSession: number;
  shortestSession: number;
  mostProductiveDay: string;
  mostProductiveTime: string;
  favoriteSubject: string;
  studyStreak: number;
  weeklyTrend: number;
  monthlyTrend: number;
}

interface ChartData {
  date: string;
  hours: number;
  sessions: number;
  productivity: number;
  mood: number;
}

const MOOD_COLORS = {
  'EXCELLENT': 'bg-green-500 text-green-50',
  'GOOD': 'bg-blue-500 text-blue-50',
  'AVERAGE': 'bg-yellow-500 text-yellow-50',
  'POOR': 'bg-red-500 text-red-50'
};

const MOOD_LABELS = {
  'EXCELLENT': 'ممتاز',
  'GOOD': 'جيد',
  'AVERAGE': 'متوسط',
  'POOR': 'ضعيف'
};

const MOOD_ICONS = {
  'EXCELLENT': '😊',
  'GOOD': '🙂',
  'AVERAGE': '😐',
  'POOR': '😔'
};

const TIME_PERIODS = [
  { value: 'week', label: 'هذا الأسبوع' },
  { value: 'month', label: 'هذا الشهر' },
  { value: 'quarter', label: 'هذا الربع' },
  { value: 'year', label: 'هذا العام' },
  { value: 'all', label: 'كل الوقت' }
];

const _CHART_TYPES = [
  { value: 'line', label: 'خط', icon: LineChart },
  { value: 'bar', label: 'أعمدة', icon: BarChart3 },
  { value: 'pie', label: 'دائري', icon: PieChart }
];

export default function StudySessionsHistory({ sessions, subjects }: StudySessionsHistoryProps) {
  const [filteredSessions, setFilteredSessions] = useState<StudySession[]>(sessions);
  const [timePeriod, setTimePeriod] = useState('month');
  const [selectedSubject, setSelectedSubject] = useState('all');
  const [selectedMood, setSelectedMood] = useState('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [sortBy, setSortBy] = useState<'date' | 'duration' | 'productivity' | 'mood'>('date');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');
  const [viewMode, setViewMode] = useState<'list' | 'grid' | 'chart'>('list');
  const [_chartType] = useState('line');
  const [showStats, setShowStats] = useState(true);
  const [showFilters, setShowFilters] = useState(false);
  const [selectedSessions, setSelectedSessions] = useState<string[]>([]);
  const [bulkSelectMode, setBulkSelectMode] = useState(false);
  
  // Pagination
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(20);
  
  // Date range
  const [customDateRange] = useState({
    start: '',
    end: ''
  });

  // Handler for session toggle in bulk select mode
  const updateSelectedSessions = useCallback((sessionId: string, isChecked: boolean) => {
    setSelectedSessions(prev => {
      if (isChecked) {
        return [...prev, sessionId];
      }
      return prev.filter(id => id !== sessionId);
    });
  }, []);

  const handleSessionToggle = useCallback((sessionId: string) => {
    return (e: React.ChangeEvent<HTMLInputElement>) => {
      updateSelectedSessions(sessionId, e.target.checked);
    };
  }, [updateSelectedSessions]);

  // Calculate comprehensive statistics
  const stats: SessionStats = useMemo(() => {
    if (filteredSessions.length === 0) {
      return {
        totalSessions: 0,
        totalHours: 0,
        averageSessionLength: 0,
        averageProductivity: 0,
        averageFocusScore: 0,
        averageMood: 0,
        totalBreaks: 0,
        totalDistractions: 0,
        longestSession: 0,
        shortestSession: 0,
        mostProductiveDay: '',
        mostProductiveTime: '',
        favoriteSubject: '',
        studyStreak: 0,
        weeklyTrend: 0,
        monthlyTrend: 0
      };
    }

    const totalSessions = filteredSessions.length;
    const totalMinutes = filteredSessions.reduce((acc, session) => acc + session.durationMin, 0);
    const totalHours = Math.round(totalMinutes / 60 * 10) / 10;
    const averageSessionLength = Math.round(totalMinutes / totalSessions);
    
    const productiveSessions = filteredSessions.filter(s => s.productivity !== undefined);
    const averageProductivity = productiveSessions.length > 0
      ? Math.round(productiveSessions.reduce((acc, s) => acc + (s.productivity || 0), 0) / productiveSessions.length)
      : 0;
    
    const focusSessions = filteredSessions.filter(s => s.focusScore !== undefined);
    const averageFocusScore = focusSessions.length > 0
      ? Math.round(focusSessions.reduce((acc, s) => acc + (s.focusScore || 0), 0) / focusSessions.length)
      : 0;
    
    const moodSessions = filteredSessions.filter(s => s.mood !== undefined);
    const moodValues = { 'EXCELLENT': 4, 'GOOD': 3, 'AVERAGE': 2, 'POOR': 1 };
    const averageMood = moodSessions.length > 0
      ? Math.round(moodSessions.reduce((acc, s) => acc + (moodValues[s.mood || 'AVERAGE'] || 2), 0) / moodSessions.length)
      : 0;
    
    const totalBreaks = filteredSessions.reduce((acc, s) => acc + (s.breaks || 0), 0);
    const totalDistractions = filteredSessions.reduce((acc, s) => acc + (s.distractions || 0), 0);
    
    const durations = filteredSessions.map(s => s.durationMin);
    const longestSession = Math.max(...durations);
    const shortestSession = Math.min(...durations);
    
    // Find most productive day of week
    const dayStats = filteredSessions.reduce((acc, session) => {
      const day = format(new Date(session.createdAt), 'EEEE', { locale: ar });
      if (!acc[day]) acc[day] = { sessions: 0, totalProductivity: 0 };
      acc[day].sessions++;
      acc[day].totalProductivity += session.productivity || 0;
      return acc;
    }, {} as Record<string, { sessions: number; totalProductivity: number }>);
    
    const mostProductiveDay = Object.keys(dayStats).reduce((best, day) => {
      const avgProductivity = dayStats[day].totalProductivity / dayStats[day].sessions;
      const bestAvg = dayStats[best]?.totalProductivity / dayStats[best]?.sessions || 0;
      return avgProductivity > bestAvg ? day : best;
    }, Object.keys(dayStats)[0] || '');
    
    // Find most productive time
    const hourStats = filteredSessions.reduce((acc, session) => {
      const hour = new Date(session.createdAt).getHours();
      if (!acc[hour]) acc[hour] = { sessions: 0, totalProductivity: 0 };
      acc[hour].sessions++;
      acc[hour].totalProductivity += session.productivity || 0;
      return acc;
    }, {} as Record<number, { sessions: number; totalProductivity: number }>);
    
    const mostProductiveHour = Object.keys(hourStats).reduce((best, hour) => {
      const avgProductivity = hourStats[Number.parseInt(hour)].totalProductivity / hourStats[Number.parseInt(hour)].sessions;
      const bestAvg = hourStats[Number.parseInt(best)]?.totalProductivity / hourStats[Number.parseInt(best)]?.sessions || 0;
      return avgProductivity > bestAvg ? hour : best;
    }, Object.keys(hourStats)[0] || '0');
    
    const mostProductiveTime = `${mostProductiveHour}:00 - ${Number.parseInt(mostProductiveHour) + 1}:00`;
    
    // Find favorite subject
    const subjectStats = filteredSessions.reduce((acc, session) => {
      if (session.subject) {
        acc[session.subject] = (acc[session.subject] || 0) + session.durationMin;
      }
      return acc;
    }, {} as Record<string, number>);
    
    const favoriteSubject = Object.keys(subjectStats).reduce((best, subject) => 
      subjectStats[subject] > (subjectStats[best] || 0) ? subject : best, ''
    );
    
    // Calculate study streak (consecutive days with sessions)
    const sortedSessions = [...filteredSessions].sort((a, b) => 
      new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
    );
    
    let studyStreak = 0;
    let currentDate = new Date();
    currentDate.setHours(0, 0, 0, 0);
    
    for (let i = 0; i < 365; i++) { // Check up to a year
      const dayStart = new Date(currentDate);
      const dayEnd = new Date(currentDate);
      dayEnd.setHours(23, 59, 59, 999);
      
      const hasSessionThisDay = sortedSessions.some(session => {
        const sessionDate = new Date(session.createdAt);
        return sessionDate >= dayStart && sessionDate <= dayEnd;
      });
      
      if (hasSessionThisDay) {
        studyStreak++;
      } else if (studyStreak > 0) {
        break; // Streak broken
      }
      
      currentDate.setDate(currentDate.getDate() - 1);
    }
    
    // Calculate trends
    const now = new Date();
    const weekAgo = subDays(now, 7);
    const twoWeeksAgo = subDays(now, 14);
    const monthAgo = subDays(now, 30);
    const twoMonthsAgo = subDays(now, 60);
    
    const thisWeekSessions = filteredSessions.filter(s => new Date(s.createdAt) >= weekAgo);
    const lastWeekSessions = filteredSessions.filter(s => {
      const date = new Date(s.createdAt);
      return date >= twoWeeksAgo && date < weekAgo;
    });
    
    const thisMonthSessions = filteredSessions.filter(s => new Date(s.createdAt) >= monthAgo);
    const lastMonthSessions = filteredSessions.filter(s => {
      const date = new Date(s.createdAt);
      return date >= twoMonthsAgo && date < monthAgo;
    });
    
    const thisWeekHours = thisWeekSessions.reduce((acc, s) => acc + s.durationMin, 0) / 60;
    const lastWeekHours = lastWeekSessions.reduce((acc, s) => acc + s.durationMin, 0) / 60;
    const thisMonthHours = thisMonthSessions.reduce((acc, s) => acc + s.durationMin, 0) / 60;
    const lastMonthHours = lastMonthSessions.reduce((acc, s) => acc + s.durationMin, 0) / 60;
    
    const weeklyTrend = lastWeekHours > 0 ? Math.round(((thisWeekHours - lastWeekHours) / lastWeekHours) * 100) : 0;
    const monthlyTrend = lastMonthHours > 0 ? Math.round(((thisMonthHours - lastMonthHours) / lastMonthHours) * 100) : 0;

    return {
      totalSessions,
      totalHours,
      averageSessionLength,
      averageProductivity,
      averageFocusScore,
      averageMood,
      totalBreaks,
      totalDistractions,
      longestSession,
      shortestSession,
      mostProductiveDay,
      mostProductiveTime,
      favoriteSubject,
      studyStreak,
      weeklyTrend,
      monthlyTrend
    };
  }, [filteredSessions]);

  // Generate chart data
  const chartData: ChartData[] = useMemo(() => {
    const data: Record<string, ChartData> = {};
    
    for (const session of filteredSessions) {
      const date = format(new Date(session.createdAt), 'yyyy-MM-dd');
      
      if (!data[date]) {
        data[date] = {
          date,
          hours: 0,
          sessions: 0,
          productivity: 0,
          mood: 0
        };
      }
      
      data[date].hours += session.durationMin / 60;
      data[date].sessions += 1;
      data[date].productivity += session.productivity || 0;
      
      const moodValues = { 'EXCELLENT': 4, 'GOOD': 3, 'AVERAGE': 2, 'POOR': 1 };
      data[date].mood += moodValues[session.mood || 'AVERAGE'] || 2;
    }
    
    // Calculate averages
    for (const day of Object.values(data)) {
      day.productivity = Math.round(day.productivity / day.sessions);
      day.mood = Math.round(day.mood / day.sessions);
      day.hours = Math.round(day.hours * 10) / 10;
    }
    
    return Object.values(data).sort((a, b) => a.date.localeCompare(b.date));
  }, [filteredSessions]);

  // Filter sessions based on criteria
  useEffect(() => {
    let filtered = [...sessions];
    
    // Time period filter
    const now = new Date();
    let startDate: Date;
    
    switch (timePeriod) {
      case 'week':
        startDate = startOfWeek(now, { weekStartsOn: 0 });
        break;
      case 'month':
        startDate = startOfMonth(now);
        break;
      case 'quarter':
        startDate = subMonths(startOfMonth(now), 3);
        break;
      case 'year':
        startDate = new Date(now.getFullYear(), 0, 1);
        break;
      case 'all':
      default:
        startDate = new Date(0);
        break;
    }
    
    if (customDateRange.start && customDateRange.end) {
      const customStart = new Date(customDateRange.start);
      const customEnd = new Date(customDateRange.end);
      filtered = filtered.filter(session => {
        const sessionDate = new Date(session.createdAt);
        return sessionDate >= customStart && sessionDate <= customEnd;
      });
    } else if (timePeriod !== 'all') {
      filtered = filtered.filter(session => new Date(session.createdAt) >= startDate);
    }
    
    // Subject filter
    if (selectedSubject !== 'all') {
      filtered = filtered.filter(session => session.subject === selectedSubject);
    }
    
    // Mood filter
    if (selectedMood !== 'all') {
      filtered = filtered.filter(session => session.mood === selectedMood);
    }
    
    // Search filter
    if (searchQuery) {
      filtered = filtered.filter(session =>
        session.notes?.toLowerCase().includes(searchQuery.toLowerCase()) ||
        session.subject?.toLowerCase().includes(searchQuery.toLowerCase()) ||
        session.tags?.some(tag => tag.toLowerCase().includes(searchQuery.toLowerCase()))
      );
    }
    
    // Sort sessions
    filtered.sort((a, b) => {
      let comparison = 0;
      
      switch (sortBy) {
        case 'date':
          comparison = new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime();
          break;
        case 'duration':
          comparison = a.durationMin - b.durationMin;
          break;
        case 'productivity':
          comparison = (a.productivity || 0) - (b.productivity || 0);
          break;
        case 'mood': {
          const moodValues = { 'EXCELLENT': 4, 'GOOD': 3, 'AVERAGE': 2, 'POOR': 1 };
          comparison = (moodValues[a.mood || 'AVERAGE'] || 2) - (moodValues[b.mood || 'AVERAGE'] || 2);
          break;
        }
      }
      
      return sortOrder === 'asc' ? comparison : -comparison;
    });
    
    setFilteredSessions(filtered);
    setCurrentPage(1); // Reset pagination
  }, [sessions, timePeriod, selectedSubject, selectedMood, searchQuery, sortBy, sortOrder, customDateRange]);

  // Pagination
  const totalPages = Math.ceil(filteredSessions.length / itemsPerPage);
  const paginatedSessions = filteredSessions.slice(
    (currentPage - 1) * itemsPerPage,
    currentPage * itemsPerPage
  );

  const formatDuration = (minutes: number): string => {
    const hours = Math.floor(minutes / 60);
    const mins = minutes % 60;
    
    if (hours > 0) {
      return `${hours}س ${mins}د`;
    }
    return `${mins}د`;
  };

  const exportData = useCallback(() => {
    try {
      const data = {
        sessions: filteredSessions,
        stats,
        chartData,
        exportDate: new Date().toISOString(),
        filters: {
          timePeriod,
          selectedSubject,
          selectedMood,
          searchQuery
        }
      };
      
      const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `study-sessions-${format(new Date(), 'yyyy-MM-dd')}.json`;
      document.body.appendChild(a);
      a.click();
      a.remove();
      URL.revokeObjectURL(url);
    } catch (error) {
      logger.error('Error exporting data:', error);
    }
  }, [filteredSessions, stats, chartData, timePeriod, selectedSubject, selectedMood, searchQuery]);

  const renderChart = () => {
    if (chartData.length === 0) {
      return (
        <div className="text-center py-8 text-gray-500">
          <BarChart3 className="mx-auto h-12 w-12 opacity-50 mb-2" />
          <p>لا توجد بيانات لعرض الرسم البياني</p>
        </div>
      );
    }

    // Simple chart representation (in a real app, you'd use a charting library like Chart.js or Recharts)
    const maxHours = Math.max(...chartData.map(d => d.hours));
    
    return (
      <div className="space-y-4">
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          <Card>
            <CardContent className="p-4">
              <div className="text-center">
                <div className="text-2xl font-bold text-blue-600">{stats.totalHours}س</div>
                <div className="text-sm text-gray-600">إجمالي الساعات</div>
              </div>
            </CardContent>
          </Card>
          
          <Card>
            <CardContent className="p-4">
              <div className="text-center">
                <div className="text-2xl font-bold text-green-600">{stats.totalSessions}</div>
                <div className="text-sm text-gray-600">إجمالي الجلسات</div>
              </div>
            </CardContent>
          </Card>
          
          <Card>
            <CardContent className="p-4">
              <div className="text-center">
                <div className="text-2xl font-bold text-purple-600">{stats.averageProductivity}%</div>
                <div className="text-sm text-gray-600">متوسط الإنتاجية</div>
              </div>
            </CardContent>
          </Card>
          
          <Card>
            <CardContent className="p-4">
              <div className="text-center">
                <div className="text-2xl font-bold text-yellow-600">{stats.studyStreak}</div>
                <div className="text-sm text-gray-600">أيام متتالية</div>
              </div>
            </CardContent>
          </Card>
        </div>
        
        {/* Simple bar chart */}
        <Card>
          <CardHeader>
            <CardTitle>الساعات اليومية</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-2">
              {chartData.slice(-14).map((day) => (
                <div key={day.date} className="flex items-center gap-3">
                  <div className="w-20 text-sm text-gray-600">
                    {format(new Date(day.date), 'dd/MM', { locale: ar })}
                  </div>
                  <div className="flex-1">
                    <div className="flex items-center gap-2">
                      {/* CSS variables for dynamic values are acceptable */}
                      <div 
                        className="bg-primary h-6 rounded min-w-[2px]"
                        style={{ width: `${(day.hours / maxHours) * 100}%` }}
                      />
                      <span className="text-sm font-medium">{day.hours}س</span>
                    </div>
                  </div>
                  <div className="w-16 text-sm text-gray-500">
                    {day.sessions} جلسة
                  </div>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      </div>
    );
  };

  const renderSessionsList = () => (
    <div className="space-y-3">
      {paginatedSessions.map((session) => (
        <Card key={session.id} className="hover:shadow-md transition-shadow">
          <CardContent className="p-4">
            <div className="flex items-start justify-between">
              <div className="flex-1">
                <div className="flex items-center gap-3 mb-2">
                  <div className="flex items-center gap-2">
                    <Clock className="h-4 w-4 text-blue-500" />
                    <span className="font-medium">{formatDuration(session.durationMin)}</span>
                  </div>
                  
                  {session.subject && (
                    <Badge variant="outline" className="text-xs">
                      <BookOpen className="h-3 w-3 mr-1" />
                      {session.subject}
                    </Badge>
                  )}
                  
                  {session.mood && (
                    <Badge className={cn("text-xs", MOOD_COLORS[session.mood])}>
                      {MOOD_ICONS[session.mood]} {MOOD_LABELS[session.mood]}
                    </Badge>
                  )}
                  
                  {session.productivity !== undefined && (
                    <Badge variant="secondary" className="text-xs">
                      <Activity className="h-3 w-3 mr-1" />
                      {session.productivity}%
                    </Badge>
                  )}
                </div>
                
                <div className="text-sm text-gray-600 mb-2">
                  {format(new Date(session.createdAt), 'EEEE، dd MMMM yyyy - HH:mm', { locale: ar })}
                </div>
                
                {session.notes && (
                  <p className="text-sm text-gray-700 dark:text-gray-300 mb-2 line-clamp-2">
                    {session.notes}
                  </p>
                )}
                
                <div className="flex flex-wrap gap-2">
                  {session.breaks !== undefined && session.breaks > 0 && (
                    <Badge variant="outline" className="text-xs">
                      <Coffee className="h-3 w-3 mr-1" />
                      {session.breaks} استراحة
                    </Badge>
                  )}
                  
                  {session.distractions !== undefined && session.distractions > 0 && (
                    <Badge variant="outline" className="text-xs text-red-600">
                      <Zap className="h-3 w-3 mr-1" />
                      {session.distractions} تشتت
                    </Badge>
                  )}
                  
                  {session.focusScore !== undefined && (
                    <Badge variant="outline" className="text-xs">
                      <Brain className="h-3 w-3 mr-1" />
                      تركيز {session.focusScore}%
                    </Badge>
                  )}
                  
                  {session.tags?.map(tag => (
                    <Badge key={tag} variant="outline" className="text-xs">
                      #{tag}
                    </Badge>
                  ))}
                </div>
              </div>
              
              <div className="flex items-center gap-1">
                {bulkSelectMode && (
                  <input
                    type="checkbox"
                    aria-label={session.subject ? `تحديد جلسة المذاكرة للمادة ${session.subject}` : 'تحديد جلسة المذاكرة'}
                    checked={selectedSessions.includes(session.id)}
                    onChange={handleSessionToggle(session.id)}
                  />
                )}
                
                <Button variant="ghost" size="sm">
                  <MoreHorizontal className="h-4 w-4" />
                </Button>
              </div>
            </div>
          </CardContent>
        </Card>
      ))}
    </div>
  );

  const renderSessionsGrid = () => (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
      {paginatedSessions.map((session) => (
        <Card key={session.id} className="hover:shadow-md transition-shadow">
          <CardContent className="p-4">
            <div className="text-center mb-3">
              <div className="text-2xl font-bold text-blue-600 mb-1">
                {formatDuration(session.durationMin)}
              </div>
              <div className="text-sm text-gray-500">
                {format(new Date(session.createdAt), 'dd/MM/yyyy', { locale: ar })}
              </div>
            </div>
            
            <div className="space-y-2">
              {session.subject && (
                <div className="flex items-center justify-center">
                  <Badge variant="outline">
                    <BookOpen className="h-3 w-3 mr-1" />
                    {session.subject}
                  </Badge>
                </div>
              )}
              
              {session.mood && (
                <div className="flex items-center justify-center">
                  <Badge className={cn("text-xs", MOOD_COLORS[session.mood])}>
                    {MOOD_ICONS[session.mood]} {MOOD_LABELS[session.mood]}
                  </Badge>
                </div>
              )}
              
              {session.productivity !== undefined && (
                <div className="text-center">
                  <div className="text-sm text-gray-600 mb-1">الإنتاجية</div>
                  <Progress value={session.productivity} className="h-2" />
                  <div className="text-xs text-gray-500 mt-1">{session.productivity}%</div>
                </div>
              )}
              
              {session.notes && (
                <p className="text-xs text-gray-600 text-center line-clamp-3 mt-2">
                  {session.notes}
                </p>
              )}
            </div>
          </CardContent>
        </Card>
      ))}
    </div>
  );

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold mb-2">سجل جلسات المذاكرة</h2>
          <div className="flex flex-wrap gap-4 text-sm text-gray-600 dark:text-gray-400">
            <span>الإجمالي: {stats.totalSessions} جلسة</span>
            <span className="text-blue-600">الساعات: {stats.totalHours}س</span>
            <span className="text-green-600">المتوسط: {stats.averageSessionLength}د</span>
            <span className="text-purple-600">الإنتاجية: {stats.averageProductivity}%</span>
          </div>
        </div>
        
        <div className="flex flex-wrap gap-2">
          {/* View Mode Buttons */}
          <div className="flex rounded-lg border">
            <Button
              variant={viewMode === 'list' ? 'default' : 'ghost'}
              size="sm"
              onClick={() => setViewMode('list')}
            >
              قائمة
            </Button>
            <Button
              variant={viewMode === 'grid' ? 'default' : 'ghost'}
              size="sm"
              onClick={() => setViewMode('grid')}
            >
              شبكة
            </Button>
            <Button
              variant={viewMode === 'chart' ? 'default' : 'ghost'}
              size="sm"
              onClick={() => setViewMode('chart')}
            >
              رسم بياني
            </Button>
          </div>
          
          <Button
            variant="outline"
            size="sm"
            onClick={() => setShowStats(!showStats)}
          >
            <BarChart3 className="h-4 w-4" />
          </Button>
          
          <Button
            variant="outline"
            size="sm"
            onClick={() => setShowFilters(!showFilters)}
          >
            <Filter className="h-4 w-4" />
          </Button>
          
          <Button
            variant="outline"
            size="sm"
            onClick={() => setBulkSelectMode(!bulkSelectMode)}
          >
            {bulkSelectMode ? <Eye className="h-4 w-4" /> : <EyeOff className="h-4 w-4" />}
          </Button>
          
          <Button
            variant="outline"
            size="sm"
            onClick={exportData}
          >
            <Download className="h-4 w-4" />
          </Button>
        </div>
      </div>

      {/* Statistics Cards */}
      {showStats && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          <Card>
            <CardContent className="p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-gray-600">أطول جلسة</p>
                  <p className="text-2xl font-bold text-blue-600">{formatDuration(stats.longestSession)}</p>
                </div>
                <Trophy className="h-8 w-8 text-yellow-500" />
              </div>
            </CardContent>
          </Card>
          
          <Card>
            <CardContent className="p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-gray-600">سلسلة الدراسة</p>
                  <p className="text-2xl font-bold text-green-600">{stats.studyStreak} يوم</p>
                </div>
                <Flame className="h-8 w-8 text-red-500" />
              </div>
            </CardContent>
          </Card>
          
          <Card>
            <CardContent className="p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-gray-600">المادة المفضلة</p>
                  <p className="text-lg font-bold text-purple-600">{stats.favoriteSubject || 'غير محدد'}</p>
                </div>
                <BookOpen className="h-8 w-8 text-purple-500" />
              </div>
            </CardContent>
          </Card>
          
          <Card>
            <CardContent className="p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-gray-600">الوقت الأمثل</p>
                  <p className="text-sm font-bold text-orange-600">{stats.mostProductiveTime}</p>
                </div>
                <Clock className="h-8 w-8 text-orange-500" />
              </div>
            </CardContent>
          </Card>
        </div>
      )}

      {/* Trends */}
      {showStats && (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <Card>
            <CardContent className="p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-gray-600">الاتجاه الأسبوعي</p>
                  <div className="flex items-center gap-2">
                    {(() => {
                      let trendColor = "text-gray-600";
                      let trendPrefix = '';
                      let TrendIcon: typeof TrendingUp | typeof TrendingDown | null = null;
                      let iconClassName = '';
                      
                      if (stats.weeklyTrend > 0) {
                        trendColor = "text-green-600";
                        trendPrefix = '+';
                        TrendIcon = TrendingUp;
                        iconClassName = "text-green-600";
                      } else if (stats.weeklyTrend < 0) {
                        trendColor = "text-red-600";
                        TrendIcon = TrendingDown;
                        iconClassName = "text-red-600";
                      }
                      
                      return (
                        <>
                          <span className={cn("text-lg font-bold", trendColor)}>
                            {trendPrefix}{stats.weeklyTrend}%
                          </span>
                          {TrendIcon && <TrendIcon className={cn("h-4 w-4", iconClassName)} />}
                        </>
                      );
                    })()}
                  </div>
                </div>
              </div>
            </CardContent>
          </Card>
          
          <Card>
            <CardContent className="p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-gray-600">الاتجاه الشهري</p>
                  <div className="flex items-center gap-2">
                    {(() => {
                      let trendColor = "text-gray-600";
                      let trendPrefix = '';
                      let TrendIcon: typeof TrendingUp | typeof TrendingDown | null = null;
                      let iconClassName = '';
                      
                      if (stats.monthlyTrend > 0) {
                        trendColor = "text-green-600";
                        trendPrefix = '+';
                        TrendIcon = TrendingUp;
                        iconClassName = "text-green-600";
                      } else if (stats.monthlyTrend < 0) {
                        trendColor = "text-red-600";
                        TrendIcon = TrendingDown;
                        iconClassName = "text-red-600";
                      }
                      
                      return (
                        <>
                          <span className={cn("text-lg font-bold", trendColor)}>
                            {trendPrefix}{stats.monthlyTrend}%
                          </span>
                          {TrendIcon && <TrendIcon className={cn("h-4 w-4", iconClassName)} />}
                        </>
                      );
                    })()}
                  </div>
                </div>
              </div>
            </CardContent>
          </Card>
        </div>
      )}

      {/* Filters */}
      {showFilters && (
        <Card>
          <CardContent className="p-4">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
              <div>
                <Label htmlFor="time-period-select">الفترة الزمنية</Label>
                <Select value={timePeriod} onValueChange={setTimePeriod}>
                  <SelectTrigger id="time-period-select">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
