'use client';

import React, { useState, useEffect, useRef } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Progress } from '@/components/ui/progress';
import { Badge } from '@/components/ui/badge';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Play, Pause, Square, BarChart3, Target, Clock } from 'lucide-react';
import { useLocalStorageState } from '@/hooks/use-local-storage-state';

import { logger } from '@/lib/logger';

interface TimeSession {
  id: string;
  taskId?: string;
  startTime: Date;
  endTime?: Date;
  duration: number; // in seconds
  subject?: string;
}

interface TimeTrackerProps {
  userId: string;
  tasks: Task[];
  subjects: string[];
  onStudySessionCreate?: (session: any) => void;
}

type Task = {
  id: string;
  title: string;
  status: string;
};

type SubjectType = string;

const TimeTracker: React.FC<TimeTrackerProps> = ({
  userId,
  tasks,
  subjects,
  onStudySessionCreate
}) => {
  const [currentTime, setCurrentTime] = useState(0);
  const [isRunning, setIsRunning] = useState(false);
  const [selectedTaskId, setSelectedTaskId] = useState<string | null>(null);
  const [selectedSubject, setSelectedSubject] = useState<string | null>(null);
  const intervalRef = useRef<NodeJS.Timeout | null>(null);
  // Using our new hook for safe localStorage access
  const [sessions, setSessions] = useLocalStorageState<TimeSession[]>(`study_sessions_${userId}`, []);
  const [todayGoal, setTodayGoal] = useLocalStorageState<number>('today_goal', 180); // 3 hours in minutes
  const [isLoading, setIsLoading] = useState(true);
  const [dailyStats, setDailyStats] = useState({ totalSeconds: 0, taskStats: {} as Record<string, number> });
  const [weeklyStats, setWeeklyStats] = useState({ totalSeconds: 0, taskStats: {} as Record<string, number> });
  const [newTaskName, setNewTaskName] = useState('');
  const [newTaskCategory, setNewTaskCategory] = useState('work');
  const [goals, setGoals] = useLocalStorageState<any[]>('time_tracker_goals', [
    { id: '1', title: 'Complete math exercises', target: 120, progress: 45, category: 'Study' },
    { id: '2', title: 'Read 30 pages', target: 60, progress: 100, category: 'Reading' },
    { id: '3', title: 'Practice piano', target: 90, progress: 20, category: 'Music' },
  ]);

  // Handle loading state
  useEffect(() => {
    // We don't need to manually load from localStorage anymore since our hook handles it
    setIsLoading(false);
  }, []);

  // Timer effect
  useEffect(() => {
    let intervalId: NodeJS.Timeout | null = null;
    
    if (isRunning) {
      intervalId = setInterval(() => {
        setCurrentTime(prev => prev + 1);
      }, 1000);
    }
    
    return () => {
      if (intervalId) {
        clearInterval(intervalId);
      }
    };
  }, [isRunning]);

  const formatTime = (seconds: number) => {
    const hrs = Math.floor(seconds / 3600);
    const mins = Math.floor((seconds % 3600) / 60);
    const secs = seconds % 60;
    return `${hrs.toString().padStart(2, '0')}:${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };
  
  const startTimer = () => {
    if (!selectedTaskId && !selectedSubject) {
      if (typeof window !== 'undefined' && (window as any).toast) {
        (window as any).toast({
          title: 'تنبيه',
          description: 'يرجى اختيار مهمة أو مادة لبدء المؤقت',
          variant: 'default'
        });
      }
      return;
    }
    
    setIsRunning(true);
  };

  const pauseTimer = () => {
    setIsRunning(false);
  };

  const stopTimer = async () => {
    setIsRunning(false);
    
    if (currentTime > 0) {
      const newSession: TimeSession = {
        id: Date.now().toString(),
        taskId: selectedTaskId || undefined,
        startTime: new Date(Date.now() - currentTime * 1000),
        endTime: new Date(),
        duration: currentTime,
        subject: selectedSubject || undefined
      };

      // Add to local state
      setSessions(prev => [newSession, ...prev]);
      
      // Save to backend
      try {
        const response = await fetch('/api/study-sessions', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            userId,
            taskId: selectedTaskId,
            durationMin: Math.floor(currentTime / 60),
            subject: selectedSubject
          })
        });

        if (response.ok) {
          const savedSession = await response.json();
          if (onStudySessionCreate) {
            onStudySessionCreate(savedSession);
          }
        }
      } catch (error) {
        logger.error("Error saving study session:", error);
      }
    }

    // Reset timer
    setCurrentTime(0);
    setSelectedTaskId(null);
    setSelectedSubject(null);
  };
  
  const addNewTask = () => {
    if (newTaskName.trim()) {
      // In a real app, this would call a function passed as a prop
      // to update the tasks in the parent component
      const newTask: any = {
        id: `task-${Date.now()}`,
        name: newTaskName,
        color: '#3b82f6',
        category: newTaskCategory
      };
      
      // This is a placeholder - in a real app, you would manage tasks at the parent level
      tasks.push(newTask as Task);
      
      // Reset form
      setNewTaskName('');
      setNewTaskCategory('work');
    }
  };
  
  const updateGoalProgress = (goalId: string, newProgress: number) => {
    setGoals(prevGoals => 
      prevGoals.map(goal => 
        goal.id === goalId 
          ? { ...goal, progress: Math.min(100, Math.max(0, newProgress)) } 
          : goal
      )
    );
  };

  // Calculate stats functions
  const calculateDailyStats = () => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const tomorrow = new Date(today);
    tomorrow.setDate(tomorrow.getDate() + 1);

    const todaySessions = sessions.filter(
      (session) =>
        session.startTime >= today &&
        (!session.endTime || session.endTime < tomorrow)
    );

    const totalSeconds = todaySessions.reduce(
      (total, session) => total + session.duration,
      0
    );

    const taskStats = todaySessions.reduce((acc, session) => {
      const taskId = session.taskId || 'unknown';
      if (!acc[taskId]) {
        acc[taskId] = 0;
      }
      acc[taskId] += session.duration;
      return acc;
    }, {} as Record<string, number>);

    return { totalSeconds, taskStats };
  };
  
  const calculateWeeklyStats = () => {
    const today = new Date();
    const dayOfWeek = today.getDay(); // 0 = Sunday, 1 = Monday, etc.
    const startOfWeek = new Date(today);
    startOfWeek.setDate(today.getDate() - dayOfWeek);
    startOfWeek.setHours(0, 0, 0, 0);
    
    const endOfWeek = new Date(startOfWeek);
    endOfWeek.setDate(startOfWeek.getDate() + 7);

    const weeklySessions = sessions.filter(
      (session) =>
        session.startTime >= startOfWeek &&
        (!session.endTime || session.endTime < endOfWeek)
    );

    const totalSeconds = weeklySessions.reduce(
      (total, session) => total + session.duration,
      0
    );

    const taskStats = weeklySessions.reduce((acc, session) => {
      const taskId = session.taskId || 'unknown';
      if (!acc[taskId]) {
        acc[taskId] = 0;
      }
      acc[taskId] += session.duration;
      return acc;
    }, {} as Record<string, number>);

    return { totalSeconds, taskStats };
  };
  
  // Update stats when sessions change
  useEffect(() => {
    setDailyStats(calculateDailyStats());
    setWeeklyStats(calculateWeeklyStats());
  }, [sessions]);
  
  // Format functions

  const todayMinutes = sessions
    .filter(session => {
      const today = new Date();
      const sessionDate = new Date(session.startTime);
      return sessionDate.toDateString() === today.toDateString();
    })
    .reduce((total, session) => total + Math.floor(session.duration / 60), 0);

  const goalProgress = Math.min(100, (todayMinutes / todayGoal) * 100);

  return (
    <div className="space-y-6 rtl" dir="rtl">
      {/* Timer Display Card */}
      <Card className="border-2 border-primary/20 shadow-lg">
        <CardHeader className="bg-gradient-to-r from-primary/10 to-primary/5 pb-4">
          <CardTitle className="flex items-center justify-center gap-3 text-2xl">
            <Clock className="h-6 w-6 text-primary" />
            مؤقت الوقت
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-6 pt-6">
          {/* Timer Display */}
          <div className="text-center space-y-4">
            <div className={`text-6xl md:text-7xl font-mono font-bold mb-6 transition-all ${
              isRunning ? 'text-primary animate-pulse' : 'text-foreground'
            }`}>
              {formatTime(currentTime)}
            </div>
            
            {/* Timer Controls */}
            <div className="flex justify-center gap-3">
              {!isRunning ? (
                <Button 
                  onClick={startTimer} 
                  size="lg"
                  className="flex items-center gap-2 bg-green-600 hover:bg-green-700 text-white px-8 py-6 text-lg shadow-lg hover:shadow-xl transition-all"
                  disabled={!selectedTaskId && !selectedSubject}
                >
                  <Play className="h-5 w-5" />
                  بدء
                </Button>
              ) : (
                <Button 
                  onClick={pauseTimer} 
                  variant="outline" 
                  size="lg"
                  className="flex items-center gap-2 px-8 py-6 text-lg border-2 border-yellow-500 hover:bg-yellow-50 dark:hover:bg-yellow-900/20"
                >
                  <Pause className="h-5 w-5" />
                  إيقاف مؤقت
                </Button>
              )}
              <Button 
                onClick={stopTimer} 
                variant="outline"
                size="lg"
                disabled={currentTime === 0}
                className="flex items-center gap-2 px-8 py-6 text-lg border-2 border-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 disabled:opacity-50"
              >
                <Square className="h-5 w-5" />
                إيقاف
              </Button>
            </div>
            
            {(!selectedTaskId && !selectedSubject) && (
              <p className="text-sm text-muted-foreground mt-2">
                يرجى اختيار مهمة أو مادة لبدء المؤقت
              </p>
            )}
          </div>

          {/* Task and Subject Selection */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <label className="block text-sm font-medium mb-2">اختر المهمة</label>
              <Select 
                value={selectedTaskId || undefined} 
                onValueChange={(value) => {
                  setSelectedTaskId(value);
                  setSelectedSubject(null); // Clear subject when task is selected
                }}
                disabled={isRunning}
              >
                <SelectTrigger className="w-full">
                  <SelectValue placeholder="اختر مهمة للمتابعة" />
                </SelectTrigger>
                <SelectContent>
                  {tasks && tasks.length > 0
                    ? tasks
                        .filter(task => task.status !== 'COMPLETED')
                        .map(task => (
                      <SelectItem key={task.id} value={task.id}>
                        {task.title}
                      </SelectItem>
                    ))
                    : <SelectItem value="no-tasks" disabled>لا توجد مهام متاحة</SelectItem>}
                </SelectContent>
              </Select>
            </div>
            
            <div className="space-y-2">
              <label className="block text-sm font-medium mb-2">أو اختر المادة</label>
              <Select 
                value={selectedSubject || undefined} 
                onValueChange={(value) => {
                  setSelectedSubject(value);
                  setSelectedTaskId(null); // Clear task when subject is selected
                }}
                disabled={isRunning}
              >
                <SelectTrigger className="w-full">
                  <SelectValue placeholder="اختر مادة للمتابعة" />
                </SelectTrigger>
                <SelectContent>
                  {subjects && subjects.length > 0
                    ? subjects.map(subject => (
                        <SelectItem key={subject} value={subject}>
                          {subject}
                        </SelectItem>
                      ))
                    : <SelectItem value="no-subjects" disabled>لا توجد مواد متاحة</SelectItem>}
                </SelectContent>
              </Select>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Goal Progress Card */}
      <Card className="border-2 border-primary/10">
        <CardHeader className="bg-gradient-to-r from-blue-50 to-blue-100 dark:from-blue-950/30">
          <CardTitle className="flex items-center gap-2 text-lg">
            <Target className="h-5 w-5 text-blue-600 dark:text-blue-400" />
            الهدف اليومي
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4 pt-4">
          <div>
            <div className="flex justify-between mb-2 text-sm">
              <span className="text-muted-foreground">الهدف: {todayGoal} دقيقة</span>
              <span className="font-semibold">{todayMinutes} دقيقة</span>
            </div>
            <Progress value={goalProgress} className="h-4" />
            <div className="flex justify-between mt-1 text-xs text-muted-foreground">
              <span>{Math.round(goalProgress)}%</span>
              <span>{todayGoal - todayMinutes} دقيقة متبقية</span>
            </div>
          </div>
          
          <div className="grid grid-cols-3 gap-2">
            {[60, 120, 180].map(goal => (
              <Button
                key={goal}
                variant={todayGoal === goal ? "default" : "outline"}
                onClick={() => setTodayGoal(goal)}
                size="sm"
                className="transition-all"
              >
                {goal} دقيقة
              </Button>
            ))}
          </div>
        </CardContent>
      </Card>

      {/* Recent Sessions Card */}
      <Card className="border-2 border-primary/10">
        <CardHeader className="bg-gradient-to-r from-purple-50 to-purple-100 dark:from-purple-950/30">
          <CardTitle className="flex items-center gap-2 text-lg">
            <BarChart3 className="h-5 w-5 text-purple-600 dark:text-purple-400" />
            الجلسات الأخيرة
          </CardTitle>
        </CardHeader>
        <CardContent>
          {sessions.length === 0 ? (
            <div className="text-center py-8">
              <Clock className="h-12 w-12 mx-auto mb-3 text-muted-foreground opacity-50" />
              <p className="text-muted-foreground">لا توجد جلسات مذاكرة بعد</p>
              <p className="text-sm text-muted-foreground mt-1">ابدأ المؤقت لتسجيل جلسة مذاكرة</p>
            </div>
          ) : (
            <div className="space-y-3 max-h-60 overflow-y-auto">
              {[...sessions].slice(0, 5).map(session => (
                <div 
                  key={session.id} 
                  className="flex items-center justify-between p-4 bg-muted/50 rounded-lg hover:bg-muted transition-colors border border-border"
                >
                  <div className="flex-1">
                    <div className="font-medium mb-1">
                      {session.taskId 
                        ? tasks.find(t => t.id === session.taskId)?.title 
                        : session.subject || 'جلسة مذاكرة'}
                    </div>
                    <div className="text-sm text-muted-foreground flex items-center gap-2">
                      <Clock className="h-3 w-3" />
                      {formatTime(session.duration)} - {new Date(session.startTime).toLocaleTimeString('ar-SA', { hour: '2-digit', minute: '2-digit' })}
                    </div>
                  </div>
                  <Badge variant="secondary" className="ml-3">
                    {Math.floor(session.duration / 60)} د
                  </Badge>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
};

export default TimeTracker;

'use client';

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { format, startOfWeek, addDays, addWeeks, subWeeks } from 'date-fns';
import { ar } from 'date-fns/locale';
import { Settings, Download, Upload, ChevronLeft, ChevronRight, Eye, EyeOff, CheckCircle, Circle } from 'lucide-react';
import type { Schedule, TimeBlock, WeeklyScheduleProps } from './WeeklySchedule/types';
import { calculateWeekStats, addMinutesToTime } from './WeeklySchedule/utils';
import { ScheduleHeader } from './WeeklySchedule/ScheduleHeader';
import { WeekNavigation } from './WeeklySchedule/WeekNavigation';
import { ScheduleFilters } from './WeeklySchedule/ScheduleFilters';
import { TimeGrid } from './WeeklySchedule/TimeGrid';
import { AgendaView } from './WeeklySchedule/AgendaView';
import { BlockFormDialog } from './WeeklySchedule/BlockFormDialog';
import { SettingsDialog } from './WeeklySchedule/SettingsDialog';

import { logger } from '@/lib/logger';

export default function WeeklySchedule({ 
  schedule, 
  subjects, 
  userId, 
  onScheduleUpdate 
}: WeeklyScheduleProps) {
  const [currentWeek, setCurrentWeek] = useState(new Date());
  const [timeBlocks, setTimeBlocks] = useState<TimeBlock[]>([]);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [blockToEdit, setBlockToEdit] = useState<TimeBlock | null>(null);
  const [selectedSlot, setSelectedSlot] = useState<{ day: number; time: string } | null>(null);
  const [viewMode, setViewMode] = useState<'week' | 'day' | 'agenda'>('week');
  const [selectedDay, setSelectedDay] = useState(0);
  const [showCompleted, setShowCompleted] = useState(true);
  const [filterType, setFilterType] = useState<string>('all');
  const [searchQuery, setSearchQuery] = useState('');
  
  // Form states
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    startTime: '09:00',
    endTime: '10:00',
    day: 0,
    color: '#3b82f6',
    type: 'STUDY' as TimeBlock['type'],
    subject: '',
    priority: 'MEDIUM' as TimeBlock['priority'],
    isRecurring: false,
    recurringPattern: 'WEEKLY' as TimeBlock['recurringPattern'],
    reminders: [] as number[],
    location: '',
    notes: ''
  });
  
  // Advanced features
  const [draggedBlock, setDraggedBlock] = useState<TimeBlock | null>(null);
  const [showSettings, setShowSettings] = useState(false);
  const [autoSave, setAutoSave] = useState(true);
  const [compactView, setCompactView] = useState(false);
  const [showTimeLabels, setShowTimeLabels] = useState(true);
  const [snapToGrid, setSnapToGrid] = useState(true);
  const [defaultDuration, setDefaultDuration] = useState(60); // minutes
  
  // Statistics
  const [weekStats, setWeekStats] = useState(calculateWeekStats([], currentWeek));

  const loadScheduleData = useCallback(() => {
    if (!schedule?.planJson) {
      setTimeBlocks([]);
      return;
    }

    try {
      const data = JSON.parse(schedule.planJson);
      setTimeBlocks(Array.isArray(data.timeBlocks) ? data.timeBlocks : []);
    } catch (error) {
      logger.error('Error parsing schedule data:', error);
      setTimeBlocks([]);
    }
  }, [schedule]);

  useEffect(() => {
    loadScheduleData();
  }, [loadScheduleData]);

  // Memoize week stats calculation
  const weekStatsMemo = useMemo(() => {
    return calculateWeekStats(timeBlocks, currentWeek);
  }, [timeBlocks, currentWeek]);

  useEffect(() => {
    setWeekStats(weekStatsMemo);
  }, [weekStatsMemo]);

  const saveSchedule = useCallback(async () => {
    if (!userId) {
      logger.warn('Cannot save schedule: userId is missing');
      return;
    }

    const scheduleData = {
      timeBlocks,
      lastUpdated: new Date().toISOString(),
      version: '2.0'
    };

    try {
      const endpoint = schedule?.id ? `/api/schedule/${schedule.id}` : '/api/schedule';
      const method = schedule?.id ? 'PATCH' : 'POST';
      
      const response = await fetch(endpoint, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          userId,
          planJson: JSON.stringify(scheduleData)
        })
      });

      if (!response.ok) {
        const errorText = await response.text().catch(() => 'Unknown error');
        throw new Error(`Failed to save schedule: ${errorText}`);
      }
      
      const savedSchedule = await response.json();
      onScheduleUpdate?.(savedSchedule);
    } catch (error) {
      logger.error('Error saving schedule:', error);
      // You can add toast notification here if needed
    }
  }, [timeBlocks, userId, schedule, onScheduleUpdate]);

  // Debounced auto-save
  useEffect(() => {
    if (!autoSave) return;
    
    const timer = setTimeout(() => {
      saveSchedule();
    }, 1000);
    
    return () => clearTimeout(timer);
  }, [timeBlocks, autoSave, saveSchedule]);

  const handleSlotClick = useCallback((day: number, time: string) => {
    setSelectedSlot({ day, time });
    setFormData(prev => ({
      ...prev,
      day,
      startTime: time,
      endTime: addMinutesToTime(time, defaultDuration)
    }));
    setBlockToEdit(null);
    setIsDialogOpen(true);
  }, [defaultDuration]);

  const handleBlockEdit = useCallback((block: TimeBlock) => {
    if (!block) return;
    
    setBlockToEdit(block);
    setFormData({
      title: block.title || '',
      description: block.description || '',
      startTime: block.startTime || '09:00',
      endTime: block.endTime || '10:00',
      day: block.day ?? 0,
      color: block.color || '#3b82f6',
      type: block.type || 'STUDY',
      subject: block.subject || '',
      priority: block.priority || 'MEDIUM',
      isRecurring: block.isRecurring || false,
      recurringPattern: block.recurringPattern || 'WEEKLY',
      reminders: block.reminders || [],
      location: block.location || '',
      notes: block.notes || ''
    });
    setIsDialogOpen(true);
  }, []);

  const handleFormSubmit = useCallback((e: React.FormEvent) => {
    e.preventDefault();
    
    // Validate time range
    if (formData.startTime >= formData.endTime) {
      logger.error('Start time must be before end time');
      return;
    }

    const newBlock: TimeBlock = {
      id: blockToEdit?.id || `block_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
      ...formData,
      isCompleted: blockToEdit?.isCompleted || false,
      completedAt: blockToEdit?.completedAt
    };

    if (blockToEdit) {
      setTimeBlocks(prev => prev.map(block => 
        block.id === blockToEdit.id ? newBlock : block
      ));
    } else {
      setTimeBlocks(prev => [...prev, newBlock]);
    }

    setIsDialogOpen(false);
    setBlockToEdit(null);
    setSelectedSlot(null);
    setFormData(prev => ({
      ...prev,
      title: '',
      description: '',
      startTime: '09:00',
      endTime: '10:00',
      day: 0,
      color: '#3b82f6',
      type: 'STUDY' as TimeBlock['type'],
      subject: '',
      priority: 'MEDIUM' as TimeBlock['priority'],
      isRecurring: false,
      recurringPattern: 'WEEKLY' as TimeBlock['recurringPattern'],
      reminders: [],
      location: '',
    }));
  }, [formData, blockToEdit]);

  const handleDialogClose = useCallback(() => {
    setIsDialogOpen(false);
    setBlockToEdit(null);
    setSelectedSlot(null);
    setFormData({
      title: '',
      description: '',
      startTime: '09:00',
      endTime: '10:00',
      day: 0,
      color: '#3b82f6',
      type: 'STUDY',
      subject: '',
      priority: 'MEDIUM',
      isRecurring: false,
      recurringPattern: 'WEEKLY',
      reminders: [],
      location: '',
      notes: ''
    });
  }, []);

  const handleBlockDelete = useCallback((blockId: string) => {
    if (!blockId) return;
    setTimeBlocks(prev => prev.filter(block => block.id !== blockId));
  }, []);

  const handleBlockComplete = useCallback((blockId: string) => {
    if (!blockId) return;
    setTimeBlocks(prev => prev.map(block => 
      block.id === blockId 
        ? { 
            ...block, 
            isCompleted: !block.isCompleted,
            completedAt: !block.isCompleted ? new Date().toISOString() : undefined
          }
        : block
    ));
  }, []);

  const duplicateBlock = useCallback((block: TimeBlock) => {
    if (!block) return;
    const newBlock: TimeBlock = {
      ...block,
      id: `block_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
      title: `${block.title} (نسخة)`,
      isCompleted: false,
      completedAt: undefined
    };
    setTimeBlocks(prev => [...prev, newBlock]);
  }, []);

  // Memoize filtered blocks
  const filteredBlocks = useMemo(() => {
    return timeBlocks.filter(block => {
      // Search filter
      if (searchQuery) {
        const query = searchQuery.toLowerCase();
        const titleMatch = block.title?.toLowerCase().includes(query);
        const descMatch = block.description?.toLowerCase().includes(query);
        if (!titleMatch && !descMatch) {
          return false;
        }
      }
      
      // Type filter
      if (filterType !== 'all' && block.type !== filterType) {
        return false;
      }
      
      // Completed filter
      if (!showCompleted && block.isCompleted) {
        return false;
      }
      
      return true;
    });
  }, [timeBlocks, searchQuery, filterType, showCompleted]);

  const exportSchedule = useCallback(() => {
    try {
      const data = {
        timeBlocks,
        weekStats,
        exportDate: new Date().toISOString(),
        version: '2.0'
      };
      
      const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `schedule-${format(currentWeek, 'yyyy-MM-dd')}.json`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
    } catch (error) {
      logger.error('Error exporting schedule:', error);
    }
  }, [timeBlocks, weekStats, currentWeek]);

  const importSchedule = useCallback((event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = JSON.parse(e.target?.result as string);
        if (Array.isArray(data.timeBlocks)) {
          setTimeBlocks(data.timeBlocks);
        } else {
          logger.error('Invalid schedule format');
        }
      } catch (error) {
        logger.error('Error importing schedule:', error);
      }
    };
    reader.onerror = () => {
      logger.error('Error reading file');
    };
    reader.readAsText(file);
  }, []);


  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4">
        <ScheduleHeader
          weekStats={weekStats}
          onSettingsClick={() => setShowSettings(true)}
          onExport={exportSchedule}
          onImport={importSchedule}
        />
        
        <div className="flex flex-wrap gap-2">
          <WeekNavigation
            currentWeek={currentWeek}
            onWeekChange={setCurrentWeek}
            viewMode={viewMode}
            onViewModeChange={setViewMode}
          />
        </div>
      </div>

      {/* Filters */}
      <ScheduleFilters
        searchQuery={searchQuery}
        onSearchChange={setSearchQuery}
        filterType={filterType}
        onFilterTypeChange={setFilterType}
        showCompleted={showCompleted}
        onShowCompletedToggle={() => setShowCompleted(!showCompleted)}
      />

      {/* Schedule View */}
      <Card>
        <CardContent className="p-0">
          {viewMode === 'week' ? (
            <div className="overflow-x-auto">
              <TimeGrid
                currentWeek={currentWeek}
                timeBlocks={filteredBlocks}
                showTimeLabels={showTimeLabels}
                compactView={compactView}
                onSlotClick={handleSlotClick}
                onBlockEdit={handleBlockEdit}
                onBlockComplete={handleBlockComplete}
                onBlockDragStart={setDraggedBlock}
              />
            </div>
          ) : (
            <div className="p-6">
              <AgendaView
                currentWeek={currentWeek}
                timeBlocks={filteredBlocks}
                onBlockEdit={handleBlockEdit}
                onBlockComplete={handleBlockComplete}
              />
            </div>
          )}
        </CardContent>
      </Card>

      {/* Add/Edit Block Dialog */}
      <BlockFormDialog
        isOpen={isDialogOpen}
        onOpenChange={setIsDialogOpen}
        blockToEdit={blockToEdit}
        formData={formData}
        subjects={subjects}
        onFormDataChange={(updates) => setFormData(prev => ({ ...prev, ...updates }))}
        onSubmit={handleFormSubmit}
        onDelete={blockToEdit ? () => {
          handleBlockDelete(blockToEdit.id);
          handleDialogClose();
        } : undefined}
      />

      {/* Settings Dialog */}
      <SettingsDialog
        isOpen={showSettings}
        onOpenChange={setShowSettings}
        autoSave={autoSave}
        onAutoSaveToggle={() => setAutoSave(!autoSave)}
        compactView={compactView}
        onCompactViewToggle={() => setCompactView(!compactView)}
        showTimeLabels={showTimeLabels}
        onShowTimeLabelsToggle={() => setShowTimeLabels(!showTimeLabels)}
        defaultDuration={defaultDuration}
        onDefaultDurationChange={setDefaultDuration}
      />
    </div>
  );
}

import React from 'react';
import { cn } from '@/lib/utils';
import { TIME_SLOTS, DAYS_OF_WEEK } from './constants';
import { getWeekDays, parseTime, addMinutesToTime } from './utils';
import { format } from 'date-fns';
import { ar } from 'date-fns/locale';
import type { TimeBlock } from './types';
import { TimeBlockCard } from './TimeBlockCard';

interface TimeGridProps {
  currentWeek: Date;
  timeBlocks: TimeBlock[];
  showTimeLabels: boolean;
  compactView: boolean;
  onSlotClick: (day: number, time: string) => void;
  onBlockEdit: (block: TimeBlock) => void;
  onBlockComplete: (blockId: string) => void;
  onBlockDragStart: (block: TimeBlock) => void;
}

const getBlocksForTimeSlot = (blocks: TimeBlock[], day: number, time: string) => {
  return blocks.filter(block => {
    if (block.day !== day) return false;
    const blockStart = parseTime(block.startTime);
    const slotStart = parseTime(time);
    const slotEnd = parseTime(addMinutesToTime(time, 60));
    return blockStart >= slotStart && blockStart < slotEnd;
  });
};

export function TimeGrid({
  currentWeek,
  timeBlocks,
  showTimeLabels,
  compactView,
  onSlotClick,
  onBlockEdit,
  onBlockComplete,
  onBlockDragStart
}: TimeGridProps) {
  const weekDays = getWeekDays(currentWeek);
  
  return (
    <div className="grid grid-cols-8 gap-1 text-sm">
      {/* Time column header */}
      <div className="sticky top-0 bg-white dark:bg-gray-900 z-10 p-2 border-b">
        <span className="text-xs text-gray-500">الوقت</span>
      </div>
      
      {/* Day headers */}
      {weekDays.map((day, index) => (
        <div key={index} className="sticky top-0 bg-white dark:bg-gray-900 z-10 p-2 border-b text-center">
          <div className="font-medium">{DAYS_OF_WEEK[index]}</div>
          <div className="text-xs text-gray-500">
            {format(day, 'dd/MM', { locale: ar })}
          </div>
        </div>
      ))}
      
      {/* Time slots */}
      {TIME_SLOTS.map((time, timeIndex) => (
        <React.Fragment key={time}>
          {/* Time label */}
          {showTimeLabels && (
            <div className="p-2 text-xs text-gray-500 border-r">
              {time}
            </div>
          )}
          
          {/* Day slots */}
          {Array.from({ length: 7 }, (_, dayIndex) => {
            const dayBlocks = getBlocksForTimeSlot(timeBlocks, dayIndex, time);
            
            return (
              <div
                key={`${dayIndex}-${time}`}
                className={cn(
                  "min-h-[60px] border border-gray-200 dark:border-gray-700 cursor-pointer hover:bg-gray-50 dark:hover:bg-gray-800 relative",
                  compactView && "min-h-[40px]"
                )}
                onClick={() => onSlotClick(dayIndex, time)}
              >
                {dayBlocks.map(block => (
                  <TimeBlockCard
                    key={block.id}
                    block={block}
                    compactView={compactView}
                    onEdit={onBlockEdit}
                    onComplete={onBlockComplete}
                    onDragStart={onBlockDragStart}
                  />
                ))}
              </div>
            );
          })}
        </React.Fragment>
      ))}
    </div>
  );
}

import { startOfWeek, addDays, parseISO } from 'date-fns';
import type { TimeBlock, WeekStats } from './types';
import { DAYS_OF_WEEK } from './constants';

export const parseTime = (timeStr: string): Date => {
  const [hours, minutes] = timeStr.split(':').map(Number);
  const date = new Date();
  date.setHours(hours, minutes, 0, 0);
  return date;
};

export const formatTimeRange = (startTime: string, endTime: string): string => {
  return `${startTime} - ${endTime}`;
};

export const getBlockDuration = (startTime: string, endTime: string): number => {
  const start = parseTime(startTime);
  const end = parseTime(endTime);
  return (end.getTime() - start.getTime()) / (1000 * 60); // minutes
};

export const addMinutesToTime = (time: string, minutes: number): string => {
  const [hours, mins] = time.split(':').map(Number);
  const totalMinutes = hours * 60 + mins + minutes;
  const newHours = Math.floor(totalMinutes / 60) % 24;
  const newMins = totalMinutes % 60;
  return `${newHours.toString().padStart(2, '0')}:${newMins.toString().padStart(2, '0')}`;
};

export const getWeekDays = (currentWeek: Date) => {
  const weekStart = startOfWeek(currentWeek, { weekStartsOn: 0 });
  return Array.from({ length: 7 }, (_, i) => addDays(weekStart, i));
};

export const calculateWeekStats = (timeBlocks: TimeBlock[], currentWeek: Date): WeekStats => {
  const weekStart = startOfWeek(currentWeek, { weekStartsOn: 0 });
  const weekEnd = addDays(weekStart, 6);
  
  const weekBlocks = timeBlocks.filter(block => {
    const blockDate = addDays(weekStart, block.day);
    return blockDate >= weekStart && blockDate <= weekEnd;
  });
  
  const totalBlocks = weekBlocks.length;
  const studyBlocks = weekBlocks.filter(b => b.type === 'STUDY');
  const breakBlocks = weekBlocks.filter(b => b.type === 'BREAK');
  const completedBlocks = weekBlocks.filter(b => b.isCompleted).length;
  const upcomingBlocks = weekBlocks.filter(b => !b.isCompleted).length;
  
  const studyHours = studyBlocks.reduce((acc, block) => {
    const start = parseTime(block.startTime);
    const end = parseTime(block.endTime);
    return acc + (end.getTime() - start.getTime()) / (1000 * 60 * 60);
  }, 0);
  
  const breakHours = breakBlocks.reduce((acc, block) => {
    const start = parseTime(block.startTime);
    const end = parseTime(block.endTime);
    return acc + (end.getTime() - start.getTime()) / (1000 * 60 * 60);
  }, 0);
  
  // Find most busy day
  const dayBlockCounts = Array.from({ length: 7 }, (_, i) => ({
    day: i,
    count: weekBlocks.filter(b => b.day === i).length
  }));
  const mostBusyDay = dayBlockCounts.reduce((max, current) => 
    current.count > max.count ? current : max
  );
  
  // Calculate average block duration
  const totalDuration = weekBlocks.reduce((acc, block) => {
    const start = parseTime(block.startTime);
    const end = parseTime(block.endTime);
    return acc + (end.getTime() - start.getTime()) / (1000 * 60); // minutes
  }, 0);
  const averageBlockDuration = totalBlocks > 0 ? totalDuration / totalBlocks : 0;
  
  return {
    totalBlocks,
    studyHours: Math.round(studyHours * 10) / 10,
    breakHours: Math.round(breakHours * 10) / 10,
    completedBlocks,
    upcomingBlocks,
    mostBusyDay: DAYS_OF_WEEK[mostBusyDay.day],
    averageBlockDuration: Math.round(averageBlockDuration)
  };
};

