'use client';

import { useState, useEffect } from 'react';
import { AuthGuard } from "@/components/auth/AuthGuard";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import WeeklySchedule from "@/app/(dashboard)/time/components/WeeklySchedule";
import TaskManagement from "@/app/(dashboard)/time/components/TaskManagement";
import StudySessionsHistory from "@/app/(dashboard)/time/components/StudySessionsHistory";
import Reminders from "@/app/(dashboard)/time/components/Reminders";
import TimeTracker from "@/app/(dashboard)/time/components/TimeTracker";
import { Button } from "@/components/ui/button";
import { RefreshCw, Settings, Filter, Search, BarChart3, Play, Pause, Cog } from 'lucide-react';
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";

// Components
import TimeManagementHeader from './components/TimeManagementHeader';
import DashboardTab from './components/DashboardTab';
import TimeAnalytics from './components/TimeAnalytics';
import ProductivityInsights from './components/ProductivityInsights';
import ExportDialog from './components/ExportDialog';
import KeyboardShortcutsHelp from './components/KeyboardShortcutsHelp';

// Hooks
import { useTimeData } from './hooks/useTimeData';
import { useTimeStats } from './hooks/useTimeStats';
import { useTimeFilters } from './hooks/useTimeFilters';
import { useOverdueNotifications } from './hooks/useOverdueNotifications';

// Types
import type { Task, StudySession, Reminder, Schedule, TimeTrackerTask } from './types';

import { logger } from '@/lib/logger';

export default function TimeManagementPage() {
  const [activeTab, setActiveTab] = useState("dashboard");
  const [isTimerRunning, setIsTimerRunning] = useState(false);
  const [currentTaskId, setCurrentTaskId] = useState<string | null>(null);
  
  // Search and filter states
  const [taskSearch, setTaskSearch] = useState("");
  const [taskFilter, setTaskFilter] = useState<"all" | "pending" | "in_progress" | "completed">("all");
  const [reminderSearch, setReminderSearch] = useState("");
  const [sessionFilter, setSessionFilter] = useState<"all" | "today" | "week" | "month">("all");
  
  // UI states
  const [showCompletedTasks, setShowCompletedTasks] = useState(true);
  const [showUpcomingRemindersOnly, setShowUpcomingRemindersOnly] = useState(true);
  const [showAnalytics, setShowAnalytics] = useState(false);
  const [showInsights, setShowInsights] = useState(false);

  // Custom hooks
  const { 
    userId, 
    schedule, 
    subjects, 
    tasks, 
    studySessions, 
    reminders, 
    isLoading, 
    fetchData 
  } = useTimeData();

  const {
    stats,
    updateStatsOnTaskChange,
    updateStatsOnTaskCreate,
    updateStatsOnTaskDelete,
    updateStatsOnSessionCreate,
    updateStatsOnReminderCreate,
    updateStatsOnReminderDelete
  } = useTimeStats({ tasks, studySessions, reminders });

  const { filteredTasks, filteredReminders, filteredSessions } = useTimeFilters({
    tasks,
    reminders,
    studySessions,
    taskSearch,
    taskFilter,
    reminderSearch,
    sessionFilter,
    showUpcomingRemindersOnly
  });

  // Local state management for tasks, reminders, and sessions
  const [tasksLocal, setTasksLocal] = useState<Task[]>(tasks);
  const [remindersLocal, setRemindersLocal] = useState<Reminder[]>(reminders);
  const [studySessionsLocal, setStudySessionsLocal] = useState<StudySession[]>(studySessions);
  const [scheduleLocal, setScheduleLocal] = useState<Schedule | null>(schedule);

  // Sync with hook data
  useEffect(() => {
    setTasksLocal(tasks);
    setRemindersLocal(reminders);
    setStudySessionsLocal(studySessions);
    setScheduleLocal(schedule);
  }, [tasks, reminders, studySessions, schedule]);

  // Handle task updates
  const handleTaskUpdate = (updatedTask: Task) => {
    const oldTask = tasksLocal.find(t => t.id === updatedTask.id);
    setTasksLocal(prev => prev.map(t => t.id === updatedTask.id ? updatedTask : t));
    if (oldTask) {
      updateStatsOnTaskChange(oldTask, updatedTask);
    }
  };

  // Handle new task creation
  const handleTaskCreate = (newTask: Task) => {
    setTasksLocal(prev => [newTask, ...prev]);
    updateStatsOnTaskCreate(newTask);
  };

  // Handle task deletion
  const handleTaskDelete = (taskId: string) => {
    const task = tasksLocal.find(t => t.id === taskId);
    if (!task) return;
    setTasksLocal(prev => prev.filter(t => t.id !== taskId));
    updateStatsOnTaskDelete(task);
  };

  // Handle new study session
  const handleStudySessionCreate = (newSession: StudySession) => {
    setStudySessionsLocal(prev => [newSession, ...prev]);
    updateStatsOnSessionCreate(newSession);
  };

  // Handle reminder updates
  const handleReminderUpdate = (updatedReminder: Reminder) => {
    setRemindersLocal(prev => prev.map(r => r.id === updatedReminder.id ? updatedReminder : r));
  };

  // Handle new reminder creation
  const handleReminderCreate = (newReminder: Reminder) => {
    setRemindersLocal(prev => [newReminder, ...prev]);
    updateStatsOnReminderCreate(newReminder);
  };

  // Handle reminder deletion
  const handleReminderDelete = (reminderId: string) => {
    const reminder = remindersLocal.find(r => r.id === reminderId);
    if (!reminder) return;
    setRemindersLocal(prev => prev.filter(r => r.id !== reminderId));
    updateStatsOnReminderDelete(reminder);
  };

  // Handle schedule updates
  const handleScheduleUpdate = (updatedSchedule: Schedule) => {
    setScheduleLocal(updatedSchedule);
  };

  // Handle notifications
  const handleNotification = (message: string, type: 'warning' | 'error') => {
    // You can integrate with your notification system here
    logger.info(`[${type.toUpperCase()}] ${message}`);
    // Example: toast notification
    if (typeof window !== 'undefined' && (window as any).toast) {
      (window as any).toast({
        title: type === 'error' ? 'تنبيه مهم' : 'إشعار',
        description: message,
        variant: type === 'error' ? 'destructive' : 'default'
      });
    }
  };

  // Overdue notifications
  useOverdueNotifications({
    tasks: tasksLocal,
    onNotification: handleNotification
  });

  // Handle timer start/stop
  const handleTimerToggle = (taskId?: string) => {
    setIsTimerRunning(!isTimerRunning);
    if (taskId) {
      setCurrentTaskId(taskId);
    }
    // Switch to tracker tab when timer starts
    if (!isTimerRunning) {
      setActiveTab("tracker");
    }
  };

  // Map our Task type to TimeTracker's expected Task type
  const mapTasksForTimeTracker = (): TimeTrackerTask[] => {
    return tasksLocal.map(task => ({
      id: task.id,
      title: task.title,
      status: task.status || 'PENDING'
    }));
  };

  if (isLoading) {
    return (
      <AuthGuard>
        <div className="container mx-auto p-4 text-center min-h-screen flex items-center justify-center">
          <div className="flex flex-col items-center justify-center space-y-4">
            <div className="relative">
              <RefreshCw className="h-8 w-8 animate-spin text-primary" />
              <div className="absolute inset-0 rounded-full border-2 border-primary/20"></div>
            </div>
            <div className="space-y-2">
              <p className="text-lg font-semibold">جاري التحميل...</p>
              <p className="text-sm text-muted-foreground">يرجى الانتظار بينما نقوم بتحميل بياناتك</p>
            </div>
          </div>
        </div>
      </AuthGuard>
    );
  }

  return (
    <AuthGuard>
      <div className="container mx-auto p-4 rtl" dir="rtl">
      <div className="mb-6 animate-in fade-in slide-in-from-top-4 duration-500">
        <TimeManagementHeader
          isTimerRunning={isTimerRunning}
          onTimerToggle={() => handleTimerToggle()}
          onRefresh={fetchData}
        />
      </div>

      <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
        <TabsList className="grid w-full grid-cols-2 sm:grid-cols-3 md:grid-cols-6 gap-1 md:gap-2 mb-6 bg-muted/50 p-1 rounded-lg">
          <TabsTrigger 
            value="dashboard"
            className="data-[state=active]:bg-background data-[state=active]:shadow-sm transition-all"
          >
            لوحة التحكم
          </TabsTrigger>
          <TabsTrigger 
            value="schedule"
            className="data-[state=active]:bg-background data-[state=active]:shadow-sm transition-all"
          >
            الجدول الأسبوعي
          </TabsTrigger>
          <TabsTrigger 
            value="tasks"
            className="data-[state=active]:bg-background data-[state=active]:shadow-sm transition-all"
          >
            إدارة المهام
          </TabsTrigger>
          <TabsTrigger 
            value="tracker"
            className="data-[state=active]:bg-background data-[state=active]:shadow-sm transition-all"
          >
            مؤقت الوقت
          </TabsTrigger>
          <TabsTrigger 
            value="history"
            className="data-[state=active]:bg-background data-[state=active]:shadow-sm transition-all"
          >
            سجل المذاكرة
          </TabsTrigger>
          <TabsTrigger 
            value="reminders"
            className="data-[state=active]:bg-background data-[state=active]:shadow-sm transition-all"
          >
            التذكيرات
          </TabsTrigger>
        </TabsList>

        <TabsContent value="dashboard" className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="flex justify-between items-center mb-4 gap-2">
            <KeyboardShortcutsHelp />
            <div className="flex gap-2">
              <ExportDialog 
                tasks={tasksLocal}
                studySessions={studySessionsLocal}
                reminders={remindersLocal}
              />
              <Button
                variant="outline"
                size="sm"
                onClick={() => setShowAnalytics(!showAnalytics)}
                className="flex items-center gap-2"
              >
                <BarChart3 className="h-4 w-4" />
                {showAnalytics ? 'إخفاء التحليلات' : 'إظهار التحليلات'}
              </Button>
            </div>
          </div>
          
          <DashboardTab
            stats={stats}
            subjects={subjects}
            tasks={filteredTasks}
            reminders={filteredReminders}
            studySessions={studySessionsLocal}
            showCompletedTasks={showCompletedTasks}
            showUpcomingRemindersOnly={showUpcomingRemindersOnly}
            onTabChange={setActiveTab}
            onToggleCompletedTasks={() => setShowCompletedTasks(!showCompletedTasks)}
            onToggleUpcomingReminders={() => setShowUpcomingRemindersOnly(!showUpcomingRemindersOnly)}
            onTimerToggle={handleTimerToggle}
          />

          {showAnalytics && (
            <div className="space-y-6">
              <TimeAnalytics
                tasks={tasksLocal}
                studySessions={studySessionsLocal}
                reminders={remindersLocal}
              />
              <ProductivityInsights
                tasks={tasksLocal}
                studySessions={studySessionsLocal}
              />
            </div>
          )}
        </TabsContent>

        <TabsContent value="schedule" className="animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="mb-6 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
            <div>
              <h2 className="text-2xl font-bold">الجدول الأسبوعي</h2>
              <p className="text-sm text-muted-foreground mt-1">نظم دراستك وخطط لأسبوعك</p>
            </div>
            <div className="flex gap-2">
              <Button variant="outline" size="sm" className="transition-all hover:shadow-md">
                <Settings className="h-4 w-4 ml-2" />
                إعدادات الجدول
              </Button>
            </div>
          </div>
          {userId && (
            <div className="animate-in fade-in duration-700">
              <WeeklySchedule schedule={scheduleLocal} subjects={subjects} userId={userId} onScheduleUpdate={handleScheduleUpdate} />
            </div>
          )}
        </TabsContent>

        <TabsContent value="tasks" className="animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="mb-6 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
            <div>
              <h2 className="text-2xl font-bold">إدارة المهام</h2>
              <p className="text-sm text-muted-foreground mt-1">تابع مهامك وأكملها في الوقت المحدد</p>
            </div>
            <div className="flex flex-wrap gap-2">
              <div className="relative">
                <Search className="absolute left-2 top-2.5 h-4 w-4 text-muted-foreground" />
                <Input
                  placeholder="بحث في المهام..."
                  value={taskSearch}
                  onChange={(e) => setTaskSearch(e.target.value)}
                  className="pl-8 w-full sm:w-40 transition-all focus:ring-2 focus:ring-primary/20"
                />
              </div>
              <Select value={taskFilter} onValueChange={(value: "all" | "pending" | "in_progress" | "completed") => setTaskFilter(value)}>
                <SelectTrigger className="w-full sm:w-32">
                  <SelectValue placeholder="تصفية حسب الحالة" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">جميع المهام</SelectItem>
                  <SelectItem value="pending">في الانتظار</SelectItem>
                  <SelectItem value="in_progress">قيد التنفيذ</SelectItem>
                  <SelectItem value="completed">مكتملة</SelectItem>
                </SelectContent>
              </Select>
              <Button variant="outline" size="sm" className="transition-all hover:shadow-md">
                <Filter className="h-4 w-4 ml-2" />
                تصفية متقدمة
              </Button>
            </div>
          </div>
          {userId && (
            <div className="animate-in fade-in duration-700">
              <TaskManagement 
                initialTasks={filteredTasks} 
                userId={userId} 
                subjects={subjects}
                onTaskUpdate={handleTaskUpdate}
                onTaskCreate={handleTaskCreate}
                onTaskDelete={handleTaskDelete}
              />
            </div>
          )}
        </TabsContent>

        <TabsContent value="tracker" className="animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="mb-6 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
            <div>
              <h2 className="text-2xl font-bold">مؤقت الوقت</h2>
              <p className="text-sm text-muted-foreground mt-1">سجل وقت مذاكرتك واتبع تقدمك</p>
            </div>
            <div className="flex gap-2">
              <Button 
                onClick={() => handleTimerToggle()} 
                className={`flex items-center gap-2 transition-all shadow-lg hover:shadow-xl ${
                  isTimerRunning 
                    ? 'bg-red-600 hover:bg-red-700 animate-pulse' 
                    : 'bg-green-600 hover:bg-green-700'
                }`}
              >
                {isTimerRunning ? (
                  <>
                    <Pause className="h-4 w-4" />
                    إيقاف
                  </>
                ) : (
                  <>
                    <Play className="h-4 w-4" />
                    بدء
                  </>
                )}
              </Button>
            </div>
          </div>
          {userId && (
            <div className="animate-in fade-in duration-700">
              <TimeTracker 
                userId={userId}
                tasks={mapTasksForTimeTracker()}
                subjects={subjects}
                onStudySessionCreate={handleStudySessionCreate}
              />
            </div>
          )}
        </TabsContent>

        <TabsContent value="history" className="animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="mb-6 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
            <div>
              <h2 className="text-2xl font-bold">سجل المذاكرة</h2>
              <p className="text-sm text-muted-foreground mt-1">راجع تاريخ جلسات المذاكرة وتحليل أدائك</p>
            </div>
            <div className="flex gap-2">
              <Select value={sessionFilter} onValueChange={(value: "all" | "today" | "week" | "month") => setSessionFilter(value)}>
                <SelectTrigger className="w-full sm:w-32">
                  <SelectValue placeholder="تصفية حسب التاريخ" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">جميع الجلسات</SelectItem>
                  <SelectItem value="today">اليوم</SelectItem>
                  <SelectItem value="week">هذا الأسبوع</SelectItem>
                  <SelectItem value="month">هذا الشهر</SelectItem>
                </SelectContent>
              </Select>
              <Button variant="outline" size="sm" className="transition-all hover:shadow-md">
                <BarChart3 className="h-4 w-4 ml-2" />
                تحليل البيانات
              </Button>
            </div>
          </div>
          <div className="animate-in fade-in duration-700">
            <StudySessionsHistory 
              sessions={filteredSessions.length > 0 ? filteredSessions : studySessionsLocal} 
              subjects={subjects}
            />
          </div>
        </TabsContent>

        <TabsContent value="reminders" className="animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="mb-6 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
            <div>
              <h2 className="text-2xl font-bold">التذكيرات</h2>
              <p className="text-sm text-muted-foreground mt-1">لا تنس أي موعد أو مهمة مهمة</p>
            </div>
            <div className="flex flex-wrap gap-2">
              <div className="relative">
                <Search className="absolute left-2 top-2.5 h-4 w-4 text-muted-foreground" />
                <Input
                  placeholder="بحث في التذكيرات..."
                  value={reminderSearch}
                  onChange={(e) => setReminderSearch(e.target.value)}
                  className="pl-8 w-full sm:w-40 transition-all focus:ring-2 focus:ring-primary/20"
                />
              </div>
              <Button variant="outline" size="sm" className="transition-all hover:shadow-md">
                <Filter className="h-4 w-4 ml-2" />
                تصفية متقدمة
              </Button>
            </div>
          </div>
          {userId && (
            <div className="animate-in fade-in duration-700">
              <Reminders 
                initialReminders={filteredReminders.length > 0 ? filteredReminders : remindersLocal} 
                userId={userId}
                onReminderUpdate={handleReminderUpdate}
                onReminderCreate={handleReminderCreate}
                onReminderDelete={handleReminderDelete}
              />
            </div>
          )}
        </TabsContent>

      </Tabs>
      </div>
    </AuthGuard>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Textarea } from '@/components/ui/textarea';
import { Progress } from "@/components/ui/progress";
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group';
import { Checkbox } from '@/components/ui/checkbox';
import { Badge } from "@/components/ui/badge";
import { AlertCircle, CheckCircle, Clock, BookOpen, Brain, Lightbulb, Award } from 'lucide-react';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';

import { logger } from '@/lib/logger';

interface Question {
  id: string;
  text: string;
  type: 'multiple-choice' | 'true-false' | 'short-answer' | 'essay';
  options?: string[];
  correctAnswer?: string | string[];
  explanation?: string;
  difficulty: 'easy' | 'medium' | 'hard';
  points: number;
}

interface Test {
  id: string;
  title: string;
  subject: string;
  questions: Question[];
  timeLimit?: number; // in minutes
  createdAt: Date;
}

interface Answer {
  questionId: string;
  value: string | string[];
}

interface TestResult {
  testId: string;
  answers: Answer[];
  score: number;
  totalPoints: number;
  timeSpent: number; // in seconds
  completedAt: Date;
  feedback: {
    correctAnswers: number;
    incorrectAnswers: number;
    strengths: string[];
    improvementAreas: string[];
    recommendations: string[];
  };
}

const subjects = [
  { value: 'math', label: 'الرياضيات' },
  { value: 'science', label: 'العلوم' },
  { value: 'history', label: 'التاريخ' },
  { value: 'arabic', label: 'اللغة العربية' },
  { value: 'english', label: 'اللغة الإنجليزية' },
  { value: 'physics', label: 'الفيزياء' },
  { value: 'chemistry', label: 'الكيمياء' },
  { value: 'biology', label: 'الأحياء' },
  { value: 'computer', label: 'علوم الحاسب' },
];

const difficultyLevels = [
  { value: 'easy', label: 'سهل' },
  { value: 'medium', label: 'متوسط' },
  { value: 'hard', label: 'صعب' },
  { value: 'mixed', label: 'مختلط' },
];

const questionTypes = [
  { value: 'multiple-choice', label: 'اختيار من متعدد' },
  { value: 'true-false', label: 'صح/خطأ' },
  { value: 'short-answer', label: 'إجابة قصيرة' },
  { value: 'essay', label: 'مقال' },
];

export default function TestPage() {
  const [testConfig, setTestConfig] = useState({
    subject: '',
    difficulty: 'mixed' as 'easy' | 'medium' | 'hard' | 'mixed',
    questionCount: 10,
    questionTypes: ['multiple-choice'] as string[],
    timeLimit: 30,
  });

  const [test, setTest] = useState<Test | null>(null);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [answers, setAnswers] = useState<Answer[]>([]);
  const [testState, setTestState] = useState<'config' | 'loading' | 'in-progress' | 'completed'>('config');
  const [timeRemaining, setTimeRemaining] = useState(0);
  const [testResult, setTestResult] = useState<TestResult | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generationProgress, setGenerationProgress] = useState(0);

  // Handle timer
  useEffect(() => {
    let timer: NodeJS.Timeout;
    if (testState === 'in-progress' && timeRemaining > 0) {
      timer = setTimeout(() => {
        setTimeRemaining(timeRemaining - 1);
      }, 1000);
    } else if (testState === 'in-progress' && timeRemaining === 0) {
      handleSubmitTest();
    }
    return () => clearTimeout(timer);
  }, [testState, timeRemaining]);

  const handleGenerateTest = async () => {
    setIsGenerating(true);
    setTestState('loading');
    setGenerationProgress(0);

    // Simulate progress
    const progressInterval = setInterval(() => {
      setGenerationProgress(prev => {
        if (prev >= 90) {
          clearInterval(progressInterval);
          return 90;
        }
        return prev + 10;
      });
    }, 300);

    try {
      // API call to generate test with AI
      const response = await fetch('/api/generate-test', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(testConfig),
      });

      if (!response.ok) {
        throw new Error('Failed to generate test');
      }

      const data = await response.json();
      const newTest = data.test as Test;

      setTest(newTest);
      setAnswers([]);
      setCurrentQuestionIndex(0);
      setTimeRemaining(newTest.timeLimit! * 60);
      setTestState('in-progress');
      setGenerationProgress(100);
    } catch (error) {
      logger.error('Error generating test:', error);
      alert('حدث خطأ أثناء إنشاء الاختبار. يرجى المحاولة مرة أخرى.');
    } finally {
      setIsGenerating(false);
      clearInterval(progressInterval);
    }
  };

  const handleAnswerChange = (questionId: string, value: string | string[]) => {
    setAnswers(prev => {
      const existingAnswerIndex = prev.findIndex(a => a.questionId === questionId);
      if (existingAnswerIndex !== -1) {
        const newAnswers = [...prev];
        newAnswers[existingAnswerIndex] = { questionId, value };
        return newAnswers;
      } else {
        return [...prev, { questionId, value }];
      }
    });
  };

  const handleNextQuestion = () => {
    if (test && currentQuestionIndex < test.questions.length - 1) {
      setCurrentQuestionIndex(currentQuestionIndex + 1);
    }
  };

  const handlePrevQuestion = () => {
    if (currentQuestionIndex > 0) {
      setCurrentQuestionIndex(currentQuestionIndex - 1);
    }
  };

  const handleSubmitTest = async () => {
    if (!test) return;

    // Simulate progress
    setIsGenerating(true);
    setTestState('loading');
    setGenerationProgress(0);

    const progressInterval = setInterval(() => {
      setGenerationProgress(prev => {
        if (prev >= 90) {
          clearInterval(progressInterval);
          return 90;
        }
        return prev + 20;
      });
    }, 500);

    try {
      // API call to evaluate test with AI
      const response = await fetch('/api/evaluate-test', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          testId: test.id,
          answers,
          questions: test.questions,
          timeSpent: test.timeLimit! * 60 - timeRemaining
        }),
      });

      if (!response.ok) {
        throw new Error('Failed to evaluate test');
      }

      const data = await response.json();
      const result = data.result as TestResult;

      setTestResult(result);
      setTestState('completed');
      setGenerationProgress(100);
    } catch (error) {
      logger.error('Error evaluating test:', error);
      alert('حدث خطأ أثناء تقييم الاختبار. يرجى المحاولة مرة أخرى.');
    } finally {
      setIsGenerating(false);
      clearInterval(progressInterval);
    }
  };

  const handleRestartTest = () => {
    setTestState('config');
    setTest(null);
    setTestResult(null);
    setAnswers([]);
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const getScoreColor = (score: number, total: number) => {
    const percentage = (score / total) * 100;
    if (percentage >= 80) return 'text-green-600';
    if (percentage >= 60) return 'text-yellow-600';
    return 'text-red-600';
  };

  if (testState === 'config') {
    return (
      <div className="container mx-auto py-8 px-4 max-w-4xl">
        <div className="text-center mb-10">
          <h1 className="text-3xl font-bold mb-4 flex items-center justify-center gap-2">
            <Brain className="h-8 w-8 text-blue-600" />
            الاختبار الذاتي الذكي
          </h1>
          <p className="text-gray-600">
            قم بإنشاء اختبار مخصص باستخدام الذكاء الاصطناعي واختبر معرفتك في المادة التي تختارها
          </p>
        </div>

        <Card className="mb-8">
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <BookOpen className="h-5 w-5" />
              إعدادات الاختبار
            </CardTitle>
            <CardDescription>
              قم بتحديد إعدادات الاختبار الذي تريد إنشاءه
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-6">
            <div className="space-y-2">
              <Label htmlFor="subject">المادة الدراسية</Label>
              <Select value={testConfig.subject} onValueChange={(value) => setTestConfig({...testConfig, subject: value})}>
                <SelectTrigger>
                  <SelectValue placeholder="اختر المادة الدراسية" />
                </SelectTrigger>
                <SelectContent>
                  {subjects.map(subject => (
                    <SelectItem key={subject.value} value={subject.value}>{subject.label}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2">
              <Label htmlFor="difficulty">مستوى الصعوبة</Label>
              <Select value={testConfig.difficulty} onValueChange={(value) => setTestConfig({...testConfig, difficulty: value as any})}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {difficultyLevels.map(level => (
                    <SelectItem key={level.value} value={level.value}>{level.label}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2">
              <Label htmlFor="questionCount">عدد الأسئلة: {testConfig.questionCount}</Label>
              <Input 
                id="questionCount"
                type="range" 
                min="5" 
                max="30" 
                value={testConfig.questionCount} 
                onChange={(e) => setTestConfig({...testConfig, questionCount: parseInt(e.target.value)})}
              />
            </div>

            <div className="space-y-2">
              <Label>أنواع الأسئلة</Label>
              <div className="grid grid-cols-2 gap-2">
                {questionTypes.map(type => (
                  <div key={type.value} className="flex items-center space-x-2">
                    <Checkbox 
                      id={type.value}
                      checked={testConfig.questionTypes.includes(type.value)}
                      onCheckedChange={(checked) => {
                        if (checked) {
                          setTestConfig({
                            ...testConfig, 
                            questionTypes: [...testConfig.questionTypes, type.value]
                          });
                        } else {
                          setTestConfig({
                            ...testConfig, 
                            questionTypes: testConfig.questionTypes.filter(t => t !== type.value)
                          });
                        }
                      }}
                    />
                    <Label htmlFor={type.value}>{type.label}</Label>
                  </div>
                ))}
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="timeLimit">المدة الزمنية (بالدقائق): {testConfig.timeLimit}</Label>
              <Input 
                id="timeLimit"
                type="range" 
                min="10" 
                max="120" 
                step="5"
                value={testConfig.timeLimit} 
                onChange={(e) => setTestConfig({...testConfig, timeLimit: parseInt(e.target.value)})}
              />
            </div>
          </CardContent>
          <CardFooter>
            <Button 
              onClick={handleGenerateTest} 
              className="w-full" 
              disabled={!testConfig.subject || isGenerating}
            >
              {isGenerating ? 'جاري إنشاء الاختبار...' : 'إنشاء الاختبار'}
            </Button>
          </CardFooter>
        </Card>
      </div>
    );
  }

  if (testState === 'loading') {
    return (
      <div className="container mx-auto py-8 px-4 max-w-4xl">
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Brain className="h-5 w-5" />
              {test ? 'جاري تقييم إجاباتك...' : 'جاري إنشاء الاختبار...'}
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <Progress value={generationProgress} className="w-full" />
            <p className="text-center text-gray-600">
              {test ? 'يقوم الذكاء الاصطناعي بتحليل إجاباتك وتقديم تقييم دقيق...' : 'يقوم الذكاء الاصطناعي بإنشاء اختبار مخصص لك...'}
            </p>
          </CardContent>
        </Card>
      </div>
    );
  }

  if (testState === 'in-progress' && test) {
    const currentQuestion = test.questions[currentQuestionIndex];
    const currentAnswer = answers.find(a => a.questionId === currentQuestion.id)?.value || '';
    const progress = ((currentQuestionIndex + 1) / test.questions.length) * 100;

    return (
      <div className="container mx-auto py-8 px-4 max-w-4xl">
        <div className="mb-6 flex justify-between items-center">
          <div>
            <h1 className="text-2xl font-bold">{test.title}</h1>
            <p className="text-gray-600">السؤال {currentQuestionIndex + 1} من {test.questions.length}</p>
          </div>
          <div className="flex items-center gap-2 bg-blue-50 px-3 py-2 rounded-lg">
            <Clock className="h-5 w-5 text-blue-600" />
            <span className="font-medium">{formatTime(timeRemaining)}</span>
          </div>
        </div>

        <Progress value={progress} className="mb-8" />

        <Card className="mb-8">
          <CardHeader>
            <div className="flex justify-between items-start">
              <div>
                <CardTitle className="text-xl">{currentQuestion.text}</CardTitle>
                <div className="flex gap-2 mt-2">
                  <Badge variant={
                    currentQuestion.difficulty === 'easy' ? 'default' : 
                    currentQuestion.difficulty === 'medium' ? 'secondary' : 'destructive'
                  }>
                    {currentQuestion.difficulty === 'easy' ? 'سهل' : 
                     currentQuestion.difficulty === 'medium' ? 'متوسط' : 'صعب'}
                  </Badge>
                  <Badge variant="outline">{currentQuestion.points} نقطة</Badge>
                </div>
              </div>
            </div>
          </CardHeader>
          <CardContent className="space-y-4">
            {currentQuestion.type === 'multiple-choice' && currentQuestion.options && (
              <RadioGroup 
                value={currentAnswer as string} 
                onValueChange={(value) => handleAnswerChange(currentQuestion.id, value)}
              >
                {currentQuestion.options.map((option, index) => (
                  <div key={index} className="flex items-center space-x-2">
                    <RadioGroupItem value={option} id={`option-${index}`} />
                    <Label htmlFor={`option-${index}`}>{option}</Label>
                  </div>
                ))}
              </RadioGroup>
            )}

            {currentQuestion.type === 'true-false' && (
              <RadioGroup 
                value={currentAnswer as string} 
                onValueChange={(value) => handleAnswerChange(currentQuestion.id, value)}
              >
                <div className="flex items-center space-x-2">
                  <RadioGroupItem value="true" id="true" />
                  <Label htmlFor="true">صحيح</Label>
                </div>
                <div className="flex items-center space-x-2">
                  <RadioGroupItem value="false" id="false" />
                  <Label htmlFor="false">خطأ</Label>
                </div>
              </RadioGroup>
            )}

            {currentQuestion.type === 'short-answer' && (
              <Textarea 
                value={currentAnswer as string}
                onChange={(e) => handleAnswerChange(currentQuestion.id, e.target.value)}
                placeholder="اكتب إجابتك هنا..."
                rows={3}
              />
            )}

            {currentQuestion.type === 'essay' && (
              <Textarea 
                value={currentAnswer as string}
                onChange={(e) => handleAnswerChange(currentQuestion.id, e.target.value)}
                placeholder="اكتب مقالك هنا..."
                rows={6}
              />
            )}
          </CardContent>
          <CardFooter className="flex justify-between">
            <Button 
              variant="outline" 
              onClick={handlePrevQuestion}
              disabled={currentQuestionIndex === 0}
            >
              السؤال السابق
            </Button>
            <div className="flex gap-2">
              {currentQuestionIndex === test.questions.length - 1 ? (
                <Button onClick={handleSubmitTest}>
                  إنهاء الاختبار
                </Button>
              ) : (
                <Button onClick={handleNextQuestion}>
                  السؤال التالي
                </Button>
              )}
            </div>
          </CardFooter>
        </Card>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
          <Card>
            <CardContent className="pt-6">
              <div className="flex items-center gap-2">
                <CheckCircle className="h-5 w-5 text-green-500" />
                <span>تمت الإجابة: {answers.length}</span>
              </div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="pt-6">
              <div className="flex items-center gap-2">
                <AlertCircle className="h-5 w-5 text-yellow-500" />
                <span>متبقي: {test.questions.length - answers.length}</span>
              </div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="pt-6">
              <div className="flex items-center gap-2">
                <Award className="h-5 w-5 text-blue-500" />
                <span>الدرجة الكلية: {test.questions.reduce((sum, q) => sum + q.points, 0)}</span>
              </div>
            </CardContent>
          </Card>
        </div>
      </div>
    );
  }

  if (testState === 'completed' && testResult && test) {
    const percentage = Math.round((testResult.score / testResult.totalPoints) * 100);

    return (
      <div className="container mx-auto py-8 px-4 max-w-4xl">
        <div className="text-center mb-10">
          <h1 className="text-3xl font-bold mb-4 flex items-center justify-center gap-2">
            <Award className="h-8 w-8 text-yellow-500" />
            نتائج الاختبار
          </h1>
          <p className="text-gray-600">
            لقد أكملت الاختبار بنجاح! إليك تقييم أدائك
          </p>
        </div>

        <Card className="mb-8">
          <CardHeader>
            <CardTitle>النتيجة الإجمالية</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="flex flex-col items-center justify-center space-y-4">
              <div className={`text-5xl font-bold ${getScoreColor(testResult.score, testResult.totalPoints)}`}>
                {percentage}%
              </div>
              <div className="text-xl">
                {testResult.score} من {testResult.totalPoints} نقطة
              </div>
              <div className="text-gray-600">
                وقت الاختبار: {formatTime(testResult.timeSpent)}
              </div>
            </div>
          </CardContent>
        </Card>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <CheckCircle className="h-5 w-5 text-green-500" />
                الإجابات الصحيحة
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-3xl font-bold text-green-600 text-center">
                {testResult.feedback.correctAnswers}
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <AlertCircle className="h-5 w-5 text-red-500" />
                الإجابات الخاطئة
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-3xl font-bold text-red-600 text-center">
                {testResult.feedback.incorrectAnswers}
              </div>
            </CardContent>
          </Card>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Lightbulb className="h-5 w-5 text-yellow-500" />
                نقاط القوة
              </CardTitle>
            </CardHeader>
            <CardContent>
              <ul className="space-y-2">
                {testResult.feedback.strengths.map((strength, index) => (
                  <li key={index} className="flex items-start gap-2">
                    <CheckCircle className="h-4 w-4 text-green-500 mt-0.5 flex-shrink-0" />
                    <span>{strength}</span>
                  </li>
                ))}
              </ul>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <AlertCircle className="h-5 w-5 text-blue-500" />
                مجالات التحسين
              </CardTitle>
            </CardHeader>
            <CardContent>
              <ul className="space-y-2">
                {testResult.feedback.improvementAreas.map((area, index) => (
                  <li key={index} className="flex items-start gap-2">
                    <AlertCircle className="h-4 w-4 text-blue-500 mt-0.5 flex-shrink-0" />
                    <span>{area}</span>
                  </li>
                ))}
              </ul>
            </CardContent>
          </Card>
        </div>

        <Card className="mb-8">
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <BookOpen className="h-5 w-5 text-purple-500" />
              توصيات للدراسة
            </CardTitle>
          </CardHeader>
          <CardContent>
            <ul className="space-y-3">
              {testResult.feedback.recommendations.map((recommendation, index) => (
                <li key={index} className="flex items-start gap-2 p-3 bg-purple-50 rounded-lg">
                  <span className="font-bold text-purple-700">{index + 1}.</span>
                  <span>{recommendation}</span>
                </li>
              ))}
            </ul>
          </CardContent>
        </Card>

        <div className="flex justify-center">
          <Button onClick={handleRestartTest} size="lg">
            إنشاء اختبار جديد
          </Button>
        </div>
      </div>
    );
  }

  return null;
}

"use client";

import { useEffect, useState, useMemo } from "react";
import { useParams, useRouter } from "next/navigation";
import Link from "next/link";
import { motion, AnimatePresence } from "framer-motion";
import { AuthGuard } from "@/components/auth/AuthGuard";
import { ensureUser } from "@/lib/user-utils";
import { logger } from "@/lib/logger";
import {
  BookOpen,
  Clock,
  Users,
  Star,
  ChevronRight,
  ChevronLeft,
  PlayCircle,
  CheckCircle2,
  Lock,
  GraduationCap,
  Award,
  FileText,
  Share2,
  Bookmark,
  BookmarkCheck,
  AlertCircle,
  Loader2
} from "lucide-react";

type Course = {
  id: string;
  title: string;
  description: string;
  instructor: string;
  subject: string;
  level: "BEGINNER" | "INTERMEDIATE" | "ADVANCED";
  duration: number;
  thumbnailUrl?: string;
  price: number;
  rating: number;
  enrolledCount: number;
  createdAt: string;
  tags: string[];
  enrolled: boolean;
  progress?: number;
};

type CourseLesson = {
  id: string;
  title: string;
  description?: string;
  content?: string;
  videoUrl?: string;
  duration: number;
  order: number;
  completed: boolean;
  progress: number;
};

const levelConfig = {
  BEGINNER: { label: "مبتدئ", color: "text-emerald-600 bg-emerald-100 dark:bg-emerald-900/30" },
  INTERMEDIATE: { label: "متوسط", color: "text-amber-600 bg-amber-100 dark:bg-amber-900/30" },
  ADVANCED: { label: "متقدم", color: "text-rose-600 bg-rose-100 dark:bg-rose-900/30" }
};

export default function CourseDetailPage() {
  const params = useParams();
  const router = useRouter();
  const courseId = params.id as string;

  const [userId, setUserId] = useState<string | null>(null);
  const [course, setCourse] = useState<Course | null>(null);
  const [lessons, setLessons] = useState<CourseLesson[]>([]);
  const [loading, setLoading] = useState(true);
  const [activeLesson, setActiveLesson] = useState<string | null>(null);
  const [enrolling, setEnrolling] = useState(false);
  const [bookmarked, setBookmarked] = useState(false);

  useEffect(() => {
    ensureUser().then(setUserId);
  }, []);

  useEffect(() => {
    if (!courseId) return;

    const fetchCourse = async () => {
      try {
        const res = await fetch(`/api/courses/${courseId}${userId ? `?userId=${userId}` : ""}`);
        if (res.ok) {
          const courseData = await res.json();
          setCourse(courseData);
        } else {
          router.push("/courses");
        }
      } catch (error) {
        logger.error("Error fetching course:", error);
        router.push("/courses");
      }
    };

    const fetchLessons = async () => {
      try {
        const res = await fetch(`/api/courses/${courseId}/lessons${userId ? `?userId=${userId}` : ""}`);
        if (res.ok) {
          const lessonsData = await res.json();
          setLessons(lessonsData);
          if (lessonsData.length > 0) {
            setActiveLesson(lessonsData[0].id);
          }
        }
      } catch (error) {
        logger.error("Error fetching lessons:", error);
      }
    };

    const loadData = async () => {
      setLoading(true);
      await Promise.all([fetchCourse(), fetchLessons()]);
      setLoading(false);
    };

    loadData();
  }, [courseId, userId, router]);

  const handleEnroll = async () => {
    if (!userId || !courseId) return;
    setEnrolling(true);

    try {
      const res = await fetch(`/api/courses/${courseId}/enroll`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ userId })
      });

      if (res.ok) {
        if (course) {
          setCourse({ ...course, enrolled: true, progress: 0 });
        }
      } else {
        alert("حدث خطأ أثناء التسجيل في الدورة");
      }
    } catch (error) {
      logger.error("Error enrolling in course:", error);
      alert("حدث خطأ أثناء التسجيل في الدورة");
    } finally {
      setEnrolling(false);
    }
  };

  const handleUnenroll = async () => {
    if (!userId || !courseId) return;
    setEnrolling(true);

    try {
      const res = await fetch(`/api/courses/${courseId}/enroll`, {
        method: "DELETE",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ userId })
      });

      if (res.ok) {
        if (course) {
          setCourse({ ...course, enrolled: false });
        }
      } else {
        alert("حدث خطأ أثناء إلغاء التسجيل من الدورة");
      }
    } catch (error) {
      logger.error("Error unenrolling from course:", error);
      alert("حدث خطأ أثناء إلغاء التسجيل من الدورة");
    } finally {
      setEnrolling(false);
    }
  };

  const handleLessonComplete = async (lessonId: string) => {
    if (!userId) return;

    try {
      const res = await fetch(`/api/courses/lessons/${lessonId}/progress`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ userId, completed: true, progress: 100 })
      });

      if (res.ok) {
        setLessons(lessons.map(lesson =>
          lesson.id === lessonId ? { ...lesson, completed: true, progress: 100 } : lesson
        ));

        if (course) {
          const completedLessons = lessons.filter(l => l.id === lessonId || l.completed).length;
          const newProgress = Math.round((completedLessons / lessons.length) * 100);
          setCourse({ ...course, progress: newProgress });
        }
      } else {
        alert("حدث خطأ أثناء تحديث تقدم الدرس");
      }
    } catch (error) {
      logger.error("Error updating lesson progress:", error);
      alert("حدث خطأ أثناء تحديث تقدم الدرس");
    }
  };

  const activeLessonData = useMemo(() => {
    return lessons.find(l => l.id === activeLesson);
  }, [lessons, activeLesson]);

  const completedLessonsCount = useMemo(() => {
    return lessons.filter(l => l.completed).length;
  }, [lessons]);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-b from-slate-50 to-white dark:from-slate-900 dark:to-slate-800">
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          className="text-center"
        >
          <motion.div
            animate={{ rotate: 360 }}
            transition={{ duration: 1, repeat: Infinity, ease: "linear" }}
            className="mx-auto mb-4"
          >
            <div className="h-16 w-16 rounded-full border-4 border-slate-200 dark:border-slate-700 relative">
              <div className="absolute inset-0 h-16 w-16 rounded-full border-4 border-transparent border-t-blue-500" />
            </div>
          </motion.div>
          <p className="text-slate-500 dark:text-slate-400">جاري تحميل الدورة...</p>
        </motion.div>
      </div>
    );
  }

  if (!course) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-b from-slate-50 to-white dark:from-slate-900 dark:to-slate-800">
        <div className="text-center">
          <AlertCircle className="h-16 w-16 mx-auto mb-4 text-slate-400" />
          <h2 className="text-xl font-bold text-slate-900 dark:text-white mb-2">الدورة غير موجودة</h2>
          <p className="text-slate-500 dark:text-slate-400 mb-4">لم نتمكن من العثور على الدورة المطلوبة</p>
          <Link href="/courses" className="text-blue-500 hover:underline">العودة إلى الدورات</Link>
        </div>
      </div>
    );
  }

  const levelInfo = levelConfig[course.level];

  return (
    <AuthGuard>
      <div className="min-h-screen bg-gradient-to-b from-slate-50 via-white to-slate-50 dark:from-slate-900 dark:via-slate-900 dark:to-slate-800">
        <div className="px-4 md:px-6 lg:px-8">
          <section className="mx-auto max-w-7xl py-8 space-y-6">
            {/* Breadcrumb */}
            <motion.nav
              initial={{ opacity: 0, y: -10 }}
              animate={{ opacity: 1, y: 0 }}
              className="flex items-center gap-2 text-sm text-slate-500 dark:text-slate-400"
            >
              <Link href="/courses" className="hover:text-blue-500 transition-colors">
                الدورات التعليمية
              </Link>
              <ChevronLeft className="h-4 w-4" />
              <span className="text-slate-900 dark:text-white font-medium truncate max-w-xs">
                {course.title}
              </span>
            </motion.nav>

            {/* Course Header */}
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.1 }}
              className="rounded-3xl overflow-hidden border border-slate-200 dark:border-slate-700 bg-white/90 dark:bg-slate-800/90 backdrop-blur-xl shadow-xl"
            >
              <div className="lg:flex">
                {/* Thumbnail */}
                <div className="lg:w-2/5 relative">
                  <div className="aspect-video lg:aspect-auto lg:h-full bg-gradient-to-br from-blue-500/20 via-purple-500/20 to-pink-500/20">
                    {course.thumbnailUrl ? (
                      <img
                        src={course.thumbnailUrl}
                        alt={course.title}
                        className="w-full h-full object-cover"
                      />
                    ) : (
                      <div className="w-full h-full min-h-[250px] flex items-center justify-center">
                        <motion.div
                          animate={{ 
                            rotate: [0, 10, -10, 0],
                            scale: [1, 1.1, 1]
                          }}
                          transition={{ duration: 4, repeat: Infinity }}
                        >
                          <GraduationCap className="h-24 w-24 text-blue-400/60" />
                        </motion.div>
                      </div>
                    )}
                  </div>

                  {/* Overlay badges */}
                  <div className="absolute top-4 right-4 flex gap-2">
                    <span className="px-3 py-1.5 rounded-full bg-white/90 dark:bg-slate-800/90 backdrop-blur-sm text-sm font-medium text-slate-700 dark:text-slate-200 shadow-lg">
                      {course.subject}
                    </span>
                  </div>
                  <div className="absolute top-4 left-4">
                    <span className={`px-3 py-1.5 rounded-full text-sm font-medium ${levelInfo.color}`}>
                      {levelInfo.label}
                    </span>
                  </div>
                </div>

                {/* Content */}
                <div className="lg:w-3/5 p-6 lg:p-8">
                  <h1 className="text-2xl lg:text-3xl font-bold text-slate-900 dark:text-white mb-4">
                    {course.title}
                  </h1>

                  <p className="text-slate-600 dark:text-slate-300 mb-6 leading-relaxed">
                    {course.description}
                  </p>

                  {/* Instructor */}
                  <div className="flex items-center gap-3 mb-6">
                    <div className="h-12 w-12 rounded-full bg-gradient-to-br from-blue-400 to-purple-500 flex items-center justify-center text-white font-bold text-lg">
                      {course.instructor.charAt(0)}
                    </div>
                    <div>
                      <p className="text-sm text-slate-500 dark:text-slate-400">المدرب</p>
                      <p className="font-semibold text-slate-900 dark:text-white">{course.instructor}</p>
                    </div>
                  </div>

                  {/* Stats */}
                  <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">
                    <div className="flex items-center gap-2">
                      <div className="h-10 w-10 rounded-xl bg-amber-100 dark:bg-amber-900/30 flex items-center justify-center">
                        <Star className="h-5 w-5 text-amber-500" />
                      </div>
                      <div>
                        <p className="text-lg font-bold text-slate-900 dark:text-white">{course.rating.toFixed(1)}</p>
                        <p className="text-xs text-slate-500">التقييم</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-2">
                      <div className="h-10 w-10 rounded-xl bg-blue-100 dark:bg-blue-900/30 flex items-center justify-center">
                        <Users className="h-5 w-5 text-blue-500" />
                      </div>
                      <div>
                        <p className="text-lg font-bold text-slate-900 dark:text-white">{course.enrolledCount}</p>
                        <p className="text-xs text-slate-500">طالب</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-2">
                      <div className="h-10 w-10 rounded-xl bg-purple-100 dark:bg-purple-900/30 flex items-center justify-center">
                        <Clock className="h-5 w-5 text-purple-500" />
                      </div>
                      <div>
                        <p className="text-lg font-bold text-slate-900 dark:text-white">{course.duration}</p>
                        <p className="text-xs text-slate-500">ساعة</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-2">
                      <div className="h-10 w-10 rounded-xl bg-emerald-100 dark:bg-emerald-900/30 flex items-center justify-center">
                        <BookOpen className="h-5 w-5 text-emerald-500" />
                      </div>
                      <div>
                        <p className="text-lg font-bold text-slate-900 dark:text-white">{lessons.length}</p>
                        <p className="text-xs text-slate-500">درس</p>
                      </div>
                    </div>
                  </div>

                  {/* Progress (for enrolled) */}
                  {course.enrolled && course.progress !== undefined && (
                    <div className="mb-6 p-4 rounded-2xl bg-gradient-to-r from-blue-50 to-purple-50 dark:from-blue-900/20 dark:to-purple-900/20 border border-blue-100 dark:border-blue-800/30">
                      <div className="flex justify-between items-center mb-2">
                        <span className="text-sm font-medium text-slate-700 dark:text-slate-300">تقدمك في الدورة</span>
                        <span className="text-lg font-bold text-blue-600">{course.progress}%</span>
                      </div>
                      <div className="h-3 bg-white dark:bg-slate-700 rounded-full overflow-hidden">
                        <motion.div
                          initial={{ width: 0 }}
                          animate={{ width: `${course.progress}%` }}
                          transition={{ duration: 1, delay: 0.5 }}
                          className="h-full bg-gradient-to-r from-blue-500 to-purple-500 rounded-full"
                        />
                      </div>
                      <p className="text-xs text-slate-500 mt-2">
                        {completedLessonsCount} من {lessons.length} درس مكتمل
                      </p>
                    </div>
                  )}

                  {/* Tags */}
                  <div className="flex flex-wrap gap-2 mb-6">
                    {course.tags.map((tag, index) => (
                      <span
                        key={index}
                        className="px-3 py-1 rounded-full bg-slate-100 dark:bg-slate-700 text-sm text-slate-600 dark:text-slate-300"
                      >
                        {tag}
                      </span>
                    ))}
                  </div>

                  {/* Actions */}
                  <div className="flex flex-wrap items-center gap-3">
                    {course.enrolled ? (
                      <>
                        <motion.button
                          whileHover={{ scale: 1.02 }}
                          whileTap={{ scale: 0.98 }}
                          onClick={handleUnenroll}
                          disabled={enrolling}
                          className="px-6 py-3 rounded-xl border border-rose-300 text-rose-600 font-medium hover:bg-rose-50 dark:hover:bg-rose-900/20 transition-colors disabled:opacity-50"
                        >
                          {enrolling ? <Loader2 className="h-5 w-5 animate-spin" /> : "إلغاء التسجيل"}
                        </motion.button>
                      </>
                    ) : (
                      <motion.button
                        whileHover={{ scale: 1.02 }}
                        whileTap={{ scale: 0.98 }}
                        onClick={handleEnroll}
                        disabled={enrolling}
                        className="px-8 py-3 rounded-xl bg-gradient-to-r from-blue-500 to-purple-500 text-white font-medium shadow-lg shadow-blue-500/25 hover:shadow-xl hover:shadow-blue-500/30 transition-all disabled:opacity-50"
                      >
                        {enrolling ? (
                          <Loader2 className="h-5 w-5 animate-spin" />
                        ) : course.price > 0 ? (
                          `سجل الآن - ${course.price} ريال`
                        ) : (
                          "سجل مجاناً"
                        )}
                      </motion.button>
                    )}
                    
                    <motion.button
                      whileHover={{ scale: 1.1 }}
                      whileTap={{ scale: 0.9 }}
                      onClick={() => setBookmarked(!bookmarked)}
                      className={`p-3 rounded-xl border transition-colors ${
                        bookmarked
                          ? "border-blue-300 bg-blue-50 dark:bg-blue-900/20 text-blue-500"
                          : "border-slate-200 dark:border-slate-700 text-slate-500 hover:border-blue-300"
                      }`}
                    >
                      {bookmarked ? <BookmarkCheck className="h-5 w-5" /> : <Bookmark className="h-5 w-5" />}
                    </motion.button>
                    
                    <motion.button
                      whileHover={{ scale: 1.1 }}
                      whileTap={{ scale: 0.9 }}
                      className="p-3 rounded-xl border border-slate-200 dark:border-slate-700 text-slate-500 hover:border-blue-300 transition-colors"
                    >
                      <Share2 className="h-5 w-5" />
                    </motion.button>
                  </div>
                </div>
              </div>
            </motion.div>

            {/* Course Content */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              {/* Lessons List */}
              <motion.div
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.2 }}
                className="lg:col-span-1"
              >
                <div className="rounded-2xl border border-slate-200 dark:border-slate-700 bg-white/90 dark:bg-slate-800/90 backdrop-blur-xl overflow-hidden sticky top-4">
                  <div className="p-4 border-b border-slate-100 dark:border-slate-700">
                    <h2 className="font-bold text-lg text-slate-900 dark:text-white flex items-center gap-2">
                      <FileText className="h-5 w-5 text-blue-500" />
                      محتوى الدورة
                    </h2>
                    <p className="text-sm text-slate-500 mt-1">
                      {lessons.length} درس • {completedLessonsCount} مكتمل
                    </p>
                  </div>
                  
                  <div className="max-h-[500px] overflow-y-auto">
                    <ul className="divide-y divide-slate-100 dark:divide-slate-700">
                      {lessons.map((lesson, index) => (
                        <li key={lesson.id}>
                          <motion.button
                            whileHover={{ backgroundColor: "rgba(59, 130, 246, 0.05)" }}
                            className={`w-full text-right p-4 transition-all ${
                              activeLesson === lesson.id
                                ? "bg-blue-50 dark:bg-blue-900/30 border-r-4 border-blue-500"
                                : ""
                            }`}
                            onClick={() => setActiveLesson(lesson.id)}
                          >
                            <div className="flex items-start gap-3">
                              <div className={`flex-shrink-0 h-8 w-8 rounded-full flex items-center justify-center text-sm font-bold ${
                                lesson.completed
                                  ? "bg-emerald-100 dark:bg-emerald-900/30 text-emerald-600"
                                  : activeLesson === lesson.id
                                  ? "bg-blue-500 text-white"
                                  : "bg-slate-100 dark:bg-slate-700 text-slate-500"
                              }`}>
                                {lesson.completed ? (
                                  <CheckCircle2 className="h-4 w-4" />
                                ) : (
                                  index + 1
                                )}
                              </div>
                              <div className="flex-grow">
                                <p className={`font-medium text-sm ${
                                  activeLesson === lesson.id
                                    ? "text-blue-600 dark:text-blue-400"
                                    : "text-slate-900 dark:text-white"
                                }`}>
                                  {lesson.title}
                                </p>
                                {lesson.description && (
                                  <p className="text-xs text-slate-500 mt-0.5 line-clamp-1">
                                    {lesson.description}
                                  </p>
                                )}
                                <div className="flex items-center gap-2 mt-1">
                                  <span className="text-xs text-slate-400">
                                    {Math.floor(lesson.duration / 60)}:{String(lesson.duration % 60).padStart(2, "0")}
                                  </span>
                                  {!course.enrolled && lesson.videoUrl && (
                                    <Lock className="h-3 w-3 text-slate-400" />
                                  )}
                                </div>
                              </div>
                            </div>
                          </motion.button>
                        </li>
                      ))}
                    </ul>
                  </div>
                </div>
              </motion.div>

              {/* Lesson Content */}
              <motion.div
                initial={{ opacity: 0, x: 20 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.3 }}
                className="lg:col-span-2"
              >
                <AnimatePresence mode="wait">
                  {activeLessonData ? (
                    <motion.div
                      key={activeLessonData.id}
                      initial={{ opacity: 0, y: 20 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0, y: -20 }}
                      className="rounded-2xl border border-slate-200 dark:border-slate-700 bg-white/90 dark:bg-slate-800/90 backdrop-blur-xl overflow-hidden"
                    >
                      {/* Lesson header */}
                      <div className="p-6 border-b border-slate-100 dark:border-slate-700">
                        <div className="flex items-center justify-between mb-2">
                          <h2 className="text-xl font-bold text-slate-900 dark:text-white">
                            {activeLessonData.title}
                          </h2>
                          <span className="text-sm text-slate-500 flex items-center gap-1">
                            <Clock className="h-4 w-4" />
                            {Math.floor(activeLessonData.duration / 60)}:{String(activeLessonData.duration % 60).padStart(2, "0")}
                          </span>
                        </div>
                        {activeLessonData.description && (
                          <p className="text-slate-600 dark:text-slate-300">
                            {activeLessonData.description}
                          </p>
                        )}
                      </div>

                      {/* Video player area */}
                      {activeLessonData.videoUrl && course.enrolled ? (
                        <div className="aspect-video bg-slate-900 flex items-center justify-center">
                          <div className="text-center">
                            <motion.div
                              whileHover={{ scale: 1.1 }}
                              className="h-20 w-20 mx-auto mb-4 rounded-full bg-white/10 flex items-center justify-center cursor-pointer"
                            >
                              <PlayCircle className="h-12 w-12 text-white" />
                            </motion.div>
                            <p className="text-white/70 text-sm">اضغط للتشغيل</p>
                          </div>
                        </div>
                      ) : activeLessonData.videoUrl && !course.enrolled ? (
                        <div className="aspect-video bg-gradient-to-br from-slate-800 to-slate-900 flex items-center justify-center">
                          <div className="text-center p-8">
                            <Lock className="h-16 w-16 mx-auto mb-4 text-slate-500" />
                            <h3 className="text-xl font-bold text-white mb-2">محتوى محمي</h3>
                            <p className="text-slate-400 mb-6 max-w-md">
                              سجل في الدورة للوصول إلى جميع الدروس والفيديوهات
                            </p>
                            <motion.button
                              whileHover={{ scale: 1.05 }}
                              whileTap={{ scale: 0.95 }}
                              onClick={handleEnroll}
                              className="px-6 py-3 rounded-xl bg-gradient-to-r from-blue-500 to-purple-500 text-white font-medium shadow-lg"
                            >
                              {course.price > 0 ? `سجل الآن - ${course.price} ريال` : "سجل مجاناً"}
                            </motion.button>
                          </div>
                        </div>
                      ) : null}

                      {/* Lesson content */}
                      {activeLessonData.content && course.enrolled ? (
                        <div className="p-6">
                          <div 
                            className="prose prose-slate dark:prose-invert max-w-none"
                            dangerouslySetInnerHTML={{ __html: activeLessonData.content }}
                          />
                        </div>
                      ) : activeLessonData.content && !course.enrolled ? (
                        <div className="p-6">
                          <div className="p-8 rounded-xl bg-slate-50 dark:bg-slate-700/50 text-center">
                            <Lock className="h-8 w-8 mx-auto mb-3 text-slate-400" />
                            <p className="text-slate-500 dark:text-slate-400">
                              سجل في الدورة للوصول إلى المحتوى الكامل للدرس
                            </p>
                          </div>
                        </div>
                      ) : null}

                      {/* Lesson navigation */}
                      {course.enrolled && lessons.length > 0 && (
                        <div className="p-6 border-t border-slate-100 dark:border-slate-700 bg-slate-50 dark:bg-slate-800/50">
                          <div className="flex items-center justify-between">
                            <motion.button
                              whileHover={{ scale: 1.02 }}
                              whileTap={{ scale: 0.98 }}
                              onClick={() => {
                                const currentIndex = lessons.findIndex(l => l.id === activeLesson);
                                if (currentIndex > 0) {
                                  setActiveLesson(lessons[currentIndex - 1].id);
                                }
                              }}
                              disabled={lessons.findIndex(l => l.id === activeLesson) === 0}
                              className="flex items-center gap-2 px-4 py-2 rounded-xl border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-300 disabled:opacity-50 hover:border-blue-300 transition-colors"
                            >
                              <ChevronRight className="h-4 w-4" />
                              الدرس السابق
                            </motion.button>

                            {!activeLessonData.completed && (
                              <motion.button
                                whileHover={{ scale: 1.02 }}
                                whileTap={{ scale: 0.98 }}
                                onClick={() => handleLessonComplete(activeLessonData.id)}
                                className="flex items-center gap-2 px-5 py-2 rounded-xl bg-gradient-to-r from-emerald-500 to-teal-500 text-white font-medium shadow-lg shadow-emerald-500/25"
                              >
                                <CheckCircle2 className="h-4 w-4" />
                                تحديد كمكتمل
                              </motion.button>
                            )}

                            <motion.button
                              whileHover={{ scale: 1.02 }}
                              whileTap={{ scale: 0.98 }}
                              onClick={() => {
                                const currentIndex = lessons.findIndex(l => l.id === activeLesson);
                                if (currentIndex < lessons.length - 1) {
                                  setActiveLesson(lessons[currentIndex + 1].id);
                                }
                              }}
                              disabled={lessons.findIndex(l => l.id === activeLesson) === lessons.length - 1}
                              className="flex items-center gap-2 px-4 py-2 rounded-xl border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-300 disabled:opacity-50 hover:border-blue-300 transition-colors"
                            >
                              الدرس التالي
                              <ChevronLeft className="h-4 w-4" />
                            </motion.button>
                          </div>
                        </div>
                      )}
                    </motion.div>
                  ) : (
                    <motion.div
                      initial={{ opacity: 0 }}
                      animate={{ opacity: 1 }}
                      className="rounded-2xl border border-slate-200 dark:border-slate-700 bg-white/90 dark:bg-slate-800/90 backdrop-blur-xl p-12 text-center"
                    >
                      <BookOpen className="h-16 w-16 mx-auto mb-4 text-slate-300 dark:text-slate-600" />
                      <h3 className="text-lg font-bold text-slate-900 dark:text-white mb-2">
                        اختر درساً للمشاهدة
                      </h3>
                      <p className="text-slate-500 dark:text-slate-400">
                        اختر درساً من القائمة الجانبية لعرض محتواه
                      </p>
                    </motion.div>
                  )}
                </AnimatePresence>
              </motion.div>
            </div>
          </section>
        </div>
      </div>
    </AuthGuard>
  );
}

"use client";

import React from "react";
import { motion } from "framer-motion";
import Link from "next/link";
import { 
  Clock, 
  Users, 
  Star, 
  BookOpen, 
  PlayCircle,
  ChevronLeft,
  Bookmark,
  GraduationCap
} from "lucide-react";

export interface CourseCardProps {
  id: string;
  title: string;
  description: string;
  instructor: string;
  subject: string;
  level: "BEGINNER" | "INTERMEDIATE" | "ADVANCED";
  duration: number;
  thumbnailUrl?: string;
  price: number;
  rating: number;
  enrolledCount: number;
  tags: string[];
  enrolled: boolean;
  progress?: number;
  lessonsCount?: number;
  onEnroll?: () => void;
  onUnenroll?: () => void;
  featured?: boolean;
  index?: number;
}

const levelConfig = {
  BEGINNER: {
    label: "مبتدئ",
    color: "from-emerald-400 to-emerald-600",
    bg: "bg-emerald-500/10",
    text: "text-emerald-600 dark:text-emerald-400",
    border: "border-emerald-500/20"
  },
  INTERMEDIATE: {
    label: "متوسط",
    color: "from-amber-400 to-amber-600",
    bg: "bg-amber-500/10",
    text: "text-amber-600 dark:text-amber-400",
    border: "border-amber-500/20"
  },
  ADVANCED: {
    label: "متقدم",
    color: "from-rose-400 to-rose-600",
    bg: "bg-rose-500/10",
    text: "text-rose-600 dark:text-rose-400",
    border: "border-rose-500/20"
  }
};

export const CourseCard: React.FC<CourseCardProps> = ({
  id,
  title,
  description,
  instructor,
  subject,
  level,
  duration,
  thumbnailUrl,
  price,
  rating,
  enrolledCount,
  tags,
  enrolled,
  progress,
  lessonsCount,
  onEnroll,
  onUnenroll,
  featured = false,
  index = 0
}) => {
  const levelInfo = levelConfig[level];

  return (
    <motion.div
      initial={{ opacity: 0, y: 30 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ 
        delay: index * 0.1, 
        duration: 0.5,
        type: "spring",
        stiffness: 100
      }}
      whileHover={{ y: -8, scale: 1.02 }}
      className={`group relative flex flex-col rounded-3xl overflow-hidden border ${
        featured 
          ? "border-blue-300/50 shadow-xl shadow-blue-500/10" 
          : "border-slate-200/80 dark:border-slate-700/50"
      } bg-white/90 dark:bg-slate-800/90 backdrop-blur-xl transition-all duration-500 hover:shadow-2xl hover:border-blue-300/60`}
    >
      {/* Glowing effect on hover */}
      <div className="absolute inset-0 rounded-3xl bg-gradient-to-br from-blue-400/0 via-purple-400/0 to-pink-400/0 opacity-0 group-hover:opacity-10 transition-opacity duration-500" />
      
      {/* Featured badge */}
      {featured && (
        <div className="absolute top-4 right-4 z-20">
          <motion.div 
            initial={{ scale: 0 }}
            animate={{ scale: 1 }}
            className="flex items-center gap-1.5 px-3 py-1.5 rounded-full bg-gradient-to-r from-amber-400 to-orange-500 text-white text-xs font-bold shadow-lg"
          >
            <Star className="h-3 w-3 fill-current" />
            <span>مميز</span>
          </motion.div>
        </div>
      )}

      {/* Thumbnail */}
      <div className="relative h-48 overflow-hidden">
        {thumbnailUrl ? (
          <motion.img
            src={thumbnailUrl}
            alt={title}
            className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
          />
        ) : (
          <div className="w-full h-full bg-gradient-to-br from-blue-500/20 via-purple-500/20 to-pink-500/20 flex items-center justify-center">
            <motion.div
              animate={{ 
                rotate: [0, 10, -10, 0],
                scale: [1, 1.1, 1]
              }}
              transition={{ 
                duration: 4, 
                repeat: Infinity, 
                repeatType: "reverse" 
              }}
            >
              <GraduationCap className="h-20 w-20 text-blue-400/60" />
            </motion.div>
          </div>
        )}
        
        {/* Overlay gradient */}
        <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent" />
        
        {/* Subject badge */}
        <div className="absolute bottom-3 right-3">
          <span className="px-3 py-1.5 rounded-full bg-white/90 dark:bg-slate-800/90 backdrop-blur-sm text-xs font-medium text-slate-700 dark:text-slate-200 shadow-lg">
            {subject}
          </span>
        </div>
        
        {/* Level badge */}
        <div className="absolute bottom-3 left-3">
          <span className={`px-3 py-1.5 rounded-full ${levelInfo.bg} ${levelInfo.text} ${levelInfo.border} border text-xs font-medium backdrop-blur-sm`}>
            {levelInfo.label}
          </span>
        </div>

        {/* Play button overlay */}
        <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-300">
          <motion.div
            whileHover={{ scale: 1.1 }}
            whileTap={{ scale: 0.95 }}
            className="h-16 w-16 rounded-full bg-white/95 shadow-xl flex items-center justify-center cursor-pointer"
          >
            <PlayCircle className="h-8 w-8 text-blue-600" />
          </motion.div>
        </div>
      </div>

      {/* Content */}
      <div className="relative flex flex-col flex-grow p-5">
        {/* Progress bar for enrolled courses */}
        {enrolled && progress !== undefined && (
          <div className="mb-4">
            <div className="flex justify-between text-xs mb-1.5">
              <span className="text-muted-foreground">التقدم</span>
              <span className="font-semibold text-blue-600">{progress}%</span>
            </div>
            <div className="h-2 bg-slate-100 dark:bg-slate-700 rounded-full overflow-hidden">
              <motion.div
                initial={{ width: 0 }}
                animate={{ width: `${progress}%` }}
                transition={{ duration: 1, delay: index * 0.1 + 0.3 }}
                className="h-full bg-gradient-to-r from-blue-500 to-purple-500 rounded-full"
              />
            </div>
          </div>
        )}

        {/* Title */}
        <Link href={`/courses/${id}`}>
          <h3 className="font-bold text-lg text-slate-900 dark:text-white line-clamp-2 mb-2 group-hover:text-blue-600 transition-colors duration-300">
            {title}
          </h3>
        </Link>

        {/* Instructor */}
        <p className="text-sm text-muted-foreground mb-2 flex items-center gap-1.5">
          <span className="w-6 h-6 rounded-full bg-gradient-to-br from-blue-400 to-purple-500 flex items-center justify-center text-white text-xs font-bold">
            {instructor.charAt(0)}
          </span>
          {instructor}
        </p>

        {/* Description */}
        <p className="text-sm text-slate-600 dark:text-slate-400 line-clamp-2 mb-4 flex-grow">
          {description}
        </p>

        {/* Stats */}
        <div className="flex items-center justify-between mb-4 text-sm">
          <div className="flex items-center gap-4">
            {/* Rating */}
            <div className="flex items-center gap-1">
              <Star className="h-4 w-4 text-amber-400 fill-amber-400" />
              <span className="font-semibold text-slate-700 dark:text-slate-200">{rating.toFixed(1)}</span>
            </div>
            
            {/* Students */}
            <div className="flex items-center gap-1 text-muted-foreground">
              <Users className="h-4 w-4" />
              <span>{enrolledCount.toLocaleString()}</span>
            </div>
          </div>
          
          {/* Duration */}
          <div className="flex items-center gap-1 text-muted-foreground">
            <Clock className="h-4 w-4" />
            <span>{duration} ساعة</span>
          </div>
        </div>

        {/* Tags */}
        {tags.length > 0 && (
          <div className="flex flex-wrap gap-1.5 mb-4">
            {tags.slice(0, 3).map((tag, i) => (
              <span
                key={i}
                className="px-2 py-0.5 rounded-full bg-slate-100 dark:bg-slate-700 text-xs text-slate-600 dark:text-slate-300"
              >
                {tag}
              </span>
            ))}
            {tags.length > 3 && (
              <span className="px-2 py-0.5 rounded-full bg-slate-100 dark:bg-slate-700 text-xs text-slate-500">
                +{tags.length - 3}
              </span>
            )}
          </div>
        )}

        {/* Footer */}
        <div className="flex items-center justify-between pt-4 border-t border-slate-100 dark:border-slate-700">
          {/* Price */}
          <div className="flex items-center gap-2">
            {price === 0 ? (
              <span className="text-lg font-bold bg-gradient-to-r from-emerald-500 to-teal-500 bg-clip-text text-transparent">
                مجاني
              </span>
            ) : (
              <span className="text-lg font-bold text-slate-900 dark:text-white">
                {price} <span className="text-sm font-normal text-muted-foreground">ريال</span>
              </span>
            )}
          </div>

          {/* Action button */}
          {enrolled ? (
            <div className="flex items-center gap-2">
              <Link href={`/courses/${id}`}>
                <motion.button
                  whileHover={{ scale: 1.05 }}
                  whileTap={{ scale: 0.95 }}
