import { NextRequest, NextResponse } from 'next/server';
import { manualCleanup } from '@/lib/cleanup-expired-challenges';
import { logger } from '@/lib/logger';

/**
 * Admin API route for manually cleaning up expired authentication challenges
 * This is useful for development and can be called periodically in production
 */
export async function POST(request: NextRequest) {
  try {
    // Check for admin authorization (you might want to implement proper admin auth)
    const authHeader = request.headers.get('authorization');
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      return NextResponse.json(
        { error: 'Authentication required' },
        { status: 401 }
      );
    }

    const result = await manualCleanup();

    if (result.success) {
      return NextResponse.json({
        message: 'Cleanup completed successfully',
        cleaned: result.cleaned
      });
    } else {
      return NextResponse.json(
        { error: 'Cleanup failed', details: result.error },
        { status: 500 }
      );
    }
  } catch (error) {
    logger.error('Manual cleanup error:', error);
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}

/**
 * GET endpoint to check the status of challenges (development only)
 */
export async function GET(request: NextRequest) {
  try {
    // In a real implementation, you might want to add admin authorization here too

    // For development purposes, return basic info about challenges
    return NextResponse.json({
      message: 'Challenge cleanup system is operational',
      note: 'Use POST method to manually trigger cleanup'
    });
  } catch (error) {
    logger.error('Status check error:', error);
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { AI_PROVIDERS, getDefaultProvider, validateApiKey } from "@/lib/ai-config";
import { opsWrapper } from "@/lib/middleware/ops-middleware";
import { analyzeSentiment } from "@/lib/ai/sentiment-analysis";
import { prisma } from '@/lib/db';
import { verifyToken } from "@/lib/services/auth-service";
import { logger } from '@/lib/logger';
import {
  parseRequestBody,
  createStandardErrorResponse,
  createSuccessResponse,
  addSecurityHeaders
} from '@/app/api/auth/_helpers';

export async function POST(request: NextRequest) {
  return opsWrapper(request, async (req) => {
    try {
      // Parse request body with timeout protection using standardized helper
      const bodyResult = await parseRequestBody<{
        messages?: { role: string; content: string }[];
        provider?: string;
        userId?: string;
      }>(req, {
        maxSize: 10240, // 10KB max for chat messages
        required: true,
      });

      if (!bodyResult.success) {
        return bodyResult.error;
      }

      const { messages, provider, userId } = bodyResult.data;

      // Try to get userId from token if not provided
      let actualUserId = userId;
      if (!actualUserId) {
        const decodedToken = verifyToken(req);
        if (decodedToken) {
          actualUserId = decodedToken.userId;
        }
      }

      // تحديد مقدم الخدمة
      const selectedProvider = provider === 'openai' ? AI_PROVIDERS.OPENAI : AI_PROVIDERS.GEMINI;

      if (!validateApiKey(selectedProvider === AI_PROVIDERS.OPENAI ? 'OPENAI' : 'GEMINI')) {
        const response = NextResponse.json(
          { error: `مفتاح API لـ ${selectedProvider.name} غير مهيأ`, code: 'API_KEY_MISSING' },
          { status: 500 }
        );
        return addSecurityHeaders(response);
      }

      if (!messages || !Array.isArray(messages)) {
        const response = NextResponse.json(
          { error: "الرسائل غير صالحة", code: 'INVALID_MESSAGES' },
          { status: 400 }
        );
        return addSecurityHeaders(response);
      }

      // Analyze sentiment of the last user message
      let sentiment = null;
      let sentimentAwareContext = "";

      if (actualUserId && messages.length > 0) {
        const lastUserMessage = messages.filter((m) => m.role === 'user').pop();
        if (lastUserMessage) {
          try {
            sentiment = await analyzeSentiment(lastUserMessage.content, actualUserId, 'chat');

            // Add sentiment-aware context
            if (sentiment.sentiment === 'frustrated' || sentiment.sentiment === 'tired') {
              sentimentAwareContext = `ملاحظة مهمة: المستخدم يبدو ${sentiment.sentiment === 'frustrated' ? 'محبطاً' : 'متعباً'}. يجب أن تكون أكثر تفهماً وتقديم دعم إضافي. `;
              if (sentiment.suggestions && sentiment.suggestions.length > 0) {
                sentimentAwareContext += `اقتراحات الدعم: ${sentiment.suggestions.join(', ')}. `;
              }
            }

            // Save chat message with sentiment
            await prisma.aiChatMessage.create({
              data: {
                userId: actualUserId,
                role: 'user',
                content: lastUserMessage.content,
                sentiment: sentiment.sentiment,
                metadata: JSON.stringify({
                  score: sentiment.score,
                  confidence: sentiment.confidence,
                  emotions: sentiment.emotions
                })
              }
            });
          } catch (error) {
            logger.error('Error analyzing sentiment:', error);
          }
        }
      }

      // إضافة رسالة النظام لتعريف شخصية المساعد مع تحليل المشاعر
      const systemMessage = {
        role: "system",
        content: `${sentimentAwareContext}أنت مساعد ذكاء اصطناعي متخصص في التعليم والإرشاد الأكاديمي لمنصة ثناوي. مهمتك هي مساعدة الطلاب في دراستهم والإجابة على أسئلتهم بطريقة واضحة ومفيدة. يجب أن تكون إجاباتك دقيقة ومتناسبة مع المستوى التعليمي للطالب. إذا لم تكن متأكداً من إجابة سؤال ما، فمن الأفضل أن تعترف بذلك بدلاً من تقديم معلومات خاطئة. كن دائماً داعماً ومشجعاً، خاصة إذا كان المستخدم يبدو محبطاً أو متعباً.`
      };

      let aiMessage = "";

      if (selectedProvider === AI_PROVIDERS.OPENAI) {
        // استخدام OpenAI API
        const response = await fetch(selectedProvider.baseUrl, {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            "Authorization": `Bearer ${selectedProvider.apiKey}`
          },
          body: JSON.stringify({
            model: selectedProvider.model,
            messages: [systemMessage, ...messages],
            temperature: 0.7,
            max_tokens: 1000
          })
        });

        if (!response.ok) {
          const errorData = await response.json();
          logger.error("Error from OpenAI:", errorData);
          const errorResponse = NextResponse.json({
            message: "عذراً، يواجه المساعد الذكي بعض الصعوبات التقنية حالياً. يرجى المحاولة مرة أخرى لاحقاً أو التواصل مع فريق الدعم.",
            code: 'AI_SERVICE_ERROR'
          }, { status: 500 });
          return addSecurityHeaders(errorResponse);
        }

        const data = await response.json();
        aiMessage = data.choices[0].message.content;
      } else {
        // استخدام Google Gemini API
        const geminiMessages = [
          systemMessage,
          ...messages
        ].map(msg => ({
          role: msg.role === "user" ? "user" : "model",
          parts: [{ text: msg.content }]
        }));

        const response = await fetch(`${selectedProvider.baseUrl}${selectedProvider.model}:generateContent?key=${selectedProvider.apiKey}`, {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            contents: geminiMessages,
            generationConfig: {
              temperature: 0.7,
              topK: 40,
              topP: 0.95,
              maxOutputTokens: 1000,
            },
          })
        });

        if (!response.ok) {
          const errorData = await response.json();
          logger.error("Error from Gemini:", errorData);
          const errorResponse = NextResponse.json({
            message: "عذراً، يواجه المساعد الذكي بعض الصعوبات التقنية حالياً. يرجى المحاولة مرة أخرى لاحقاً أو التواصل مع فريق الدعم.",
            code: 'AI_SERVICE_ERROR'
          }, { status: 500 });
          return addSecurityHeaders(errorResponse);
        }

        const data = await response.json();
        aiMessage = data.candidates[0].content.parts[0].text;
      }

      // Save assistant message if userId exists
      if (actualUserId) {
        await prisma.aiChatMessage.create({
          data: {
            userId: actualUserId,
            role: 'assistant',
            content: aiMessage,
            metadata: JSON.stringify({
              provider: selectedProvider.name,
              sentiment: sentiment?.sentiment || null
            })
          }
        });
      }

      return createSuccessResponse({
        message: aiMessage,
        sentiment: sentiment ? {
          sentiment: sentiment.sentiment,
          score: sentiment.score,
          suggestions: sentiment.suggestions
        } : null
      });
    } catch (error) {
      logger.error("Error in AI chat API:", error);
      return createStandardErrorResponse(
        error,
        "حدث خطأ في معالجة طلبك"
      );
    }
  });
}

