import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/db';
import { TwoFactorChallengeService } from '@/lib/services/auth-challenges-service';
import { authService } from '@/lib/services/auth-service';
import { securityLogger } from '@/lib/security-logger';
import { opsWrapper } from "@/lib/middleware/ops-middleware";
import { logger } from '@/lib/logger';
import { extractRequestMetadata, createErrorResponse } from '@/lib/auth-utils';
import { rateLimitingService } from '@/lib/services/rate-limiting-service';
import { TokenService } from '@/lib/services/token-service';

export async function POST(request: NextRequest) {
    return opsWrapper(request, async (req) => {
        try {
            const body = await req.json();
            // Added type safety by checking if body is null or undefined
            if (!body) {
                return NextResponse.json({ error: 'Missing request body' }, { status: 400 });
            }

            const { loginAttemptId, code, trustDevice } = body;
            const { ip, userAgent, clientId } = extractRequestMetadata(req);

            if (!loginAttemptId || !code) {
                return NextResponse.json({ error: 'Missing loginAttemptId or code' }, { status: 400 });
            }

            const trimmedCode = code.trim();
            const trimmedAttemptId = loginAttemptId.trim();

            if (trimmedCode.length !== 6 || !/^\d{6}$/.test(trimmedCode)) {
                return NextResponse.json({ error: 'رمز التحقق يجب أن يكون مكون من 6 أرقام', code: 'INVALID_CODE_FORMAT' }, { status: 400 });
            }

            // Lookup challenge
            const challenge = await prisma.twoFactorChallenge.findUnique({
                where: { id: trimmedAttemptId }
            });

            if (challenge?.userId) {
                // Check user rate limit
                const userRateLimit = await rateLimitingService.checkRateLimit(`user:${challenge.userId}`, {
                    maxAttempts: 5,
                    windowMs: 15 * 60 * 1000
                });

                if (!userRateLimit.allowed) {
                    return NextResponse.json(
                        {
                            error: userRateLimit.lockedUntil
                                ? `تم حظر محاولات التحقق مؤقتاً.`
                                : 'تم تجاوز الحد المسموح به من المحاولات.',
                            code: 'RATE_LIMIT_EXCEEDED'
                        },
                        { status: 429 }
                    );
                }
            }

            // Check IP rate limit
            const ipRateLimit = await rateLimitingService.checkRateLimit(clientId, {
                maxAttempts: 5,
                windowMs: 15 * 60 * 1000
            });

            if (!ipRateLimit.allowed) {
                return NextResponse.json(
                    { error: 'تم تجاوز الحد المسموح به من المحاولات.', code: 'RATE_LIMIT_EXCEEDED' },
                    { status: 429 }
                );
            }

            // Verify Challenge
            const challengePromise = TwoFactorChallengeService.verifyAndConsumeChallenge(trimmedAttemptId, trimmedCode);
            const timeoutPromise = new Promise<{ valid: false }>((resolve) => setTimeout(() => resolve({ valid: false }), 5000));

            const challengeResult = await Promise.race([challengePromise, timeoutPromise]);

            if (!challengeResult.valid || !challengeResult.userId) {
                if (challenge?.userId) {
                    await rateLimitingService.incrementAttempts(`user:${challenge.userId}`);
                }
                await rateLimitingService.incrementAttempts(clientId);

                await securityLogger.logEvent({
                    userId: challenge?.userId || 'unknown',
                    eventType: 'TWO_FACTOR_FAILED',
                    ip,
                    userAgent,
                    metadata: { reason: 'invalid_code', loginAttemptId: trimmedAttemptId }
                });
                return NextResponse.json({ error: 'رمز التحقق غير صحيح أو منتهي الصلاحية', code: 'INVALID_OR_EXPIRED' }, { status: 400 });
            }

            // Reset attempts
            await rateLimitingService.resetAttempts(`user:${challengeResult.userId}`);
            await rateLimitingService.resetAttempts(clientId);

            // Fetch user
            const user = await prisma.user.findUnique({
                where: { id: challengeResult.userId }
            });

            if (!user) {
                return NextResponse.json({ error: 'المستخدم غير موجود', code: 'USER_NOT_FOUND' }, { status: 404 });
            }

            // Complete Login using TokenService
            // Assuming low risk for verified 2FA, but ideally should carry over risk from first step
            // or re-assess. For now, we assume safe.
            const loginResult = await TokenService.completeLogin(
                {
                    id: user.id,
                    email: user.email,
                    name: user.name,
                    role: user.role,
                    emailVerified: user.emailVerified,
                    twoFactorEnabled: user.twoFactorEnabled,
                    lastLogin: user.lastLogin
                },
                userAgent,
                ip,
                { level: 'low', score: 0, factors: {}, blockAccess: false, requireAdditionalAuth: false },
                !trustDevice, // Treat as new device if not trusted? Or simply isNewDevice=false (assuming checked earlier)
                false, // accountWasCreated
                clientId
            );

            // TokenService.completeLogin returns { success: true, response: LoginResponse, ... }
            // We return the response JSON directly.
            if (loginResult.success) {
                // Need to set cookies. completeLogin doesn't set cookies on the response object it generates?
                // It returns a LoginResponse object. It does NOT return NextResponse.
                // Wait, `createLoginSuccessResponse` returns a plain object.
                // I need to create NextResponse and set cookies.
                // TokenService.completeLogin logic ends with returning the object.
                // I should handle cookie setting here.

                const loginResponse = loginResult.response as any; // Type assertion if needed

                const response = NextResponse.json(loginResponse);

                // Import setAuthCookies
                const { setAuthCookies } = await import('@/lib/auth-utils');
                setAuthCookies(response, loginResponse.token, loginResponse.refreshToken, !!trustDevice);

                return response;
            } else {
                return NextResponse.json(loginResult.response || { error: 'Login failed' }, { status: loginResult.statusCode });
            }

        } catch (error) {
            logger.error('Two-factor login verification error:', error);
            return createErrorResponse(error, 'حدث خطأ غير متوقع.');
        }
    });
}

import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/db';
import { jwtVerify } from 'jose';
import { TextEncoder } from 'util';
import { authService } from '@/lib/services/auth-service';
import { verifyTOTP } from '@/lib/two-factor/totp-service';
import { logger } from '@/lib/logger';
import { opsWrapper } from "@/lib/middleware/ops-middleware";
import { logSecurityEventSafely, extractRequestMetadata } from '@/lib/auth-utils';
import { securityLogger } from '@/lib/security-logger';
import { securityNotificationService } from '@/lib/security/security-notifications';

export async function POST(request: NextRequest) {
    return opsWrapper(request, async (req) => {
        try {
            const { code } = await req.json();

            const authHeader = req.headers.get('authorization');
            if (!authHeader || !authHeader.startsWith('Bearer ')) {
                return NextResponse.json({ error: 'Authentication required' }, { status: 401 });
            }
            const token = authHeader.substring(7);
            const secretKey = new TextEncoder().encode(process.env.JWT_SECRET!);
            const { payload } = await jwtVerify(token, secretKey);
            const userId = payload.userId as string;

            const user = await prisma.user.findUnique({
                where: { id: userId },
                select: {
                    id: true, email: true, name: true, role: true,
                    twoFactorEnabled: true, twoFactorSecret: true, recoveryCodes: true
                }
            });

            if (!user) return NextResponse.json({ error: 'User not found' }, { status: 404 });

            if (!code) return NextResponse.json({ error: 'Verification code is required' }, { status: 400 });
            if (!user.twoFactorSecret) return NextResponse.json({ error: '2FA not set up' }, { status: 400 });

            // Check lockout status
            const lockoutStatus = await authService.get2FALockoutStatus(user.id);
            if (lockoutStatus.locked) {
                return NextResponse.json(
                    {
                        error: `تم حظر محاولات التحقق مؤقتاً. يمكنك المحاولة مرة أخرى بعد ${lockoutStatus.lockedUntil?.toLocaleTimeString()}`,
                        code: 'ACCOUNT_LOCKED',
                        lockedUntil: lockoutStatus.lockedUntil
                    },
                    { status: 403 }
                );
            }

            const { ip, userAgent } = extractRequestMetadata(req);
            const clientId = `${ip}-${userAgent}`;

            // Rate Limit for Management
            try {
                await authService.checkRateLimit(clientId);
            } catch (error) {
                logSecurityEventSafely(userId, 'two_factor_rate_limit', { userAgent, ip });
                return NextResponse.json({ error: 'Too many attempts. Please try again later.' }, { status: 429 });
            }

            const totpResult = verifyTOTP(user.twoFactorSecret, code);
            const isValid = totpResult.valid;

            if (!isValid) {
                await authService.recordFailed2FAAttempt(user.id);
                logSecurityEventSafely(user.id, 'two_factor_verify_failed', { userAgent, method: 'TOTP', ip });
                securityLogger.logEvent({ userId: user.id, eventType: 'TWO_FACTOR_FAILED', ip, userAgent, metadata: { method: 'TOTP' } });
                return NextResponse.json({ error: 'رمز التحقق غير صحيح' }, { status: 400 });
            }

            await prisma.user.update({ where: { id: user.id }, data: { twoFactorEnabled: true } });
            await authService.resetRateLimit(clientId);

            logSecurityEventSafely(user.id, 'two_factor_enabled', { userAgent, method: 'TOTP', ip });
            securityLogger.logEvent({ userId: user.id, eventType: 'TWO_FACTOR_ENABLED', ip, userAgent, metadata: { method: 'TOTP' } });
            securityNotificationService.notify2FAStatusChange(user.id, true, ip);

            return NextResponse.json({ message: 'تم تفعيل المصادقة الثنائية بنجاح' });
        } catch (error) {
            logger.error('2FA verify error:', error);
            return NextResponse.json({ error: 'Failed to verify 2FA' }, { status: 500 });
        }
    });
}

import { NextRequest, NextResponse } from 'next/server';
import { oauthConfig, verifyState, generateToken } from '@/lib/oauth';
import { prisma } from '@/lib/db';
import { opsWrapper } from "@/lib/middleware/ops-middleware";
import { logger } from '@/lib/logger';
import {
    getSecureCookieOptions,
    createOAuthErrorResponse,
    createOAuthErrorRedirect,
    OAUTH_ERROR_MESSAGES,
    withDatabaseRetry,
    getDatabaseErrorMessage
} from '@/lib/auth-utils';
import { jwtVerify, createRemoteJWKSet } from 'jose';
import crypto from 'crypto';

const APPLE_JWKS = createRemoteJWKSet(new URL('https://appleid.apple.com/auth/keys'));

/**
 * POST /api/auth/apple/callback
 * Apple uses form_post for OAuth callback
 */
export async function POST(request: NextRequest) {
    return opsWrapper(request, async (req) => {
        try {
            // Apple sends data as form-urlencoded in POST body
            const formData = await req.formData();
            const code = formData.get('code') as string | null;
            const state = formData.get('state') as string | null;
            const idToken = formData.get('id_token') as string | null;
            const error = formData.get('error') as string | null;

            // Apple sends user info only on first login
            const userDataStr = formData.get('user') as string | null;
            let appleUser: { name?: { firstName?: string; lastName?: string }; email?: string } | null = null;
            if (userDataStr) {
                try {
                    appleUser = JSON.parse(userDataStr);
                } catch {
                    logger.warn('Failed to parse Apple user data');
                }
            }

            // Handle errors from Apple - use centralized error messages
            if (error) {
                logger.error('Apple OAuth error:', error);
                return createOAuthErrorResponse(
                    error,
                    OAUTH_ERROR_MESSAGES[error] || 'حدث خطأ أثناء تسجيل الدخول بـ Apple'
                );
            }

            // Verify state parameter to prevent CSRF attacks
            const savedState = req.cookies.get('oauth_state')?.value;
            if (!state || !savedState || !verifyState(state, savedState)) {
                logger.error('Apple OAuth: Invalid state parameter', { state, savedState });
                return createOAuthErrorResponse('invalid_state');
            }

            if (!code || !idToken) {
                logger.error('Apple OAuth: Missing code or id_token');
                return createOAuthErrorResponse('no_code', 'لم يتم استلام رمز التفويض من Apple');
            }

            // Verify the token signature using Apple's public keys
            let payload;
            try {
                const verified = await jwtVerify(idToken, APPLE_JWKS, {
                    issuer: 'https://appleid.apple.com',
                    audience: process.env.APPLE_CLIENT_ID
                });
                payload = verified.payload;

                // Additional validation: check token expiry and subject
                if (!payload.sub) {
                    throw new Error('Missing subject in token');
                }
            } catch (err) {
                logger.error('Apple JWT verification failed', err);
                return createOAuthErrorResponse('invalid_token', 'فشل التحقق من رمز المصادقة');
            }

            const appleUserId = payload.sub;
            const email = (payload.email as string) || appleUser?.email;

            if (!email) {
                logger.error('No email in Apple OAuth response');
                return createOAuthErrorResponse(
                    'no_email',
                    'لم يتم استلام البريد الإلكتروني من Apple. يرجى السماح بمشاركة البريد.'
                );
            }

            const normalizedEmail = email.toLowerCase().trim();

            // Check if user exists with retry
            let user;
            try {
                user = await withDatabaseRetry(
                    async () => prisma.user.findUnique({ where: { email: normalizedEmail } }),
                    { maxAttempts: 3, operationName: 'find user for Apple OAuth' }
                );
            } catch (dbError) {
                logger.error('Database error finding user:', dbError);
                return createOAuthErrorResponse('database_error', getDatabaseErrorMessage(dbError));
            }

            // If user doesn't exist, create a new one
            if (!user) {
                const name = appleUser?.name
                    ? `${appleUser.name.firstName || ''} ${appleUser.name.lastName || ''}`.trim()
                    : 'Apple User';

                try {
                    user = await withDatabaseRetry(
                        async () => prisma.user.create({
                            data: {
                                email: normalizedEmail,
                                name,
                                passwordHash: crypto.randomUUID(), // Secure random "password" for OAuth users
                                emailVerified: true, // Apple verified the email
                            },
                        }),
                        { maxAttempts: 3, operationName: 'create user for Apple OAuth' }
                    );
                    logger.info('Created new user via Apple OAuth:', { userId: user.id, email: normalizedEmail });
                } catch (createError) {
                    logger.error('Error creating user:', createError);
                    return createOAuthErrorResponse('database_error', getDatabaseErrorMessage(createError));
                }
            }

            // Generate JWT token
            const token = await generateToken(user.id, user.email, user.name || undefined);

            // Create response with redirect
            const response = NextResponse.redirect(
                `${process.env.NEXT_PUBLIC_BASE_URL || 'http://localhost:3000'}/`
            );

            // Security: Use centralized secure cookie settings
            response.cookies.set('access_token', token, {
                ...getSecureCookieOptions({ maxAge: 7 * 24 * 60 * 60 }), // 7 days
            });

            // Clear state cookie
            response.cookies.set('oauth_state', '', {
                ...getSecureCookieOptions({ maxAge: 0 }),
            });

            return response;
        } catch (error) {
            logger.error('Error in Apple OAuth callback:', error);
            return createOAuthErrorResponse('server_error', 'حدث خطأ في الخادم. يرجى المحاولة مرة أخرى.');
        }
    });
}

/**
 * GET /api/auth/apple/callback
 * Apple may send GET requests in some scenarios
 */
export async function GET(request: NextRequest) {
    return createOAuthErrorResponse('invalid_request', 'Apple OAuth يتطلب استخدام POST');
}

﻿import { NextRequest, NextResponse } from 'next/server';
import { authService } from '@/lib/services/auth-service';
import { webAuthnService } from '@/lib/security/webauthn';
import { prisma } from '@/lib/db';
import { opsWrapper } from "@/lib/middleware/ops-middleware";
import { logger } from '@/lib/logger';
import {
  getSecureCookieOptions,
  setAuthCookies,
  createErrorResponse,
  createSuccessResponse
} from '@/app/api/auth/_helpers';
import crypto from 'crypto';

interface BiometricAuthBody {
  email?: string;
  credential?: any;
  challenge?: string;
}

export async function POST(request: NextRequest) {
  return opsWrapper(request, async (req) => {
    try {
      const body = await req.json() as BiometricAuthBody;

      // Check if this is a verification request (has credential)
      if (body.credential && body.challenge) {
        return handleVerification(req, body);
      }

      // Otherwise assume it's an options request (has email)
      if (body.email) {
        return handleOptions(req, body);
      }

      return createErrorResponse('بيانات غير مكتملة', 'بيانات غير مكتملة', 400);
    } catch (error) {
      logger.error('Biometric API error:', error);
      return createErrorResponse(error, 'حدث خطأ في الخادم', 500);
    }
  });
}

export async function PUT(request: NextRequest) {
  return opsWrapper(request, async (req) => {
    try {
      const body = await req.json() as BiometricAuthBody;
      return handleVerification(req, body);
    } catch (error) {
      logger.error('Biometric verification error:', error);
      return createErrorResponse(error, 'حدث خطأ أثناء التحقق', 500);
    }
  });
}

async function handleOptions(req: NextRequest, body: BiometricAuthBody) {
  const { email } = body;

  if (!email) {
    return createErrorResponse('البريد الإلكتروني مطلوب', 'البريد الإلكتروني مطلوب', 400);
  }

  // Find user
  const user = await prisma.user.findUnique({
    where: { email: email.toLowerCase().trim() },
    select: {
      id: true,
      email: true,
      name: true,
      biometricEnabled: true,
      biometricCredentials: true,
    },
  });

  if (!user || !user.biometricEnabled) {
    return createErrorResponse('المصادقة البيومترية غير مفعلة لهذا الحساب', 'المصادقة البيومترية غير مفعلة لهذا الحساب', 404);
  }

  const credentials = user.biometricCredentials || [];

  if (credentials.length === 0) {
    return createErrorResponse('لا توجد بيانات اعتماد بيومترية', 'لا توجد بيانات اعتماد بيومترية', 404);
  }

  // Generate authentication options
  const options = webAuthnService.generateAuthenticationOptions(
    credentials.map((cred) => ({
      id: cred.id,
      userId: user.id,
      credentialId: cred.credentialId,
      publicKey: cred.publicKey,
      counter: cred.counter,
      deviceType: cred.deviceType || 'unknown',
      createdAt: new Date(cred.createdAt),
    }))
  );

  // Store challenge temporarily
  await prisma.biometricChallenge.create({
    data: {
      id: crypto.randomUUID(),
      challenge: options.challenge,
      type: 'authenticate',
      userId: user.id,
      expiresAt: new Date(Date.now() + 5 * 60 * 1000), // 5 minutes
      used: false,
    },
  });

  // Log security event
  const ip = authService.getClientIP(req);
  const userAgent = authService.getUserAgent(req);
  await authService.logSecurityEvent(user.id, 'biometric_authentication_initiated', ip, {
    userAgent,
  }).catch(() => {
    // Non-blocking log failure
  });

  return createSuccessResponse({ options });
}

async function handleVerification(req: NextRequest, body: BiometricAuthBody) {
  const { credential, challenge, email } = body;

  if (!credential || !challenge) {
    return createErrorResponse('بيانات غير مكتملة', 'بيانات غير مكتملة', 400);
  }

  if (!email) {
    return createErrorResponse('البريد الإلكتروني مطلوب للتحقق', 'البريد الإلكتروني مطلوب للتحقق', 400);
  }

  // Find user
  const user = await prisma.user.findUnique({
    where: { email: email.toLowerCase().trim() },
    select: {
      id: true,
      email: true,
      name: true,
      biometricEnabled: true,
      biometricCredentials: true,
    },
  });

  if (!user || !user.biometricEnabled) {
    return createErrorResponse('المصادقة البيومترية غير مفعلة', 'المصادقة البيومترية غير مفعلة', 404);
  }

  // Verify challenge
  const storedChallenge = await prisma.biometricChallenge.findFirst({
    where: {
      challenge,
      userId: user.id,
      type: 'authenticate',
      used: false,
      expiresAt: {
        gt: new Date(),
      },
    },
  });

  if (!storedChallenge) {
    return createErrorResponse('الحالة غير صالحة', 'الحالة غير صالحة', 400);
  }

  // Find matching credential
  const credentials = user.biometricCredentials || [];
  const matchingCredential = credentials.find(
    (cred) => cred.credentialId === credential.id
  );

  if (!matchingCredential) {
    return createErrorResponse('بيانات الاعتماد غير صالحة', 'بيانات الاعتماد غير صالحة', 400);
  }

  // Verify authentication response
  const verificationResult = await webAuthnService.verifyAuthentication(
    credential,
    challenge,
    {
      id: matchingCredential.id,
      userId: user.id,
      credentialId: matchingCredential.credentialId,
      publicKey: matchingCredential.publicKey,
      counter: matchingCredential.counter,
      deviceType: matchingCredential.deviceType || 'unknown',
      createdAt: new Date(matchingCredential.createdAt),
    }
  );

  if (!verificationResult.verified) {
    // Log failed authentication attempt
    const ip = authService.getClientIP(req);
    const userAgent = authService.getUserAgent(req);
    await authService.logSecurityEvent(user.id, 'biometric_authentication_failed', ip, {
      userAgent,
    }).catch(() => {
      // Non-blocking log failure
    });

    return createErrorResponse('فشل التحقق من المصادقة البيومترية', 'فشل التحقق من المصادقة البيومترية', 400);
  }

  // Update counter
  if (verificationResult.newCounter !== undefined) {
    await prisma.biometricCredential.update({
      where: { id: matchingCredential.id },
      data: {
        counter: verificationResult.newCounter,
      },
    });
  }

  // Mark challenge as used
  await prisma.biometricChallenge.update({
    where: { id: storedChallenge.id },
    data: { used: true },
  });

  // Create session and tokens
  const ip = authService.getClientIP(req);
  const userAgent = authService.getUserAgent(req);

  await authService.updateLastLogin(user.id);

  // Create tokens first to get a refresh token
  const tempTokens = await authService.createTokens({
    id: user.id,
    email: user.email,
    name: user.name || undefined,
  });

  // Create session with the refresh token
  const session = await authService.createSession(user.id, tempTokens.refreshToken, userAgent, ip);

  // Create final tokens with session ID
  const { accessToken, refreshToken } = await authService.createTokens(
    {
      id: user.id,
      email: user.email,
      name: user.name || undefined,
    },
    session.id
  );

  // Update session with final refresh token
  await prisma.session.update({
    where: { id: session.id },
    data: { refreshToken }
  });

  // Log security event
  await authService.logSecurityEvent(
    user.id,
    'biometric_login_success',
    ip,
    { userAgent, sessionId: session.id }
  );

  const response = createSuccessResponse({
    token: accessToken,
    refreshToken,
    sessionId: session.id,
    user: {
      id: user.id,
      email: user.email,
      name: user.name,
    },
  }, 'تم تسجيل الدخول بنجاح');

  // Set cookies
  setAuthCookies(response, accessToken, refreshToken, true);

  return response;
}

import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/db';
import { authService } from '@/lib/services/auth-service';
import { webAuthnService, WebAuthnCredential } from '@/lib/security/webauthn';
import { opsWrapper } from "@/lib/middleware/ops-middleware";
import { logger } from '@/lib/logger';
import {
  setAuthCookies,
  createErrorResponse,
  createSuccessResponse,
} from '@/app/api/auth/_helpers';
import { withDatabaseRetry } from '@/lib/auth-utils';
import { authChallengeService } from '@/lib/services/auth-challenges-service';
import crypto from 'crypto';

/**
 * POST /api/auth/biometric
 * المصادقة البيومترية - التسجيل والتحقق
 */
export async function POST(request: NextRequest) {
  return opsWrapper(request, async (req) => {
    try {
      const { action, ...data } = await req.json();

      logger.info(`Biometric API request: ${action}`, { ip: req.headers.get('x-forwarded-for') });

      switch (action) {
        case 'register':
          return handleBiometricRegistration(req, data);
        case 'authenticate':
          return handleBiometricAuthentication(req, data);
        case 'options':
          return handleAuthenticationOptions(req, data);
        default:
          logger.warn(`Invalid biometric action: ${action}`);
          return createErrorResponse(
            { error: 'Invalid action', code: 'INVALID_ACTION' },
            'إجراء غير صحيح',
            400
          );
      }
    } catch (error: unknown) {
      logger.error('Biometric authentication error:', error);
      return createErrorResponse(error, 'حدث خطأ في المصادقة البيومترية', 500);
    }
  });
}

/**
 * Handle Biometric Registration
 */
async function handleBiometricRegistration(
  request: NextRequest,
  data: { userId: string; response: any }
) {
  const { userId, response } = data;

  if (!userId || !response) {
    return createErrorResponse(
      { error: 'Missing data', code: 'MISSING_DATA' },
      'معرف المستخدم والاستجابة مطلوبان',
      400
    );
  }

  // Find user with retry
  const user = await withDatabaseRetry(
    async () => prisma.user.findUnique({ where: { id: userId } }),
    { maxAttempts: 3, operationName: 'find user for biometric registration' }
  );

  if (!user) {
    return createErrorResponse(
      { error: 'User not found', code: 'USER_NOT_FOUND' },
      'المستخدم غير موجود',
      404
    );
  }

  // Get the registration challenge from database with retry
  const challenge = await withDatabaseRetry(
    async () => prisma.biometricChallenge.findFirst({
      where: {
        userId,
        type: 'register',
        used: false,
        expiresAt: { gt: new Date() }
      },
      orderBy: { createdAt: 'desc' }
    }),
    { maxAttempts: 3, operationName: 'find biometric registration challenge' }
  );

  if (!challenge) {
    return createErrorResponse(
      { error: 'No challenge found', code: 'NO_CHALLENGE' },
      'لم يتم العثور على تحدي تسجيل نشط',
      400
    );
  }

  // Verify registration response
  const verificationResult = await webAuthnService.verifyRegistration(
    response,
    challenge.challenge
  );

  if (!verificationResult.verified || !verificationResult.credential) {
    logger.error('Registration verification failed:', verificationResult.error);
    return createErrorResponse(
      { error: 'Verification failed', code: 'VERIFICATION_FAILED' },
      'فشل التحقق من التسجيل',
      400
    );
  }

  // Mark challenge as used
  await withDatabaseRetry(
    async () => prisma.biometricChallenge.update({
      where: { id: challenge.id },
      data: { used: true }
    }),
    { maxAttempts: 3, operationName: 'mark challenge as used' }
  );

  // Save credential
  await withDatabaseRetry(
    async () => prisma.biometricCredential.create({
      data: {
        userId: user.id,
        credentialId: verificationResult.credential!.credentialId,
        publicKey: verificationResult.credential!.publicKey,
        counter: verificationResult.credential!.counter,
        transports: JSON.stringify([]),
        deviceType: 'singleDevice',
      }
    }),
    { maxAttempts: 3, operationName: 'save biometric credential' }
  );

  await withDatabaseRetry(
    async () => prisma.user.update({
      where: { id: userId },
      data: { biometricEnabled: true }
    }),
    { maxAttempts: 3, operationName: 'enable biometric for user' }
  );

  logger.info('Biometric registration completed', { userId });

  return createSuccessResponse({
    message: 'تم تسجيل المصادقة البيومترية بنجاح'
  });
}

async function handleBiometricAuthentication(
  request: NextRequest,
  data: { response: any }
) {
  const { response } = data;

  if (!response) {
    return createErrorResponse(
      { error: 'Response required', code: 'MISSING_RESPONSE' },
      'استجابة المصادقة مطلوبة',
      400
    );
  }

  const ip = authService.getClientIP(request);
  const userAgent = authService.getUserAgent(request);
  const clientId = `${ip}-${userAgent}`;

  // 1. Check Rate Limit
  try {
    await authService.checkRateLimit(clientId);
  } catch (error) {
    await authService.logSecurityEvent(null, 'biometric_rate_limit_exceeded', ip, { userAgent });
    return createErrorResponse(
      { error: 'Rate limited', code: 'RATE_LIMITED' },
      'محاولات كثيرة جداً. يرجى المحاولة لاحقاً.',
      429
    );
  }

  // Find credential
  const credential = await prisma.biometricCredential.findUnique({
    where: { credentialId: response.id },
    include: { user: true }
  });

  if (!credential || !credential.user) {
    await authService.recordFailedAttempt(clientId);
    return createErrorResponse(
      { error: 'Credential not found', code: 'CREDENTIAL_NOT_FOUND' },
      'بيانات الاعتماد غير موجودة',
      404
    );
  }

  const user = credential.user;

  if (!user.biometricEnabled) {
    return createErrorResponse(
      { error: 'Biometric not enabled', code: 'BIOMETRIC_NOT_ENABLED' },
      'المصادقة البيومترية غير مفعلة لهذا الحساب',
      401
    );
  }

  // 2. Extract challenge from client response to find the CORRECT challenge record
  // This prevents race conditions where we might verify against the wrong challenge
  let clientChallenge = '';
  try {
    const clientData = JSON.parse(Buffer.from(response.clientDataJSON, 'base64').toString('utf8'));
    clientChallenge = clientData.challenge;
  } catch (e) {
    await authService.recordFailedAttempt(clientId);
    return createErrorResponse(
      { error: 'Invalid client data', code: 'INVALID_CLIENT_DATA' },
      'بيانات العميل غير صحيحة',
      400
    );
  }

  // Debug log
  logger.debug(`Biometric Auth: Looking for challenge ${clientChallenge} for user ${user.id}`);

  // 3. Find specific challenge by VALUE (secure lookup)
  const challenge = await prisma.biometricChallenge.findFirst({
    where: {
      challenge: clientChallenge,
      userId: user.id,
      type: 'authenticate',
      used: false,
      expiresAt: { gt: new Date() }
    }
  });

  if (!challenge) {
    await authService.recordFailedAttempt(clientId);
    await authService.logSecurityEvent(user.id, 'biometric_challenge_not_found', ip, { userAgent });
    return createErrorResponse(
      { error: 'Challenge expired', code: 'CHALLENGE_EXPIRED' },
      'جلسة تسجيل الدخول غير صالحة أو منتهية الصلاحية',
      400
    );
  }

  // 4. Verify using Centralized Service
  // Note: We use the service to handle the complex verification logic logic consistently
  const verification = await authChallengeService.verifyBiometricChallenge(
    challenge.id,
    clientChallenge,
    user.id
  );

  if (!verification.valid) {
    await authService.recordFailedAttempt(clientId);
    await authService.logSecurityEvent(user.id, 'biometric_verification_failed', ip, { userAgent });
    return createErrorResponse(
      { error: 'Verification failed', code: 'VERIFICATION_FAILED' },
      'فشل التحقق من المصادقة',
      400
    );
  }

  // Map to WebAuthnCredential for strict signature verification
  const webAuthnCred: WebAuthnCredential = {
    id: credential.id,
    userId: credential.userId,
    credentialId: credential.credentialId,
    publicKey: credential.publicKey,
    counter: credential.counter,
    deviceType: credential.deviceType || 'unknown',
    transports: JSON.parse(credential.transports || '[]'),
    createdAt: credential.createdAt,
  };

  // 5. Verify Cryptographic Signature (WebAuthn)
  const signatureVerification = await webAuthnService.verifyAuthentication(
    response,
    challenge.challenge,
    webAuthnCred
  );

  if (!signatureVerification.verified) {
    await authService.recordFailedAttempt(clientId);
    logger.error('Authentication signature verification failed:', signatureVerification.error);
    return createErrorResponse(
      { error: 'Signature failed', code: 'SIGNATURE_FAILED' },
      'فشل التحقق من التوقيع',
      400
    );
  }

  // Update credential counter
  if (signatureVerification.newCounter !== undefined) {
    await prisma.biometricCredential.update({
      where: { id: credential.id },
      data: {
        counter: signatureVerification.newCounter
      }
    });
  }

  // Create tokens first to get a refresh token
  const tempTokens = await authService.createTokens({
    id: user.id,
    email: user.email,
    name: user.name || undefined,
  });

  // Create session
  const session = await authService.createSession(user.id, tempTokens.refreshToken, userAgent, ip);

  // Reset rate limiting
  await authService.resetRateLimit(clientId);

  // Update last login
  await authService.updateLastLogin(user.id);

  // Create tokens
  const tokensResult = await authService.createTokens(
    {
      id: user.id,
      email: user.email,
      name: user.name || undefined,
      role: user.role || undefined,
    },
    session.id
  );

  // Update session with final refresh token
  await prisma.session.update({
    where: { id: session.id },
    data: { refreshToken: tokensResult.refreshToken }
  });

  // Log security event
  await authService.logSecurityEvent(
    user.id,
    'biometric_login_success',
    ip,
    { userAgent, sessionId: session.id, credentialId: credential.credentialId }
  );

  const responseObj = NextResponse.json({
    message: 'Biometric authentication successful',
    user: {
      id: user.id,
      email: user.email,
      name: user.name,
    },
    token: tokensResult.accessToken,
    refreshToken: tokensResult.refreshToken
  });

  setAuthCookies(responseObj, tokensResult.accessToken, tokensResult.refreshToken, true);

  return responseObj;
}

async function handleAuthenticationOptions(
  request: NextRequest,
  data: { userId?: string; action: 'register' | 'login' }
) {
  const { userId, action } = data;

  if (!action || !['register', 'login'].includes(action)) {
    return createErrorResponse(
      { error: 'Invalid action', code: 'INVALID_ACTION' },
      'إجراء غير صحيح. يجب أن يكون "register" أو "login"',
      400
    );
  }

  let options;
  let targetUserId = userId;

  if (action === 'register') {
    if (!userId) {
      return createErrorResponse(
        { error: 'Missing user ID', code: 'MISSING_USER_ID' },
        'معرف المستخدم مطلوب للتسجيل',
        400
      );
    }

    const user = await prisma.user.findUnique({
      where: { id: userId }
    });

    if (!user) {
      return createErrorResponse(
        { error: 'User not found', code: 'USER_NOT_FOUND' },
        'المستخدم غير موجود',
        404
      );
    }

    options = webAuthnService.generateRegistrationOptions({
      id: user.id,
      email: user.email,
      name: user.name || undefined,
    });
  } else {
    // Login options
    options = webAuthnService.generateAuthenticationOptions();
  }

  // Store challenge in database
  const challenge = await prisma.biometricChallenge.create({
    data: {
      id: crypto.randomUUID(),
      challenge: options.challenge,
      type: action === 'login' ? 'authenticate' : 'register',
      userId: targetUserId,
      expiresAt: new Date(Date.now() + 5 * 60 * 1000), // 5 minutes
    }
  });

  return createSuccessResponse({
    options,
    challengeId: challenge.id
  });
}

import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/db';
import { authService } from '@/lib/services/auth-service';
import { generateSecureToken } from '@/lib/security-utils';
import { opsWrapper } from '@/lib/middleware/ops-middleware';
import { logger } from '@/lib/logger';
import {
  createErrorResponse,
  createSuccessResponse,
  withDatabaseRetry
} from '@/lib/auth-utils';

/**
 * POST /api/auth/biometric/setup
 * تفعيل المصادقة البيومترية للمستخدم
 * 
 * NOTE: This is a mock WebAuthn implementation.
 * In production, use proper WebAuthn/FIDO2 libraries like @simplewebauthn/server
 */
export async function POST(request: NextRequest) {
  return opsWrapper(request, async (req) => {
    try {
      // التحقق من التوكن باستخدام authService
      const token = authService.extractToken(req);
      if (!token) {
        return createErrorResponse(
          { error: 'Authorization required', code: 'NO_TOKEN' },
          'يجب تسجيل الدخول أولاً',
          401
        );
      }

      const decoded = await authService.verifyTokenFromInput(token);
      if (!decoded.isValid || !decoded.userId) {
        return createErrorResponse(
          { error: 'Invalid or expired token', code: 'INVALID_TOKEN' },
          'رمز المصادقة غير صالح أو منتهي الصلاحية',
          401
        );
      }

      // جلب المستخدم مع إعادة المحاولة
      const user = await withDatabaseRetry(
        async () => prisma.user.findUnique({ where: { id: decoded.userId } }),
        { maxAttempts: 3, operationName: 'find user for biometric setup' }
      );

      if (!user) {
        return createErrorResponse(
          { error: 'User not found', code: 'USER_NOT_FOUND' },
          'المستخدم غير موجود',
          404
        );
      }

      // توليد بيانات بيومترية وهمية 
      // TODO: في التطبيق الحقيقي استخدم @simplewebauthn/server لتوليد WebAuthn credentials
      const credentialId = generateSecureToken(32);
      const publicKey = generateSecureToken(64);
      const deviceName = req.headers.get('user-agent') || 'Unknown device';

      // حفظ بيانات الاعتماد البيومترية
      await withDatabaseRetry(
        async () => prisma.biometricCredential.create({
          data: {
            userId: user.id,
            credentialId,
            publicKey,
            deviceType: deviceName,
            transports: JSON.stringify([]),
          }
        }),
        { maxAttempts: 3, operationName: 'create biometric credential' }
      );

      // تفعيل المصادقة البيومترية للمستخدم
      await withDatabaseRetry(
        async () => prisma.user.update({
          where: { id: user.id },
          data: { biometricEnabled: true }
        }),
        { maxAttempts: 3, operationName: 'enable biometric for user' }
      );

      logger.info('Biometric setup completed', { userId: user.id });

      return createSuccessResponse({
        message: 'تم إعداد المصادقة البيومترية بنجاح',
        credentialId,
        challenge: generateSecureToken(32)
      });
    } catch (error) {
      logger.error('Biometric setup error:', error);
      return createErrorResponse(error, 'فشل إعداد المصادقة البيومترية', 500);
    }
  });
}

/**
 * DELETE /api/auth/biometric/setup
 * إزالة المصادقة البيومترية للمستخدم
 */
export async function DELETE(request: NextRequest) {
  return opsWrapper(request, async (req) => {
    try {
      // التحقق من التوكن باستخدام authService
      const token = authService.extractToken(req);
      if (!token) {
        return createErrorResponse(
          { error: 'Authorization required', code: 'NO_TOKEN' },
          'يجب تسجيل الدخول أولاً',
          401
        );
      }

      const decoded = await authService.verifyTokenFromInput(token);
      if (!decoded.isValid || !decoded.userId) {
        return createErrorResponse(
          { error: 'Invalid or expired token', code: 'INVALID_TOKEN' },
          'رمز المصادقة غير صالح',
          401
        );
      }

      // حذف بيانات الاعتماد البيومترية للمستخدم
      await withDatabaseRetry(
        async () => prisma.biometricCredential.deleteMany({
          where: { userId: decoded.userId }
        }),
        { maxAttempts: 3, operationName: 'delete biometric credentials' }
      );

      // تعطيل المصادقة البيومترية للمستخدم
      await withDatabaseRetry(
        async () => prisma.user.update({
          where: { id: decoded.userId },
          data: { biometricEnabled: false }
        }),
        { maxAttempts: 3, operationName: 'disable biometric for user' }
      );

      logger.info('Biometric removed', { userId: decoded.userId });

      return createSuccessResponse({
        message: 'تم إزالة المصادقة البيومترية بنجاح'
      });
    } catch (error) {
      logger.error('Biometric removal error:', error);
      return createErrorResponse(error, 'فشل إزالة المصادقة البيومترية', 500);
    }
  });
}

import { NextRequest, NextResponse } from 'next/server';
import { opsWrapper } from '@/lib/middleware/ops-middleware';
import { logger } from '@/lib/logger';
import { authService } from '@/lib/services/auth-service';
import {
    createStandardErrorResponse,
    createSuccessResponse,
    parseRequestBody,
    extractRequestMetadata,
    logSecurityEventSafely,
    addSecurityHeaders
} from '@/app/api/auth/_helpers';
import { z } from 'zod';

const forgotPasswordSchema = z.object({
    email: z.string().email('البريد الإلكتروني غير صالح'),
});

export async function POST(request: NextRequest) {
    return opsWrapper(request, async (req) => {
        const { ip, userAgent } = extractRequestMetadata(req);

        try {
            const bodyResult = await parseRequestBody<{ email?: string }>(req, {
                maxSize: 1024,
                required: true,
            });

            if (!bodyResult.success) {
                return bodyResult.error;
            }

            const parsed = forgotPasswordSchema.safeParse(bodyResult.data);

            if (!parsed.success) {
                return createStandardErrorResponse(
                    {
                        error: 'VALIDATION_ERROR',
                        details: parsed.error.flatten().fieldErrors,
                    },
                    'البيانات المدخلة غير صحيحة.',
                    400
                );
            }

            const { email } = parsed.data;

            // Delegate to authService
            try {
                await authService.requestPasswordReset(email, ip, userAgent);
            } catch (serviceError) {
                logger.error('Password reset request failed:', serviceError);
            }

            await logSecurityEventSafely(null, 'forgot_password_request', {
                email,
                ip,
                userAgent,
            });

            return createSuccessResponse({
                message: 'إذا كان البريد الإلكتروني مسجلاً لدينا، سيتم إرسال رابط إعادة تعيين كلمة المرور.',
            });

        } catch (error) {
            logger.error('Forgot password route error:', error);
            return createStandardErrorResponse(
                error,
                'حدث خطأ غير متوقع. حاول مرة أخرى لاحقاً.'
            );
        }
    });
}

