import { NextRequest, NextResponse } from 'next/server';
import { oauthConfig, verifyState, generateToken, validateRedirectUri } from '@/lib/oauth';
import { prisma } from '@/lib/db';
import { v4 as uuidv4 } from 'uuid';
import {
  isConnectionError,
  getSecureCookieOptions,
  logSecurityEventSafely,
  createOAuthErrorResponse,
  createOAuthErrorRedirect,
  OAUTH_ERROR_MESSAGES,
  withDatabaseRetry,
  getDatabaseErrorMessage
} from '@/app/api/auth/_helpers';
import { opsWrapper } from "@/lib/middleware/ops-middleware";
import { logger } from '@/lib/logger';

export async function GET(request: NextRequest) {
  return opsWrapper(request, async (req) => {
    try {
      const { searchParams } = new URL(req.url);
      const code = searchParams.get('code');
      const state = searchParams.get('state');
      const error = searchParams.get('error');

      // Handle errors from Google
      if (error) {
        logger.error('Google OAuth error:', error);

        // Use centralized error messages with special handling for invalid_request
        let errorMessage = OAUTH_ERROR_MESSAGES[error] || 'حدث خطأ أثناء تسجيل الدخول بجوجل';

        if (error === 'invalid_request') {
          const redirectUri = oauthConfig.google.redirectUri;
          errorMessage = `طلب غير صحيح. يرجى التحقق من:
1. Redirect URI يجب أن يكون بالضبط: ${redirectUri}
2. OAuth Consent Screen مكتمل
3. تثبت من إضافة بريدك في "Test users"`;
        }

        return createOAuthErrorResponse(error, errorMessage);
      }

      // Verify state parameter to prevent CSRF attacks
      const savedState = req.cookies.get('oauth_state')?.value;
      if (!state || !savedState || !verifyState(state, savedState)) {
        logger.error('Google OAuth: Invalid state parameter', { state, savedState });
        return createOAuthErrorResponse('invalid_state');
      }

      if (!code) {
        logger.error('Google OAuth: No authorization code received');
        return createOAuthErrorResponse('no_code');
      }

      // Validate OAuth configuration before making token request
      if (!oauthConfig.google.isConfigured()) {
        logger.error('Google OAuth: Missing credentials in callback');
        return createOAuthErrorResponse('oauth_not_configured', 'إعدادات OAuth غير مكتملة. يرجى التحقق من GOOGLE_CLIENT_ID و GOOGLE_CLIENT_SECRET.');
      }

      // Exchange authorization code for access token
      // redirect_uri must match EXACTLY what was sent in the initial auth request
      // This is the complete redirect URI stored in oauthConfig (e.g., http://localhost:3000/api/auth/google/callback)
      // Google OAuth requires exact match - any difference will cause failure
      const redirectUriForTokenExchange = oauthConfig.google.redirectUri;

      // Validate redirect URI before token exchange (helps catch configuration issues early)
      const redirectUriValidation = validateRedirectUri(redirectUriForTokenExchange);
      if (!redirectUriValidation.valid) {
        logger.error('Google OAuth callback: Invalid redirect URI format', {
          redirectUri: redirectUriForTokenExchange,
          error: redirectUriValidation.error,
          note: 'This redirect_uri will be sent to Google. It must match exactly what is configured in Google Cloud Console.',
        });
      } else {
        // Log the redirect_uri being used for debugging (only in development)
        if (process.env.NODE_ENV === 'development') {
          logger.info('Google OAuth callback: Using redirect_uri for token exchange', {
            redirectUri: redirectUriForTokenExchange,
            note: 'This must match exactly the redirect_uri sent in the initial auth request and configured in Google Cloud Console',
          });
        }
      }

      const tokenResponse = await fetch('https://oauth2.googleapis.com/token', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          client_id: oauthConfig.google.clientId,
          client_secret: oauthConfig.google.clientSecret,
          code,
          redirect_uri: redirectUriForTokenExchange, // Complete redirect URI from oauthConfig (must match exactly)
          grant_type: 'authorization_code',
        }),
      });

      if (!tokenResponse.ok) {
        const errorText = await tokenResponse.text();
        logger.error('Google OAuth token exchange failed:', {
          status: tokenResponse.status,
          statusText: tokenResponse.statusText,
          error: errorText,
          redirectUri: redirectUriForTokenExchange,
          note: 'If error is "redirect_uri_mismatch", ensure the redirect_uri in Google Cloud Console matches exactly: ' + redirectUriForTokenExchange,
        });

        let errorMessage = `طلب غير صحيح. يرجى التحقق من:
        1. إعدادات Google OAuth في ملف.env.local
        2. تأكد من إضافة بريدك الإلكتروني في "Test users"
        3. تأكد من تطابق البروتوكول(http / https) والنطاق والمنفذ والمسار بالضبط`;
        try {
          const errorData = JSON.parse(errorText);
          if (errorData.error === 'invalid_grant') {
            errorMessage = `طلب غير صحيح. يرجى التحقق من:
            1. إعدادات Google OAuth في ملف.env.local
            2. تأكد من إضافة بريدك الإلكتروني في "Test users"
            3. تأكد من تطابق البروتوكول(http / https) والنطاق والمنفذ والمسار بالضبط`;
          } else if (errorData.error === 'invalid_client') {
            errorMessage = `طلب غير صحيح. يرجى التحقق من:
            1. إعدادات Google OAuth في ملف.env.local
            2. تأكد من إضافة بريدك الإلكتروني في "Test users"
            3. تأكد من تطابق البروتوكول(http / https) والنطاق والمنفذ والمسار بالضبط`;
          } else if (errorData.error === 'redirect_uri_mismatch') {
            // Special handling for redirect_uri mismatch - most common OAuth configuration error
            errorMessage = `عدم تطابق redirect_uri. يجب أن يكون العنوان في Google Cloud Console بالضبط:
${redirectUriForTokenExchange}

💡 خطوات الإصلاح:
1. افتح Google Cloud Console: https://console.cloud.google.com/
2. انتقل إلى: APIs & Services → Credentials
3. اختر OAuth 2.0 Client ID الخاص بك
4. تأكد من وجود هذا العنوان بالضبط في "Authorized redirect URIs":
   ${redirectUriForTokenExchange}
5. تأكد من تطابق البروتوكول (http / https) والنطاق والمنفذ والمسار بالضبط.`;


            logger.error('Google OAuth redirect_uri mismatch detected', {
              expectedRedirectUri: redirectUriForTokenExchange,
              errorFromGoogle: errorData.error_description || errorData.error,
            });
          } else if (errorData.error_description) {
            errorMessage = errorData.error_description;
          }
        } catch (e) {
          // If JSON parsing fails, use default message
        }

        return NextResponse.redirect(
          `${process.env.NEXT_PUBLIC_BASE_URL || 'http://localhost:3000'}/login?error=token_error&message=${encodeURIComponent(errorMessage)}`
        );
      }

      const tokenData = await tokenResponse.json();

      if (tokenData.error) {
        logger.error('Google OAuth token error:', tokenData);
        let errorMessage = 'فشل الحصول على رمز الوصول من Google.';
        if (tokenData.error_description) {
          errorMessage = tokenData.error_description;
        }

        return NextResponse.redirect(
          `${process.env.NEXT_PUBLIC_BASE_URL || 'http://localhost:3000'}/login?error=token_error&message=${encodeURIComponent(errorMessage)}`
        );
      }

      if (!tokenData.access_token) {
        logger.error('Google OAuth: No access token in response');
        return NextResponse.redirect(
          `${process.env.NEXT_PUBLIC_BASE_URL || 'http://localhost:3000'}/login?error=token_error&message=${encodeURIComponent('لم يتم استلام رمز الوصول من Google. يرجى المحاولة مرة أخرى.')}`
        );
      }

      // Get user info from Google
      const userResponse = await fetch('https://www.googleapis.com/oauth2/v2/userinfo', {
        headers: {
          Authorization: `Bearer ${tokenData.access_token}`,
        },
      });

      if (!userResponse.ok) {
        logger.error('Google OAuth: Failed to fetch user info', {
          status: userResponse.status,
          statusText: userResponse.statusText,
        });
        return NextResponse.redirect(
          `${process.env.NEXT_PUBLIC_BASE_URL || 'http://localhost:3000'}/login?error=user_info_error&message=${encodeURIComponent('فشل الحصول على معلومات المستخدم من Google. يرجى المحاولة مرة أخرى.')}`
        );
      }

      const userData = await userResponse.json();

      if (!userData.email) {
        logger.error('Google OAuth: No email in user data');
        return NextResponse.redirect(
          `${process.env.NEXT_PUBLIC_BASE_URL || 'http://localhost:3000'}/login?error=user_info_error&message=${encodeURIComponent('لم يتم استلام البريد الإلكتروني من Google. يرجى التأكد من منح التطبيق صلاحية الوصول إلى البريد الإلكتروني.')}`
        );
      }

      // Normalize email
      const normalizedEmail = userData.email.toLowerCase().trim();

      // Check if user exists in our database with retry
      let user;
      try {
        user = await withDatabaseRetry(
          async () => prisma.user.findUnique({ where: { email: normalizedEmail } }),
          { maxAttempts: 5, operationName: 'find user by email' }
        );
      } catch (dbError: unknown) {
        logger.error('Database error while finding user:', dbError);
        return createOAuthErrorResponse('database_error', getDatabaseErrorMessage(dbError));
      }

      // If user doesn't exist, create a new one with retry
      if (!user) {
        try {
          // Generate unique user ID
          const userId = uuidv4();

          // Normalize name (handle null/undefined)
          const normalizedName = userData.name?.trim() || null;

          user = await withDatabaseRetry(async () => {
            return await prisma.user.create({
              data: {
                id: userId,
                email: normalizedEmail,
                name: normalizedName,
                passwordHash: uuidv4(), // Secure random "password" for OAuth users
                // Set required defaults
                emailVerified: true, // OAuth users are considered verified
                emailNotifications: true,
                smsNotifications: false,
                twoFactorEnabled: false,
                biometricEnabled: false,

                // Gamification defaults
                totalXP: 0,
                level: 1,
                currentStreak: 0,
                longestStreak: 0,
                totalStudyTime: 0,
                tasksCompleted: 0,
                examsPassed: 0,
                pomodoroSessions: 0,
                deepWorkSessions: 0,
                focusStrategy: 'POMODORO',
              },
            });
          }, { maxAttempts: 5, operationName: 'create new user' });

          logger.info('Google OAuth: Created new user', {
            id: user.id,
            email: user.email,
            name: user.name,
          });

          // Log security event for new user creation
          await logSecurityEventSafely(user.id, 'USER_REGISTER_OAUTH', {
            provider: 'google',
            email: user.email,
            ip: req.headers.get('x-forwarded-for') || req.headers.get('x-real-ip') || 'unknown',
            userAgent: req.headers.get('user-agent') || 'unknown',
          });
        } catch (createError: unknown) {
          const errorMsg = createError instanceof Error ? createError.message : String(createError);
          const errorCode = createError instanceof Error && 'code' in createError ? (createError as { code: string }).code : undefined;
          const errorMeta = createError instanceof Error && 'meta' in createError ? (createError as { meta: unknown }).meta : undefined;
          const errorStack = createError instanceof Error ? createError.stack : undefined;

          logger.error('Database error while creating user:', {
            error: errorMsg,
            code: errorCode,
            meta: errorMeta,
            stack: errorStack,
          });

          // If user already exists (race condition or duplicate email), try to find them again
          if (errorCode === 'P2002') {
            logger.info('User already exists (race condition), finding user...');
            try {
              user = await withDatabaseRetry(
                async () => prisma.user.findUnique({ where: { email: normalizedEmail } }),
                { maxAttempts: 5, operationName: 'find user after duplicate error' }
              );

              if (!user) {
                logger.error('User not found after duplicate error');
                return createOAuthErrorResponse('database_error', 'فشل العثور على المستخدم. يرجى المحاولة مرة أخرى.');
              }

              logger.info('Google OAuth: Found existing user after race condition', {
                id: user.id,
                email: user.email,
              });
            } catch (findError: unknown) {
              logger.error('Error finding user after duplicate:', findError);
              return createOAuthErrorResponse('database_error', getDatabaseErrorMessage(findError));
            }
          } else {
            // Return detailed error for debugging
            let errorMessage = 'فشل إنشاء حساب جديد. يرجى المحاولة مرة أخرى.';

            if (isConnectionError(createError)) {
              errorMessage = 'فشل الاتصال بقاعدة البيانات. يرجى المحاولة مرة أخرى.';
            } else if (errorCode === 'P1001') {
              errorMessage = 'لا يمكن الاتصال بقاعدة البيانات. يرجى المحاولة مرة أخرى لاحقاً.';
            } else if (errorCode === 'P1017') {
              errorMessage = 'تم إغلاق الاتصال بقاعدة البيانات. يرجى المحاولة مرة أخرى.';
            } else if ((createError as any).meta?.target) {
              errorMessage = `فشل إنشاء حساب: ${(createError as any).meta.target.join(', ')}`;
            } else if (errorMsg) {
              // In development, show more details
              if (process.env.NODE_ENV === 'development') {
                errorMessage = `فشل إنشاء حساب: ${errorMsg}`;
              }
            }

            return NextResponse.redirect(
              `${process.env.NEXT_PUBLIC_BASE_URL || 'http://localhost:3000'}/login?error=database_error&message=${encodeURIComponent(errorMessage)}`
            );
          }
        }
      }

      // Ensure user exists before proceeding
      if (!user) {
        logger.error('Google OAuth: User is null after all attempts');
        return NextResponse.redirect(
          `${process.env.NEXT_PUBLIC_BASE_URL || 'http://localhost:3000'}/login?error=database_error&message=${encodeURIComponent('فشل الحصول على معلومات المستخدم. يرجى المحاولة مرة أخرى.')}`
        );
      }

      // Generate JWT token
      const token = await generateToken(user.id, user.email, user.name || undefined);

      // Get redirect path from cookie (set during OAuth initiation)
      const redirectPath = req.cookies.get('oauth_redirect')?.value || '/';

      // Validate redirect path (security measure)
      const safeRedirectPath = redirectPath.startsWith('/') && !redirectPath.startsWith('//')
        ? redirectPath
        : '/';

      // Create response with redirect
      const baseUrl = process.env.NEXT_PUBLIC_BASE_URL || 'http://localhost:3000';
      const response = NextResponse.redirect(
        `${baseUrl}${safeRedirectPath}`
      );

      // Security: Use centralized secure cookie settings
      // Set token in cookie - use access_token for consistency with login route
      response.cookies.set('access_token', token, {
        ...getSecureCookieOptions({ maxAge: 7 * 24 * 60 * 60 }), // 7 days
      });

      // Log security event for successful login
      await logSecurityEventSafely(user.id, 'USER_LOGIN_OAUTH', {
        provider: 'google',
        email: user.email,
        ip: req.headers.get('x-forwarded-for') || req.headers.get('x-real-ip') || 'unknown',
        userAgent: req.headers.get('user-agent') || 'unknown',
      });

      // Clear state and redirect cookies
      response.cookies.set('oauth_state', '', {
        ...getSecureCookieOptions({ maxAge: 0 }),
      });
      response.cookies.set('oauth_redirect', '', {
        ...getSecureCookieOptions({ maxAge: 0 }),
      });

      return response;
    } catch (error: unknown) {
      // Enhanced error logging
      const errorDetails = {
        error,
        errorType: typeof error,
        errorConstructor: error instanceof Error ? error.constructor.name : 'unknown',
        errorMessage: error instanceof Error ? error.message : String(error),
        errorStack: error instanceof Error ? error.stack : undefined,
        errorCode: error && typeof error === 'object' && 'code' in error ? (error as any).code : undefined,
      };

      logger.error('Error in Google OAuth callback:', errorDetails);

      let errorMessage = 'حدث خطأ غير متوقع أثناء تسجيل الدخول بجوجل. يرجى المحاولة مرة أخرى.';
      let errorCode = 'server_error';

      if (error instanceof Error) {
        const errorMsg = error.message.toLowerCase();

        // Network errors
        if (errorMsg.includes('fetch') || errorMsg.includes('network') ||
          errorMsg.includes('econnrefused') || errorMsg.includes('enotfound') ||
          errorMsg.includes('etimedout') || errorMsg.includes('econnreset')) {
          errorMessage = 'فشل الاتصال بخادم Google. يرجى التحقق من اتصال الإنترنت والمحاولة مرة أخرى.';
          errorCode = 'network_error';
        }
        // Database connection errors
        else if (isConnectionError(error) ||
          errorMsg.includes('database') ||
          errorMsg.includes('prisma') ||
          errorMsg.includes('p1001') ||
          errorMsg.includes('p1017') ||
          errorMsg.includes('p2002') ||
          errorMsg.includes('connection') ||
          errorMsg.includes('timeout')) {
          errorMessage = 'فشل الاتصال بقاعدة البيانات. يرجى التحقق من اتصال الإنترنت والمحاولة مرة أخرى.';
          errorCode = 'database_error';

          // Try to ensure database is properly closed on error
          try {
            await prisma.$disconnect().catch(() => {
              // Ignore disconnect errors
            });
          } catch (disconnectError) {
            // Ignore disconnect errors
          }
        }
        // OAuth configuration errors
        else if (errorMsg.includes('oauth') || errorMsg.includes('client_id') ||
          errorMsg.includes('client_secret') || errorMsg.includes('secret')) {
          errorMessage = 'خطأ في إعدادات تسجيل الدخول. يرجى التواصل مع الدعم الفني.';
          errorCode = 'oauth_error';
        }
        // JWT/Token errors (check before timeout since jwt/token are more specific)
        else if ((errorMsg.includes('jwt') || errorMsg.includes('token')) && !errorMsg.includes('timeout')) {
          errorMessage = 'خطأ في إنشاء رمز المصادقة. يرجى المحاولة مرة أخرى.';
          errorCode = 'token_error';
        }
        // Timeout errors (check after token to avoid conflicts)
        else if (errorMsg.includes('timeout')) {
          errorMessage = 'انتهت مهلة الاتصال. يرجى المحاولة مرة أخرى.';
          errorCode = 'timeout_error';
        }
        // Development mode - show more details
        else if (process.env.NODE_ENV === 'development') {
          errorMessage = `خطأ في التطوير: ${error.message}`;
        }
      } else if (error && typeof error === 'object') {
        // Handle object errors (Prisma errors, etc.)
        const errorObj = error as any;
        if (errorObj.code) {
          const prismaCode = String(errorObj.code);
          if (prismaCode.startsWith('P1')) {
            errorMessage = 'فشل الاتصال بقاعدة البيانات. يرجى المحاولة مرة أخرى.';
            errorCode = 'database_error';
          } else if (prismaCode.startsWith('P2')) {
            errorMessage = 'حدث خطأ أثناء معالجة البيانات. يرجى المحاولة مرة أخرى.';
            errorCode = 'database_error';
          } else {
            errorCode = prismaCode.toLowerCase();
          }
        }

        if (errorObj.message) {
          errorMessage = errorObj.message;
        }
      }

      // Ensure safe redirect URL
      const baseUrl = process.env.NEXT_PUBLIC_BASE_URL || 'http://localhost:3000';
      const redirectUrl = `${baseUrl}/login?error=${encodeURIComponent(errorCode)}&message=${encodeURIComponent(errorMessage)}`;

      return NextResponse.redirect(redirectUrl);
    }
  });
}

import { NextRequest, NextResponse } from 'next/server';
import { authService } from '@/lib/services/auth-service';
import { opsWrapper } from '@/lib/middleware/ops-middleware';
import {
  clearAuthCookies,
  createStandardErrorResponse,
  createSuccessResponse,
  parseRequestBody,
  extractRequestMetadata,
  logSecurityEventSafely
} from '@/app/api/auth/_helpers';

import { logger } from '@/lib/logger';

/**
 * Helper to extract and validate session from token
 */
async function extractSessionFromToken(token: string | null): Promise<{
  sessionId: string | null;
  userId: string | null;
}> {
  if (!token) return { sessionId: null, userId: null };

  try {
    const decoded = await authService.verifyTokenFromInput(token);
    if (decoded.isValid && decoded.sessionId) {
      const session = await authService.getSession(decoded.sessionId);
      return {
        sessionId: decoded.sessionId,
        userId: session?.userId || decoded.userId || null
      };
    }
  } catch {
    // Silent fail - logout should proceed regardless
  }

  return { sessionId: null, userId: null };
}

export async function POST(request: NextRequest) {
  return opsWrapper(request, async (req) => {
    const { ip, userAgent } = extractRequestMetadata(req);

    try {
      // Extract token
      const token = authService.extractToken(req);

      // Parse body for logout options
      const bodyResult = await parseRequestBody<{
        logoutAllDevices?: boolean;
      }>(req, { maxSize: 128, required: false });

      const logoutAllDevices = bodyResult.success && bodyResult.data.logoutAllDevices === true;

      // Get session info from token
      const { sessionId, userId } = await extractSessionFromToken(token);

      // Execute logout operations if we have valid session info
      if (userId) {
        try {
          if (logoutAllDevices) {
            await authService.deleteAllUserSessions(userId);
          } else if (sessionId) {
            await authService.deleteSession(sessionId);
          }

          // Log security event (non-blocking)
          logSecurityEventSafely(
            userId,
            logoutAllDevices ? 'logout_all_devices' : 'logout',
            { ip, userAgent, sessionId }
          ).catch(() => { /* Silent fail for logging */ });
        } catch (error) {
          logger.warn('Error during logout cleanup:', error);
          // Continue - don't fail the logout
        }
      }

      // Create response
      const response = createSuccessResponse({
        message: 'تم تسجيل الخروج بنجاح.'
      });

      // Clear all auth cookies
      clearAuthCookies(response);

      return response;
    } catch (error) {
      logger.error('Logout error:', error);
      return createStandardErrorResponse(
        error,
        'حدث خطأ غير متوقع أثناء معالجة طلب تسجيل الخروج. حاول مرة أخرى لاحقاً.'
      );
    }
  });
}

import { NextRequest, NextResponse } from 'next/server';
import { createAndSendMagicLink } from '@/lib/passwordless/magic-link-service';
import { authService } from '@/lib/services/auth-service';
import { opsWrapper } from "@/lib/middleware/ops-middleware";
import { logger } from '@/lib/logger';
import { createErrorResponse, createSuccessResponse, parseRequestBody, magicLinkSchema } from '@/app/api/auth/_helpers';

/**
 * POST /api/auth/magic-link
 * طلب رابط سحري لتسجيل الدخول
 */
export async function POST(request: NextRequest) {
  return opsWrapper(request, async (req) => {
    try {
      const bodyResult = await parseRequestBody<{ email: string }>(req, { required: true });

      if (!bodyResult.success) {
        return bodyResult.error;
      }

      // Use Zod schema for validation
      const parsed = magicLinkSchema.safeParse(bodyResult.data);
      if (!parsed.success) {
        const firstError = parsed.error.issues[0]?.message || 'البريد الإلكتروني غير صحيح';
        return createErrorResponse(firstError, firstError, 400);
      }

      const { email } = parsed.data;
      const ip = authService.getClientIP(req);
      const userAgent = authService.getUserAgent(req);

      const result = await createAndSendMagicLink(email, ip, userAgent);

      // Always return success to prevent email enumeration
      return createSuccessResponse({
        expiresIn: result.expiresIn,
        message: 'إذا كان البريد مسجلاً لدينا، ستتلقى رابط تسجيل الدخول.',
      });
    } catch (error) {
      logger.error('Magic link error:', error);
      return createErrorResponse(error, 'حدث خطأ أثناء إرسال رابط تسجيل الدخول', 500);
    }
  });
}

import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/db';
import { generateAuthenticationOptions } from '@simplewebauthn/server';
import type { PublicKeyCredentialRequestOptionsJSON } from '@simplewebauthn/types';
import { BiometricChallengeService } from '@/lib/services/auth-challenges-service';
import { opsWrapper } from "@/lib/middleware/ops-middleware";
import { logger } from '@/lib/logger';

async function handler(req: NextRequest) {
  const { userId } = await req.json();

  let allowCredentials: PublicKeyCredentialRequestOptionsJSON['allowCredentials'] = undefined;

  if (userId) {
    const user = await prisma.user.findUnique({
      where: { id: userId },
      include: { biometricCredentials: true },
    });

    if (user) {
      allowCredentials = user.biometricCredentials.map((cred) => ({
        id: cred.credentialId,
        type: 'public-key',
        transports: cred.transports ? JSON.parse(cred.transports) : [],
      }));
    }
  }

  const rpID = new URL(process.env.NEXT_PUBLIC_BASE_URL || 'http://localhost:3000').hostname;

  const options: PublicKeyCredentialRequestOptionsJSON = await generateAuthenticationOptions({
    rpID,
    userVerification: 'preferred',
    allowCredentials,
  });

  // The challenge needs to be stored for the verification step.
  // The old biometric service stored the challenge with a key like `auth-${response.id}`.
  // This is problematic because we don't know the response.id yet.
  // A better approach is to generate a random key for the challenge and send it back to the client.
  // The client will then send it back during the verification step.
  // However, to maintain consistency with the existing (flawed) pattern, we'll create a challenge
  // that is not tied to a user or credential ID yet. The verification step will have to look for it.

  // Let's create a temporary ID for the challenge.
  const challengeId = `auth-challenge-${Date.now()}`;
  await BiometricChallengeService.createChallenge(
    options.challenge,
    'authenticate',
    userId, // Store userId if available
    5 // 5 minutes validity
  );

  // We'll add the challenge itself to the response so the client can use it to find the challenge later.
  // This is not ideal, but it's a way to work with the current challenge service.
  // A better solution would be to return a unique challenge identifier.
  const response = {
    ...options,
    // The PasskeyManager expects the challenge in the response.
    challenge: options.challenge
  };

  return NextResponse.json(response);
}

export async function POST(request: NextRequest) {
  try {
    return await opsWrapper(request, handler);
  } catch (error) {
    logger.error('Error generating passkey authentication options:', error);
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/db';
import { authService } from '@/lib/services/auth-service';
import { getDeviceInfo, getLocationFromIP } from '@/lib/security-utils';
import crypto from 'crypto';
import { verifyAuthenticationResponse } from '@simplewebauthn/server';
import { isoUint8Array } from '@simplewebauthn/server/helpers';
import type { AuthenticationResponseJSON } from '@simplewebauthn/types';
import { opsWrapper } from "@/lib/middleware/ops-middleware";
import { logger } from '@/lib/logger';
import { getSecureCookieOptions } from '@/app/api/auth/_helpers';
import { BiometricChallengeService } from '@/lib/services/auth-challenges-service';

async function handler(req: NextRequest) {
  const responseBody: AuthenticationResponseJSON = await req.json();

  if (!responseBody) {
    return NextResponse.json({ error: 'Authentication response is required' }, { status: 400 });
  }

  // The credential ID is sent in base64url format from the client.
  const credentialId = responseBody.id;

  const credential = await prisma.biometricCredential.findUnique({
    where: { credentialId: credentialId },
    include: { user: true },
  });

  if (!credential) {
    return NextResponse.json({ error: 'Credential not found' }, { status: 404 });
  }

  const user = credential.user;

  if (!user.biometricEnabled) {
    return NextResponse.json({ error: 'Biometric authentication is not enabled for this account' }, { status: 401 });
  }

  // FIX: Extract challenge directly from clientDataJSON to verify we have a matching record
  // instead of blindly picking the first available one.
  let clientChallenge = '';
  try {
    const clientData = JSON.parse(Buffer.from(responseBody.response.clientDataJSON, 'base64').toString('utf8'));
    clientChallenge = clientData.challenge;
  } catch (e) {
    return NextResponse.json({ error: 'Invalid client data' }, { status: 400 });
  }

  // Find the SPECIFIC challenge in DB
  const challengeRecord = await prisma.biometricChallenge.findFirst({
    where: {
      challenge: clientChallenge,
      type: 'authenticate',
      used: false,
      userId: user.id, // Security hardening: Ensure challenge belongs to user
      expiresAt: { gt: new Date() }
    }
  });

  if (!challengeRecord) {
    return NextResponse.json({ error: 'Invalid or expired challenge' }, { status: 400 });
  }

  const expectedChallenge = challengeRecord.challenge;


  let verification;
  try {
    const rpID = new URL(process.env.NEXT_PUBLIC_BASE_URL || 'http://localhost:3000').hostname;

    verification = await verifyAuthenticationResponse({
      response: responseBody,
      expectedChallenge: expectedChallenge,
      expectedOrigin: process.env.NEXT_PUBLIC_BASE_URL || 'http://localhost:3000',
      expectedRPID: rpID,
      credential: {
        id: credential.credentialId,
        publicKey: isoUint8Array.fromHex(credential.publicKey),
        counter: credential.counter,
      },
      requireUserVerification: true,
    });
  } catch (error) {
    logger.error('Passkey authentication verification failed:', { error });
    const errorMessage = error instanceof Error ? error.message : 'Unknown error';
    return NextResponse.json({ error: `Verification failed: ${errorMessage}` }, { status: 400 });
  }

  const { verified, authenticationInfo } = verification;

  if (!verified) {
    return NextResponse.json({ error: 'Could not verify authentication' }, { status: 400 });
  }

  // Mark the challenge as used
  await BiometricChallengeService.deleteChallenge(challengeRecord.id);

  // Update the credential counter
  await prisma.biometricCredential.update({
    where: { id: credential.id },
    data: { counter: authenticationInfo.newCounter },
  });

  // Create tokens first to get a refresh token
  const tempTokens = await authService.createTokens({
    id: user.id,
    email: user.email,
    name: user.name || undefined,
    role: user.role || undefined,
  });

  // Create session
  const ip = req.headers.get('x-forwarded-for') || req.headers.get('x-real-ip') || 'unknown';
  const userAgent = req.headers.get('user-agent') || 'unknown';
  const session = await authService.createSession(user.id, tempTokens.refreshToken, userAgent, ip);

  // Create tokens
  const tokensResult = await authService.createTokens(
    {
      id: user.id,
      email: user.email,
      name: user.name || undefined,
      role: user.role || undefined,
    },
    session.id
  );

  // Update session with final refresh token
  await prisma.session.update({
    where: { id: session.id },
    data: { refreshToken: tokensResult.refreshToken }
  });

  // Log security event
  const deviceInfo = await getDeviceInfo(userAgent);
  const location = await getLocationFromIP(ip);
  await prisma.securityLog.create({
    data: {
      id: crypto.randomUUID(),
      userId: user.id,
      eventType: 'PASSKEY_LOGIN_SUCCESS',
      ip,
      userAgent,
      deviceInfo: JSON.stringify(deviceInfo),
      location,
      metadata: JSON.stringify({ sessionId: session.id, credentialId: credential.credentialId })
    }
  });

  const { passwordHash, ...userData } = user;

  const response = NextResponse.json({
    message: 'Authentication successful',
    user: userData,
    token: tokensResult.accessToken,
  });

  response.cookies.set('refresh_token', tokensResult.refreshToken, {
    ...getSecureCookieOptions({ maxAge: 30 * 24 * 60 * 60 }), // 30 days
  });

  return response;
}

export async function POST(request: NextRequest) {
  try {
    return await opsWrapper(request, handler);
  } catch (error) {
    logger.error('Error during passkey authentication:', error);
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/db';
import { verifyRegistrationResponse } from '@simplewebauthn/server';
import type { RegistrationResponseJSON } from '@simplewebauthn/types';
import { BiometricChallengeService } from '@/lib/services/auth-challenges-service';
import { opsWrapper } from "@/lib/middleware/ops-middleware";
import { logger } from '@/lib/logger';
import { isoUint8Array } from '@simplewebauthn/server/helpers';

async function handler(req: NextRequest) {
  const { userId, deviceName, transports = [], ...registrationResponse } = await req.json();

  if (!userId || !registrationResponse) {
    return NextResponse.json({ error: 'User ID and registration response are required' }, { status: 400 });
  }

  const user = await prisma.user.findUnique({
    where: { id: userId },
  });

  if (!user) {
    return NextResponse.json({ error: 'User not found' }, { status: 404 });
  }

  // Find the challenge that was generated for this registration
  // The BiometricChallengeService doesn't store the challenge with a specific key,
  // so we have to find it by userId and type. This is not ideal, but we'll follow the existing pattern.
  const challenges = await prisma.biometricChallenge.findMany({
    where: {
      userId: userId,
      type: 'register',
      used: false,
      expiresAt: { gt: new Date() }
    }
  });

  const expectedChallenge = challenges.length > 0 ? challenges[0].challenge : undefined;

  if (!expectedChallenge) {
    return NextResponse.json({ error: 'No valid registration challenge found for this user.' }, { status: 400 });
  }

  let verification;
  try {
    const rpID = new URL(process.env.NEXT_PUBLIC_BASE_URL || 'http://localhost:3000').hostname;

    verification = await verifyRegistrationResponse({
      response: registrationResponse,
      expectedChallenge: expectedChallenge,
      expectedOrigin: process.env.NEXT_PUBLIC_BASE_URL || 'http://localhost:3000',
      expectedRPID: rpID,
      requireUserVerification: true,
    });
  } catch (error) {
    logger.error('Passkey registration verification failed:', { error });
    const errorMessage = error instanceof Error ? error.message : 'Unknown error';
    return NextResponse.json({ error: `Verification failed: ${errorMessage}` }, { status: 400 });
  }

  const { verified, registrationInfo } = verification;

  if (!verified || !registrationInfo) {
    return NextResponse.json({ error: 'Could not verify registration' }, { status: 400 });
  }

  // Mark the challenge as used
  await BiometricChallengeService.deleteChallenge(challenges[0].id);

  const { credential } = registrationInfo;
  const { publicKey: credentialPublicKey, id: credentialID, counter } = credential;

  // Store the new credential in the `BiometricCredential` table
  const newCredential = await prisma.biometricCredential.create({
    data: {
      user: {
        connect: {
          id: user.id
        }
      },
      credentialId: credentialID,
      publicKey: isoUint8Array.toHex(credentialPublicKey),
      counter: counter,
      // The PasskeyManager doesn't seem to send deviceType, so we'll leave it nullable
      // deviceType: registrationResponse.transports,
      deviceName: deviceName,
      transports: Array.isArray(transports) ? transports.join(',') : transports
    }
  });

  // Update the user to reflect that they have a biometric credential enabled
  await prisma.user.update({
    where: { id: user.id },
    data: {
      biometricEnabled: true,
    },
  });

  return NextResponse.json({ verified: true, credential: newCredential });
}

export async function POST(request: NextRequest) {
  try {
    return await opsWrapper(request, handler);
  } catch (error) {
    logger.error('Error during passkey registration:', error);
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { authService } from '@/lib/services/auth-service';
import { registerSchema } from '@/lib/validations/auth';
import { setAuthCookies, createErrorResponse } from '@/lib/auth-utils';

export async function POST(req: NextRequest) {
  try {
    const body = await req.json();

    // 1. Validate Body
    const parsed = registerSchema.safeParse(body);
    if (!parsed.success) {
      return NextResponse.json(
        {
          error: 'بيانات غير صالحة',
          details: parsed.error.flatten().fieldErrors,
          code: 'VALIDATION_ERROR'
        },
        { status: 400 }
      );
    }

    const { email, password, name } = parsed.data;

    // 2. Check if user already exists
    const existingUser = await authService.getUserByEmail(email);
    if (existingUser) {
      return NextResponse.json(
        { error: 'البريد الإلكتروني مستخدم بالفعل', code: 'EMAIL_IN_USE' },
        { status: 409 }
      );
    }

    // 3. Create User
    const newUser = await authService.createUser(parsed.data);

    // 4. Generate Tokens
    // Ensure role is a string
    const userRole = newUser.role || "USER";
    const tokenPayload = { userId: newUser.id, email: newUser.email, role: userRole };
    const accessToken = await authService.generateToken(tokenPayload, '1h');
    const refreshToken = await authService.generateToken(tokenPayload, '1d');

    // 5. Create Response
    const response = NextResponse.json({
      success: true,
      user: {
        id: newUser.id,
        name: newUser.name,
        email: newUser.email,
        role: userRole,
        avatar: newUser.avatar || null,
        emailVerified: false,
        twoFactorEnabled: false,
        lastLogin: null,
        createdAt: newUser.createdAt,
        provider: 'local',
      },
      token: accessToken
    }, { status: 201 });

    // 6. Set Cookies
    setAuthCookies(response, accessToken, refreshToken, false);

    return response;

  } catch (error) {
    console.error('Register route error:', error);
    return createErrorResponse(error);
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { authService } from '@/lib/services/auth-service';
import { TwoFactorChallengeService } from '@/lib/services/auth-challenges-service';
import { opsWrapper } from "@/lib/middleware/ops-middleware";
import { logger } from '@/lib/logger';
import { prisma } from '@/lib/db';
import { createErrorResponse, createSuccessResponse, parseRequestBody } from '@/app/api/auth/_helpers';

export async function POST(request: NextRequest) {
   return opsWrapper(request, async (req) => {
      try {
         const bodyResult = await parseRequestBody<{
            loginAttemptId: string;
            method?: string;
         }>(req, { required: true });

         if (!bodyResult.success) {
            return bodyResult.error;
         }

         const { loginAttemptId, method } = bodyResult.data;

         if (!loginAttemptId) {
            return createErrorResponse('Missing loginAttemptId', '���� �������� �����', 400);
         }

         // Check if it's a JWT (TOTP flow)
         // JWTs have 3 parts separated by dots
         if (loginAttemptId.split('.').length === 3) {
            // It's a JWT. Verify it.
            const verification = await authService.verifyTokenFromInput(loginAttemptId);
            if (!verification.isValid || !verification.user) {
               return createErrorResponse('���� ��� �����', '���� ��� �����', 401);
            }

            // If method is email, we can generate a challenge and send it.
            if (method === 'email') {
               const code = Math.floor(100000 + Math.random() * 900000).toString();
               const challengeId = await TwoFactorChallengeService.createChallenge(verification.user.id, code);

               // Send email (mock for now, or use email service if available)
               logger.info(`Sending 2FA code ${code} to ${verification.user.email}`);

               return createSuccessResponse({
                  loginAttemptId: challengeId // Return new ID for the challenge
               }, '�� ����� ����� ��� ������ ����������');
            }

            return createErrorResponse(
               '�� ���� ����� ����� ����� �� TOTP. ������ ���� ���������.',
               '�� ���� ����� ����� ����� �� TOTP. ������ ���� ���������.',
               400
            );
         }

         // It's a UUID (Challenge flow)
         const challenge = await TwoFactorChallengeService.getChallenge(loginAttemptId);
         if (!challenge) {
            return createErrorResponse('���� ��� ����', '���� ��� ����', 400);
         }

         if (challenge.used) {
            return createErrorResponse('�� ������� ������ ������', '�� ������� ������ ������', 400);
         }

         // Generate new code
         const newCode = Math.floor(100000 + Math.random() * 900000).toString();
         const newChallengeId = await TwoFactorChallengeService.createChallenge(challenge.userId!, newCode);

         // Send email
         const user = await prisma.user.findUnique({ where: { id: challenge.userId! } });
         if (user) {
            logger.info(`Resending 2FA code ${newCode} to ${user.email}`);
         }

         return createSuccessResponse({
            loginAttemptId: newChallengeId
         }, '�� ����� ����� �����');

      } catch (error) {
         logger.error('Resend error:', error);
         return createErrorResponse(error, '��� ��� �� ������', 500);
      }
   });
}

import { NextRequest, NextResponse } from 'next/server';
import { opsWrapper } from '@/lib/middleware/ops-middleware';
import { logger } from '@/lib/logger';
import { authService } from '@/lib/services/auth-service';
import {
    createStandardErrorResponse,
    createSuccessResponse,
    parseRequestBody,
    extractRequestMetadata,
    logSecurityEventSafely,
    addSecurityHeaders
} from '@/lib/auth-utils';
import { z } from 'zod';

import { passwordSchema } from '@/lib/validations/auth';

const resetPasswordSchema = z.object({
    token: z.string().min(1, 'رمز إعادة التعيين مطلوب'),
    password: passwordSchema,
});

export async function POST(request: NextRequest) {
    return opsWrapper(request, async (req) => {
        const { ip, userAgent } = extractRequestMetadata(req);

        try {
            const bodyResult = await parseRequestBody<{ token?: string; password?: string }>(req, {
                maxSize: 1024,
                required: true,
            });

            if (!bodyResult.success) {
                return bodyResult.error;
            }

            const parsed = resetPasswordSchema.safeParse(bodyResult.data);

            if (!parsed.success) {
                return createStandardErrorResponse(
                    {
                        error: 'VALIDATION_ERROR',
                        details: parsed.error.flatten().fieldErrors,
                    },
                    'البيانات المدخلة غير صحيحة.',
                    400
                );
            }

            const { token, password } = parsed.data;

            await authService.resetPassword(token, password, ip, userAgent);

            await logSecurityEventSafely(null, 'password_reset_success', {
                ip,
                userAgent,
            });

            return createSuccessResponse({
                message: 'تم تغيير كلمة المرور بنجاح. يمكنك الآن تسجيل الدخول.',
            });

        } catch (error) {
            logger.error('Reset password route error:', error);
            return createStandardErrorResponse(
                error,
                'حدث خطأ أثناء إعادة تعيين كلمة المرور. قد يكون الرابط منتهي الصلاحية.'
            );
        }
    });
