/**
 * 🌍 Geo Sessions API
 * 
 * إرجاع جلسات المستخدم مع معلومات الموقع الجغرافي
 */

import { NextRequest, NextResponse } from 'next/server';
import { AuthService } from '@/lib/services/auth-service';
import { prisma } from '@/lib/db';
import { logger } from '@/lib/logger';
import { getGeoLocationService } from '@/lib/security/geo/geo-location-service';

export async function GET(request: NextRequest) {
    try {
        // Get token from Authorization header
        const authHeader = request.headers.get('authorization');
        const token = authHeader?.replace('Bearer ', '');

        if (!token) {
            return NextResponse.json(
                { error: 'غير مصرح لك بالوصول' },
                { status: 401 }
            );
        }

        // Find session by refresh token
        const currentSession = await prisma.session.findFirst({
            where: {
                refreshToken: token,
                isActive: true,
                expiresAt: { gt: new Date() },
            },
            select: { id: true, userId: true },
        });

        if (!currentSession) {
            return NextResponse.json(
                { error: 'جلسة غير صالحة' },
                { status: 401 }
            );
        }

        const userId = currentSession.userId;
        const currentSessionId = currentSession.id;
        const geoService = getGeoLocationService();

        // Get user sessions
        const sessions = await prisma.session.findMany({
            where: {
                userId,
                expiresAt: { gt: new Date() },
            },
            orderBy: { lastAccessed: 'desc' },
            take: 20,
        });

        // Get security logs for location data
        const securityLogs = await prisma.securityLog.findMany({
            where: {
                userId,
                eventType: 'LOGIN_SUCCESS',
            },
            orderBy: { createdAt: 'desc' },
            take: 20,
        });

        // Build geo sessions
        const geoSessions = await Promise.all(
            sessions.map(async (sess) => {
                // Find matching security log for location
                const log = securityLogs.find(l =>
                    Math.abs(new Date(l.createdAt).getTime() - new Date(sess.createdAt).getTime()) < 60000
                );

                let location;
                const ip = log?.ip || sess.ip || '127.0.0.1';

                if (log?.location) {
                    // Parse stored location
                    try {
                        location = JSON.parse(log.location);
                    } catch {
                        location = await geoService.getLocationFromIP(ip);
                    }
                } else {
                    location = await geoService.getLocationFromIP(ip);
                }

                // Parse device info
                let device = 'Unknown';
                let browser = 'Unknown';

                if (sess.deviceInfo) {
                    device = sess.deviceInfo;
                }

                const isCurrentSession = sess.id === currentSessionId;

                return {
                    sessionId: sess.id,
                    userId,
                    location: location || {
                        ip,
                        country: 'Unknown',
                        countryCode: 'XX',
                        region: '',
                        regionCode: '',
                        city: 'Unknown',
                        lat: 0,
                        lng: 0,
                        timezone: 'UTC',
                    },
                    timestamp: sess.createdAt,
                    device,
                    browser,
                    isCurrentSession,
                    isSuspicious: false,
                };
            })
        );

        // Get unique countries
        const uniqueCountries = [...new Set(geoSessions.map(s => s.location.country))];
        const uniqueCities = [...new Set(geoSessions.map(s => s.location.city))];

        return NextResponse.json({
            sessions: geoSessions,
            stats: {
                totalSessions: geoSessions.length,
                uniqueCountries,
                uniqueCities,
                suspiciousCount: geoSessions.filter(s => s.isSuspicious).length,
            },
        });

    } catch (error) {
        logger.error('Error fetching geo sessions:', error);

        return NextResponse.json(
            { error: 'حدث خطأ أثناء تحميل البيانات' },
            { status: 500 }
        );
    }
}

/**
 * 🚪 Revoke All Sessions API
 * 
 * إنهاء جميع الجلسات الأخرى للمستخدم الحالي
 */

import { NextRequest, NextResponse } from 'next/server';
import { AuthService } from '@/lib/services/auth-service';
import { prisma } from '@/lib/db';
import { logger } from '@/lib/logger';

export async function POST(request: NextRequest) {
    try {
        const authService = AuthService.getInstance();

        // Get token from Authorization header
        const authHeader = request.headers.get('authorization');
        const token = authHeader?.replace('Bearer ', '');

        if (!token) {
            return NextResponse.json(
                { error: 'غير مصرح لك بالوصول' },
                { status: 401 }
            );
        }

        // Find session by refresh token
        const currentSession = await prisma.session.findFirst({
            where: {
                refreshToken: token,
                isActive: true,
                expiresAt: { gt: new Date() },
            },
            select: { id: true, userId: true },
        });

        if (!currentSession) {
            return NextResponse.json(
                { error: 'جلسة غير صالحة' },
                { status: 401 }
            );
        }

        const userId = currentSession.userId;
        const currentSessionId = currentSession.id;

        // Delete all other sessions for this user
        const result = await prisma.session.deleteMany({
            where: {
                userId: userId,
                id: {
                    not: currentSessionId,
                },
            },
        });

        logger.info('Revoked all other sessions', {
            userId,
            revokedCount: result.count,
        });

        return NextResponse.json({
            success: true,
            message: `تم إنهاء ${result.count} جلسة بنجاح`,
            revokedCount: result.count,
        });

    } catch (error) {
        logger.error('Error revoking all sessions:', error);

        return NextResponse.json(
            { error: 'حدث خطأ أثناء إنهاء الجلسات' },
            { status: 500 }
        );
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { authService } from '@/lib/services/auth-service';
import { addSecurityHeaders, createStandardErrorResponse, parseRequestBody } from '@/app/api/auth/_helpers';
import { logger } from '@/lib/logger';

export async function GET(request: NextRequest) {
  try {
    const authResult = await authService.getCurrentUser();
    if (!authResult.isValid || !authResult.user) {
      return NextResponse.json(
        { error: 'Unauthorized', code: 'UNAUTHORIZED' },
        { status: 401 }
      );
    }

    const sessions = await authService.getUserSessions(authResult.user.id);
    
    // Map to safe response format
    const safeSessions = sessions.map(session => ({
      id: session.id,
      userAgent: session.userAgent,
      ip: session.ip,
      deviceInfo: session.deviceInfo ? JSON.parse(session.deviceInfo) : null,
      createdAt: session.createdAt,
      lastAccessed: session.lastAccessed,
      isCurrent: session.id === authResult.sessionId
    }));

    const response = NextResponse.json({
      sessions: safeSessions
    });

    return addSecurityHeaders(response);
  } catch (error) {
    logger.error('Get sessions error:', error);
    return createStandardErrorResponse(error, 'Failed to retrieve sessions');
  }
}

export async function DELETE(request: NextRequest) {
  try {
    const authResult = await authService.getCurrentUser();
    if (!authResult.isValid || !authResult.user) {
      return NextResponse.json(
        { error: 'Unauthorized', code: 'UNAUTHORIZED' },
        { status: 401 }
      );
    }

    const bodyResult = await parseRequestBody<{ sessionId: string }>(request);
    if (!bodyResult.success) return bodyResult.error;

    const { sessionId } = bodyResult.data;

    if (!sessionId) {
      return NextResponse.json(
        { error: 'Session ID is required', code: 'MISSING_FIELDS' },
        { status: 400 }
      );
    }

    // Prevent revoking current session via this endpoint (use logout instead)
    if (sessionId === authResult.sessionId) {
      return NextResponse.json(
        { error: 'Cannot revoke current session via this endpoint', code: 'INVALID_OPERATION' },
        { status: 400 }
      );
    }

    const success = await authService.revokeSession(sessionId, authResult.user.id);

    if (!success) {
      return NextResponse.json(
        { error: 'Session not found or could not be revoked', code: 'OPERATION_FAILED' },
        { status: 404 }
      );
    }

    const response = NextResponse.json({
      success: true,
      message: 'Session revoked successfully'
    });

    return addSecurityHeaders(response);
  } catch (error) {
    logger.error('Revoke session error:', error);
    return createStandardErrorResponse(error, 'Failed to revoke session');
  }
}

import { NextRequest, NextResponse } from 'next/server';
import bcrypt from 'bcryptjs';
import { prisma } from '@/lib/db';
import { SignJWT, jwtVerify } from 'jose';
import { TextEncoder } from 'util';
import { TwoFactorChallengeService } from '@/lib/services/auth-challenges-service';
import { authService } from '@/lib/services/auth-service';
import { verifyTOTP, disableTOTP, generateSecret } from '@/lib/two-factor/totp-service';
import { verifyAndConsumeRecoveryCode, generateRecoveryCodes } from '@/lib/two-factor/recovery-codes';
import { securityLogger } from '@/lib/security-logger';
import { securityNotificationService } from '@/lib/security/security-notifications';
import type { TwoFactorVerifyRequest, TwoFactorVerifyResponse, TwoFactorErrorResponse } from '@/types/api/auth';
import { setAuthCookies, createErrorResponse, parseRequestBody, createStandardErrorResponse } from '@/lib/auth-utils';
import { opsWrapper } from "@/lib/middleware/ops-middleware";
import { logger } from '@/lib/logger';
import { getJWTSecret } from '@/lib/env-validation';
import type { Prisma } from '@prisma/client';
import QRCode from 'qrcode';
import { authenticator } from 'otplib';

// Type for user with 2FA fields
type UserWith2FA = Prisma.UserGetPayload<{
  select: {
    id: true;
    email: true;
    name: true;
    role: true;
    twoFactorEnabled: true;
    twoFactorSecret: true;
    recoveryCodes: true;
  }
}>;

// Security: JWT_SECRET is required - no fallback values allowed
let JWT_SECRET: Uint8Array | null = null;

function getJWTSecretSafe(): Uint8Array {
  if (!JWT_SECRET) {
    const secretString = getJWTSecret();
    JWT_SECRET = new TextEncoder().encode(secretString);
  }
  return JWT_SECRET;
}

// Generate a new 2FA verification code
export async function GET(request: NextRequest) {
  return opsWrapper(request, async (req) => {
    try {
      // Generate a 6-digit code
      const code = Math.floor(100000 + Math.random() * 900000).toString();

      // Generate a unique ID for this login attempt
      const loginAttemptId = Math.random().toString(36).substring(2, 15) + Math.random().toString(36).substring(2, 15);

      // Store the attempt in database (expires in 10 minutes)
      await TwoFactorChallengeService.createChallenge('', code, 10);

      return NextResponse.json({
        loginAttemptId
        // Removed code from response for security - it should only be sent via email/SMS
      });
    } catch (error) {
      logger.error('Error generating 2FA code:', error);
      return NextResponse.json(
        { error: 'Internal server error' },
        { status: 500 }
      );
    }
  });
}

// Combined POST handler for both 2FA login verification and management
interface TwoFactorBody {
  loginAttemptId?: string;
  code?: string;
  action?: string;
  userId?: string;
  backupCode?: string;
  trustDevice?: boolean;
}

export async function POST(request: NextRequest) {
  return opsWrapper(request, async (req) => {
    try {
      const bodyResult = await parseRequestBody<TwoFactorBody>(req, { maxSize: 2048 });
      if (!bodyResult.success) return bodyResult.error;

      const body = bodyResult.data;
      const { loginAttemptId, code, action, userId, backupCode } = body;

      // If loginAttemptId is provided, this is a login verification request
      if (loginAttemptId) {
        // Verify 2FA code for login
        if (!code) {
          return NextResponse.json(
            { error: 'Code is required' },
            { status: 400 }
          );
        }

        // Enhanced code validation with comprehensive checks
        if (!code || typeof code !== 'string') {
          const errorResponse: TwoFactorErrorResponse = {
            error: 'رمز التحقق مطلوب',
            code: 'MISSING_CODE',
          };
          return NextResponse.json(errorResponse, { status: 400 });
        }

        const trimmedCode = code.trim();
        if (trimmedCode.length === 0) {
          const errorResponse: TwoFactorErrorResponse = {
            error: 'رمز التحقق لا يمكن أن يكون فارغاً',
            code: 'EMPTY_CODE',
          };
          return NextResponse.json(errorResponse, { status: 400 });
        }

        // Validate code format (must be exactly 6 digits)
        if (trimmedCode.length !== 6 || !/^\d{6}$/.test(trimmedCode)) {
          const errorResponse: TwoFactorErrorResponse = {
            error: 'رمز التحقق يجب أن يكون مكون من 6 أرقام',
            code: 'INVALID_CODE_FORMAT',
          };
          return NextResponse.json(errorResponse, { status: 400 });
        }

        // Validate loginAttemptId format
        if (!loginAttemptId || typeof loginAttemptId !== 'string' || loginAttemptId.trim().length === 0) {
          const errorResponse: TwoFactorErrorResponse = {
            error: 'معرف محاولة تسجيل الدخول مطلوب',
            code: 'MISSING_LOGIN_ATTEMPT_ID',
          };
          return NextResponse.json(errorResponse, { status: 400 });
        }

        const trimmedLoginAttemptId = loginAttemptId.trim();
        if (trimmedLoginAttemptId.length < 10 || trimmedLoginAttemptId.length > 100) {
          const errorResponse: TwoFactorErrorResponse = {
            error: 'معرف محاولة تسجيل الدخول غير صحيح',
            code: 'INVALID_LOGIN_ATTEMPT_ID',
          };
          return NextResponse.json(errorResponse, { status: 400 });
        }

        // Verify and consume the challenge from database (with timeout)
        // Use trimmed values for consistency
        const challengePromise = TwoFactorChallengeService.verifyAndConsumeChallenge(trimmedLoginAttemptId, trimmedCode);
        const timeoutPromise = new Promise<{ valid: false }>((resolve) => {
          setTimeout(() => resolve({ valid: false }), 5000); // 5 second timeout
        });

        const challengeResult = await Promise.race([challengePromise, timeoutPromise]);

        if (!challengeResult.valid) {
          const errorResponse: TwoFactorErrorResponse = {
            error: 'رمز التحقق غير صحيح أو منتهي الصلاحية',
            code: 'INVALID_OR_EXPIRED',
          };
          return NextResponse.json(errorResponse, { status: 400 });
        }

        if (!challengeResult.userId) {
          const errorResponse: TwoFactorErrorResponse = {
            error: 'رمز التحقق غير صحيح أو منتهي الصلاحية',
            code: 'INVALID_OR_EXPIRED',
          };
          return NextResponse.json(errorResponse, { status: 400 });
        }

        // Fetch user with timeout
        const userPromise = prisma.user.findUnique({
          where: { id: challengeResult.userId },
          select: {
            id: true,
            email: true,
            name: true,
            role: true,
            twoFactorEnabled: true,
            lastLogin: true,
          }
        });

        const userTimeoutPromise = new Promise<null>((resolve) => {
          setTimeout(() => resolve(null), 3000); // 3 second timeout
        });

        const user = await Promise.race([userPromise, userTimeoutPromise]);

        if (!user) {
          const errorResponse: TwoFactorErrorResponse = {
            error: 'المستخدم غير موجود',
            code: 'USER_NOT_FOUND',
          };
          return NextResponse.json(errorResponse, { status: 404 });
        }

        const ip = authService.getClientIP(req);
        const userAgent = authService.getUserAgent(req);
        const clientId = `${ip}-${userAgent}`;
        const rememberDevice = Boolean(body.trustDevice);
        const loginTimestamp = new Date();

        await authService.resetRateLimit(clientId);

        // Create tokens first to get a refresh token
        const tempTokens = await authService.createTokens({
          id: user.id,
          email: user.email,
          name: user.name || undefined,
          role: user.role || undefined,
        });

        const session = await authService.createSession(user.id, tempTokens.refreshToken, userAgent, ip);
        const { accessToken, refreshToken } = await authService.createTokens(
          {
            id: user.id,
            email: user.email,
            name: user.name || undefined,
            role: user.role || undefined,
          },
          session.id,
        );

        // Update session with final refresh token
        await prisma.session.update({
          where: { id: session.id },
          data: { refreshToken }
        });

        // Update user (non-blocking, with timeout)
        Promise.allSettled([
          prisma.user.update({
            where: { id: user.id },
            data: {
              lastLogin: loginTimestamp,
            },
          }),
          authService.logSecurityEvent(user.id, 'two_factor_verified', ip, {
            userAgent,
            sessionId: session.id,
          }),
        ]).catch(() => {
          // Non-critical errors - login can proceed
        });

        const twoFactorResponse: TwoFactorVerifyResponse = {
          message: 'تم التحقق من الرمز بنجاح.',
          user: {
            id: user.id,
            email: user.email,
            name: user.name || undefined,
            role: user.role || 'user',
            emailVerified: false, // Add if available from user
            twoFactorEnabled: user.twoFactorEnabled || false,
            lastLogin: loginTimestamp,
          },
          token: accessToken,
          refreshToken,
          sessionId: session.id,
        };

        const response = NextResponse.json(twoFactorResponse);
        setAuthCookies(response, accessToken, refreshToken, rememberDevice);
        return response;
      }

      // Otherwise, handle 2FA management actions
      if (!action) {
        return NextResponse.json(
          { error: 'Action is required for 2FA management' },
          { status: 400 }
        );
      }

      // Get user ID from token if not provided
      let targetUserId = userId;
      if (!targetUserId) {
        const authHeader = req.headers.get('authorization');
        if (!authHeader || !authHeader.startsWith('Bearer ')) {
          return NextResponse.json(
            { error: 'Authentication required' },
            { status: 401 }
          );
        }

        const token = authHeader.substring(7);
        const { payload } = await jwtVerify(token, getJWTSecretSafe());

        targetUserId = payload.userId as string;
      }

      // Get user with required 2FA fields
      const user = await prisma.user.findUnique({
        where: { id: targetUserId },
        select: {
          id: true,
          email: true,
          name: true,
          role: true,
          twoFactorEnabled: true,
          twoFactorSecret: true,
          recoveryCodes: true,
        }
      });

      if (!user) {
        return NextResponse.json(
          { error: 'User not found' },
          { status: 404 }
        );
      }

      // Rate Limit for Management Actions
      const ip = authService.getClientIP(req);
      const userAgent = authService.getUserAgent(req);
      const clientId = `${ip}-${userAgent}`;

      try {
        await authService.checkRateLimit(clientId);
      } catch (error) {
        await authService.logSecurityEvent(targetUserId, 'two_factor_rate_limit', ip, { userAgent });
        return NextResponse.json(
          { error: 'Too many attempts. Please try again later.' },
          { status: 429 }
        );
      }

      // Handle different actions
      switch (action) {
        case 'setup':
          return await handleSetup2FA(user);
        case 'verify':
          return await handleVerify2FA(user, code || '', req);
        case 'disable':
          return await handleDisable2FA(user, code || '', req);
        case 'backup-code':
          return await handleBackupCode(user, backupCode || '', req);
        default:
          return NextResponse.json(
            { error: 'Invalid action' },
            { status: 400 }
          );
      }
    } catch (error) {
      logger.error('Two-factor authentication error:', error);
      return createErrorResponse(
        error,
        'حدث خطأ غير متوقع أثناء معالجة طلب التحقق ثنائي العامل. حاول مرة أخرى لاحقاً.'
      );
    }
  });
}

// Handle 2FA setup
async function handleSetup2FA(user: UserWith2FA) {
  try {
    // Generate a cryptographically secure secret key using crypto.randomBytes
    const secret = generateSecret();

    // Generate cryptographically secure backup codes
    const backupCodes = generateRecoveryCodes();

    // Store the secret temporarily (not enabled yet)
    await prisma.user.update({
      where: { id: user.id },
      data: {
        twoFactorSecret: secret,
        recoveryCodes: JSON.stringify(backupCodes)
      }
    });

    // Generate QR Code
    const otpauth = authenticator.keyuri(user.email, 'Thanawy', secret);
    const qrCode = await QRCode.toDataURL(otpauth);

    // Return the secret and backup codes
    // Note: The frontend should generate a QR code from the secret for easy setup
    return NextResponse.json({
      secret,
      qrCode,
      backupCodes,
      message: '2FA setup initiated. Please verify with your authenticator app.'
    });
  } catch (error) {
    logger.error('2FA setup error:', error);
    return NextResponse.json(
      { error: 'Failed to setup 2FA' },
      { status: 500 }
    );
  }
}

// Handle 2FA verification
async function handleVerify2FA(user: UserWith2FA, code: string, request: NextRequest) {
  try {
    if (!code) {
      return NextResponse.json(
        { error: 'Verification code is required' },
        { status: 400 }
      );
    }

    if (!user.twoFactorSecret) {
      return NextResponse.json(
        { error: '2FA not set up for this user' },
        { status: 400 }
      );
    }

    // Verify TOTP code using real implementation
    const isValid = verifyTOTP(user.twoFactorSecret, code);

    const ip = authService.getClientIP(request);
    const userAgent = authService.getUserAgent(request);

    if (!isValid) {
      // Log failed verification attempt
      await Promise.all([
        authService.logSecurityEvent(user.id, 'two_factor_verify_failed', ip, {
          userAgent,
          method: 'TOTP',
        }),
        securityLogger.logEvent({
          userId: user.id,
          eventType: 'TWO_FACTOR_FAILED',
          ip,
          userAgent,
          metadata: { method: 'TOTP' },
        }),
      ]).catch(() => {
        // Non-blocking log failure
      });

      return NextResponse.json(
        { error: 'رمز التحقق غير صحيح' },
        { status: 400 }
      );
    }

    // Enable 2FA
    await prisma.user.update({
      where: { id: user.id },
      data: { twoFactorEnabled: true }
    });

    const clientId = `${ip}-${userAgent}`;
    await authService.resetRateLimit(clientId);

    // Log security events
    await Promise.all([
      authService.logSecurityEvent(user.id, 'two_factor_enabled', ip, {
        userAgent,
        method: 'TOTP',
      }),
      securityLogger.logEvent({
        userId: user.id,
        eventType: 'TWO_FACTOR_ENABLED',
        ip,
        userAgent,
        metadata: { method: 'TOTP' },
      }),
      securityNotificationService.notify2FAStatusChange(user.id, true, ip),
    ]).catch(() => {
      // Non-blocking log failure
    });

    return NextResponse.json({
      message: 'تم تفعيل المصادقة الثنائية بنجاح'
    });
  } catch (error) {
    logger.error('2FA verification error:', error);
    return NextResponse.json(
      { error: 'Failed to verify 2FA' },
      { status: 500 }
    );
  }
}

// Handle 2FA disabling
async function handleDisable2FA(user: UserWith2FA, code: string, request: NextRequest) {
  try {
    if (!code) {
      return NextResponse.json(
        { error: 'Verification code is required' },
        { status: 400 }
      );
    }

    if (!user.twoFactorEnabled) {
      return NextResponse.json(
        { error: '2FA is not enabled for this user' },
        { status: 400 }
      );
    }

    const ip = authService.getClientIP(request);
    const userAgent = authService.getUserAgent(request);

    // Try TOTP verification first
    let isValid = false;
    if (user.twoFactorSecret) {
      isValid = verifyTOTP(user.twoFactorSecret, code);
    }

    // If TOTP verification failed, try recovery code
    if (!isValid) {
      isValid = await verifyAndConsumeRecoveryCode(user.id, code);
    }

    if (!isValid) {
      // Log failed disable attempt
      await Promise.all([
        authService.logSecurityEvent(user.id, 'two_factor_disable_failed', ip, {
          userAgent,
          reason: 'invalid_code',
        }),
        securityLogger.logEvent({
          userId: user.id,
          eventType: 'TWO_FACTOR_DISABLED',
          ip,
          userAgent,
          metadata: { reason: 'invalid_code' },
        }),
      ]).catch(() => {
        // Non-blocking log failure
      });

      return NextResponse.json(
        { error: 'رمز التحقق غير صحيح' },
        { status: 400 }
      );
    }

    // Disable 2FA using proper service (code already verified)
    await disableTOTP(user.id);

    const clientId = `${ip}-${userAgent}`;
    await authService.resetRateLimit(clientId);

    // Log security events
    await Promise.all([
      authService.logSecurityEvent(user.id, 'two_factor_disabled', ip, {
        userAgent,
      }),
      securityLogger.logEvent({
        userId: user.id,
        eventType: 'TWO_FACTOR_DISABLED',
        ip,
        userAgent,
      }),
      securityNotificationService.notify2FAStatusChange(user.id, false, ip),
    ]).catch(() => {
      // Non-blocking log failure
    });

    return NextResponse.json({
      message: 'تم إلغاء تفعيل المصادقة الثنائية بنجاح'
    });
  } catch (error) {
    logger.error('2FA disable error:', error);
    return NextResponse.json(
      { error: 'Failed to disable 2FA' },
      { status: 500 }
    );
  }
}

// Handle backup code verification
async function handleBackupCode(user: UserWith2FA, backupCode: string, request: NextRequest) {
  try {
    if (!backupCode) {
      return NextResponse.json(
        { error: 'Backup code is required' },
        { status: 400 }
      );
    }

    if (!user.twoFactorEnabled) {
      return NextResponse.json(
        { error: '2FA is not enabled for this user' },
        { status: 400 }
      );
    }

    const ip = authService.getClientIP(request);
    const userAgent = authService.getUserAgent(request);

    // Verify and consume recovery code using proper service
    const isValid = await verifyAndConsumeRecoveryCode(user.id, backupCode);

    if (!isValid) {
      // Log failed backup code attempt
      await Promise.all([
        authService.logSecurityEvent(user.id, 'two_factor_backup_code_failed', ip, {
          userAgent,
        }),
        securityLogger.logEvent({
          userId: user.id,
          eventType: 'TWO_FACTOR_FAILED',
          ip,
          userAgent,
        }),
      ]).catch(() => {
        // Non-blocking log failure
      });

      return NextResponse.json(
        { error: 'رمز الاسترداد غير صحيح أو مستخدم' },
        { status: 400 }
      );
    }

    // Get remaining codes count
    const userWithCodes = await prisma.user.findUnique({
      where: { id: user.id },
      select: { recoveryCodes: true },
    });

    const remainingCodes = userWithCodes?.recoveryCodes
      ? JSON.parse(userWithCodes.recoveryCodes as string).length
      : 0;

    // Log security events
    await Promise.all([
      authService.logSecurityEvent(user.id, 'two_factor_backup_code_used', ip, {
        userAgent,
        remainingCodes,
      }),
      securityLogger.logEvent({
        userId: user.id,
        eventType: 'TWO_FACTOR_SUCCESS',
        ip,
        userAgent,
        metadata: { remainingCodes },
      }),
    ]).catch(() => {
      // Non-blocking log failure
    });

    // Generate a new token for the user
    const clientId = `${ip}-${userAgent}`;
    await authService.resetRateLimit(clientId);

    const token = await new SignJWT({
      userId: user.id,
      email: user.email,
      name: user.name || undefined,
      role: user.role || 'user'
    })
      .setProtectedHeader({ alg: 'HS256' })
      .setIssuedAt()
      .setExpirationTime('7d')
      .sign(getJWTSecretSafe());

    return NextResponse.json({
      message: 'تم التحقق من رمز الاسترداد بنجاح',
      token,
      remainingBackupCodes: remainingCodes
    });
  } catch (error) {
    logger.error('Backup code verification error:', error);
    return NextResponse.json(
      { error: 'Failed to verify backup code' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { authService } from '@/lib/services/auth-service';
import { addSecurityHeaders, createStandardErrorResponse } from '@/lib/auth-utils';
import { logger } from '@/lib/logger';
import { opsWrapper } from '@/lib/middleware/ops-middleware';

export async function GET(request: NextRequest) {
    return opsWrapper(request, async (req) => {
        try {
            const authResult = await authService.getCurrentUser();
            if (!authResult.isValid || !authResult.user) {
                return NextResponse.json(
                    { error: 'Unauthorized', code: 'UNAUTHORIZED' },
                    { status: 401 }
                );
            }

            const user = await authService.findUserByEmail(authResult.user.email);

            const response = NextResponse.json({
                enabled: user?.twoFactorEnabled || false
            });

            return addSecurityHeaders(response);
        } catch (error) {
            logger.error('2FA status error:', error);
            return createStandardErrorResponse(error, 'Failed to get 2FA status');
        }
    });
}

import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/db';
import { TwoFactorChallengeService } from '@/lib/services/auth-challenges-service';
import { authService } from '@/lib/services/auth-service';
import { securityLogger } from '@/lib/security-logger';
import { setAuthCookies, logSecurityEventSafely, extractRequestMetadata } from '@/lib/auth-utils';
import { opsWrapper } from "@/lib/middleware/ops-middleware";
import { logger } from '@/lib/logger';

export async function POST(request: NextRequest) {
    return opsWrapper(request, async (req) => {
        try {
            const body = await req.json();
            const { loginAttemptId, code, trustDevice } = body;
            const { ip, userAgent } = extractRequestMetadata(req);
            const clientId = `${ip}-${userAgent}`;

            if (!loginAttemptId) {
                return NextResponse.json({ error: 'Login attempt ID is required' }, { status: 400 });
            }
            if (!code) {
                return NextResponse.json({ error: 'Code is required' }, { status: 400 });
            }

            const trimmedCode = code.trim();
            const trimmedAttemptId = loginAttemptId.trim();

            if (trimmedCode.length !== 6 || !/^\d{6}$/.test(trimmedCode)) {
                return NextResponse.json({ error: 'رمز التحقق يجب أن يكون مكون من 6 أرقام', code: 'INVALID_CODE_FORMAT' }, { status: 400 });
            }

            // Lookup challenge to identify user for rate limiting
            const challenge = await prisma.twoFactorChallenge.findUnique({
                where: { id: trimmedAttemptId }
            });

            if (challenge?.userId) {
                try {
                    // Check for persistent lockout first
                    const lockoutStatus = await authService.get2FALockoutStatus(challenge.userId);
                    if (lockoutStatus.locked) {
                        return NextResponse.json(
                            {
                                error: `تم حظر محاولات التحقق مؤقتاً. يمكنك المحاولة مرة أخرى بعد ${lockoutStatus.lockedUntil?.toLocaleTimeString()}`,
                                code: 'ACCOUNT_LOCKED',
                                lockedUntil: lockoutStatus.lockedUntil
                            },
                            { status: 403 }
                        );
                    }

                    // Check user-specific rate limit (e.g. 5 attempts per 15 mins)
                    await authService.checkUserRateLimit(challenge.userId, 5, 15 * 60);
                } catch (error: any) {
                    return NextResponse.json(
                        { error: error.message || 'تم تجاوز الحد المسموح به من المحاولات لهذا الحساب. يرجى الانتظار قليلاً.', code: 'RATE_LIMIT_EXCEEDED' },
                        { status: 429 }
                    );
                }
            }

            // Rate Limit Check (IP based)
            try {
                await authService.checkRateLimit(clientId, 5, 15 * 60);
            } catch (error) {
                return NextResponse.json(
                    { error: 'تم تجاوز الحد المسموح به من المحاولات. يرجى الانتظار قليلاً.', code: 'RATE_LIMIT_EXCEEDED' },
                    { status: 429 }
                );
            }

            // Verify Challenge
            const challengePromise = TwoFactorChallengeService.verifyAndConsumeChallenge(trimmedAttemptId, trimmedCode);
            const timeoutPromise = new Promise<{ valid: false; userId?: string }>((resolve) => setTimeout(() => resolve({ valid: false }), 5000));

            const challengeResult = await Promise.race([challengePromise, timeoutPromise]);

            if (!challengeResult.valid || !challengeResult.userId) {
                // Record failure and check for lockout
                if (challenge?.userId) {
                    await authService.recordFailed2FAAttempt(challenge.userId);
                }

                // Log failure for rate limiting
                await securityLogger.logEvent({
                    userId: challenge?.userId || 'unknown',
                    eventType: 'TWO_FACTOR_FAILED',
                    ip,
                    userAgent,
                    metadata: { reason: 'invalid_code', loginAttemptId: trimmedAttemptId }
                });

                return NextResponse.json({ error: 'رمز التحقق غير صحيح أو منتهي الصلاحية', code: 'INVALID_OR_EXPIRED' }, { status: 400 });
            }

            // On success, reset attempts
            await authService.reset2FAAttempts(challengeResult.userId);

            // Fetch user
            const user = await prisma.user.findUnique({
                where: { id: challengeResult.userId },
                select: {
                    id: true, email: true, name: true, role: true, twoFactorEnabled: true, lastLogin: true
                }
            });

            if (!user) {
                return NextResponse.json({ error: 'المستخدم غير موجود', code: 'USER_NOT_FOUND' }, { status: 404 });
            }

            const rememberDevice = Boolean(trustDevice);
            await authService.resetRateLimit(clientId);

            // Create Session & Tokens
            const tempTokens = await authService.createTokens({
                id: user.id, email: user.email, name: user.name || undefined, role: user.role || undefined
            });

            const session = await authService.createSession(user.id, tempTokens.refreshToken, userAgent, ip, rememberDevice);

            const { accessToken, refreshToken } = await authService.createTokens({
                id: user.id, email: user.email, name: user.name || undefined, role: user.role || undefined
            }, session.id);

            await prisma.session.update({ where: { id: session.id }, data: { refreshToken } });

            // Update user & Log
            await prisma.user.update({
                where: { id: user.id },
                data: { lastLogin: new Date() }
            });

            logSecurityEventSafely(user.id, 'two_factor_verified', { userAgent, sessionId: session.id, ip });

            const response = NextResponse.json({
                message: 'تم التحقق من الرمز بنجاح.',
                user: { ...user, emailVerified: false }, // emailVerified not in select, safe to assume false or handle otherwise
                token: accessToken,
                refreshToken,
                sessionId: session.id
            });

            setAuthCookies(response, accessToken, refreshToken, rememberDevice);
            return response;

        } catch (error) {
            logger.error('TOTP verify login error:', error);
            return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
        }
    });
}

import { NextRequest, NextResponse } from 'next/server';
import { opsWrapper } from '@/lib/middleware/ops-middleware';
import { logger } from '@/lib/logger';
import { authService } from '@/lib/services/auth-service';
import {
    createStandardErrorResponse,
    createSuccessResponse,
    extractRequestMetadata,
    logSecurityEventSafely,
    addSecurityHeaders
} from '@/app/api/auth/_helpers';

export async function GET(request: NextRequest) {
    return opsWrapper(request, async (req) => {
        const { ip, userAgent } = extractRequestMetadata(req);
        const { searchParams } = new URL(req.url);
        const token = searchParams.get('token');

        if (!token) {
            return createStandardErrorResponse(
                new Error('Token missing'),
                'رابط التحقق غير صالح.',
                400
            );
        }

        try {
            await authService.verifyEmail(token, ip, userAgent);

            await logSecurityEventSafely(null, 'email_verified', {
                ip,
                userAgent,
            });

            // Redirect to login with success message
            const baseUrl = process.env.NEXT_PUBLIC_BASE_URL || 'http://localhost:3000';
            return NextResponse.redirect(`${baseUrl}/login?verified=true`);

        } catch (error) {
            logger.error('Email verification error:', error);

            // Redirect to login with error message
            const baseUrl = process.env.NEXT_PUBLIC_BASE_URL || 'http://localhost:3000';
            return NextResponse.redirect(`${baseUrl}/login?error=verification_failed`);
        }
    });
}

import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';
import { prisma } from '@/lib/db';
import {
    createStandardErrorResponse,
    createSuccessResponse,
    emailSchema,
    parseRequestBody,
    extractRequestMetadata,
    logSecurityEventSafely,
    withDatabaseQuery
} from '@/app/api/auth/_helpers';
import { opsWrapper } from "@/lib/middleware/ops-middleware";
import { logger } from '@/lib/logger';

const verifyCodeSchema = z.object({
    email: emailSchema,
    code: z.string().length(6, 'رمز التحقق يجب أن يكون 6 أرقام'),
});

export async function POST(request: NextRequest) {
    return opsWrapper(request, async (req) => {
        const { ip, userAgent } = extractRequestMetadata(req);

        const bodyResult = await parseRequestBody<{
            email?: string;
            code?: string;
        }>(req, { required: true });

        if (!bodyResult.success) {
            return bodyResult.error;
        }

        const parsed = verifyCodeSchema.safeParse(bodyResult.data);

        if (!parsed.success) {
            return createStandardErrorResponse(
                {
                    error: 'VALIDATION_ERROR',
                    details: parsed.error.flatten().fieldErrors,
                },
                'بيانات غير صالحة',
                400
            );
        }

        const { email, code } = parsed.data;

        // Find user with valid reset token
        const userResult = await withDatabaseQuery(
            () => prisma.user.findFirst({
                where: {
                    email,
                    resetToken: code,
                    resetTokenExpires: {
                        gte: new Date(),
                    },
                },
                select: {
                    id: true,
                    email: true,
                    resetToken: true,
                },
            })
        );

        if (!userResult.success) {
            return userResult.response;
        }

        const user = userResult.data;

        if (!user) {
            await logSecurityEventSafely(null, 'verify_reset_code_failed', {
                ip,
                userAgent,
                email,
            });

            return createStandardErrorResponse(
                null,
                'رمز التحقق غير صحيح أو منتهي الصلاحية',
                400
            );
        }

        await logSecurityEventSafely(user.id, 'verify_reset_code_success', {
            ip,
            userAgent,
        });

        return createSuccessResponse({
            message: 'تم التحقق بنجاح',
            resetToken: user.resetToken, // Return token to be used in reset password step
        });
    });
}

