      if (userId) {
        enrollment = await prisma.subjectEnrollment.findFirst({
          where: {
            userId,
            subjectId: subject.id
          }
        });
      }

      return NextResponse.json({
        subject,
        enrollment
      });
    } catch (error) {
      logger.error("Error fetching subject:", error);
      return NextResponse.json(
