import { NextRequest, NextResponse } from 'next/server';
import { logger } from '@/lib/logger';
import { opsWrapper } from '@/lib/middleware/ops-middleware';

import {
  checkDatabaseHealth,
  ensureDatabaseConnection,
} from '@/lib/db-connection-helper';

/**
 * GET /api/db/connection
 * Get database connection status and diagnostics
 */
export async function GET(request: NextRequest) {
  return opsWrapper(request, async (req) => {
    try {
      const { searchParams } = new URL(req.url);
      const action = searchParams.get('action');

      switch (action) {
        case 'test':
          // Test connection
          const testResult = await checkDatabaseHealth();
          return NextResponse.json({
            success: testResult,
            message: testResult
              ? 'Database connection test passed'
              : 'Database connection test failed'
          });

        case 'initialize':
          // Initialize connection
          try {
            await ensureDatabaseConnection();
            return NextResponse.json({
              success: true,
              message: 'Database connection initialized successfully'
            });
          } catch (error) {
            return NextResponse.json({
              success: false,
              message: 'Failed to initialize database connection'
            });
          }

        default:
          // Get status (simple check)
          const status = await checkDatabaseHealth();
          return NextResponse.json({
            success: true,
            status: {
              connected: status,
              timestamp: new Date().toISOString()
            }
          });
      }
    } catch (error: unknown) {
      logger.error('Database connection API error:', error);
      return NextResponse.json(
        {
          success: false,
          error: error instanceof Error ? error.message : String(error),
          message: 'Failed to check database connection'
        },
        { status: 500 }
      );
    }
  });
}

/**
 * POST /api/db/connection
 * Initialize or test database connection
 */
export async function POST(request: NextRequest) {
  return opsWrapper(request, async (req) => {
    try {
      const body = await req.json().catch(() => ({}));
      const { action = 'test' } = body;

      switch (action) {
        case 'initialize':
          try {
            await ensureDatabaseConnection();
            return NextResponse.json({
              success: true,
              message: 'Database connection initialized successfully'
            });
          } catch (error) {
            return NextResponse.json({
              success: false,
              message: 'Failed to initialize database connection'
            });
          }

        case 'test':
          const testResult = await checkDatabaseHealth();
          return NextResponse.json({
            success: testResult,
            message: testResult
              ? 'Database connection test passed'
              : 'Database connection test failed'
          });

        default:
          return NextResponse.json(
            {
              success: false,
              error: 'Invalid action',
              message: 'Supported actions: initialize, test'
            },
            { status: 400 }
          );
      }
    } catch (error: unknown) {
      logger.error('Database connection API error:', error);
      return NextResponse.json(
        {
          success: false,
          error: error instanceof Error ? error.message : String(error),
          message: 'Failed to process database connection request'
        },
        { status: 500 }
      );
    }
  });
}

import { NextRequest, NextResponse } from 'next/server';
import { verifyToken } from '@/lib/services/auth-service';
import { prisma } from '@/lib/db';
import { OpenAI } from 'openai';
import { rateLimit } from '@/lib/api-utils';
import { opsWrapper } from "@/lib/middleware/ops-middleware";
import { logger } from '@/lib/logger';

// Initialize OpenAI client lazily/conditionally to avoid build errors
const openai = process.env.OPENAI_API_KEY
  ? new OpenAI({ apiKey: process.env.OPENAI_API_KEY })
  : null;

export async function POST(request: NextRequest) {
  return opsWrapper(request, async (req) => {
    try {
      // Apply rate limiting
      const rateLimitResult = await rateLimit(req, 20, 'evaluate_test'); // 20 requests per window
      if (rateLimitResult) {
        return rateLimitResult;
      }

      // Verify authentication
      const decodedToken = verifyToken(req);
      if (!decodedToken) {
        return NextResponse.json(
          { error: 'Unauthorized' },
          { status: 401 }
        );
      }

      const { testId, answers, timeSpent } = await req.json();

      if (!testId || !answers) {
        return NextResponse.json(
          { error: 'Test ID and answers are required' },
          { status: 400 }
        );
      }

      // Get user from database
      const user = await prisma.user.findUnique({
        where: { id: decodedToken.userId }
      });

      if (!user) {
        return NextResponse.json(
          { error: 'User not found' },
          { status: 404 }
        );
      }

      // Get test with questions from database
      const test = await prisma.aiGeneratedExam.findUnique({
        where: { id: testId },
        include: { questions: true }
      });

      if (!test) {
        return NextResponse.json(
          { error: 'Test not found' },
          { status: 404 }
        );
      }

      // Prepare answers and questions for AI evaluation
      const questionsForEvaluation = test.questions.map((q) => ({
        id: q.id,
        question: q.question,
        type: q.type,
        options: q.options ? JSON.parse(q.options) : null,
        correctAnswer: q.correctAnswer,
        explanation: q.explanation,
        difficulty: q.difficulty,
        points: q.points
      }));

      const userAnswersForEvaluation = answers.map((a: { questionId: string; value: string }) => ({
        questionId: a.questionId,
        value: a.value
      }));

      // Create prompt for AI to evaluate answers
      const prompt = `
        قم بتقييم إجابات الطالب على الاختبار التالي في مادة ${getSubjectName(test.subject)}.

        الأسئلة والإجابات الصحيحة:
        ${JSON.stringify(questionsForEvaluation, null, 2)}

        إجابات الطالب:
        ${JSON.stringify(userAnswersForEvaluation, null, 2)}

        قم بتقييم كل إجابة وتحديد ما إذا كانت صحيحة أم خاطئة، مع تقديم شرح موجز لكل إجابة.

        بعد ذلك، قم بتقديم ملخص شامل للتقييم يتضمن:
        1. الدرجة الإجمالية والنسبة المئوية
        2. عدد الإجابات الصحيحة والخاطئة
        3. نقاط القوة في إجابات الطالب
        4. جوانب تحتاج إلى تحسين
        5. توصيات للطالب لتحسين أدائه

        قم بتنسيق الإجابة كـ JSON بالهيكل التالي:
        {
          "detailedResults": [
            {
              "questionId": "معرف السؤال",
              "isCorrect": true,
              "userAnswer": "إجابة الطالب",
              "correctAnswer": "الإجابة الصحيحة",
              "explanation": "شرح للتقييم",
              "feedback": "ملاحظات على الإجابة"
            }
          ],
          "summary": {
            "score": 85,
            "totalPoints": 100,
            "correctAnswers": 8,
            "incorrectAnswers": 2,
            "strengths": [
              "فهمك للمفاهيم الأساسية جيد"
            ],
            "improvementAreas": [
              "تحتاج إلى تحسين معرفتك بالمفاهيم المتقدمة"
            ],
            "recommendations": [
              "راجع الفصول من 5 إلى 7 في الكتاب المقرر"
            ]
          }
        }
      `;

      // Call OpenAI API to evaluate answers
      if (!openai) {
        throw new Error("OpenAI API key is not configured");
      }

      const completion = await openai.chat.completions.create({
        model: "gpt-4",
        messages: [{ role: "user", content: prompt }],
        response_format: { type: "json_object" },
      });

      const responseContent = completion.choices[0].message.content;
      if (!responseContent) {
        throw new Error("Empty response from AI");
      }

      const evaluation = JSON.parse(responseContent);

      // Calculate score
      let score = 0;
      let totalPoints = 0;

      test.questions.forEach((question) => {
        totalPoints += question.points;
        const result = evaluation.detailedResults.find((r: { questionId: string; isCorrect: boolean }) => r.questionId === question.id);
        if (result && result.isCorrect) {
          score += question.points;
        }
      });

      // Save test result to database
      const testResult = await prisma.testResult.create({
        data: {
          userId: user.id,
          examId: testId,
          score,
          totalScore: totalPoints,
          timeTaken: timeSpent,
          answers: JSON.stringify(answers)
        }
      });

      // Return the evaluation result
      return NextResponse.json({
        result: {
          testId,
          answers,
          score,
          totalPoints,
          timeSpent,
          completedAt: new Date(),
          feedback: evaluation.summary,
          detailedResults: evaluation.detailedResults
        }
      });
    } catch (error: unknown) {
      logger.error('Error evaluating test:', error);
      return NextResponse.json(
        { error: 'Failed to evaluate test' },
        { status: 500 }
      );
    }
  });
}

function getSubjectName(subjectValue: string): string {
  const subjects: Record<string, string> = {
    'MATH': 'الرياضيات',
    'SCIENCE': 'العلوم',
    'HISTORY': 'التاريخ',
    'ARABIC': 'اللغة العربية',
    'ENGLISH': 'اللغة الإنجليزية',
    'PHYSICS': 'الفيزياء',
    'CHEMISTRY': 'الكيمياء',
    'BIOLOGY': 'الأحياء',
    'COMPUTER': 'علوم الحاسب',
  };

  return subjects[subjectValue] || subjectValue;
}

import { NextRequest, NextResponse } from "next/server";
import { prisma } from "@/lib/db";
import { opsWrapper } from "@/lib/middleware/ops-middleware";
import { logger } from '@/lib/logger';

// GET all attendees for an event
export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  return opsWrapper(request, async (req) => {
    try {
      const { id } = await params;

      // Check if event exists
      const event = await prisma.event.findUnique({
        where: { id }
      });

      if (!event) {
        return NextResponse.json(
          { error: "المناسبة غير موجودة" },
          { status: 404 }
        );
      }

      const attendees = await prisma.eventAttendee.findMany({
        where: { eventId: id },
        orderBy: {
          createdAt: "asc"
        }
      });

      // Fetch user details manually since relation is missing
      const userIds = attendees.map(a => a.userId);
      const users = await prisma.user.findMany({
        where: { id: { in: userIds } },
        select: {
          id: true,
          name: true,
          avatar: true
        }
      });

      const userMap = new Map(users.map(u => [u.id, u]));

      // Transform the data to match the frontend structure
      const transformedAttendees = attendees.map((attendee) => {
        const user = userMap.get(attendee.userId);
        return {
          id: user?.id || attendee.userId,
          name: user?.name || 'Unknown',
          avatar: user?.avatar || null,
          joinedAt: attendee.createdAt.toISOString()
        };
      });

      return NextResponse.json(transformedAttendees);
    } catch (error: unknown) {
      logger.error("Error fetching event attendees:", error);
      return NextResponse.json(
        { error: "حدث خطأ في جلب المشاركين" },
        { status: 500 }
      );
    }
  });
}

// POST to join an event
export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  return opsWrapper(request, async (req) => {
    try {
      const { id } = await params;
      const { userId } = await req.json();

      if (!userId) {
        return NextResponse.json(
          { error: "معرف المستخدم مطلوب" },
          { status: 400 }
        );
      }

      // Check if event exists
      const event = await prisma.event.findUnique({
        where: { id },
        include: {
          _count: {
            select: { attendees: true }
          }
        }
      });

      if (!event) {
        return NextResponse.json(
          { error: "المناسبة غير موجودة" },
          { status: 404 }
        );
      }

      // Check if max attendees limit reached
      if (event.maxAttendees && event._count.attendees >= event.maxAttendees) {
        return NextResponse.json(
          { error: "وصل الحد الأقصى للمشاركين" },
          { status: 400 }
        );
      }

      // Check if user is already attending
      const existingAttendance = await prisma.eventAttendee.findUnique({
        where: {
          eventId_userId: {
            eventId: id,
            userId
          }
        }
      });

      if (existingAttendance) {
        return NextResponse.json(
          { error: "المستخدم مشارك بالفعل" },
          { status: 400 }
        );
      }

      // Add attendee
      const newAttendee = await prisma.eventAttendee.create({
        data: {
          eventId: id,
          userId
        }
      });

      // Fetch user details
      const user = await prisma.user.findUnique({
        where: { id: userId },
        select: {
          id: true,
          name: true,
