import { NextRequest, NextResponse } from 'next/server';
import { gamificationService } from '@/lib/services/gamification-service';
import { prisma as db } from '@/lib/db';
import { opsWrapper } from "@/lib/middleware/ops-middleware";
import { logger } from '@/lib/logger';

export async function GET(request: NextRequest) {
  return opsWrapper(request, async (req) => {
    try {
      const { searchParams } = new URL(req.url);
      const userId = searchParams.get('userId');
      const category = searchParams.get('category');
      const difficulty = searchParams.get('difficulty');

      if (!userId || userId.trim() === '') {
        return NextResponse.json(
          {
            error: 'User ID is required',
            achievements: [],
            userProgress: null
          },
          { status: 400 }
        );
      }

      // Get all available achievements first (this always works)
      const allAchievements = gamificationService.getAllAchievements();

      // Try to get user progress, but handle errors gracefully
      let progress;
      let userAchievements: string[] = [];
      let userProgressData = {
        totalXP: 0,
        level: 1,
        achievementsCount: 0,
        totalAchievements: allAchievements.length
      };

      try {
        progress = await gamificationService.getUserProgress(userId);
        userAchievements = progress.achievements || [];
        userProgressData = {
          totalXP: progress.totalXP || 0,
          level: progress.level || 1,
          achievementsCount: userAchievements.length,
          totalAchievements: allAchievements.length
        };
      } catch (progressError: unknown) {
        // If user doesn't exist or other error, continue with empty progress
        const errorMessage = progressError instanceof Error ? progressError.message : String(progressError);
        logger.warn('Could not fetch user progress, using defaults:', errorMessage);
        // Continue with default values
      }

      // Filter achievements based on query parameters
      let filteredAchievements = allAchievements;

      if (category) {
        filteredAchievements = filteredAchievements.filter((a) => a.category === category);
      }

      if (difficulty) {
        filteredAchievements = filteredAchievements.filter((a) => a.difficulty === difficulty);
      }

      // Mark which achievements are earned by the user
      const achievementsWithStatus = filteredAchievements.map((achievement) => ({
        ...achievement,
        isEarned: userAchievements.includes(achievement.key),
        earnedAt: userAchievements.includes(achievement.key) ?
          // In a real implementation, you'd get the actual earned date from the database
          new Date().toISOString() : null
      }));

      return NextResponse.json({
        achievements: achievementsWithStatus,
        userProgress: userProgressData
      });

    } catch (error: unknown) {
      logger.error('Error fetching achievements:', error);
      const errorMessage = error instanceof Error ? error.message : String(error);

      // Return a safe fallback response
      const allAchievements = gamificationService.getAllAchievements();
      return NextResponse.json({
        error: errorMessage || 'Failed to fetch achievements',
        achievements: allAchievements.map((ach) => ({
          ...ach,
          isEarned: false,
          earnedAt: null
        })),
        userProgress: {
          totalXP: 0,
          level: 1,
          achievementsCount: 0,
          totalAchievements: allAchievements.length
        }
      }, { status: 500 });
    }
  });
}

export async function POST(request: NextRequest) {
  return opsWrapper(request, async (req) => {
    try {
      const body = await req.json();
      const { userId, action, data } = body;

      if (!userId || !action) {
        return NextResponse.json({ error: 'User ID and action are required' }, { status: 400 });
      }

      let result;

      switch (action) {
        case 'unlock_achievement':
          if (!data?.achievementKey) {
            return NextResponse.json({ error: 'Achievement key is required' }, { status: 400 });
          }

          const achievement = gamificationService.getAchievement(data.achievementKey);
          if (!achievement) {
            return NextResponse.json({ error: 'Achievement not found' }, { status: 404 });
          }

          await gamificationService.unlockAchievement(userId, achievement);
          result = { message: 'Achievement unlocked successfully' };
          break;

        case 'check_achievements':
          // This would check and potentially unlock new achievements based on user progress
          result = await gamificationService.getUserProgress(userId);
          break;

        default:
          return NextResponse.json({ error: 'Invalid action' }, { status: 400 });
      }

      return NextResponse.json(result);

    } catch (error) {
      logger.error('Error in achievements API:', error);
      return NextResponse.json(
        { error: 'Internal server error' },
        { status: 500 }
      );
    }
  });
}

import { NextRequest, NextResponse } from 'next/server';
import { gamificationService } from '@/lib/services/gamification-service';
import { opsWrapper } from "@/lib/middleware/ops-middleware";
import { logger } from '@/lib/logger';

export async function PATCH(
  request: NextRequest,
  { params }: { params: Promise<{ goalId: string }> }
) {
  return opsWrapper(request, async (req) => {
    try {
      const { goalId } = await params;
      const body = await req.json();
      const { currentValue } = body;

      if (currentValue === undefined) {
        return NextResponse.json({ error: 'currentValue is required' }, { status: 400 });
      }

      const updatedGoal = await gamificationService.updateCustomGoal(goalId, currentValue);
      return NextResponse.json(updatedGoal);

    } catch (error: unknown) {
      logger.error('Error updating custom goal:', error);
      const errorMessage = error instanceof Error ? error.message : String(error);
      if (errorMessage?.includes('not found')) {
        return NextResponse.json({ error: 'Goal not found' }, { status: 404 });
      }
      return NextResponse.json(
        { error: 'Failed to update custom goal' },
        { status: 500 }
      );
    }
  });
}

export async function DELETE(
  request: NextRequest,
  { params }: { params: Promise<{ goalId: string }> }
) {
  return opsWrapper(request, async (req) => {
    try {
      const { goalId } = await params;
      await gamificationService.deleteCustomGoal(goalId);
      return NextResponse.json({ message: 'Goal deleted successfully' });

    } catch (error: unknown) {
      logger.error('Error deleting custom goal:', error);
      const errorMessage = error instanceof Error ? error.message : String(error);
      if (errorMessage?.includes('not found')) {
        return NextResponse.json({ error: 'Goal not found' }, { status: 404 });
      }
      return NextResponse.json(
        { error: 'Failed to delete custom goal' },
        { status: 500 }
      );
    }
  });
}

import { NextRequest, NextResponse } from 'next/server';
import { verifyToken, DecodedToken } from '@/lib/services/auth-service';
import { prisma, Prisma } from '@/lib/db';
import { OpenAI } from 'openai';
import { rateLimit } from '@/lib/api-utils';
import { opsWrapper } from "@/lib/middleware/ops-middleware";
import { logger } from '@/lib/logger';

export const dynamic = 'force-dynamic';

export async function POST(request: NextRequest) {
  return opsWrapper(request, async (req) => {
    try {
      const openai = new OpenAI({
        apiKey: process.env.OPENAI_API_KEY,
      });
      // Apply rate limiting
      const rateLimitResult = await rateLimit(req, 10, 'generate_test'); // 10 requests per window
      if (rateLimitResult) {
        return rateLimitResult;
      }

      // Verify authentication
      const decodedToken = verifyToken(req);
      if (!decodedToken) {
        return NextResponse.json(
          { error: 'Unauthorized' },
          { status: 401 }
        );
      }

      const { subject, difficulty, questionCount, questionTypes, timeLimit, lesson } = await req.json();

      if (!subject) {
        return NextResponse.json(
          { error: 'Subject is required' },
          { status: 400 }
        );
      }

      // Get user from database
      const user = await prisma.user.findUnique({
        where: { id: decodedToken.userId }
      });

      if (!user) {
        return NextResponse.json(
          { error: 'User not found' },
          { status: 404 }
        );
      }

      // Create prompt for AI to generate test
      const prompt = `
      قم بإنشاء اختبار في مادة ${getSubjectName(subject)}${lesson ? ` حول موضوع ${lesson}` : ''}.

      التفاصيل:
      - عدد الأسئلة: ${questionCount || 10}
      - مستوى الصعوبة: ${getDifficultyName(difficulty)}
      - أنواع الأسئلة: ${questionTypes.map((t: string) => getQuestionTypeName(t)).join(', ')}
      - المدة الزمنية: ${timeLimit || 30} دقيقة

      لكل سؤال، قم بتوفير:
      1. نص السؤال
      2. نوع السؤال
      3. الخيارات (إذا كان سؤال اختيار من متعدد)
      4. الإجابة الصحيحة
      5. شرح للإجابة (بحد أقصى 50 كلمة)
      6. مستوى الصعوبة (سهل، متوسط، صعب)
      7. نقاط السؤال (1 للسهل، 2 للمتوسط، 3 للصعب)

      قم بتنسيق الإجابة كـ JSON بالهيكل التالي:
      {
        "title": "عنوان الاختبار",
        "questions": [
          {
            "question": "نص السؤال",
            "type": "نوع السؤال",
            "options": ["خيار1", "خيار2", "خيار3", "خيار4"],
            "correctAnswer": "الإجابة الصحيحة",
            "explanation": "شرح للإجابة",
            "difficulty": "مستوى الصعوبة",
            "points": 1
          }
        ]
      }
    `;

      // Call OpenAI API to generate test
      const completion = await openai.chat.completions.create({
        model: "gpt-4",
        messages: [{ role: "user", content: prompt }],
        response_format: { type: "json_object" },
      });

      const responseContent = completion.choices[0].message.content;
      if (!responseContent) {
        throw new Error("Empty response from AI");
      }

      const generatedTest = JSON.parse(responseContent);

      // Create exam in database
      const newExam = await prisma.aiGeneratedExam.create({
        data: {
          userId: user.id,
          title: generatedTest.title,
          subject: subject.toUpperCase(),
          year: new Date().getFullYear(),
          difficulty: difficulty || 'medium',
          duration: timeLimit || 30,
        }
      });

      // Create questions in database
      for (const q of generatedTest.questions) {
        await prisma.aiQuestion.create({
          data: {
            examId: newExam.id,
            question: q.question,
            options: q.options ? q.options : Prisma.JsonNull,
            correctAnswer: q.correctAnswer,
            explanation: q.explanation,
            points: q.points || 1
          }
        });
      }

      // Return the created exam with questions
      const examWithQuestions = await prisma.aiGeneratedExam.findUnique({
        where: { id: newExam.id },
        include: { questions: true }
      });

      return NextResponse.json({ test: examWithQuestions });
    } catch (error) {
      logger.error('Error generating test:', error);
      return NextResponse.json(
        { error: 'Failed to generate test' },
        { status: 500 }
      );
    }
  });
}

function getSubjectName(subjectValue: string): string {
  const subjects: Record<string, string> = {
    'math': 'الرياضيات',
    'science': 'العلوم',
    'history': 'التاريخ',
    'arabic': 'اللغة العربية',
    'english': 'اللغة الإنجليزية',
    'physics': 'الفيزياء',
    'chemistry': 'الكيمياء',
    'biology': 'الأحياء',
    'computer': 'علوم الحاسب',
  };

  return subjects[subjectValue] || subjectValue;
}

function getDifficultyName(difficulty: string): string {
  const difficulties: Record<string, string> = {
    'easy': 'سهل',
    'medium': 'متوسط',
    'hard': 'صعب',
    'mixed': 'مختلط',
  };

  return difficulties[difficulty] || difficulty;
}

function getQuestionTypeName(type: string): string {
  const types: Record<string, string> = {
    'multiple-choice': 'اختيار من متعدد',
    'true-false': 'صح/خطأ',
    'short-answer': 'إجابة قصيرة',
    'essay': 'مقال',
  };

  return types[type] || type;
}

