import { opsWrapper } from "@/lib/middleware/ops-middleware";
import { logger } from '@/lib/logger';
import type { Prisma } from '@prisma/client';
import { TASK_STATUS } from '@/lib/constants';

/**
 * GET /api/recommendations
 * Get AI-powered personalized recommendations based on user's actual data
 */
export async function GET(request: NextRequest) {
  return opsWrapper(request, async (req) => {
    try {
      // Try to get userId from query params first (for backward compatibility)
      const { searchParams } = new URL(req.url);
    let userId = searchParams.get('userId');
    
      // If not in query params, try to get from authenticated user
      if (!userId) {
        const verification = await authService.verifyTokenFromRequest(req, { checkSession: true });
      if (verification.isValid && verification.user) {
        userId = verification.user.id;
      }
    }
    
    if (!userId) {
      return NextResponse.json(
        { error: 'User ID is required', recommendations: [] },
        { status: 400 }
      );
    }

    // Fetch user's actual data
    const [
      user,
      studySessions,
      tasks,
      examResults,
      userGrades,
      progress
    ] = await Promise.all([
      prisma.user.findUnique({ where: { id: userId } }),
      prisma.studySession.findMany({
        where: { userId },
        orderBy: { startTime: 'desc' },
        take: 50
      }),
      prisma.task.findMany({
        where: { userId },
        orderBy: { createdAt: 'desc' },
        take: 50
      }),
      prisma.examResult.findMany({
        where: { userId },
        include: { exam: true },
        orderBy: { takenAt: 'desc' },
        take: 20
      }),
      prisma.examResult.findMany({
        where: { userId },
        include: { exam: true },
        orderBy: { takenAt: 'desc' },
        take: 20
      }),
      gamificationService.getUserProgress(userId).catch(() => null)
    ]);

    if (!user) {
      return NextResponse.json(
        { error: 'User not found', recommendations: [] },
        { status: 404 }
      );
    }

    const recommendations = generateRecommendations({
      user,
      studySessions,
      tasks,
      examResults,
      userGrades,
      progress: progress ? {
        totalStudyMinutes: 0,
        averageFocusScore: 0,
        currentStreak: progress.currentStreak
      } : null
    });

    return NextResponse.json({
      success: true,
      recommendations,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Error fetching recommendations:', error);
    return NextResponse.json(
      { error: 'Failed to fetch recommendations', recommendations: [] },
      { status: 500 }
    );
    }
  });
}

interface RecommendationData {
  user: Prisma.UserGetPayload<{ select: { id: true; email: true; name: true } }>;
  studySessions: Prisma.StudySessionGetPayload<{}>[];
  tasks: Prisma.TaskGetPayload<{}>[];
  examResults: Prisma.ExamResultGetPayload<{}>[];
  userGrades: Prisma.ExamResultGetPayload<{ include: { exam: true } }>[];
  progress: { totalStudyMinutes: number; averageFocusScore: number; currentStreak?: number } | null;
}

interface Recommendation {
  id?: string;
  type: string;
  category?: string;
  title: string;
  description: string;
  priority: 'high' | 'medium' | 'low';
  impact?: number;
  estimatedTime?: string;
  icon?: string;
  actionUrl?: string;
}

function generateRecommendations(data: RecommendationData): Recommendation[] {
  const { user, studySessions, tasks, examResults, userGrades, progress } = data;
  const recommendations: Recommendation[] = [];

  // 1. Study Time Analysis
  const weekStart = startOfWeek(new Date(), { weekStartsOn: 6 });
  const weekEnd = endOfWeek(new Date(), { weekStartsOn: 6 });
  const weekSessions = studySessions.filter(s => {
    const sessionDate = new Date(s.startTime);
    return sessionDate >= weekStart && sessionDate <= weekEnd;
  });
  const weeklyMinutes = weekSessions.reduce((sum, s) => sum + (s.durationMin || 0), 0);
  const weeklyHours = weeklyMinutes / 60;

  // Calculate average daily study time
  const last7Days = studySessions.filter(s => {
    const sessionDate = new Date(s.startTime);
    return sessionDate >= subDays(new Date(), 7);
  });
  const avgDailyMinutes = last7Days.length > 0 
    ? last7Days.reduce((sum, s) => sum + (s.durationMin || 0), 0) / 7 
    : 0;

  // Study plan recommendations
  if (weeklyHours < 10) {
    const targetHours = 10;
    const deficit = targetHours - weeklyHours;
    recommendations.push({
      id: `study_plan_weekly_${Date.now()}`,
      type: "study_plan",
      category: "study_plan",
      title: "زيادة وقت الدراسة الأسبوعي",
      description: `أنت تدرس حالياً ${weeklyHours.toFixed(1)} ساعة أسبوعياً. نوصي بزيادة الوقت إلى ${targetHours} ساعة على الأقل لتحقيق أهدافك التعليمية.`,
      priority: "high",
      impact: Math.min(95, 60 + Math.floor(deficit * 5)),
      estimatedTime: `${Math.ceil(deficit * 60)} دقيقة`,
      icon: "target",
      actionUrl: "/schedule"
    });
  }

  // 2. Subject Balance Analysis
  const subjectStats: Record<string, { minutes: number; count: number }> = {};
  studySessions.forEach(session => {
    const subject = session.subject || 'غير محدد';
    if (!subjectStats[subject]) {
      subjectStats[subject] = { minutes: 0, count: 0 };
    }
    subjectStats[subject].minutes += session.durationMin || 0;
    subjectStats[subject].count += 1;
  });

  const totalSubjectMinutes = Object.values(subjectStats).reduce((sum, stat) => sum + stat.minutes, 0);
  const avgMinutesPerSubject = totalSubjectMinutes / Math.max(Object.keys(subjectStats).length, 1);

  // Find subjects with low study time
  Object.entries(subjectStats).forEach(([subject, stats]) => {
    if (stats.minutes < avgMinutesPerSubject * 0.5 && stats.minutes > 0) {
      recommendations.push({
        id: `study_plan_${subject}_${Date.now()}`,
        type: "study_plan",
        category: "study_plan",
        title: `زيادة وقت الدراسة في ${subject}`,
        description: `أنت تدرس ${subject} أقل من المتوسط. نوصي بتخصيص وقت أكثر لهذه المادة لتحسين التوازن.`,
        priority: "medium",
        impact: 75,
        estimatedTime: `${Math.ceil((avgMinutesPerSubject - stats.minutes) / 60)} ساعة`,
        icon: "book-open",
        actionUrl: `/schedule?subject=${encodeURIComponent(subject)}`
      });
    }
  });

  // 3. Task Completion Analysis
  const completedTasks = tasks.filter(t => t.status === TASK_STATUS.COMPLETED);
  const pendingTasks = tasks.filter(t => t.status === TASK_STATUS.PENDING || t.status === TASK_STATUS.IN_PROGRESS);
  const completionRate = tasks.length > 0 ? (completedTasks.length / tasks.length) * 100 : 0;

  if (pendingTasks.length > 0 && completionRate < 70) {
    const overdueTasks = pendingTasks.filter(t => {
      if (!t.dueAt) return false;
      return new Date(t.dueAt) < new Date();
    });

    if (overdueTasks.length > 0) {
      recommendations.push({
        id: `task_overdue_${Date.now()}`,
        type: "task",
        category: "task",
        title: `${overdueTasks.length} مهمة متأخرة`,
        description: `لديك ${overdueTasks.length} مهمة تجاوزت موعدها. نوصي بمراجعتها وإكمالها في أقرب وقت.`,
        priority: "high",
        impact: 90,
        estimatedTime: `${overdueTasks.length * 30} دقيقة`,
        icon: "clock",
        actionUrl: "/tasks?filter=overdue"
      });
    } else {
      recommendations.push({
        id: `task_pending_${Date.now()}`,
        type: "task",
        category: "task",
        title: `إكمال ${pendingTasks.length} مهمة معلقة`,
        description: `لديك ${pendingTasks.length} مهمة معلقة. معدل الإكمال الحالي ${completionRate.toFixed(0)}%. نوصي بتحسين هذا المعدل.`,
        priority: "medium",
        impact: 80,
        estimatedTime: `${pendingTasks.length * 25} دقيقة`,
        icon: "check-circle-2",
        actionUrl: "/tasks"
      });
    }
  }

  // 4. Exam Performance Analysis
  if (examResults.length > 0) {
    const avgScore = examResults.reduce((sum, r) => sum + r.score, 0) / examResults.length;
    const lowScores = examResults.filter(r => r.score < 60);
    
    if (avgScore < 70) {
      recommendations.push({
        id: `exam_prep_average_${Date.now()}`,
        type: "exam_prep",
        category: "exam_prep",
        title: "تحسين الأداء في الامتحانات",
        description: `متوسط درجاتك ${avgScore.toFixed(0)}%. نوصي بمراجعة المواد التي حصلت فيها على درجات منخفضة والتحضير بشكل أفضل للامتحانات القادمة.`,
        priority: "high",
        impact: 85,
        estimatedTime: "60 دقيقة",
        icon: "target",
        actionUrl: "/exams"
      });
    }

    // Subject-specific recommendations based on grades
    const subjectScores: Record<string, number[]> = {};
    userGrades.forEach(result => {
      const subject = result.exam?.subject || 'غير محدد';
      if (!subjectScores[subject]) {
        subjectScores[subject] = [];
      }
      subjectScores[subject].push(result.score);
    });

    Object.entries(subjectScores).forEach(([subject, scores]) => {
      const avgSubjectScore = scores.reduce((sum, s) => sum + s, 0) / scores.length;
      if (avgSubjectScore < 65) {
        recommendations.push({
          id: `exam_prep_${subject}_${Date.now()}`,
          type: "exam_prep",
          category: "exam_prep",
          title: `تحسين الأداء في ${subject}`,
          description: `متوسط درجاتك في ${subject} هو ${avgSubjectScore.toFixed(0)}%. نوصي بمراجعة شاملة للمادة قبل الامتحان القادم.`,
          priority: "high",
          impact: 88,
          estimatedTime: "90 دقيقة",
          icon: "book-open",
          actionUrl: `/exams?subject=${encodeURIComponent(subject)}`
        });
      }
    });
  }

  // 5. Study Streak Analysis
  if (progress && progress.currentStreak !== undefined) {
    const currentStreak = progress.currentStreak;
    
    if (currentStreak === 0 && studySessions.length > 0) {
      recommendations.push({
        id: `streak_rebuild_${Date.now()}`,
        type: "study_plan",
        category: "study_plan",
        title: "إعادة بناء سلسلة الدراسة",
        description: "لم تدرس منذ فترة. نوصي ببدء جلسة دراسة اليوم لبدء سلسلة جديدة!",
        priority: "high",
        impact: 85,
        estimatedTime: "30 دقيقة",
        icon: "zap",
        actionUrl: "/time"
      });
    } else if (currentStreak > 0 && currentStreak < 7) {
      recommendations.push({
        id: `streak_week_${Date.now()}`,
        type: "study_plan",
        category: "study_plan",
        title: `${currentStreak} يوم متتالي - استمر!`,
        description: `أنت على سلسلة ${currentStreak} أيام! استمر حتى تصل إلى أسبوع كامل واحصل على إنجاز خاص.`,
        priority: "medium",
        impact: 70,
        estimatedTime: "30 دقيقة",
        icon: "trending-up",
        actionUrl: "/time"
      });
    }
  }

  // 6. Study Pattern Recommendations
  if (avgDailyMinutes > 0 && avgDailyMinutes < 60) {
    recommendations.push({
      id: `study_pattern_${Date.now()}`,
      type: "tip",
      category: "tip",
      title: "تحسين نمط الدراسة اليومي",
      description: `متوسط وقت الدراسة اليومي هو ${Math.round(avgDailyMinutes)} دقيقة. نوصي بزيادة هذا الوقت إلى 60-90 دقيقة يومياً لتحقيق نتائج أفضل.`,
      priority: "medium",
      impact: 75,
      estimatedTime: `${60 - Math.round(avgDailyMinutes)} دقيقة`,
      icon: "lightbulb",
      actionUrl: "/time"
    });
  }

  // 7. Spaced Repetition Recommendations
  const recentSessions = studySessions.slice(0, 10);
  if (recentSessions.length > 0) {
    const oldestRecentSession = recentSessions[recentSessions.length - 1];
    const daysSinceOldest = differenceInDays(new Date(), new Date(oldestRecentSession.startTime));
    
    if (daysSinceOldest > 3) {
      const subject = oldestRecentSession.subject || 'المواد';
      recommendations.push({
        id: `review_${Date.now()}`,
        type: "task",
        category: "task",
        title: "مراجعة المواد القديمة",
        description: `مر ${daysSinceOldest} أيام منذ آخر دراسة لـ${subject}. نوصي بمراجعة هذه المواد الآن لتحسين الاست retention.`,
        priority: "medium",
        impact: 80,
        estimatedTime: "30 دقيقة",
        icon: "book-open",
        actionUrl: `/tasks?subject=${encodeURIComponent(subject)}`
      });
    }
  }

  // 8. Resource Recommendations
  if (examResults.length > 0 && examResults.some(r => r.score < 70)) {
    recommendations.push({
      id: `resource_improvement_${Date.now()}`,
      type: "resource",
      category: "resource",
      title: "مصادر تعليمية إضافية",
      description: "بناءً على أدائك في الامتحانات، نوصي باستخدام مصادر تعليمية إضافية مثل الفيديوهات والتمارين التفاعلية لتحسين فهمك.",
      priority: "medium",
      impact: 75,
      icon: "lightbulb",
      actionUrl: "/resources"
    });
  }

  // Sort by impact (highest first) and limit to top 10
  return recommendations
    .sort((a, b) => (b.impact ?? 0) - (a.impact ?? 0))
    .slice(0, 10)
    .map((rec, index) => ({
      ...rec,
      id: `rec_${index}_${Date.now()}`
    }));
}

﻿import { NextRequest, NextResponse } from "next/server";
import { z } from "zod";
import { prisma } from '@/lib/db';
import { handleApiError, badRequestResponse, successResponse } from "@/lib/api-utils";

// Validation schemas
const ReminderCreateSchema = z.object({
  userId: z.string().min(1, "userId is required"),
  title: z.string().min(1, "title is required").max(200, "title is too long"),
  message: z.string().max(1000, "message is too long").optional().nullable(),
  remindAt: z.string().datetime().or(z.date()),
  repeat: z.string().optional().nullable(),
});

export async function GET(req: NextRequest) {
	try {
		const { searchParams } = new URL(req.url);
		const userId = searchParams.get("userId");
		
		// Validate userId parameter
		if (!userId || userId === 'undefined' || userId.trim() === '') {
			return badRequestResponse("userId is required", 'MISSING_USER_ID');
		}
		const reminders = await prisma.reminder.findMany({ where: { userId }, orderBy: { remindAt: "asc" } });
		return successResponse(reminders);
	} catch (error) {
		return handleApiError(error);
	}
}

export async function POST(req: NextRequest) {
	try {
		const body = await req.json();
		
		// Validate request body
		const parsedBody = ReminderCreateSchema.safeParse(body);
		if (!parsedBody.success) {
			return badRequestResponse(
				`Invalid request body: ${parsedBody.error.message}`,
				'VALIDATION_ERROR'
			);
		}
		
		const { userId, title, message, remindAt, repeat } = parsedBody.data;
		
		const reminder = await prisma.reminder.create({
			data: {
				userId,
				title,
				message: message ?? null,
				remindAt: typeof remindAt === 'string' ? new Date(remindAt) : remindAt,
				repeat: repeat ?? null,
			},
		});
		return successResponse(reminder, 'Reminder created successfully', 201);
	} catch (error) {
		return handleApiError(error);
	}
}

import { NextRequest, NextResponse } from "next/server";
import { z } from "zod";
import { prisma } from '@/lib/db';
import { authService } from "@/lib/services/auth-service";
import { handleApiError, badRequestResponse, successResponse } from "@/lib/api-utils";
import { opsWrapper } from "@/lib/middleware/ops-middleware";

// Validation schemas
const SchedulePostSchema = z.object({
  userId: z.string().min(1, "userId is required"),
  plan: z.record(z.unknown()).or(z.array(z.unknown())).or(z.object({})),
  version: z.number().optional(),
});



export async function GET(req: NextRequest) {
  return opsWrapper(req, async (request) => {
    try {
      // Verify authentication
      const payload = await authService.verifyToken(request);
      if (!payload) {
        return badRequestResponse('Unauthorized', 'UNAUTHORIZED');
      }
      const authUser = { id: payload.userId, role: payload.role };

      const { searchParams } = new URL(request.url);
      const userId = searchParams.get("userId");

      // Validate userId parameter
      if (!userId || userId === 'undefined' || userId.trim() === '') {
        return badRequestResponse('userId parameter is required', 'MISSING_USER_ID');
      }

      // For security, we should only allow fetching the authenticated user's schedule
      // unless there's a specific admin requirement
      if (userId !== authUser.id) {
        return badRequestResponse('Invalid userId parameter', 'INVALID_PARAMETER');
      }

      let schedule = await prisma.schedule.findFirst({
        where: {
          userId,
          active: true
        }
      });

      if (!schedule) {
        schedule = await prisma.schedule.create({
          data: {
            userId,
            name: "مخصص",
            title: "Default Schedule",
            startTime: new Date(),
            endTime: new Date(),
            // weeklyHours: 0, // Removed
            planJson: JSON.stringify({}),
            active: true
          }
        });
      }

      return successResponse(schedule);
    } catch (error) {
      return handleApiError(error);
    }
  });
}

export async function POST(req: NextRequest) {
  return opsWrapper(req, async (request) => {
    try {
      // Verify authentication
      const payload = await authService.verifyToken(request);
      if (!payload) {
        return badRequestResponse('Unauthorized', 'UNAUTHORIZED');
      }
      const authUser = { id: payload.userId, role: payload.role };

      let body;
      try {
        body = await request.json();
      } catch (error) {
        return badRequestResponse('Invalid JSON body', 'INVALID_JSON');
      }

      // Validate request body
      const parsedBody = SchedulePostSchema.safeParse(body);
      if (!parsedBody.success) {
        return badRequestResponse(
          `Invalid request body: ${parsedBody.error.message}`,
          'VALIDATION_ERROR'
        );
      }

      const { userId, plan, version } = parsedBody.data;

      // For security, we should only allow modifying the authenticated user's schedule
      if (userId !== authUser.id) {
        return badRequestResponse('Invalid userId parameter', 'INVALID_PARAMETER');
      }

      const existing = await prisma.schedule.findFirst({
        where: {
          userId,
          active: true
        }
      });

      if (existing && existing.version > (version || 0)) {
        return NextResponse.json(
          { error: 'CONFLICT', latest: existing },
          { status: 409 }
        );
      }

      const schedule = await prisma.schedule.upsert({
        where: {
          userId_active: {
            userId,
            active: true
          }
        },
        update: {
          planJson: JSON.stringify(plan),
          version: Date.now()
        },
        create: {
          userId,
          name: "مخصص",
          title: "Default Schedule",
          startTime: new Date(),
          endTime: new Date(),
          // weeklyHours: 0, // Removed
          planJson: JSON.stringify(plan),
          active: true,
          version: Date.now()
        },
      });

      return successResponse(schedule);
    } catch (error) {
      return handleApiError(error);
    }
  });
}

import { NextRequest, NextResponse } from "next/server";
import { prisma } from '@/lib/db';
import { SubjectType, FocusStrategy } from "@/types/settings";
import { SettingsUpdateRequest } from "@/types/settings";
import { authService } from "@/lib/services/auth-service";
import { randomUUID } from "crypto";
import { logger } from '@/lib/logger';
import { opsWrapper } from "@/lib/middleware/ops-middleware";
import {
	parseRequestBody,
	createStandardErrorResponse,
	createSuccessResponse,
} from '@/app/api/auth/_helpers';

export async function GET(req: NextRequest) {
	return opsWrapper(req, async (request) => {
		try {
			// Authenticate user
			const verification = await authService.verifyTokenFromRequest(request, { checkSession: true });
			if (!verification.isValid || !verification.user) {
				return createStandardErrorResponse('Unauthorized', 'Unauthorized', 401);
			}
			const authUser = verification.user;

			const { searchParams } = new URL(request.url);
			const userId = searchParams.get("userId");

			// If userId is provided in query, ensure it matches the authenticated user
			if (userId && userId !== authUser.id) {
				return createStandardErrorResponse('Forbidden: Can only access your own settings', 'Forbidden', 403);
			}

			// Use authenticated user's ID if no userId provided in query
			const targetUserId = userId || authUser.id;

			// Fetch user with timeout protection
			const userPromise = prisma.user.findUnique({
				where: { id: targetUserId },
				select: { id: true, wakeUpTime: true, sleepTime: true, focusStrategy: true }
			});

			const userTimeoutPromise = new Promise<never>((resolve, reject) => {
				setTimeout(() => reject(new Error('Database query timeout')), 5000);
			});

			const user = await Promise.race([userPromise, userTimeoutPromise]);

			const subjectsPromise = prisma.subjectEnrollment.findMany({
				where: { userId: targetUserId },
				orderBy: { subjectId: "asc" }
			});

			const subjectsTimeoutPromise = new Promise<never>((resolve, reject) => {
				setTimeout(() => reject(new Error('Database query timeout')), 5000);
			});

			const subjects = await Promise.race([subjectsPromise, subjectsTimeoutPromise]);

			return createSuccessResponse({ user, subjects });
		} catch (e: unknown) {
			logger.error("Error fetching settings:", e);
			const errorMessage = e instanceof Error ? e.message : "Server error";
			return createStandardErrorResponse(
				e,
				errorMessage
			);
		}
	});
}

export async function POST(req: NextRequest) {
	return opsWrapper(req, async (request) => {
		try {
			// Authenticate user with timeout protection
			const verification = await authService.verifyTokenFromRequest(request, { checkSession: true });
			if (!verification.isValid || !verification.user) {
				return createStandardErrorResponse('Unauthorized', 'Unauthorized', 401);
			}
			const authUser = verification.user;


			// Parse request body with timeout protection using standardized helper
			const bodyResult = await parseRequestBody<SettingsUpdateRequest>(request, {
				maxSize: 4096, // 4KB max for settings
				required: true,
			});

			if (!bodyResult.success) {
				return bodyResult.error;
			}

			const body = bodyResult.data;
			const { userId, wakeUpTime, sleepTime, focusStrategy, subjects } = body;

			// If userId is provided in body, ensure it matches the authenticated user
			if (userId && userId !== authUser.id) {
				return createStandardErrorResponse('Forbidden: Can only update your own settings', 'Forbidden', 403);
			}

			// Use authenticated user's ID if no userId provided in body
			const targetUserId = userId || authUser.id;

			// Verify user exists with timeout protection
			const userExistsPromise = prisma.user.findUnique({
				where: { id: targetUserId },
				select: { id: true }
			});

			const userExistsTimeoutPromise = new Promise<never>((resolve, reject) => {
				setTimeout(() => reject(new Error('Database query timeout')), 5000);
			});

			const userExists = await Promise.race([userExistsPromise, userExistsTimeoutPromise]);

			if (!userExists) {
				return createStandardErrorResponse('User not found', 'User not found', 404);
			}

			// Update user settings with timeout protection
			const updateUserPromise = prisma.user.update({
				where: { id: targetUserId },
				data: {
					wakeUpTime: wakeUpTime ?? null,
					sleepTime: sleepTime ?? null,
					focusStrategy: focusStrategy ?? null
				}
			});

			const updateUserTimeoutPromise = new Promise<never>((resolve, reject) => {
				setTimeout(() => reject(new Error('Database update timeout')), 10000);
			});

			await Promise.race([updateUserPromise, updateUserTimeoutPromise]);

			// Update subject enrollments
			if (Array.isArray(subjects) && subjects.length > 0) {
				try {
					// Get existing enrollments
					const existing = await prisma.subjectEnrollment.findMany({
						where: { userId: targetUserId }
					});

					// Create a map for quick lookup
					type EnrollmentType = { subjectId: string; id: string };
					const existingMap = new Map<string, EnrollmentType>(existing.map((e: EnrollmentType) => [e.subjectId, e]));
					const incomingSubjects = new Set(subjects.map((s: { subject: string }) => s.subject));

					// Delete enrollments that are not in the incoming list
					const toDelete = existing
						.filter((e: EnrollmentType) => !incomingSubjects.has(e.subjectId))
						.map((e: EnrollmentType) => e.id);

					if (toDelete.length > 0) {
						await prisma.subjectEnrollment.deleteMany({
							where: { id: { in: toDelete } }
						});
					}

					// Process each subject enrollment
					const updatePromises: Promise<unknown>[] = [];

					for (const s of subjects) {
						// Validate subject type
						if (!Object.values(SubjectType).includes(s.subject as SubjectType)) {
							logger.warn(`Invalid subject type: ${s.subject}, skipping`);
							continue;
						}

						// Validate targetWeeklyHours
						const hours = Math.max(0, Math.floor(s.targetWeeklyHours || 0));

						// Find existing enrollment
						const existingEnrollment: EnrollmentType | undefined = existingMap.get(s.subject);

						if (existingEnrollment) {
							// Update existing enrollment
							updatePromises.push(
								prisma.subjectEnrollment.update({
									where: { id: existingEnrollment.id },
									data: { targetWeeklyHours: hours }
								}).catch((err: unknown) => {
									logger.error(`Error updating enrollment for ${s.subject}:`, err);
									throw err;
								})
							);
						} else {
							// Create new enrollment with duplicate handling
							updatePromises.push(
								prisma.subjectEnrollment.create({
									data: {
										id: randomUUID(),
										userId: targetUserId,
										subjectId: s.subject,
										targetWeeklyHours: hours
									}
								}).catch(async (err: unknown) => {
									logger.error(`Error creating enrollment for ${s.subject}:`, err);
									// If creation fails due to duplicate, try to update instead
									const error = err as { code?: string; message?: string };
									if (error?.code === 'P2002' || error?.message?.includes('Unique constraint') || error?.message?.includes('UNIQUE constraint')) {
										const existing = await prisma.subjectEnrollment.findFirst({
											where: { userId: targetUserId, subjectId: s.subject }
										});
										if (existing) {
											return prisma.subjectEnrollment.update({
												where: { id: existing.id },
												data: { targetWeeklyHours: hours }
											});
										}
									}
									// For other errors, log but don't fail the whole operation
									logger.error(`Failed to create/update enrollment for ${s.subject} after retry`);
									return null; // Return null to indicate skipped
								})
							);
						}
					}

					// Execute all updates/creates
					const results = await Promise.allSettled(updatePromises);

					// Log any failures
					results.forEach((result, index) => {
						if (result.status === 'rejected') {
							logger.error(`Failed to process subject enrollment ${index}:`, result.reason);
						}
					});
				} catch (subjectError: unknown) {
					logger.error("Error updating subject enrollments:", subjectError);
					// Don't throw - user settings were updated successfully
					// Just log the error
					if (process.env.NODE_ENV === 'development') {
						const error = subjectError as any;
						logger.error("Subject enrollment error details:", {
							message: error?.message,
							code: error?.code,
							stack: error?.stack
						});
					}
				}
			}

			return createSuccessResponse({ ok: true, message: "Settings updated successfully" });
		} catch (e: unknown) {
			logger.error("Error updating settings:", e);
			const errorMessage = e instanceof Error ? e.message : "Server error";
			return createStandardErrorResponse(
				e,
				errorMessage
			);
		}
	});
}

import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';
import { authService } from '@/lib/services/auth-service';
import { prisma } from '@/lib/db';
import { withAuthCache } from '@/lib/cache-middleware';
import { invalidateUserCache } from '@/lib/cache-invalidation-service';
import { getOrSetEnhanced } from '@/lib/cache-service-unified';
import { gamificationService } from '@/lib/services/gamification-service';
import { firestoreService } from '@/lib/services/firestore-service';
import { rateLimit, handleApiError, badRequestResponse, unauthorizedResponse, successResponse } from '@/lib/api-utils';
import { opsWrapper } from "@/lib/middleware/ops-middleware";
import { TASK_STATUS, TASK_STATUS_VALUES, TASK_PRIORITY, TASK_PRIORITY_VALUES, TASK_PRIORITY_MAP, TASK_DEFAULTS, type TaskStatus, type TaskPriority } from '@/lib/constants';

// Validation schemas
const TaskCreateSchema = z.object({
  title: z.string().min(1, "Title is required").max(200, "Title is too long"),
  description: z.string().max(1000, "Description is too long").optional(),
  dueDate: z.string().datetime().optional().nullable(),
  priority: z.enum([TASK_PRIORITY.LOW, TASK_PRIORITY.MEDIUM, TASK_PRIORITY.HIGH] as [string, ...string[]]).optional(),
  subjectId: z.string().optional().nullable(),
  status: z.enum([TASK_STATUS.PENDING, TASK_STATUS.IN_PROGRESS, TASK_STATUS.COMPLETED] as [string, ...string[]]).optional(),
});

const TaskUpdateSchema = z.object({
  id: z.string().min(1, "Task ID is required"),
  title: z.string().min(1, "Title is required").max(200, "Title is too long").optional(),
  description: z.string().max(1000, "Description is too long").optional(),
  dueDate: z.string().datetime().optional().nullable(),
  priority: z.enum([TASK_PRIORITY.LOW, TASK_PRIORITY.MEDIUM, TASK_PRIORITY.HIGH] as [string, ...string[]]).optional(),
  subjectId: z.string().optional().nullable(),
  status: z.enum([TASK_STATUS.PENDING, TASK_STATUS.IN_PROGRESS, TASK_STATUS.COMPLETED] as [string, ...string[]]).optional(),
});

// Rate limiting configuration
const GET_RATE_LIMIT = 100; // 100 requests per window
const MUTATION_RATE_LIMIT = 50; // 50 requests per window

// Handle GET requests - fetch tasks
export async function GET(request: NextRequest) {
  return opsWrapper(request, async (req) => {
    return withAuthCache(req, handleGetRequest, 'tasks', 300); // Cache for 5 minutes
  });
}

async function handleGetRequest(req: NextRequest) {
  try {
    // Apply rate limiting with timeout protection
    const rateLimitPromise = rateLimit(req, GET_RATE_LIMIT, 'get_tasks');
    const timeoutPromise = new Promise<NextResponse | null>((resolve) => {
      setTimeout(() => resolve(null), 2000); // 2 second timeout
    });

    const rateLimitResult = await Promise.race([rateLimitPromise, timeoutPromise]);
    if (rateLimitResult) {
      return rateLimitResult;
    }

    // Verify authentication using the unified AuthService with timeout protection
    const verifyPromise = authService.verifyTokenFromRequest(req);
    const verifyTimeoutPromise = new Promise<{ isValid: false }>((resolve) => {
      setTimeout(() => resolve({ isValid: false }), 5000); // 5 second timeout
    });

    const verification = await Promise.race([verifyPromise, verifyTimeoutPromise]);
    const decodedToken = verification.isValid && verification.user ? { userId: verification.user.id } : null;
    if (!decodedToken) {
      return unauthorizedResponse();
    }

    const { searchParams } = new URL(req.url);
    const limitParam = searchParams.get('limit') || '20';
    const completed = searchParams.get('completed');
    const offsetParam = searchParams.get('offset') || '0';
    const status = searchParams.get('status');
    const priority = searchParams.get('priority');
    const subjectId = searchParams.get('subjectId');

    // Validate and parse query parameters with better error handling
    const limit = parseInt(limitParam, 10);
    if (isNaN(limit) || limit > 100 || limit < 1) {
      return badRequestResponse('Invalid limit parameter. Must be between 1 and 100.', 'INVALID_PARAMETER');
    }

    const offset = parseInt(offsetParam, 10);
    if (isNaN(offset) || offset < 0) {
      return badRequestResponse('Invalid offset parameter. Must be a non-negative integer.', 'INVALID_PARAMETER');
    }

    // Validate status if provided
    if (status && !TASK_STATUS_VALUES.includes(status as TaskStatus)) {
      return badRequestResponse(`Invalid status parameter. Must be ${TASK_STATUS_VALUES.join(', ')}.`, 'INVALID_PARAMETER');
    }

    // Validate priority if provided
    if (priority && !TASK_PRIORITY_VALUES.includes(priority as TaskPriority)) {
      return badRequestResponse(`Invalid priority parameter. Must be ${TASK_PRIORITY_VALUES.join(', ')}.`, 'INVALID_PARAMETER');
    }

    // Build where clause with proper typing using Prisma types
    const where: {
      userId: string;
      completedAt?: { not: null } | null;
      status?: string;
      priority?: number;
      subject?: string;
    } = {
      userId: decodedToken.userId,
    };

    if (completed !== null) {
      const isCompleted = completed === 'true';
      where.completedAt = isCompleted ? { not: null } : null;
    }

    if (status) {
      where.status = status;
    }

    if (priority) {
      // Convert string priority to number using constants
      where.priority = TASK_PRIORITY_MAP[priority as TaskPriority] || TASK_DEFAULTS.PRIORITY_NUMBER;
    }

    if (subjectId) {
      where.subject = subjectId;
    }

    // Fetch tasks from database with timeout protection
    const fetchPromise = prisma.task.findMany({
      where,
      orderBy: {
        createdAt: 'desc',
      },
      take: limit,
      skip: offset,
    });

    const dbFetchTimeoutPromise = new Promise<never>((resolve, reject) => {
      setTimeout(() => reject(new Error('Database query timeout')), 10000); // 10 second timeout
    });

    const tasks = await Promise.race([fetchPromise, dbFetchTimeoutPromise]);

    // Return successful response
    return successResponse(tasks);
  } catch (error) {
    return handleApiError(error);
  }
}

// Handle POST requests - create task
export async function POST(request: NextRequest) {
  return opsWrapper(request, async (req) => {
      try {
      // Apply rate limiting
      const rateLimitResult = await rateLimit(req, MUTATION_RATE_LIMIT, 'create_task');
      if (rateLimitResult) {
        return rateLimitResult;
      }

      // Verify authentication using the unified AuthService
      const verification = await authService.verifyTokenFromRequest(req);
      const decodedToken = verification.isValid && verification.user ? { userId: verification.user.id } : null;
      if (!decodedToken) {
        return unauthorizedResponse();
      }

      // Parse and validate request body with timeout protection
      let body;
      try {
        const bodyPromise = req.json();
        const bodyTimeoutPromise = new Promise<never>((resolve, reject) => {
          setTimeout(() => reject(new Error('Request body parsing timeout')), 5000);
        });
        body = await Promise.race([bodyPromise, bodyTimeoutPromise]);
      } catch (parseError) {
        return badRequestResponse('Invalid request body format', 'PARSE_ERROR');
      }

      const parsedBody = TaskCreateSchema.safeParse(body);

      if (!parsedBody.success) {
        const errorMessage = parsedBody.error.errors
          .map((err) => `${err.path.join('.')}: ${err.message}`)
          .join(', ');
        return badRequestResponse(`Invalid request body: ${errorMessage}`, 'VALIDATION_ERROR');
      }

      const { title, description, dueDate, priority, subjectId, status } = parsedBody.data;

      // Validate dueDate if provided
      if (dueDate) {
        const dueDateObj = new Date(dueDate);
        if (isNaN(dueDateObj.getTime())) {
          return badRequestResponse('Invalid dueDate format. Must be a valid ISO 8601 datetime string.', 'INVALID_DATE');
        }
        if (dueDateObj < new Date()) {
          return badRequestResponse('Due date cannot be in the past', 'INVALID_DATE');
        }
      }

      // Convert priority string to number using constants
      const priorityNumber = priority 
        ? TASK_PRIORITY_MAP[priority as TaskPriority] || TASK_DEFAULTS.PRIORITY_NUMBER
        : TASK_DEFAULTS.PRIORITY_NUMBER;

      // Create task in database with timeout protection
      const createPromise = prisma.task.create({
        data: {
          id: `task_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
          title: title.trim(),
          description: description?.trim() || null,
          dueAt: dueDate ? new Date(dueDate) : null,
          priority: priorityNumber,
          status: status || TASK_DEFAULTS.STATUS,
          userId: decodedToken.userId,
          subject: subjectId || null,
        },
      });

      const createTimeoutPromise = new Promise<never>((resolve, reject) => {
        setTimeout(() => reject(new Error('Database operation timeout')), 10000);
      });

      const task = await Promise.race([createPromise, createTimeoutPromise]);

      // Invalidate cache and trigger gamification in parallel (non-blocking)
      Promise.allSettled([
        invalidateUserCache(decodedToken.userId),
        gamificationService.updateUserProgress(decodedToken.userId, 'task_created'),
      ]).catch((error) => {
        // Log but don't block response - use console in case logger is not available
        if (process.env.NODE_ENV === 'development') {
          console.warn('Cache invalidation or gamification update failed:', error);
        }
      });

      // Return successful response
      return successResponse(task, 'Task created successfully', 201);
    } catch (error) {
      return handleApiError(error);
    }
  });
}

// Handle PUT requests - update task
export async function PUT(request: NextRequest) {
  return opsWrapper(request, async (req) => {
    try {
      // Apply rate limiting
      const rateLimitResult = await rateLimit(req, MUTATION_RATE_LIMIT, 'update_task');
      if (rateLimitResult) {
        return rateLimitResult;
      }

      // Verify authentication using the unified AuthService
      const verification = await authService.verifyTokenFromRequest(req);
      const decodedToken = verification.isValid && verification.user ? { userId: verification.user.id } : null;
      if (!decodedToken) {
        return unauthorizedResponse();
      }

      // Parse and validate request body with timeout protection
      let body;
      try {
        const bodyPromise = req.json();
        const bodyTimeoutPromise = new Promise<never>((resolve, reject) => {
          setTimeout(() => reject(new Error('Request body parsing timeout')), 5000);
        });
        body = await Promise.race([bodyPromise, bodyTimeoutPromise]);
      } catch (parseError) {
        return badRequestResponse('Invalid request body format', 'PARSE_ERROR');
      }

      const parsedBody = TaskUpdateSchema.safeParse(body);

      if (!parsedBody.success) {
        const errorMessage = parsedBody.error.errors
          .map((err) => `${err.path.join('.')}: ${err.message}`)
          .join(', ');
        return badRequestResponse(`Invalid request body: ${errorMessage}`, 'VALIDATION_ERROR');
      }

      const { id, title, description, dueDate, priority, subjectId, status } = parsedBody.data;

      // Validate task ID
      if (!id || typeof id !== 'string' || id.trim().length === 0) {
        return badRequestResponse('Task ID is required and must be a non-empty string', 'INVALID_TASK_ID');
      }

      // Check if task belongs to user with timeout protection
      const findPromise = prisma.task.findUnique({
        where: {
          id: id.trim(),
        },
      });

      const findTimeoutPromise = new Promise<never>((resolve, reject) => {
        setTimeout(() => reject(new Error('Database query timeout')), 5000);
      });

      const existingTask = await Promise.race([findPromise, findTimeoutPromise]);

      if (!existingTask) {
        return badRequestResponse('Task not found', 'TASK_NOT_FOUND');
      }

      if (existingTask.userId !== decodedToken.userId) {
        return unauthorizedResponse('You do not have permission to update this task');
      }

      // Validate dueDate if provided
      if (dueDate !== undefined && dueDate !== null) {
        const dueDateObj = new Date(dueDate);
        if (isNaN(dueDateObj.getTime())) {
          return badRequestResponse('Invalid dueDate format. Must be a valid ISO 8601 datetime string.', 'INVALID_DATE');
        }
        if (dueDateObj < new Date()) {
          return badRequestResponse('Due date cannot be in the past', 'INVALID_DATE');
        }
      }

      // Convert priority string to number if provided using constants
      const priorityNumber = priority ? TASK_PRIORITY_MAP[priority as TaskPriority] : undefined;

      // Update task in database with timeout protection
      const updatePromise = prisma.task.update({
        where: {
          id: id.trim(),
        },
        data: {
          ...(title !== undefined && { title: title.trim() }),
          ...(description !== undefined && { description: description?.trim() || null }),
          ...(dueDate !== undefined && { dueAt: dueDate ? new Date(dueDate) : null }),
          ...(priorityNumber !== undefined && { priority: priorityNumber }),
          ...(status !== undefined && { status }),
          ...(subjectId !== undefined && { subject: subjectId || null }),
        },
      });

      const updateTimeoutPromise = new Promise<never>((resolve, reject) => {
        setTimeout(() => reject(new Error('Database update timeout')), 10000);
      });

      const task = await Promise.race([updatePromise, updateTimeoutPromise]);

      // Invalidate cache and trigger gamification in parallel (non-blocking)
      const wasCompleted = task.status === TASK_STATUS.COMPLETED && existingTask.status !== TASK_STATUS.COMPLETED;
      Promise.allSettled([
        invalidateUserCache(decodedToken.userId),
        wasCompleted ? gamificationService.updateUserProgress(decodedToken.userId, 'task_completed') : Promise.resolve(),
      ]).catch((error) => {
        // Log but don't block response - use console in case logger is not available
        if (process.env.NODE_ENV === 'development') {
          console.warn('Cache invalidation or gamification update failed:', error);
        }
      });

      // Return successful response
      return successResponse(task, 'Task updated successfully');
    } catch (error) {
      return handleApiError(error);
    }
  });
}

// Handle DELETE requests - delete task
export async function DELETE(request: NextRequest) {
  return opsWrapper(request, async (req) => {
    try {
      // Apply rate limiting
      const rateLimitResult = await rateLimit(req, MUTATION_RATE_LIMIT, 'delete_task');
      if (rateLimitResult) {
        return rateLimitResult;
      }

      // Verify authentication using the unified AuthService
      const verification = await authService.verifyTokenFromRequest(req);
      const decodedToken = verification.isValid && verification.user ? { userId: verification.user.id } : null;
      if (!decodedToken) {
        return unauthorizedResponse();
      }

      const { searchParams } = new URL(req.url);
      const taskId = searchParams.get('id');

      if (!taskId || typeof taskId !== 'string' || taskId.trim().length === 0) {
        return badRequestResponse('Task ID is required and must be a non-empty string', 'MISSING_TASK_ID');
      }

      const trimmedTaskId = taskId.trim();

      // Check if task belongs to user with timeout protection
      const findPromise = prisma.task.findUnique({
        where: {
          id: trimmedTaskId,
        },
      });

      const findTimeoutPromise = new Promise<never>((resolve, reject) => {
        setTimeout(() => reject(new Error('Database query timeout')), 5000);
      });

      const existingTask = await Promise.race([findPromise, findTimeoutPromise]);

      if (!existingTask) {
        return badRequestResponse('Task not found', 'TASK_NOT_FOUND');
      }

      if (existingTask.userId !== decodedToken.userId) {
        return unauthorizedResponse('You do not have permission to delete this task');
      }

      // Delete task from database with timeout protection
      const deletePromise = prisma.task.delete({
        where: {
          id: trimmedTaskId,
        },
      });

      const deleteTimeoutPromise = new Promise<never>((resolve, reject) => {
        setTimeout(() => reject(new Error('Database delete timeout')), 10000);
      });

      await Promise.race([deletePromise, deleteTimeoutPromise]);

      // Invalidate cache (non-blocking)
      invalidateUserCache(decodedToken.userId).catch((error) => {
        if (process.env.NODE_ENV === 'development') {
          console.warn('Cache invalidation failed:', error);
        }
      });

      // Return successful response
      return successResponse(null, 'Task deleted successfully');
    } catch (error) {
      return handleApiError(error);
    }
  });
}

