			// Validate required fields
			if (!email) {
				return NextResponse.json(
					{ error: "Email is required" },
					{ status: 400 }
				);
			}

			// Create or update user with TEACHER role
			const user = await prisma.user.upsert({
				where: { email },
				update: {
