				}
			});

			// If subject is provided, create enrollment
			if (subject) {
				// Check if enrollment already exists
				const existingEnrollment = await prisma.subjectEnrollment.findFirst({
					where: {
						userId: user.id,
						subjectId: subject
					}
				});

