import { NextRequest, NextResponse } from "next/server";
import { authService } from "@/lib/services/auth-service";
import { prisma } from "@/lib/db";
import { opsWrapper } from "@/lib/middleware/ops-middleware";
import { logger } from '@/lib/logger';

// GET user by ID
export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  return opsWrapper(request, async (req) => {
    try {
      const { id } = await params;
      // Verify authentication
      const payload = await authService.verifyToken(request);
      if (!payload) {
        return NextResponse.json(
          { error: "Unauthorized" },
          { status: 401 }
        );
      }
      const authUser = { id: payload.userId, role: payload.role };

      // Users can only view their own profile
      if (authUser.id !== id) {
        return NextResponse.json(
          { error: "Access denied" },
          { status: 403 }
        );
      }

      const user = await prisma.user.findUnique({
        where: { id },
        select: {
          id: true,
          name: true,
          email: true,
          avatar: true,
          createdAt: true,
          emailVerified: true,
          phone: true
        }
      });

      if (!user) {
        return NextResponse.json(
          { error: "المستخدم غير موجود" },
          { status: 404 }
        );
      }

      return NextResponse.json(user);
    } catch (error) {
      logger.error("Error fetching user:", error);
      return NextResponse.json(
        { error: "حدث خطأ في جلب بيانات المستخدم" },
        { status: 500 }
      );
    }
  });
}

// PATCH update user profile
export async function PATCH(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  return opsWrapper(request, async (req) => {
    try {
      const { id } = await params;
      // Verify authentication
      const payload = await authService.verifyToken(request);
      if (!payload) {
        return NextResponse.json(
          { error: "Unauthorized" },
          { status: 401 }
        );
      }
      const authUser = { id: payload.userId, role: payload.role };

      // Users can only update their own profile
      if (authUser.id !== id) {
        return NextResponse.json(
          { error: "Access denied" },
          { status: 403 }
        );
      }

      const { name, email } = await req.json();

      const updatedUser = await prisma.user.update({
        where: { id },
        data: {
          ...(name && { name }),
          ...(email && { email })
        },
        select: {
          id: true,
          name: true,
          email: true,
          avatar: true,
          createdAt: true
        }
      });

      return NextResponse.json(updatedUser);
    } catch (error) {
      logger.error("Error updating user:", error);
      return NextResponse.json(
        { error: "حدث خطأ في تحديث بيانات المستخدم" },
        { status: 500 }
      );
    }
  });
}

// DELETE user account
export async function DELETE(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  return opsWrapper(request, async (req) => {
    try {
      const { id } = await params;
      // Verify authentication
      const payload = await authService.verifyToken(request);
      if (!payload) {
        return NextResponse.json(
          { error: "Unauthorized" },
          { status: 401 }
        );
      }
      const authUser = { id: payload.userId, role: payload.role };

      // Users can only delete their own account
      if (authUser.id !== id) {
        return NextResponse.json(
          { error: "Access denied" },
          { status: 403 }
        );
      }

      // Delete user account and all related data
      // Note: This will cascade delete related records based on Prisma schema
      await prisma.user.delete({
        where: { id }
      });

      return NextResponse.json({
        message: "تم حذف الحساب بنجاح"
      });
    } catch (error) {
      logger.error("Error deleting user:", error);
      return NextResponse.json(
        { error: "حدث خطأ في حذف الحساب" },
        { status: 500 }
      );
    }
  });
}

﻿import { NextRequest, NextResponse } from "next/server";
import { prisma } from '@/lib/db';
import bcrypt from "bcryptjs";
import { handleApiError, badRequestResponse, successResponse } from "@/lib/api-utils";
import { opsWrapper } from "@/lib/middleware/ops-middleware";

export async function POST(req: NextRequest) {
	return opsWrapper(req, async (request) => {
		try {
			let body;
			try {
				body = await request.json();
			} catch (error) {
				return badRequestResponse('Invalid JSON body', 'INVALID_JSON');
			}

			const { email, password, name } = body;

			if (!email || !password) {
				return badRequestResponse('Email and password are required', 'MISSING_CREDENTIALS');
			}

			const existing = await prisma.user.findUnique({ where: { email } });
			if (existing) {
				return NextResponse.json(
					{
						error: 'Email already registered',
						code: 'USER_EXISTS',
						status: 409
					},
					{ status: 409 }
				);
			}

			const passwordHash = await bcrypt.hash(password, 10);
			const user = await prisma.user.create({ data: { email, passwordHash, name } });

			return successResponse(
				{ id: user.id, email: user.email, name: user.name },
				'User registered successfully',
				201
			);
		} catch (error) {
			return handleApiError(error);
		}
	});
}

import { NextRequest, NextResponse } from "next/server";
import { authService } from "@/lib/services/auth-service";
import { prisma } from '@/lib/db';
import { opsWrapper } from "@/lib/middleware/ops-middleware";
import { logger } from '@/lib/logger';
import { 
  createStandardErrorResponse, 
  createSuccessResponse,
  addSecurityHeaders 
} from '@/app/api/auth/_helpers';

// GET all users
export async function GET(request: NextRequest) {
  return opsWrapper(request, async (req) => {
    try {
      // Verify authentication with timeout protection
      const verification = await authService.verifyTokenFromRequest(req, { checkSession: true });
      if (!verification.isValid) {
        return createStandardErrorResponse(
            'Unauthorized',
            'Unauthorized',
            401
        );
      }

      // Fetch users with timeout protection
      const fetchPromise = prisma.user.findMany({
        select: {
          id: true,
          name: true,
          email: true,
          avatar: true,
          lastLogin: true
        },
        orderBy: { name: "asc" }
      });

      const timeoutPromise = new Promise<never>((resolve, reject) => {
        setTimeout(() => reject(new Error('Database query timeout')), 10000);
      });

      const users = await Promise.race([fetchPromise, timeoutPromise]);

      return createSuccessResponse(users);
    } catch (error) {
      logger.error("Error fetching users:", error);
      return createStandardErrorResponse(
        error,
        "حدث خطأ في جلب المستخدمين"
      );
    }
  });
}

