        name: 'زائر',
        role: 'STUDENT',
        emailVerified: false,
        twoFactorEnabled: false,
        lastLogin: null,
        provider: 'local',
      };

  return (
    <UserHome 
      user={apiUser} 
      summary={summary} 
      performanceMetrics={performanceMetrics}
      metricsLoading={metricsLoading}
    />
  );
}

