            </motion.div>

            {/* Performance & Analytics */}
            <motion.div variants={itemVariants}>
              <PerformanceDashboardSection metrics={performanceMetrics || []} loading={metricsLoading} />
            </motion.div>

            {/* Battle Arena (Exams) */}
            <motion.div variants={itemVariants}>
              <ExamsSection />
            </motion.div>
            
            {/* Achievements */}
            <motion.div variants={itemVariants}>
               <AchievementsSection />
            </motion.div>
            
             <motion.div variants={itemVariants}>
              <AnalyticsSection />
            </motion.div>

         </div>

         {/* Sidebar (3 Columns) */}
