// --- Types ---
export interface Achievement {
  id: string;
  icon?: React.ReactNode;
  title: string;
  description: string;
  progress: number;
  color?: string;
  iconName?: string; // Fallback for serializable data
}

export interface AchievementStat {
  id: string;
  icon?: React.ReactNode;
  value: string | number;
  label: string;
  color?: string;
}

interface AchievementsSectionProps {
  achievements?: Achievement[];
  stats?: AchievementStat[];
  loading?: boolean;
}

// --- Constants & Defaults ---
const DEFAULT_ACHIEVEMENTS: Achievement[] = [
  { id: '1', title: "بطل الدراسة", description: "أكمل 10 أيام متتالية من المذاكرة", progress: 70, color: "from-yellow-400 to-amber-500", icon: <Trophy className="text-white" /> },
  { id: '2', title: "نجم المواد", description: "احصل على معدل 90% في 3 مواد", progress: 45, color: "from-blue-400 to-indigo-500", icon: <Star className="text-white" /> },
  { id: '3', title: "محلل ممتاز", description: "استخدم أدوات التحليل 5 أيام", progress: 80, color: "from-purple-400 to-pink-500", icon: <Award className="text-white" /> },
];

const DEFAULT_STATS: AchievementStat[] = [
  { id: 'completed', icon: <CheckCircle2 className="w-5 h-5 text-green-400" />, value: "12", label: "إنجاز مكتمل", color: "bg-green-500/10 border-green-500/20" },
  { id: 'points', icon: <Star className="w-5 h-5 text-yellow-400" />, value: "2,450", label: "نقطة مكافأة", color: "bg-yellow-500/10 border-yellow-500/20" },
  { id: 'rank', icon: <Trophy className="w-5 h-5 text-purple-400" />, value: "#42", label: "الترتيب الحالي", color: "bg-purple-500/10 border-purple-500/20" },
];

// --- Sub-components ---
const AchievementCard = memo(({ achievement, index }: { achievement: Achievement; index: number }) => (
  <motion.div
    initial={{ opacity: 0, scale: 0.9 }}
    whileInView={{ opacity: 1, scale: 1 }}
    viewport={{ once: true }}
    transition={{ delay: index * 0.1, duration: 0.4 }}
    whileHover={{ y: -5 }}
    className="h-full"
  >
    <div className={`relative overflow-hidden rounded-2xl border border-white/10 bg-white/5 p-5 hover:bg-white/10 transition-all duration-300 group`}>
      <div className={`absolute inset-0 bg-gradient-to-br ${achievement.color || "from-primary to-primary/50"} opacity-0 group-hover:opacity-10 transition-opacity duration-500`} />
      
      <div className="relative z-10 flex items-start gap-4">
        <div className={`w-12 h-12 rounded-xl bg-gradient-to-br ${achievement.color || "from-gray-700 to-gray-600"} flex items-center justify-center shrink-0 shadow-lg`}>
          {achievement.icon || <Trophy className="h-6 w-6 text-white" />}
        </div>
        <div className="flex-1 space-y-1">
          <h3 className="font-bold text-gray-100 group-hover:text-primary transition-colors">{achievement.title}</h3>
          <p className="text-xs text-muted-foreground leading-snug">{achievement.description}</p>
        </div>
      </div>

      <div className="mt-4 space-y-2 relative z-10">
        <div className="flex justify-between text-xs font-medium">
          <span className="text-gray-400">التقدم</span>
          <span className="text-primary">{achievement.progress}%</span>
        </div>
        <div className="h-1.5 w-full bg-black/40 rounded-full overflow-hidden">
          <motion.div 
            initial={{ width: 0 }}
            whileInView={{ width: `${achievement.progress}%` }}
            transition={{ duration: 1, delay: 0.2 }}
            className={`h-full rounded-full bg-gradient-to-r ${achievement.color || "from-primary to-purple-500"}`}
          />
        </div>
      </div>
    </div>
  </motion.div>
));
AchievementCard.displayName = "AchievementCard";

export const AchievementsSection = memo(function AchievementsSection({ 
  achievements = DEFAULT_ACHIEVEMENTS, 
  stats = DEFAULT_STATS, 
  loading = false 
}: AchievementsSectionProps) {
  
  if (loading) {
     return <div className="h-64 animate-pulse bg-white/5 rounded-3xl" />;
  }

  return (
    <section className={rpgCommonStyles.glassPanel + " px-6 py-10"}>
       <div className="absolute inset-0 bg-[url('/grid-pattern.svg')] opacity-5 mix-blend-overlay pointer-events-none" />
       
       <div className="relative z-10">
         <div className="flex flex-col md:flex-row items-center justify-between gap-6 mb-10">
            <div className="text-center md:text-right">
              <Badge variant="outline" className="mb-3 bg-yellow-500/10 text-yellow-400 border-yellow-500/20 hover:bg-yellow-500/20 backdrop-blur-sm">
                <Sparkles className="h-3 w-3 mr-2" />
                <span>لوحة الشرف</span>
              </Badge>
              <h2 className={`text-3xl font-black ${rpgCommonStyles.goldText}`}>
                إنجازاتك الأسطورية
              </h2>
              <p className="text-muted-foreground text-sm mt-1">سجلك الحافل بالانتصارات والأوسمة</p>
            </div>

            {/* Quick Stats Row */}
            <div className="flex flex-wrap justify-center gap-3">
              {stats.map((stat) => (
                <div key={stat.id} className={`flex items-center gap-3 px-4 py-2 rounded-xl border backdrop-blur-md ${stat.color || "bg-white/5 border-white/10"}`}>
                  <div className="shrink-0">{stat.icon}</div>
                  <div className="text-center">
                    <div className="text-lg font-bold text-white leading-none">{stat.value}</div>
                    <div className="text-[10px] text-gray-400 mt-1">{stat.label}</div>
                  </div>
                </div>
              ))}
            </div>
         </div>

         <div className="grid gap-4 md:gap-6 grid-cols-1 md:grid-cols-2 lg:grid-cols-3 mb-8">
           {achievements.map((ach, idx) => (
             <AchievementCard key={ach.id} achievement={ach} index={idx} />
           ))}
         </div>

         <div className="text-center">
            <Link href="/achievements">
              <Button size="lg" variant="ghost" className="group text-gray-300 hover:text-white hover:bg-white/10">
                <span>عرض سجل الأوسمة الكامل</span>
                <ArrowRight className="mr-2 h-4 w-4 group-hover:translate-x-1 transition-transform rtl:rotate-180 rtl:group-hover:-translate-x-1" />
              </Button>
            </Link>
         </div>
       </div>
    </section>
  );
});

export default AchievementsSection;

"use client";

import { useState, useEffect, useRef, memo } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Card, CardContent } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { safeFetch, safeGetItem, safeSetItem } from "@/lib/safe-client-utils";
import { 
  Search,
  FileText,
  BookOpen,
  Users,
  Video,
  Zap,
  TrendingUp,
  Clock,
  X
} from "lucide-react";
import Link from "next/link";

import { logger } from '@/lib/logger';

interface SearchResult {
  id: string;
  type: "course" | "resource" | "task" | "teacher" | "video";
  title: string;
  description: string;
  category: string;
  relevance: number;
  url: string;
  icon: React.ReactNode;
}

interface Course {
  id: string;
  title?: string;
  name?: string;
  description?: string;
  category?: string;
  subject?: string;
}

interface Resource {
  id: string;
  type: string;
  title?: string;
  name?: string;
  description?: string;
  category?: string;
  subject?: string;
}

interface Teacher {
  id: string;
  name?: string;
  subject?: string;
  bio?: string;
  description?: string;
}

export const AdvancedSearchSection = memo(function AdvancedSearchSection() {
  const [query, setQuery] = useState("");
  const [results, setResults] = useState<SearchResult[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [recentSearches, setRecentSearches] = useState<string[]>([]);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [selectedIndex, setSelectedIndex] = useState(-1);
  const searchTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  useEffect(() => {
    // Load recent searches from localStorage using safe wrapper
    const stored = safeGetItem("recent_searches", { fallback: null });
    if (stored) {
      try {
        setRecentSearches(Array.isArray(stored) ? stored : JSON.parse(String(stored)));
      } catch {
        // Ignore parse errors
      }
    }

    // Generate suggestions based on query and recent searches
    if (query.length > 1) {
      // Filter recent searches that match the query
      const matchingRecent = recentSearches.filter(s => 
        s.toLowerCase().includes(query.toLowerCase())
      );
      
      // Only show suggestions if we have matching recent searches
      setSuggestions(matchingRecent.slice(0, 5));
      setSelectedIndex(-1);
    } else {
      setSuggestions([]);
    }
  }, [query]);

  const performSearch = async (searchQuery: string) => {
    if (!searchQuery.trim()) {
      setResults([]);
      return;
    }

    setIsSearching(true);
    
    try {
      // Search in multiple endpoints
      const [coursesData, resourcesData, teachersData] = await Promise.all([
        safeFetch<Course[]>(`/api/courses?search=${encodeURIComponent(searchQuery)}`, undefined, []),
        safeFetch<Resource[]>(`/api/resources?search=${encodeURIComponent(searchQuery)}`, undefined, []),
        safeFetch<Teacher[]>(`/api/teachers?search=${encodeURIComponent(searchQuery)}`, undefined, [])
      ]);

      const results: SearchResult[] = [];

      // Transform courses
      if (coursesData.data) {
        coursesData.data.forEach((course) => {
          results.push({
            id: `course-${course.id}`,
            type: "course",
            title: course.title || course.name || "دورة بدون عنوان",
            description: course.description || "",
            category: course.category || course.subject || "عام",
            relevance: 95,
            url: `/courses/${course.id}`,
            icon: <BookOpen className="h-5 w-5" />
          });
        });
      }

      // Transform resources
      if (resourcesData.data) {
        resourcesData.data.forEach((resource) => {
          results.push({
            id: `resource-${resource.id}`,
            type: resource.type === "video" ? "video" : "resource",
            title: resource.title || resource.name || "مورد بدون عنوان",
            description: resource.description || "",
            category: resource.category || resource.subject || "عام",
            relevance: 88,
            url: `/resources/${resource.id}`,
            icon: resource.type === "video" ? <Video className="h-5 w-5" /> : <FileText className="h-5 w-5" />
          });
        });
      }

      // Transform teachers
      if (teachersData.data) {
        teachersData.data.forEach((teacher) => {
          results.push({
            id: `teacher-${teacher.id}`,
            type: "teacher",
            title: `${teacher.name || "معلم"} - ${teacher.subject || "عام"}`,
            description: teacher.bio || teacher.description || `معلم متخصص في ${teacher.subject || "المواد الدراسية"}`,
            category: teacher.subject || "عام",
            relevance: 75,
            url: `/teachers/${teacher.id}`,
            icon: <Users className="h-5 w-5" />
          });
        });
      }

      // Sort by relevance and limit results
      const sortedResults = results
        .filter(r => 
          r.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
          r.description.toLowerCase().includes(searchQuery.toLowerCase())
        )
        .sort((a, b) => b.relevance - a.relevance)
        .slice(0, 10);

      setResults(sortedResults);

      // Save to recent searches using safe wrapper
      if (searchQuery && !recentSearches.includes(searchQuery)) {
        const updated = [searchQuery, ...recentSearches.slice(0, 4)];
        setRecentSearches(updated);
        safeSetItem("recent_searches", updated);
      }
    } catch (error) {
      logger.error("Error performing search:", error);
      setResults([]);
    } finally {
      setIsSearching(false);
    }
  };

  const handleSearch = (searchQuery: string) => {
    if (searchTimeoutRef.current) {
      clearTimeout(searchTimeoutRef.current);
    }

    searchTimeoutRef.current = setTimeout(() => {
      performSearch(searchQuery);
    }, 300);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (suggestions.length > 0) {
      if (e.key === 'ArrowDown') {
        e.preventDefault();
        setSelectedIndex(prev => (prev < suggestions.length - 1 ? prev + 1 : prev));
        return;
      }
      if (e.key === 'ArrowUp') {
        e.preventDefault();
        setSelectedIndex(prev => (prev > -1 ? prev - 1 : prev));
        return;
      }
    }
    
    if (e.key === 'Enter') {
      e.preventDefault();
      if (selectedIndex >= 0 && suggestions[selectedIndex]) {
        handleSuggestionClick(suggestions[selectedIndex]);
      } else {
        performSearch(query);
      }
    }
  };

  const handleSuggestionClick = (suggestion: string) => {
    setQuery(suggestion);
    performSearch(suggestion);
  };

  const clearSearch = () => {
    setQuery("");
    setResults([]);
    setSuggestions([]);
  };

  const getTypeLabel = (type: string) => {
    const labels: Record<string, string> = {
      course: "دورة",
      resource: "مورد",
      task: "مهمة",
      teacher: "معلم",
      video: "فيديو"
    };
    return labels[type] || type;
  };

  const getTypeColor = (type: string) => {
    const colors: Record<string, string> = {
      course: "bg-blue-100 text-blue-700",
      resource: "bg-green-100 text-green-700",
      task: "bg-purple-100 text-purple-700",
      teacher: "bg-orange-100 text-orange-700",
      video: "bg-red-100 text-red-700"
    };
    return colors[type] || "bg-gray-100 text-gray-700";
  };

  return (
    <section className="relative overflow-hidden rounded-3xl border border-slate-100/80 bg-white/80 px-6 md:px-12 py-12 shadow-xl backdrop-blur-md">
      <div className="absolute inset-0 bg-gradient-to-br from-emerald-200/25 via-transparent to-teal-200/25" />
      
      <div className="relative z-10 max-w-4xl mx-auto">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.5 }}
          className="mb-8 text-center"
        >
          <div className="flex items-center justify-center gap-3 mb-4">
            <div className="rounded-full bg-gradient-to-r from-emerald-600 to-teal-600 p-3">
              <Search className="h-6 w-6 text-white" />
            </div>
            <h2 className="text-3xl md:text-4xl font-bold text-primary">
              بحث ذكي متقدم
            </h2>
          </div>
          <p className="text-muted-foreground text-lg">
            ابحث في الدورات، الموارد، المعلمين والمزيد باستخدام الذكاء الاصطناعي
          </p>
        </motion.div>

        {/* Search Input */}
        <motion.div
          initial={{ opacity: 0, scale: 0.95 }}
          whileInView={{ opacity: 1, scale: 1 }}
          viewport={{ once: true }}
          transition={{ delay: 0.1 }}
          className="relative mb-6"
        >
          <div className="relative">
            <Search className="absolute right-4 top-1/2 -translate-y-1/2 h-5 w-5 text-muted-foreground" />
            <Input
              type="text"
              placeholder="ابحث عن دورات، موارد، معلمين..."
              value={query}
              onChange={(e) => {
                setQuery(e.target.value);
                handleSearch(e.target.value);
              }}
              onKeyDown={handleKeyDown}
              className="pr-12 pl-4 py-6 text-lg border-2 focus:border-emerald-500 rounded-full"
            />
            {query && (
              <button
                onClick={clearSearch}
                className="absolute left-4 top-1/2 -translate-y-1/2 p-1 rounded-full hover:bg-slate-100"
              >
                <X className="h-5 w-5 text-muted-foreground" />
              </button>
            )}
          </div>

          {/* Suggestions */}
          <AnimatePresence>
            {suggestions.length > 0 && (
              <motion.div
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -10 }}
                className="absolute top-full left-0 right-0 mt-2 bg-white rounded-xl shadow-xl border border-slate-200 z-50 max-h-60 overflow-y-auto"
              >
                {suggestions.map((suggestion, index) => (
                  <button
                    key={suggestion}
                    onClick={() => handleSuggestionClick(suggestion)}
                    className={`w-full text-right px-4 py-3 hover:bg-slate-50 transition-colors flex items-center gap-3 ${index === selectedIndex ? 'bg-slate-50' : ''}`}
                  >
                    <Zap className="h-4 w-4 text-emerald-600" />
                    <span className="flex-1">{suggestion}</span>
                  </button>
                ))}
              </motion.div>
            )}
          </AnimatePresence>
        </motion.div>

        {/* Recent Searches */}
        {recentSearches.length > 0 && !query && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="mb-6"
          >
            <p className="text-sm font-medium text-muted-foreground mb-3">البحث الأخير:</p>
            <div className="flex flex-wrap gap-2">
              {recentSearches.map((search, index) => (
                <Badge
                  key={index}
                  variant="outline"
                  className="cursor-pointer hover:bg-emerald-50 hover:border-emerald-300"
                  onClick={() => handleSuggestionClick(search)}
                >
                  <Clock className="h-3 w-3 mr-1" />
                  {search}
                </Badge>
              ))}
            </div>
          </motion.div>
        )}

        {/* Search Results */}
        {isSearching && (
          <div className="flex justify-center items-center py-12">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-emerald-600" />
          </div>
        )}

        <AnimatePresence>
          {results.length > 0 && !isSearching && (
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="space-y-3"
            >
              <div className="flex items-center justify-between mb-4">
                <p className="text-sm font-medium text-muted-foreground">
                  تم العثور على {results.length} نتيجة
                </p>
              </div>

              {results.map((result, index) => (
                <motion.div
                  key={result.id}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: index * 0.05 }}
                  whileHover={{ scale: 1.02 }}
                >
                  <Link href={result.url}>
                    <Card className="border-slate-200/80 shadow-sm hover:shadow-md transition-all cursor-pointer">
                      <CardContent className="p-4">
                        <div className="flex items-start gap-4">
                          <div className={`rounded-xl p-3 ${getTypeColor(result.type)} flex-shrink-0`}>
                            {result.icon}
                          </div>
                          
                          <div className="flex-1 min-w-0">
                            <div className="flex items-start justify-between gap-2 mb-2">
                              <h3 className="font-semibold text-slate-900 text-base">
                                {result.title}
                              </h3>
                              <Badge className={getTypeColor(result.type)}>
                                {getTypeLabel(result.type)}
                              </Badge>
                            </div>
                            
                            <p className="text-sm text-muted-foreground mb-3">
                              {result.description}
                            </p>

                            <div className="flex items-center gap-3">
                              <Badge variant="outline" className="text-xs">
                                {result.category}
                              </Badge>
                              <div className="flex items-center gap-1 text-xs text-muted-foreground">
                                <TrendingUp className="h-3 w-3" />
                                <span>صلة: {result.relevance}%</span>
                              </div>
                            </div>
                          </div>
                        </div>
                      </CardContent>
                    </Card>
                  </Link>
                </motion.div>
              ))}
            </motion.div>
          )}
        </AnimatePresence>

        {query && !isSearching && results.length === 0 && (
          <div className="text-center py-12">
            <Search className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
            <p className="text-muted-foreground">لم يتم العثور على نتائج</p>
            <p className="text-sm text-muted-foreground mt-2">جرب مصطلحات بحث مختلفة</p>
          </div>
        )}
      </div>
    </section>
  );
});

export default AdvancedSearchSection;

import React from 'react';
import Link from 'next/link';
import { safeFetch } from '@/lib/safe-client-utils';
import { getSafeUserId } from '@/lib/safe-client-utils';
import { logger } from '@/lib/logger';
import StatusMessage from '@/app/(dashboard)/analytics/components/StatusMessage';
import { rpgCommonStyles, rpgGradients } from "../constants";
import { Sword, Scroll, Clock, Target, RefreshCw } from "lucide-react";

/**
 * @typedef {Object} DailyData
 * @property {string} day - اسم الوحدة أو اليوم (مثل س1، س2)
 * @property {number} progress - نسبة التقدم في ذلك اليوم
 */

/**
 * @typedef {Object} AnalyticsData
 * @property {number} progressRate - معدل التقدم الحالي
 * @property {number} skillsAcquired - المهارات المكتسبة
 * @property {number} studyHours - ساعات الدراسة
 * @property {string} lastUpdate - وقت آخر تحديث
 * @property {DailyData[]} dailyProgress - بيانات التقدم على مدار 7 أيام/وحدات
 */

// Define the available paths for filtering
const PATH_OPTIONS = ['الكل', 'البرمجة', 'التصميم'];

/**
 * Function to fetch real analytics data from API based on the selected path filter.
 * @param {string} path - The selected study path (e.g., 'البرمجة').
 */
const fetchAnalyticsData = async (path: string) => {
    const userId = getSafeUserId();
    
    try {
        // Fetch analytics data from API
        const { data, error } = await safeFetch<{
            progressRate: number;
            skillsAcquired: number;
            studyHours: number;
            dailyProgress: Array<{ day: string; progress: number }>;
            timestamp: string;
        }>(
            `/api/analytics/weekly${userId ? `?userId=${userId}` : ''}${path !== 'الكل' ? `&path=${encodeURIComponent(path)}` : ''}`,
            undefined,
            null
        );

        if (error || !data) {
            // Fallback to progress summary if weekly analytics not available
            const { data: summaryData } = await safeFetch<{
                totalMinutes: number;
                averageFocus: number;
                tasksCompleted: number;
                streakDays: number;
            }>(
                `/api/progress/summary${userId ? `?userId=${userId}` : ''}`,
                undefined,
                null
            );

            if (summaryData) {
                // Calculate progress rate from summary
                const progressRate = Math.min(100, Math.round(
                    (summaryData.tasksCompleted / 10) * 20 + 
                    (summaryData.streakDays / 30) * 30 + 
                    (summaryData.averageFocus / 100) * 50
                ));
                
                // Generate daily progress from summary data
                const dailyProgress = Array.from({ length: 7 }, (_, i) => ({
                    day: `Lvl ${i + 1}`,
                    progress: Math.min(100, Math.max(0, progressRate + (i % 3 === 0 ? 5 : -2)))
                }));

                return {
                    progressRate,
                    skillsAcquired: Math.floor(summaryData.tasksCompleted / 2),
                    studyHours: Math.floor(summaryData.totalMinutes / 60),
                    dailyProgress,
                    lastUpdate: new Date().toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit', second: '2-digit' }),
                };
            }

            // Final fallback with minimal data
            return {
                progressRate: 0,
                skillsAcquired: 0,
                studyHours: 0,
                dailyProgress: Array.from({ length: 7 }, (_, i) => ({
                    day: `Lvl ${i + 1}`,
                    progress: 0
                })),
                lastUpdate: new Date().toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit', second: '2-digit' }),
            };
        }

        return {
            progressRate: data.progressRate,
            skillsAcquired: data.skillsAcquired,
            studyHours: data.studyHours,
            dailyProgress: data.dailyProgress,
            lastUpdate: new Date(data.timestamp).toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit', second: '2-digit' }),
        };
    } catch (err) {
        logger.error('Error fetching analytics data:', err);
        throw new Error("فشل جلب سجل المعارك بسبب خطأ في الخادم.");
    }
};

/**
 * DailyProgressChart Component (Visualizes progress using SVG)
 * @param {DailyData[]} chartData 
 */
const DailyProgressChart = React.memo(({ chartData }: { chartData: Array<{ day: string; progress: number }> }) => {
    if (!chartData || chartData.length === 0) {
        return <div className="text-center py-8 text-gray-500">لا تتوفر بيانات لعرض الرسم البياني.</div>;
    }

    // SVG Configuration and Scaling
    const width = 600;
    const height = 180;
    const padding = 25;

    const fixedMin = 50; 
    const fixedMax = 100;
    const rangeY = fixedMax - fixedMin;

    const scaleX = (index: number) => (index / (chartData.length - 1)) * (width - 2 * padding) + padding;
    const scaleY = (value: number) => {
        const normalizedValue = (value - fixedMin) / rangeY;
        return height - padding - (normalizedValue * (height - 2 * padding));
    };

    const points = chartData.map((d, i) => {
        const x = scaleX(i);
        const y = scaleY(d.progress);
        return `${x},${y}`;
    }).join(' L ');
    
    const lastIndex = chartData.length - 1;
    const lastPoint = chartData[lastIndex];
    const lastX = scaleX(lastIndex);
    const lastY = scaleY(lastPoint.progress);
    
    return (
        <div className="w-full bg-black/20 rounded-xl p-4 border border-white/10 shadow-lg mb-6 backdrop-blur-md">
            <h3 className="text-lg font-bold text-gray-200 mb-4 text-right border-b pb-2 border-white/10 flex items-center justify-end gap-2">
                <span>تطور المستوى القتالي (Level History)</span>
            </h3>
            
            <div className="relative overflow-x-auto">
                <svg viewBox={`0 0 ${width} ${height}`} className="w-full" preserveAspectRatio="xMidYMid meet" style={{ minWidth: '300px' }}>
                    {/* Gradient Definition for Area */}
                    <defs>
                        <linearGradient id="progressGradient" x1="0" x2="0" y1="0" y2="1">
                            <stop offset="0%" stopColor="#8b5cf6" stopOpacity={0.3} />
                            <stop offset="100%" stopColor="#8b5cf6" stopOpacity={0.05} />
                        </linearGradient>
                    </defs>
                    
                    {/* Y-Axis Grid Lines & Labels */}
                    {[100, 90, 80, 70, 60, 50].map((value, i) => {
                        const y = scaleY(value);
                        return (
                            <React.Fragment key={value}>
                                {/* Grid Line */}
                                <line
                                    x1={padding}
                                    y1={y}
                                    x2={width - padding}
                                    y2={y}
                                    stroke="#ffffff"
                                    strokeOpacity="0.1"
                                    strokeDasharray="4 4"
                                />
                                {/* Y Label */}
                                <text
                                    x={padding - 10}
                                    y={y + 4}
                                    textAnchor="end"
                                    fontSize="10"
                                    fill="#9ca3af"
                                >
                                    {value}%
                                </text>
                            </React.Fragment>
                        );
                    })}
                    
                    {/* Area under the line */}
                    <path
                        d={`M ${padding},${height - padding} L ${points} L ${width - padding},${height - padding} Z`}
                        fill="url(#progressGradient)"
                        className="transition-all duration-1000 ease-out"
                    />

                    {/* The main line path */}
                    <path 
                        d={`M ${points}`} 
                        fill="none" 
                        stroke="#8b5cf6" 
                        strokeWidth="3" 
                        strokeLinecap="round"
                        strokeLinejoin="round"
                        className="transition-all duration-1000 ease-out drop-shadow-[0_0_8px_rgba(139,92,246,0.5)]"
                    />
                    
                    {/* Data Points */}
                    {chartData.map((d, i) => (
                        <circle
                            key={i}
                            cx={scaleX(i)}
                            cy={scaleY(d.progress)}
                            r={4}
                            fill="#8b5cf6"
                            stroke="#ffffff"
                            strokeWidth="2"
                            className="transition-all duration-1000 ease-out"
                        />
                    ))}

                    {/* X-Axis Labels (Day/Unit Labels) */}
                    {chartData.map((d, i) => (
                        <text
                            key={`label-${i}`}
                            x={scaleX(i)}
                            y={height - 5}
                            textAnchor="middle"
                            fontSize="11"
                            fontWeight="bold"
                            fill="#d1d5db"
                        >
                            {d.day}
                        </text>
                    ))}
                    
                    {/* Last Point Label (Current Value) */}
                    <text
                        x={lastX}
                        y={lastY - 10}
                        textAnchor="middle"
                        fontWeight="extrabold"
                        fontSize="14"
                        fill="#a78bfa"
                        filter="drop-shadow(0 0 2px rgba(0,0,0,0.5))"
                    >
                        {`${lastPoint.progress}%`}
                    </text>
                </svg>
            </div>
            
            <p className="text-xs text-gray-400 mt-4 text-center">
                ملاحظة: هذا الرسم البياني يمثل تطور مهاراتك القتالية في آخر 7 مهام.
            </p>
        </div>
    );
});

DailyProgressChart.displayName = 'DailyProgressChart';


