import { forwardRef, ReactNode } from 'react';
import { motion, HTMLMotionProps } from 'framer-motion';
import { Loader2, LucideIcon } from 'lucide-react';
import { cn } from '@/lib/utils';

export interface AuthButtonProps extends Omit<HTMLMotionProps<"button">, 'children'> {
  children: ReactNode;
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost' | 'danger';
  size?: 'sm' | 'md' | 'lg';
  isLoading?: boolean;
  loadingText?: string;
  icon?: LucideIcon;
  iconPosition?: 'left' | 'right';
  fullWidth?: boolean;
  gradient?: boolean;
}

const variantClasses = {
  primary: cn(
    'bg-gradient-to-r from-indigo-500 to-purple-600',
    'hover:from-indigo-600 hover:to-purple-700',
    'text-white shadow-lg shadow-indigo-500/30',
    'border border-indigo-400/20'
  ),
  secondary: cn(
    'bg-white/10 hover:bg-white/20',
    'text-white',
    'border border-white/20'
  ),
  outline: cn(
    'bg-transparent hover:bg-white/5',
    'text-white',
    'border-2 border-indigo-500/50 hover:border-indigo-500'
  ),
  ghost: cn(
    'bg-transparent hover:bg-white/10',
    'text-slate-300 hover:text-white'
  ),
  danger: cn(
    'bg-gradient-to-r from-red-500 to-rose-600',
    'hover:from-red-600 hover:to-rose-700',
    'text-white shadow-lg shadow-red-500/30',
    'border border-red-400/20'
  ),
};

const sizeClasses = {
  sm: 'h-9 px-4 text-sm gap-1.5',
  md: 'h-11 px-6 text-base gap-2',
  lg: 'h-13 px-8 text-lg gap-2.5',
};

const iconSizeClasses = {
  sm: 'h-4 w-4',
  md: 'h-5 w-5',
  lg: 'h-6 w-6',
};

export const AuthButton = forwardRef<HTMLButtonElement, AuthButtonProps>(
  (
    {
      children,
      variant = 'primary',
      size = 'md',
      isLoading,
      loadingText,
      icon: Icon,
      iconPosition = 'left',
      fullWidth,
      gradient = true,
      className,
      disabled,
      ...props
    },
    ref
  ) => {
    const isDisabled = disabled || isLoading;

    return (
      <motion.button
        ref={ref}
        whileHover={!isDisabled ? { scale: 1.02 } : undefined}
        whileTap={!isDisabled ? { scale: 0.98 } : undefined}
        disabled={isDisabled}
        className={cn(
          'relative overflow-hidden rounded-xl font-semibold',
          'flex items-center justify-center',
          'transition-all duration-200',
          'focus:outline-none focus:ring-2 focus:ring-indigo-500/50 focus:ring-offset-2 focus:ring-offset-transparent',
          variantClasses[variant],
          sizeClasses[size],
          fullWidth && 'w-full',
          isDisabled && 'opacity-60 cursor-not-allowed',
          className
        )}
        {...props}
      >
        {/* Shimmer Effect for Primary */}
        {variant === 'primary' && !isDisabled && (
          <motion.div
            className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent"
            initial={{ x: '-100%' }}
            animate={{ x: '200%' }}
            transition={{
              duration: 2,
              repeat: Infinity,
              repeatDelay: 3,
            }}
          />
        )}

        {/* Content */}
        <span className="relative z-10 flex items-center justify-center gap-2">
          {isLoading ? (
            <>
              <Loader2 className={cn('animate-spin', iconSizeClasses[size])} />
              {loadingText || 'جاري التحميل...'}
            </>
          ) : (
            <>
              {Icon && iconPosition === 'left' && (
                <Icon className={iconSizeClasses[size]} />
              )}
              {children}
              {Icon && iconPosition === 'right' && (
                <Icon className={iconSizeClasses[size]} />
              )}
            </>
          )}
        </span>
      </motion.button>
    );
  }
);

AuthButton.displayName = 'AuthButton';

