'use client';

/**
 * 🔤 AuthInput - حقل إدخال محسّن للمصادقة
 * 
 * حقل إدخال مع دعم كامل لـ:
 * - الأيقونات
 * - رسائل الخطأ
 * - حالة النجاح
 * - التحميل
 * - إظهار/إخفاء كلمة المرور
 */

import { forwardRef, InputHTMLAttributes, ReactNode, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Eye, EyeOff, AlertCircle, CheckCircle, Loader2, LucideIcon } from 'lucide-react';
import { cn } from '@/lib/utils';

export interface AuthInputProps extends Omit<InputHTMLAttributes<HTMLInputElement>, 'size'> {
  label?: string;
  error?: string;
  success?: string;
  hint?: string;
  icon?: LucideIcon;
  rightIcon?: ReactNode;
  isLoading?: boolean;
  showPasswordToggle?: boolean;
  size?: 'sm' | 'md' | 'lg';
  variant?: 'default' | 'filled' | 'outline';
}

const sizeClasses = {
  sm: 'h-9 text-sm px-3',
  md: 'h-11 text-base px-4',
  lg: 'h-13 text-lg px-5',
};

const iconSizeClasses = {
  sm: 'h-4 w-4',
  md: 'h-5 w-5',
  lg: 'h-6 w-6',
};

export const AuthInput = forwardRef<HTMLInputElement, AuthInputProps>(
  (
    {
      label,
      error,
      success,
      hint,
      icon: Icon,
      rightIcon,
      isLoading,
      showPasswordToggle,
      size = 'md',
      variant = 'default',
      className,
      type,
      disabled,
      id,
      ...props
    },
    ref
  ) => {
    const [showPassword, setShowPassword] = useState(false);
    const [isFocused, setIsFocused] = useState(false);

    const inputId = id || `auth-input-${Math.random().toString(36).substr(2, 9)}`;
    const isPassword = type === 'password';
    const inputType = isPassword && showPassword ? 'text' : type;

    const hasError = Boolean(error);
    const hasSuccess = Boolean(success) && !hasError;

    return (
      <div className="w-full space-y-2">
        {/* Label */}
        {label && (
          <label
            htmlFor={inputId}
            className={cn(
              'flex items-center gap-2 text-sm font-medium transition-colors',
              hasError ? 'text-red-400' : hasSuccess ? 'text-green-400' : 'text-slate-300',
              isFocused && !hasError && !hasSuccess && 'text-indigo-400'
            )}
          >
            {Icon && <Icon className={iconSizeClasses[size]} />}
            {label}
          </label>
        )}

        {/* Input Container */}
        <div className="relative">
          {/* Left Icon */}
          {Icon && !label && (
            <div
              className={cn(
                'absolute left-3 top-1/2 -translate-y-1/2 transition-colors',
                hasError
                  ? 'text-red-400'
                  : hasSuccess
                  ? 'text-green-400'
                  : isFocused
                  ? 'text-indigo-400'
                  : 'text-slate-400'
              )}
            >
              <Icon className={iconSizeClasses[size]} />
            </div>
          )}

          {/* Input */}
          <input
            ref={ref}
            id={inputId}
            type={inputType}
            disabled={disabled || isLoading}
            onFocus={(e) => {
              setIsFocused(true);
              props.onFocus?.(e);
            }}
            onBlur={(e) => {
              setIsFocused(false);
              props.onBlur?.(e);
            }}
            className={cn(
              'w-full rounded-xl border bg-white/5 backdrop-blur-sm',
              'text-white placeholder:text-slate-500',
              'transition-all duration-200',
              'focus:outline-none focus:ring-2 focus:ring-offset-0',
              sizeClasses[size],
              Icon && !label && 'pl-11',
              (showPasswordToggle || rightIcon || isLoading) && 'pr-11',
              hasError
                ? 'border-red-500/50 focus:border-red-500 focus:ring-red-500/30'
                : hasSuccess
                ? 'border-green-500/50 focus:border-green-500 focus:ring-green-500/30'
                : 'border-white/10 focus:border-indigo-500 focus:ring-indigo-500/30 hover:border-white/20',
              disabled && 'opacity-50 cursor-not-allowed',
              className
            )}
            aria-invalid={hasError}
            aria-describedby={
              hasError
                ? `${inputId}-error`
                : hint
                ? `${inputId}-hint`
                : undefined
            }
            {...props}
          />

          {/* Right Side Elements */}
          <div className="absolute right-3 top-1/2 -translate-y-1/2 flex items-center gap-2">
            {/* Loading Spinner */}
            {isLoading && (
              <Loader2 className={cn('animate-spin text-slate-400', iconSizeClasses[size])} />
            )}

            {/* Status Icons */}
            {!isLoading && hasError && (
              <motion.div
                initial={{ scale: 0 }}
                animate={{ scale: 1 }}
                className="text-red-400"
              >
                <AlertCircle className={iconSizeClasses[size]} />
              </motion.div>
            )}
            {!isLoading && hasSuccess && (
              <motion.div
                initial={{ scale: 0 }}
                animate={{ scale: 1 }}
                className="text-green-400"
              >
                <CheckCircle className={iconSizeClasses[size]} />
              </motion.div>
            )}

            {/* Password Toggle */}
            {!isLoading && showPasswordToggle && isPassword && (
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                className="text-slate-400 hover:text-white transition-colors focus:outline-none"
                tabIndex={-1}
                aria-label={showPassword ? 'إخفاء كلمة المرور' : 'إظهار كلمة المرور'}
              >
                {showPassword ? (
                  <EyeOff className={iconSizeClasses[size]} />
                ) : (
                  <Eye className={iconSizeClasses[size]} />
                )}
              </button>
            )}

            {/* Custom Right Icon */}
            {!isLoading && rightIcon}
          </div>
        </div>

        {/* Error/Success/Hint Messages */}
        <AnimatePresence mode="wait">
          {hasError && (
            <motion.p
              id={`${inputId}-error`}
              initial={{ opacity: 0, y: -5 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -5 }}
              className="text-xs text-red-400 flex items-center gap-1"
            >
              <AlertCircle className="h-3 w-3" />
              {error}
            </motion.p>
          )}
          {hasSuccess && (
            <motion.p
              initial={{ opacity: 0, y: -5 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -5 }}
              className="text-xs text-green-400 flex items-center gap-1"
            >
              <CheckCircle className="h-3 w-3" />
              {success}
            </motion.p>
          )}
          {!hasError && !hasSuccess && hint && (
            <motion.p
              id={`${inputId}-hint`}
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              className="text-xs text-slate-500"
            >
              {hint}
            </motion.p>
          )}
        </AnimatePresence>
      </div>
    );
  }
);

AuthInput.displayName = 'AuthInput';

export default AuthInput;

'use client';

/**
 * Lockout Countdown Timer Component
 * Shows remaining lockout time with visual countdown
 */

import { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Clock, Lock, AlertTriangle } from 'lucide-react';

interface LockoutCountdownProps {
  /** Lockout end time (Unix timestamp in ms or ISO string) */
  lockedUntil: number | string;
  /** Number of failed attempts */
  attempts?: number;
  /** Callback when lockout expires */
  onLockoutEnd?: () => void;
  /** Additional CSS classes */
  className?: string;
}

interface TimeRemaining {
  minutes: number;
  seconds: number;
  total: number;
}

function formatTime(minutes: number, seconds: number): string {
  const m = String(minutes).padStart(2, '0');
  const s = String(seconds).padStart(2, '0');
  return `${m}:${s}`;
}

function calculateTimeRemaining(lockedUntil: number): TimeRemaining {
  const now = Date.now();
  const total = Math.max(0, lockedUntil - now);
  const minutes = Math.floor(total / 60000);
  const seconds = Math.floor((total % 60000) / 1000);
  return { minutes, seconds, total };
}

export function LockoutCountdown({
  lockedUntil,
  attempts = 0,
  onLockoutEnd,
  className = '',
}: LockoutCountdownProps) {
  // Convert to timestamp if ISO string
  const lockoutTimestamp = typeof lockedUntil === 'string' 
    ? new Date(lockedUntil).getTime() 
    : lockedUntil;

  const [timeRemaining, setTimeRemaining] = useState<TimeRemaining>(() => 
    calculateTimeRemaining(lockoutTimestamp)
  );

  useEffect(() => {
    // Update every second
    const interval = setInterval(() => {
      const newTime = calculateTimeRemaining(lockoutTimestamp);
      setTimeRemaining(newTime);

      if (newTime.total <= 0) {
        clearInterval(interval);
        onLockoutEnd?.();
      }
    }, 1000);

    return () => clearInterval(interval);
  }, [lockoutTimestamp, onLockoutEnd]);

  // Don't render if no lockout
  if (timeRemaining.total <= 0) {
    return null;
  }

  // Calculate progress (0 to 100)
  const initialDuration = 60 * 60 * 1000; // 60 minutes default
  const progress = Math.max(0, Math.min(100, (timeRemaining.total / initialDuration) * 100));

  return (
    <AnimatePresence>
      <motion.div
        initial={{ opacity: 0, y: -10, scale: 0.95 }}
        animate={{ opacity: 1, y: 0, scale: 1 }}
        exit={{ opacity: 0, y: -10, scale: 0.95 }}
        className={`rounded-2xl border border-red-500/30 bg-red-500/10 p-4 backdrop-blur ${className}`}
      >
        {/* Header */}
        <div className="flex items-center gap-3 text-red-400 mb-3">
          <motion.div
            animate={{ rotate: [0, 10, -10, 0] }}
            transition={{ duration: 0.5, repeat: Infinity, repeatDelay: 2 }}
          >
            <Lock className="h-5 w-5" />
          </motion.div>
          <span className="font-semibold text-sm">تم تعليق محاولات تسجيل الدخول</span>
        </div>

        {/* Timer Display */}
        <div className="flex items-center justify-center gap-4 my-4">
          <Clock className="h-6 w-6 text-red-300" />
          <motion.span
            key={`${timeRemaining.minutes}:${timeRemaining.seconds}`}
            initial={{ scale: 1.1, opacity: 0.8 }}
            animate={{ scale: 1, opacity: 1 }}
            className="text-3xl font-bold text-white font-mono tracking-wider"
          >
            {formatTime(timeRemaining.minutes, timeRemaining.seconds)}
          </motion.span>
        </div>

        {/* Progress Bar */}
        <div className="h-2 bg-red-900/30 rounded-full overflow-hidden mb-3">
          <motion.div
            initial={{ width: '100%' }}
            animate={{ width: `${progress}%` }}
            transition={{ duration: 1 }}
            className="h-full bg-gradient-to-r from-red-500 to-orange-500 rounded-full"
          />
        </div>

        {/* Info Text */}
        <div className="flex items-start gap-2 text-xs text-slate-300">
          <AlertTriangle className="h-4 w-4 text-amber-400 shrink-0 mt-0.5" />
          <div className="text-right">
            <p>تم تعليق تسجيل الدخول بسبب محاولات متكررة فاشلة.</p>
            {attempts > 0 && (
              <p className="mt-1 text-slate-400">
                عدد المحاولات الفاشلة: <span className="text-red-400">{attempts}</span>
              </p>
            )}
            <p className="mt-1 text-slate-400">
              يمكنك المحاولة مرة أخرى بعد انتهاء العد التنازلي.
            </p>
          </div>
        </div>
      </motion.div>
    </AnimatePresence>
  );
}

export default LockoutCountdown;

"use client";

import { useLogin } from "@/hooks/use-login";
import { Loader2 } from "lucide-react";
import Link from "next/link";

export default function LoginForm() {
  const { form, onSubmit, isLoading, showTwoFactor, loginAttemptId } = useLogin();
  const { register, formState: { errors } } = form;

  if (showTwoFactor) {
      // Simple 2FA placeholder - ideally this would be a separate form or component
      // For now, redirecting user conceptually or we can handle it here if we extended useLogin to handle 2FA submit
      return (
          <div className="text-center p-6 bg-white/5 rounded-xl">
              <h3 className="text-xl font-bold text-white mb-4">التحقق بخطوتين</h3>
              <p className="text-slate-300 mb-4">تم إرسال رمز التحقق. (هذه الميزة تتطلب نموذج تحقق منفصل)</p>
               {/* This requires extending the hook and UI to handle code input */}
               {/* Since the user asked for LoginForm specifically using hooks */}
          </div>
      );
  }

  return (
    <form onSubmit={onSubmit} className="space-y-4" dir="rtl">
      {/* Email */}
      <div className="space-y-2 text-right">
        <label htmlFor="email" className="text-sm font-medium text-slate-200">
          البريد الإلكتروني
        </label>
        <input
          {...register("email")}
          id="email"
          type="email"
          placeholder="name@example.com"
          disabled={isLoading}
          className="w-full px-4 py-2 bg-slate-800/50 border border-slate-700 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent text-white placeholder-slate-400 transition-all text-right"
        />
        {errors.email && (
          <p className="text-sm text-red-400">{errors.email.message}</p>
        )}
      </div>

      {/* Password */}
      <div className="space-y-2 text-right">
        <label htmlFor="password" className="text-sm font-medium text-slate-200">
          كلمة المرور
        </label>
        <input
          {...register("password")}
          id="password"
          type="password"
          placeholder="••••••••"
          disabled={isLoading}
          className="w-full px-4 py-2 bg-slate-800/50 border border-slate-700 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent text-white placeholder-slate-400 transition-all text-right"
        />
        {errors.password && (
          <p className="text-sm text-red-400">{errors.password.message}</p>
        )}
      </div>

      {/* Options */}
      <div className="flex items-center justify-between text-sm">
        <label className="flex items-center gap-2 cursor-pointer text-slate-300 hover:text-white transition-colors">
          <input
            {...register("rememberMe")}
            type="checkbox"
            className="w-4 h-4 rounded border-slate-600 bg-slate-700 text-indigo-500 focus:ring-indigo-500 focus:ring-offset-slate-900"
          />
          تذكرني
        </label>
        <Link href="/forgot-password" className="text-indigo-400 hover:text-indigo-300 transition-colors">
          نسيت كلمة المرور؟
        </Link>
      </div>

      {/* Global Error */}
      {errors.root && (
        <div className="p-3 bg-red-500/10 border border-red-500/20 rounded-lg text-red-400 text-sm text-center">
          {errors.root.message}
        </div>
      )}

      {/* Submit */}
      <button
        type="submit"
        disabled={isLoading}
        className="w-full py-2.5 px-4 bg-indigo-600 hover:bg-indigo-500 text-white font-medium rounded-lg transition-all focus:ring-2 focus:ring-indigo-500 focus:ring-offset-2 focus:ring-offset-slate-900 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
      >
        {isLoading ? (
          <>
            <Loader2 className="w-4 h-4 animate-spin" />
            جاري التحميل...
          </>
        ) : (
          "تسجيل الدخول"
        )}
      </button>

      {/* Register Link */}
      <p className="text-center text-sm text-slate-400 mt-4">
        ليس لديك حساب؟{" "}
        <Link href="/register" className="text-indigo-400 hover:text-indigo-300 font-medium transition-colors">
          إنشاء حساب جديد
        </Link>
      </p>
    </form>
  );
}

