"use client";

import React, { useState, useEffect, useRef, useMemo } from "react";
import Link from "next/link";
import {
	Bell,
	Check,
	X,
	MoreVertical,
	Settings,
	Volume2,
	VolumeX,
	Clock,
	AlertCircle,
	Info,
	CheckCircle,
	XCircle,
	Filter,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { motion, AnimatePresence } from "framer-motion";
import { VirtualList } from "@/components/ui/VirtualList";
import { cn } from "@/lib/utils";
import { soundNotificationManager, NotificationSound } from "@/lib/notifications/sound-notifications";
import { useRealtimeNotifications } from "@/hooks/use-realtime-notifications";
import { logger } from '@/lib/logger';

import {
	DropdownMenu,
	DropdownMenuContent,
	DropdownMenuItem,
	DropdownMenuSeparator,
	DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";

interface Notification {
	id: string;
	title: string;
	message: string;
	type?: "info" | "success" | "warning" | "error";
	category?: string;
	priority?: "low" | "medium" | "high";
	isRead: boolean;
	link?: string;
	actions?: Array<{ label: string; action: string; url?: string }>;
	createdAt: string;
	time?: string;
}

import { type User } from "@/types/api/auth";

interface HeaderNotificationsProps {
	user: User | null;
	mounted: boolean;
}

const notificationIcons = {
	info: Info,
	success: CheckCircle,
	warning: AlertCircle,
	error: XCircle,
};

const notificationColors = {
	info: "bg-blue-100 dark:bg-blue-900/40 text-blue-600 dark:text-blue-400",
	success: "bg-green-100 dark:bg-green-900/40 text-green-600 dark:text-green-400",
	warning: "bg-yellow-100 dark:bg-yellow-900/40 text-yellow-600 dark:text-yellow-400",
	error: "bg-red-100 dark:bg-red-900/40 text-red-600 dark:text-red-400",
};

export function EnhancedNotifications({ user, mounted }: HeaderNotificationsProps) {
	const [isNotificationOpen, setIsNotificationOpen] = useState(false);
	const [notificationCount, setNotificationCount] = useState(0);
	const [notifications, setNotifications] = useState<Notification[]>([]);
	const [filter, setFilter] = useState<"all" | "unread" | string>("all");
	const [soundEnabled, setSoundEnabled] = useState(true);
	const notificationRef = useRef<HTMLDivElement>(null);

	// Load sound preference
	useEffect(() => {
		if (mounted) {
			setSoundEnabled(soundNotificationManager.isEnabled());
		}
	}, [mounted]);

	// Realtime notifications
		const { disconnect } = useRealtimeNotifications({
		onNotification: (notification) => {
			// Add to notifications list
			setNotifications((prev) => {
				const newNotification: Notification = {
					id: notification.id || String(Date.now()),
					title: notification.title || '',
					message: notification.message || '',
					type: notification.type || 'info',
					isRead: notification.isRead || false,
					createdAt: notification.createdAt || new Date().toISOString(),
				};
				return [newNotification, ...prev];
			});
			setNotificationCount((prev) => prev + 1);
		},
		enabled: mounted && !!user,
	});

	// Fetch notifications
	useEffect(() => {
		if (!mounted || !user) return;

		const fetchNotifications = async () => {
			try {
				// Fetch notification count
				const countRes = await fetch("/api/notifications/unread-count");
				if (countRes.ok) {
					const countData = await countRes.json();
					if (countData.count !== undefined) {
						const prevCount = notificationCount;
						setNotificationCount(countData.count);

						// Play sound if new notification
						if (countData.count > prevCount && soundEnabled) {
							soundNotificationManager.play("default");
						}
					}
				}

				// Fetch recent notifications
				const params = new URLSearchParams({
					limit: "10",
					...(filter !== "all" && { unreadOnly: filter === "unread" ? "true" : "false" }),
					...(filter !== "all" && filter !== "unread" && { category: filter }),
				});

				const res = await fetch(`/api/notifications?${params}`);
				if (res.ok) {
					const data = await res.json();
					if (data.notifications) {
						setNotifications(data.notifications);
					} else if (Array.isArray(data)) {
						setNotifications(data);
					}
				}
			} catch (error) {
				logger.debug("Failed to fetch notifications:", error);
			}
		};

		fetchNotifications();
		const interval = setInterval(fetchNotifications, 30000); // Poll every 30 seconds

		return () => clearInterval(interval);
	}, [user, mounted, filter, notificationCount, soundEnabled]);

	// Group notifications by category
	const groupedNotifications = useMemo(() => {
		const groups: Record<string, Notification[]> = {};
		notifications.forEach((notif) => {
			const category = notif.category || "عام";
			if (!groups[category]) {
				groups[category] = [];
			}
			groups[category].push(notif);
		});
		return groups;
	}, [notifications]);

	// Filtered notifications
	const filteredNotifications = useMemo(() => {
		if (filter === "all") return notifications;
		if (filter === "unread") return notifications.filter((n) => !n.isRead);
		return notifications.filter((n) => n.category === filter);
	}, [notifications, filter]);

	// Mark as read
	const markAsRead = async (id: string) => {
		try {
			await fetch("/api/notifications/mark-read", {
				method: "POST",
				headers: { "Content-Type": "application/json" },
				body: JSON.stringify({ notificationIds: [id] }),
			});
			setNotifications((prev) =>
				prev.map((n) => (n.id === id ? { ...n, isRead: true } : n))
			);
			setNotificationCount((prev) => Math.max(0, prev - 1));
		} catch (error) {
			logger.error("Error marking notification as read:", error);
		}
	};

	// Mark all as read
	const markAllAsRead = async () => {
		try {
			await fetch("/api/notifications/mark-read", {
				method: "POST",
				headers: { "Content-Type": "application/json" },
				body: JSON.stringify({ all: true }),
			});
			setNotifications((prev) => prev.map((n) => ({ ...n, isRead: true })));
			setNotificationCount(0);
		} catch (error) {
			logger.error("Error marking all notifications as read:", error);
		}
	};

	// Toggle sound
	const toggleSound = () => {
		const newValue = !soundEnabled;
		setSoundEnabled(newValue);
		soundNotificationManager.setEnabled(newValue);
	};

	// Close dropdown when clicking outside
	useEffect(() => {
		if (!mounted || !isNotificationOpen) return;

		const handleClickOutside = (event: MouseEvent) => {
			const target = event.target as HTMLElement;
			if (
				notificationRef.current &&
				!notificationRef.current.contains(target) &&
				!target?.closest?.("[data-notification-trigger]")
			) {
				setIsNotificationOpen(false);
			}
		};

		document.addEventListener("mousedown", handleClickOutside);
		return () => document.removeEventListener("mousedown", handleClickOutside);
	}, [isNotificationOpen, mounted]);

	if (!mounted || !user) return null;

	return (
		<div className="relative" ref={notificationRef}>
			<motion.div whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}>
				<Button
					variant="ghost"
					size="icon"
					onClick={() => setIsNotificationOpen(!isNotificationOpen)}
					data-notification-trigger
					className="relative hover:bg-primary/10 hover:text-primary transition-all duration-300 group"
					suppressHydrationWarning
				>
					<Bell className="h-4 w-4 transition-transform group-hover:rotate-12" />
					{notificationCount > 0 && (
						<motion.span
							initial={false}
							animate={{ scale: 1 }}
							style={{ transform: "none" }}
							className="absolute top-1 right-1 flex h-5 w-5 items-center justify-center rounded-full bg-gradient-to-r from-destructive via-destructive to-destructive/80 text-destructive-foreground text-[10px] font-bold shadow-lg ring-2 ring-background"
							suppressHydrationWarning
						>
							{notificationCount > 9 ? "9+" : notificationCount}
						</motion.span>
					)}
				</Button>
			</motion.div>

			<AnimatePresence>
				{isNotificationOpen && (
					<motion.div
						initial={{ opacity: 0, y: -10, scale: 0.95 }}
						animate={{ opacity: 1, y: 0, scale: 1 }}
						exit={{ opacity: 0, y: -10, scale: 0.95 }}
						transition={{ duration: 0.2 }}
						className="absolute left-0 top-full mt-2 w-96 max-w-[calc(100vw-2rem)] bg-background border border-border rounded-lg shadow-xl z-50 max-h-[32rem] overflow-hidden flex flex-col"
					>
						{/* Header */}
						<div className="p-4 border-b border-border flex items-center justify-between">
							<div className="flex items-center gap-2">
								<h3 className="font-semibold text-sm">الإشعارات</h3>
								{notificationCount > 0 && (
									<span className="px-2 py-0.5 rounded-full bg-primary/10 text-primary text-xs font-medium">
										{notificationCount}
									</span>
								)}
							</div>
							<div className="flex items-center gap-1">
								<Button
									variant="ghost"
									size="icon"
									onClick={toggleSound}
									className="h-8 w-8"
									title={soundEnabled ? "تعطيل الصوت" : "تفعيل الصوت"}
								>
									{soundEnabled ? (
										<Volume2 className="h-4 w-4" />
									) : (
										<VolumeX className="h-4 w-4" />
									)}
								</Button>
								<DropdownMenu>
									<DropdownMenuTrigger asChild>
										<Button variant="ghost" size="icon" className="h-8 w-8">
											<MoreVertical className="h-4 w-4" />
										</Button>
									</DropdownMenuTrigger>
									<DropdownMenuContent align="end">
										<DropdownMenuItem onClick={markAllAsRead}>
											<Check className="h-4 w-4 mr-2" />
											تحديد الكل كمقروء
										</DropdownMenuItem>
										<DropdownMenuSeparator />
										<DropdownMenuItem asChild>
											<Link href="/notifications">
												<Settings className="h-4 w-4 mr-2" />
												إعدادات الإشعارات
											</Link>
										</DropdownMenuItem>
									</DropdownMenuContent>
								</DropdownMenu>
							</div>
						</div>

						{/* Filter Tabs */}
						<div className="px-4 py-2 border-b border-border flex items-center gap-2 overflow-x-auto">
							<button
								onClick={() => setFilter("all")}
								className={cn(
									"px-3 py-1 rounded-md text-xs font-medium transition-colors whitespace-nowrap",
									filter === "all"
										? "bg-primary text-primary-foreground"
										: "hover:bg-accent text-muted-foreground"
								)}
							>
								الكل
							</button>
							<button
								onClick={() => setFilter("unread")}
								className={cn(
									"px-3 py-1 rounded-md text-xs font-medium transition-colors whitespace-nowrap",
									filter === "unread"
										? "bg-primary text-primary-foreground"
										: "hover:bg-accent text-muted-foreground"
								)}
							>
								غير المقروء
							</button>
						</div>

						{/* Notifications List */}
						<div className="flex-1 overflow-y-auto" style={{ maxHeight: "24rem" }}>
							{filteredNotifications.length > 0 ? (
								<VirtualList
									items={filteredNotifications}
									itemHeight={100}
									containerHeight={384}
									keyExtractor={(item) => item.id}
									renderItem={(notification) => {
										const Icon = notificationIcons[notification.type || "info"];
										const colorClass = notificationColors[notification.type || "info"];

										return (
											<div
												className={cn(
													"p-4 border-b border-border last:border-0 transition-colors",
													!notification.isRead && "bg-primary/5"
												)}
											>
												<div className="flex items-start gap-3">
													<div className={cn("flex-shrink-0 p-2 rounded-lg", colorClass)}>
														<Icon className="h-4 w-4" />
													</div>
													<div className="flex-1 min-w-0">
														<div className="flex items-start justify-between gap-2">
															<div className="flex-1 min-w-0">
																<p className="text-sm font-medium truncate">
																	{notification.title}
																</p>
																<p className="text-xs text-muted-foreground mt-1 line-clamp-2">
																	{notification.message}
																</p>
																{notification.time && (
																	<p className="text-xs text-muted-foreground mt-1 flex items-center gap-1">
																		<Clock className="h-3 w-3" />
																		{notification.time}
																	</p>
																)}
															</div>
															{!notification.isRead && (
																<Button
																	variant="ghost"
																	size="icon"
																	className="h-6 w-6"
																	onClick={() => markAsRead(notification.id)}
																>
																	<Check className="h-3 w-3" />
																</Button>
															)}
														</div>
														{notification.actions && notification.actions.length > 0 && (
															<div className="flex items-center gap-2 mt-2">
																{notification.actions.map((action, idx) => (
																	<Button
																		key={idx}
																		variant="outline"
																		size="sm"
																		className="h-7 text-xs"
																		onClick={() => {
																			if (action.url) {
																				window.location.href = action.url;
																			}
																		}}
																	>
																		{action.label}
																	</Button>
																))}
															</div>
														)}
													</div>
												</div>
											</div>
										);
									}}
									overscan={2}
								/>
							) : (
								<div className="p-8 text-center text-muted-foreground">
									<Bell className="h-8 w-8 mx-auto mb-2 opacity-50" />
									<p className="text-sm">لا توجد إشعارات</p>
								</div>
							)}
						</div>

						{/* Footer */}
						<div className="p-3 border-t border-border">
							<Link
								href="/notifications"
								onClick={() => setIsNotificationOpen(false)}
								className="block text-center text-xs text-primary hover:underline"
							>
								عرض جميع الإشعارات
							</Link>
						</div>
					</motion.div>
				)}
			</AnimatePresence>
		</div>
	);
}

"use client";

import React, { memo } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Focus, Eye, EyeOff, Bell, BellOff, Search, Minimize2, Maximize2, RotateCcw, Clock } from "lucide-react";
import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
  DropdownMenuCheckboxItem,
} from "@/components/ui/dropdown-menu";
import { cn } from "@/lib/utils";
import { useFocusMode } from "./hooks/useFocusMode";

interface FocusModeToggleProps {
  className?: string;
  showLabel?: boolean;
}

export const FocusModeToggle = memo(function FocusModeToggle({
  className,
  showLabel = false,
}: FocusModeToggleProps) {
  const { state, actions, visibilityState } = useFocusMode();

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button
          variant="ghost"
          size="icon"
          className={cn(
            "relative transition-all duration-300 group",
            state.isEnabled && "text-primary bg-primary/10",
            className
          )}
          title={state.isEnabled ? "وضع التركيز مفعّل" : "وضع التركيز"}
        >
          <motion.div
            animate={{
              scale: state.isEnabled ? [1, 1.1, 1] : 1,
            }}
            transition={{
              duration: 0.3,
              ease: "easeInOut",
            }}
          >
            <Focus className="h-4 w-4" />
          </motion.div>
          
          {/* Active indicator */}
          <AnimatePresence>
            {state.isEnabled && (
              <motion.span
                initial={{ scale: 0 }}
                animate={{ scale: 1 }}
                exit={{ scale: 0 }}
                className="absolute -top-0.5 -right-0.5 w-2 h-2 bg-primary rounded-full"
              />
            )}
          </AnimatePresence>

          {showLabel && (
            <span className="mr-2 text-sm">
              {state.isEnabled ? "مركّز" : "تركيز"}
            </span>
          )}
        </Button>
      </DropdownMenuTrigger>

      <DropdownMenuContent align="end" className="w-64">
        <DropdownMenuLabel className="flex items-center justify-between">
          <span>وضع التركيز</span>
          <Button
            variant="ghost"
            size="sm"
            className="h-7 px-2 text-xs"
            onClick={actions.toggle}
          >
            {state.isEnabled ? (
              <>
                <EyeOff className="h-3 w-3 ml-1" />
                إيقاف
              </>
            ) : (
              <>
                <Eye className="h-3 w-3 ml-1" />
                تفعيل
              </>
            )}
          </Button>
        </DropdownMenuLabel>

        <DropdownMenuSeparator />

        {/* Focus mode options */}
        <DropdownMenuCheckboxItem
          checked={state.hideNotifications}
          onCheckedChange={actions.setHideNotifications}
          disabled={!state.isEnabled}
        >
          <BellOff className="h-4 w-4 ml-2" />
          إخفاء الإشعارات
        </DropdownMenuCheckboxItem>

        <DropdownMenuCheckboxItem
          checked={state.hideSearch}
          onCheckedChange={actions.setHideSearch}
          disabled={!state.isEnabled}
        >
          <Search className="h-4 w-4 ml-2" />
          إخفاء البحث
        </DropdownMenuCheckboxItem>

        <DropdownMenuCheckboxItem
          checked={state.isMinimal}
          onCheckedChange={actions.setMinimal}
          disabled={!state.isEnabled}
        >
          <Minimize2 className="h-4 w-4 ml-2" />
          وضع الحد الأدنى
        </DropdownMenuCheckboxItem>

        <DropdownMenuCheckboxItem
          checked={state.autoHideIdle}
          onCheckedChange={actions.setAutoHideIdle}
          disabled={!state.isEnabled}
        >
          <Clock className="h-4 w-4 ml-2" />
          إخفاء تلقائي عند الخمول
        </DropdownMenuCheckboxItem>

        <DropdownMenuSeparator />

        <DropdownMenuItem onClick={actions.reset} className="text-muted-foreground">
          <RotateCcw className="h-4 w-4 ml-2" />
          إعادة تعيين
        </DropdownMenuItem>

        {/* Keyboard shortcut hint */}
        <div className="px-2 py-1.5 text-xs text-muted-foreground text-center border-t mt-1">
          اختصار: <kbd className="px-1 py-0.5 bg-muted rounded text-[10px]">Ctrl+Shift+F</kbd>
        </div>
      </DropdownMenuContent>
    </DropdownMenu>
  );
});

// Compact focus mode indicator for minimal header
export const FocusModeIndicator = memo(function FocusModeIndicator({
  className,
}: {
  className?: string;
}) {
  const { state, actions } = useFocusMode();

  if (!state.isEnabled) return null;

  return (
    <motion.div
      initial={{ opacity: 0, x: -10 }}
      animate={{ opacity: 1, x: 0 }}
      exit={{ opacity: 0, x: -10 }}
      className={cn(
        "flex items-center gap-2 px-3 py-1.5 rounded-full bg-primary/10 text-primary text-xs font-medium",
        className
      )}
    >
      <Focus className="h-3.5 w-3.5" />
      <span>وضع التركيز</span>
      <button
        onClick={actions.disable}
        className="hover:bg-primary/20 rounded-full p-0.5 transition-colors"
        title="إيقاف وضع التركيز"
      >
        <EyeOff className="h-3 w-3" />
      </button>
    </motion.div>
  );
});

export default FocusModeToggle;

"use client";

import React, { useMemo } from "react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { ChevronLeft, Home } from "lucide-react";
import { motion } from "framer-motion";
import { cn } from "@/lib/utils";

interface BreadcrumbItem {
	label: string;
	href: string;
}

// Route labels mapping
const routeLabels: Record<string, string> = {
	"/": "الرئيسية",
	"/courses": "الدورات",
	"/schedule": "الجدول الدراسي",
	"/analytics": "التحليلات",
	"/forum": "المنتدى",
	"/blog": "المدونة",
	"/library": "المكتبة",
	"/time": "إدارة الوقت",
	"/profile": "الملف الشخصي",
	"/settings": "الإعدادات",
	"/notifications": "الإشعارات",
	"/help": "المساعدة",
};

export function HeaderBreadcrumbs() {
	const pathname = usePathname();

	const breadcrumbs = useMemo(() => {
		if (!pathname) return [];

		const paths = pathname.split("/").filter(Boolean);
		const items: BreadcrumbItem[] = [
			{ label: "الرئيسية", href: "/" },
		];

		let currentPath = "";
		paths.forEach((path, index) => {
			currentPath += `/${path}`;
			const label = routeLabels[currentPath] || 
				path.split("-").map(word => 
					word.charAt(0).toUpperCase() + word.slice(1)
				).join(" ");
			
			items.push({
				label,
				href: currentPath,
			});
		});

		return items;
	}, [pathname]);

	if (breadcrumbs.length <= 1) return null;

	return (
		<nav
			aria-label="Breadcrumb"
			className="hidden lg:flex items-center gap-1 text-sm text-muted-foreground px-4 py-2 border-b border-border/50 bg-background/50"
		>
			<ol className="flex items-center gap-1.5">
				{breadcrumbs.map((item, index) => {
					const isLast = index === breadcrumbs.length - 1;
					
					return (
						<li key={item.href} className="flex items-center gap-1.5">
							{index === 0 ? (
								<Link
									href={item.href}
									prefetch={true}
									className={cn(
										"flex items-center gap-1 px-2 py-1 rounded-md transition-colors",
										"hover:text-foreground hover:bg-accent/50",
										isLast && "text-foreground font-medium"
									)}
								>
									<Home className="h-3.5 w-3.5" />
									<span className="sr-only">{item.label}</span>
								</Link>
							) : (
								<>
									<ChevronLeft className="h-3.5 w-3.5 text-muted-foreground/50" />
									{isLast ? (
										<span className="px-2 py-1 text-foreground font-medium">
											{item.label}
										</span>
									) : (
										<Link
											href={item.href}
											prefetch={true}
											className="px-2 py-1 rounded-md transition-colors hover:text-foreground hover:bg-accent/50"
										>
											{item.label}
										</Link>
									)}
								</>
							)}
						</li>
					);
				})}
			</ol>
		</nav>
	);
}

