			action: () => {
				router.push("/notes/new");
				setIsOpen(false);
			},
			color: "bg-green-500",
			requiresAuth: true,
		},
		{
			id: "new-event",
			label: "حدث جديد",
			description: "إضافة حدث إلى التقويم",
			icon: <Calendar className="h-4 w-4" />,
			action: () => {
				router.push("/schedule/new");
				setIsOpen(false);
			},
			color: "bg-purple-500",
			requiresAuth: true,
		},
		{
			id: "new-post",
			label: "منشور جديد",
			description: "إنشاء منشور في المنتدى",
			icon: <MessageSquare className="h-4 w-4" />,
			action: () => {
				router.push("/forum/new");
				setIsOpen(false);
			},
			color: "bg-orange-500",
			requiresAuth: true,
		},
		{
			id: "upload-video",
			label: "رفع فيديو",
			description: "رفع فيديو تعليمي",
			icon: <Video className="h-4 w-4" />,
			action: () => {
				router.push("/upload/video");
				setIsOpen(false);
			},
			color: "bg-red-500",
			requiresAuth: true,
		},
		{
			id: "upload-image",
			label: "رفع صورة",
			description: "رفع صورة أو مستند",
			icon: <Image className="h-4 w-4" />,
			action: () => {
				router.push("/upload/image");
				setIsOpen(false);
			},
			color: "bg-pink-500",
			requiresAuth: true,
		},
	];

	// Filter actions based on auth
	const availableActions = actions.filter((action) => !action.requiresAuth || user);

	// Keyboard shortcut
	useEffect(() => {
		const handleKeyDown = (e: KeyboardEvent) => {
			if ((e.ctrlKey || e.metaKey) && e.shiftKey && e.key === "n") {
				e.preventDefault();
				setIsOpen((prev) => !prev);
			}
		};

		window.addEventListener("keydown", handleKeyDown);
		return () => window.removeEventListener("keydown", handleKeyDown);
	}, []);

	if (availableActions.length === 0) return null;

	return (
		<DropdownMenu open={isOpen} onOpenChange={setIsOpen}>
			<DropdownMenuTrigger asChild>
				<Button
					ref={triggerRef}
					variant="default"
					size="icon"
					className={cn(
						"relative h-9 w-9 rounded-lg",
						"bg-gradient-to-br from-primary to-primary/80",
						"hover:from-primary/90 hover:to-primary/70",
						"shadow-md hover:shadow-lg",
						"transition-all duration-300",
						"group"
					)}
					aria-label="إجراءات سريعة"
					title="إجراءات سريعة (Ctrl+Shift+N)"
				>
					<motion.div
						animate={{ rotate: isOpen ? 45 : 0 }}
						transition={{ duration: 0.2 }}
					>
						<Zap className="h-4 w-4 text-primary-foreground" />
					</motion.div>
					{availableActions.length > 0 && (
						<span className="absolute -top-1 -right-1 h-4 w-4 rounded-full bg-yellow-500 border-2 border-background flex items-center justify-center">
							<span className="text-[8px] font-bold text-background">{availableActions.length}</span>
						</span>
					)}
				</Button>
			</DropdownMenuTrigger>
			<DropdownMenuContent
				align="end"
				className="w-80 p-2"
				sideOffset={8}
			>
				<DropdownMenuLabel className="px-3 py-2 flex items-center gap-2">
					<Zap className="h-4 w-4 text-primary" />
					<span>إجراءات سريعة</span>
				</DropdownMenuLabel>
				<DropdownMenuSeparator />
				<div className="grid grid-cols-1 gap-1 p-1">
					<AnimatePresence>
						{availableActions.map((action, index) => (
							<motion.div
								key={action.id}
								initial={{ opacity: 0, x: -10 }}
								animate={{ opacity: 1, x: 0 }}
								exit={{ opacity: 0, x: -10 }}
								transition={{ delay: index * 0.05 }}
							>
								<DropdownMenuItem
									onClick={action.action}
									className={cn(
										"flex items-center gap-3 p-3 rounded-lg cursor-pointer",
										"hover:bg-accent transition-colors",
										"group/item"
									)}
								>
									<div
										className={cn(
											"flex items-center justify-center h-10 w-10 rounded-lg shrink-0",
											"transition-transform duration-200",
											"group-hover/item:scale-110",
											action.color
										)}
									>
										<div className="text-white">{action.icon}</div>
									</div>
									<div className="flex-1 min-w-0 text-right">
										<div className="text-sm font-medium text-foreground">{action.label}</div>
										{action.description && (
											<div className="text-xs text-muted-foreground mt-0.5">{action.description}</div>
										)}
									</div>
									<ChevronRight className="h-4 w-4 text-muted-foreground shrink-0 opacity-0 group-hover/item:opacity-100 transition-opacity" />
								</DropdownMenuItem>
							</motion.div>
						))}
					</AnimatePresence>
				</div>
				<DropdownMenuSeparator />
				<div className="px-3 py-2 text-xs text-muted-foreground text-center">
					اضغط <kbd className="px-1.5 py-0.5 rounded border bg-muted">Ctrl+Shift+N</kbd> للوصول السريع
				</div>
			</DropdownMenuContent>
		</DropdownMenu>
	);
}

"use client";

import React, { useMemo } from "react";
import { usePathname } from "next/navigation";
import { useNavigationHistory } from "@/hooks/use-navigation-history";
import { safeGetItem } from "@/lib/safe-client-utils";

interface SmartNavigationProps {
	children: React.ReactNode;
}

/**
 * Smart Navigation component that adapts menu based on usage patterns
 * - Shows most visited pages first
 * - Highlights frequently accessed items
 * - Adapts to user behavior
 */
export function SmartNavigation({ children }: SmartNavigationProps) {
	const pathname = usePathname();
	const { getMostVisited, getRecentPages } = useNavigationHistory();

	// Get usage statistics
	const usageStats = useMemo(() => {
		const mostVisited = getMostVisited(10);
		const recent = getRecentPages(10);
		
		// Get click counts from localStorage
		const clickCounts = safeGetItem("navigation_click_counts", { fallback: {} }) as Record<string, number>;
		
		return {
			mostVisited,
			recent,
			clickCounts,
		};
	}, [getMostVisited, getRecentPages]);

	// This component can wrap navigation items and provide smart ordering
	// For now, it just provides context - actual implementation would be in HeaderNavigation
	return <>{children}</>;
}

"use client";

import React, { useState, useEffect, useMemo } from "react";
import { useRouter, usePathname } from "next/navigation";
import { Clock, TrendingUp, Star, ArrowRight } from "lucide-react";
import { Button } from "@/components/ui/button";
import {
	DropdownMenu,
	DropdownMenuContent,
	DropdownMenuItem,
	DropdownMenuLabel,
	DropdownMenuSeparator,
	DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { cn } from "@/lib/utils";
import { motion, AnimatePresence } from "framer-motion";
import { useUnifiedAuth } from "@/contexts/auth-context";
import { safeGetItem } from "@/lib/safe-client-utils";

import { logger } from '@/lib/logger';

interface NavigationSuggestion {
	id: string;
	label: string;
	href: string;
	type: "recent" | "popular" | "recommended";
	icon: React.ReactNode;
	description?: string;
}

interface NavigationPage {
	path: string;
	label?: string;
	timestamp?: number;
}

export function SmartNavigationSuggestions() {
	const router = useRouter();
	const pathname = usePathname();
	const { user } = useUnifiedAuth();
	const mounted = true;
	const [suggestions, setSuggestions] = useState<NavigationSuggestion[]>([]);
	const [isOpen, setIsOpen] = useState(false);

	// Load navigation history
	useEffect(() => {
		if (!mounted) return;

		const loadSuggestions = () => {
			try {
				// Get recent pages
				const recentPages = safeGetItem<NavigationPage[]>("navigation_history", { fallback: [] });
				const popularPages = safeGetItem<NavigationPage[]>("popular_pages", { fallback: [] });

				const recent: NavigationSuggestion[] = Array.isArray(recentPages)
					? recentPages
							.slice(0, 5)
							.map((page: NavigationPage) => ({
								id: `recent-${page.path}`,
								label: page.label || page.path,
								href: page.path,
								type: "recent" as const,
								icon: <Clock className="h-4 w-4" />,
								description: "مستخدم مؤخراً",
							}))
					: [];

				const popular: NavigationSuggestion[] = Array.isArray(popularPages)
					? popularPages
							.slice(0, 5)
							.map((page: NavigationPage) => ({
								id: `popular-${page.path}`,
								label: page.label || page.path,
								href: page.path,
								type: "popular" as const,
								icon: <TrendingUp className="h-4 w-4" />,
								description: "شائع",
							}))
					: [];

				// Recommended based on user activity
				const recommended: NavigationSuggestion[] = user
					? [
							{
								id: "recommended-courses",
								label: "دورات موصى بها",
								href: "/courses?recommended=true",
								type: "recommended" as const,
								icon: <Star className="h-4 w-4" />,
								description: "مخصص لك",
							},
							{
								id: "recommended-time",
								label: "إدارة الوقت",
								href: "/time",
								type: "recommended" as const,
								icon: <Star className="h-4 w-4" />,
								description: "مخصص لك",
							},
					  ]
					: [];

				setSuggestions([...recent, ...popular, ...recommended].slice(0, 8));
			} catch (error) {
				logger.debug("Failed to load navigation suggestions:", error);
			}
		};

		loadSuggestions();

		// Update on navigation
		const handleNavigation = () => {
			loadSuggestions();
		};

		window.addEventListener("popstate", handleNavigation);
		return () => window.removeEventListener("popstate", handleNavigation);
	}, [mounted, user]);

	const handleSuggestionClick = (suggestion: NavigationSuggestion) => {
		router.push(suggestion.href);
		setIsOpen(false);

		// Track navigation
		try {
			const history = safeGetItem<NavigationPage[]>("navigation_history", { fallback: [] });
			const updated = [
				{ path: suggestion.href, label: suggestion.label, timestamp: Date.now() },
				...(Array.isArray(history) ? history : []).filter(
					(item: NavigationPage) => item.path !== suggestion.href
				),
			].slice(0, 10);
			localStorage.setItem("navigation_history", JSON.stringify(updated));
		} catch (e) {
			// Ignore
		}
	};

	const groupedSuggestions = useMemo(() => {
		const groups: Record<string, NavigationSuggestion[]> = {
			recent: [],
			popular: [],
			recommended: [],
		};

		suggestions.forEach((suggestion) => {
			groups[suggestion.type].push(suggestion);
		});

		return groups;
	}, [suggestions]);

	if (!mounted || suggestions.length === 0) return null;

	return (
		<DropdownMenu open={isOpen} onOpenChange={setIsOpen}>
			<DropdownMenuTrigger asChild>
				<Button
					variant="ghost"
					size="sm"
					className="hidden lg:flex items-center gap-2 h-9"
					aria-label="اقتراحات التنقل الذكية"
				>
					<TrendingUp className="h-4 w-4" />
					<span className="text-xs">اقتراحات</span>
				</Button>
			</DropdownMenuTrigger>
			<DropdownMenuContent align="end" className="w-72 p-0" sideOffset={8}>
				<DropdownMenuLabel className="px-4 py-3 flex items-center gap-2">
					<TrendingUp className="h-4 w-4 text-primary" />
					<span>اقتراحات التنقل</span>
				</DropdownMenuLabel>
				<DropdownMenuSeparator />

				<div className="max-h-[400px] overflow-y-auto p-2 space-y-4">
					{groupedSuggestions.recommended.length > 0 && (
						<div>
							<div className="text-xs font-semibold text-muted-foreground px-2 mb-2">
								موصى به لك
							</div>
							<div className="space-y-1">
								{groupedSuggestions.recommended.map((suggestion) => (
									<DropdownMenuItem
										key={suggestion.id}
										onClick={() => handleSuggestionClick(suggestion)}
										className="flex items-center gap-3 p-2.5 rounded-lg cursor-pointer hover:bg-accent"
									>
										<div className="flex items-center justify-center h-8 w-8 rounded-lg bg-yellow-500/10 text-yellow-600 shrink-0">
											{suggestion.icon}
										</div>
										<div className="flex-1 min-w-0 text-right">
											<div className="text-sm font-medium text-foreground">{suggestion.label}</div>
											{suggestion.description && (
												<div className="text-xs text-muted-foreground">{suggestion.description}</div>
											)}
										</div>
										<ArrowRight className="h-4 w-4 text-muted-foreground shrink-0" />
									</DropdownMenuItem>
								))}
							</div>
						</div>
					)}

					{groupedSuggestions.recent.length > 0 && (
						<div>
							<div className="text-xs font-semibold text-muted-foreground px-2 mb-2">مستخدم مؤخراً</div>
							<div className="space-y-1">
								{groupedSuggestions.recent.map((suggestion) => (
									<DropdownMenuItem
										key={suggestion.id}
										onClick={() => handleSuggestionClick(suggestion)}
										className="flex items-center gap-3 p-2.5 rounded-lg cursor-pointer hover:bg-accent"
									>
										<div className="flex items-center justify-center h-8 w-8 rounded-lg bg-blue-500/10 text-blue-600 shrink-0">
											{suggestion.icon}
										</div>
										<div className="flex-1 min-w-0 text-right">
											<div className="text-sm font-medium text-foreground">{suggestion.label}</div>
										</div>
										<ArrowRight className="h-4 w-4 text-muted-foreground shrink-0" />
									</DropdownMenuItem>
								))}
							</div>
						</div>
					)}

					{groupedSuggestions.popular.length > 0 && (
						<div>
							<div className="text-xs font-semibold text-muted-foreground px-2 mb-2">شائع</div>
							<div className="space-y-1">
								{groupedSuggestions.popular.map((suggestion) => (
									<DropdownMenuItem
										key={suggestion.id}
										onClick={() => handleSuggestionClick(suggestion)}
										className="flex items-center gap-3 p-2.5 rounded-lg cursor-pointer hover:bg-accent"
									>
										<div className="flex items-center justify-center h-8 w-8 rounded-lg bg-green-500/10 text-green-600 shrink-0">
											{suggestion.icon}
										</div>
										<div className="flex-1 min-w-0 text-right">
											<div className="text-sm font-medium text-foreground">{suggestion.label}</div>
										</div>
										<ArrowRight className="h-4 w-4 text-muted-foreground shrink-0" />
									</DropdownMenuItem>
								))}
							</div>
						</div>
					)}
				</div>
			</DropdownMenuContent>
		</DropdownMenu>
	);
}

/**
 * مثال استخدام سريع لملفات التطويرات
 * Quick Usage Example for Header Enhancements
 */
import { logger } from '@/lib/logger';


// ==================== مثال 1: عرض جميع التطويرات ====================
import {
	headerEnhancements,
	getEnhancementsByPriority,
	getEnhancementsByCategory,
	getEnhancementStats
} from "./header-enhancements";

// الحصول على جميع التطويرات
logger.info("إجمالي التطويرات:", headerEnhancements.length);

// الحصول على التطويرات عالية الأولوية فقط
const highPriorityFeatures = getEnhancementsByPriority("high");
logger.info("التطويرات عالية الأولوية:", highPriorityFeatures.length);

// الحصول على التطويرات في فئة معينة
const searchFeatures = getEnhancementsByCategory("البحث المتقدم");
logger.info("ميزات البحث:", searchFeatures);

// الحصول على إحصائيات
const stats = getEnhancementStats();
logger.info("الإحصائيات:", stats);

// ==================== مثال 2: عرض خطة التنفيذ ====================
import {
	implementationPhases,
	priorityImplementationOrder,
	recommendedTechnologies
} from "./header-implementation-plan";

// عرض جميع المراحل
implementationPhases.forEach((phase, index) => {
	logger.info(`\nالمرحلة ${phase.phase}: ${phase.name}`);
	logger.info(`المدة: ${phase.duration}`);
	logger.info(`الميزات: ${phase.features.length} ميزة`);
});

// عرض الأولويات
priorityImplementationOrder.forEach((priority) => {
	logger.info(`\n${priority.level}:`);
	priority.features.forEach((feature) => {
		logger.info(`  - ${feature}`);
	});
});

// عرض التقنيات الموصى بها
logger.info("\nالتقنيات الموصى بها للأداء:", recommendedTechnologies.performance);
logger.info("التقنيات الموصى بها للبحث:", recommendedTechnologies.search);

// ==================== مثال 3: استخدام الملخص السريع ====================
import {
	headerFeaturesSummary,
	quickStats,
	quickPriorities
} from "./header-features-summary";

// عرض الميزات حسب الفئة
Object.entries(headerFeaturesSummary).forEach(([category, features]) => {
	logger.info(`\n${category}:`);
	features.forEach((feature) => {
		logger.info(`  - ${feature}`);
	});
});

// عرض الإحصائيات السريعة
logger.info("\nالإحصائيات السريعة:", quickStats);

// عرض الأولويات السريعة
logger.info("\nأولويات المرحلة الأولى:", quickPriorities.phase1);

// ==================== مثال 4: إنشاء قائمة مهام ====================
function createTaskList() {
	const highPriority = getEnhancementsByPriority("high");
	const simpleTasks = highPriority.filter((e) => e.complexity === "simple");
	
	logger.info("\nالمهام السهلة عالية الأولوية:");
	simpleTasks.forEach((task, index) => {
		logger.info(`${index + 1}. ${task.feature} (${task.category})`);
	});
	
	return simpleTasks.map((task) => ({
		title: task.feature,
		category: task.category,
		description: task.description
	}));
}

// ==================== مثال 5: تصفية حسب المعايير ====================
function getRecommendedFeatures() {
	// ميزات عالية الأولوية وسهلة التنفيذ
	return headerEnhancements.filter(
		(e) => e.priority === "high" && e.complexity === "simple"
	);
}

// ميزات معقدة لكن مهمة
function getComplexHighPriorityFeatures() {
	return headerEnhancements.filter(
		(e) => e.priority === "high" && e.complexity === "complex"
	);
}

// ==================== مثال 6: إنشاء خطة تنفيذ مخصصة ====================
function createCustomImplementationPlan(focusAreas: string[]) {
	const plan = focusAreas.map((area) => {
		const features = getEnhancementsByCategory(area);
		return {
			area,
			features: features.length,
			highPriority: features.filter((f) => f.priority === "high").length,
			estimatedTime: `${features.length * 2} أسابيع`
		};
	});
	
	return plan;
}

// استخدام المثال
const customPlan = createCustomImplementationPlan([
	"تجربة المستخدم",
	"البحث المتقدم",
	"الأداء والتحسينات"
]);

logger.info("\nالخطة المخصصة:", customPlan);

