"use client";

import { useState, useEffect, useCallback, createContext, useContext } from "react";
import { safeGetItem, safeSetItem } from "@/lib/safe-client-utils";

export interface FocusModeState {
    isEnabled: boolean;
    isMinimal: boolean;
    hideNotifications: boolean;
    hideSearch: boolean;
    hideUserMenu: boolean;
    autoHideIdle: boolean;
    idleTimeout: number;
}

export interface FocusModeActions {
    toggle: () => void;
    enable: () => void;
    disable: () => void;
    setMinimal: (value: boolean) => void;
    setHideNotifications: (value: boolean) => void;
    setHideSearch: (value: boolean) => void;
    setHideUserMenu: (value: boolean) => void;
    setAutoHideIdle: (value: boolean) => void;
    setIdleTimeout: (timeout: number) => void;
    reset: () => void;
}

const defaultState: FocusModeState = {
    isEnabled: false,
    isMinimal: false,
    hideNotifications: true,
    hideSearch: false,
    hideUserMenu: false,
    autoHideIdle: false,
    idleTimeout: 5000,
};

const STORAGE_KEY = "header_focus_mode";

export function useFocusMode() {
    const [state, setState] = useState<FocusModeState>(defaultState);
    const [mounted, setMounted] = useState(false);
    const [isIdle, setIsIdle] = useState(false);

    // Load saved preferences
    useEffect(() => {
        setMounted(true);
        const saved = safeGetItem(STORAGE_KEY, { fallback: null });
        if (saved && typeof saved === 'object' && saved !== null) {
            setState((prev) => ({ ...prev, ...(saved as Partial<FocusModeState>) }));
        }
    }, []);

    // Save preferences when they change
    useEffect(() => {
        if (mounted) {
            safeSetItem(STORAGE_KEY, state);
        }
    }, [state, mounted]);

    // Auto-hide on idle functionality
    useEffect(() => {
        if (!mounted || !state.autoHideIdle || !state.isEnabled) {
            setIsIdle(false);
            return;
        }

        let idleTimer: NodeJS.Timeout;

        const resetIdleTimer = () => {
            setIsIdle(false);
            clearTimeout(idleTimer);
            idleTimer = setTimeout(() => {
                setIsIdle(true);
            }, state.idleTimeout);
        };

        // Events that reset idle timer
        const events = ["mousedown", "mousemove", "keydown", "scroll", "touchstart"];
        events.forEach((event) => {
            document.addEventListener(event, resetIdleTimer, { passive: true });
        });

        // Initial timer
        resetIdleTimer();

        return () => {
            clearTimeout(idleTimer);
            events.forEach((event) => {
                document.removeEventListener(event, resetIdleTimer);
            });
        };
    }, [mounted, state.autoHideIdle, state.isEnabled, state.idleTimeout]);

    // Keyboard shortcut (Ctrl/Cmd + Shift + F)
    useEffect(() => {
        if (!mounted) return;

        const handleKeyDown = (e: KeyboardEvent) => {
            if ((e.ctrlKey || e.metaKey) && e.shiftKey && e.key.toLowerCase() === "f") {
                e.preventDefault();
                setState((prev) => ({ ...prev, isEnabled: !prev.isEnabled }));
            }
        };

        window.addEventListener("keydown", handleKeyDown);
        return () => window.removeEventListener("keydown", handleKeyDown);
    }, [mounted]);

    const actions: FocusModeActions = {
        toggle: useCallback(() => {
            setState((prev) => ({ ...prev, isEnabled: !prev.isEnabled }));
        }, []),

        enable: useCallback(() => {
            setState((prev) => ({ ...prev, isEnabled: true }));
        }, []),

        disable: useCallback(() => {
            setState((prev) => ({ ...prev, isEnabled: false }));
        }, []),

        setMinimal: useCallback((value: boolean) => {
            setState((prev) => ({ ...prev, isMinimal: value }));
        }, []),

        setHideNotifications: useCallback((value: boolean) => {
            setState((prev) => ({ ...prev, hideNotifications: value }));
        }, []),

        setHideSearch: useCallback((value: boolean) => {
            setState((prev) => ({ ...prev, hideSearch: value }));
        }, []),

        setHideUserMenu: useCallback((value: boolean) => {
            setState((prev) => ({ ...prev, hideUserMenu: value }));
        }, []),

        setAutoHideIdle: useCallback((value: boolean) => {
            setState((prev) => ({ ...prev, autoHideIdle: value }));
        }, []),

        setIdleTimeout: useCallback((timeout: number) => {
            setState((prev) => ({ ...prev, idleTimeout: timeout }));
        }, []),

        reset: useCallback(() => {
            setState(defaultState);
        }, []),
    };

    // Computed values for header visibility
    const shouldHideHeader = state.isEnabled && state.autoHideIdle && isIdle;
    const shouldShowMinimal = state.isEnabled && state.isMinimal;

    const visibilityState = {
        showNotifications: !state.isEnabled || !state.hideNotifications,
        showSearch: !state.isEnabled || !state.hideSearch,
        showUserMenu: !state.isEnabled || !state.hideUserMenu,
        showNavigation: !shouldShowMinimal,
        headerVisible: !shouldHideHeader,
    };

    return {
        state,
        actions,
        isIdle,
        visibilityState,
        mounted,
    };
}

// Context for global focus mode state
interface FocusModeContextType {
    state: FocusModeState;
    actions: FocusModeActions;
    isIdle: boolean;
    visibilityState: {
        showNotifications: boolean;
        showSearch: boolean;
        showUserMenu: boolean;
        showNavigation: boolean;
        headerVisible: boolean;
    };
}

const FocusModeContext = createContext<FocusModeContextType | null>(null);

export function useFocusModeContext() {
    const context = useContext(FocusModeContext);
    if (!context) {
        throw new Error("useFocusModeContext must be used within FocusModeProvider");
    }
    return context;
}

export { FocusModeContext };
export default useFocusMode;

"use client";

import { useState, useEffect, useCallback, useRef } from "react";

export interface StickyHeaderState {
    isScrolled: boolean;
    isShrunk: boolean;
    isHidden: boolean;
    scrollY: number;
    scrollDirection: "up" | "down" | null;
    scrollProgress: number;
}

export interface UseStickyHeaderOptions {
    shrinkThreshold?: number;
    hideThreshold?: number;
    showOnScrollUp?: boolean;
    enableProgress?: boolean;
    debounceMs?: number;
}

const defaultOptions: UseStickyHeaderOptions = {
    shrinkThreshold: 50,
    hideThreshold: 200,
    showOnScrollUp: true,
    enableProgress: true,
    debounceMs: 10,
};

export function useStickyHeader(options: UseStickyHeaderOptions = {}) {
    const opts = { ...defaultOptions, ...options };

    const [state, setState] = useState<StickyHeaderState>({
        isScrolled: false,
        isShrunk: false,
        isHidden: false,
        scrollY: 0,
        scrollDirection: null,
        scrollProgress: 0,
    });

    const lastScrollY = useRef(0);
    const ticking = useRef(false);
    const frameId = useRef<number | null>(null);

    const calculateProgress = useCallback(() => {
        if (typeof document === "undefined") return 0;

        const scrollTop = window.scrollY;
        const docHeight = document.documentElement.scrollHeight;
        const winHeight = window.innerHeight;
        const scrollableHeight = docHeight - winHeight;

        if (scrollableHeight <= 0) return 0;
        return Math.min(100, Math.max(0, (scrollTop / scrollableHeight) * 100));
    }, []);

    const updateState = useCallback(() => {
        if (typeof window === "undefined") return;

        const currentScrollY = window.scrollY;
        const scrollDirection = currentScrollY > lastScrollY.current ? "down" : "up";
        const scrollDelta = Math.abs(currentScrollY - lastScrollY.current);

        // Only update if scroll delta is significant
        if (scrollDelta < 5 && currentScrollY !== 0) {
            ticking.current = false;
            return;
        }

        const isScrolled = currentScrollY > 10;
        const isShrunk = currentScrollY > (opts.shrinkThreshold || 50);

        let isHidden = false;
        if (opts.showOnScrollUp) {
            // Hide when scrolling down past threshold, show when scrolling up
            if (scrollDirection === "down" && currentScrollY > (opts.hideThreshold || 200)) {
                isHidden = true;
            } else if (scrollDirection === "up") {
                isHidden = false;
            }
        }

        const scrollProgress = opts.enableProgress ? calculateProgress() : 0;

        setState({
            isScrolled,
            isShrunk,
            isHidden,
            scrollY: currentScrollY,
            scrollDirection,
            scrollProgress,
        });

        lastScrollY.current = currentScrollY;
        ticking.current = false;
    }, [opts.shrinkThreshold, opts.hideThreshold, opts.showOnScrollUp, opts.enableProgress, calculateProgress]);

    const handleScroll = useCallback(() => {
        if (!ticking.current) {
            if (frameId.current) {
                cancelAnimationFrame(frameId.current);
            }
            frameId.current = requestAnimationFrame(updateState);
            ticking.current = true;
        }
    }, [updateState]);

    useEffect(() => {
        if (typeof window === "undefined") return;

        // Initial calculation
        updateState();

        // Add scroll listener with passive option for better performance
        window.addEventListener("scroll", handleScroll, { passive: true });

        return () => {
            window.removeEventListener("scroll", handleScroll);
            if (frameId.current) {
                cancelAnimationFrame(frameId.current);
            }
        };
    }, [handleScroll, updateState]);

    // CSS classes based on state
    const headerClasses = {
        base: "sticky top-0 z-50 w-full transition-all duration-300 ease-out",
        scrolled: state.isScrolled ? "backdrop-blur-xl bg-background/80 border-b border-border/50" : "bg-transparent",
        shrunk: state.isShrunk ? "py-2" : "py-4",
        hidden: state.isHidden ? "-translate-y-full" : "translate-y-0",
        shadow: state.isScrolled ? "shadow-lg shadow-black/5 dark:shadow-black/20" : "",
    };

    return {
        ...state,
        headerClasses,
    };
}

export default useStickyHeader;

"use client";

import { useState, useCallback, useEffect } from "react";
import { usePathname } from "next/navigation";

/**
 * Hook مشترك لإدارة حالة Mega Menu في Header
 * يضمن إغلاق القوائم عند تغيير المسار أو النقر خارج القائمة
 */
export function useMegaMenuState() {
	const pathname = usePathname();
	const [openMegaMenu, setOpenMegaMenu] = useState<string | null>(null);
	const [mounted, setMounted] = useState(false);

	// Handle mount to prevent hydration mismatch
	useEffect(() => {
		requestAnimationFrame(() => {
			setMounted(true);
		});
	}, []);

	// إغلاق القائمة عند تغيير المسار
	useEffect(() => {
		setOpenMegaMenu(null);
	}, [pathname]);

	// إغلاق القائمة عند النقر خارجها
	useEffect(() => {
		if (!mounted || !openMegaMenu) return;

		const handleClickOutside = (event: MouseEvent) => {
			const target = event.target as HTMLElement;
			if (
				!target?.closest?.("[data-mega-menu-trigger]") &&
				!target?.closest?.("[data-mega-menu-content]")
			) {
				setOpenMegaMenu(null);
			}
		};

		document.addEventListener("mousedown", handleClickOutside);
		return () => {
			document.removeEventListener("mousedown", handleClickOutside);
		};
	}, [openMegaMenu, mounted]);

	// إغلاق القائمة عند الضغط على ESC
	useEffect(() => {
		if (!mounted || !openMegaMenu) return;

		const handleEscape = (event: KeyboardEvent) => {
			if (event.key === "Escape") {
				setOpenMegaMenu(null);
			}
		};

		document.addEventListener("keydown", handleEscape);
		return () => {
			document.removeEventListener("keydown", handleEscape);
		};
	}, [openMegaMenu, mounted]);

	const toggleMegaMenu = useCallback((menuKey: string | null) => {
		setOpenMegaMenu((current) => (current === menuKey ? null : menuKey));
	}, []);

	const closeMegaMenu = useCallback(() => {
		setOpenMegaMenu(null);
	}, []);

	const openMegaMenuKey = useCallback((menuKey: string) => {
		setOpenMegaMenu(menuKey);
	}, []);

	return {
		openMegaMenu,
		setOpenMegaMenu,
		toggleMegaMenu,
		closeMegaMenu,
		openMegaMenuKey,
		mounted,
	};
}

"use client";

import React, { useEffect } from "react";
import { ErrorBoundary, FallbackProps } from "react-error-boundary";

// Lazy load logger to prevent server-only bundling issues
interface Logger {
  info: (...args: unknown[]) => void;
  warn: (...args: unknown[]) => void;
  error: (...args: unknown[]) => void;
  debug: (...args: unknown[]) => void;
}

let loggerInstance: Logger | null = null;
async function getLogger() {
  if (!loggerInstance) {
    try {
      const loggerModule = await import('@/lib/logger');
      loggerInstance = loggerModule.logger as unknown as Logger;
    } catch (error) {
      // Fallback to console if logger fails to load
      loggerInstance = {
        info: (...args: unknown[]) => console.info(...args),
        warn: (...args: unknown[]) => console.warn(...args),
        error: (...args: unknown[]) => console.error(...args),
        debug: (...args: unknown[]) => console.debug(...args),
      };
    }
  }
  return loggerInstance;
}

/**
 * Error fallback component for ErrorBoundary
 * Displays user-friendly error message
 */
const ErrorFallback = React.memo(function ErrorFallback({ 
  error, 
  resetErrorBoundary 
}: FallbackProps) {
  if (!error) {
    return (
      <div className="p-4 text-red-500" role="alert">
        <h2 className="text-xl font-bold mb-2">حدث خطأ غير معروف</h2>
        <button
          onClick={resetErrorBoundary}
          className="mt-4 px-4 py-2 bg-blue-500 text-white rounded hover:bg-blue-600 transition-colors"
        >
          إعادة المحاولة
        </button>
      </div>
    );
  }

  return (
    <div className="p-4 text-red-500" role="alert">
      <h2 className="text-xl font-bold mb-2">حدث خطأ في تحميل التطبيق</h2>
      <pre className="whitespace-pre-wrap break-words mb-4">
        {error?.message || 'خطأ غير معروف'}
      </pre>
      {error?.stack && (
        <details className="mt-4">
          <summary className="cursor-pointer text-sm">تفاصيل الخطأ</summary>
          <pre className="mt-2 text-xs overflow-auto max-h-64 bg-red-50 p-2 rounded">
            {error.stack}
          </pre>
        </details>
      )}
      <button
        onClick={resetErrorBoundary}
        className="mt-4 px-4 py-2 bg-blue-500 text-white rounded hover:bg-blue-600 transition-colors"
      >
        إعادة المحاولة
      </button>
    </div>
  );
});

/**
 * Hook to handle webpack/turbopack module loading errors
 * Automatically reloads the page on certain errors including HMR issues
 */
function useWebpackErrorHandler() {
  useEffect(() => {
    const handleError = (event: ErrorEvent) => {
      const error = event.error || new Error(event.message);
      const errorMessage = error.message || event.message || '';
      
      // Check for various module loading errors including HMR issues
      if (
        errorMessage.includes('Cannot read properties of undefined') ||
        errorMessage.includes('call') ||
        errorMessage.includes('is not a function') ||
        errorMessage.includes('Component is not a function') ||
        errorMessage.includes('module factory is not available') ||
        errorMessage.includes('was instantiated because it was required') ||
        errorMessage.includes('next-auth') ||
        errorMessage.includes('HMR update')
      ) {
        getLogger().then(logger => {
          logger.error('Module loading error detected:', error);
        }).catch(() => {
          console.error('Module loading error detected:', error);
        });
        // Clear any cached module references and reload
        if (typeof window !== 'undefined') {
          setTimeout(() => {
            window.location.reload();
          }, 500);
        }
      }
    };

    const handleUnhandledRejection = (event: PromiseRejectionEvent) => {
      const error = event.reason;
      const errorMessage = error?.message || '';
      
      if (
        errorMessage.includes('is not a function') ||
        errorMessage.includes('Component is not a function') ||
        errorMessage.includes('module factory is not available') ||
        errorMessage.includes('next-auth') ||
        errorMessage.includes('HMR update')
      ) {
        getLogger().then(logger => {
          logger.error('Unhandled promise rejection (module error):', error);
        }).catch(() => {
          console.error('Unhandled promise rejection (module error):', error);
        });
        if (typeof window !== 'undefined') {
          setTimeout(() => {
            window.location.reload();
          }, 500);
        }
      }
    };

    window.addEventListener('error', handleError);
    window.addEventListener('unhandledrejection', handleUnhandledRejection);

    return () => {
      window.removeEventListener('error', handleError);
      window.removeEventListener('unhandledrejection', handleUnhandledRejection);
    };
  }, []);
}

/**
 * ClientLayoutWrapper component
 * Wraps the application with error boundary and error handling
 * 
 * @optimized - Uses ErrorBoundary for better error handling
 */
export function ClientLayoutWrapper({
  children,
}: {
  children: React.ReactNode;
}) {
  useWebpackErrorHandler();

  return (
    <ErrorBoundary
      fallbackRender={({ error, resetErrorBoundary }) => (
        <ErrorFallback error={error} resetErrorBoundary={resetErrorBoundary} />
      )}
      onError={(error: Error, info: React.ErrorInfo) => {
        // Log error - in production, this should be sent to error tracking service
        if (process.env.NODE_ENV === 'production') {
          // Error tracking service integration would go here
          // Example: errorTracker.captureException(error, { extra: info });
        } else {
          getLogger().then(logger => {
            logger.error('Layout Error:', error, info.componentStack);
          }).catch(() => {
            console.error('Layout Error:', error, info.componentStack);
          });
        }
      }}
      onReset={() => {
        // Reset any state that might have caused the error
        window.location.reload();
      }}
    >
      {children}
    </ErrorBoundary>
  );
}

"use client";

import React, { useRef, useEffect } from "react";
import { motion, useMotionValue, useSpring } from "framer-motion";
import { cn } from "@/lib/utils";

interface MegaMenuContainerProps {
	children: React.ReactNode;
	menuWidth: string;
	onClose: () => void;
}

export function MegaMenuContainer({ children, menuWidth, onClose }: MegaMenuContainerProps) {
	const menuRef = useRef<HTMLDivElement>(null);
	
	// Mouse tracking for interactive effects
	const mouseX = useMotionValue(0);
	const mouseY = useMotionValue(0);
	const springConfig = { damping: 25, stiffness: 200 };
	const mouseXSpring = useSpring(mouseX, springConfig);
	const mouseYSpring = useSpring(mouseY, springConfig);

	const handleMouseMove = (e: MouseEvent) => {
		if (!menuRef.current) return;
		const rect = menuRef.current.getBoundingClientRect();
		const x = e.clientX - rect.left;
		const y = e.clientY - rect.top;
		mouseX.set(x);
		mouseY.set(y);
	};

	useEffect(() => {
		if (!menuRef.current) return;
		window.addEventListener("mousemove", handleMouseMove);
		return () => window.removeEventListener("mousemove", handleMouseMove);
	}, [mouseX, mouseY]);

	return (
		<motion.div
			ref={menuRef}
			initial={{ opacity: 0, y: -30, scale: 0.95, filter: "blur(10px)" }}
			animate={{ opacity: 1, y: 0, scale: 1, filter: "blur(0px)" }}
			exit={{ opacity: 0, y: -30, scale: 0.95, filter: "blur(10px)" }}
			transition={{ 
				type: "spring",
				stiffness: 500,
				damping: 40,
				mass: 0.8
			}}
			className={`fixed top-16 left-1/2 -translate-x-1/2 w-full max-w-[110vw] md:${menuWidth} lg:${menuWidth} xl:${menuWidth} z-50 overflow-hidden`}
			onMouseLeave={onClose}
			data-mega-menu-content
			suppressHydrationWarning
			role="dialog"
			aria-modal="true"
			aria-label="القائمة الرئيسية"
		>
			<div className="relative bg-gradient-to-br from-popover/98 via-popover/95 to-popover/98 backdrop-blur-2xl rounded-b-3xl border border-border/60 shadow-2xl shadow-black/50 overflow-hidden">
				{/* Animated mesh gradient background */}
				<div className="absolute inset-0 bg-gradient-to-br from-primary/12 via-primary/5 via-primary/8 to-primary/12 pointer-events-none" />
				
				{/* Animated gradient overlay with smooth movement */}
				<motion.div
					className="absolute inset-0 bg-gradient-to-tr from-primary/15 via-transparent to-primary/10 pointer-events-none"
					animate={{
						backgroundPosition: ["0% 0%", "100% 100%"],
						opacity: [0.6, 0.8, 0.6],
					}}
					transition={{
						duration: 10,
						repeat: Infinity,
						repeatType: "reverse",
						ease: "easeInOut"
					}}
				/>
				
				{/* Interactive mouse glow effect */}
				<motion.div
					className="absolute pointer-events-none"
					style={{
						left: mouseXSpring,
						top: mouseYSpring,
						translateX: "-50%",
						translateY: "-50%",
						opacity: 0.3,
					}}
				>
					<div className="w-96 h-96 bg-gradient-radial from-primary/40 via-primary/20 to-transparent rounded-full blur-3xl" />
				</motion.div>
				
				{/* Shimmer effect */}
				<motion.div
					className="absolute inset-0 -translate-x-full pointer-events-none"
					animate={{
						translateX: ["-100%", "200%"],
					}}
					transition={{
						duration: 3,
						repeat: Infinity,
						repeatDelay: 2,
						ease: "linear"
					}}
				>
					<div className="w-full h-full bg-gradient-to-r from-transparent via-white/10 to-transparent skew-x-12" />
				</motion.div>

				{children}
			</div>
		</motion.div>
	);
}

