import { useState, useEffect } from 'react';

/**
 * Hook للاستجابة لحجم الشاشة (Media Query)
 * 
 * يتيح استخدام media queries في React بشكل سهل
 * 
 * @param {string} query - استعلام الوسائط (media query)
 * @returns {boolean} true إذا كان الاستعلام متطابقاً
 * 
 * @example
 * ```tsx
 * function ResponsiveComponent() {
 *   const isMobile = useMediaQuery('(max-width: 768px)');
 *   const isTablet = useMediaQuery('(min-width: 769px) and (max-width: 1024px)');
 *   const isDesktop = useMediaQuery('(min-width: 1025px)');
 *   const isDarkMode = useMediaQuery('(prefers-color-scheme: dark)');
 * 
 *   return (
 *     <div>
 *       {isMobile && <MobileLayout />}
 *       {isTablet && <TabletLayout />}
 *       {isDesktop && <DesktopLayout />}
 *     </div>
 *   );
 * }
 * ```
 */
export function useMediaQuery(query: string): boolean {
  const [matches, setMatches] = useState<boolean>(false);

  useEffect(() => {
    // التحقق من دعم المتصفح
    if (typeof window === 'undefined' || !window.matchMedia) {
      return;
    }

    const mediaQuery = window.matchMedia(query);
    
    // تعيين القيمة الأولية
    setMatches(mediaQuery.matches);

    // معالج التغيير
    const handler = (event: MediaQueryListEvent) => {
      setMatches(event.matches);
    };

    // الاستماع للتغييرات
    // استخدام addEventListener للمتصفحات الحديثة
    if (mediaQuery.addEventListener) {
      mediaQuery.addEventListener('change', handler);
    } else {
      // fallback للمتصفحات القديمة
      mediaQuery.addListener(handler);
    }

    // التنظيف
    return () => {
      if (mediaQuery.removeEventListener) {
        mediaQuery.removeEventListener('change', handler);
      } else {
        mediaQuery.removeListener(handler);
      }
    };
  }, [query]);

  return matches;
}

/**
 * Hook للحصول على نوع الجهاز الحالي
 * 
 * @returns {Object} معلومات عن نوع الجهاز
 * 
 * @example
 * ```tsx
 * function Component() {
 *   const { isMobile, isTablet, isDesktop } = useDeviceType();
 * 
 *   return (
 *     <div>
 *       {isMobile && <p>أنت تستخدم هاتفاً محمولاً</p>}
 *       {isTablet && <p>أنت تستخدم جهازاً لوحياً</p>}
 *       {isDesktop && <p>أنت تستخدم حاسوباً مكتبياً</p>}
 *     </div>
 *   );
 * }
 * ```
 */
export function useDeviceType() {
  const isMobile = useMediaQuery('(max-width: 768px)');
  const isTablet = useMediaQuery('(min-width: 769px) and (max-width: 1024px)');
  const isDesktop = useMediaQuery('(min-width: 1025px)');

  return {
    isMobile,
    isTablet,
    isDesktop,
    /** true إذا كان الجهاز محمولاً أو لوحياً */
    isTouchDevice: isMobile || isTablet,
  };
}

/**
 * Hook للحصول على اتجاه الشاشة
 * 
 * @returns {'portrait' | 'landscape'} اتجاه الشاشة
 * 
 * @example
 * ```tsx
 * function Component() {
 *   const orientation = useOrientation();
 * 
 *   return (
 *     <div>
 *       الشاشة في وضع: {orientation === 'portrait' ? 'عمودي' : 'أفقي'}
 *     </div>
 *   );
 * }
 * ```
 */
export function useOrientation(): 'portrait' | 'landscape' {
  const isPortrait = useMediaQuery('(orientation: portrait)');
  return isPortrait ? 'portrait' : 'landscape';
}

"use client";

import React, { useEffect, useRef, useState, ReactNode, useCallback } from "react";
import { useClientEffect, useClientLayoutEffect } from "@/hooks/use-client-effect";
import { logger } from "@/lib/logger";

interface LazyLoadSectionProps {
  children: ReactNode;
  threshold?: number;
  rootMargin?: string;
  fallback?: ReactNode;
  onVisible?: () => void;
  onLoadStart?: () => void;
  onLoadComplete?: () => void;
  priority?: boolean;
  className?: string;
}

export function LazyLoadSection({
  children,
  threshold,
  rootMargin,
  fallback,
  onVisible,
  onLoadStart,
  onLoadComplete,
  priority = false,
  className = ""
}: LazyLoadSectionProps) {
  // Use default values from perfConfig only when needed, not in function parameters
  // This prevents module-level evaluation that can cause bundling issues
  const actualThreshold = threshold ?? 0.1;
  const actualRootMargin = rootMargin ?? "200px";
  const [isVisible, setIsVisible] = useState<boolean>(priority);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [hasError, setHasError] = useState<boolean>(false);
  const ref = useRef<HTMLDivElement>(null);
  const observerRef = useRef<IntersectionObserver | null>(null);
  const loadStartTime = useRef<number>(0);

  // Performance monitoring
  const reportPerformance = useCallback((action: string, duration?: number) => {
    if (typeof window !== 'undefined' && 'performance' in window) {
      try {
        // Report to performance monitoring if available
        if (duration !== undefined && process.env.NODE_ENV === 'development') {
          logger.debug(`LazyLoadSection: ${action} took ${duration}ms`);
        }
      } catch (error) {
        // Silently fail performance reporting
      }
    }
  }, []);

  const handleIntersection = useCallback((entries: IntersectionObserverEntry[]) => {
    const [entry] = entries;

    if (entry.isIntersecting && !isVisible) {
      const intersectionTime = performance.now();
      loadStartTime.current = intersectionTime;

      setIsVisible(true);
      setIsLoading(true);
      onVisible?.();
      onLoadStart?.();

      reportPerformance('intersection detected');

      // Disconnect observer after first intersection
      if (observerRef.current) {
        observerRef.current.disconnect();
        observerRef.current = null;
      }
    }
  }, [isVisible, onVisible, onLoadStart, reportPerformance]);

  // Initialize intersection observer with better error handling and SSR safety
  useClientLayoutEffect(() => {
    // Skip if already visible (priority loading) or no window
    if (priority || typeof window === 'undefined' || !('IntersectionObserver' in window)) {
      if (!priority) {
        setIsVisible(true);
      }
      return;
    }

    try {
      observerRef.current = new IntersectionObserver(handleIntersection, {
        threshold: actualThreshold,
        rootMargin: actualRootMargin,
        // Add root option for better performance
        root: null,
      });

      const currentRef = ref.current;
      if (currentRef) {
        observerRef.current.observe(currentRef);
        reportPerformance('observer attached');
      }
    } catch (error) {
      if (process.env.NODE_ENV === 'development') {
        logger.warn('LazyLoadSection: Failed to create IntersectionObserver, falling back to immediate load', { error });
      }
      setIsVisible(true);
    }

    return () => {
      if (observerRef.current) {
        observerRef.current.disconnect();
        observerRef.current = null;
      }
    };
  }, [actualThreshold, actualRootMargin, priority, handleIntersection, reportPerformance]);

  // Handle loading completion
  useEffect(() => {
    if (isVisible && isLoading) {
      // Simulate loading completion (in real app, this would be based on actual content loading)
      const timer = setTimeout(() => {
        setIsLoading(false);
        onLoadComplete?.();

        const loadDuration = performance.now() - loadStartTime.current;
        reportPerformance('content loaded', loadDuration);
      }, 100); // Small delay to ensure DOM updates

      return () => clearTimeout(timer);
    }
  }, [isVisible, isLoading, onLoadComplete, reportPerformance]);

  // Enhanced fallback with better loading states
  const defaultFallback = (
    <div className="flex items-center justify-center h-48 bg-gradient-to-r from-gray-100 to-gray-200 animate-pulse rounded-lg">
      <div className="space-y-3 w-full max-w-xs">
        <div className="h-4 bg-gray-300 rounded w-3/4 mx-auto"></div>
        <div className="h-4 bg-gray-300 rounded w-1/2 mx-auto"></div>
        <div className="h-4 bg-gray-300 rounded w-2/3 mx-auto"></div>
      </div>
    </div>
  );

  const errorFallback = (
    <div className="flex items-center justify-center h-48 bg-red-50 border border-red-200 rounded-lg">
      <div className="text-center text-red-600">
        <div className="text-sm">فشل في تحميل المحتوى</div>
        <button
          onClick={() => {
            setHasError(false);
            setIsVisible(false);
            // Re-trigger intersection observer
            if (ref.current && observerRef.current) {
              observerRef.current.observe(ref.current);
            }
          }}
          className="mt-2 text-xs underline hover:no-underline"
        >
          إعادة المحاولة
        </button>
      </div>
    </div>
  );

  // For server-side rendering, show the same fallback as client initial state
  if (typeof window === 'undefined') {
    return (
      <div
        className={`lazy-load-section ${className}`}
        data-visible={priority}
        data-loading={false}
        data-error={false}
      >
        {priority ? children : fallback || defaultFallback}
      </div>
    );
  }

  return (
    <div
      ref={ref}
      className={`lazy-load-section ${className}`}
      data-visible={isVisible}
      data-loading={isLoading}
      data-error={hasError}
    >
      {hasError ? (
        errorFallback
      ) : isVisible ? (
        <React.Suspense fallback={fallback || defaultFallback}>
          {children}
        </React.Suspense>
      ) : (
        fallback || defaultFallback
      )}
    </div>
  );
}

"use client";

import React, { ComponentType, ReactNode, useState, useCallback, useRef } from 'react';
import { LazyLoadSection } from './LazyLoadSection';
import { SkeletonLoader } from './SkeletonLoader';
import { useClientEffect } from '@/hooks/use-client-effect';
import { useProgressiveComponent } from '@/hooks/use-progressive-loading';

interface ProgressiveComponentProps<P = unknown> {
  importFunc: () => Promise<{ default: ComponentType<P> }>;
  componentProps?: P;
  fallback?: ReactNode;
  errorFallback?: ReactNode;
  priority?: boolean;
  lazyLoad?: boolean;
  onLoadStart?: () => void;
  onLoadComplete?: () => void;
  onError?: (error: Error) => void;
  className?: string;
}

export function ProgressiveComponent<P = unknown>({
  importFunc,
  componentProps,
  fallback,
  errorFallback,
  priority = false,
  lazyLoad = true,
  onLoadStart,
  onLoadComplete,
  onError,
  className = ""
}: ProgressiveComponentProps<P>) {
  const [hasError, setHasError] = useState(false);
  const [error, setError] = useState<Error | null>(null);
  const retryCountRef = useRef(0);

  // Use the enhanced progressive component hook
  const {
    data: Component,
    isLoading,
    error: hookError,
    load,
    retry,
    canRetry
  } = useProgressiveComponent(importFunc, {
    priority,
    lazyLoad,
    retryAttempts: 3,
    retryDelay: 1000,
    timeout: 10000,
    onLoadStart,
    onLoadComplete: () => {
      setHasError(false);
      setError(null);
      retryCountRef.current = 0;
      onLoadComplete?.();
    },
    onError: (err) => {
      setHasError(true);
      setError(err);
      onError?.(err);
    },
    onRetry: (attempt) => {
      retryCountRef.current = attempt;
    }
  });

  const handleRetry = useCallback(() => {
    setHasError(false);
    setError(null);
    retry();
  }, [retry]);

  const defaultFallback = (
    <div className="flex items-center justify-center p-8">
      <SkeletonLoader className="w-full h-32" />
    </div>
  );

  const defaultErrorFallback = (
    <div className="flex items-center justify-center p-8 bg-red-50 border border-red-200 rounded-lg">
      <div className="text-center">
        <div className="text-red-600 font-medium mb-2">فشل في تحميل المكون</div>
        <div className="text-sm text-red-500 mb-4">
          {error?.message || hookError?.message || 'حدث خطأ غير متوقع'}
        </div>
        {canRetry && (
          <button
            onClick={handleRetry}
            className="px-4 py-2 bg-red-600 text-white rounded-md hover:bg-red-700 transition-colors text-sm"
          >
            إعادة المحاولة {retryCountRef.current > 0 && `(${retryCountRef.current})`}
          </button>
        )}
      </div>
    </div>
  );

  const componentContent = (
    <div className={className}>
      {hasError ? (
        errorFallback || defaultErrorFallback
      ) : Component ? (
        <Component {...(componentProps as P & React.JSX.IntrinsicAttributes)} />
      ) : isLoading ? (
        fallback || defaultFallback
      ) : null}
    </div>
  );

  // If priority loading is enabled, load immediately (client-side only)
  useClientEffect(() => {
    if (priority && !Component && !isLoading && !hasError) {
      load();
    }
  }, [priority, Component, isLoading, hasError, load]);

  // If lazy loading is disabled, load immediately (client-side only)
  useClientEffect(() => {
    if (!lazyLoad && !Component && !isLoading && !hasError) {
      load();
    }
  }, [lazyLoad, Component, isLoading, hasError, load]);

  if (lazyLoad && !priority) {
    return (
      <LazyLoadSection
        onVisible={load}
        fallback={fallback || defaultFallback}
        priority={false}
        className={className}
      >
        {componentContent}
      </LazyLoadSection>
    );
  }

  return componentContent;
}

// Higher-order component for easier usage
export function withProgressiveLoading<P extends object>(
  importFunc: () => Promise<{ default: ComponentType<P> }>,
  options: Omit<ProgressiveComponentProps<P>, 'importFunc' | 'componentProps'> & { displayName?: string; componentName?: string } = {}
) {
  const Component = React.forwardRef<unknown, P>((props, ref) => (
    <ProgressiveComponent
      importFunc={importFunc}
      componentProps={{ ...props, ref } as P}
      {...options}
    />
  ));
  Component.displayName = `withProgressiveLoading(${options.displayName || options.componentName || 'Component'})`;
  return Component;
}

// Utility function for creating progressive sections
export function createProgressiveSection<P = unknown>(
  importFunc: () => Promise<{ default: ComponentType<P> }>,
  displayName: string
) {
  const ProgressiveSection = React.forwardRef<unknown, Omit<ProgressiveComponentProps<P>, 'importFunc'>>((props, ref) => {
    return (
      <ProgressiveComponent
        importFunc={importFunc}
        {...props}
        // ref is not passed to ProgressiveComponent as it doesn't accept it, 
        // but we could wrap it if needed. For now, we ignore ref to avoid type issues.
      />
    );
  });

  ProgressiveSection.displayName = `ProgressiveSection(${displayName})`;
  return ProgressiveSection;
}

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { motion, AnimatePresence } from 'framer-motion';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { 
  Home, 
  BookOpen, 
  Calendar, 
