  // Mobile menu component - memoized to prevent unnecessary re-renders
  const MobileMenu = useMemo(() => (
    <AnimatePresence>
      {isMobileMenuOpen && (
        <>
          <motion.div
            className="fixed inset-0 bg-black/50 z-40 md:hidden"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
