  ), [isMobileMenuOpen, closeMobileMenu, user, userDisplayData, navigationItems, isActive]);

  return (
    <>
      {/* Mobile menu button */}
      <div className="md:hidden fixed top-4 right-4 z-30">
        <Button
          variant="outline"
          size="icon"
          onClick={openMobileMenu}
