          layout
          role="navigation"
          aria-label="Main navigation"
        >
          {/* رأس القائمة الجانبية */}
          <div className="flex items-center justify-between p-4 border-b">
            {isExpanded && (
              <motion.h2
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                className="text-xl font-bold"
