                        }`}
                        role="menuitem"
                      >
                        <div className="flex items-center gap-3 min-w-0">
                          {item.icon}
                          {isExpanded && (
                            <motion.span
                              initial={{ opacity: 0 }}
                              animate={{ opacity: 1 }}
                              exit={{ opacity: 0 }}
                              className="truncate"
                            >
                              {item.title}
                            </motion.span>
                          )}
                        </div>
                        {isExpanded && (
                          <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            className="flex items-center gap-2 flex-shrink-0"
                          >
                            {item.badge && (
                              <Badge variant="secondary" className="text-xs">
                                {item.badge}
                              </Badge>
                            )}
                            {item.subItems && (
                              <Button
                                variant="ghost"
                                size="icon"
                                className="h-5 w-5 p-0"
                                onClick={(e) => {
                                  e.preventDefault();
                                  e.stopPropagation();
                                  toggleSubmenu(item.title);
                                }}
                                aria-label={isSubmenuOpen ? 'Close submenu' : 'Open submenu'}
                                aria-expanded={isSubmenuOpen}
                              >
                                {isSubmenuOpen ? (
                                  <ChevronDown className="h-4 w-4" />
                                ) : (
                                  <ChevronRight className="h-4 w-4" />
                                )}
                              </Button>
                            )}
                          </motion.div>
                        )}
                      </div>
                    </Link>
                    {isExpanded && item.subItems && isSubmenuOpen && (
                      <motion.div
                        initial={{ opacity: 0, height: 0 }}
                        animate={{ opacity: 1, height: 'auto' }}
                        exit={{ opacity: 0, height: 0 }}
                        className="mr-6 mt-1 space-y-1"
                        role="group"
                      >
                        {item.subItems.map((subItem) => {
                          const subItemIsActive = isActive(subItem.href);
                          return (
                            <Link key={subItem.href} href={subItem.href} prefetch={false}>
                              <div
                                className={`p-2 rounded text-sm transition-colors ${
                                  subItemIsActive
                                    ? 'bg-blue-50 text-blue-600 font-medium'
                                    : 'hover:bg-gray-100 text-muted-foreground'
                                }`}
                                role="menuitem"
                              >
                                {subItem.title}
                              </div>
                            </Link>
                          );
                        })}
                      </motion.div>
                    )}
                  </div>
                );
              })}
            </nav>
          </div>

          {/* تذييل القائمة الجانبية */}
          {isExpanded && (
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="absolute bottom-0 left-0 right-0 p-4 border-t bg-white"
            >
              <div className="space-y-1">
                <Link href="/help">
                  <div className="flex items-center gap-3 p-3 rounded-lg hover:bg-gray-100">
                    <HelpCircle className="h-5 w-5" />
                    <span>المساعدة والدعم</span>
                  </div>
                </Link>
                <Link href="/logout">
                  <div className="flex items-center gap-3 p-3 rounded-lg hover:bg-gray-100 text-red-600">
                    <LogOut className="h-5 w-5" />
                    <span>تسجيل الخروج</span>
                  </div>
                </Link>
              </div>
            </motion.div>
          )}
        </motion.div>
      </div>

      {/* Mobile menu */}
      {MobileMenu}
    </>
  );
};

export default SidebarNavigation;

