'use client';

import { createContext, useContext, useEffect, useState, ErrorInfo } from 'react';
import React from 'react';
import { logger } from '@/lib/logger';

// import { useToast } from '@/contexts/toast-context'; // Not needed - WebSocket is disabled

type WebSocketContextType = {
  socket: WebSocket | null;
  isConnected: boolean;
};

const WebSocketContext = createContext<WebSocketContextType>({
  socket: null,
  isConnected: false,
});

// Error boundary component to catch any WebSocket-related errors
class WebSocketErrorBoundary extends React.Component<
  { children: React.ReactNode },
  { hasError: boolean }
> {
  constructor(props: { children: React.ReactNode }) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError(): { hasError: boolean } {
    // Update state so the next render will show the fallback UI
    return { hasError: true };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    // Completely suppress WebSocket errors - do not log
    // Errors are expected when WebSocket is disabled
  }

  render() {
    if (this.state.hasError) {
      // Silently return children without WebSocket functionality
      return <>{this.props.children}</>;
    }

    return this.props.children;
  }
}

// WebSocket is completely disabled - set as constant outside component
// Change to true only when deploying to edge runtime (Cloudflare Workers)
const WEBSOCKET_ENABLED = false;

export function WebSocketProvider({ children, userId }: { children: React.ReactNode, userId?: string }) {
  const [socket, setSocket] = useState<WebSocket | null>(null);
  const [isConnected, setIsConnected] = useState(false);

  useEffect(() => {
    // CRITICAL: WebSocket is disabled - exit immediately before any operations
    // This prevents any WebSocket connection attempts or error events
    if (!WEBSOCKET_ENABLED) {
      // Explicitly set state to ensure no WebSocket is used
      setSocket(null);
      setIsConnected(false);
      // Return early with empty cleanup function to prevent any errors
      return () => {
        // No-op cleanup when WebSocket is disabled
      };
    }
    
    // The code below will never execute while WEBSOCKET_ENABLED is false
    // WebSocket is currently disabled as it requires edge runtime (Cloudflare Workers)
    // The app works fine without it - it's only for real-time notifications

    // WebSocket implementation (currently disabled)
    const isWebSocketSupported = typeof window !== 'undefined' && 'WebSocket' in window;
    
    if (!isWebSocketSupported) {
      return;
    }

    let ws: WebSocket | null = null;
    let reconnectAttempts = 0;
    const maxReconnectAttempts = 3;
    let reconnectTimeout: NodeJS.Timeout | null = null;

    const connect = () => {
      // Double check WebSocket is still enabled
      if (!WEBSOCKET_ENABLED) {
        return;
      }

      // Validate userId if provided
      if (userId && (typeof userId !== 'string' || userId.trim().length === 0)) {
        logger.warn('Invalid userId provided to WebSocket connection');
        return;
      }

      try {
        const wsProtocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
        const trimmedUserId = userId?.trim();
        const wsUrl = trimmedUserId 
          ? `${wsProtocol}//${window.location.host}/api/ws?userId=${encodeURIComponent(trimmedUserId)}`
          : `${wsProtocol}//${window.location.host}/api/ws`;
        
        // Validate URL before creating WebSocket
        try {
          new URL(wsUrl);
        } catch (urlError) {
          logger.error('Invalid WebSocket URL:', urlError);
          return;
        }

        ws = new WebSocket(wsUrl);

        // Set connection timeout (30 seconds)
        const connectionTimeout = setTimeout(() => {
          if (ws && ws.readyState === WebSocket.CONNECTING) {
            logger.warn('WebSocket connection timeout');
            ws.close();
          }
        }, 30000);

        ws.onopen = () => {
          clearTimeout(connectionTimeout);
          
          if (!WEBSOCKET_ENABLED) {
            ws?.close();
            return;
          }
          setIsConnected(true);
          setSocket(ws);
          reconnectAttempts = 0;
        };

        ws.onmessage = (event) => {
          if (!WEBSOCKET_ENABLED) return;
          
          // Validate message data
          if (!event || !event.data) {
            logger.warn('Received empty WebSocket message');
            return;
          }

          try {
            // Validate data size (prevent DoS)
            if (typeof event.data === 'string' && event.data.length > 10000) {
              logger.warn('WebSocket message too large, ignoring');
              return;
            }

            const data = JSON.parse(event.data);
            
            // Validate data structure
            if (!data || typeof data !== 'object') {
              logger.warn('Invalid WebSocket message format');
              return;
            }

            if (data.type === 'notification') {
              logger.info('WebSocket notification:', data.message);
            } else if (data.type === 'SCHEDULE_CONFLICT') {
              logger.info('WebSocket: Schedule conflict detected');
            }
          } catch (error) {
            // Only log if WebSocket is enabled
            if (WEBSOCKET_ENABLED) {
              logger.warn('Error parsing WebSocket message:', error);
            }
          }
        };

        ws.onclose = (event) => {
          clearTimeout(connectionTimeout);
          setIsConnected(false);
          setSocket(null);
          
          // Only attempt reconnect if WebSocket is still enabled and not a normal closure
          if (WEBSOCKET_ENABLED && reconnectAttempts < maxReconnectAttempts && event.code !== 1000) {
            reconnectAttempts++;
            // Exponential backoff with jitter
            const baseDelay = Math.min(3000 * Math.pow(2, reconnectAttempts - 1), 15000);
            const jitter = Math.random() * 0.3 * baseDelay;
            const delay = baseDelay + jitter;
            reconnectTimeout = setTimeout(connect, delay);
          }
        };

        ws.onerror = (error) => {
          clearTimeout(connectionTimeout);
          
          // Completely suppress WebSocket errors when disabled
          // Do not log anything to prevent console errors
          // Silently handle - do not propagate errors
          // Prevent default error behavior
          if (ws) {
            try {
              ws.close();
            } catch {
              // Ignore any errors during cleanup
            }
          }
        };
      } catch (error) {
        // Completely suppress errors when WebSocket is disabled
        // Do not log anything to prevent console errors
        // Silently ignore all connection errors
        if (WEBSOCKET_ENABLED && process.env.NODE_ENV === 'development') {
          logger.debug('WebSocket connection error (suppressed):', error);
        }
      }
    };

    connect();

    return () => {
      if (reconnectTimeout) {
        clearTimeout(reconnectTimeout);
        reconnectTimeout = null;
      }
      if (ws) {
        try {
          ws.onerror = null; // Remove error handler before closing
          ws.onopen = null;
          ws.onmessage = null;
          ws.onclose = null;
          ws.close();
        } catch (e) {
          // Silently ignore cleanup errors
        }
        ws = null;
      }
      setSocket(null);
      setIsConnected(false);
    };
    // Always use consistent dependency array - include userId to avoid React warnings
    // The early exit check inside handles when WebSocket is disabled
  }, [userId]); // Fixed: use consistent dependency array

  // Always provide safe default values
  const contextValue = {
    socket: WEBSOCKET_ENABLED ? socket : null,
    isConnected: WEBSOCKET_ENABLED ? isConnected : false,
  };

  // Wrap in error boundary to catch any unexpected errors
  return (
    <WebSocketErrorBoundary>
      <WebSocketContext.Provider value={contextValue}>
        {children}
      </WebSocketContext.Provider>
    </WebSocketErrorBoundary>
  );
}

export function useWebSocket() {
  const context = useContext(WebSocketContext);
  
  // Always return safe defaults, never undefined
  if (!context) {
    return {
      socket: null,
      isConnected: false,
    };
  }
  
  return context;
}

'use client';

import { useState } from 'react';
import { toast } from 'sonner';

export function useBiometricAuth() {
    const [isLoading, setIsLoading] = useState(false);

    const isSupported = () => {
        return typeof window !== 'undefined' && !!window.PublicKeyCredential;
    };

    const authenticate = async (): Promise<{
        token: string;
        user: unknown;
    }> => {
        if (!isSupported()) {
            throw new Error('المصادقة البيومترية غير مدعومة في هذا المتصفح');
        }

        setIsLoading(true);

        try {
            // Get challenge
            const challengeController = new AbortController();
            const challengeTimeout = setTimeout(
                () => challengeController.abort(),
                30000
            );

            let challengeResponse: Response;
            let challenge: string;

            try {
                challengeResponse = await fetch('/api/auth/biometric', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ type: 'authenticate' }),
                    signal: challengeController.signal,
                });

                clearTimeout(challengeTimeout);

                const contentType = challengeResponse.headers.get('content-type');
                const isJson = contentType?.includes('application/json');

                if (!challengeResponse.ok) {
                    if (isJson) {
                        const errorData = await challengeResponse.json();
                        throw new Error(errorData.error || `خطأ في الاتصال: ${challengeResponse.status}`);
                    } else {
                        const status = challengeResponse.status;
                        throw new Error(
                            status === 404
                                ? 'المصادقة البيومترية غير متاحة حالياً.'
                                : status >= 500
                                    ? 'خطأ في الخادم. يرجى المحاولة لاحقاً.'
                                    : `خطأ في الخادم (${status})`
                        );
                    }
                }

                if (!isJson) {
                    throw new Error('استجابة غير صحيحة من الخادم.');
                }

                const challengeData = await challengeResponse.json();
                challenge = challengeData.challenge;
            } catch (fetchError: unknown) {
                const error = fetchError as Error;
                if (error.name === 'AbortError' || error.message?.includes('aborted')) {
                    throw new Error('انتهت مهلة الاتصال بالخادم. يرجى التحقق من اتصال الإنترنت والمحاولة مرة أخرى.');
                }

                if (
                    error.message?.includes('Failed to fetch') ||
                    error.message?.includes('NetworkError') ||
                    !navigator.onLine
                ) {
                    throw new Error('خطأ في الاتصال: حدث خطأ أثناء الاتصال بالخادم. يرجى التحقق من اتصال الإنترنت والمحاولة مرة أخرى.');
                }

                throw fetchError;
            }

            // Request credential
            let credential: PublicKeyCredential | null = null;
            try {
                credential = (await navigator.credentials.get({
                    publicKey: {
                        challenge: Uint8Array.from(atob(challenge), (c) => c.charCodeAt(0)),
                        timeout: 60000,
                        userVerification: 'required',
                    },
                })) as PublicKeyCredential;

                if (!credential) {
                    throw new Error('فشلت المصادقة البيومترية');
                }
            } catch (credError: unknown) {
                const error = credError as Error;
                if (error.name === 'NotAllowedError' || error.name === 'NotSupportedError') {
                    throw new Error('تم إلغاء المصادقة البيومترية أو غير مدعومة');
                } else {
                    throw new Error('فشلت المصادقة البيومترية');
                }
            }

            // Verify credential
            const verifyController = new AbortController();
            const verifyTimeout = setTimeout(() => verifyController.abort(), 30000);

            try {
                const verifyResponse = await fetch('/api/auth/biometric/verify', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        credential,
                        challenge,
                    }),
                    signal: verifyController.signal,
                });

                clearTimeout(verifyTimeout);

                const contentType = verifyResponse.headers.get('content-type');
                const isJson = contentType?.includes('application/json');

                if (!verifyResponse.ok) {
                    if (isJson) {
                        const errorData = await verifyResponse.json();
                        throw new Error(errorData.error || `خطأ في الاتصال: ${verifyResponse.status}`);
                    } else {
                        const status = verifyResponse.status;
                        throw new Error(
                            status === 404
                                ? 'المصادقة البيومترية غير متاحة حالياً.'
                                : status >= 500
                                    ? 'خطأ في الخادم. يرجى المحاولة لاحقاً.'
                                    : `خطأ في الخادم (${status})`
                        );
                    }
                }

                if (!isJson) {
                    throw new Error('استجابة غير صحيحة من الخادم.');
                }

                const data = await verifyResponse.json();

                if (!data.token || !data.user) {
                    throw new Error('استجابة غير صحيحة من الخادم.');
                }

                return {
                    token: data.token,
                    user: data.user,
                };
            } catch (verifyError: unknown) {
                clearTimeout(verifyTimeout);
                const error = verifyError as Error;

                if (error.name === 'AbortError' || error.message?.includes('aborted')) {
                    throw new Error('انتهت مهلة الاتصال بالخادم. يرجى التحقق من اتصال الإنترنت والمحاولة مرة أخرى.');
                }

                if (
                    error.message?.includes('Failed to fetch') ||
                    error.message?.includes('NetworkError') ||
                    !navigator.onLine
                ) {
                    throw new Error('خطأ في الاتصال: حدث خطأ أثناء الاتصال بالخادم. يرجى التحقق من اتصال الإنترنت والمحاولة مرة أخرى.');
                }

                throw verifyError;
            }
        } finally {
            setIsLoading(false);
        }
    };

    return {
        isLoading,
        isSupported,
        authenticate,
    };
}

/**
 * Custom hook for managing login form state and logic
 * Refactored to use composed hooks for better maintainability
