export type { RegisterFormData } from '@/types/auth-form';

export function useRegisterForm() {
    // Initialize state hook
    const state = useRegisterState();

    // Initialize validation hook
    const { validateForm } = useRegisterValidation();

    // Initialize submission hook
    const { submitRegister } = useRegisterSubmission(state);

    // Check OAuth provider status
    useEffect(() => {
        const checkOAuthStatus = async () => {
            try {
                const response = await fetch('/api/auth/oauth/status');
                if (response.ok) {
                    const data = await response.json();
                    state.setIsGoogleOAuthEnabled(data.providers?.google?.enabled ?? false);
                }
            } catch (error) {
                logger.error('Failed to check OAuth status:', error);
                state.setIsGoogleOAuthEnabled(false);
            }
        };

        checkOAuthStatus();
    }, [state.setIsGoogleOAuthEnabled]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        const validation = validateForm(state.formData);
        if (!validation.isValid) {
            state.setFieldErrors(validation.errors);
            const firstError = Object.values(validation.errors)[0];
            toast.error(firstError);
            return;
        }

        await submitRegister(state.formData);
    };

    const handleGoogleSignup = () => {
        window.location.href = '/api/auth/google?type=register';
    };

    return {
        ...state,
        handleSubmit,
        handleGoogleSignup,
    };
}

import { registerSchema } from '@/lib/validations/auth';
import { toast } from 'sonner';
import { getPasswordStrengthDisplay } from '@/lib/auth/password-strength';
import { RegisterFormData } from '@/types/auth-form';


export const useRegisterValidation = () => {


    const validateForm = (formData: RegisterFormData): { isValid: boolean; errors: Record<string, string> } => {
        const result = registerSchema.safeParse(formData);

        if (!result.success) {
            const errors: Record<string, string> = {};
            result.error.issues.forEach((issue) => {
                if (issue.path.length > 0) {
                    errors[issue.path[0] as string] = issue.message;
                }
            });

            return { isValid: false, errors };
        }

        // Additional check for password strength score
        const passwordStrength = getPasswordStrengthDisplay(formData.password);
        if (passwordStrength.score < 40) {
            return {
                isValid: false,
                errors: { password: 'كلمة المرور ضعيفة. يجب أن تستوفي جميع المتطلبات' }
            };
        }

        return { isValid: true, errors: {} };
    };

    return { validateForm };
};

