import { authService, AuthService } from '@/lib/services/auth-service';
import { validateEmail } from '@/lib/auth/validation';
import {
  AuthenticationProvider,
  AuthProviderResult,
  AuthenticatedUser,
} from './types';

/**
 * Credentials required for the Email/Password authentication provider.
 */
export interface EmailPasswordCredentials {
  email: string;
  password: string;
}

/**
 * Implements the authentication logic for the traditional email and password method.
 */
export class EmailPasswordProvider implements AuthenticationProvider<EmailPasswordCredentials> {

  constructor(private authService: AuthService) { }

  /**
   * Authenticates a user with their email and password.
   * This logic is extracted from the original AuthService.login method.
   * @param credentials - The user's email and password.
   * @returns A promise that resolves to an AuthProviderResult.
   */
  public async authenticate(credentials: EmailPasswordCredentials): Promise<AuthProviderResult> {
    const { email, password } = credentials;

    // 1. Validate inputs
    const emailValidation = validateEmail(email);
    if (!emailValidation.isValid) {
      return { status: 'error', code: 'INVALID_CREDENTIALS', message: emailValidation.error || 'البريد الإلكتروني غير صحيح' };
    }
    const normalizedEmail = emailValidation.normalized!;

    // For login, only validate password presence and length limits
    // Password strength requirements (uppercase, special chars, etc.) are only for registration
    if (!password || typeof password !== 'string') {
      return { status: 'error', code: 'INVALID_CREDENTIALS', message: 'كلمة المرور مطلوبة' };
    }
    if (password.length < 8) {
      return { status: 'error', code: 'INVALID_CREDENTIALS', message: 'كلمة المرور يجب أن تتكون من 8 أحرف على الأقل' };
    }
    if (password.length > 128) {
      return { status: 'error', code: 'INVALID_CREDENTIALS', message: 'كلمة المرور طويلة جداً' };
    }

    // 2. Find the user
    const user = await this.authService.findUserByEmail(normalizedEmail);
    if (!user || !user.passwordHash || user.passwordHash === 'oauth_user') {
      return { status: 'error', code: 'USER_NOT_FOUND', message: 'بيانات تسجيل الدخول غير صحيحة' };
    }

    // 3. Verify email is verified (skip in development for testing)
    if (!user.emailVerified && process.env.NODE_ENV !== 'development') {
      return { status: 'error', code: 'EMAIL_NOT_VERIFIED', message: 'البريد الإلكتروني غير مفعل. يرجى تفعيل حسابك.' };
    }

    // 4. Compare passwords
    const isValidPassword = await AuthService.comparePasswords(password, user.passwordHash);
    if (!isValidPassword) {
      // Note: We don't handle rate limiting here. The calling service (LoginService) is responsible for it.
      return { status: 'error', code: 'INVALID_CREDENTIALS', message: 'بيانات تسجيل الدخول غير صحيحة' };
    }

    // 5. Sanitize user object - remove sensitive fields
    const { passwordHash, twoFactorSecret, recoveryCodes, ...sanitizedUser } = user;
    const authenticatedUser: AuthenticatedUser = sanitizedUser;

    // 6. Check if 2FA is required
    if (user.twoFactorEnabled) {
      return {
        status: '2fa_required',
        user: authenticatedUser,
      };
    }

    // 7. Return success
    return {
      status: 'success',
      user: authenticatedUser,
    };
  }
}

// Export an instance for convenience
export const emailPasswordProvider = new EmailPasswordProvider(authService);

/**
 * Session Synchronization
 * مزامنة الجلسات عبر التبويبات والأجهزة
 * 
 * يوفر:
 * - مزامنة تلقائية عبر التبويبات
 * - إشعارات عند تسجيل الدخول/الخروج من تبويب آخر
 * - مزامنة الحالة في الوقت الفعلي
 */

import { EventEmitter } from 'events';
import { logger } from '@/lib/logger';
import type { AuthUser } from '@/lib/services/auth-service';
import type { AuthState } from './unified-auth-manager';

export interface SyncMessage {
  type: 'login' | 'logout' | 'state_update' | 'token_refresh' | 'session_expired';
  data?: unknown;
  timestamp: number;
  tabId: string;
}

class SessionSyncManager extends EventEmitter {
  private channel: BroadcastChannel | null = null;
  private storage: Storage | null = null;
  private tabId: string;
  private isInitialized = false;

  constructor() {
    super();
    this.tabId = this.generateTabId();

    if (typeof window !== 'undefined') {
      this.initialize();
    }
  }

  /**
   * توليد معرف فريد للتبويب
   */
  private generateTabId(): string {
    return `tab_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
  }

  /**
   * تهيئة النظام
   */
  private initialize() {
    if (this.isInitialized) return;

    // إعداد BroadcastChannel
    if (typeof BroadcastChannel !== 'undefined') {
      this.channel = new BroadcastChannel('auth-session-sync');
      this.channel.onmessage = (event) => {
        this.handleMessage(event.data);
      };
    }

    // إعداد localStorage للاستماع للتغييرات
    if (typeof window !== 'undefined') {
      this.storage = window.localStorage;
      window.addEventListener('storage', (event) => {
        this.handleStorageChange(event);
      });
    }

    // إشعار التبويبات الأخرى بوجود هذا التبويب
    this.broadcast({
      type: 'state_update',
      data: { action: 'tab_opened', tabId: this.tabId },
      timestamp: Date.now(),
      tabId: this.tabId,
    } as SyncMessage);

    // مراقبة إغلاق التبويب
    window.addEventListener('beforeunload', () => {
      this.broadcast({
        type: 'state_update',
        data: { action: 'tab_closed', tabId: this.tabId },
        timestamp: Date.now(),
        tabId: this.tabId,
      } as SyncMessage);
    });

    this.isInitialized = true;
  }

  /**
   * معالجة الرسائل من التبويبات الأخرى
   */
  private handleMessage(message: SyncMessage) {
    // تجاهل الرسائل من نفس التبويب
    if (message.tabId === this.tabId) {
      return;
    }

    logger.debug('Received sync message:', message);

    switch (message.type) {
      case 'login':
        this.emit('login', message.data);
        break;

      case 'logout':
        this.emit('logout', message.data);
        break;

      case 'state_update':
        this.emit('state_update', message.data);
        break;

      case 'token_refresh':
        this.emit('token_refresh', message.data);
        break;

      case 'session_expired':
        this.emit('session_expired', message.data);
        break;
    }
  }

  /**
   * معالجة تغييرات localStorage
   */
  private handleStorageChange(event: StorageEvent) {
    if (event.key === 'auth_state' && event.newValue) {
      try {
        const newState = JSON.parse(event.newValue);
        this.emit('storage_update', newState);
      } catch (error) {
        logger.error('Failed to parse storage update:', error);
      }
    }
  }

  /**
   * إرسال رسالة للتبويبات الأخرى
   */
  broadcast(message: Omit<SyncMessage, 'tabId'>) {
    const fullMessage: SyncMessage = {
      ...message,
      tabId: this.tabId,
    };

    // إرسال عبر BroadcastChannel
    if (this.channel) {
      this.channel.postMessage(fullMessage);
    }

    // تحديث localStorage لإشعار التبويبات الأخرى
    if (this.storage) {
      try {
        this.storage.setItem('auth_sync_timestamp', Date.now().toString());
        this.storage.setItem('auth_sync_data', JSON.stringify(fullMessage));
      } catch (error) {
        logger.error('Failed to update storage:', error);
      }
    }
  }

  /**
   * إشعار بتسجيل الدخول
   */
  notifyLogin(userData: AuthUser) {
    this.broadcast({
      type: 'login',
      data: { user: userData },
      timestamp: Date.now(),
    });
  }

  /**
   * إشعار بتسجيل الخروج
   */
  notifyLogout() {
    this.broadcast({
      type: 'logout',
      timestamp: Date.now(),
    });
  }

  /**
   * إشعار بتحديث الحالة
   */
  notifyStateUpdate(state: AuthState) {
    this.broadcast({
      type: 'state_update',
      data: { state },
      timestamp: Date.now(),
    });
  }

  /**
   * إشعار بتحديث التوكن
   */
  notifyTokenRefresh() {
    this.broadcast({
      type: 'token_refresh',
      timestamp: Date.now(),
    });
  }

  /**
   * إشعار بانتهاء الجلسة
   */
  notifySessionExpired() {
    this.broadcast({
      type: 'session_expired',
      timestamp: Date.now(),
    });
  }

  /**
   * الحصول على معرف التبويب
   */
  getTabId(): string {
    return this.tabId;
  }

  /**
   * تنظيف الموارد
   */
  destroy() {
    if (this.channel) {
      this.channel.close();
      this.channel = null;
    }

    this.removeAllListeners();
    this.isInitialized = false;
  }
}

// Singleton instance
let syncManagerInstance: SessionSyncManager | null = null;

export function getSessionSyncManager(): SessionSyncManager {
  if (typeof window === 'undefined') {
    // في SSR، نعيد instance وهمي
    return {
      broadcast: () => { },
      notifyLogin: () => { },
      notifyLogout: () => { },
      notifyStateUpdate: () => { },
      notifyTokenRefresh: () => { },
      notifySessionExpired: () => { },
      getTabId: () => 'ssr',
      on: ((event: string, listener: (...args: unknown[]) => void): SessionSyncManager => {
        return {} as SessionSyncManager;
      }) as (event: string, listener: (...args: unknown[]) => void) => SessionSyncManager,
      off: () => { },
      emit: () => false,
      destroy: () => { },
    } as any;
  }

  if (!syncManagerInstance) {
    syncManagerInstance = new SessionSyncManager();
  }

  return syncManagerInstance;
}

export default getSessionSyncManager;

import { jwtVerify, SignJWT } from 'jose'
import { getJWTSecret } from '@/lib/env-validation'

/**
 * Token payload interface
 */
export interface TokenPayload {
    userId: string
    email?: string
    role?: string
    sessionId?: string
    type?: 'access' | 'refresh' | '2fa_temp'
    jti?: string
    [key: string]: unknown
}

/**
 * Get JWT secret securely - returns null if not configured
 */
function getSecret(): Uint8Array | null {
    try {
        const secret = getJWTSecret()
        if (!secret) {
            console.error('[Auth] JWT_SECRET not configured')
            return null
        }
        return new TextEncoder().encode(secret)
    } catch {
        console.error('[Auth] Failed to get JWT secret')
        return null
    }
}

/**
 * Verify a JWT token from a request
 * Extracts token from Authorization header or cookies
 * @param req - The Request object
 * @returns The token payload or null if invalid
 */
export async function verifyToken(req: Request): Promise<TokenPayload | null> {
    try {
        const token = await extractToken(req)
        if (!token) return null

        const secret = getSecret()
        if (!secret) return null

        const { payload } = await jwtVerify(token, secret, {
            issuer: 'thanawy-auth',
            audience: 'thanawy-app'
        })

        return payload as TokenPayload
    } catch (error) {
        // Token is invalid or expired
        return null
    }
}

/**
 * Verify a raw JWT token string
 * @param token - The JWT token string
 * @returns The token payload or null if invalid
 */
export async function verifyTokenString(token: string): Promise<TokenPayload | null> {
    try {
        if (!token || typeof token !== 'string') return null

        const secret = getSecret()
        if (!secret) return null

        const { payload } = await jwtVerify(token, secret, {
            issuer: 'thanawy-auth',
            audience: 'thanawy-app'
        })

        return payload as TokenPayload
    } catch {
        return null
    }
}

/**
 * Generate a new JWT token
 * @param payload - The payload to encode
 * @param expiresIn - Token expiration time (default: 1h)
 * @returns The signed JWT token or null if secret not configured
 */
export async function generateToken(
    payload: Partial<TokenPayload>,
    expiresIn: string = '1h'
): Promise<string | null> {
    try {
        const secret = getSecret()
        if (!secret) return null

        const token = await new SignJWT({ ...payload })
            .setProtectedHeader({ alg: 'HS256' })
            .setIssuedAt()
            .setExpirationTime(expiresIn)
            .setIssuer('thanawy-auth')
            .setAudience('thanawy-app')
            .sign(secret)

        return token
    } catch {
        console.error('[Auth] Failed to generate token')
        return null
    }
}

/**
 * Extract token from request (Authorization header or cookies)
 */
async function extractToken(req: Request): Promise<string | undefined> {
    try {
        // Check Authorization header
        const authHeader = req.headers.get('Authorization') || req.headers.get('authorization')
        if (authHeader?.startsWith('Bearer ')) {
            return authHeader.substring(7)
        }

        // Check cookies
        const cookieHeader = req.headers.get('cookie')
        if (cookieHeader) {
            const cookies = cookieHeader.split(';').reduce((acc, cookie) => {
                const [key, value] = cookie.trim().split('=')
                acc[key] = value
                return acc
            }, {} as Record<string, string>)

            if (cookies['access_token']) return cookies['access_token']
        }
        return undefined
    } catch {
        return undefined
    }
}

/**
 * ============================================
 * مدير المصادقة الموحد (Unified Auth Manager)
 * ============================================
 * 
 * ⚠️ IMPORTANT: هذا ملف داخلي - لا تستورده مباشرة
 * ✅ استخدم useUnifiedAuth من @/contexts/auth-context
 * 
 * ⚠️ IMPORTANT - البنية الموحدة:
 * 
 * 📁 CLIENT-SIDE (العميل):
 *   ✅ src/contexts/auth-context.tsx → نقطة التصدير الموحدة ⭐
 *      └─> src/components/auth/UnifiedAuthProvider.tsx
 *          └─> هذا الملف (التنفيذ الداخلي)
 * 
 * 📖 للاستخدام:
 *   ✅ في Client Components: 
 *      import { useUnifiedAuth } from '@/contexts/auth-context'
 *      (لا تستورد من هذا الملف مباشرة)
 * 
 * 📚 راجع AUTH_STRUCTURE_UNIFIED.md للتفاصيل الكاملة
 */

import { EventEmitter } from 'events';
import { logger } from '@/lib/logger';
import { getSessionSyncManager } from './session-sync';
import { createAuthFetchInterceptor } from '@/lib/token-refresh-interceptor';
import type { AuthUser } from '@/lib/services/auth-service';

export interface AuthState {
  user: AuthUser | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  sessionId: string | null;
  lastActivity: number;
  tokenExpiry: number | null;
}

export interface AuthEvent {
  type: 'login' | 'logout' | 'token_refresh' | 'session_expired' | 'error' | 'state_change';
  data?: unknown;
  timestamp: number;
}

class UnifiedAuthManager extends EventEmitter {
  private state: AuthState = {
    user: null,
    isAuthenticated: false,
    isLoading: true,
    sessionId: null,
    lastActivity: Date.now(),
    tokenExpiry: null,
  };

  private refreshTimer: NodeJS.Timeout | null = null;
  private activityTimer: NodeJS.Timeout | null = null;
  private syncChannel: BroadcastChannel | null = null;
  private sessionSync: ReturnType<typeof getSessionSyncManager> | null = null;
  private interceptorCleanup: (() => void) | null = null;
  private isInitialized = false;

  constructor() {
    super();
    this.setMaxListeners(50); // Allow many listeners

    if (typeof window !== 'undefined') {
      this.initialize();
    }
  }

  /**
   * تهيئة النظام
   */
  private initialize() {
    if (this.isInitialized) return;

    // إعداد BroadcastChannel للمزامنة عبر التبويبات
    if (typeof BroadcastChannel !== 'undefined') {
      this.syncChannel = new BroadcastChannel('auth-sync');
      this.syncChannel.onmessage = (event) => {
        this.handleSyncMessage(event.data);
      };
    }

    // إعداد Session Sync Manager
    this.sessionSync = getSessionSyncManager();
    this.sessionSync.on('login', (data) => {
      if (data?.user) {
        this.setState({
          user: data.user,
          isAuthenticated: true,
        });
      }
    });
    this.sessionSync.on('logout', () => {
      this.setState({
        user: null,
        isAuthenticated: false,
        sessionId: null,
      });
    });
    this.sessionSync.on('state_update', (data) => {
      if (data?.state) {
        this.setState(data.state);
      }
    });

    // إعداد مراقبة النشاط
    this.setupActivityMonitoring();

    // إعداد مراقبة الاتصال
    this.setupConnectionMonitoring();

    // إعداد Interceptor لتحديث التوكن تلقائياً عند 401
    this.interceptorCleanup = createAuthFetchInterceptor();

    // استعادة الحالة من localStorage
    this.restoreState();

    this.isInitialized = true;
    this.emit('initialized');
  }

  /**
   * استعادة الحالة من التخزين المحلي
   */
  private restoreState() {
    try {
      const stored = localStorage.getItem('auth_state');
      let restored = false;

      if (stored) {
        const parsed = JSON.parse(stored);
        if (parsed.user && parsed.isAuthenticated) {
          this.state = {
            ...this.state,
            ...parsed,
            isLoading: false,
          };
          this.emit('state_change', { state: this.state });
          restored = true;
        }
      }

      if (!restored) {
        // If no valid state found, ensure we're not stuck in loading
        this.state = {
          ...this.state,
          isLoading: false,
        };
        this.emit('state_change', { state: this.state });
      }
    } catch (error) {
      logger.error('Failed to restore auth state:', error);
      // Ensure we're not stuck in loading on error
      this.state = {
        ...this.state,
        isLoading: false,
      };
      this.emit('state_change', { state: this.state });
    }
  }

  /**
   * حفظ الحالة في التخزين المحلي
   */
  private persistState() {
    try {
      const stateToSave = {
        user: this.state.user,
        isAuthenticated: this.state.isAuthenticated,
        sessionId: this.state.sessionId,
        tokenExpiry: this.state.tokenExpiry,
      };
      localStorage.setItem('auth_state', JSON.stringify(stateToSave));
    } catch (error) {
      logger.error('Failed to persist auth state:', error);
    }
  }

  /**
   * إعداد مراقبة النشاط
   */
  private setupActivityMonitoring() {
    if (typeof window === 'undefined') return;

    const updateActivity = () => {
      this.state.lastActivity = Date.now();
    };

    // مراقبة أحداث المستخدم
    ['mousedown', 'keydown', 'scroll', 'touchstart'].forEach(event => {
      window.addEventListener(event, updateActivity, { passive: true });
    });

    // تحديث النشاط كل دقيقة
    this.activityTimer = setInterval(() => {
      if (this.state.isAuthenticated) {
        this.state.lastActivity = Date.now();
      }
    }, 60000);
  }

  /**
   * إعداد مراقبة الاتصال
   */
  private setupConnectionMonitoring() {
    if (typeof window === 'undefined') return;

    window.addEventListener('online', () => {
      this.emit('connection_restored');
      this.syncWithServer();
    });

    window.addEventListener('offline', () => {
      this.emit('connection_lost');
    });
  }

  /**
   * معالجة رسائل المزامنة من التبويبات الأخرى
   */
  private handleSyncMessage(data: AuthEvent) {
    if (data.type === 'login' || data.type === 'logout') {
      // مزامنة الحالة مع التبويبات الأخرى
      this.syncWithServer();
    } else if (data.type === 'state_change') {
      // تحديث الحالة من تبويب آخر
      if (data.data?.state) {
        this.state = { ...this.state, ...data.data.state };
        this.emit('state_change', { state: this.state, source: 'sync' });
      }
    }
  }

  /**
   * إرسال حدث للمزامنة عبر التبويبات
   */
  private broadcastEvent(event: AuthEvent) {
    if (this.syncChannel) {
      this.syncChannel.postMessage(event);
    }
  }

  /**
   * مزامنة الحالة مع الخادم
   * يضمن التكامل الكامل بين الواجهة الأمامية والخلفية
   */
  async syncWithServer(): Promise<void> {
    try {
      // التحقق من حالة المصادقة من الخادم
      // التوكن في httpOnly cookie - لا حاجة لإرسال Authorization header
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 5000); // 5 second timeout

      try {
        const response = await fetch('/api/auth/me', {
          method: 'GET',
          headers: {
            'Content-Type': 'application/json',
          },
          credentials: 'include', // مهم: إرسال cookies
          cache: 'no-store',
          signal: controller.signal,
        });

        clearTimeout(timeoutId);

        if (response.ok) {
          const contentType = response.headers.get('content-type');
          const isJson = contentType?.includes('application/json');

          if (isJson) {
            const data = await response.json();
            if (data.user) {
              // تحديث الحالة من الخادم
              this.setState({
                user: data.user,
                isAuthenticated: true,
                isLoading: false,
              });
              return;
            }
          }
        } else if (response.status === 401) {
          // انتهت الجلسة - مسح الحالة
          this.handleSessionExpired();
        } else if (response.status >= 500) {
          // خطأ في الخادم - لا نغير الحالة
          logger.warn('Server error during sync:', response.status);
        }
      } catch (error) {
        clearTimeout(timeoutId);
        throw error;
      }
    } catch (error) {
      // خطأ في الاتصال - لا نغير الحالة المحلية
      // قد يكون خطأ مؤقت في الشبكة
      logger.warn('Failed to sync with server:', error);

      // إذا كان المستخدم مسجلاً دخولاً محلياً، نحتفظ بالحالة
      // وإلا نمسح الحالة
      if (!this.state.user) {
        this.setState({
          isAuthenticated: false,
          isLoading: false,
        });
      }
    }
  }

  /**
   * تعيين الحالة
   */
  setState(updates: Partial<AuthState>) {
    const oldState = { ...this.state };
    this.state = { ...this.state, ...updates };

