    }

    if (keys.length > 100) {
      logger.warn('Too many keys to delete, limiting to 100');
      keys = keys.slice(0, 100);
    }

    const trimmedKeys = keys
      .filter(key => key && typeof key === 'string' && key.trim().length > 0)
      .map(key => key.trim());

    if (trimmedKeys.length === 0) {
      return;
    }

    const start = Date.now();
    try {
      const delPromise = redisClient.del(...trimmedKeys);
      const timeoutPromise = new Promise<never>((resolve, reject) => {
        setTimeout(() => reject(new Error('Cache mdel timeout')), 5000); // 5 second timeout
      });

      await Promise.race([delPromise, timeoutPromise]);
      const duration = Date.now() - start;
      recordCacheMetric('mdel', duration, true);
    } catch (error) {
      const duration = Date.now() - start;
      recordCacheMetric('mdel', duration, false);
      logger.error('Error deleting multiple data from cache:', error);
    }
  }

  /**
   * Get or set data in cache with a function to compute the value if not found
   * @param key Cache key
   * @param compute Function to compute the value if not found
   * @param ttl Time to live in seconds (default: 1 hour)
   * @returns Cached or computed data
   */
  static async getOrSet<T>(
    key: string,
    compute: () => Promise<T>,
    ttl: number = 3600
  ): Promise<T> {
    const cached = await this.get<T>(key);
    if (cached) {
      return cached;
    }
    
    const computed = await compute();
    await this.set(key, computed, ttl);
    return computed;
  }

  /**
   * Invalidate cache keys matching a pattern
   * @param pattern Pattern to match keys
   */
  static async invalidatePattern(pattern: string): Promise<void> {
    const start = Date.now();
    try {
      const keys = await redisClient.keys(pattern);
      if (keys.length > 0) {
        await redisClient.del(...keys);
      }
      const duration = Date.now() - start;
      recordCacheMetric('invalidatePattern', duration, true);
    } catch (error) {
      const duration = Date.now() - start;
      recordCacheMetric('invalidatePattern', duration, false);
      logger.error('Error invalidating cache pattern:', error);
    }
  }

  /**
   * Check if Redis client is connected
   * @returns Boolean indicating if Redis client is connected
   */
  static isConnected(): boolean {
    return redisClient.status === 'ready';
  }

  /**
   * Disconnect Redis client
   */
  static async disconnect(): Promise<void> {
    try {
      await redisClient.quit();
    } catch (error) {
      logger.error('Error disconnecting from Redis:', error);
    }
  }
}

// Export convenience functions for backward compatibility
export async function getOrSetEnhanced<T>(
  key: string,
  fetchFn: () => Promise<T>,
  ttl: number = 3600
): Promise<T> {
  return CacheService.getOrSet(key, fetchFn, ttl);
}

export async function batchGetOrSet<T>(
  items: { key: string; fetchFn: () => Promise<T>; ttl?: number }[]
): Promise<T[]> {
  return Promise.all(
    items.map(async (item) => {
      return CacheService.getOrSet(item.key, item.fetchFn, item.ttl || 3600);
    })
  );
}

// Export default instance for backward compatibility
const cacheService = CacheService;
export default cacheService;

/**
 * Client-Side Logger
 * مسجل خفيف للعميل (المتصفح) لتجنب استيراد dependecies الخادم
 * 
 * Supports basic logging levels and format
 */

export type LogLevel = 'debug' | 'info' | 'warn' | 'error';
export type LogContext = Record<string, any>;

class ClientLogger {
    private level: LogLevel = (process.env.NODE_ENV === 'production' ? 'info' : 'debug') as LogLevel;

    private shouldLog(level: LogLevel): boolean {
        const levels: LogLevel[] = ['debug', 'info', 'warn', 'error'];
        const currentLevelIndex = levels.indexOf(this.level);
        const messageLevelIndex = levels.indexOf(level);
        return messageLevelIndex >= currentLevelIndex;
    }

    private formatMessage(level: LogLevel, message: string, context?: LogContext): string {
        const timestamp = new Date().toISOString();
        return `[${timestamp}] [${level.toUpperCase()}] ${message}`;
    }

    debug(message: string, context?: LogContext | unknown): void {
        if (!this.shouldLog('debug')) return;
        const msg = this.formatMessage('debug', message);
        if (context) console.debug(msg, context);
        else console.debug(msg);
    }

    info(message: string, context?: LogContext | unknown): void {
        if (!this.shouldLog('info')) return;
        const msg = this.formatMessage('info', message);
        if (context) console.info(msg, context);
        else console.info(msg);
    }

    warn(message: string, context?: LogContext | unknown): void {
        if (!this.shouldLog('warn')) return;
        const msg = this.formatMessage('warn', message);
        if (context) console.warn(msg, context);
        else console.warn(msg);
    }

    error(message: string, error?: Error | unknown, context?: LogContext | unknown): void {
        if (!this.shouldLog('error')) return;
        const msg = this.formatMessage('error', message);
        if (error && context) console.error(msg, error, context);
        else if (error) console.error(msg, error);
        else console.error(msg);
    }
}

export const clientLogger = new ClientLogger();
export default clientLogger;

