/**
 * Client-Server Compatibility Utilities
 *
 * This module provides utilities for handling client-server compatibility issues
 * in Next.js applications, including hydration safety, progressive loading,
 * and error recovery.
 */

import React, { useEffect, useState, useCallback, useRef } from 'react';
import { useClientEffect } from '@/hooks/use-client-effect';

type Logger = {
  info: (message: string, context?: unknown) => void;
  warn: (message: string, context?: unknown) => void;
  error: (message: string, context?: unknown) => void;
  debug: (message: string, context?: unknown) => void;
};

let loggerInstance: Logger | null = null;
async function getLogger(): Promise<Logger> {
  if (!loggerInstance) {
    try {
      const loggerModule = await import('@/lib/logger');
      const importedLogger = loggerModule.logger;
      // Wrap the logger to match our type signature
      loggerInstance = {
        info: (message: string, context?: unknown) => {
          if (typeof importedLogger.info === 'function') {
            if (importedLogger.info.length === 1) {
              (importedLogger.info as (message: string) => void)(message);
            } else {
              (importedLogger.info as (message: string, context?: unknown) => void)(message, context);
            }
          }
        },
        warn: (message: string, context?: unknown) => {
          if (typeof importedLogger.warn === 'function') {
            if (importedLogger.warn.length === 1) {
              (importedLogger.warn as (message: string) => void)(message);
            } else {
              (importedLogger.warn as (message: string, context?: unknown) => void)(message, context);
            }
          }
        },
        error: (message: string, context?: unknown) => {
          if (typeof importedLogger.error === 'function') {
            if (importedLogger.error.length === 1) {
              (importedLogger.error as (message: string) => void)(message);
            } else {
              (importedLogger.error as (message: string, context?: unknown) => void)(message, context);
            }
          }
        },
        debug: (message: string, context?: unknown) => {
          if (typeof importedLogger.debug === 'function') {
            if (importedLogger.debug.length === 1) {
              (importedLogger.debug as (message: string) => void)(message);
            } else {
              (importedLogger.debug as (message: string, context?: unknown) => void)(message, context);
            }
          }
        },
      };
    } catch (error) {
      // Fallback to console if logger fails to load
      loggerInstance = {
        info: (message: string) => console.info(message),
        warn: (message: string) => console.warn(message),
        error: (message: string) => console.error(message),
        debug: (message: string) => console.debug(message),
      };
    }
  }
  return loggerInstance;
}

/**
 * Check if code is running on the client side
 */
export const isClient = (): boolean => typeof window !== 'undefined';

/**
 * Check if code is running on the server side
 */
export const isServer = (): boolean => typeof window === 'undefined';

/**
 * Safe wrapper for accessing window object
 */
export function safeWindow(): Window | null {
  return isClient() ? window : null;
}

/**
 * Safe wrapper for accessing document object
 */
export function safeDocument(): Document | null {
  return isClient() ? document : null;
}

/**
 * Safe wrapper for accessing localStorage
 */
export function safeLocalStorage(): Storage | null {
  return isClient() ? localStorage : null;
}

/**
 * Safe wrapper for accessing sessionStorage
 */
export function safeSessionStorage(): Storage | null {
  return isClient() ? sessionStorage : null;
}

/**
 * Hook for safe access to browser APIs with hydration safety
 */
export function useBrowserAPI<T>(
  apiGetter: () => T,
  defaultValue: T,
  options?: {
    skipHydration?: boolean;
  }
): T {
  const [value, setValue] = useState<T>(defaultValue);
  const [isReady, setIsReady] = useState(false);

  useClientEffect(() => {
    try {
      const apiValue = apiGetter();
      setValue(apiValue);
      setIsReady(true);
    } catch (error) {
      getLogger().then(logger => {
        if (logger) {
          logger.warn('Failed to access browser API:', error);
        }
      }).catch(() => {
        console.warn('Failed to access browser API:', error);
      });
      setIsReady(true);
    }
  }, [], options);

  return isReady ? value : defaultValue;
}

/**
 * Hook for managing hydration-safe state
 */
export function useHydrationSafeState<T>(
  initialValue: T,
  options?: {
    onHydrationMismatch?: (serverValue: T, clientValue: T) => void;
  }
): [T, React.Dispatch<React.SetStateAction<T>>, boolean] {
  const [state, setState] = useState(initialValue);
  const [isHydrated, setIsHydrated] = useState(false);
  const serverValueRef = useRef(initialValue);

  useEffect(() => {
    setIsHydrated(true);

    // Check for hydration mismatch
    if (options?.onHydrationMismatch && serverValueRef.current !== state) {
      options.onHydrationMismatch(serverValueRef.current, state);
    }
  }, []);

  const setHydrationSafeState: React.Dispatch<React.SetStateAction<T>> = useCallback(
    (value) => {
      if (isHydrated) {
        setState(value);
      } else {
        // Store the server value for comparison
        if (typeof value === 'function') {
          const updater = value as (previous: T) => T;
          serverValueRef.current = updater(serverValueRef.current);
        } else {
          serverValueRef.current = value;
        }
        setState(value);
      }
    },
    [isHydrated]
  );

  return [state, setHydrationSafeState, isHydrated];
}

/**
 * Hook for progressive enhancement
 * Allows components to work with reduced functionality on server,
 * then enhance on client
 */
export function useProgressiveEnhancement<T>(
  serverValue: T,
  clientEnhancer: () => T | Promise<T>,
  options?: {
    onError?: (error: Error) => void;
  }
): T {
  const [value, setValue] = useState(serverValue);

  useClientEffect(() => {
    (async () => {
      try {
        const enhancedValue = await clientEnhancer();
        setValue(enhancedValue);
      } catch (error) {
        getLogger().then(logger => {
          if (logger) {
            logger.error('Progressive enhancement failed:', error);
          }
        }).catch(() => {
          console.error('Progressive enhancement failed:', error);
        });
        options?.onError?.(error as Error);
      }
    })();
  }, []);

  return value;
}

/**
 * Utility for creating hydration-safe event handlers
 */
export function createHydrationSafeHandler<T extends (...args: unknown[]) => unknown>(
  handler: T,
  options?: {
    skipServer?: boolean;
  }
): T {
  return ((...args: Parameters<T>) => {
    if (options?.skipServer && isServer()) {
      return;
    }

    if (isClient()) {
      return handler(...args);
    }
  }) as T;
}

/**
 * Hook for managing client-only side effects with cleanup
 */
export function useClientOnlyEffect(
  effect: () => (() => void) | void | Promise<void>,
  deps?: React.DependencyList,
  options?: {
    onError?: (error: Error) => void;
  }
) {
  const cleanupRef = useRef<(() => void) | void>();

  useClientEffect(() => {
    (async () => {
      try {
        const result = effect();
        if (result instanceof Promise) {
          await result;
        } else {
          cleanupRef.current = result;
        }
      } catch (error) {
        const logger = await getLogger().catch(() => null);
        if (logger) {
          logger.error('Client-only effect failed:', error);
        } else {
          console.error('Client-only effect failed:', error);
        }
        options?.onError?.(error as Error);
      }
    })();

    return () => {
      if (cleanupRef.current && typeof cleanupRef.current === 'function') {
        try {
          cleanupRef.current();
        } catch (error) {
          getLogger().then(logger => {
            logger.error('Client-only effect cleanup failed:', error);
          }).catch(() => {
            console.error('Client-only effect cleanup failed:', error);
          });
        }
        cleanupRef.current = undefined;
      }
    };
  }, deps);
}

/**
 * Utility for safe dynamic imports with error handling
 */
export async function safeDynamicImport<T>(
  importFn: () => Promise<T>,
  fallback?: T,
  options?: {
    onError?: (error: Error) => void;
    retries?: number;
    retryDelay?: number;
  }
): Promise<T | undefined> {
  const { retries = 3, retryDelay = 1000, onError } = options || {};

  for (let attempt = 1; attempt <= retries; attempt++) {
    try {
      return await importFn();
    } catch (error) {
      getLogger().then(logger => {
        if (logger) {
          logger.warn(`Dynamic import failed (attempt ${attempt}/${retries}):`, error);
        }
      }).catch(() => {
        console.warn(`Dynamic import failed (attempt ${attempt}/${retries}):`, error);
      });

      if (attempt === retries) {
        onError?.(error as Error);
        return fallback;
      }

      // Wait before retrying
      await new Promise(resolve => setTimeout(resolve, retryDelay * attempt));
    }
  }

  return fallback;
}

/**
 * Hook for safe dynamic imports
 */
export function useSafeDynamicImport<T>(
  importFn: () => Promise<T>,
  options?: {
    fallback?: T;
    onError?: (error: Error) => void;
    retries?: number;
    retryDelay?: number;
  }
) {
  const [module, setModule] = useState<T | undefined>(options?.fallback);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<Error | null>(null);

  const load = useCallback(async () => {
    setIsLoading(true);
    setError(null);

    try {
      const result = await safeDynamicImport(importFn, options?.fallback, options);
      setModule(result);
    } catch (err) {
      const error = err as Error;
      setError(error);
      options?.onError?.(error);
    } finally {
      setIsLoading(false);
    }
  }, [importFn, options]);

  useClientEffect(() => {
    load();
  }, [load]);

  return { module, isLoading, error, reload: load };
}

/**
 * Utility for detecting hydration mismatches
 */
export function detectHydrationMismatch(
  serverValue: unknown,
  clientValue: unknown,
  tolerance?: {
    ignoreFunctions?: boolean;
    ignoreUndefined?: boolean;
  }
): boolean {
  const { ignoreFunctions = true, ignoreUndefined = true } = tolerance || {};

  // Ignore functions if specified
  if (ignoreFunctions && (typeof serverValue === 'function' || typeof clientValue === 'function')) {
    return false;
  }

  // Ignore undefined values if specified
  if (ignoreUndefined && (serverValue === undefined || clientValue === undefined)) {
    return false;
  }

  // Deep comparison for objects
  if (typeof serverValue === 'object' && typeof clientValue === 'object' &&
      serverValue !== null && clientValue !== null) {
    const serverKeys = Object.keys(serverValue);
    const clientKeys = Object.keys(clientValue);

    if (serverKeys.length !== clientKeys.length) {
      return true;
    }

    for (const key of serverKeys) {
      if (!(key in clientValue)) {
        return true;
      }

      if (detectHydrationMismatch((serverValue as Record<string, unknown>)[key], (clientValue as Record<string, unknown>)[key], tolerance)) {
        return true;
      }
    }

    return false;
  }

  return serverValue !== clientValue;
}

/**
 * Hook for monitoring hydration status
 */
export function useHydrationStatus() {
  const [isHydrated, setIsHydrated] = useState(false);
  const [hydrationTime, setHydrationTime] = useState<number | null>(null);

  useEffect(() => {
    const startTime = performance.now();
    setIsHydrated(true);
    setHydrationTime(performance.now() - startTime);
     
  }, []);

  return { isHydrated, hydrationTime };
}

/**
 * Utility for creating SSR-safe components
 */
export function createSSRSafeComponent<P extends object>(
  Component: React.ComponentType<P>,
  options?: {
    fallback?: React.ComponentType<P>;
    loadingComponent?: React.ComponentType;
  }
) {
  const SSRSafeComponent = (props: P & { ssr?: boolean }) => {
    const [isClient, setIsClient] = useState(false);

    useEffect(() => {
      setIsClient(true);
    }, []);

    // Force server-side rendering if specified
    if (props.ssr === false && !isClient) {
      const { loadingComponent: Loading } = options || {};
      return Loading ? <Loading /> : null;
    }

    // Use fallback component during SSR
    if (!isClient && options?.fallback) {
      const FallbackComponent = options.fallback;
      return <FallbackComponent {...props} />;
    }

    return <Component {...props} />;
  };

  SSRSafeComponent.displayName = `SSRSafe(${Component.displayName || Component.name})`;
  return SSRSafeComponent;
}

/**
 * Performance monitoring for client-server operations
 */
export const clientServerPerf = {
  mark: (name: string) => {
    if (isClient() && 'performance' in window) {
      performance.mark(`client-server:${name}`);
    }
  },

  measure: (name: string, startMark?: string, endMark?: string) => {
    if (isClient() && 'performance' in window) {
      try {
        performance.measure(`client-server:${name}`, startMark, endMark);
        const measure = performance.getEntriesByName(`client-server:${name}`, 'measure')[0];
        return measure?.duration;
      } catch (error) {
        getLogger().then(logger => {
          logger.warn('Performance measurement failed:', error);
        }).catch(() => {
          console.warn('Performance measurement failed:', error);
        });
      }
    }
    return null;
  },

  clearMarks: (name?: string) => {
    if (isClient() && 'performance' in window) {
      if (name) {
        performance.clearMarks(`client-server:${name}`);
        performance.clearMeasures(`client-server:${name}`);
      } else {
        // Clear all client-server marks and measures
        const entries = performance.getEntries();
        entries.forEach(entry => {
          if (entry.name.startsWith('client-server:')) {
            if (entry.entryType === 'mark') {
              performance.clearMarks(entry.name);
            } else if (entry.entryType === 'measure') {
              performance.clearMeasures(entry.name);
            }
          }
        });
      }
    }
  }
};

import { prisma } from './db';
import { logger } from '@/lib/logger';

export interface PartitionInfo {
  tableName: string
  partitionName: string
  startDate: Date
  endDate: Date
  rowCount?: number
}

export interface DataRetentionPolicy {
  tableName: string
  retentionDays: number
  cleanupEnabled: boolean
}

export interface DataSizeThreshold {
  tableName: string
  maxRows: number
  maxSizeInMB: number
  autoExtendMonths: number
}

export class DataPartitioningService {
  private static readonly DATA_SIZE_THRESHOLDS: DataSizeThreshold[] = [
    { tableName: 'StudySession', maxRows: 1000000, maxSizeInMB: 500, autoExtendMonths: 12 }, // 1M rows, 500MB, extend 1 year
    { tableName: 'ProgressSnapshot', maxRows: 500000, maxSizeInMB: 200, autoExtendMonths: 6 },
    { tableName: 'SecurityLog', maxRows: 100000, maxSizeInMB: 100, autoExtendMonths: 6 },
    { tableName: 'Session', maxRows: 50000, maxSizeInMB: 50, autoExtendMonths: 3 }
  ]
  private static readonly RETENTION_POLICIES: DataRetentionPolicy[] = [
    { tableName: 'StudySession', retentionDays: 730, cleanupEnabled: true }, // 2 years
    { tableName: 'ProgressSnapshot', retentionDays: 365, cleanupEnabled: true }, // 1 year
    { tableName: 'SecurityLog', retentionDays: 90, cleanupEnabled: true }, // 3 months
    { tableName: 'Session', retentionDays: 30, cleanupEnabled: true } // 1 month
  ]

  /**
   * Create monthly partitions for a specific date range
   */
  static async createMonthlyPartitions(tableName: string, startDate: Date, endDate: Date): Promise<void> {
    const months: Date[] = []

    const currentDate = new Date(startDate)
    currentDate.setDate(1) // Start of month

    while (currentDate <= endDate) {
      months.push(new Date(currentDate))
      currentDate.setMonth(currentDate.getMonth() + 1)
    }

    try {
      for (const month of months) {
        await this.createPartitionForMonth(tableName, month)
      }

      logger.info(`Created ${months.length} partitions for ${tableName}`)
    } catch (error) {
      logger.error(`Failed to create partitions for ${tableName}:`, error)
      throw error
    }
  }

  /**
   * Create partition for a specific month
   */
  private static async createPartitionForMonth(tableName: string, date: Date): Promise<void> {
    const year = date.getFullYear()
    const month = String(date.getMonth() + 1).padStart(2, '0')
    const partitionName = `${tableName}_${year}_${month}`

    const startDate = new Date(date)
    startDate.setDate(1) // First day of month

    const endDate = new Date(date)
    endDate.setMonth(endDate.getMonth() + 1) // First day of next month

    try {
      // Use raw SQL to create partition since Prisma doesn't support partitioning directly
      await prisma.$executeRaw`
        DO $$
        BEGIN
          IF NOT EXISTS (
            SELECT 1 FROM pg_class c
            JOIN pg_namespace n ON c.relnamespace = n.oid
            WHERE c.relname = ${partitionName}
            AND c.relkind = 'r'
            AND n.nspname = 'public'
          ) THEN
            EXECUTE format('CREATE TABLE IF NOT EXISTS %I PARTITION OF %I FOR VALUES FROM (%L) TO (%L)',
              ${partitionName}, ${tableName}, ${startDate}, ${endDate});
          END IF;
        END
        $$;
      `
    } catch (error) {
      logger.error(`Failed to create partition ${partitionName} for ${tableName}:`, error)
      throw error
    }
  }

  /**
   * Get information about existing partitions for a table
   */
  static async getPartitionInfo(tableName: string): Promise<PartitionInfo[]> {
    try {
      const result = await prisma.$queryRaw<PartitionInfo[]>`
        SELECT
          c.relname as "partitionName",
          pg_get_expr(c.relpartbound, c.oid) as bounds,
          CASE
            WHEN pg_get_expr(c.relpartbound, c.oid) LIKE '%default%' THEN NULL
            ELSE pg_table_size(c.oid)
          END as size_bytes,
          CASE
            WHEN pg_get_expr(c.relpartbound, c.oid) LIKE '%default%' THEN NULL
            ELSE (SELECT count(*) FROM ONLY c)
          END as "rowCount"
        FROM pg_class c
        JOIN pg_namespace n ON c.relnamespace = n.oid
        JOIN pg_partitioned_table pt ON c.relpartof = pt.partrelid
        WHERE n.nspname = 'public'
        AND pt.partrelid = (SELECT oid FROM pg_class WHERE relname = ${tableName} AND relnamespace = n.oid)
        ORDER BY c.relname;
      `

      // Parse bounds to extract dates
      const partitions: PartitionInfo[] = result.map((row: any) => {
        let startDate: Date | null = null
        let endDate: Date | null = null

        const bounds = row.bounds || row.partitionBound || null
        if (bounds && !String(bounds).includes('DEFAULT')) {
          // Parse bounds like "FOR VALUES FROM ('2025-01-01 00:00:00+00') TO ('2025-02-01 00:00:00+00')"
          const boundsStr = String(bounds)
          const match = boundsStr.match(/FOR VALUES FROM \('([^']+)'\) TO \('([^']+)'\)/)
          if (match) {
            startDate = new Date(match[1])
            endDate = new Date(match[2])
          }
        }

        return {
          tableName,
          partitionName: row.partitionName || row.relname || '',
          startDate: startDate || new Date('1970-01-01'),
          endDate: endDate || new Date('2100-01-01'),
          rowCount: row.rowCount as number | undefined
        }
      })

      return partitions.filter(p => !p.partitionName.includes('_default'))
    } catch (error) {
      logger.error(`Failed to get partition info for ${tableName}:`, error)
      return []
    }
  }

  /**
   * Cleanup old partitions based on retention policies
   */
  static async cleanupOldPartitions(): Promise<{
    deletedPartitions: string[]
    error?: string
  }> {
    const deletedPartitions: string[] = []
    let errorMessage: string | undefined

    try {
      for (const policy of this.RETENTION_POLICIES) {
        if (!policy.cleanupEnabled) continue

        const cutoffDate = new Date()
        cutoffDate.setDate(cutoffDate.getDate() - policy.retentionDays)

        // Get old partitions to drop
        const oldPartitions = await prisma.$queryRaw<{ partition_name: string }[]>`
          SELECT c.relname as partition_name
          FROM pg_class c
          JOIN pg_namespace n ON c.relnamespace = n.oid
          JOIN pg_partitioned_table pt ON c.relpartof = pt.partrelid
          WHERE n.nspname = 'public'
          AND pt.partrelid = (SELECT oid FROM pg_class WHERE relname = ${policy.tableName} AND relnamespace = n.oid)
          AND c.relname NOT LIKE '%_default'
          AND pg_get_expr(c.relpartbound, c.oid) LIKE '%FROM%'
          AND split_part(split_part(pg_get_expr(c.relpartbound, c.oid), '''', 2), '-', 1)::integer < ${cutoffDate.getFullYear()}
            OR (
              split_part(split_part(pg_get_expr(c.relpartbound, c.oid), '''', 2), '-', 1)::integer = ${cutoffDate.getFullYear()}
              AND split_part(split_part(pg_get_expr(c.relpartbound, c.oid), '''', 2), '-', 2)::integer < ${cutoffDate.getMonth() + 1}
            );
        `

        // Drop old partitions
        for (const partition of oldPartitions) {
          try {
            await prisma.$executeRaw`DROP TABLE IF EXISTS ${policy.tableName}.${partition.partition_name} CASCADE;`
            deletedPartitions.push(`${policy.tableName}.${partition.partition_name}`)
          } catch (dropError) {
            logger.error(`Failed to drop partition ${partition.partition_name}:`, dropError)
            errorMessage = errorMessage || `Failed to drop some partitions: ${dropError}`
          }
        }
      }

      // Create archive table for analytical data
      await this.archiveOperationalData()

    } catch (error) {
      logger.error('Error during partition cleanup:', error)
      errorMessage = `Partition cleanup failed: ${error}`
    }

    return { deletedPartitions, error: errorMessage }
  }

  /**
   * Archive operational data for analytics (keep aggregated data)
   */
  private static async archiveOperationalData(): Promise<void> {
    try {
      // Archive monthly aggregated study session data
      await prisma.$executeRaw`
        INSERT INTO archive.study_sessions_monthly (
          user_id,
          year,
          month,
          total_minutes,
          session_count,
          average_focus_score,
          last_activity
        )
        SELECT
          "userId",
          EXTRACT(YEAR FROM "createdAt")::integer,
          EXTRACT(MONTH FROM "createdAt")::integer,
          SUM("durationMin"),
          COUNT(*),
          AVG("focusScore"),
          MAX("createdAt")
        FROM "StudySession"
        WHERE "createdAt" < CURRENT_DATE - INTERVAL '1 year'
        AND NOT EXISTS (
          SELECT 1 FROM archive.study_sessions_monthly asm
          WHERE asm.user_id = "StudySession"."userId"
          AND asm.year = EXTRACT(YEAR FROM "StudySession"."createdAt")::integer
          AND asm.month = EXTRACT(MONTH FROM "StudySession"."createdAt")::integer
        )
        GROUP BY "userId", EXTRACT(YEAR FROM "createdAt"), EXTRACT(MONTH FROM "createdAt")
        ON CONFLICT (user_id, year, month) DO NOTHING;
      `
    } catch (error) {
      logger.error('Error archiving operational data:', error)
      // Don't throw - archiving failure shouldn't stop cleanup
    }
  }

  /**
   * Monitor partition health and generate maintenance recommendations
   */
  static async getPartitionHealthReport(): Promise<{
    tableHealth: {
      tableName: string
      partitionCount: number
      largestPartition: string
      oldestPartition: string
      newestPartition: string
      recommendedActions: string[]
    }[]
  }> {
    const tableHealth: any[] = []

    for (const policy of this.RETENTION_POLICIES) {
      const partitions = await this.getPartitionInfo(policy.tableName)
      const recommendedActions: string[] = []

      if (partitions.length === 0) {
        recommendedActions.push(`No partitions found - create initial partitions`)
      } else {
        // Check for old partitions that should be cleaned up
        const cutoffDate = new Date()
        cutoffDate.setDate(cutoffDate.getDate() - policy.retentionDays)

        const oldPartitions = partitions.filter(p => p.endDate < cutoffDate)
        if (oldPartitions.length > 0) {
          recommendedActions.push(`Remove ${oldPartitions.length} partitions older than ${policy.retentionDays} days`)
        }

        // Check for missing recent partitions
        const latestPartition = partitions
          .filter(p => p.endDate < new Date())
          .sort((a, b) => b.endDate.getTime() - a.endDate.getTime())[0]

        if (latestPartition) {
          const oneMonthFromNow = new Date()
          oneMonthFromNow.setMonth(oneMonthFromNow.getMonth() + 1)

          if (latestPartition.endDate < oneMonthFromNow) {
            const missingMonths = Math.ceil((oneMonthFromNow.getTime() - latestPartition.endDate.getTime()) / (1000 * 60 * 60 * 24 * 30))
            recommendedActions.push(`Create ${missingMonths} additional future partitions`)
          }
        }
      }

      tableHealth.push({
        tableName: policy.tableName,
        partitionCount: partitions.length,
        largestPartition: partitions.sort((a, b) => (b.rowCount || 0) - (a.rowCount || 0))[0]?.partitionName || 'N/A',
        oldestPartition: partitions.sort((a, b) => a.startDate.getTime() - b.startDate.getTime())[0]?.partitionName || 'N/A',
        newestPartition: partitions.sort((a, b) => b.endDate.getTime() - a.endDate.getTime())[0]?.partitionName || 'N/A',
        recommendedActions
      })
    }

    return { tableHealth }
  }

  /**
   * Check data size and automatically extend partitions if needed
   */
  static async checkAndExtendPartitionsIfNeeded(): Promise<{
    triggeredActions: string[]
    errors?: string[]
  }> {
    const triggeredActions: string[] = []
    const errors: string[] = []

    try {
      for (const threshold of this.DATA_SIZE_THRESHOLDS) {
        try {
          // Get current table statistics
          const stats = await prisma.$queryRaw<{ row_count: number, size_bytes: number, size_pretty: string }[]>`
            SELECT
              (SELECT count(*) FROM "${threshold.tableName}") as row_count,
              pg_total_relation_size('${threshold.tableName}') as size_bytes,
              pg_size_pretty(pg_total_relation_size('${threshold.tableName}')) as size_pretty
          `

          const { row_count, size_bytes, size_pretty } = stats[0]
          const sizeMB = size_bytes / (1024 * 1024)

          // Check if thresholds are exceeded
          const rowsExceeded = row_count > threshold.maxRows
          const sizeExceeded = sizeMB > threshold.maxSizeInMB

          if (rowsExceeded || sizeExceeded) {
            const reason = rowsExceeded && sizeExceeded
              ? `${row_count} rows (> ${threshold.maxRows}) and ${size_pretty} (> ${threshold.maxSizeInMB}MB)`
              : rowsExceeded
                ? `${row_count} rows (> ${threshold.maxRows})`
                : `${size_pretty} (> ${threshold.maxSizeInMB}MB)`

            logger.info(`Table ${threshold.tableName} size large: ${reason}, extending partitions by ${threshold.autoExtendMonths} months`)

            // Get latest partition to extend from
            const partitions = await this.getPartitionInfo(threshold.tableName)
            const lastPartition = partitions.sort((a, b) => b.endDate.getTime() - a.endDate.getTime())[0]

            if (lastPartition) {
              const endDate = new Date(lastPartition.endDate)
              endDate.setMonth(endDate.getMonth() + threshold.autoExtendMonths)

              await this.createMonthlyPartitions(threshold.tableName, lastPartition.endDate, endDate)
              triggeredActions.push(`Extended ${threshold.tableName} partitions by ${threshold.autoExtendMonths} months due to: ${reason}`)
            } else {
              // No partitions exist, create initial set
              const startDate = new Date()
              startDate.setHours(0, 0, 0, 0)
              const endDate = new Date(startDate)
              endDate.setMonth(endDate.getMonth() + threshold.autoExtendMonths)

              await this.createMonthlyPartitions(threshold.tableName, startDate, endDate)
              triggeredActions.push(`Created initial ${threshold.autoExtendMonths} months of partitions for ${threshold.tableName} due to: ${reason}`)
            }
          }
        } catch (tableError) {
          logger.error(`Error checking table ${threshold.tableName}:`, tableError)
          errors.push(`Failed to check ${threshold.tableName}: ${tableError}`)
        }
      }
    } catch (error) {
      logger.error('Error in checkAndExtendPartitionsIfNeeded:', error)
      errors.push(`General error: ${error}`)
    }

    return { triggeredActions, errors: errors.length > 0 ? errors : undefined }
  }

  /**
   * Optimize query performance by checking if partitioning is working correctly
   */
  static async verifyPartitioningEfficiency(): Promise<{
    queriesOptimized: number
    partitionsPruned: number
    performanceIssues: string[]
  }> {
    // This would require database-level monitoring, but we can provide recommendations
    const performanceIssues: string[] = []

    try {
      // Check if large tables are partitioned
      const tableSizes = await prisma.$queryRaw<{ table_name: string, table_size: string }[]>`
        SELECT
          schemaname || '.' || tablename as table_name,
          pg_size_pretty(pg_total_relation_size(schemaname||'.'||tablename)) as table_size
        FROM pg_tables t
        JOIN pg_class c ON c.relname = t.tablename
        WHERE schemaname = 'public'
        AND t.tablename IN ('StudySession', 'ProgressSnapshot', 'SecurityLog', 'Session')
        ORDER BY pg_total_relation_size(schemaname||'.'||tablename) DESC;
      `

      for (const table of tableSizes) {
        const size = table.table_size
        if (size.includes('GB') || (size.includes('MB') && parseFloat(size) > 500)) {
          performanceIssues.push(`${table.table_name} is large (${size}) - ensure proper partitioning`)
        }
      }

      // Check partition distribution
      const partitionsWithData = await prisma.$queryRaw<{ count: number }[]>`
        SELECT count(*) as count
        FROM (
          SELECT c.relname
          FROM pg_class c
          JOIN pg_namespace n ON c.relnamespace = n.oid
          JOIN pg_partitioned_table pt ON c.relpartof = pt.partrelid
          WHERE n.nspname = 'public'
          AND (SELECT count(*) FROM ONLY c) > 0
        ) t;
      `

      const partitionsPruned = partitionsWithData[0]?.count || 0

    } catch (error) {
      performanceIssues.push(`Failed to analyze partitioning efficiency: ${error}`)
    }

    return {
      queriesOptimized: 0, // Would need EXPLAIN ANALYZE to determine
      partitionsPruned: 0, // Would need query analysis
      performanceIssues
    }
  }
}

