import { jwtVerify } from 'jose';
import { NextRequest } from 'next/server';

export interface EdgeTokenVerificationResult {
    isValid: boolean;
    user?: {
        id: string;
        email: string;
        name?: string;
        role?: string;
    };
    error?: string;
}

export function getEdgeJWTSecret(): Uint8Array {
    const secret = process.env.JWT_SECRET;
    if (!secret) {
        // In Edge runtime, we might want to fail gracefully or log differently
        // But for auth, missing secret is critical.
        console.error('JWT_SECRET is not set');
        throw new Error('JWT_SECRET is not set');
    }
    return new TextEncoder().encode(secret);
}

export async function verifyEdgeToken(token: string): Promise<EdgeTokenVerificationResult> {
    try {
        const secret = getEdgeJWTSecret();
        const { payload } = await jwtVerify(token, secret);

        return {
            isValid: true,
            user: {
                id: payload.userId as string,
                email: payload.email as string,
                name: payload.name as string,
                role: payload.role as string,
            },
        };
    } catch (error) {
        return { isValid: false, error: 'Invalid token' };
    }
}

export function extractEdgeToken(request: NextRequest): string | null {
    const tokenCookie = request.cookies.get('access_token')?.value || request.cookies.get('authToken')?.value;
    if (tokenCookie) return tokenCookie;

    const authHeader = request.headers.get('authorization');
    if (authHeader?.startsWith('Bearer ')) {
        return authHeader.substring(7);
    }

    return null;
}

/**
 * Environment Variables Validation
 * Validates all required environment variables at startup
 */

import { logger } from './logger';

const REQUIRED_ENV_VARS = {
  // Production required
  production: [
    'JWT_SECRET',
    'DATABASE_URL',
  ],
  // Development optional (but should be set)
  development: [],
} as const;

const MIN_JWT_SECRET_LENGTH = 32;

export interface EnvValidationResult {
  valid: boolean;
  errors: string[];
  warnings: string[];
}

/**
 * Validate JWT_SECRET format and security
 */
function validateJWTSecret(): { valid: boolean; error?: string } {
  const jwtSecret = process.env.JWT_SECRET;

  if (!jwtSecret) {
    return {
      valid: false,
      error: 'JWT_SECRET is not set in environment variables',
    };
  }

  // Check for default/unsafe values
  const unsafeValues = [
    'your-secret-key',
    'fallback-jwt-secret-for-dev-only',
    'secret',
    'password',
    'changeme',
  ];

  if (unsafeValues.includes(jwtSecret)) {
    return {
      valid: false,
      error: `JWT_SECRET is using an unsafe default value: "${jwtSecret}". Please set a secure random secret.`,
    };
  }

  // Check minimum length
  if (jwtSecret.length < MIN_JWT_SECRET_LENGTH) {
    return {
      valid: false,
      error: `JWT_SECRET must be at least ${MIN_JWT_SECRET_LENGTH} characters long. Current length: ${jwtSecret.length}`,
    };
  }

  return { valid: true };
}

/**
 * Validate all environment variables
 */
export function validateEnvironment(): EnvValidationResult {
  const errors: string[] = [];
  const warnings: string[] = [];
  const isProduction = process.env.NODE_ENV === 'production';
  const isDevelopment = process.env.NODE_ENV === 'development';

  // Validate JWT_SECRET
  const jwtValidation = validateJWTSecret();
  if (!jwtValidation.valid) {
    if (isProduction) {
      errors.push(jwtValidation.error!);
    } else {
      warnings.push(jwtValidation.error! + ' (Development mode - should be fixed before production)');
    }
  }

  // Check required variables for production
  if (isProduction) {
    for (const envVar of REQUIRED_ENV_VARS.production) {
      if (!process.env[envVar]) {
        errors.push(`Required environment variable ${envVar} is not set`);
      }
    }
  }

  // Check DATABASE_URL format if set
  if (process.env.DATABASE_URL) {
    try {
      new URL(process.env.DATABASE_URL);
    } catch {
      errors.push('DATABASE_URL is not a valid URL format');
    }
  } else if (isProduction) {
    errors.push('DATABASE_URL is required in production');
  }

  // Check SESSION_DURATION if set
  if (process.env.SESSION_DURATION) {
    const duration = parseInt(process.env.SESSION_DURATION, 10);
    if (isNaN(duration) || duration < 60) {
      warnings.push('SESSION_DURATION should be at least 60 seconds');
    }
  }

  // Check NEXT_PUBLIC_BASE_URL if set
  if (process.env.NEXT_PUBLIC_BASE_URL) {
    try {
      new URL(process.env.NEXT_PUBLIC_BASE_URL);
    } catch {
      warnings.push('NEXT_PUBLIC_BASE_URL is not a valid URL format');
    }
  }

  return {
    valid: errors.length === 0,
    errors,
    warnings,
  };
}

/**
 * Get validated JWT_SECRET with safety checks
 * Security: Validates in ALL environments to prevent unsafe fallback values
 * 
 * CRITICAL SECURITY: This function NEVER uses fallback values or defaults.
 * If JWT_SECRET is not set or is unsafe, the application will fail to start.
 * This prevents accidental deployment with insecure secrets.
 * 
 * @throws Error if JWT_SECRET is missing, unsafe, or too short
 * @returns Validated JWT_SECRET string
 */
export function getJWTSecret(): string {
  const isProduction = process.env.NODE_ENV === 'production';
  
  // Security: NO FALLBACK VALUES ALLOWED
  const jwtSecret = process.env.JWT_SECRET;

  if (!jwtSecret) {
    const errorMessage = 'JWT_SECRET is not set in environment variables. Please set JWT_SECRET.';
    
    // In production, this is a critical security error
    if (isProduction) {
      logger.error('CRITICAL SECURITY ERROR: JWT_SECRET is missing in production!', undefined, {
        error: errorMessage,
        environment: 'production'
      });
    }
    
    throw new Error(errorMessage);
  }

  // Enforce strict validation in ALL environments (not just production)
  // This prevents unsafe fallback values from being used accidentally
  const validation = validateJWTSecret();
  if (!validation.valid) {
    const errorMessage = `JWT_SECRET validation failed: ${validation.error}`;
    
    // Log security warning
    logger.error('JWT_SECRET validation failed - unsafe secret detected!', undefined, {
      error: validation.error,
      environment: process.env.NODE_ENV,
      secretLength: jwtSecret.length,
      // Don't log the actual secret, but log if it matches known unsafe patterns
      isUnsafeValue: jwtSecret === 'fallback-jwt-secret-for-dev-only' || 
                     jwtSecret === 'your-secret-key' ||
                     jwtSecret === 'secret' ||
                     jwtSecret === 'password' ||
                     jwtSecret === 'changeme'
    });
    
    // In production, always throw (critical security issue)
    if (isProduction) {
      throw new Error(`CRITICAL SECURITY ERROR: ${errorMessage}`);
    }
    
    // In development, log warning but still throw to prevent accidental deployment
    // This ensures developers fix the issue before it reaches production
    logger.warn(`JWT_SECRET validation failed: ${validation.error}`);
    throw new Error(errorMessage);
  }

  // Additional security check: warn if secret seems weak (but still valid)
  if (jwtSecret.length < 64 && isProduction) {
    logger.warn('JWT_SECRET is shorter than recommended (64+ characters) for production use', {
      currentLength: jwtSecret.length,
      recommendedLength: 64
    });
  }

  return jwtSecret;
}

/**
 * Validate and throw if environment is invalid
 * Call this at application startup
 */
export function ensureValidEnvironment(): void {
  const result = validateEnvironment();

  // Log warnings
  if (result.warnings.length > 0) {
    logger.warn('Environment variable warnings', { warnings: result.warnings });
    result.warnings.forEach((warning) => {
      logger.warn(`Environment warning: ${warning}`);
    });
  }

  // Throw on errors in production
  if (!result.valid) {
    logger.error('Environment validation failed', undefined, { errors: result.errors });
    result.errors.forEach((error) => {
      logger.error(`Environment error: ${error}`);
    });
    
    if (process.env.NODE_ENV === 'production') {
      throw new Error(
        'Environment validation failed. Please fix the errors above before starting the application.'
      );
    }
  }
}

/**
 * Unified Logging System
 * نظام تسجيل موحد للمشروع
 * 
 * هذا النظام يوحد جميع أنظمة التسجيل في المشروع ويوفر:
 * - دعم للتسجيل على الخادم والعميل
 * - تكامل مع ELK Stack
 * - تسجيل الأخطاء المتقدم
 * - تسجيل الأحداث الأمنية
 * - تسجيل أحداث المصادقة
 */

// Types
export type LogLevel = 'debug' | 'info' | 'warn' | 'error';
export type LogContext = Record<string, any>;
export type LoggableContext = LogContext | unknown;

export interface LogEntry {
  timestamp: string;
  level: LogLevel;
  message: string;
  context?: LogContext;
  error?: {
    message: string;
    stack?: string;
    name?: string;
  };
  source?: string;
  userId?: string;
  sessionId?: string;
  ip?: string;
  userAgent?: string;
}

export interface LoggerConfig {
  level: LogLevel;
  enableConsole: boolean;
  enableELK: boolean;
  enableErrorLogger: boolean;
  enableAuthLogger: boolean;
  enableSecurityLogger: boolean;
  serviceName?: string;
  environment?: string;
}

// Check if we're on the server
const isServer = typeof window === 'undefined';

// Lazy load winston only on server-side
let winstonLoggerInstance: any = null;

async function getWinstonLogger() {
  if (!isServer) return null;
  
  if (!winstonLoggerInstance) {
    try {
      const winstonModule = await import('winston');
      // Winston can be imported as default or namespace
      const winston = (winstonModule as any).default || winstonModule;
      
      winstonLoggerInstance = winston.createLogger({
        level: process.env.LOG_LEVEL || (process.env.NODE_ENV === 'production' ? 'info' : 'debug'),
        format: winston.format.combine(
          winston.format.timestamp({ format: 'YYYY-MM-DD HH:mm:ss' }),
          winston.format.errors({ stack: true }),
          winston.format.colorize(),
          winston.format.printf(({ timestamp, level, message, ...meta }: any) => {
            const metaString = Object.keys(meta).length ? JSON.stringify(meta, null, 2) : '';
            return `${timestamp} [${level}]: ${message}${metaString ? '\n' + metaString : ''}`;
          })
        ),
        transports: [
          new winston.transports.Console({
            silent: !isServer,
          }),
        ],
      });
    } catch (err) {
      // If winston fails to load, return null
      return null;
    }
  }
  
  return winstonLoggerInstance;
}

// Default configuration
const defaultConfig: LoggerConfig = {
  level: (process.env.LOG_LEVEL as LogLevel) || (process.env.NODE_ENV === 'production' ? 'info' : 'debug'),
  enableConsole: true,
  enableELK: process.env.ELASTICSEARCH_ENABLED !== 'false' && isServer,
  enableErrorLogger: true,
  enableAuthLogger: isServer, // Only enable on server
  enableSecurityLogger: isServer, // Only enable on server - prevents client bundling
  serviceName: 'thanawy',
  environment: process.env.NODE_ENV || 'development',
};

class UnifiedLogger {
  private config: LoggerConfig;
  private elkLogger: any = null;
  private errorLogger: any = null;
  private authLogger: any = null;
  private securityLogger: any = null;
  private initialized = false;
  private initializing = false;

  constructor(config: Partial<LoggerConfig> = {}) {
    this.config = { ...defaultConfig, ...config };
    // Initialize lazily on first use
  }

  /**
   * Initialize all logging systems (lazy initialization)
   */
  private async ensureInitialized(): Promise<void> {
    if (this.initialized || this.initializing) return;
    
    this.initializing = true;
    
    try {
      // Initialize ELK logger (server-side only)
      if (this.config.enableELK && isServer) {
        try {
          const { elkLogger } = await import('./elk-logger');
          this.elkLogger = elkLogger;
        } catch (error) {
          // ELK logger initialization failed, continue without it
          this.config.enableELK = false;
        }
      }

      // Initialize Error Logger (client-side)
      if (this.config.enableErrorLogger && !isServer) {
        try {
          const errorLoggerModule = await import('@/services/ErrorLogger');
          this.errorLogger = errorLoggerModule.default;
        } catch (error) {
          // Error logger initialization failed, continue without it
          this.config.enableErrorLogger = false;
        }
      }

      // Initialize Auth Logger (server-side only)
      // Use loader to prevent client bundling of server-only code
      if (this.config.enableAuthLogger && isServer) {
        try {
          // Use dynamic import with string literal to prevent static analysis
          const loaderPath = './' + 'auth-logger-loader';
          const { loadAuthLogger } = await import(loaderPath);
          this.authLogger = await loadAuthLogger();
        } catch (error) {
          // Auth logger initialization failed, continue without it
          this.config.enableAuthLogger = false;
        }
      }

      // Initialize Security Logger (server-side only)
      // Use a server-only loader to prevent client bundling
      if (this.config.enableSecurityLogger && isServer && typeof window === 'undefined') {
        try {
          // Dynamically construct the loader path to prevent static analysis
          const loaderPath = './' + 'security-logger-loader';
          const { loadSecurityLogger } = await import(loaderPath);
          this.securityLogger = await loadSecurityLogger();
        } catch (error) {
          // Security logger initialization failed, continue without it
          // This can happen if the module doesn't exist or has server-only dependencies
          this.config.enableSecurityLogger = false;
        }
      }
    } finally {
      this.initialized = true;
      this.initializing = false;
    }
  }

  /**
   * Format log message
   */
  private formatMessage(level: LogLevel, message: string, context?: LogContext): string {
    const timestamp = new Date().toISOString();
    const contextStr = context ? ` ${JSON.stringify(context)}` : '';
    return `[${timestamp}] [${level.toUpperCase()}] ${message}${contextStr}`;
  }

  /**
   * Create log entry
   */
  private createLogEntry(
    level: LogLevel,
    message: string,
    error?: Error | unknown,
    context?: LogContext
  ): LogEntry {
    const entry: LogEntry = {
      timestamp: new Date().toISOString(),
      level,
      message,
      context,
    };

    if (error !== undefined) {
      if (error instanceof Error) {
        entry.error = {
          message: error.message,
          stack: error.stack,
          name: error.name,
        };
      } else {
        entry.error = {
          message: String(error),
        };
      }
    }

    // Add context metadata
    if (context) {
      if (context.userId) entry.userId = String(context.userId);
      if (context.sessionId) entry.sessionId = String(context.sessionId);
      if (context.ip) entry.ip = String(context.ip);
      if (context.userAgent) entry.userAgent = String(context.userAgent);
      if (context.source) entry.source = String(context.source);
    }

    return entry;
  }

  /**
   * Check if level should be logged
   */
  private shouldLog(level: LogLevel): boolean {
    const levels: LogLevel[] = ['debug', 'info', 'warn', 'error'];
    const currentLevelIndex = levels.indexOf(this.config.level);
    const messageLevelIndex = levels.indexOf(level);
    return messageLevelIndex >= currentLevelIndex;
  }

  /**
   * Log to console
   */
  private async logToConsole(level: LogLevel, message: string, context?: LogContext, error?: Error | unknown): Promise<void> {
    if (!this.config.enableConsole) return;

    const formattedMessage = this.formatMessage(level, message, context);
    const contextStr = context ? ` ${JSON.stringify(context)}` : '';
    const errorStr = error instanceof Error ? `\nError: ${error.message}${error.stack ? `\n${error.stack}` : ''}` : error ? `\nError: ${String(error)}` : '';

    const fullMessage = formattedMessage + contextStr + errorStr;

    if (isServer) {
      // Use winston on server-side
      try {
        const winstonLogger = await getWinstonLogger();
        if (winstonLogger) {
          switch (level) {
            case 'debug':
              if (process.env.NODE_ENV === 'development') {
                winstonLogger.debug(fullMessage);
              }
              break;
            case 'info':
              winstonLogger.info(fullMessage);
              break;
            case 'warn':
              winstonLogger.warn(fullMessage);
              break;
            case 'error':
              winstonLogger.error(fullMessage);
              break;
          }
        }
      } catch (err) {
        // Fallback to console if winston fails
        switch (level) {
          case 'debug':
            if (process.env.NODE_ENV === 'development') console.debug(fullMessage);
            break;
          case 'info':
            console.info(fullMessage);
            break;
          case 'warn':
            console.warn(fullMessage);
            break;
          case 'error':
            console.error(fullMessage);
            break;
        }
      }
    } else {
      // Use console on client-side
      switch (level) {
        case 'debug':
          if (process.env.NODE_ENV === 'development') {
            console.debug(fullMessage);
          }
          break;
        case 'info':
          console.info(fullMessage);
          break;
        case 'warn':
          console.warn(fullMessage);
          break;
        case 'error':
          console.error(fullMessage);
          break;
      }
    }
  }

  /**
   * Log to ELK
   */
  private async logToELK(level: LogLevel, message: string, context?: LogContext, error?: Error | unknown): Promise<void> {
    if (!this.config.enableELK) return;
    
    await this.ensureInitialized();
    
    if (!this.elkLogger) return;

    try {
      const logEntry = this.createLogEntry(level, message, error, context);
      const meta = {
        ...logEntry.context,
        ...(logEntry.error && { error: logEntry.error }),
        service: this.config.serviceName,
        environment: this.config.environment,
      };

      this.elkLogger.log(level, message, meta);
    } catch (err) {
      // If ELK logging fails, don't throw - just log to console
      this.logToConsole('warn', 'Failed to log to ELK', { error: String(err) });
    }
  }

  /**
   * Log to Error Logger (client-side)
   */
  private async logToErrorLogger(level: LogLevel, message: string, error?: Error | unknown, context?: LogContext): Promise<void> {
    if (!this.config.enableErrorLogger || isServer) return;
    
    await this.ensureInitialized();
    
    if (!this.errorLogger) return;

    try {
      if (level === 'error' && error) {
        const errorObj = error instanceof Error ? error : new Error(String(error));
        this.errorLogger.logError(errorObj, {
          source: context?.source || 'UnifiedLogger',
          severity: context?.severity || 'medium',
          ...context,
        });
      }
    } catch (err) {
      // If error logger fails, don't throw
      this.logToConsole('warn', 'Failed to log to ErrorLogger', { error: String(err) });
    }
  }

  /**
   * Log to Auth Logger (server-side)
   */
  private async logToAuthLogger(
    level: LogLevel,
    message: string,
    context?: LogContext,
    error?: Error | unknown
  ): Promise<void> {
    if (!this.config.enableAuthLogger || !isServer) return;
    
    await this.ensureInitialized();
    
    if (!this.authLogger) return;

    try {
      const userId = context?.userId || null;
      const ip = context?.ip || 'unknown';
      const metadata = { ...context, message };

      if (level === 'error') {
        await this.authLogger.error(message, userId, ip, String(error), metadata);
      } else if (level === 'warn') {
        await this.authLogger.warn(message, userId, ip, metadata);
      } else if (level === 'info') {
        await this.authLogger.info(message, userId, ip, metadata);
      } else if (level === 'debug') {
        await this.authLogger.debug(message, userId, ip, metadata);
      }
    } catch (err) {
      // If auth logger fails, don't throw
      this.logToConsole('warn', 'Failed to log to AuthLogger', { error: String(err) });
    }
  }

  /**
   * Log to Security Logger (server-side)
   */
  private async logToSecurityLogger(
    level: LogLevel,
    message: string,
    context?: LogContext
  ): Promise<void> {
    if (!this.config.enableSecurityLogger || !isServer) return;
    if (level !== 'warn' && level !== 'error') return; // Security logger only for warnings and errors
    
    await this.ensureInitialized();
    
    if (!this.securityLogger) return;

    try {
      const userId = context?.userId || 'unknown';
      const ip = context?.ip || 'unknown';
      const userAgent = context?.userAgent || 'unknown';

      if (context?.eventType) {
        await this.securityLogger.logEvent({
          userId,
          eventType: context.eventType as any,
          ip,
          userAgent,
          metadata: context,
        });
      }
    } catch (err) {
      // If security logger fails, don't throw
      this.logToConsole('warn', 'Failed to log to SecurityLogger', { error: String(err) });
    }
  }

  /**
   * Main log method
   */
  private normalizeContext(context?: LoggableContext): LogContext | undefined {
    if (context === undefined || context === null) {
      return undefined;
    }

    if (context instanceof Error) {
      return {
        error: {
          message: context.message,
          stack: context.stack,
          name: context.name,
        },
      };
    }

    if (typeof context === 'object') {
      if (Array.isArray(context)) {
        return { data: context };
      }

      return context as LogContext;
    }

    return { value: context };
  }

  private async log(
    level: LogLevel,
    message: string,
    error?: Error | unknown,
    context?: LoggableContext
  ): Promise<void> {
    if (!this.shouldLog(level)) return;

    const normalizedContext = this.normalizeContext(context);

    const logEntry = this.createLogEntry(level, message, error, normalizedContext);

    // Log to console (async now)
    this.logToConsole(level, message, normalizedContext, error).catch(() => {
      // Silently handle async errors
    });

    // Log to ELK (server-side, async)
    this.logToELK(level, message, normalizedContext, error).catch(() => {
      // Silently handle async errors
    });

    // Log to Error Logger (client-side, async)
    this.logToErrorLogger(level, message, error, normalizedContext).catch(() => {
      // Silently handle async errors
    });

    // Log to Auth Logger (server-side, async)
    if (isServer) {
      await this.logToAuthLogger(level, message, normalizedContext, error);
    }

    // Log to Security Logger (server-side, async)
    if (isServer) {
      await this.logToSecurityLogger(level, message, normalizedContext);
    }
  }

  /**
   * Debug log
   */
  debug(message: string, context?: LoggableContext): void {
    this.log('debug', message, undefined, context).catch(() => {
      // Silently handle async errors
    });
  }

  /**
   * Info log
   */
  info(message: string, context?: LoggableContext): void {
    this.log('info', message, undefined, context).catch(() => {
      // Silently handle async errors
    });
  }

  /**
   * Warn log
   */
  warn(message: string, context?: LoggableContext): void {
    this.log('warn', message, undefined, context).catch(() => {
      // Silently handle async errors
    });
  }

  /**
   * Error log
   */
  error(message: string, error?: Error | unknown, context?: LoggableContext): void {
    this.log('error', message, error, context).catch(() => {
      // Silently handle async errors
    });
  }

  /**
   * HTTP request log
   */
  http(req: {
    method: string;
    url: string;
    statusCode?: number;
    duration?: number;
    ip?: string;
    userAgent?: string;
    userId?: string;
  }): void {
    this.info('HTTP Request', {
      type: 'http',
      method: req.method,
      url: req.url,
      statusCode: req.statusCode,
      duration: req.duration,
      ip: req.ip,
      userAgent: req.userAgent,
      userId: req.userId,
    });
  }

  /**
   * Database query log
   */
  db(query: {
    operation: string;
    table?: string;
    duration: number;
    success: boolean;
    error?: string;
  }): void {
    const level = query.success ? 'info' : 'error';
    this.log(level, 'Database Query', query.error ? new Error(query.error) : undefined, {
      type: 'database',
      operation: query.operation,
      table: query.table,
      duration: query.duration,
      success: query.success,
    }).catch(() => {
      // Silently handle async errors
    });
  }

  /**
   * Authentication event log
   */
  auth(event: {
    type: string;
    userId?: string;
    ip: string;
    success: boolean;
    method?: string;
    error?: string;
  }): void {
    const level = event.success ? 'info' : 'warn';
    this.log(level, 'Authentication Event', event.error ? new Error(event.error) : undefined, {
      type: 'authentication',
      eventType: event.type,
      userId: event.userId,
      ip: event.ip,
      success: event.success,
      method: event.method,
    }).catch(() => {
      // Silently handle async errors
    });
  }

  /**
   * Security event log
   */
  security(event: {
    eventType: string;
    userId?: string;
    ip: string;
    userAgent?: string;
    metadata?: LogContext;
  }): void {
    this.warn('Security Event', {
      type: 'security',
      eventType: event.eventType,
      userId: event.userId,
      ip: event.ip,
      userAgent: event.userAgent,
      ...event.metadata,
    });
  }

  /**
   * Update configuration
   */
  updateConfig(config: Partial<LoggerConfig>): void {
    this.config = { ...this.config, ...config };
  }

  /**
   * Get current configuration
   */
  getConfig(): LoggerConfig {
    return { ...this.config };
  }
}

// Create singleton instance
let loggerInstance: UnifiedLogger | null = null;

/**
 * Get the unified logger instance
 */
export function getLogger(): UnifiedLogger {
  if (!loggerInstance) {
    loggerInstance = new UnifiedLogger();
  }
  return loggerInstance;
}

// Export singleton instance
export const logger = getLogger();

// Export default
export default logger;

import { NextRequest, NextResponse } from 'next/server';
import { authService } from '@/lib/services/auth-service';
import type { TokenVerificationResult } from '@/lib/services/auth-service';

export interface AuthenticatedRequest extends NextRequest {
  user?: {
    id: string;
    email: string;
    name?: string;
    role?: string;
  };
  sessionId?: string;
}

export interface AuthMiddlewareOptions {
  /**
   * Whether to require authentication (default: true)
   */
  requireAuth?: boolean;

  /**
   * Whether to check session validity in database (default: true)
   */
  checkSession?: boolean;

  /**
   * Required roles (if any)
   */
  requiredRoles?: string[];

  /**
   * Whether to allow unverified email (default: false)
   */
  allowUnverified?: boolean;

  /**
   * Custom error handler
   */
  onError?: (error: string, code: string) => NextResponse;
}

/**
 * Authentication middleware for API routes
 * 
 * Usage:
 * ```typescript
 * export async function GET(request: NextRequest) {
 *   const authResult = await withAuth(request);
 *   if (!authResult.success) {
 *     return authResult.response;
 *   }
 *   const { user, sessionId } = authResult;
 *   // ... your route logic
 * }
 * ```
 */
export async function withAuth(
  request: NextRequest,
  options: AuthMiddlewareOptions = {}
): Promise<
  | { success: true; user: NonNullable<TokenVerificationResult['user']>; sessionId?: string; request: AuthenticatedRequest }
  | { success: false; response: NextResponse }
> {
  const {
    requireAuth = true,
    checkSession = true,
    requiredRoles = [],
    allowUnverified = false,
    onError,
  } = options;

  // Extract token from various sources with validation
  let token: string | undefined = undefined;

  const authHeader = request.headers.get('Authorization') || request.headers.get('authorization');
  if (authHeader?.startsWith('Bearer ')) {
    token = authHeader.substring(7);
  } else {
    const cookieHeader = request.headers.get('cookie');
    if (cookieHeader) {
      const cookies = cookieHeader.split(';').reduce((acc, cookie) => {
        const [key, value] = cookie.trim().split('=');
        acc[key] = value;
        return acc;
      }, {} as Record<string, string>);
      token = cookies['access_token'];
    }
  }

  // Enhanced token validation
  if (token && typeof token === 'string') {
    // Basic JWT format validation (should have 3 parts separated by dots)
    const tokenParts = token.split('.');
    if (tokenParts.length !== 3 || tokenParts.some(part => part.length === 0)) {
      // ... Error response logic same as before ... 
      const errorResponse = NextResponse.json(
        {
          error: 'رمز المصادقة غير صحيح',
          code: 'INVALID_TOKEN_FORMAT',
        },
        { status: 401 }
      );

      if (onError) {
        return { success: false, response: onError('INVALID_TOKEN_FORMAT', 'INVALID_TOKEN_FORMAT') };
      }

      return { success: false, response: errorResponse };
    }
  }

  // If authentication is required but no token provided
  if (requireAuth && !token) {
    // ... Error response ...
    const errorResponse = NextResponse.json(
      {
        error: 'يتطلب هذا الطلب تسجيل الدخول.',
        code: 'UNAUTHORIZED',
      },
      { status: 401 }
    );

    if (onError) {
      return { success: false, response: onError('UNAUTHORIZED', 'UNAUTHORIZED') };
    }

    return { success: false, response: errorResponse };
  }

  // If no token and auth not required, return success without user
  if (!token) {
    return {
      success: true,
      user: null as any,
      request: request as AuthenticatedRequest,
    };
  }

  // Verify token
  let userPayload: any = null;
  try {
    // Using verifyToken from auth-service (via direct import needed at top)
    // Since I cannot change imports in this block easily without viewing top, assuming I will fix imports in next step or I use global authService if available.
    // Actually authService.verifyToken checks signature.
    // But verifyToken returns payload or null.

    userPayload = await authService.verifyToken(token);

  } catch (error) {
    // ... Error handling ...
  }

  if (!userPayload) {
    const errorResponse = NextResponse.json(
      {
        error: 'انتهت صلاحية الجلسة الحالية.',
        code: 'INVALID_OR_EXPIRED_TOKEN',
      },
      { status: 401 }
    );

    if (onError) {
      return { success: false, response: onError('INVALID_OR_EXPIRED_TOKEN', 'INVALID_OR_EXPIRED_TOKEN') };
    }

    return { success: false, response: errorResponse };
  }

  // Construct verification result object to match downstream usage
  const verification = {
    isValid: true,
    user: {
      id: userPayload.userId,
      userId: userPayload.userId, // Added to satisfy UserPayload
      email: userPayload.email,
      role: userPayload.role,
      name: userPayload.name // if exists
    },
    sessionId: userPayload.sessionId
  };


  // Enhanced role validation
  if (requiredRoles.length > 0) {
    const userRole = verification.user.role || 'user';

    // Validate role format
    if (typeof userRole !== 'string' || userRole.trim().length === 0) {
      const errorResponse = NextResponse.json(
        {
          error: 'دور المستخدم غير صحيح',
          code: 'INVALID_USER_ROLE',
        },
        { status: 403 }
      );

      if (onError) {
        return { success: false, response: onError('INVALID_USER_ROLE', 'INVALID_USER_ROLE') };
      }

      return { success: false, response: errorResponse };
    }

    // Check if user has required role
    if (!requiredRoles.includes(userRole)) {
      const errorResponse = NextResponse.json(
        {
          error: 'ليس لديك صلاحية للوصول إلى هذا المورد.',
          code: 'FORBIDDEN',
        },
        { status: 403 }
      );

      if (onError) {
        return { success: false, response: onError('FORBIDDEN', 'FORBIDDEN') };
      }

      return { success: false, response: errorResponse };
    }
  }

  // Attach user to request object
  const authenticatedRequest = request as AuthenticatedRequest;
  authenticatedRequest.user = verification.user;
  authenticatedRequest.sessionId = verification.sessionId;

  return {
    success: true,
    user: verification.user,
    sessionId: verification.sessionId,
    request: authenticatedRequest,
  };
}

/**
 * Helper to create authenticated route handler
 */
export function createAuthHandler(
  handler: (request: AuthenticatedRequest, user: NonNullable<TokenVerificationResult['user']>, sessionId?: string) => Promise<NextResponse>,
  options: AuthMiddlewareOptions = {}
) {
  return async (request: NextRequest) => {
    const authResult = await withAuth(request, options);

    if (!authResult.success) {
      return authResult.response;
    }

    return handler(authResult.request, authResult.user, authResult.sessionId);
  };
}

/**
 * Middleware for role-based access control
 */
export function requireRole(...roles: string[]) {
  return (request: NextRequest, options: Omit<AuthMiddlewareOptions, 'requiredRoles'> = {}) => {
    return withAuth(request, { ...options, requiredRoles: roles });
  };
}

/**
 * Middleware for admin-only access
 */
export function requireAdmin(request: NextRequest, options: Omit<AuthMiddlewareOptions, 'requiredRoles'> = {}) {
  return withAuth(request, { ...options, requiredRoles: ['admin'] });
}

/**
 * Logging Middleware
 * Provides request/response logging for API routes
 */

import { NextRequest, NextResponse } from 'next/server';
import { logger } from '@/lib/logger';

export interface LoggingOptions {
  logBody?: boolean;
  logHeaders?: boolean;
  logResponse?: boolean;
}

/**
 * Logging middleware for API routes
 */
export async function loggingMiddleware(
  request: NextRequest,
  handler: (req: NextRequest) => Promise<NextResponse>,
  options: LoggingOptions = {}
): Promise<NextResponse> {
  const startTime = Date.now();
  const { logBody = false, logHeaders = false, logResponse = false } = options;

  // Log request
  const requestLog: any = {
    method: request.method,
    url: request.url,
    timestamp: new Date().toISOString(),
  };

  if (logHeaders) {
    requestLog.headers = Object.fromEntries(request.headers.entries());
  }

  if (logBody && request.method !== 'GET') {
    try {
      const body = await request.clone().json();
      requestLog.body = body;
    } catch (error) {
      // Body might not be JSON
    }
  }

  logger.info('Incoming request:', requestLog);

  try {
    // Execute handler
    const response = await handler(request);

    // Log response
    const duration = Date.now() - startTime;
    const responseLog: any = {
      status: response.status,
      duration: `${duration}ms`,
    };

    if (logResponse) {
      try {
        const responseBody = await response.clone().json();
        responseLog.body = responseBody;
      } catch (error) {
        // Response might not be JSON
      }
    }

    logger.info('Response sent:', responseLog);

    return response;
  } catch (error) {
    const duration = Date.now() - startTime;
    logger.error('Request failed:', {
      error,
      duration: `${duration}ms`,
    });
    throw error;
  }
}

/**
 * Tracing Middleware
 * 
 * Middleware لتتبع الطلبات HTTP مع Jaeger
 */

import { NextRequest, NextResponse } from 'next/server';
import { traceAsync, extractContext, injectContext, getTracer } from '@/lib/tracing/jaeger-tracer';

export async function tracingMiddleware(
  request: NextRequest,
  handler: (req: NextRequest) => Promise<NextResponse>
): Promise<NextResponse> {
  const method = request.method;
  const url = new URL(request.url);
  const route = url.pathname;
  
  // استخراج context من headers
  const headers: Record<string, string> = {};
  request.headers.forEach((value, key) => {
    headers[key] = value;
  });
  
  const parentContext = extractContext(headers);

  // إنشاء span للطلب
  return traceAsync(
    `HTTP ${method} ${route}`,
    async (span) => {
      // إضافة attributes
      span.setAttributes({
        'http.method': method,
        'http.url': route,
        'http.route': route,
        'http.user_agent': request.headers.get('user-agent') || 'unknown',
        'http.ip': request.headers.get('x-forwarded-for')?.split(',')[0]?.trim() || 'unknown',
      });

      try {
        // تنفيذ الـ handler
        const response = await handler(request);
        
        const statusCode = response.status;
        span.setAttributes({
          'http.status_code': statusCode,
          'http.status_text': response.statusText,
        });

        // إضافة tracing headers إلى الاستجابة
        const tracingHeaders = injectContext({});
        Object.entries(tracingHeaders).forEach(([key, value]) => {
          response.headers.set(key, value);
        });

        return response;
      } catch (error) {
        span.setAttributes({
          'error': true,
          'error.message': error instanceof Error ? error.message : String(error),
        });
        throw error;
      }
    },
    {
      'http.method': method,
      'http.url': route,
    }
  );
}

