    cache: {
      // Enable cache hit/miss logging
      logMetrics: isDevelopment,

      // Threshold for logging slow cache operations (in ms)
      slowOperationThreshold: 100,

      // Sample rate for cache metrics (0.0 to 1.0)
      sampleRate: isProduction ? 0.1 : 1.0,
