'use client';

/**
 * مكتبة شاملة للوصول الآمن لواجهات برمجة التطبيقات الخاصة بالعميل
 * Comprehensive library for safe client-side API access
 */

import { useState, useEffect, useCallback, useRef } from 'react';

import { clientLogger as logger } from '@/lib/client-logger';

// ==================== Type Definitions ====================

export type StorageType = 'local' | 'session';

export interface SafeStorageOptions<T = unknown> {
  /** قيمة افتراضية في حالة عدم توفر التخزين */
  fallback?: T;
  /** نوع التخزين */
  storageType?: StorageType;
  /** تحليل القيمة المخزنة */
  parser?: (value: string) => T;
  /** تحويل القيمة قبل التخزين */
  serializer?: (value: T) => string;
}

// ==================== Storage Safety Checks ====================

/**
 * فحص ما إذا كان localStorage متاحًا
 * Check if localStorage is available
 */
export function isLocalStorageAvailable(): boolean {
  if (typeof window === 'undefined') return false;
  try {
    const testKey = '__storage_test__';
    window.localStorage.setItem(testKey, 'test');
    window.localStorage.removeItem(testKey);
    return true;
  } catch (e) {
    return false;
  }
}

/**
 * فحص ما إذا كان sessionStorage متاحًا
 * Check if sessionStorage is available
 */
export function isSessionStorageAvailable(): boolean {
  if (typeof window === 'undefined') return false;
  try {
    const testKey = '__storage_test__';
    window.sessionStorage.setItem(testKey, 'test');
    window.sessionStorage.removeItem(testKey);
    return true;
  } catch (e) {
    return false;
  }
}

/**
 * الحصول على كائن التخزين المناسب
 * Get the appropriate storage object
 */
function getStorage(type: StorageType = 'local'): Storage | null {
  if (typeof window === 'undefined') return null;

  try {
    return type === 'local' ? window.localStorage : window.sessionStorage;
  } catch (e) {
    logger.warn(`Failed to access ${type}Storage:`, e);
    return null;
  }
}

// ==================== Safe Storage Operations ====================

/**
 * قراءة قيمة من التخزين بشكل آمن
 * Safely read a value from storage
 */
export function safeGetItem<T = unknown>(
  key: string,
  options: SafeStorageOptions<T> = {}
): T | null {
  const { fallback = null, storageType = 'local', parser } = options;

  const storage = getStorage(storageType);
  if (!storage) return fallback;

  try {
    const item = storage.getItem(key);
    if (item === null) return fallback;

    if (parser) {
      return parser(item);
    }

    // Try to parse as JSON by default
    try {
      return JSON.parse(item);
    } catch {
      return item as unknown as T;
    }
  } catch (e) {
    logger.warn(`Failed to get item "${key}" from ${storageType}Storage:`, e);
    return fallback;
  }
}

/**
 * كتابة قيمة إلى التخزين بشكل آمن
 * Safely write a value to storage
 */
export function safeSetItem<T = unknown>(
  key: string,
  value: T,
  options: SafeStorageOptions<T> = {}
): boolean {
  const { storageType = 'local', serializer } = options;

  const storage = getStorage(storageType);
  if (!storage) return false;

  try {
    const stringValue = serializer
      ? serializer(value)
      : typeof value === 'string'
        ? value
        : JSON.stringify(value);

    storage.setItem(key, stringValue);
    return true;
  } catch (e) {
    logger.warn(`Failed to set item "${key}" in ${storageType}Storage:`, e);
    return false;
  }
}

/**
 * حذف قيمة من التخزين بشكل آمن
 * Safely remove a value from storage
 */
export function safeRemoveItem(
  key: string,
  options: SafeStorageOptions = {}
): boolean {
  const { storageType = 'local' } = options;

  const storage = getStorage(storageType);
  if (!storage) return false;

  try {
    storage.removeItem(key);
    return true;
  } catch (e) {
    logger.warn(`Failed to remove item "${key}" from ${storageType}Storage:`, e);
    return false;
  }
}

/**
 * مسح جميع البيانات من التخزين بشكل آمن
 * Safely clear all storage
 */
export function safeClearStorage(storageType: StorageType = 'local'): boolean {
  const storage = getStorage(storageType);
  if (!storage) return false;

  try {
    storage.clear();
    return true;
  } catch (e) {
    logger.warn(`Failed to clear ${storageType}Storage:`, e);
    return false;
  }
}

// ==================== React Hooks ====================

/**
 * Hook للوصول الآمن إلى localStorage مع المزامنة التلقائية
 * Hook for safe localStorage access with automatic sync
 */
export function useSafeLocalStorage<T = any>(
  key: string,
  initialValue: T
): [T, (value: T | ((prev: T) => T)) => void, boolean] {
  // حالة للتحقق من تحميل المكون
  const [mounted, setMounted] = useState(false);

  // الحالة مع القيمة الأولية
  const [storedValue, setStoredValue] = useState<T>(initialValue);

  // تحميل القيمة من localStorage بعد التحميل
  useEffect(() => {
    setMounted(true);
    const value = safeGetItem(key, { fallback: initialValue });
    setStoredValue(value as T);
  }, [key, initialValue]);

  // دالة لتحديث القيمة
  const setValue = useCallback((value: T | ((prev: T) => T)) => {
    try {
      // Allow value to be a function so we have same API as useState
      const valueToStore = value instanceof Function ? value(storedValue) : value;

      setStoredValue(valueToStore);
      safeSetItem(key, valueToStore);
    } catch (error) {
      logger.warn(`Error setting localStorage key "${key}":`, error);
    }
  }, [key, storedValue]);

  return [storedValue, setValue, mounted];
}

/**
 * Hook للوصول الآمن إلى sessionStorage مع المزامنة التلقائية
 * Hook for safe sessionStorage access with automatic sync
 */
export function useSafeSessionStorage<T = any>(
  key: string,
  initialValue: T
): [T, (value: T | ((prev: T) => T)) => void, boolean] {
  const [mounted, setMounted] = useState(false);
  const [storedValue, setStoredValue] = useState<T>(initialValue);

  useEffect(() => {
    setMounted(true);
    const value = safeGetItem(key, {
      fallback: initialValue,
      storageType: 'session'
    });
    setStoredValue(value as T);
  }, [key, initialValue]);

  const setValue = useCallback((value: T | ((prev: T) => T)) => {
    try {
      const valueToStore = value instanceof Function ? value(storedValue) : value;

      setStoredValue(valueToStore);
      safeSetItem(key, valueToStore, { storageType: 'session' });
    } catch (error) {
      logger.warn(`Error setting sessionStorage key "${key}":`, error);
    }
  }, [key, storedValue]);

  return [storedValue, setValue, mounted];
}

// ==================== Window & Document Safe Access ====================

/**
 * فحص ما إذا كان الكود يعمل في المتصفح
 * Check if code is running in browser
 */
export function isBrowser(): boolean {
  return typeof window !== 'undefined';
}

/**
 * الوصول الآمن إلى window
 * Safe window access
 */
export function safeWindow<T>(
  accessor: (window: Window) => T,
  fallback: T
): T {
  if (!isBrowser()) return fallback;

  try {
    return accessor(window);
  } catch (e) {
    logger.warn('Failed to access window:', e);
    return fallback;
  }
}

/**
 * الوصول الآمن إلى document
 * Safe document access
 */
export function safeDocument<T>(
  accessor: (document: Document) => T,
  fallback: T
): T {
  if (!isBrowser() || typeof document === 'undefined') return fallback;

  try {
    return accessor(document);
  } catch (e) {
    logger.warn('Failed to access document:', e);
    return fallback;
  }
}

/**
 * Hook للتحقق من تحميل المكون في المتصفح
 * Hook to check if component is mounted in browser
 */
export function useIsMounted(): boolean {
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  return mounted;
}

/**
 * Hook للحصول على حجم نافذة المتصفح
 * Hook to get browser window size
 */
export function useWindowSize() {
  const [windowSize, setWindowSize] = useState({
    width: 0,
    height: 0,
  });

  useEffect(() => {
    function handleResize() {
      setWindowSize({
        width: window.innerWidth,
        height: window.innerHeight,
      });
    }

    // تعيين الحجم الأولي
    handleResize();

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  return windowSize;
}

/**
 * Hook للتحقق من استعلامات الوسائط
 * Hook for media queries
 */
export function useSafeMediaQuery(query: string): boolean {
  const [matches, setMatches] = useState(false);
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);

    if (!isBrowser()) return;

    try {
      const media = window.matchMedia(query);

      // تعيين القيمة الأولية
      setMatches(media.matches);

      // الاستماع للتغييرات
      const listener = (e: MediaQueryListEvent) => setMatches(e.matches);

      // استخدام الطريقة المناسبة حسب دعم المتصفح
      if (media.addEventListener) {
        media.addEventListener('change', listener);
        return () => media.removeEventListener('change', listener);
      } else {
        // للمتصفحات القديمة
        media.addListener(listener);
        return () => media.removeListener(listener);
      }
    } catch (e) {
      logger.warn('Failed to setup media query:', e);
    }
  }, [query]);

  // إرجاع false قبل التحميل لتجنب مشاكل الهايدريشن
  return mounted ? matches : false;
}

// ==================== Event Listener Helpers ====================

/**
 * Hook لإضافة مستمع أحداث بشكل آمن
 * Hook to safely add event listener
 */
export function useSafeEventListener<K extends keyof WindowEventMap>(
  eventName: K,
  handler: (event: WindowEventMap[K]) => void,
  element?: HTMLElement | Window | null
) {
  const savedHandler = useRef<(event: WindowEventMap[K]) => void>();

  useEffect(() => {
    savedHandler.current = handler;
  }, [handler]);

  useEffect(() => {
    if (!isBrowser()) return;

    const targetElement = element || window;
    if (!targetElement || !targetElement.addEventListener) return;

    const eventListener = (event: Event) => {
      savedHandler.current?.(event as WindowEventMap[K]);
    };

    targetElement.addEventListener(eventName, eventListener);

    return () => {
      targetElement.removeEventListener(eventName, eventListener);
    };
  }, [eventName, element]);
}

// ==================== User ID Management ====================

const LOCAL_USER_KEY = 'user_id';

/**
 * الحصول على معرف المستخدم بشكل آمن
 * Safely get user ID
 */
export function getSafeUserId(): string | null {
  return safeGetItem(LOCAL_USER_KEY, { fallback: null });
}

/**
 * تعيين معرف المستخدم بشكل آمن
 * Safely set user ID
 */
export function setSafeUserId(userId: string): boolean {
  return safeSetItem(LOCAL_USER_KEY, userId);
}

/**
 * Hook لإدارة معرف المستخدم
 * Hook to manage user ID
 */
export function useSafeUserId(): [string | null, (id: string) => void, boolean] {
  const [userId, setUserId, mounted] = useSafeLocalStorage<string | null>(
    LOCAL_USER_KEY,
    null
  );

  return [userId, setUserId, mounted];
}

// ==================== Auth Token Management ====================

const AUTH_TOKEN_KEY = 'authToken';

/**
 * الحصول على رمز المصادقة بشكل آمن
 * DEPRECATED: Token is now stored in httpOnly cookie, not accessible from JavaScript
 * This function is kept for backward compatibility but returns null
 * Safely get auth token
 */
export function getSafeAuthToken(): string | null {
  // Token is in httpOnly cookie - not accessible from JavaScript
  // Return null to indicate token should be read from cookie by server
  if (process.env.NODE_ENV === 'development') {
    console.warn('getSafeAuthToken is deprecated. Token is now in httpOnly cookie.');
  }
  return null;
}

/**
 * تعيين رمز المصادقة بشكل آمن
 * DEPRECATED: Token is now stored in httpOnly cookie by server, not in localStorage
 * This function is kept for backward compatibility but does nothing
 * Safely set auth token
 */
export function setSafeAuthToken(token: string): boolean {
  // Token should not be saved to localStorage for security
  // Only kept for backward compatibility
  if (process.env.NODE_ENV === 'development') {
    console.warn('setSafeAuthToken is deprecated. Token is now in httpOnly cookie.');
  }
  // Don't actually save - token is in cookie
  return false;
}

/**
 * حذف رمز المصادقة بشكل آمن
 * Safely remove auth token (for cleanup of legacy tokens)
 */
export function removeSafeAuthToken(): boolean {
  // Clean up any legacy tokens from localStorage
  return safeRemoveItem(AUTH_TOKEN_KEY);
}

/**
 * Hook لإدارة رمز المصادقة
 * DEPRECATED: Token is now in httpOnly cookie, not accessible from JavaScript
 * This hook is kept for backward compatibility but always returns null
 * Hook to manage auth token
 */
export function useSafeAuthToken(): [string | null, (token: string) => void, () => void, boolean] {
  // Token is in httpOnly cookie - not accessible from JavaScript
  // Always return null for token
  const removeToken = useCallback(() => {
    // Clean up any legacy tokens from localStorage
    removeSafeAuthToken();
  }, []);

  return [null, () => { }, removeToken, true];
}

// ==================== Safe Fetch & JSON Parsing ====================

/**
 * التحقق من أن الاستجابة هي JSON وليست HTML
 * Check if response is JSON and not HTML
 */
function isJsonResponse(response: Response): boolean {
  const contentType = response.headers.get('content-type');
  return contentType?.includes('application/json') ?? false;
}

/**
 * التحقق من أن النص هو HTML وليس JSON
 */
function isHtmlContent(text: string): boolean {
  const trimmed = text.trim();
  return (
    trimmed.startsWith('<!DOCTYPE') ||
    trimmed.startsWith('<!doctype') ||
    trimmed.startsWith('<html') ||
    trimmed.startsWith('<HTML') ||
    trimmed.startsWith('<Html') ||
    (trimmed.startsWith('<') && trimmed.includes('<head') || trimmed.includes('<body'))
  );
}

export async function safeJsonParse<T = any>(
  response: Response,
  fallback: T | null = null
): Promise<T | null> {
  try {
    // قراءة النص أولاً للتحقق من نوع المحتوى
    // نستخدم clone() إذا كان response مستهلكاً بالفعل
    let text: string;
    try {
      text = await response.text();
    } catch (textError) {
      // إذا فشل قراءة النص (مثلاً إذا تم استهلاك response بالفعل)
      if (process.env.NODE_ENV === 'development') {
        logger.warn('[Development] Failed to read response text:', textError);
      }
      return fallback;
    }

    // التحقق من أن النص غير فارغ
    if (!text || text.trim().length === 0) {
      return fallback;
    }

    // إذا كان HTML، يعني أن هناك خطأ في الخادم (مثل صفحة خطأ Next.js)
    if (isHtmlContent(text)) {
      // فقط في وضع التطوير نُظهر الخطأ التفصيلي
      if (process.env.NODE_ENV === 'development') {
        const url = response.url || 'Unknown URL';
        logger.warn(
          `[Development] Server returned HTML error page instead of JSON:`,
          {
            status: response.status,
            statusText: response.statusText,
            url: url,
            preview: text.substring(0, 200)
          }
        );
      }
      return fallback;
    }

    // التحقق من أن الاستجابة ناجحة وأن المحتوى هو JSON
    if (!response.ok) {
      // محاولة تحليل JSON حتى لو كانت الاستجابة غير ناجحة
      // (بعض APIs ترجع JSON حتى في حالة الخطأ)
      try {
        return JSON.parse(text) as T;
      } catch (parseError) {
        // إذا فشل تحليل JSON، رجوع للـ fallback
        if (process.env.NODE_ENV === 'development') {
          logger.warn(
            `[Development] Failed to parse error response as JSON:`,
            {
              status: response.status,
              statusText: response.statusText,
              preview: text.substring(0, 200),
              error: parseError
            }
          );
        }
        return fallback;
      }
    }

    // محاولة تحليل JSON من النص
    try {
      return JSON.parse(text) as T;
    } catch (parseError) {
      // فقط في وضع التطوير نُظهر تفاصيل الخطأ
      if (process.env.NODE_ENV === 'development') {
        logger.warn(
          `[Development] Failed to parse response as JSON:`,
          {
            error: parseError,
            preview: text.substring(0, 200),
            contentType: response.headers.get('content-type')
          }
        );
      }
      return fallback;
    }
  } catch (error) {
    // فقط في وضع التطوير نُظهر تفاصيل الخطأ
    if (process.env.NODE_ENV === 'development') {
      logger.error('[Development] Error parsing JSON response:', error);
    }
    return fallback;
  }
}

/**
 * استدعاء fetch مع معالجة آمنة للأخطاء والـ JSON
 * Safe fetch with error handling and JSON parsing
 */
export async function safeFetch<T = any>(
  url: string,
  options?: RequestInit,
  fallback: T | null = null
): Promise<{ data: T | null; error: Error | null; response: Response | null }> {
  try {
    const response = await fetch(url, options);

    // استخدام safeJsonParse الذي يتعامل مع HTML و JSON بشكل آمن
    const data = await safeJsonParse<T>(response, fallback);

    // إذا كانت الاستجابة غير ناجحة
    if (!response.ok) {
      // إذا كان data هو fallback (يعني أن الـ response لم تكن JSON صالحة)
      // يجب التحقق من ذلك أولاً قبل محاولة استخراج رسالة الخطأ
      const isFallback = data === fallback;

      if (isFallback) {
        const errorMessage = `HTTP ${response.status}: ${response.statusText} - Server returned non-JSON response`;
        return {
          data: fallback,
          error: new Error(errorMessage),
          response
        };
      }

      // محاولة استخراج رسالة خطأ من البيانات إذا كانت موجودة
      let errorMessage: string = `HTTP ${response.status}: ${response.statusText}`;

      try {
        if (data && typeof data === 'object' && data !== null) {
          // محاولة استخراج رسالة الخطأ من الـ response
          if ('error' in data && typeof data.error === 'string') {
            errorMessage = data.error;
          } else if ('message' in data && typeof data.message === 'string') {
            errorMessage = data.message;
          } else if ('details' in data && typeof data.details === 'string') {
            errorMessage = `${errorMessage} - ${data.details}`;
          }
        }
      } catch (extractError) {
        // في حالة فشل استخراج رسالة الخطأ، نستخدم الرسالة الافتراضية
        if (process.env.NODE_ENV === 'development') {
          logger.warn('[Development] Failed to extract error message:', extractError);
        }
      }

      // التأكد من أن errorMessage ليس فارغاً أو undefined
      if (!errorMessage || typeof errorMessage !== 'string' || errorMessage.trim().length === 0) {
        errorMessage = `HTTP ${response.status}: ${response.statusText}`;
      }

      // إذا كان data ليس fallback، يعني أننا حصلنا على JSON (حتى لو كانت error response)
      const error = new Error(errorMessage);
      // فقط في وضع التطوير نعرض الخطأ في console
      if (process.env.NODE_ENV === 'development') {
        logger.warn(`[Development] API Error (${url}):`, {
          status: response.status,
          statusText: response.statusText,
          error: errorMessage,
          data: data
        });
      }

      return {
        data,
        error,
        response
      };
    }

    return { data, error: null, response };
  } catch (error) {
    // فقط في وضع التطوير نُظهر تفاصيل الخطأ
    if (process.env.NODE_ENV === 'development') {
      logger.error('[Development] Fetch error:', error);
    }
    return {
      data: fallback,
      error: error instanceof Error ? error : new Error('Unknown fetch error'),
      response: null
    };
  }
}

// ==================== Export All ====================

const safeClientUtils = {
  // Storage checks
  isLocalStorageAvailable,
  isSessionStorageAvailable,

  // Storage operations
  safeGetItem,
  safeSetItem,
  safeRemoveItem,
  safeClearStorage,

  // React hooks
  useSafeLocalStorage,
  useSafeSessionStorage,
  useIsMounted,
  useWindowSize,
  useSafeMediaQuery,
  useSafeEventListener,

  // Browser checks
  isBrowser,
  safeWindow,
  safeDocument,

  // User ID management
  getSafeUserId,
  setSafeUserId,
  useSafeUserId,

  // Auth token management
  getSafeAuthToken,
  setSafeAuthToken,
  removeSafeAuthToken,
  useSafeAuthToken,

  // Safe fetch & JSON
  safeJsonParse,
  safeFetch,
};

export default safeClientUtils;

// Import prisma singleton to prevent multiple connection pools
// This uses the unified singleton instance from db.ts
import { prisma } from './db';
import { DeviceInfo, SecurityMetadata } from '@/types/services';

// Lazy load elkLogger to prevent client bundling of server-only code
let elkLoggerInstance: any = null;

async function getElkLogger() {
  if (!elkLoggerInstance) {
    if (typeof window !== 'undefined') {
      // Return a no-op logger on client side
      return {
        error: () => { },
        warn: () => { },
        info: () => { },
        debug: () => { },
      };
    }
    const elkLoggerModule = await import('@/lib/logging/elk-logger');
    elkLoggerInstance = elkLoggerModule.elkLoggerHelper;
  }
  return elkLoggerInstance;
}

export type SecurityEventType =
  | 'LOGIN_SUCCESS'
  | 'LOGIN_FAILED'
  | 'LOGIN_ATTEMPT_BLOCKED'
  | 'LOGOUT'
  | 'LOGOUT_ALL'
  | 'PASSWORD_CHANGED'
  | 'PASSWORD_RESET_REQUESTED'
  | 'PASSWORD_RESET_COMPLETED'
  | 'EMAIL_VERIFIED'
  | 'EMAIL_VERIFICATION_SENT'
  | 'TWO_FACTOR_ENABLED'
  | 'TWO_FACTOR_DISABLED'
  | 'TWO_FACTOR_SETUP'
  | 'TWO_FACTOR_REQUESTED'
  | 'TWO_FACTOR_SUCCESS'
  | 'TWO_FACTOR_FAILED'
  | 'RECOVERY_CODES_REGENERATED'
  | 'BIOMETRIC_ENABLED'
  | 'BIOMETRIC_DISABLED'
  | 'BIOMETRIC_LOGIN_SUCCESS'
  | 'BIOMETRIC_LOGIN_FAILED'
  | 'SESSION_CREATED'
  | 'SESSION_REVOKED'
  | 'SESSION_EXPIRED'
  | 'SUSPICIOUS_ACTIVITY_DETECTED'
  | 'ACCOUNT_LOCKED'
  | 'ACCOUNT_UNLOCKED'
  | 'IP_WHITELIST_ADDED'
  | 'IP_WHITELIST_REMOVED'
  | 'SECURITY_SETTINGS_CHANGED'
  | 'MAGIC_LINK_SENT'
  | 'MAGIC_LINK_USED';

export interface SecurityLogData {
  userId: string | null;
  eventType: SecurityEventType;
  ip: string;
  userAgent: string;
  deviceInfo?: DeviceInfo;
  location?: string | null;
  metadata?: SecurityMetadata;
}

/**
 * خدمة تسجيل الأحداث الأمنية
 */
export class SecurityLogger {
  private static instance: SecurityLogger;

  private constructor() { }

  public static getInstance(): SecurityLogger {
    if (!SecurityLogger.instance) {
      SecurityLogger.instance = new SecurityLogger();
    }
    return SecurityLogger.instance;
  }

  /**
   * تسجيل حدث أمني
   */
