// Whitelist of allowed template keys for security
const ALLOWED_TEMPLATE_KEYS: ReadonlySet<keyof typeof notificationTemplates> = new Set([
  'taskDueSoon',
  'taskOverdue',
  'taskCompleted',
  'testGenerated',
  'testCompleted',
  'testReminder',
  'scheduleConflict',
  'classReminder',
  'progressMilestone',
  'goalAchieved',
  'newMessage',
  'eventReminder',
  'newFollower',
  'systemUpdate',
  'securityAlert',
  'newContent',
  'contentRecommendation',
] as const);

// دالة لإرسال إشعار باستخدام القوالب
export function sendTemplatedNotification(
  templateKey: keyof typeof notificationTemplates,
  ...args: unknown[]
) {
  // Security: Validate templateKey against whitelist before accessing object
  if (!ALLOWED_TEMPLATE_KEYS.has(templateKey)) {
    logger.error('Invalid template key attempted', undefined, { templateKey });
    return Promise.resolve({ success: false, error: 'Invalid template key' });
  }

  const template = notificationTemplates[templateKey];
  if (!template) {
    logger.error('Template not found', undefined, { templateKey });
    return Promise.resolve({ success: false, error: 'Template not found' });
  }

  // Type-safe dynamic function call
  const notification = (template as (...args: unknown[]) => ReturnType<typeof template>)(...args);
  
  // Safely extract optional properties
  const options: { actionUrl?: string; icon?: string } = {};
  if ('actionUrl' in notification && notification.actionUrl) {
    options.actionUrl = notification.actionUrl;
  }
  if ('icon' in notification && notification.icon) {
    options.icon = notification.icon;
  }
  
  return sendNotification(notification.title, notification.message, notification.type, options);
}

import { RedisClientType } from 'redis';
import { redis, RedisClient } from '../redis';

import { logger } from '@/lib/logger';
import { RateLimitConfig, RateLimitResult, RateLimitService } from '@/types/services';

export class RateLimitingService implements RateLimitService {
  private redisClient: RedisClient;
  private defaultConfig: RateLimitConfig;

  constructor(
    redisClient: RedisClient,
    defaultConfig: RateLimitConfig = {
      windowMs: 10 * 60 * 1000, // 10 minutes (stricter)
      maxAttempts: 3, // Reduced from 5 for better security
      lockoutMs: 60 * 60 * 1000 // 60 minutes (progressive lockout)
    }
  ) {
    this.redisClient = redisClient;
    this.defaultConfig = defaultConfig;
  }

  /**
   * Check if a client has exceeded rate limits
   * @param clientId Unique identifier for the client (e.g., IP + User Agent)
   * @param config Rate limiting configuration
   * @returns RateLimitResult indicating if the request is allowed
   */
  async checkRateLimit(clientId: string, config: RateLimitConfig = this.defaultConfig): Promise<RateLimitResult> {
    // Validate inputs
    if (!clientId || typeof clientId !== 'string' || clientId.trim().length === 0) {
      // logger.warn('Invalid clientId provided to checkRateLimit');
      return { allowed: true, attempts: 0 };
    }

    if (!config || typeof config !== 'object') {
      // logger.warn('Invalid config provided to checkRateLimit, using default');
      config = this.defaultConfig;
    }

    // Fail open if Redis client is not available
    if (!this.redisClient) {
      return { allowed: true, attempts: 0 };
    }

    // Validate config values
    const validWindowMs = Math.max(1000, Math.min(config.windowMs || this.defaultConfig.windowMs, 3600000)); // 1s to 1h
    const validMaxAttempts = Math.max(1, Math.min(config.maxAttempts || this.defaultConfig.maxAttempts, 1000)); // 1 to 1000
    const validLockoutMs = config.lockoutMs ? Math.max(1000, Math.min(config.lockoutMs, 86400000)) : undefined; // 1s to 24h

    const trimmedClientId = clientId.trim().slice(0, 200); // Limit length
    const key = `rate_limit:${trimmedClientId}`;
    const lockoutKey = `lockout:${trimmedClientId}`;

    const now = Date.now();
    const windowStart = now - validWindowMs;

    try {
      // Check if account is locked with timeout
      const getLockPromise = this.redisClient.get(lockoutKey);
      const lockTimeoutPromise = new Promise<string | null>((resolve) => {
        setTimeout(() => resolve(null), 1000); // 1 second timeout
      });

      const lockedUntil = await Promise.race([getLockPromise, lockTimeoutPromise]);
      if (lockedUntil) {
        const lockoutTime = parseInt(lockedUntil, 10);
        if (!isNaN(lockoutTime) && now < lockoutTime) {
          const remainingTime = Math.ceil((lockoutTime - now) / 60000); // in minutes
          return {
            allowed: false,
            attempts: validMaxAttempts,
            remainingTime,
            lockedUntil: lockoutTime
          };
        } else {
          // Lockout expired, remove the lockout key (non-blocking)
          this.redisClient.del(lockoutKey).catch(() => { });
        }
      }

      // Use Redis pipeline for atomic operations with timeout
      const pipeline = this.redisClient.multi();

      // Remove old entries outside the window
      pipeline.zremrangebyscore(key, 0, windowStart);

      // Get current count
      pipeline.zcard(key);

      const execPromise = pipeline.exec();
      const execTimeoutPromise = new Promise<never>((resolve, reject) => {
        setTimeout(() => {
          reject(new Error('Redis pipeline timeout'));
        }, 1500); // 1.5 second timeout
      });

      const results = await Promise.race([execPromise, execTimeoutPromise]);
      const currentCount = (results && results[1] && typeof results[1] === 'number') ? results[1] : 0;

      return {
        allowed: currentCount < validMaxAttempts,
        attempts: currentCount,
        remainingTime: undefined
      };
    } catch (error) {
      // Only log critical Redis errors, ignore timeouts/connection issues to reduce noise
      const errorMessage = error instanceof Error ? error.message : String(error);
      if (!errorMessage.includes('timeout') && !errorMessage.includes('connection')) {
        logger.warn('Rate limiting check failed (failing open):', errorMessage);
      }

      // Fail open - don't block requests if rate limiting fails
      return {
        allowed: true,
        attempts: 0
      };
    }
  }

  /**
   * Record a failed attempt and update rate limiting data
   * @param clientId Unique identifier for the client
   * @param config Rate limiting configuration
   */
  async recordFailedAttempt(clientId: string, config: RateLimitConfig = this.defaultConfig): Promise<void> {
    // Validate inputs
    if (!clientId || typeof clientId !== 'string' || clientId.trim().length === 0) {
      return;
    }

    // Fail silently if Redis client is not available
    if (!this.redisClient) {
      return;
    }

    if (!config || typeof config !== 'object') {
      config = this.defaultConfig;
    }

    // Validate config values
    const validWindowMs = Math.max(1000, Math.min(config.windowMs || this.defaultConfig.windowMs, 3600000)); // 1s to 1h
    const validMaxAttempts = Math.max(1, Math.min(config.maxAttempts || this.defaultConfig.maxAttempts, 1000)); // 1 to 1000
    const validLockoutMs = config.lockoutMs ? Math.max(1000, Math.min(config.lockoutMs, 86400000)) : undefined; // 1s to 24h

    const trimmedClientId = clientId.trim().slice(0, 200); // Limit length
    const key = `rate_limit:${trimmedClientId}`;
    const lockoutKey = `lockout:${trimmedClientId}`;

    const now = Date.now();

    try {
      // Use Redis pipeline for atomic operations with timeout
      const pipeline = this.redisClient.multi();

      // Add current attempt
      pipeline.zadd(key, { [now]: now.toString() });

      // Set expiration for the sorted set
      pipeline.expire(key, Math.ceil(validWindowMs / 1000));

      const execPromise = pipeline.exec();
      const execTimeoutPromise = new Promise<never>((resolve, reject) => {
        setTimeout(() => {
          reject(new Error('Redis pipeline timeout'));
        }, 1500); // 1.5 second timeout
      });

      await Promise.race([execPromise, execTimeoutPromise]);

      // Check if we need to lock the account (non-blocking)
      // We don't await this to avoid blocking the response
      this.checkRateLimit(trimmedClientId, { ...config, windowMs: validWindowMs, maxAttempts: validMaxAttempts, lockoutMs: validLockoutMs })
        .then((result) => {
          if (result.attempts >= validMaxAttempts && validLockoutMs) {
            // Lock the account with timeout
            const lockoutUntil = now + validLockoutMs;
            const setExPromise = this.redisClient.setEx(lockoutKey, Math.ceil(validLockoutMs / 1000), lockoutUntil.toString());
            // Fire and forget with error catching
            setExPromise.catch(() => { });
          }
        })
        .catch(() => { });
    } catch (error) {
      // Silent fail for recording attempts
    }
  }

  /**
   * Increment failed attempts for a client (alias for recordFailedAttempt)
   * @param clientId Unique identifier for the client
   * @param config Rate limiting configuration
   */
  async incrementAttempts(clientId: string, config: RateLimitConfig = this.defaultConfig): Promise<void> {
    return this.recordFailedAttempt(clientId, config);
  }

  /**
   * Reset rate limiting for a client after successful authentication
   * @param clientId Unique identifier for the client
   */
  async resetAttempts(clientId: string): Promise<void> {
    // Validate input
    if (!clientId || typeof clientId !== 'string' || clientId.trim().length === 0) {
      return;
    }

    if (!this.redisClient) {
      return;
    }

    const trimmedClientId = clientId.trim().slice(0, 200); // Limit length
    const key = `rate_limit:${trimmedClientId}`;
    const lockoutKey = `lockout:${trimmedClientId}`;

    try {
      // Add timeout protection
      const delPromise = this.redisClient.del(key, lockoutKey);
      const timeoutPromise = new Promise<void>((resolve) => {
        setTimeout(() => resolve(), 1500); // 1.5 second timeout
      });

      await Promise.race([delPromise, timeoutPromise]);
    } catch (error) {
      // Silent fail
    }
  }

  /**
   * Reset rate limiting for a client after successful authentication (alias for resetAttempts)
   * @param clientId Unique identifier for the client
   */
  async resetRateLimit(clientId: string): Promise<void> {
    return this.resetAttempts(clientId);
  }

  /**
   * Get current rate limiting status for a client
   * @param clientId Unique identifier for the client
   * @param config Rate limiting configuration
   * @returns Current rate limiting status
   */
  async getRateLimitStatus(clientId: string, config: RateLimitConfig = this.defaultConfig): Promise<RateLimitResult> {
    return this.checkRateLimit(clientId, config);
  }
}

// Create and export a default instance
export const rateLimitingService = new RateLimitingService(redis);

export default rateLimitingService;

import { logger } from '@/lib/logger';
import { authService } from '@/lib/services/auth-service';
import { captchaService } from '@/lib/security/captcha-service';
import { createCaptchaRequiredResponse } from '@/app/api/auth/_helpers';
import type { LoginResult } from '@/lib/services/login-service';
import type { LoginErrorResponse } from '@/types/api/auth';
import type { RateLimitService, RateLimitResult } from '@/types/services';

export interface RateLimitConfig {
    windowMs: number;
    maxAttempts: number;
    lockoutMs: number;
}

export class SecurityCheckService {
    /**
     * Initialize rate limiting service
     */
    static async initializeRateLimitService(clientId: string): Promise<{
        rateLimitService: RateLimitService | null;
        rateLimitStatus: RateLimitResult;
    }> {
        if (!clientId) {
            return {
                rateLimitService: null,
                rateLimitStatus: { allowed: true, attempts: 0 },
            };
        }

        try {
            // Add timeout to prevent hanging on Redis connection
            const timeoutPromise = new Promise<{ rateLimitService: RateLimitService | null; rateLimitStatus: RateLimitResult }>((resolve) => {
                setTimeout(() => {
                    resolve({
                        rateLimitService: null,
                        rateLimitStatus: { allowed: true, attempts: 0 },
                    });
                }, 500); // 500ms timeout - faster fallback when Redis unavailable
            });

            const initPromise = (async () => {
                const { RateLimitingService } = await import('@/lib/services/rate-limiting-service');
                const { getRedisClient } = await import('@/lib/redis');

                const redis = await getRedisClient();
                const rateLimitService = new RateLimitingService(redis);
                const rateLimitStatus = await rateLimitService.checkRateLimit(clientId);

                return { rateLimitService, rateLimitStatus };
            })();

            return await Promise.race([initPromise, timeoutPromise]);
        } catch (redisError) {
            logger.warn('Redis unavailable, proceeding without rate limiting:', redisError);
            return {
                rateLimitService: null,
                rateLimitStatus: { allowed: true, attempts: 0 },
            };
        }
    }

    /**
     * Check IP blocking
     */
    static async checkIPBlocking(ip: string): Promise<LoginResult | null> {
        try {
            const { ipBlockingService } = await import('@/lib/security/ip-blocking');
            const ipBlockStatus = ipBlockingService.isBlocked(ip);

            if (ipBlockStatus.blocked) {
                await authService.logSecurityEvent(null, 'login_blocked_ip', ip, {
                    reason: ipBlockStatus.reason,
                    blockedUntil: ipBlockStatus.blockedUntil?.toISOString(),
                });

                return {
                    success: false,
                    response: {
                        error: `تم حظر عنوان IP هذا بسبب محاولات غير مصرح بها. السبب: ${ipBlockStatus.reason}`,
                        code: 'IP_BLOCKED',
                        blockedUntil: ipBlockStatus.blockedUntil?.toISOString(),
                    },
                    statusCode: 403,
                };
            }
        } catch (ipBlockError) {
            // Enhanced error logging with context
            logger.warn('IP blocking check failed', {
                ip: ip.substring(0, 10) + '***', // Partially mask IP for privacy
                error: ipBlockError instanceof Error ? ipBlockError.message : 'Unknown error',
                stack: process.env.NODE_ENV === 'development' && ipBlockError instanceof Error
                    ? ipBlockError.stack
                    : undefined,
            });
            // Fail open - don't block login if IP check fails
        }

        return null;
    }

    /**
     * Check rate limiting
     */
    static async checkRateLimiting(
        rateLimitStatus: RateLimitResult,
        ip: string,
        userAgent: string
    ): Promise<LoginResult | null> {
        if (!rateLimitStatus.allowed) {
            const now = Date.now();
            const lockoutUntil = rateLimitStatus.lockedUntil ?? 0;
            const retryMs = lockoutUntil > now
                ? lockoutUntil - now
                : (rateLimitStatus.remainingTime ?? 0) * 60 * 1000;
            const retryAfterSeconds = Math.max(1, Math.ceil((retryMs || 60000) / 1000));

            // Record suspicious IP activity
            try {
                const { ipBlockingService } = await import('@/lib/security/ip-blocking');
                ipBlockingService.recordFailedAttempt(ip, 'Rate limit exceeded');
            } catch (ipBlockError) {
                // Ignore IP blocking errors
            }

            await authService.logSecurityEvent(null, 'login_rate_limited', ip, {
                userAgent,
                attempts: rateLimitStatus.attempts,
                retryAfterSeconds,
                lockedUntil: lockoutUntil ? new Date(lockoutUntil).toISOString() : undefined,
            });

            return {
                success: false,
                response: {
                    error: 'تم تعليق محاولات تسجيل الدخول مؤقتاً بسبب محاولات متكررة. يمكنك المحاولة مرة أخرى بعد انتهاء العد التنازلي.',
                    code: 'RATE_LIMITED',
                    retryAfterSeconds,
                    lockedUntil: lockoutUntil ? new Date(lockoutUntil).toISOString() : undefined,
                    attempts: rateLimitStatus.attempts,
                },
                statusCode: 429,
            };
        }

        return null;
    }

    /**
     * Check CAPTCHA requirement and verify
     */
    static async checkCaptcha(
        currentAttempts: number,
        captchaToken: string | undefined,
        ip: string,
        email: string
    ): Promise<LoginResult | null> {
        if (captchaService.shouldRequireCaptcha(currentAttempts)) {
            if (!captchaToken) {
                return {
                    success: false,
                    response: {
                        error: 'يرجى إكمال التحقق من CAPTCHA للمتابعة. تم اكتشاف محاولات تسجيل دخول متكررة.',
                        requiresCaptcha: true,
                        failedAttempts: currentAttempts,
                        code: 'CAPTCHA_REQUIRED',
                    },
                    statusCode: 403,
                };
            }

            // Verify CAPTCHA token
            const isValidCaptcha = await captchaService.verifyCaptcha(captchaToken, ip);
            if (!isValidCaptcha) {
                await authService.logSecurityEvent(null, 'captcha_verification_failed', ip, {
                    email,
                });

                return {
                    success: false,
                    response: {
                        error: 'فشل التحقق من CAPTCHA. يرجى المحاولة مرة أخرى.',
                        requiresCaptcha: true,
                        failedAttempts: currentAttempts,
                        code: 'CAPTCHA_INVALID',
                    },
                    statusCode: 403,
                };
            }
        }

        return null;
    }

    /**
     * Get updated failed attempts count
     */
    static async getUpdatedAttempts(
        rateLimitService: RateLimitService | null,
        clientId: string
    ): Promise<number> {
        if (!rateLimitService || !clientId) {
            return 1;
        }

        try {
            // Add timeout to prevent hanging
            const timeoutPromise = new Promise<number>((resolve) => {
                setTimeout(() => resolve(1), 500); // 500ms timeout - faster response
            });

            const rateLimitPromise = rateLimitService.checkRateLimit(clientId)
                .then((status: RateLimitResult) => (status?.attempts || 0) + 1)
                .catch(() => 1);

            const attempts = await Promise.race([rateLimitPromise, timeoutPromise]);
            return attempts;
        } catch (redisError) {
            logger.warn('Redis unavailable for rate limit check:', redisError);
            return 1;
        }
    }

    /**
     * Handle failed login attempt
     */
    static async handleFailedLogin(
        clientId: string,
        userId: string | null,
        ip: string,
        userAgent: string,
        reason: string,
        email: string,
        rateLimitService: RateLimitService | null
    ): Promise<LoginResult> {
        // Execute security operations in parallel for better performance
        const securityOperations = Promise.allSettled([
            // Record failed attempt (non-blocking)
            authService.recordFailedAttempt(clientId).catch((err) => {
                logger.warn('Failed to record failed attempt:', err);
            }),

            // Record IP-based failed attempt (non-blocking)
            import('@/lib/security/ip-blocking')
                .then(({ ipBlockingService }) =>
                    ipBlockingService.recordFailedAttempt(ip, `Failed login: ${reason}`)
                )
                .catch((ipBlockError) => {
                    // Ignore IP blocking errors silently
                    if (process.env.NODE_ENV === 'development') {
                        logger.debug('IP blocking service unavailable:', ipBlockError);
                    }
                }),

            // Log security event (non-blocking)
            authService.logSecurityEvent(userId, 'login_failed', ip, {
                userAgent,
                reason,
                email: userId ? undefined : email,
            }).catch((logError) => {
                logger.warn('Failed to log security event:', logError);
            }),
        ]);

        // Don't wait for security operations to complete
        securityOperations.catch(() => {
            // Silent fail - security logging shouldn't block login response
        });

        // Get updated failed attempts count (with timeout)
        const updatedAttempts = await this.getUpdatedAttempts(rateLimitService, clientId);

        // Require CAPTCHA after threshold failed attempts
        if (captchaService.shouldRequireCaptcha(updatedAttempts)) {
            const captchaResponse = createCaptchaRequiredResponse(updatedAttempts, 401);
            // Extract the JSON body from NextResponse
            const responseBody = await captchaResponse.json();
            return {
                success: false,
                response: responseBody as LoginErrorResponse,
                statusCode: 401,
            };
        }

        return {
            success: false,
            response: {
                error: 'بيانات تسجيل الدخول غير صحيحة.',
                code: 'INVALID_CREDENTIALS',
            },
            statusCode: 401,
        };
    }
}

