import { authService } from '@/lib/services/auth-service';
import { prisma } from '@/lib/db';
import { Session } from '@prisma/client';
import { logger } from '@/lib/logger';
import type { LoginResult } from '@/lib/services/login-service';
import type { LoginResponse, User, RiskAssessment } from '@/types/api/auth';
import { LOGIN_ERRORS } from '@/lib/auth/login-errors';
import { securityLogger, SecurityEventType } from '@/lib/security-logger';
import { v4 as uuidv4 } from 'uuid';

/**
 * Create successful login response
 */
const createLoginSuccessResponse = (
    user: User,
    accessToken: string,
    refreshToken: string,
    sessionId: string,
    riskAssessment: RiskAssessment,
    isNewDevice: boolean,
    accountWasCreated?: boolean
): LoginResponse => {
    return {
        message: accountWasCreated
            ? 'تم إنشاء الحساب وتسجيل الدخول بنجاح!'
            : 'تم تسجيل الدخول بنجاح.',
        token: accessToken,
        refreshToken,
        sessionId,
        user: {
            id: user.id,
            email: user.email,
            name: user.name || undefined,
            role: user.role || 'user',
            emailVerified: user.emailVerified || false,
            twoFactorEnabled: user.twoFactorEnabled || false,
            lastLogin: user.lastLogin
                ? (typeof user.lastLogin === 'string'
                    ? user.lastLogin
                    : user.lastLogin.toISOString())
                : undefined,
        },
        riskAssessment: {
            level: riskAssessment.level,
            score: riskAssessment.score || 0,
        },
        isNewDevice: isNewDevice || false,
        accountWasCreated: accountWasCreated || false,
    };
};

export class TokenService {

    /**
     * Generate access and refresh tokens
     */
    private static async createTokens(payload: any, sessionId?: string): Promise<{ accessToken: string; refreshToken: string }> {
        const tokenPayload = { ...payload, sessionId };

        const accessToken = await authService.generateToken(tokenPayload, '15m');
        const refreshToken = await authService.generateToken(tokenPayload, '7d');

        return { accessToken, refreshToken };
    }

    /**
     * Create a new session in DB
     */
    private static async createSession(userId: string, userAgent: string, ip: string, refreshToken: string, deviceInfo: string): Promise<Session> {
        return await prisma.session.create({
            data: {
                id: uuidv4(),
                userId,
                refreshToken: refreshToken,
                expiresAt: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000), // 7 days
                ip,
                userAgent,
                deviceInfo: deviceInfo || null,
                isActive: true,
                lastAccessed: new Date(),
            }
        });
    }

    /**
     * Complete successful login
     * Improved with better error handling and parallel operations
     */
    static async completeLogin(
        user: User,
        userAgent: string,
        ip: string,
        riskAssessment: RiskAssessment,
        isNewDevice: boolean,
        accountWasCreated: boolean,
        clientId: string
    ): Promise<LoginResult> {
        // Validate user data before proceeding
        if (!user || !user.id || !user.email) {
            logger.error('Invalid user data in completeLogin');
            throw new Error('Invalid user data');
        }

        // Reset rate limit on successful login
        // Assuming rate limits are stored in Redis or DB. 
        // For now, we skip explicit reset if we don't have direct access to RateLimitService here.
        // Or we can import it if available. 

        // Generate tokens first to get a refresh token
        let tempRefreshToken: string;
        try {
            const tokens = await this.createTokens({
                userId: user.id,
                email: user.email,
                role: user.role,
            });
            tempRefreshToken = tokens.refreshToken;
        } catch (tokenError) {
            logger.error('Failed to generate temp tokens:', tokenError);
            throw new Error(LOGIN_ERRORS.TOKEN_GENERATION_FAILED);
        }

        // Create session with timeout protection
        let session;
        try {
            const deviceInfo = riskAssessment?.deviceFingerprint
                ? JSON.stringify(riskAssessment.deviceFingerprint)
                : '{}';

            // We need to match the actual Session schema.
            // Using a safe create approach.
            const sessionPromise = this.createSession(user.id, userAgent, ip, tempRefreshToken, deviceInfo);

            const timeoutPromise = new Promise<Session>((resolve, reject) => {
                setTimeout(() => reject(new Error('Session creation timeout')), 5000);
            });

            session = await Promise.race([sessionPromise, timeoutPromise]);
        } catch (sessionError) {
            logger.error('Failed to create session:', sessionError);
            throw new Error(LOGIN_ERRORS.SESSION_CREATION_FAILED);
        }

        if (!session || !session.id) {
            logger.error('Invalid session created');
            throw new Error(LOGIN_ERRORS.SESSION_CREATION_FAILED);
        }

        // Generate final tokens with sessionId
        let accessToken: string;
        let refreshToken: string;
        try {
            const tokens = await this.createTokens(
                {
                    userId: user.id,
                    email: user.email,
                    role: user.role,
                },
                session.id,
            );
            accessToken = tokens.accessToken;
            refreshToken = tokens.refreshToken;
        } catch (tokenError) {
            logger.error('Failed to generate tokens:', tokenError);
            throw new Error(LOGIN_ERRORS.TOKEN_GENERATION_FAILED);
        }

        // Update session with final refresh token
        try {
            await prisma.session.update({
                where: { id: session.id },
                data: { refreshToken: refreshToken }
            });
        } catch (updateError) {
            logger.warn('Failed to update session with final refresh token:', updateError);
        }

        // Update user with last login
        prisma.user.update({
            where: { id: user.id },
            data: {
                lastLogin: new Date(), // Check if schema has this common field. Schema says yes.
            }
        }).catch(() => { });

        // Log successful login
        securityLogger.logEvent({
            userId: user.id,
            eventType: 'LOGIN_SUCCESS' as SecurityEventType,
            ip,
            userAgent,
            metadata: {
                sessionId: session.id,
                riskLevel: riskAssessment.level,
                isNewDevice,
            }
        }).catch((logError) => {
            logger.warn('Failed to log security event:', logError);
        });

        return {
            success: true,
            response: createLoginSuccessResponse(
                user,
                accessToken,
                refreshToken,
                session.id,
                riskAssessment,
                isNewDevice,
                accountWasCreated
            ),
            statusCode: 200,
        };
    }
}

'use client';

import { logger } from '@/lib/logger';
import { safeRemoveItem } from '@/lib/safe-client-utils';

/**
 * Clear authentication state from local storage
 */
function clearAuthState(): void {
  safeRemoveItem('authToken');
  safeRemoveItem('user');
  safeRemoveItem('token');
  safeRemoveItem('refreshToken');
}

/**
 * تحديث التوكن تلقائياً
 * Note: Token is in httpOnly cookie, so we can't check expiration from client
 * We'll rely on the server to handle token refresh based on the cookie
 */
export async function refreshTokenIfNeeded(bufferMinutes: number = 5): Promise<string | null> {
  // Token is in httpOnly cookie - we can't read it from JavaScript
  // Just call the refresh endpoint and let the server handle it
  // The server will check the refresh_token cookie and update access_token cookie if needed

  try {
    const response = await fetch('/api/auth/refresh', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      credentials: 'include', // Important: include cookies for refresh
    });

    // التحقق من نوع المحتوى قبل تحليل JSON
    const contentType = response.headers.get('content-type');
    const isJson = contentType?.includes('application/json') ?? false;

    // قراءة النص أولاً للتحقق من نوع المحتوى
    const text = await response.text();

    // إذا كان HTML، يعني أن هناك خطأ في الخادم (مثل 404 أو 500 صفحة خطأ)
    if (text.trim().startsWith('<!DOCTYPE') || text.trim().startsWith('<html')) {
      // فقط في وضع التطوير نُظهر الخطأ التفصيلي
      if (process.env.NODE_ENV === 'development') {
        // Suppress HTML error logs unless explicitly debugging
        // logger.warn('[Development] Token refresh: Server returned HTML error page');
      }

      // If refresh failed, clear auth state
      clearAuthState();
      return null;
    }

    if (!response.ok) {
      // If refresh failed, clear auth state
      clearAuthState();

      // محاولة تحليل JSON للرسالة الخطأ
      if (isJson) {
        try {
          const errorData = JSON.parse(text);

          // Don't log error if it's just missing refresh token (expected when not logged in)
          if (
            errorData?.errorData?.error === 'REFRESH_TOKEN_MISSING' ||
            errorData?.error === 'REFRESH_TOKEN_MISSING' ||
            errorData?.code === 'REFRESH_TOKEN_MISSING'
          ) {
            // Just clear state and return null, no need to log as error
            clearAuthState();
            return null;
          }

          // Log other errors
          logger.warn('Token refresh failed:', {
            status: response.status,
            error: errorData?.error || 'Unknown error'
          });
        } catch {
          // لا بأس إذا فشل تحليل JSON
        }
      }

      return null;
    }

    // محاولة تحليل JSON من النص
    let data: { token?: string };
    try {
      data = JSON.parse(text);
    } catch (parseError) {
      // logger.error('Failed to parse token refresh response as JSON');
      return null;
    }

    // Token is updated in httpOnly cookie by server
    // Return success indicator (token is in cookie, not accessible from JS)
    if (data.token || response.ok) {
      return 'token_refreshed'; // Return indicator that refresh succeeded
    }

    return null;
  } catch (error) {
    // Network errors etc.
    // logger.error('Token refresh error:', error);
    clearAuthState();
    return null;
  }
}

/**
 * إعداد مراقب تلقائي لتحديث التوكن
 * يتحقق كل دقيقة من الحاجة للتحديث
 */
export function setupAutoTokenRefresh(
  onTokenRefreshed?: (token: string) => void,
  onRefreshFailed?: () => void,
  bufferMinutes: number = 5,
  checkIntervalMinutes: number = 4 // Increase interval to reduce load, server handles expiration
): () => void {
  let intervalId: NodeJS.Timeout | null = null;
  let isRefreshing = false;

  // دالة التنظيف - تعريفها أولاً كدالة مسماة لتجنب مشاكل الـ hoisting
  const cleanup = () => {
    if (intervalId) {
      clearInterval(intervalId);
      intervalId = null;
    }
  };

  // دالة التحقق والتحديث - استخدام arrow function لضمان الوصول الصحيح لـ cleanup
  const checkAndRefresh = async () => {
    // تجنب التحديث المتزامن
    if (isRefreshing) return;

    // Token is in httpOnly cookie - we can't check expiration from client
    // Just call refresh endpoint periodically and let server handle it
    // Server will check refresh_token cookie and update access_token cookie if needed
    isRefreshing = true;
    try {
      const result = await refreshTokenIfNeeded(bufferMinutes);
      if (result) {
        // Token was refreshed (in cookie)
        onTokenRefreshed?.('token_refreshed');
      } else {
        // Refresh failed - token might be expired
        onRefreshFailed?.();
        cleanup();
      }
    } catch (error) {
      logger.error('Auto refresh error:', error);
      onRefreshFailed?.();
      cleanup();
    } finally {
      isRefreshing = false;
    }
  };

  // التحقق الفوري
  checkAndRefresh();

  // إعداد المراقبة الدورية
  intervalId = setInterval(
    checkAndRefresh,
    checkIntervalMinutes * 60 * 1000
  );

  return cleanup;
}

/**
 * Interceptor للـ fetch API لتحديث التوكن تلقائياً قبل الطلبات
 * Note: Token is in httpOnly cookie, so we don't add Authorization header
 * The server will read the token from the cookie automatically
 */
export function createAuthFetchInterceptor() {
  const originalFetch = window.fetch;

  window.fetch = async (input: RequestInfo | URL, init?: RequestInit) => {
    // Ensure credentials are included for cookie-based auth
    if (!init) {
      init = { credentials: 'include' };
    } else if (!init.credentials) {
      init.credentials = 'include';
    }

    // إجراء الطلب الأصلي (لا حاجة لإضافة Authorization header - التوكن في cookie)
    let response = await originalFetch(input, init);

    // معالجة 401 Unauthorized - محاولة تحديث التوكن وإعادة الطلب
    if (response.status === 401) {
      // Token might be expired, try to refresh
      const refreshResult = await refreshTokenIfNeeded(0);

      if (refreshResult) {
        // Token was refreshed (in cookie), retry the request
        response = await originalFetch(input, init);
      }
    }

    return response;
  };

  // إرجاع دالة لاستعادة fetch الأصلي
  return () => {
    window.fetch = originalFetch;
  };
}

/**
 * Jaeger Tracing Service
 * 
 * هذا الملف يوفر Distributed Tracing مع Jaeger
 * يستخدم OpenTelemetry API للتوافق مع Jaeger
 */

import { trace, Span, SpanStatusCode, context, propagation, Context } from '@opentelemetry/api';
import { Resource } from '@opentelemetry/resources';
import { SemanticResourceAttributes } from '@opentelemetry/semantic-conventions';
import { NodeTracerProvider } from '@opentelemetry/sdk-trace-node';
import { BatchSpanProcessor } from '@opentelemetry/sdk-trace-base';
// JaegerExporter is imported dynamically to avoid loading issues
import { registerInstrumentations } from '@opentelemetry/instrumentation';
import { HttpInstrumentation } from '@opentelemetry/instrumentation-http';
import { ExpressInstrumentation } from '@opentelemetry/instrumentation-express';
import { PrismaInstrumentation } from '@prisma/instrumentation';

import { logger } from '@/lib/logger';

// متغيرات التكوين
const JAEGER_ENABLED = process.env.JAEGER_ENABLED === 'true';
const JAEGER_AGENT_HOST = process.env.JAEGER_AGENT_HOST || 'jaeger';
const JAEGER_AGENT_PORT = parseInt(process.env.JAEGER_AGENT_PORT || '6831', 10);
const SERVICE_NAME = process.env.SERVICE_NAME || 'thanawy';

let tracer: ReturnType<typeof trace.getTracer> | null = null;
let provider: NodeTracerProvider | null = null;

// تهيئة Tracer
export async function initializeTracer(): Promise<void> {
  if (!JAEGER_ENABLED) {
    logger.info('Jaeger tracing is disabled');
    return;
  }

  try {
    // استيراد ديناميكي لـ JaegerExporter لتجنب مشاكل التحميل
    let JaegerExporter: typeof import('@opentelemetry/exporter-jaeger').JaegerExporter;
    try {
      const jaegerModule = await import('@opentelemetry/exporter-jaeger');
      JaegerExporter = jaegerModule.JaegerExporter;
    } catch (importError: unknown) {
      logger.warn('Jaeger exporter not available, disabling tracing:', (importError as Error)?.message);
      return;
    }

    // إنشاء Resource
    const resource = new Resource({
      [SemanticResourceAttributes.SERVICE_NAME]: SERVICE_NAME,
      [SemanticResourceAttributes.SERVICE_VERSION]: process.env.npm_package_version || '1.0.0',
      [SemanticResourceAttributes.DEPLOYMENT_ENVIRONMENT]: process.env.NODE_ENV || 'development',
    });

    // إنشاء Tracer Provider
    provider = new NodeTracerProvider({
      resource,
    });

    // إنشاء Jaeger Exporter
    const jaegerExporter = new JaegerExporter({
      endpoint: `http://${JAEGER_AGENT_HOST}:14268/api/traces`,
      // أو استخدام UDP:
      // agentHost: JAEGER_AGENT_HOST,
      // agentPort: JAEGER_AGENT_PORT,
    });

    // إضافة Batch Span Processor
    provider.addSpanProcessor(new BatchSpanProcessor(jaegerExporter));

    // تسجيل Tracer Provider
    provider.register();

    // تسجيل Instrumentations
    registerInstrumentations({
      instrumentations: [
        new HttpInstrumentation({
          enabled: true,
        }),
        new ExpressInstrumentation({
          enabled: true,
        }),
        new PrismaInstrumentation({
          enabled: true,
        }),
      ],
    });

    // الحصول على Tracer
    tracer = trace.getTracer(SERVICE_NAME);

    logger.info('Jaeger tracing initialized successfully');
  } catch (error: unknown) {
    const err = error as { message?: string; code?: string };
    logger.error('Failed to initialize Jaeger tracing:', err?.message || String(error));
    // لا نرمي خطأ حتى لا نؤثر على التطبيق
    // تعطيل Jaeger تلقائياً في حالة الفشل
    if (err?.code === 'ENOENT' || err?.message?.includes('jaeger') || err?.message?.includes('thrift')) {
      logger.warn('Jaeger dependencies missing, tracing will be disabled');
    }
  }
}

// الحصول على Tracer
export function getTracer() {
  if (!tracer) {
    // إنشاء tracer بسيط بدون Jaeger
    tracer = trace.getTracer(SERVICE_NAME);
  }
  return tracer;
}

// إنشاء Span جديد
export function startSpan(name: string, options?: { attributes?: Record<string, unknown> }): Span {
  const tracerInstance = getTracer();
  const span = tracerInstance.startSpan(name, {
    attributes: (options?.attributes || {}) as any,
  });
  return span;
}

// إنشاء Span مع context
export function startSpanWithContext(
  name: string,
  parentContext: unknown,
  options?: { attributes?: Record<string, unknown> }
): Span {
  const tracerInstance = getTracer();
  const span = tracerInstance.startSpan(name, {
    attributes: (options?.attributes || {}) as unknown as import('@opentelemetry/api').SpanAttributes,
  }, parentContext as Context);
  return span;
}

// Helper function لتتبع async operations
export async function traceAsync<T>(
  name: string,
  operation: (span: Span) => Promise<T>,
  attributes?: Record<string, unknown>
): Promise<T> {
  const tracerInstance = getTracer();
  return tracerInstance.startActiveSpan(name, {
    attributes: (attributes || {}) as any,
  }, async (span) => {
    try {
      const result = await operation(span);
      span.setStatus({ code: SpanStatusCode.OK });
      return result;
    } catch (error) {
      span.setStatus({
        code: SpanStatusCode.ERROR,
        message: error instanceof Error ? error.message : String(error),
      });
      span.recordException(error instanceof Error ? error : new Error(String(error)));
      throw error;
    } finally {
      span.end();
    }
  });
}

// Helper function لتتبع synchronous operations
export function traceSync<T>(
  name: string,
  operation: (span: Span) => T,
  attributes?: Record<string, unknown>
): T {
  const tracerInstance = getTracer();
  return tracerInstance.startActiveSpan(name, {
    attributes: (attributes || {}) as any,
  }, (span) => {
    try {
      const result = operation(span);
      span.setStatus({ code: SpanStatusCode.OK });
      return result;
    } catch (error) {
      span.setStatus({
        code: SpanStatusCode.ERROR,
        message: error instanceof Error ? error.message : String(error),
      });
      span.recordException(error instanceof Error ? error : new Error(String(error)));
      throw error;
    } finally {
      span.end();
    }
  });
}

// Extract context from headers (للـ HTTP requests)
export function extractContext(headers: Record<string, string | string[] | undefined>): Context | undefined {
  const carrier: Record<string, string> = {};

  for (const [key, value] of Object.entries(headers)) {
    if (value) {
      carrier[key] = Array.isArray(value) ? value[0] : value;
    }
  }

  return propagation.extract(context.active(), carrier);
}

// Inject context into headers (للـ HTTP requests)
export function injectContext(headers: Record<string, string>): Record<string, string> {
  const carrier: Record<string, string> = {};
  propagation.inject(context.active(), carrier);
  return { ...headers, ...carrier };
}

// Shutdown tracer
export async function shutdownTracer(): Promise<void> {
  if (provider) {
    await provider.shutdown();
    provider = null;
    tracer = null;
  }
}

// تهيئة تلقائية إذا كان التطبيق يعمل
if (typeof window === 'undefined') {
  // تهيئة غير متزامنة لتجنب مشاكل التحميل
  initializeTracer().catch((error) => {
    logger.error('Failed to auto-initialize tracer:', error);
  });
}

﻿/**
 * Recovery Codes Service
 * خدمة رموز الاسترداد للـ 2FA
 */

import crypto from 'crypto';
import bcrypt from 'bcryptjs';
import { prisma } from '@/lib/db';
import { logger } from '@/lib/logger';

/**
 * Generate recovery codes
 * @param count Number of codes to generate (default: 10)
 */
export function generateRecoveryCodes(count: number = 10): string[] {
  const codes: string[] = [];

  for (let i = 0; i < count; i++) {
    // Generate 8-character alphanumeric code
    const randomBytes = crypto.randomBytes(4);
    const code = randomBytes
      .toString('base64')
      .replace(/[+/=]/g, '')
      .substring(0, 8)
      .toUpperCase();

    // Format: XXXX-XXXX
    const formatted = code.substring(0, 4) + '-' + code.substring(4, 8);
    codes.push(formatted);
  }

  return codes;
}

/**
 * Hash recovery code for storage
 * Security: Uses bcrypt instead of sha256 for better protection against rainbow tables
 */
export async function hashRecoveryCode(code: string): Promise<string> {
  // Normalize: remove dashes and convert to uppercase
  const cleanCode = code.replace(/-/g, '').toUpperCase();
  return bcrypt.hash(cleanCode, 10);
}

/**
 * Verify recovery code using timing-safe comparison
 * Security: Uses bcrypt.compare which is timing-safe
 */
export async function verifyRecoveryCode(
  code: string,
  hashedCodes: string[]
): Promise<{ valid: boolean; matchedIndex: number }> {
  const cleanCode = code.replace(/-/g, '').toUpperCase();

  for (let i = 0; i < hashedCodes.length; i++) {
    try {
      const isMatch = await bcrypt.compare(cleanCode, hashedCodes[i]);
      if (isMatch) {
        return { valid: true, matchedIndex: i };
      }
    } catch (error) {
      // Continue checking other codes if one fails
      logger.debug('Error comparing recovery code', { index: i });
    }
  }

  return { valid: false, matchedIndex: -1 };
}

/**
 * Generate and store recovery codes for user
 * Security: Codes are hashed with bcrypt before storage
 */
export async function generateAndStoreRecoveryCodes(
  userId: string,
  count: number = 10
): Promise<string[]> {
  const codes = generateRecoveryCodes(count);

  // Hash all codes with bcrypt (async)
  const hashedCodes = await Promise.all(codes.map(code => hashRecoveryCode(code)));

  // Replace existing codes (don't merge - regeneration means new set)
  await prisma.user.update({
    where: { id: userId },
    data: {
      recoveryCodes: JSON.stringify(hashedCodes),
    },
  });

  logger.info('Recovery codes generated', { userId, count });

  // Return plain codes (only shown once!)
  return codes;
}

/**
 * Verify and consume recovery code
 * Security: Uses bcrypt for timing-safe comparison
 */
export async function verifyAndConsumeRecoveryCode(
  userId: string,
  code: string
): Promise<boolean> {
  const user = await prisma.user.findUnique({
    where: { id: userId },
    select: { recoveryCodes: true },
  });

  if (!user || !user.recoveryCodes) {
    return false;
  }

  try {
    const hashedCodes: string[] = JSON.parse(user.recoveryCodes as string);

    const { valid, matchedIndex } = await verifyRecoveryCode(code, hashedCodes);

    if (!valid) {
      return false;
    }

    // Remove used code by index
    const remainingCodes = hashedCodes.filter((_, index) => index !== matchedIndex);

    // Update user
    await prisma.user.update({
      where: { id: userId },
      data: {
        recoveryCodes: remainingCodes.length > 0
          ? JSON.stringify(remainingCodes)
          : null,
      },
    });

    logger.info('Recovery code consumed', { userId, remainingCount: remainingCodes.length });
    return true;
  } catch (error) {
    logger.error('Error verifying recovery code', { userId, error });
    return false;
  }
}

/**
 * Get remaining recovery codes count
 */
export async function getRemainingRecoveryCodesCount(
  userId: string
): Promise<number> {
  const user = await prisma.user.findUnique({
    where: { id: userId },
    select: { recoveryCodes: true },
  });

  if (!user || !user.recoveryCodes) {
    return 0;
  }

  try {
    const hashedCodes: string[] = JSON.parse(user.recoveryCodes as string);
    return hashedCodes.length;
  } catch {
    return 0;
  }
}

/**
 * Regenerate recovery codes (replaces existing ones)
 */
export async function regenerateRecoveryCodes(
  userId: string,
  count: number = 10
): Promise<string[]> {
  const codes = generateRecoveryCodes(count);
  const hashedCodes = codes.map(hashRecoveryCode);

  await prisma.user.update({
    where: { id: userId },
    data: {
      recoveryCodes: JSON.stringify(hashedCodes),
    },
  });

  return codes;
}

/**
 * URL Validation Utility
 * Validates URLs to prevent open redirect and XSS vulnerabilities
 */

/**
 * Validates if a URL is safe for navigation
 * @param url - The URL to validate
 * @returns true if the URL is safe, false otherwise
 */
export function isSafeUrl(url: string | undefined | null): boolean {
  if (!url || typeof url !== 'string') {
    return false;
  }

  // Trim whitespace
  const trimmedUrl = url.trim();

  // Empty URLs are not safe
  if (trimmedUrl.length === 0) {
    return false;
  }

  try {
    // Check for dangerous protocols
    const dangerousProtocols = [
      'javascript:',
      'data:',
      'vbscript:',
      'file:',
      'about:',
    ];

    const lowerUrl = trimmedUrl.toLowerCase();
    
    // Block dangerous protocols
    for (const protocol of dangerousProtocols) {
      if (lowerUrl.startsWith(protocol)) {
        return false;
      }
    }

    // If it's a relative URL (starts with / or ./ or ../), it's safe
    if (trimmedUrl.startsWith('/') || trimmedUrl.startsWith('./') || trimmedUrl.startsWith('../')) {
      return true;
    }

    // For absolute URLs, validate using URL constructor
    const urlObj = new URL(trimmedUrl);

    // Only allow http and https protocols
    if (urlObj.protocol !== 'http:' && urlObj.protocol !== 'https:') {
      return false;
    }

    // Optional: Restrict to same origin only
    // Uncomment the following lines if you want to only allow same-origin URLs
    // if (typeof window !== 'undefined') {
    //   const currentOrigin = window.location.origin;
    //   if (urlObj.origin !== currentOrigin) {
    //     return false;
    //   }
    // }

    return true;
  } catch (error) {
    // If URL parsing fails, treat as relative URL
    // Only allow if it starts with / (relative path)
    return trimmedUrl.startsWith('/');
  }
}

/**
 * Sanitizes a URL for safe navigation
 * @param url - The URL to sanitize
 * @param fallback - Fallback URL if the input is unsafe (default: '/')
 * @returns A safe URL or the fallback
 */
export function sanitizeUrl(url: string | undefined | null, fallback: string = '/'): string {
  return isSafeUrl(url) ? url!.trim() : fallback;
}

/**
 * Safely navigates to a URL after validation
 * @param url - The URL to navigate to
 * @param fallback - Fallback URL if the input is unsafe (default: '/')
 */
export function safeNavigate(url: string | undefined | null, fallback: string = '/'): void {
  const safeUrl = sanitizeUrl(url, fallback);
  if (typeof window !== 'undefined') {
    window.location.href = safeUrl;
  }
}

import { clsx, type ClassValue } from "clsx"
import { twMerge } from "tailwind-merge"

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}

/**
 * Format date with validation and error handling
 */
export function formatDate(date: Date | string | null | undefined): string {
  // Validate input
  if (!date) {
    return 'تاريخ غير صحيح';
  }

  try {
    const dateObj = typeof date === "string" ? new Date(date) : date;
    
    // Validate date object
    if (isNaN(dateObj.getTime())) {
      return 'تاريخ غير صحيح';
    }

    return dateObj.toLocaleDateString("ar-SA", {
      year: "numeric",
      month: "long",
      day: "numeric",
    });
  } catch (error) {
    return 'تاريخ غير صحيح';
  }
}

/**
 * Format date and time with validation and error handling
 */
export function formatDateTime(date: Date | string | null | undefined): string {
  // Validate input
  if (!date) {
    return 'تاريخ غير صحيح';
  }

  try {
    const dateObj = typeof date === "string" ? new Date(date) : date;
    
    // Validate date object
    if (isNaN(dateObj.getTime())) {
      return 'تاريخ غير صحيح';
    }

    return dateObj.toLocaleDateString("ar-SA", {
      year: "numeric",
      month: "long",
      day: "numeric",
      hour: "2-digit",
      minute: "2-digit",
    });
  } catch (error) {
    return 'تاريخ غير صحيح';
  }
}

/**
 * Format relative time with validation and error handling
 */
export function formatRelativeTime(date: Date | string | null | undefined): string {
  // Validate input
  if (!date) {
    return 'تاريخ غير صحيح';
  }

  try {
    const dateObj = typeof date === "string" ? new Date(date) : date;
    
    // Validate date object
    if (isNaN(dateObj.getTime())) {
      return 'تاريخ غير صحيح';
    }

    const now = new Date();
    const diffInSeconds = Math.floor((now.getTime() - dateObj.getTime()) / 1000);
    
    // Handle future dates
    if (diffInSeconds < 0) {
      const futureDiffInSeconds = Math.abs(diffInSeconds);
      if (futureDiffInSeconds < 60) {
        return "قريباً";
      }
      const futureDiffInMinutes = Math.floor(futureDiffInSeconds / 60);
      if (futureDiffInMinutes < 60) {
        return `خلال ${futureDiffInMinutes} دقيقة`;
      }
      return "في المستقبل";
    }
    
    if (diffInSeconds < 60) {
      return "الآن";
    }
    
    const diffInMinutes = Math.floor(diffInSeconds / 60);
    if (diffInMinutes < 60) {
      return `منذ ${diffInMinutes} دقيقة`;
    }
    
    const diffInHours = Math.floor(diffInMinutes / 60);
    if (diffInHours < 24) {
      return `منذ ${diffInHours} ساعة`;
    }
    
    const diffInDays = Math.floor(diffInHours / 24);
    if (diffInDays < 7) {
      return `منذ ${diffInDays} يوم`;
    }
    
    const diffInWeeks = Math.floor(diffInDays / 7);
    if (diffInWeeks < 4) {
      return `منذ ${diffInWeeks} أسبوع`;
    }
    
    const diffInMonths = Math.floor(diffInDays / 30);
    if (diffInMonths < 12) {
      return `منذ ${diffInMonths} شهر`;
    }
    
    const diffInYears = Math.floor(diffInDays / 365);
    return `منذ ${diffInYears} سنة`;
  } catch (error) {
    return 'تاريخ غير صحيح';
  }
}

/**
 * Truncate text with validation
 */
export function truncateText(text: string | null | undefined, maxLength: number): string {
  // Validate input
  if (!text || typeof text !== 'string') {
    return '';
  }

  // Validate maxLength
  if (typeof maxLength !== 'number' || maxLength < 0) {
    return text;
  }

  if (text.length <= maxLength) {
    return text;
  }
  
  // Ensure we don't cut in the middle of a word if possible
  const truncated = text.slice(0, maxLength);
  const lastSpace = truncated.lastIndexOf(' ');
  
  if (lastSpace > maxLength * 0.7) {
    return truncated.slice(0, lastSpace) + "...";
  }
  
  return truncated + "...";
}

/**
 * Generate unique ID with validation
 */
export function generateId(): string {
  try {
    const part1 = Math.random().toString(36).substring(2, 15);
    const part2 = Math.random().toString(36).substring(2, 15);
    return part1 + part2;
  } catch (error) {
    // Fallback to timestamp-based ID if Math.random fails
    return `id-${Date.now()}-${Math.floor(Math.random() * 1000)}`;
  }
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { Bell, Check, CheckCheck, Trash2, MoreHorizontal } from 'lucide-react';
import { scheduleNotificationChecks } from '@/lib/notification-scheduler';
import { Button } from '@/components/ui/button';
// Token is in httpOnly cookie - no need to import getSafeAuthToken
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
  DropdownMenuSubContent,
  DropdownMenuSubTrigger,
  DropdownMenuSub,
} from '@/components/ui/dropdown-menu';
import { Badge } from "@/components/ui/badge";
import { Avatar, AvatarFallback } from '@/components/ui/avatar';

import { logger } from '@/lib/logger';
import { safeNavigate } from '@/lib/url-validator';

interface Notification {
  id: string;
  title: string;
  message: string;
  type: 'info' | 'success' | 'warning' | 'error';
  isRead: boolean;
  actionUrl?: string;
  icon?: string;
  createdAt: string;
}

interface NotificationsProviderProps {
  children: React.ReactNode;
}

export function NotificationsProvider({ children }: NotificationsProviderProps) {
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [unreadCount, setUnreadCount] = useState(0);
  const [isLoading, setIsLoading] = useState(false);
  const [hasMore, setHasMore] = useState(true);
  const [offset, setOffset] = useState(0);
  const limit = 10;

  // Fetch notifications
  const fetchNotifications = useCallback(async (reset = false) => {
    setIsLoading(true);
    try {
      // Token is in httpOnly cookie - no need to send Authorization header
      const currentOffset = reset ? 0 : offset;
      const params = new URLSearchParams({
        limit: limit.toString(),
        offset: currentOffset.toString(),
      });

      const response = await fetch(`/api/notifications?${params}`, {
        credentials: 'include',
      });

      if (!response.ok) throw new Error('Failed to fetch notifications');

      const data = await response.json();

      if (reset) {
        setNotifications(data.notifications);
        setOffset(0);
      } else {
        setNotifications(prev => [...prev, ...data.notifications]);
        setOffset(currentOffset + limit);
      }

      setUnreadCount(data.unreadCount);
      setHasMore(data.hasMore);
    } catch (error) {
      logger.error('Error fetching notifications:', error);
    } finally {
      setIsLoading(false);
    }
  }, [offset, limit]);

  // Initial fetch and schedule notification checks
  useEffect(() => {
    fetchNotifications(true);
    scheduleNotificationChecks();
  }, []);

  // Mark notifications as read
  const markAsRead = async (notificationIds?: string[], all = false) => {
    try {
      // Token is in httpOnly cookie - no need to send Authorization header
      const response = await fetch('/api/notifications/mark-read', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        credentials: 'include',
        body: JSON.stringify({
          notificationIds,
          all,
        }),
      });

      if (!response.ok) throw new Error('Failed to mark notifications as read');

      const data = await response.json();

      // Update local state
      if (all) {
        setNotifications(prev => prev.map(n => ({ ...n, isRead: true })));
      } else if (notificationIds) {
        setNotifications(prev => 
          prev.map(n => notificationIds.includes(n.id) ? { ...n, isRead: true } : n)
        );
      }

      setUnreadCount(data.unreadCount);
    } catch (error) {
      logger.error('Error marking notifications as read:', error);
    }
  };

  // Format date
  const formatDate = (dateString: string) => {
    const date = new Date(dateString);
    const now = new Date();
    const diffMs = now.getTime() - date.getTime();
    const diffMins = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMs / 3600000);
    const diffDays = Math.floor(diffMs / 86400000);

    if (diffMins < 1) return 'الآن';
    if (diffMins < 60) return `منذ ${diffMins} دقيقة`;
    if (diffHours < 24) return `منذ ${diffHours} ساعة`;
    if (diffDays < 7) return `منذ ${diffDays} يوم`;

    return date.toLocaleDateString('ar-SA', {
      day: 'numeric',
      month: 'short',
      year: date.getFullYear() !== now.getFullYear() ? 'numeric' : undefined,
    });
  };

  // Get notification icon
  const getNotificationIcon = (type: string, icon?: string) => {
    if (icon) return icon;

    switch (type) {
      case 'success':
        return '✅';
      case 'warning':
        return '⚠️';
      case 'error':
        return '❌';
      default:
        return 'ℹ️';
    }
  };

  // Load more notifications
  const loadMore = () => {
    if (!isLoading && hasMore) {
      fetchNotifications();
    }
  };

  return (
    <>
      {/* Notification bell icon */}
      <DropdownMenu>
        <DropdownMenuTrigger asChild>
          <button className="relative inline-flex items-center justify-center rounded-md text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:opacity-50 disabled:pointer-events-none hover:bg-accent hover:text-accent-foreground h-10 py-2 px-4 bg-transparent border-0 cursor-pointer">
            <Bell className="h-5 w-5" />
            {unreadCount > 0 && (
              <Badge 
                variant="destructive" 
                className="absolute -top-1 -right-1 h-5 w-5 flex items-center justify-center p-0 text-xs"
              >
                {unreadCount > 99 ? '99+' : unreadCount}
              </Badge>
            )}
          </button>
        </DropdownMenuTrigger>
        <DropdownMenuContent align="end" className="w-80 max-h-96">
          <div className="flex items-center justify-between p-2">
            <DropdownMenuLabel className="text-lg font-bold">الإشعارات</DropdownMenuLabel>
            {unreadCount > 0 && (
              <Button 
                variant="ghost" 
                size="sm" 
                onClick={() => markAsRead(undefined, true)}
                className="text-xs h-8"
              >
                <CheckCheck className="h-3 w-3 mr-1" />
                تحديد الكل كمقروء
              </Button>
            )}
          </div>
          <DropdownMenuSeparator />

          <div className="max-h-80 overflow-y-auto">
            {notifications.length === 0 ? (
              <div className="text-center py-6 text-muted-foreground">
                لا توجد إشعارات
              </div>
            ) : (
              notifications.map((notification) => (
                <DropdownMenuItem
                  key={notification.id}
                  className={`p-3 cursor-pointer flex-col items-start ${!notification.isRead ? 'bg-muted/30' : ''}`}
                  onClick={() => {
                    if (!notification.isRead) {
                      markAsRead([notification.id]);
                    }
                    if (notification.actionUrl) {
                      safeNavigate(notification.actionUrl);
                    }
                  }}
                >
                  <div className="flex w-full">
                    <div className="flex items-start gap-3 w-full">
                      <Avatar className="h-8 w-8 flex-shrink-0">
                        <AvatarFallback className="text-lg">
                          {getNotificationIcon(notification.type, notification.icon)}
                        </AvatarFallback>
                      </Avatar>
                      <div className="flex-1 min-w-0">
                        <div className="flex justify-between items-start">
                          <h4 className={`font-medium truncate ${!notification.isRead ? 'font-bold' : ''}`}>
                            {notification.title}
                          </h4>
                          <div className="flex items-center gap-1">
                            <span className="text-xs text-muted-foreground whitespace-nowrap">
                              {formatDate(notification.createdAt)}
                            </span>
                            {!notification.isRead && (
                              <span className="h-2 w-2 rounded-full bg-primary flex-shrink-0"></span>
                            )}
                          </div>
                        </div>
                        <p className="text-sm text-muted-foreground mt-1 line-clamp-2">
                          {notification.message}
                        </p>
                      </div>
                    </div>
                  </div>
                </DropdownMenuItem>
              ))
            )}

            {hasMore && (
              <div className="p-2 text-center">
                <Button 
                  variant="ghost" 
                  size="sm" 
                  onClick={loadMore}
                  disabled={isLoading}
                  className="w-full"
                >
                  {isLoading ? 'جاري التحميل...' : 'تحميل المزيد'}
                </Button>
              </div>
            )}
          </div>

          <DropdownMenuSeparator />
          <DropdownMenuItem className="text-center justify-center text-primary font-medium">
            عرض جميع الإشعارات
          </DropdownMenuItem>
        </DropdownMenuContent>
      </DropdownMenu>

      {children}
    </>
  );
}

