'use client';

import React, { useEffect, useState, Suspense } from 'react';
import { UnifiedAuthProvider } from '@/contexts/auth-context';
import { ToastProvider } from '@/contexts/toast-context';
import { WebSocketProvider } from '@/contexts/websocket-context';
import ClientLayoutProvider from '@/providers/ClientLayoutProvider';
import { ThemeProvider } from '@/providers/ThemeProvider';

type GlobalProvidersProps = {
  children: React.ReactNode;
};

export function GlobalProviders({ children }: GlobalProvidersProps) {
  const [mounted, setMounted] = useState(false);
  const [isReady, setIsReady] = useState(false);
  
  useEffect(() => {
    setMounted(true);
    // Small delay to ensure all providers are fully initialized
    const timer = setTimeout(() => {
      setIsReady(true);
    }, 0);
    return () => clearTimeout(timer);
  }, []);
  
  // ✅ النظام الموحد: UnifiedAuthProvider هو المصدر الوحيد للمصادقة
  // ✅ تم إزالة AuthProvider لتجنب التضارب - نظام واحد فقط يدير الحالة
  return (
    <UnifiedAuthProvider>
      <Suspense fallback={null}>
        <ClientLayoutProvider>
          <ThemeProvider
            attribute="class"
            defaultTheme="system"
            enableSystem
            disableTransitionOnChange
          >
            <ToastProvider>
              {mounted && isReady ? (
                <WebSocketProvider>
                  {children}
                </WebSocketProvider>
              ) : (
                <>{children}</>
              )}
            </ToastProvider>
          </ThemeProvider>
        </ClientLayoutProvider>
      </Suspense>
    </UnifiedAuthProvider>
  );
}

